	// TypeConverter that populates a dropdown with installed system fonts for the PanelFontFamily property
	public class PanelFontFamilyConverter : System.ComponentModel.StringConverter
	{
		private static System.ComponentModel.TypeConverter.StandardValuesCollection cachedValues;

		public override bool GetStandardValuesSupported(System.ComponentModel.ITypeDescriptorContext context) { return true; }
		public override bool GetStandardValuesExclusive(System.ComponentModel.ITypeDescriptorContext context) { return false; }

		public override System.ComponentModel.TypeConverter.StandardValuesCollection GetStandardValues(System.ComponentModel.ITypeDescriptorContext context)
		{
			if (cachedValues == null)
			{
				var list = new System.Collections.Generic.List<string>();
				try
				{
					foreach (var ff in System.Windows.Media.Fonts.SystemFontFamilies)
					{
						if (ff != null && !string.IsNullOrEmpty(ff.Source))
							list.Add(ff.Source);
					}
					list.Sort(System.StringComparer.OrdinalIgnoreCase);
				}
				catch { }
				cachedValues = new System.ComponentModel.TypeConverter.StandardValuesCollection(list);
			}
			return cachedValues;
		}
	}



