		private int effectiveMoveOrdersNewLeft = 260;

		// ============================================================
		// UNIFIED HIT-TEST RESOLVER (recommendation #3 — hover-only scope)
		// ============================================================
		//
		// Goal: a single source of truth for "what is the mouse currently
		// hovering on" so hover glow only lights up the truly-armed target
		// when overlapping rects compete for the cursor.
		//
		// SCOPE: HOVER ONLY — click dispatch stays on the legacy flow.
		//
		// An earlier version of this code also ran the resolver at the top
		// of OnMouseDown and tried to route every click priority decision
		// through it. That broke regular order-move and qty click handlers
		// because several OnMouseDown handlers expect fresh inline state
		// and the once-per-frame resolver answer was subtly misaligned
		// with what the click loops needed. Reverted to hover-only scope:
		//
		//   * ResolveHoverCategory() runs ONCE per OnRender frame (before
		//     DrawPlanOrder / DrawOrders).
		//
		//   * DrawPlanOrder hover glow sites (Entry text, plan line stroke)
		//     read HoverIsOrderOrHigher() to suppress their glow when an
		//     order flag is under the cursor. This is the core UX win from
		//     recommendation #2.
		//
		//   * OnMouseDown click paths do NOT read resolvedHoverCategory.
		//     The one place that needed order-vs-plan-line click priority
		//     (ATM plan line click loop) uses a small local
		//     clickNearOrderMove bool computed inline — see :48067.
		//
		// Architecture (for the hover path):
		//
		//   * HitCategory enum defines priority-ordered clickable groups.
		//     Higher value = higher priority = wins any conflict.
		//
		//   * ResolveHoverCategory() scans in priority-DESCENDING order
		//     and returns the first category whose hit-test matches the
		//     current mouse position. Runs once per frame from the
		//     last-populated hit-test dicts.
		//
		// What this replaced:
		//
		//   * frameOrderHoverDominates (bool) → becomes
		//     `resolvedHoverCategory >= HitCategory.FlagBody` via the
		//     HoverIsOrderOrHigher() helper.
		//
		// What this does NOT do:
		//
		//   * Rewrite any foreach loop in OnMouseDown. The ~30 loops for
		//     narrow buttons (cancel, attach1-6, qty adjust, order move,
		//     etc.) have no known overlap bugs and are left alone. Click
		//     priority is still enforced by loop ordering + early returns
		//     plus the one local clickNearOrderMove guard in the plan
		//     line loop.
		//
		// To add a new HOVER priority later:
		//   1. Insert a new enum value between two existing ones (its
		//      numeric position determines priority).
		//   2. Add a scan block to ResolveHoverCategory() in the right
		//      priority position.
		//   3. Guard the affected hover-glow draw site on
		//      `resolvedHoverCategory == HitCategory.Foo` (or use a
		//      convenience helper like HoverIsOrderOrHigher).
		private enum HitCategory
		{
			None          = 0, // nothing determined yet
			Background    = 1, // chart canvas (default when nothing matches)
			PlanLine      = 2, // wide ATM strategy plan horizontal strip
			PlanMarker    = 3, // small Auto BE / Trail marker on plan stop line
			FlagBody      = 4, // order move rect (live + LIT/iceberg/TS)
			FlagNarrowBtn = 5, // cancel X, attach1-6, qty adjust, etc. (future use)
			SyntheticQty  = 6, // iceberg / time-sliced qty click button
			Modal         = 7  // move-in-progress, click-entry active, etc.
		}

		// Updated once per OnRender frame only (not in OnMouseDown).
		private HitCategory resolvedHoverCategory = HitCategory.None;

		// Reference to the specific hit object (if any) that won the
		// resolution — populated alongside resolvedHoverCategory. Lets
		// handlers dispatch directly on the winner without re-running
		// their own hit-test. Currently only used for PlanMarker (stop-
		// strategy markers) but the field is here so future expansion
		// doesn't need another field.
		private object resolvedHoverTarget = null;

		// Scans clickable groups in priority-DESCENDING order and returns
		// the first HitCategory whose rect contains the cursor. This is
		// the single source of truth for hover arbitration — call it once
		// per frame (top of OnRender) and once per click (top of
		// OnMouseDown), then check resolvedHoverCategory at every gate
		// site instead of running independent geometry checks.
		//
		// Note: all rect hit-tests here MUST use the same slop as the
		// matching click handler. The order-move / LIT / plan-toggle /
		// qty click handlers all use `exmbl, exmbl` (0 px), so the
		// resolver does too. Previously the FlagBody resolver lookups
		// used ±5 px Y slop which made the cursor flip to Hand 5 px
		// before the click area began — approaching a flag from below
		// gave a hand cursor in a 5 px dead zone where no click handler
		// would fire. earlyClickNearOrderMove (which gates iceberg / TS /
		// plan-toggle handlers off when click is "near" an order) was
		// also at ±5 px, so clicks in that dead zone got blocked from
		// all other handlers too — click silently did nothing.
		private HitCategory ResolveHoverCategory()
		{
			resolvedHoverTarget = null;

			// --- Modal (highest) ---
			// Any mode where the next click MUST commit something and
			// nothing else should compete for the click. Same gating as
			// the hoisted click-entry / move-commit blocks at the top of
			// OnMouseDown.
			if (MovingOrder != null || (MovingOrders != null && MovingOrders.Count > 0)
				|| _movingStopStrategyItem != null
				|| BuyClickReady || SellClickReady
				|| BuyCloseClick || SellCloseClick
				|| BuyIcebergClick || SellIcebergClick
				|| BuyTimeSlicedClick || SellTimeSlicedClick
				|| MoveTargetsClick || MoveStopsClick
				|| InProfitActionIcebergClick)
			{
				return HitCategory.Modal;
			}

			// --- SyntheticQty ---
			// Iceberg / time-sliced qty click rects live inside
			// AllOrderQuantityButtons alongside live-order and LIT qty
			// entries, distinguished by the "SYN:" name prefix. They
			// must win over the iceberg / TS move rects that ExpandRect
			// 2000 px to the right — otherwise clicking the qty number
			// cancels the pending order instead of starting a qty adjust.
			if (pAllowOrderQuantityAdjustment && AllOrderQuantityButtons != null)
			{
				foreach (KeyValuePair<double, OrderDetails> kv in AllOrderQuantityButtons)
				{
					if (kv.Value.Name != null
						&& kv.Value.Name.StartsWith("SYN:")
						&& MouseIn(kv.Value.ThisRectA, exmbl, exmbl))
					{
						resolvedHoverTarget = kv.Value;
						return HitCategory.SyntheticQty;
					}
				}
			}

			// --- FlagNarrowBtn ---
			// Placeholder slot — no sites currently route through here.
			// When an overlap bug involving a narrow button surfaces, add
			// the scan here and gate that button's foreach on this
			// category.

			// --- FlagBody ---
			// Order move rects — include live orders, LIT, iceberg,
			// time-sliced. Use `exmbl, exmbl` to match the actual click
			// handler at :52244 (and LIT/iceberg/TS equivalents). Mismatch
			// here was the "hand cursor appears before clickable" bug —
			// approaching from below, cursor would flip 5 px before the
			// click area started.
			if (AllOrderMoveButtons != null)
			{
				foreach (KeyValuePair<double, OrderDetails> kv in AllOrderMoveButtons)
				{
					if (MouseIn(kv.Value.ThisRectA, exmbl, exmbl))
					{
						resolvedHoverTarget = kv.Value;
						return HitCategory.FlagBody;
					}
				}
			}
			if (AllLITOrderMoveButtons != null)
			{
				foreach (KeyValuePair<double, OrderDetails> kv in AllLITOrderMoveButtons)
				{
					if (MouseIn(kv.Value.ThisRectA, exmbl, exmbl))
					{
						resolvedHoverTarget = kv.Value;
						return HitCategory.FlagBody;
					}
				}
			}

			// --- PlanMarker ---
			// Stop-strategy markers (Auto BE, Trail step triggers). They
			// sit on ATM plan stop lines but are small specific rects —
			// priority must be higher than PlanLine so a click on the
			// marker starts a marker move instead of selecting the
			// underlying plan line.
			try
			{
				var ssHit = FindHoveredStopStrategyButton();
				if (ssHit != null)
				{
					resolvedHoverTarget = ssHit;
					return HitCategory.PlanMarker;
				}
			}
			catch { /* FindHoveredStopStrategyButton can throw during init */ }

			// --- PlanLine ---
			// Wide ATM plan horizontal strip. Lowest priority above
			// Background because it has the widest hit area and should
			// only win when nothing else is under the cursor.
			if (AllATMStrategyLevelButtons != null)
			{
				foreach (KeyValuePair<double, ATMMoveDetails> kv in AllATMStrategyLevelButtons)
				{
					if (MouseIn(kv.Value.ThisRectA, exmbl, exmbl))
					{
						resolvedHoverTarget = kv.Value;
						return HitCategory.PlanLine;
					}
				}
			}

			// --- Background ---
			return HitCategory.Background;
		}

		// Convenience shorthand — used by the remaining sites that
		// previously checked `frameOrderHoverDominates`. Returns true
		// when an order flag (or anything with higher priority) is
		// currently the armed hover target, so ATM plan line hover glow
		// and similar lower-priority effects should be suppressed.
