		}

		// Per-render plot index cursor for ATM plan Y-axis flags.
		//
		// DrawPlanOrder is called once per ATM plan level (Entry, Target 1..N,
		// Stop 1..N, BE lines, trail steps, sim stops). Each call grabs the
		// NEXT free plot slot counting DOWN from the end of Values[], which
		// lets NinjaTrader's built-in plot-flag mechanism render the level as
		// a Y-axis flag in the color of the line's stroke.
		//
		// Counting down (instead of up from plot 25 where live orders live)
		// keeps the live-order loop and the ATM plan loop from fighting over
		// the same slots: live orders allocate upward starting at 25, ATM
		// plans allocate downward starting at Values.Length - 1. Collision
		// happens only if live orders + ATM plans exceed the total allocated
		// plot count (~119), which is far above any realistic combined total.
		//
		// Reset at the top of OnRender (unconditional) — NOT inside
		// SetOrderFlags() which has early-return guards on `myAccount` and
		// `pScaleByOrders`.
		private int atmPlanPlotCursor = 0;

		// The lowest plot index written to by DrawPlanOrder in the PREVIOUS
		// render frame. Used at the top of the next frame to clear exactly
		// the slots the plan code owned, instead of a fixed conservative
		// range that would risk wiping out live-order plots at the edge.
		// Sentinel value int.MaxValue means "no plan levels drawn last
		// frame", so nothing to clear.
		private int atmPlanPlotLastLow = int.MaxValue;

