		// Hit-test priority constants. Higher number = wins ties when two rects
		// overlap and the mouse is over both. Used by FindHoveredButton to make
		// click routing deterministic instead of dependent on insertion order.
		// Text toggles (Hide, Now/Mode, R/R, IE, Entry label) all beat
		// PLAN_LINE so clicking the highlighted text always toggles the text.
		// The line wins clicks outside every toggle rect. Paired with a
		// narrower-than-before line drag strip (asymmetric: tighter on the
		// toggle side) so the overlap zone is small to begin with. SS markers
		// keep their slot just above the line so BE / Trail / Sim markers still
		// beat the underlying stop line.
		private const int HIT_PRIORITY_HIDE        = 37;  // Hide button
		private const int HIT_PRIORITY_NOW_PRICE   = 37;  // [Now]/[Price] toggle
		private const int HIT_PRIORITY_RR_TOGGLE   = 37;  // R/R ON/OFF button
		private const int HIT_PRIORITY_STOP_SRC    = 37;  // IE: badge
		private const int HIT_PRIORITY_PLAN_LINE   = 35;  // entry/target/stop main lines
		private const int HIT_PRIORITY_SS_MARKER   = 40;  // stop-strategy marker lines (Auto BE / Trail / Sim)
		private const int HIT_PRIORITY_PLAN_LABEL  = 45;  // Entry direction-toggle text — always wins (incl. during plan move)
		private const int HIT_PRIORITY_PLACE_ORDER = 50;  // Place Order button
		// Plain Dictionary instead of SortedDictionary — no iteration site
		// depends on key ordering (the click router uses LINQ
		// .OrderByDescending(...) and FindHoveredButton uses an explicit
		// priority+key tie-break, both unaffected by container ordering).
		// Avoids per-Add tree-node allocations and O(log N) insertion cost.
		Dictionary<double, ATMMoveDetails> AllATMStrategyLevelButtons = new Dictionary<double, ATMMoveDetails>();

		// Strict flag-only rect per live order — populated each frame in the
		// order render loop with the narrow on-chart flag rect (the flag
		// label visual itself, NOT the line going across the chart, NOT the
		// 2000-px move-rect extension). Used by DrawPlanOrder's Hide-button
		// suppression so Hide disappears ONLY when the cursor is over the
		// flag visual, not when it's anywhere else (including the line).
		Dictionary<Order, SharpDX.RectangleF> _orderStrictFlagRects = new Dictionary<Order, SharpDX.RectangleF>();

		// Snapshot of the hover resolver's last result, used by OnMouseMove
		// to skip RefreshRender when the cursor moves WITHIN the same hover
		// region. Hover state changes (FlagBody → Background, PlanLine →
		// FlagBody, etc.) still invalidate immediately so glow / Hide-button
		// / cursor transitions stay pixel-snappy. Avoids invalidating the
		// chart on every micro-movement when nothing visible changed.
		HitCategory _lastHoverCategory = HitCategory.None;
		object _lastHoverTarget = null;
		
		
