		// Dimmed-color brush cache for click-entry preview flags. Users want the
		// live Buy Click / Sell Click cursor flag to show the buy/sell color
		// (not a flat gray) but darkened -- same visual cue as an order flag
		// being dragged. Cached to avoid per-frame SolidColorBrush allocations.
		private System.Collections.Generic.Dictionary<System.Windows.Media.Color, Brush> _dimmedBrushCache
			= new System.Collections.Generic.Dictionary<System.Windows.Media.Color, Brush>();
		private Brush DimmedBrush(Brush src)
		{
			SolidColorBrush scb = src as SolidColorBrush;
			if (scb == null) return src;
			var c = scb.Color;
			Brush cached;
			if (!_dimmedBrushCache.TryGetValue(c, out cached))
			{
				// 50% alpha preserves hue while reading as "dimmed / preview".
				cached = new SolidColorBrush(System.Windows.Media.Color.FromArgb(128, c.R, c.G, c.B));
				(cached as System.Windows.Freezable)?.Freeze();
				_dimmedBrushCache[c] = cached;
			}
			return cached;
		}

