		// Lightweight TextLayout cache for short, frequently-rendered plan label strings
		// ([Now], [Price], R / R ON/OFF, Buy/Sell Now/Price, stop source badges, etc.).
		// Keyed by text + font size so a font change invalidates automatically.
		// Disposed in OnRenderTargetChanged when RenderTarget is null.
		private Dictionary<string, SharpDX.DirectWrite.TextLayout> PlanLabelLayoutCache
			= new Dictionary<string, SharpDX.DirectWrite.TextLayout>();
		private float PlanLabelLayoutCacheFontSize = 0f;
		// Bound on PlanLabelLayoutCache. Plan label text is MOSTLY static
		// ([Now], [Price], R/R ON/OFF, fixed badges), but some labels contain
		// dynamic values ("R/R 1.5:1", "SL 10t", "Auto BE @ +5t", etc.). Over
		// long sessions, each new unique value permanently grows the cache
		// because the eviction was font-size-change only. Cap at 150 — well
		// above the realistic working set (~20 labels at a time) but small
		// enough that a runaway value doesn't bleed native resources for hours.
		private const int PlanLabelCacheMaxEntries = 150;

		private SharpDX.DirectWrite.TextLayout GetPlanLabelLayout(string text)
		{
			if (string.IsNullOrEmpty(text) || CellFormat == null) return null;

			float fs = CellFormat.FontSize;
			if (fs != PlanLabelLayoutCacheFontSize)
			{
				DisposePlanLabelLayoutCache();
				PlanLabelLayoutCacheFontSize = fs;
			}

			SharpDX.DirectWrite.TextLayout layout;
			if (!PlanLabelLayoutCache.TryGetValue(text, out layout) || layout == null)
			{
				// Cap reached — flush cache and rebuild. Cheap because the
				// currently-visible labels are re-populated on the very next
				// few GetPlanLabelLayout calls within this same render frame.
				// Dispose clears PlanLabelLayoutCacheFontSize to 0 as a side
				// effect, so re-stamp it AFTER the dispose to avoid an
				// infinite flush loop on the next call (which would see
				// 0 != actual fs and flush again).
				if (PlanLabelLayoutCache.Count >= PlanLabelCacheMaxEntries)
				{
					DisposePlanLabelLayoutCache();
					PlanLabelLayoutCacheFontSize = fs;
				}

				layout = new SharpDX.DirectWrite.TextLayout(
					NinjaTrader.Core.Globals.DirectWriteFactory, text, CellFormat, 10000, 10000);
				PlanLabelLayoutCache[text] = layout;
			}
			return layout;
		}

		// Helper: get just the width via the plan label cache — zero alloc on cache hit.
		// Safe to use from any Draw* path since it doesn't touch the CellLayout field.
		private float MeasureCachedWidth(string text)
		{
			var layout = GetPlanLabelLayout(text);
			return layout != null ? layout.Metrics.Width : 0f;
		}

		private void DisposePlanLabelLayoutCache()
		{
			if (PlanLabelLayoutCache == null) return;
			foreach (var l in PlanLabelLayoutCache.Values)
			{
				try { if (l != null) l.Dispose(); } catch {}
			}
			PlanLabelLayoutCache.Clear();
			PlanLabelLayoutCacheFontSize = 0f;
		}

		// Same idea as PlanLabelLayoutCache but works with ANY TextFormat (the
		// plan cache assumes the global CellFormat). Used by hot-path render
		// sites — timer (~74164), status bar (~74031), message alerts
		// (~73187) — that previously allocated a fresh TextLayout every
		// frame just to read .Metrics.Width / .Metrics.Height. On a chart
		// with no visible elements except the bottom-right timer, this was
		// the dominant per-frame allocation source.
		//
		// Cache key includes the format's identity (NativePointer hash) and
		// the maxWidth bucket because the same text in a different format or
		// at a different wrap width produces a different layout.
		//
		// Disposed in lock-step with cached TextFormats (formats own the
		// underlying DirectWrite resources that layouts reference) via
		// DisposeAllCachedTextFormats().
		private Dictionary<string, SharpDX.DirectWrite.TextLayout> _measureLayoutCache
			= new Dictionary<string, SharpDX.DirectWrite.TextLayout>();
		private const int MeasureLayoutCacheMaxEntries = 200;

		private SharpDX.DirectWrite.TextLayout GetMeasureLayout(string text, SharpDX.DirectWrite.TextFormat format, float maxWidth)
		{
			if (string.IsNullOrEmpty(text) || format == null) return null;

			// Compose a string key. format.GetHashCode() resolves to the
			// SharpDX NativePointer hash, stable for the lifetime of the
			// format instance — different cached formats produce distinct
			// hashes. Bucketing maxWidth to int avoids cache churn from
			// sub-pixel chart-panel width jitter.
			string key = text + "\0" + format.GetHashCode().ToString("X") + "\0" + ((int)maxWidth).ToString();

			SharpDX.DirectWrite.TextLayout layout;
			if (_measureLayoutCache.TryGetValue(key, out layout) && layout != null)
				return layout;

			if (_measureLayoutCache.Count >= MeasureLayoutCacheMaxEntries)
				DisposeMeasureLayoutCache();

			layout = new SharpDX.DirectWrite.TextLayout(
				NinjaTrader.Core.Globals.DirectWriteFactory, text, format, maxWidth, 10000);
			_measureLayoutCache[key] = layout;
			return layout;
		}

		private void DisposeMeasureLayoutCache()
		{
			if (_measureLayoutCache == null) return;
			foreach (var l in _measureLayoutCache.Values)
			{
				try { if (l != null) l.Dispose(); } catch {}
			}
			_measureLayoutCache.Clear();
		}

        private SharpDX.DirectWrite.TextFormat CellFormat;
		private SharpDX.DirectWrite.TextFormat CellFormatFinal;
		private SharpDX.DirectWrite.TextFormat CellFormatImb;
		private SharpDX.DirectWrite.TextFormat CellFormatCalc;
		SortedList<int, double> HeightToTexThisTickSize = new SortedList<int, double>();
		// Bound on HeightToTexThisTickSize — if the box-fit code encounters
		// more than this many unique font sizes, the cache is flushed and
		// rebuilt from scratch. 40 is well above typical box-fit working sets
		// (~7-10 per resize) and caps the worst case where workspace changes
		// repeatedly cycle the chart through many different sizes.
		private const int HeightCacheMaxEntries = 40;

		// Lazy text-height cache. Replaces a 100-iteration FirstRender pre-compute that
		// allocated SimpleFont + TextFormat + TextLayout DirectWrite resources for every
		// possible font size up front. Now we only compute the sizes binary search actually
		// touches (~7 per box-height change, then cached forever).
		//
		// LEAK FIX (Finding #2 from deep-dive): the dictionary was previously
		// unbounded. Over long idle sessions, repeated workspace / chart
		// resizes could accumulate unique font sizes and grow the cache
		// without limit, contributing to sustained GC pressure. Now capped
		// at HeightCacheMaxEntries — when exceeded we flush and rebuild.
		private double GetCachedTextHeight(int fontSize)
		{
			double cached;
			if (HeightToTexThisTickSize.TryGetValue(fontSize, out cached))
				return cached;

			// Cap reached — flush the cache before adding the new entry so the
			// cache never grows beyond HeightCacheMaxEntries. Cheap: the next
			// ~10 box-fit iterations will re-populate whatever is currently
			// needed and the old entries (mostly stale font sizes from a
			// previous layout) are dropped.
			if (HeightToTexThisTickSize.Count >= HeightCacheMaxEntries)
				HeightToTexThisTickSize.Clear();

			SimpleFont TextFontCalc = new SimpleFont(pTextFont5.Family.ToString(), fontSize);
			if (CellFormatCalc != null) CellFormatCalc.Dispose();
			CellFormatCalc = TextFontCalc.ToDirectWriteTextFormat();
			if (CellLayoutCalc != null) CellLayoutCalc.Dispose();
			CellLayoutCalc = new TextLayout(Core.Globals.DirectWriteFactory, "L1343", CellFormatCalc, 10000, 10000);
			double h = CellLayoutCalc.Metrics.Height;
			HeightToTexThisTickSize.Add(fontSize, h);
			return h;
		}
		
