		private int[] RedoArrayInt(int[] input, int num, int emptyv)
			{
						
					int[] pAllTrailingStopsNew = new int[num];
					
					int slot = 0;
					
				
				//Print(pAllTrailingStopsNew.Length);
				
				
					foreach (int s in input)
					{
						//Print(slot);
						
						
						
						if (slot+1 <= pAllTrailingStopsNew.Length)
						{
							
							pAllTrailingStopsNew[slot] = emptyv;
							
							if (slot+1 <= input.Length)
							{
								
								pAllTrailingStopsNew[slot] = input[slot];
							}
						
						
						}						
						


						slot++;
						
					}

					return pAllTrailingStopsNew;
					
					
					
			}
					
					
					
		private string[] RedoArrayString(string[] input, int num, bool IsMain)
			{
						
					string[] pAllTrailingStopsNew = new string[num];
					
					int slot = 0;
					
					foreach (string s in input)
					{
						
						if (IsMain)
						{
							if (slot+1 <= pAllTrailingStopsNew.Length)
							{
								
								pAllTrailingStopsNew[slot] = "Custom " + (slot+1).ToString();
								
								if (slot+1 <= input.Length)
								{
									
									pAllTrailingStopsNew[slot] = input[slot];
									
									if (input[slot] == string.Empty || input[slot] == " " || input[slot] == "  ")
									{
										pAllTrailingStopsNew[slot] = "Custom " + (slot+1).ToString();
									}
									
									
								}
							
							
							}
						}
						else
						{
							
							if (slot+1 <= pAllTrailingStopsNew.Length)
							{
								
								pAllTrailingStopsNew[slot] = "";
								
								if (slot+1 <= input.Length)
								{
									
									pAllTrailingStopsNew[slot] = input[slot];
									
									if (input[slot] == string.Empty || input[slot] == " " || input[slot] == "  ")
									{
										pAllTrailingStopsNew[slot] = "";
									}
									
									
								}
							
							
							}							
							
						}
							
						
//						if (slot+1 <= pAllTrailingStopsNew.Length)
//							pAllTrailingStopsNew[slot] = input[slot];
						
//						if (IsMain)
//						{
							
//							if (input[slot] == string.Empty)
//								pAllTrailingStopsNew[slot] = "Custom " + (slot+1).ToString();
//						}
						
						slot++;
						
					}

					return pAllTrailingStopsNew;
					
					
					
			}
			
			
				
