				microinstrument = thisexinstr.Replace("FDXM", "FDXS");
 				miniinstrument = thisexinstr.Replace("FDXS", "FDXM");	
				
				
				
			}									
			else if (thisexinstr.Contains("RTY") || thisexinstr.Contains("M2K"))
			{
				microinstrument = thisexinstr.Replace("RTY", "M2K");
