//				}
				
				
//				if (thisexinstr.Contains("M"))
//				{
//					if (!thisexinstr.Contains("YM"))
//					{				
//						IsMicro = true;
//					}
//					else
//					{
//						if (thisexinstr.Contains("MYM"))
//							IsMicro = true;	
//					}			
//				}	
				
				
//				if (IsMicro)
//				{
//						microinstrument = thisexinstr;										
//						miniinstrument = thisexinstr.Substring(1); // remove first character
					
//				}
