		bool IsCTRLNow = false;
		bool IsALTNow = false;
		
	
		private void ChartControl_PreviewKeyUp(object sender, KeyEventArgs e)
		{
			if (pOneClickOrdersEnabled2 && pActivateWithKeys)
			{
				IsCTRLNow = Keyboard.IsKeyDown(Key.LeftCtrl);
				IsALTNow = Keyboard.IsKeyDown(Key.LeftAlt);
				
				InOneClick = false;
				
				if (IsCTRLNow)
				{
					InOneClick = true;
					pOneClickStatus = "Long";
				}
				if (IsALTNow)
				{
					InOneClick = true;
					pOneClickStatus = "Short";
				}

				BuyClickReady = false;
				SellClickReady = false;	
				
				if (InOneClick)
				if (pOneClickStatus == "Long")
				{
					BuyClickReady = true;
				}
				else
				{
					SellClickReady = true;	
				}
					
				UpdateButtons();
				RefreshRender(44);
			}
			
	
		}
		
		
		private bool IsHotKeyModifierPressed()
		{
			switch (pHotKeyModifier)
			{
				case "Left Alt":
					return Keyboard.IsKeyDown(Key.LeftAlt);
				case "Left Shift":
					return Keyboard.IsKeyDown(Key.LeftShift);
				case "Ctrl + Shift":
					return Keyboard.IsKeyDown(Key.LeftCtrl) && Keyboard.IsKeyDown(Key.LeftShift);
				case "Ctrl + Alt":
					return Keyboard.IsKeyDown(Key.LeftCtrl) && Keyboard.IsKeyDown(Key.LeftAlt);
				default: // "Left Ctrl"
					return Keyboard.IsKeyDown(Key.LeftCtrl);
			}
		}

