		private void ChartControl_PreviewMouseWheel(object sender, MouseWheelEventArgs e)
		{
			// === ATM plan direction toggle (highest priority) ===
			// When the 'i' has been clicked to launch a Price-mode ATM plan and
			// we're waiting for the user to click in the chart to lock the entry
			// price, the wheel flips Long/Short so the user can pick a side
			// without leaving the chart. Scroll up = Long, scroll down = Short.
			if (IsMovingPlan != "" && !pMarketPlanActive)
			{
				string newDir = e.Delta > 0 ? "Long" : "Short";
				if (pLastPlanDirection != newDir)
				{
					pLastPlanDirection = newDir;
					IsMovingPlan = newDir;
				}
				e.Handled = true;
				RefreshRender(45);
				return;
			}

			// === Qty-adjust wheel (HIGHEST PRIORITY) ===
			// When the user is mid-adjustment on ANY qty (live broker order,
			// LIT/Close custom order, or pending iceberg/time-sliced flag),
			// the wheel must adjust the qty no matter where the mouse is or
			// what else the wheel might otherwise trigger. Previously this
			// block lived below the stop-strategy marker and InOneClick
			// handlers, which meant hovering a stop-strategy rect (common
			// since markers sit on the same stop line as the order flag) or
			// being in one-click mode would steal the wheel and the qty
			// wouldn't advance. Hoisted to the top so qty-adjust mode is
			// fully modal for the wheel, matching how it's modal for clicks.
			if (QtyOrder != null || QtyOrderLIT != null || SyntheticQtyKey != null)
			{
				if (e.Delta > 0)
					NewQuantityUpdate = NewQuantityUpdate + pQtyChangeI2;
				else
					NewQuantityUpdate = NewQuantityUpdate - pQtyChangeI2;

				NewQuantityUpdate = Math.Max(1, NewQuantityUpdate);

				e.Handled = true;
				RefreshRender(44);
				return;
			}

			// === Stop-strategy marker wheel nudging ===
			// If the mouse is hovering a stop-strategy hit rect while the plan is
			// visible, the wheel adjusts values on that marker:
			//   - No modifier: Stop Loss     (Trail only)
			//   - Shift:       Frequency     (Trail only)
			//   - Alt:         Plus offset   (Auto BE only)
			// Step size = 1. We don't use Ctrl so built-in chart zoom stays intact.
			//
			// Master switch: skip entirely when Stop Strategy management is
			// disabled in the property grid (default).
			if (!pStopStrategyManagementDisabled)
			try
			{
				var hit = FindHoveredStopStrategyButton();
				if (hit != null)
				{
					MoveKind kind; int stepIdx;
					if (ParseStopStrategyRectName(hit.Name, out kind, out stepIdx))
					{
						int bi;
						ParseStopStrategyBracketIdx(hit.Name, out bi);

						bool shift = Keyboard.IsKeyDown(Key.LeftShift) || Keyboard.IsKeyDown(Key.RightShift);
						bool alt   = Keyboard.IsKeyDown(Key.LeftAlt)   || Keyboard.IsKeyDown(Key.RightAlt);
						int dir  = e.Delta > 0 ? 1 : -1;
						int step = 1;

						var info = ReadAtmStopStrategyInfo(hit.ThisATM, bi);
						if (info != null)
						{
							if (kind == MoveKind.AutoBETrigger)
							{
								// Auto BE has only one scrollable field (Plus), so plain
								// scroll adjusts it directly — no modifier needed.
								int newPlus = info.AutoBEPlus + dir * step;
								SetDraftAutoBEPlus(hit.ThisATM, bi, newPlus);
								e.Handled = true;
								RefreshRender(1210);
								return;
							}
							else if (kind == MoveKind.TrailStepTrigger)
							{
								if (stepIdx >= 0 && stepIdx < info.AutoTrailSteps.Count)
								{
									var s = info.AutoTrailSteps[stepIdx];
									int sl   = s.StopLoss;
									int pt   = s.ProfitTrigger;
									int freq = s.Frequency;

									if (shift)
										freq = Math.Max(1, freq + dir * step);
									else
										sl = Math.Max(1, sl + dir * step);

									SetDraftTrailStep(hit.ThisATM, bi, stepIdx, sl, pt, freq);
									e.Handled = true;
									RefreshRender(1211);
									return;
								}
							}
						}
					}
				}
			}
			catch { }


			// === Click Entry order-type wheel cycling ===
			// When Buy/Sell Click is armed, scroll wheel cycles the order type
			// so the user can adjust without returning to the panel buttons.
			// Limit side (LMT/MIT/LIT) or Stop side (STP/SLM) depends on
			// cursor price vs market, mirroring the auto-select logic in OnRender.
			if ((BuyClickReady || SellClickReady) && !InOneClick)
			{
				bool isLimitSide;
				if (BuyClickReady)
				{
					double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentAsk;
					isLimitSide = CurrentMousePrice <= refPrice;
				}
				else
				{
					double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentBid;
					isLimitSide = CurrentMousePrice >= refPrice;
				}

				if (isLimitSide)
				{
					if (e.Delta > 0)
					{
						if (pThisEntryLimitClick == "LMT")
							pThisEntryLimitClick = "MIT";
						else if (pThisEntryLimitClick == "MIT")
							pThisEntryLimitClick = pLITEntryOrdersEnabled ? "LIT" : "LMT";
						else
							pThisEntryLimitClick = "LMT";
					}
					else
					{
						if (pThisEntryLimitClick == "LMT")
							pThisEntryLimitClick = pLITEntryOrdersEnabled ? "LIT" : "MIT";
						else if (pThisEntryLimitClick == "LIT")
							pThisEntryLimitClick = "MIT";
						else
							pThisEntryLimitClick = "LMT";
					}
				}
				else
				{
					pUseSLM = !pUseSLM;
				}

				e.Handled = true;
				UpdateButtons();
				RefreshRender(248);
				return;
			}

			if (InOneClick)
			{
				bool shiftHeld = Keyboard.IsKeyDown(Key.LeftShift) || Keyboard.IsKeyDown(Key.RightShift);

				// New: parameter controls which action the plain wheel performs.
				// Shift inverts the choice so both actions remain accessible.
				bool switchDirection = shiftHeld ? !pOneClickWheelSwitchesDirection : pOneClickWheelSwitchesDirection;

				if (switchDirection)
				{
					// Wheel = switch direction (Long/Short)
					if (e.Delta > 0)
						pOneClickStatus = "Long";
					else
						pOneClickStatus = "Short";

					BuyClickReady = false;
					SellClickReady = false;

					if (pOneClickStatus == "Long")
						BuyClickReady = true;
					else
						SellClickReady = true;
				}
				else
				{
					// Wheel = cycle order type (same as Click Entry)
					bool isLimitSide;
					if (BuyClickReady)
					{
						double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentAsk;
						isLimitSide = CurrentMousePrice <= refPrice;
					}
					else
					{
						double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentBid;
						isLimitSide = CurrentMousePrice >= refPrice;
					}

					if (isLimitSide)
					{
						if (e.Delta > 0)
						{
							if (pThisEntryLimitClick == "LMT")
								pThisEntryLimitClick = "MIT";
							else if (pThisEntryLimitClick == "MIT")
								pThisEntryLimitClick = pLITEntryOrdersEnabled ? "LIT" : "LMT";
							else
								pThisEntryLimitClick = "LMT";
						}
						else
						{
							if (pThisEntryLimitClick == "LMT")
								pThisEntryLimitClick = pLITEntryOrdersEnabled ? "LIT" : "MIT";
							else if (pThisEntryLimitClick == "LIT")
								pThisEntryLimitClick = "MIT";
							else
								pThisEntryLimitClick = "LMT";
						}
					}
					else
					{
						pUseSLM = !pUseSLM;
					}
				}

				e.Handled = true;
				UpdateButtons();
				RefreshRender(44);
			}
			
			// (Qty-adjust wheel handling moved to the top of this method so
			// it takes priority over stop-strategy marker wheel and
			// InOneClick — see the hoisted block at the start of
			// ChartControl_PreviewMouseWheel.)

				if (!pUseYScroll)
				return;
			
			//chartScale.Properties.YAxisRangeType = YAxisRangeType.Automatic;	
			
			MouseWheelDone = true;
			
			
			//ChartControl.LastSlotPainted = CurrentBars[0];
			
			
			int pAmountPerScroll = pScrollTicks;
			
			
			
			int moveit = -1 * pAmountPerScroll;
			
			if (e.Delta > 0)
				moveit = Math.Abs(moveit);
			
			TicksAdjust = TicksAdjust + moveit;
			
					//	MaxValue = ScaleHigh.GetValueAt(ChartBars.ToIndex) + ThisTickSize*TicksAdjust;
					//		MinValue = ScaleLow.GetValueAt(ChartBars.ToIndex) + ThisTickSize*TicksAdjust;
			
		
//					if (!pZoomEnabled)
//						SetBarSize(pCurrentSetting, pSpaceBetweenBars);
//					else
//						SetBarSize(pCurrentSetting2, pSpaceBetweenBars2);			

			IsScrolled = true;	
			
			//ChartControl.ChartPanels[0].InvalidateVisual();	
			RefreshRender(44);
			
			//ForceRefresh();
			//RefreshRender(44);
		
			//ChartControl.ChartPanels[0].InvalidateVisual(); 
			
		  
		}





		// chart sidebar
		
//							if (buttonn == "Market" || buttonn == "Limit")
//					{
//						if (pThisEntryType == "Market")
//						{
