		// Returns a ToolTip pre-assigned the shared tight-layout Style. Style is
		// lazily built and registered as an implicit style on ChartControl.Resources.
		// Use this in place of `new ToolTip()` everywhere in the indicator so every
		// tooltip across every button picks up the same minimal Border+ContentPresenter
		// template (no MinWidth from NT's default template → no trailing dead space).
		private ToolTip MakeToolTip()
		{
			if (tipStyle == null)
			{
				string tipTemplateXaml =
					"<ControlTemplate xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation'" +
					" xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml'" +
					" TargetType='{x:Type ToolTip}'>" +
					"  <Border Background='{TemplateBinding Background}'" +
					"          BorderBrush='{TemplateBinding BorderBrush}'" +
					"          BorderThickness='{TemplateBinding BorderThickness}'" +
					"          Padding='{TemplateBinding Padding}'" +
					"          SnapsToDevicePixels='True'>" +
					"    <ContentPresenter HorizontalAlignment='Left' VerticalAlignment='Center'/>" +
					"  </Border>" +
					"</ControlTemplate>";
				var tipTemplate = (ControlTemplate)System.Windows.Markup.XamlReader.Parse(tipTemplateXaml);

				tipStyle = new Style(typeof(ToolTip));
				tipStyle.Setters.Add(new Setter(Control.TemplateProperty,        tipTemplate));
				tipStyle.Setters.Add(new Setter(Control.PaddingProperty,         new Thickness(6, 2, 6, 2)));
				// Colors track NT's chart skin so the tooltip looks like every
				// other panel element instead of the Windows yellow InfoBrush.
				// Replacing the ControlTemplate (above) bypassed NT's default
				// tooltip skin, so we have to re-supply the colors here.
				System.Windows.Media.Brush tipBg = ChartControl != null
					? ChartControl.Properties.ChartBackground
					: SystemColors.InfoBrush;
				System.Windows.Media.Brush tipFg = ChartControl != null
					? ChartControl.Properties.ChartText
					: SystemColors.InfoTextBrush;
				tipStyle.Setters.Add(new Setter(Control.BackgroundProperty,      tipBg));
				tipStyle.Setters.Add(new Setter(Control.ForegroundProperty,      tipFg));
				tipStyle.Setters.Add(new Setter(Control.BorderBrushProperty,     tipFg));
				tipStyle.Setters.Add(new Setter(Control.BorderThicknessProperty, new Thickness(1)));
				tipStyle.Setters.Add(new Setter(ToolTip.HasDropShadowProperty,   false));
				tipStyle.Setters.Add(new Setter(FrameworkElement.MinWidthProperty,  0d));
				tipStyle.Setters.Add(new Setter(FrameworkElement.MinHeightProperty, 0d));
				tipStyle.Setters.Add(new Setter(FrameworkElement.HorizontalAlignmentProperty, HorizontalAlignment.Left));
				tipStyle.Setters.Add(new Setter(Control.HorizontalContentAlignmentProperty,   HorizontalAlignment.Left));

				if (ChartControl != null && !ChartControl.Resources.Contains(typeof(ToolTip)))
					ChartControl.Resources.Add(typeof(ToolTip), tipStyle);
			}
			return new ToolTip { Style = tipStyle };
		}

		// Convenience overload: returns a styled ToolTip pre-populated with `content`.
		// Use this in place of `obj.ToolTip = "some string"` so the system default
		// template (with extra trailing dead space) isn't used.
		private ToolTip MakeToolTip(string content)
		{
			var t = MakeToolTip();
			t.Content = content;
			return t;
		}

		// True when the ATM strategy name shown in the (closed) selector is
		// clipped — its rendered width exceeds the room the combo gives it.
		// fullName is always set to the complete name. Used by the selector's
		// ToolTipOpening handler so the full-name tooltip appears only when the
		// name isn't already fully visible.
		private bool IsAtmSelectorNameTruncated(out string fullName)
		{
			fullName = "";
			if (atmStrategySelector == null)
				return false;

			// Preferred path: measure against the actual on-screen TextBlock.
			// Its Text is exactly what the user sees (WPF TextTrimming leaves
			// Text complete but renders an ellipsis), and ActualWidth is the
			// real space the combo allotted it.
			System.Windows.Controls.TextBlock tb = FindFirstVisibleTextBlock(atmStrategySelector);
			if (tb != null && tb.ActualWidth > 0 && !string.IsNullOrEmpty(tb.Text))
			{
				fullName = tb.Text;
				double natural = MeasureWpfTextWidth(tb.Text, tb.FontFamily,
					tb.FontStyle, tb.FontWeight, tb.FontStretch, tb.FontSize);
				double avail = tb.ActualWidth - tb.Padding.Left - tb.Padding.Right;
				return natural > avail + 1.0;
			}

			// Fallback (no display TextBlock found): measure the ATM display
			// name against the combo's content width, minus an estimate for the
			// dropdown arrow and border/padding chrome.
			var atm = atmStrategySelector.SelectedAtmStrategy;
			if (atm == null || string.IsNullOrEmpty(atm.DisplayName))
				return false;
			fullName = atm.DisplayName;
			double availFallback = atmStrategySelector.ActualWidth - 24;
			if (availFallback <= 0)
				return false;
			double w = MeasureWpfTextWidth(fullName, atmStrategySelector.FontFamily,
				atmStrategySelector.FontStyle, atmStrategySelector.FontWeight,
				atmStrategySelector.FontStretch, atmStrategySelector.FontSize);
			return w > availFallback;
		}

		// Width in DIPs the text occupies when drawn unconstrained — compared
		// against a control's constrained width to detect clipping. The 7-arg
		// FormattedText overload (pixelsPerDip = 1.0) keeps the result in the
		// same DIP units as ActualWidth.
		private double MeasureWpfTextWidth(string text, System.Windows.Media.FontFamily family,
			System.Windows.FontStyle style, System.Windows.FontWeight weight,
			System.Windows.FontStretch stretch, double fontSize)
		{
			if (string.IsNullOrEmpty(text))
				return 0;
			System.Windows.Media.Typeface typeface =
				new System.Windows.Media.Typeface(family, style, weight, stretch);
			System.Windows.Media.FormattedText ft = new System.Windows.Media.FormattedText(
				text,
				System.Globalization.CultureInfo.CurrentCulture,
				System.Windows.FlowDirection.LeftToRight,
				typeface,
				fontSize > 0 ? fontSize : 12,
				System.Windows.Media.Brushes.Black,
				1.0);
			return ft.Width;
		}

		// Depth-first search for the first laid-out, non-empty TextBlock in a
		// visual tree. ComboBox dropdown items live in a Popup (a separate
		// visual tree VisualTreeHelper does not descend into), so on a closed
		// combo this returns the selection-box text and never a list item.
		private System.Windows.Controls.TextBlock FindFirstVisibleTextBlock(System.Windows.DependencyObject parent)
		{
			if (parent == null)
				return null;
			int count = System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent);
			for (int i = 0; i < count; i++)
			{
				System.Windows.DependencyObject child =
					System.Windows.Media.VisualTreeHelper.GetChild(parent, i);
				System.Windows.Controls.TextBlock tb = child as System.Windows.Controls.TextBlock;
				if (tb != null && tb.IsVisible && !string.IsNullOrEmpty(tb.Text))
					return tb;
				System.Windows.Controls.TextBlock found = FindFirstVisibleTextBlock(child);
				if (found != null)
					return found;
			}
			return null;
		}

