		private void ResetCustomATMStrategy()
		{
			
			if (atmStrategySelector.SelectedAtmStrategy != null)
			if (atmStrategySelector.SelectedIndex == 1 + NumberOfActiveStrategies())	
			
							{
								// is Custom - and wasn't modified - then automatically adjust Target 1 and Stop 1 to 20 ticks.
								
									int thiscount = 0;
								
								
								
									//Print(atmStrategySelector.SelectedAtmStrategy.Brackets.Length);
								
									if (atmStrategySelector.SelectedAtmStrategy.Brackets.Length == 1)
									foreach( Bracket bb in atmStrategySelector.SelectedAtmStrategy.Brackets)
									{
										thiscount = thiscount + 1;
										
										if (thiscount == 1)
										{
											if (bb.Target == 0 && bb.StopLoss == 1)
											{
												// 20 ticks default; convert to whatever native units the ATM uses.
												var customAtm = atmStrategySelector.SelectedAtmStrategy;
												double customEntryRef = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
												double twentyInUnits = TicksToBracketUnits(20, customAtm, customEntryRef);
												bb.StopLoss = twentyInUnits;
												bb.Target   = twentyInUnits;
											}

										}
										
										
										//Print(bb.Target);
										//bb.Target = 5;
										
									}
								
								
							}
										
			
		}
		
		private bool CheckNewTradeReady()
		{

			if (!AccountIsInitalized)
				return true;

			// If OnConnectionStatusUpdate never fired (indicator loaded after a connection was
			// already established), the `connected` flag can still be false even though real
			// data is flowing. Self-heal from MarketDataOK or live Connection state before
			// falsely telling the user they must connect to a data feed.
			if (!connected)
			{
				if (MarketDataOK)
				{
					connected = true;
				}
				else
				{
					try
					{
						var mi = Instrument != null ? Instrument.MasterInstrument : null;
						if (mi != null)
						{
							lock (Connection.Connections)
							{
								for (int ci = 0; ci < Connection.Connections.Count; ci++)
								{
									var c = Connection.Connections[ci];
									if (c != null
										&& c.Status == ConnectionStatus.Connected
										&& c.InstrumentTypes != null
										&& c.InstrumentTypes.Contains(mi.InstrumentType))
									{
										connected = true;
										break;
									}
								}
							}
						}
					}
					catch (Exception) { }
				}
			}

			if (!connected)
			{
				AddMessage("You must connect to a data feed to use the Enhanced Chart Trader.", 10, Brushes.Red);
				return false;
			}


			if (myAccount == null)
			{
				AddMessage("You must select an account to use the Enhanced Chart Trader.", 10, Brushes.Red);
				return false;
			}


			if (!MarketDataOK && myAccount.Provider != Provider.Simulator && myAccount.Provider != Provider.Playback)
			{
				AddMessage("There is no market data available to route live entry orders.", 10, Brushes.Red);
				return false;
			}


			//ResetCustomATMStrategy();


			if (pRequireATM)
			{

				if (atmStrategySelector.SelectedAtmStrategy == null)
				{

					AddMessage(ATMStrategyRequiredMessage, 6, Brushes.Red);

					return false;
					
				
				
//					if (pLastATMSelectedS == "None")
//					{
//						AddMessage(ATMStrategyRequiredMessage, 6, Brushes.Red);
//						return false;
//					}
//					else
//					{
//						ATMToggle(); 
//					}
				
					
					
					
			
					
				}
			}
				
			return true;
		}
			
	
