		public override void OnCalculateMinMax()
		{

				if (!pScaleByOrders && !pScaleByATM)
				return;
			
		
			//return;
			
			// testing values update
			
//			MinValue = 20600+iiiiiii;
//			MaxValue = 20900+iiiiiii;
//			ChartControl.InvalidateVisual();
//			return;
			
			//Print("OnCalculateMinMax");
			
			// make sure to always start fresh values to calculate new min/max values
			  double tmpMin = double.MaxValue;
			  double tmpMax = double.MinValue;
			 
			  // For performance optimization, only loop through what is viewable on the chart
			  for (int index = ChartBars.FromIndex; index <= ChartBars.ToIndex; index++)
			  {
			    // since using Close[0] is not guaranteed to be in sync
			    // retrieve "Close" value at the current viewable range index
			    double plotValue1 = High.GetValueAt(index);
			 	double plotValue2 = Low.GetValueAt(index);
				  
				  
			    // return min/max of close value
			    tmpMin = Math.Min(tmpMin, plotValue2);
			    tmpMax = Math.Max(tmpMax, plotValue1);

				  
			  }
				 
				  
				  double total = tmpMax - tmpMin;
				  // percent
				  
				  tmpMax = tmpMax + total*(6/100);
				  tmpMin = tmpMin - total*(6/100);
			  
			  
			  // Finally, set the minimum and maximum Y-Axis values to +/- 50 ticks from the primary close value
			  //MinValue = tmpMin - 50 * TickSize;
			 // MaxValue = tmpMax + 50 * TickSize;
			  
			 // MaxValue = 20150;
			//  MinValue = 19800;
			  
			//Print(MaxValue);
			//Print(MinValue);
			
		

			  
//			  Print("MaxOrderDisplay " + MaxOrderDisplay);
//			  Print("MinOrderDisplay " + MinOrderDisplay);
			  
//			  Print("MaxValue " + MaxValue);
//			  Print("MinValue " + MinValue);			  
			  
		//	  return;
			  
			  
			  
			  if (pScaleByOrders)
			  {
			
				  if (MaxOrderDisplay != 0)
				 	tmpMax = Math.Max(MaxOrderDisplay, tmpMax);

				  if (MinOrderDisplay != 100000000)
				 	tmpMin = Math.Min(MinOrderDisplay, tmpMin);
						
				
			  }
			  
		
			  if (!BuyClickReady && !SellClickReady)
			  if (pScaleByATM)
			  {
			  
				  if (MaxATMPlanningDisplay != 0)
				 	tmpMax = Math.Max(MaxATMPlanningDisplay, tmpMax);
				  
				  if (MinATMPlanningDisplay != 100000000)
				 	tmpMin = Math.Min(MinATMPlanningDisplay, tmpMin);
			 
				  
			  }
				  
			  
			  MaxValue = tmpMax;
			  MinValue = tmpMin;
			  
			  
			  
//			 // IsChanged = false;
			  
//			  if (PrevHigh != MaxValue || PrevLow != MinValue)
//			  {
////				  Print("CHANGED");
				  
////				  Print("Final MaxValue " + MaxValue);
			 
////				  Print("Final MinValue " + MinValue);	
				  
				  
				  
//				 // ChartControl.InvalidateVisual();
				  
//			  }
			  
			  
				 
//			PrevHigh = MaxValue;
//			PrevLow = MinValue;
			
			  
			  
		  
  
		}
		
		
		
