				pTSOffsetATR = Math.Max(0, OffsetBox10.Value*ThisSizeOffset);
				OffsetBox10.Value = pTSOffsetATR;
			}
			//else if (cb5.SelectedIndex == 2)
			else if (pTrailingStopType == "High / Low")
			{
				//pTrailingStopType = "High / Low";
				pTSOffsetBar = Math.Max(0, OffsetBox10.Value*ThisSizeOffset);
				OffsetBox10.Value = pTSOffsetBar;
			}
			else
			{
				//pTrailingStopType = "Indicator";
				//pTSOffsetIndicator = OffsetBox10.Value * ThisSizeOffset;
				
				
				
				
				
				// saved offset for custom stops
				
				int trailingstoparraynumber = cb5.SelectedIndex-totaltrailingstoptypes;
				
				
				
				pAllTrailingStopsOffsets[trailingstoparraynumber] = OffsetBox10.Value * ThisSizeOffset;
				
				
				
				
			}
			
			
			// trailing stop offset adjustment
		
			if (pTrailingStopIsEnabled)
			{
		
				if (pTrailingStopChangeMode == "Immediately")
					UpdateTrailingStopNow(true, true);
				if (pTrailingStopChangeMode == "Decrease Only")
					UpdateTrailingStopNow(true, false);

			}
				
			
				
				
//			if (pTrailingStopIsEnabled)
//			if (UpdateNow)
