//				pTrailingStopOffset = OffsetBox10.Value * ThisSizeOffset;
				
			
				
//				TrackStopLossOrders2(pTrailingStopIndicator, pTrailingStopPlot, "+-");
							

				
//			}
//			UpdateNow = true;	
			
			
			
			
			
			UpdateButtons();
			RefreshRender(44);
		}		
						
 	
