		private void TrailingStopButtonClick()
		{
			LogDiag("TRAILING", "ButtonClick");
			if (!pTrailingStopIsEnabled)
			if (!CheckNewTradeReady())
			{
				RefreshRender(44);
				return;
			}
							
			pTrailingStopIsEnabled = !pTrailingStopIsEnabled;
							
			if (ConfiguringTrailingStop != -1)
				pTrailingStopIsEnabled = false;
			
			

			
			// trailing stop button on off
			
			if (pTrailingStopIsEnabled)
			{
				
				
				if (pAttachmentOrdersButtonOK)
					UnattachAllStops();
				

				if (pTrailingStopChangeMode == "Immediately")
					UpdateTrailingStopNow(true, true);
				if (pTrailingStopChangeMode == "Decrease Only")
					UpdateTrailingStopNow(true, false);

				
				IgnoreNextLog = true;
				
				
				TurnOffTrailingStops();
				
				//pTrailingStopIsEnabled = true;
				
				//Log(LogIndicatorDisplayName + " | " + myAccount.Name + " | " + Instrument.FullName + " | " + "Trailing Stop Is Enabled", LogLevel.Information);
				
			}
			
			
				//TrackStopLossOrders(pTrailingStopIsEnabled, pTrailingStopIndicator, pTrailingStopPlot);
				
				//TrackStopLossOrders2(pTrailingStopIndicator, pTrailingStopPlot, "On Off");
			
				UpdateButtons();			
			
			
		}
		
