	private string GetTrailingStopName(int trailingstoparraynumber)
		{
			
			//Print(trailingstoparraynumber);
		
					
					int LongInd = pAllTrailingStopsIndicator[trailingstoparraynumber];
					int ShortInd = pAllTrailingStopsIndicator2[trailingstoparraynumber];
					int LongPlot = pAllTrailingStopsPlot[trailingstoparraynumber];
					int ShortPlot = pAllTrailingStopsPlot2[trailingstoparraynumber];
					
					string LongIndS = GetThisIndicatorName(LongInd);
					string ShortIndS = GetThisIndicatorName(ShortInd);
					string LongPlotS = GetThisPlotName(LongInd, LongPlot, false);
					string ShortPlotS = GetThisPlotName(ShortInd, ShortPlot, false);
					
					
					//Print("LongInd " + LongInd);
					//Print("ShortInd " + ShortInd);
					
					if (LongInd == ShortInd)
					{
						
						if (LongPlotS == ShortPlotS)
						{
							string LongFinalName2 = LongIndS + " – Long & Short: " + LongPlotS;
							
//							if (LongIndS == LongPlotS)
//								LongFinalName2 = "Long & Short: " + LongPlotS;
//							if (LongPlotS.Contains(LongIndS))
//								LongFinalName2 = "Long & Short: " + LongPlotS;
						
							
							if (LongIndS == LongPlotS)
								LongFinalName2 = LongPlotS + " – Long & Short";
							if (LongPlotS.Contains(LongIndS))
								LongFinalName2 = LongPlotS + " – Long & Short";
						
							
							return LongFinalName2;
							
						}
						else
						{	
							
							return LongIndS +  " –" + " Long: " + LongPlotS + " | Short: " + ShortPlotS;
						}
						
						
					}
					else
					{
						
						string LongFinalName = LongIndS + " " + LongPlotS;
						string ShortFinalName = ShortIndS + " " + ShortPlotS;
						
						if (LongIndS == LongPlotS)
							LongFinalName = LongIndS;
						
						if (LongPlotS.Contains(LongIndS))
							LongFinalName = LongPlotS;
						
						if (ShortIndS == ShortPlotS)
							ShortFinalName = ShortIndS;
						
						if (ShortPlotS.Contains(ShortIndS))
							ShortFinalName = ShortPlotS;
						
						
						return "Long: " + LongFinalName + " | Short: " + ShortFinalName;
						
					}
							
					
			
		}
		
		
		
		
		
		
		private void AddTrailingStopMessage(int trailingstoparraynumber, string Action)
		{
		
			//string thisnammeeee = GetTrailingStopName(trailingstoparraynumber);
		
			//string thisnammeeee = pAllTrailingStopsGeneratedName[trailingstoparraynumber];
			
			string thisnammeeee = string.Empty;
			
			
			if (thisnammeeee == "")
				thisnammeeee = GetTrailingStopName(trailingstoparraynumber);
			
			
			RemoveMessage(false, "Trailing Stop ");
			AddMessage("Trailing Stop " + Action + " – " + thisnammeeee, 5, Brushes.Goldenrod);	
			
		}
		
		
