		// position sizing on and off
		
		internal void toggle13_PreviewMouseUp (object sender, MouseButtonEventArgs e)
        {

			if (e.ChangedButton == MouseButton.Left)
			{	
				
	
				pPositionSizingIsEnabled = !pPositionSizingIsEnabled; 
				
				

//				if (!pPositionSizingIsEnabled)
//					ResetAllATMStrategies();
				
//				if (pATMQuickButtonsEnabled)
//					SetATMButtonLabels();
						
				if (pPositionSizingIsEnabled)
				{
					qudSelector.Minimum = pPositionSizingMinSize;
					qudSelector.Maximum = pPositionSizingMaxSize;
				}
				else
				{
					qudSelector.Minimum = pPositionSizingMinSize;
					qudSelector.Maximum = 1000000;					
					
				}
				
			    if (pPositionSizingIsEnabled)
				{
					PositionSizingAdjustQuantities(true, atmStrategySelector.SelectedAtmStrategy, true);
					
					if (pATMQuickButtonsEnabled)
						SetATMButtonLabels();
					
					
					
					//Print("pPositionSizingIsEnabled " + pPositionSizingIsEnabled);
				}
				else
				{
				
		
					DisablePositionSizing("6");
				
					//Print("pPositionSizingIsEnabled " + pPositionSizingIsEnabled);
					
					
					
					//	When turning size off, change quantity back to selected atm qty
					
					 
					ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, true, false);
					
					
//					if (atmStrategySelector.SelectedAtmStrategy != null)
//					if (qudSelector.Value != atmStrategySelector.SelectedAtmStrategy.EntryQuantity)
//					{
						

						
//						qudSelector.Value = atmStrategySelector.SelectedAtmStrategy.EntryQuantity;
						
						
						
//						RemoveMessage(false, PSAdjustedMessage);
//						AddMessage(PSAdjustedMessage + pLastQuantity.ToString() + PSAdjustedContacts, 5, Brushes.Goldenrod);
						
						
//					}
					
				}
			
				if (AllCustomOrders.Count != 0)
				{
					foreach (KeyValuePair<double, CustomOrderDetails> ZZ in AllCustomOrders)
					{
						if (ZZ.Value.IsLinked)
							ZZ.Value.Qty = pQty;
						
					}
					
				}
				
				
				
				foreach (Order or in LinkedOrders.ToList())
				{
		
					if (or.Quantity != pQty)
					{	
						UpdateOrderQty1(or, pQty);

					}
				}		
	   
				
				UpdateButtons();
				RefreshRender(206);				
	
			}
			
			
		}
		
		
		
		
