		private bool SkipSetLastSelectedATM = false;
		
		public void ATMToggle ()
		{
			
			
				if (IsFreeEditionNinjaTrader)
				{
					
					pFreeATMEnabled = !pFreeATMEnabled;
	
					if (pFreeATMEnabled)
					{
					
						pFreeSLEnabled = true;
						pFreePTEnabled = true;
						
					}
					
				}
				else
				{
	
			
					
					
					if (atmStrategySelector.SelectedIndex == 2 + NumberOfActiveStrategies()) // NONE
					{
						
						//Print("TOGGLE NONE " + pLastATMSelectedS);
						
						SetATM (pLastATMSelectedS);
						
						pPositionSizingIsEnabled = LastPositionSizingStatus;
					}					
					else if (atmStrategySelector.SelectedIndex == 1 + NumberOfActiveStrategies()) // CUSTOM
					{
					
						LastPositionSizingStatus = pPositionSizingIsEnabled;
						
						
						//DisablePositionSizing();
					
						
						SkipSetLastSelectedATM = true;
						
						SetATM ("None");
					
						
					}	
					
					else if (atmStrategySelector.SelectedIndex > 3 + NumberOfActiveStrategies()) // OTHER NOT ACTIVE ATM
					{

						//Print(atmStrategySelector.SelectedAtmStrategy.DisplayName);


						bool ATMIS = true;


						ATMIS = ATMIsSame(atmStrategySelector.SelectedAtmStrategy, null);

						// Include stop-strategy drafts in the "is dirty?" decision so
						// pending draft edits also count as a reset-needed condition.
						bool hasDrafts = AtmHasStopStrategyDrafts(atmStrategySelector.SelectedAtmStrategy);

						if (!ATMIS || hasDrafts || pMarketPlanActive)
						{

							//PrintATM(DefaultAtmStrategy[atmStrategySelector.SelectedAtmStrategy.DisplayName]);


							ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, false, true);

							// Wipe any per-trade stop-strategy drafts too — the user
							// just asked to reset the ATM and those drafts are part of
							// the "dirty state" they want cleared.
							ClearStopStrategyDrafts();

							// Snap Initial Exits source back to Default. The reset
							// button means "use the ATM template's saved settings" —
							// any active ATR / High-Low override is part of the dirty
							// state and would keep recomputing stops/targets after the
							// reset, fighting with the user's intent.
							if (pInitialExitsType != "Default")
								pInitialExitsType = "Default";

							pMarketPlanActive = false;
							pMarketPlanActiveSaved = pMarketPlanActive;

							foreach (Order or in LinkedOrders.ToList())
							{

								ResetATMStrategy(or);
							}

						}
						else
						{
						
						
							//ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, false,true);
							
							//pLastATMSelected = atmStrategySelector.SelectedIndex;
							//pLastATMSelectedS = atmStrategySelector.SelectedAtmStrategy.Name;
							
							
							//pLastATMSelectedS = SelectedIndexToATMName[atmStrategySelector.SelectedIndex];
							
							
							
					
							LastPositionSizingStatus = pPositionSizingIsEnabled;
							
							
							//DisablePositionSizing();
						
							
							SkipSetLastSelectedATM = true;
							
							SetATM ("None");
							
						}
						
					}

					else
					{
						//atmStrategySelector.SelectedIndex = 2;
						
					}
								
				
				}
				
				
				

				UpdateButtons();
				RefreshRender(211);
			//RefreshRender(2);

		}

		// Auto-reset the ATM Strategy to its default (equivalent to clicking
		// the "X" button next to the ATM selector) when the account goes
		// completely flat AND there are no working orders left for this
		// instrument. Only acts when the ATM is "dirty" — differs from the
		// template, has per-trade stop-strategy drafts, or pMarketPlanActive
		// is set. Safe no-op in every other case. Called from OnPosition-
		// Update2 / OnOrderUpdate2 via Dispatcher.InvokeAsync so it runs on
		// the UI thread.
		private void TryAutoResetATMOnFlatAndEmpty()
		{
			if (atmStrategySelector == null || atmStrategySelector.SelectedAtmStrategy == null)
				return;

			// Position must be flat.
			Position pos = ThisPositionNow();
			if (pos != null && pos.MarketPosition != MarketPosition.Flat)
				return;

			// No working / pending-state orders for this instrument.
			if (myAccount == null || ThisInstrumment == null)
				return;
			foreach (Order or in myAccount.Orders.ToList())
			{
				if (or.Instrument == null || or.Instrument.FullName != ThisInstrumment.FullName)
					continue;
				if (or.OrderState == OrderState.Working
					|| or.OrderState == OrderState.Accepted
					|| or.OrderState == OrderState.ChangePending
					|| or.OrderState == OrderState.ChangeSubmitted
					|| or.OrderState == OrderState.CancelPending
					|| or.OrderState == OrderState.CancelSubmitted
					|| or.OrderState == OrderState.TriggerPending)
					return;
			}

			// Nothing to clean up?
			bool ATMIS = ATMIsSame(atmStrategySelector.SelectedAtmStrategy, null);
			bool hasDrafts = AtmHasStopStrategyDrafts(atmStrategySelector.SelectedAtmStrategy);
			if (ATMIS && !hasDrafts && !pMarketPlanActive)
				return;

			// Mirrors ATMToggle() dirty-branch behavior at :12666.
			ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, false, true);
			ClearStopStrategyDrafts();
			pMarketPlanActive = false;
			pMarketPlanActiveSaved = pMarketPlanActive;

			foreach (Order or in LinkedOrders.ToList())
			{
				ResetATMStrategy(or);
			}

			UpdateButtons();
			RefreshRender(999);
		}

