		// Expiry timestamps for the PC hover preview. Set to MaxValue while
		// the mouse is over the button (preview stays) and pushed to
		// Now + pShowPlanSeconds333 on MouseLeave so the preview decays the
		// same way Market / Limit / Close Bar do. OnRender drops IsInPCBuy /
		// IsInPCSell once these elapse.
		private DateTime _pcBuyPreviewExpiresAt = DateTime.MinValue;
		private DateTime _pcSellPreviewExpiresAt = DateTime.MinValue;

		// Separate from IsInPCBuy / IsInPCSell: these track whether the mouse
		// is *actually* over the Price-Based button right now. The synthetic
		// order flag (DrawClickEntry) is gated on these so it disappears the
		// instant the mouse leaves the button, while the ATM plan continues to
		// render via IsInPCBuy / IsInPCSell until _pcBuyPreviewExpiresAt /
		// _pcSellPreviewExpiresAt elapse (giving it the normal timeout fade).
		private bool _pcBuyHovering = false;
		private bool _pcSellHovering = false;

		// Generalized hover-preview state for the non-Price-Based entry
		// buttons (Market / Limit1 / Limit2 / Close Bar / Signal). Each
		// button's MouseEnter fills these with a price-computation delegate
		// + the order-type label, and OnRender invokes the delegate every
		// frame so the synthetic flag tracks the market in realtime (Market
		// follows Bid/Ask, Limit follows the basis + offset, Close Bar /
		// Signal follows the chosen bar basis). Entry-row decorations
		// (Hide / qty / order-type label) are suppressed on the sentinel
		// plan while _hoverPreviewActive is true so the synthetic flag
		// isn't doubled.
		private bool _hoverPreviewActive = false;
		private System.Func<double> _hoverPreviewPriceFn = null;
		private string _hoverPreviewClickText = "";
		private bool _hoverPreviewIsBuy = true;
		
		
