		/// True if the panel was actively scrolling within the last ~400ms. Button-level
		/// wheel handlers check this and yield to keep the panel scroll smooth instead
		/// of abruptly hijacking into button-adjust mode when the cursor crosses a button.
		private bool IsPanelScrollingRecently()
		{
			return (DateTime.Now - lastPanelScrollTime).TotalMilliseconds < 800;
		}

		private void button20_PreviewMouseWheel(object sender, MouseWheelEventArgs e)
		{
			if (IsPanelScrollingRecently()) return; // yield to ongoing panel scroll


			e.Handled = true;
		}
			
			
		private void button13_PreviewMouseWheel(object sender, MouseWheelEventArgs e)
		{
			if (IsPanelScrollingRecently()) return; // yield to ongoing panel scroll

			if (pCloseButtonType == "BE")
			{
				if (e.Delta > 0)
					pBEOffset = pBEOffset + 1;
				else
					pBEOffset = pBEOffset - 1;

				UpdateButtons();
			}

			if (pCloseButtonType == "Close Partial")
			{
				if (e.Delta > 0)
					CloseButtonNumber = CloseButtonNumber + 1;
				else
					CloseButtonNumber = CloseButtonNumber - 1;

				if (CloseButtonNumber == 0)
					CloseButtonNumber = 3;

				if (CloseButtonNumber == 4)
					CloseButtonNumber = 1;

				UpdateButtons();
			}

			// Consume the wheel event so the panel ScrollViewer doesn't scroll too
			e.Handled = true;
		}
					
			 
		
