		// Price-Based Entry Orders (button37/38) — shows the ATM Strategy plan
		// preview AND a synthetic order line at the actual entry price the
		// click would place (NextOrderHigh + pOffsetTicks for Long, NextOrderLow
		// - pOffsetTicks for Short). The IsInPCBuy / IsInPCSell flags drive the
		// OnRender PC-preview branch which adds an EntryOrder at the computed
		// price; the OnRender expiry check at _pcBuyPreviewExpiresAt /
		// _pcSellPreviewExpiresAt drops the flag once the timer fires, so the
		// preview fades the same way the ATM plan does on MouseLeave.
        internal void Button37_MouseEnter (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			if (DateTime.Now <= ClickedMarketLimitTime)
				return;

			// IsInPCBuy drives the OnRender PC plan branch (line ~66943) that
			// adds the EntryOrder at the actual entry price. _pcBuyHovering
			// drives the DrawClickEntry call so the synthetic flag is only
			// visible while the mouse is on the button. Don't call ShowPlan
			// here — it triggers AddNextOrder which adds a duplicate sentinel
			// EntryOrder at price 10, producing a second ATM plan on screen.
			IsInPCBuy = true;
			IsInPCSell = false;
			_pcBuyHovering = true;
			_pcSellHovering = false;
			_pcBuyPreviewExpiresAt = DateTime.Now.AddSeconds(10000);
			_pcSellPreviewExpiresAt = DateTime.MinValue;

			// Cancel any active Market / Limit / Close Bar / Signal hover so
			// the most-recent button wins the on-chart plan.
			ClearEntryHoverPreview();

			// Preview Entry-label type matches the Price-Based execution mode.
			_previewEntryTypeOverride = pUseSLMStopEntry ? "SLM" : "STP";

			pLastPlanDirection = "Long";

			RefreshRender(4);
		}


        internal void Button37_MouseLeave (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			// Synthetic order flag goes away the instant the mouse leaves —
			// matches Buy Click / Sell Click cursor preview behavior.
			_pcBuyHovering = false;

			// ATM plan keeps rendering until the timer expires (OnRender drops
			// IsInPCBuy at line ~63704 once Now >= _pcBuyPreviewExpiresAt).
			_pcBuyPreviewExpiresAt = DateTime.Now.AddSeconds(pShowPlanSeconds333);

			RefreshRender(5);
		}


        internal void Button38_MouseEnter (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			if (DateTime.Now <= ClickedMarketLimitTime)
				return;

			IsInPCBuy = false;
			IsInPCSell = true;
			_pcBuyHovering = false;
			_pcSellHovering = true;
			_pcBuyPreviewExpiresAt = DateTime.MinValue;
			_pcSellPreviewExpiresAt = DateTime.Now.AddSeconds(10000);

			// Cancel any active Market / Limit / Close Bar / Signal hover.
			ClearEntryHoverPreview();

			_previewEntryTypeOverride = pUseSLMStopEntry ? "SLM" : "STP";

			pLastPlanDirection = "Short";

			RefreshRender(6);
		}


        internal void Button38_MouseLeave (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			_pcSellHovering = false;
			_pcSellPreviewExpiresAt = DateTime.Now.AddSeconds(pShowPlanSeconds333);

			RefreshRender(219);
		}
		
		
		
