			if (!CheckNewTradeReady())
				return;

			if (DateTime.Now <= ClickedMarketLimitTime)
				return;

			// Cancel any active Price-Based hover so the previous PC plan
			// doesn't fight back through the OnRender PC branch.
			IsInPCBuy = false;
			IsInPCSell = false;
			_pcBuyHovering = false;
			_pcSellHovering = false;
			_pcBuyPreviewExpiresAt = DateTime.MinValue;
			_pcSellPreviewExpiresAt = DateTime.MinValue;

			// Resolve which button fired so the preview Entry label reads
			// "MKT" / "LMT" / "MIT" per the button's configured type.
			_previewEntryTypeOverride = ResolveBuyMarketLimitPreviewType(sender);

			// Live price-computation delegate so OnRender re-evaluates each
			// frame and the synthetic flag tracks the market.
			System.Func<double> priceFn = null;
			string clickTxt = "MKT";
			if (sender == button1)
			{
				priceFn = () => CurrentAsk;
				clickTxt = "MKT";
			}
			else if (sender == button14)
			{
				priceFn = () => ComputeBuyLimitPreviewPrice(pLimitOrderOffset4, pLimit1EntryBasis);
				clickTxt = NormalizePreviewOrderType(pLimit1EntryType);
			}
			else if (sender == button16)
			{
				priceFn = () => ComputeBuyLimitPreviewPrice(pLimitOrderOffset5, pLimit2EntryBasis);
				clickTxt = NormalizePreviewOrderType(pLimit2EntryType);
			}
			SetEntryHoverPreview(true, priceFn, clickTxt);

			if (GetAllNonExitOrders(false) == 0 || pAllowMultiplePlans)
			{
				ShowPlan(true, "Long");
			}

			RefreshRender(223);

		}

		// Normalize a Limit-type combo value to the 3-letter abbreviation used
		// elsewhere in the plan preview ("Limit" → "LMT", others pass through).
		// Only "Limit" needs translation — "MIT", "LIT", "STP", etc. are
		// already abbreviated in the combo items.
		private string NormalizePreviewOrderType(string t)
		{
			if (t == "Limit") return "LMT";
			if (t == "Market") return "MKT";
			return t;
		}

		// Map the WPF sender of a Buy Market/Limit hover to its configured
		// order-type string — used by the preview Entry label so "MKT" /
		// "LMT" / "MIT" all render correctly per button.
		private string ResolveBuyMarketLimitPreviewType(object sender)
		{
			if (sender == button1) return "MKT";
			if (sender == button14) return NormalizePreviewOrderType(pLimit1EntryType);
			if (sender == button16) return NormalizePreviewOrderType(pLimit2EntryType);
			return "";
		}
		private string ResolveSellMarketLimitPreviewType(object sender)
		{
			if (sender == button2) return "MKT";
			if (sender == button15) return NormalizePreviewOrderType(pLimit1EntryType);
			if (sender == button17) return NormalizePreviewOrderType(pLimit2EntryType);
			return "";
		}

		// Buy Limit price formula — mirrors BuyLimitButton at line ~13720.
		private double ComputeBuyLimitPreviewPrice(int offset, string basis)
		{
			double sp = (basis == "Spread" || basis == "Bid") ? CurrentBid : CurrentAsk;
			return RTTS(sp - offset * ThisTickSize);
		}

		// Sell Limit price formula — mirrors SellLimitButton at line ~13770.
		private double ComputeSellLimitPreviewPrice(int offset, string basis)
		{
			double sp = (basis == "Spread" || basis == "Ask") ? CurrentAsk : CurrentBid;
			return RTTS(sp + offset * ThisTickSize);
		}

		// Bar-basis entry price (Close Bar / Signal). Mirrors AddATMPlanEntry's
		// formula at line ~47089 so the synthetic flag lands at the same price
		// the click would actually place.
		private double ComputeBarBasisPreviewPrice(bool isBuy, string basis, int offset, string orderType)
		{
			if (orderType == "MKT" || orderType == "ICE" || orderType == "Market")
				return CurrentLastData;

			bool isLimitType = orderType == "LMT" || orderType == "LIT" || orderType == "MIT" || orderType == "Limit";

			double basePx;
			if (basis == "Close")
				basePx = CurrentLastData;
			else if (basis == "Middle")
				basePx = CurrentLastMiddle;
			else if (basis == "High / Low")
				basePx = isBuy ? CurrentLastHigh : CurrentLastLow;
			else
				basePx = CurrentLastData;

			if (isBuy)
				return RTTS(isLimitType ? basePx - offset * ThisTickSize : basePx + offset * ThisTickSize);
			else
				return RTTS(isLimitType ? basePx + offset * ThisTickSize : basePx - offset * ThisTickSize);
		}

		// Sets the hover-preview state. priceFn is invoked on every render
		// frame so the synthetic flag tracks the market in realtime — pass
		// a closure over the live price source (Bid / Ask / Last / High /
		// Low + offset) rather than a fixed value.
		private void SetEntryHoverPreview(bool isBuy, System.Func<double> priceFn, string clickText)
		{
			_hoverPreviewActive = priceFn != null;
			_hoverPreviewPriceFn = priceFn;
			_hoverPreviewClickText = clickText;
			_hoverPreviewIsBuy = isBuy;
		}

		private void ClearEntryHoverPreview()
		{
			_hoverPreviewActive = false;
			_hoverPreviewPriceFn = null;
		}


        internal void MarketLimitSell_MouseEnter (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			if (DateTime.Now <= ClickedMarketLimitTime)
				return;

			// Cancel any active Price-Based hover (see Buy-side handler).
			IsInPCBuy = false;
			IsInPCSell = false;
			_pcBuyHovering = false;
			_pcSellHovering = false;
			_pcBuyPreviewExpiresAt = DateTime.MinValue;
			_pcSellPreviewExpiresAt = DateTime.MinValue;

			_previewEntryTypeOverride = ResolveSellMarketLimitPreviewType(sender);

			System.Func<double> priceFn = null;
			string clickTxt = "MKT";
			if (sender == button2)
			{
				priceFn = () => CurrentBid;
				clickTxt = "MKT";
			}
			else if (sender == button15)
			{
				priceFn = () => ComputeSellLimitPreviewPrice(pLimitOrderOffset4, pLimit1EntryBasis);
				clickTxt = NormalizePreviewOrderType(pLimit1EntryType);
			}
			else if (sender == button17)
			{
				priceFn = () => ComputeSellLimitPreviewPrice(pLimitOrderOffset5, pLimit2EntryBasis);
				clickTxt = NormalizePreviewOrderType(pLimit2EntryType);
			}
			SetEntryHoverPreview(false, priceFn, clickTxt);

			if (GetAllNonExitOrders(false) == 0 || pAllowMultiplePlans)
			{
				ShowPlan(true, "Short");
			}

			RefreshRender(224);

		}


        internal void MarketLimit_MouseLeave (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			ClearEntryHoverPreview();

//			if (!_hasPlanInProgress)
//				HidePlan(false);

			// MouseEnter shows the preview plan with a 10000-second expiry so
			// it never times out while the mouse is hovering. The Market /
			// Limit hover plan must vanish the instant the mouse leaves the
			// button — no pShowPlanSeconds333 fade-out — so drop the sentinel
			// keys ShowPlan created outright (10 = Long, -10 = Short) instead
			// of bumping them to the timeout. Other sentinel plans (Close Bar,
			// Signal, click-entry) keep their own timers.
			RemoveATMPlanEntry(10);
			RemoveATMPlanEntry(-10);

			RefreshRender(225);
		}
		

			
