        internal void Button7_MouseEnter (object sender, MouseEventArgs e)
        {

			// When Buy/Sell Click is armed the user is setting up an entry — ignore
			// hover behavior on the Buy Click / Sell Click buttons so the plan
			// preview and button styling don't flicker as the mouse crosses them.
			if (BuyClickReady || SellClickReady)
				return;

			if (!CheckNewTradeReady())
				return;

			// Bump sentinel expiry instead of HidePlan. HidePlan was wiping a
			// fresh preview when the mouse crossed the Buy Click button on the
			// way from one hover source to another (Market → Close Bar, etc.),
			// killing the preview between frames. The 6-second expiry handles
			// the "user paused on Buy Click without arming it" case fine.
			if (!_hasPlanInProgress)
			{
				BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);
				RefreshRender(223);
			}

		}
		
		
