		private void BuyLimitButton(int offss, string OT, string pricebasis)
		{
			LogDiag("UI", "BuyLimitButton");
				
			
			if (!CheckNewTradeReady())
					return;				

			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{				

				HidePlan(false);
				pMarketPlanActive = false;
				
				int thisoffset = offss;

				//EntryOrderPrice = RTTS(CurrentLastData - thisoffset*ThisTickSize);
				
				double startingprice = CurrentAsk;
				
				if (pricebasis == "Spread")
					startingprice = CurrentBid;
				
				
				if (pricebasis == "Ask") startingprice = CurrentAsk;
				if (pricebasis == "Bid") startingprice = CurrentBid;	
				
				EntryOrderPrice = startingprice - thisoffset*ThisTickSize;
					
				bool ISMIT = OT == "MIT";

				if (pLinkButtonsIsOn && pLinkOnPlaceOrder) LinkNextOrder = true;

				if (!TestingRejectedStopOrders)
				BuyLimit(pQty, atmStrategySelector.SelectedAtmStrategy, "", RTTS(EntryOrderPrice), pThisEntryLimitClick == "MIT", "Entry");
				
				// testing rejected orders on follower accounts
				
				if (TestingRejectedStopOrders)
				BuyStop(pQty, atmStrategySelector.SelectedAtmStrategy, "", RTTS(EntryOrderPrice-offffffff*ThisTickSize), pUseSLM, pSLOffsetReg, "Entry");
				
				

			}));		
			
			
		}				
				
		private void SellLimitButton(int offss, string OT, string pricebasis)
		{
			LogDiag("UI", "SellLimitButton");
			
			
			if (!CheckNewTradeReady())
					return;				

			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{				

				HidePlan(false);
				pMarketPlanActive = false;
				
				int thisoffset = offss;

				//EntryOrderPrice = RTTS(CurrentLastData - thisoffset*ThisTickSize);

				double startingprice = CurrentBid;
				
				if (pricebasis == "Spread")
					startingprice = CurrentAsk;	
				
				if (pricebasis == "Ask") startingprice = CurrentAsk;
				if (pricebasis == "Bid") startingprice = CurrentBid;	
								
				EntryOrderPrice = startingprice + thisoffset*ThisTickSize;
				
				bool ISMIT = OT == "MIT";

				if (pLinkButtonsIsOn && pLinkOnPlaceOrder) LinkNextOrder = true;
				
				if (!TestingRejectedStopOrders)
				SellLimit(pQty, atmStrategySelector.SelectedAtmStrategy, "", RTTS(EntryOrderPrice), ISMIT, "Entry");
				
				
				if (TestingRejectedStopOrders)
				SellStop(pQty, atmStrategySelector.SelectedAtmStrategy, "", RTTS(EntryOrderPrice+offffffff*ThisTickSize), pUseSLM, pSLOffsetReg, "Entry");
				
								

			}));			
			
		}				
		
		

		
		

		
		
				
