				private void SetBuyTimeSlicedPrice(double ThisPrice, int offset)
				{
					
				
				
					if (TimeSlicedSellPricePending())
						CancelTimeSlicedOrder("Sell");
					
					if (ThisPrice > CurrentAsk)
					{
						BuyTimeSlicedAtOrAbove = ThisPrice - offset*ThisTickSize;
					}       
					else if (ThisPrice < CurrentBid)
					{
						BuyTimeSlicedAtOrBelow = ThisPrice + offset*ThisTickSize;
					}	
					else
					{
						if (TimeSlicedBuyOrderSequence == 0)
							StartTimeSlicedOrder(BuyName, "Price");
					}		

					
					UpdateButtons();	

					
				}			
				
							
				
				private void SetSellTimeSlicedPrice(double ThisPrice, int offset)
				{
					

					
					if (TimeSlicedBuyPricePending())
						CancelTimeSlicedOrder("Buy");
					
					if (ThisPrice > CurrentAsk)
					{
						SellTimeSlicedAtOrAbove = ThisPrice - offset*ThisTickSize;
					}       
					else if (ThisPrice < CurrentBid)
					{
						SellTimeSlicedAtOrBelow = ThisPrice + offset*ThisTickSize;
					}	
					else
					{
						if (TimeSlicedSellOrderSequence == 0)
							StartTimeSlicedOrder(SellName, "Price");
					}	
					
					
					UpdateButtons();					
				
					
				}
				
					
				private double GetLongPrice()
				{
					
		
						if (pTimeSlicedPriceOrderType == "Breakout")
							return RTTS(LastBarHigh + pTimeSlicedPriceOffsetTicks*ThisTickSize);
						else
							return RTTS(LastBarLow - pTimeSlicedPriceOffsetTicks*ThisTickSize);
			
					
				}
				
				private double GetShortPrice()
				{
					
		
						if (pTimeSlicedPriceOrderType == "Pullback")
							return RTTS(LastBarHigh + pTimeSlicedPriceOffsetTicks*ThisTickSize);
						else
							return RTTS(LastBarLow - pTimeSlicedPriceOffsetTicks*ThisTickSize);
			
					
				}
				
				private void StartTimeSlicedLongPriceNow()
				{
				
					SetBuyTimeSlicedPrice(GetLongPrice(), 0);

					if (pTimeSlicedPriceTrailEnabled)
						IsSignalTrailWorking = true;
				
					
				}
				
				
				private void StartTimeSlicedShortPriceNow()
				{
				
					SetSellTimeSlicedPrice(GetShortPrice(), 0);
					
					if (pTimeSlicedPriceTrailEnabled)
						IsSignalTrailWorking = true;
					
				
				}
				
				
				
