        internal void Button9_MouseEnter (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			if (DateTime.Now <= ClickedMarketLimitTime)
				return;

			// Cancel any active Price-Based hover so the most-recent button wins.
			IsInPCBuy = false;
			IsInPCSell = false;
			_pcBuyHovering = false;
			_pcSellHovering = false;
			_pcBuyPreviewExpiresAt = DateTime.MinValue;
			_pcSellPreviewExpiresAt = DateTime.MinValue;

			// Preview label uses the Close Bar entry type.
			_previewEntryTypeOverride = pThisEntryType1;

			SetEntryHoverPreview(true,
				() => ComputeBarBasisPreviewPrice(true, pCloseBarBasis, pLimitOrderOffset1, pThisEntryType1),
				pThisEntryType1);

			if (GetAllNonExitOrders(false) == 0 || pAllowMultiplePlans)
			{
				ShowPlan(true, "Long");
			}

			RefreshRender(223);

		}


