        internal void Button9_MouseLeave (object sender, MouseEventArgs e)
        {

			if (!CheckNewTradeReady())
				return;

			ClearEntryHoverPreview();

			// MouseEnter shows the preview with a 10000-second expiry so it
			// never times out while hovering. When the mouse leaves, bump all
			// sentinel plan timestamps down to pShowPlanSeconds333 so the
			// preview fades away as usual.
			BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);

			RefreshRender(225);
		}


