		protected void Button9_Click(object sender, RoutedEventArgs e)
		{
			if (!CheckNewTradeReady())
				return;
			
			if (pCloseEntryType == "Bar")
			{
				
				ClickedMarketLimitTime = DateTime.MinValue;
			
				if (BuyCloseReady)
			    {
			        BuyCloseReady = false;
					
			
					RemoveATMPlanEntry(10);
			    }
			    else
			    {

					BuyCloseReady = true;
					
					if (pThisEntryType1 == "MKT")
					if (pBuyCloseMode == "All" || pSellCloseMode == "All" || pBuyCloseMode == pSellCloseMode)
					SellCloseReady = false;	
					
					RemoveATMPlanEntry(10);
					AddATMPlanEntry(10, pShowPlanSeconds333);
					RemoveATMPlanEntry(-10);						
						
					
					
					
					
			    }
				
			}
			else
			{
				
				
				
				
	 
					 
					if (BuyCloseClick)
				    {
				        BuyCloseClick = false;
						SelectPlotClickEntry = false;
						
					
						RemoveATMPlanEntry(12);
						
				 
								
				    }
				    else
				    {

						//DrawQTYBox(1,1);

						ResetAllActiveClickOrders();
						

						
						AddATMPlanEntry(12, pShowPlanSeconds333);
						if (myProperties != null)
							myProperties.CrosshairDrawCursorOnly = true;
						
				        BuyCloseClick = true;	

				
						if (pAttachClickEnabled && pAttachmentOrdersButtonOK)
							SelectPlotClickEntry = true;
						
				    }

				
				
			}
				
				
			
			
			UpdateButtons();
			RefreshPriceButtonPulses();
			RefreshRender(9);
		}

		protected void Button10_Click(object sender, RoutedEventArgs e)
		{
			if (!CheckNewTradeReady())
				return;
			
			
			if (pCloseEntryType == "Bar")
			{			
			
				ClickedMarketLimitTime = DateTime.MinValue;
				
				
				if (SellCloseReady)
			    {
			        SellCloseReady = false;
					
					
					RemoveATMPlanEntry(-10);
			    }
			    else
			    {

					if (pThisEntryType1 == "MKT")
					if (pBuyCloseMode == "All" || pSellCloseMode == "All" || pBuyCloseMode == pSellCloseMode)					
					BuyCloseReady = false;
					
					
					SellCloseReady = true;	
					
					RemoveATMPlanEntry(-10);
						AddATMPlanEntry(-10, pShowPlanSeconds333);
						RemoveATMPlanEntry(10);						
					
					
				
					
			    }
				
				
			}
			else
			{
				
				
				
				
			
				
				
				
	 
					 
					if (SellCloseClick)
				    {
				        SellCloseClick = false;
						SelectPlotClickEntry = false;
						
					
						RemoveATMPlanEntry(12);
						
				 
								
				    }
				    else
				    {

						//DrawQTYBox(1,1);

						ResetAllActiveClickOrders();
						

						
						AddATMPlanEntry(12, pShowPlanSeconds333);
						if (myProperties != null)
							myProperties.CrosshairDrawCursorOnly = true;
						
				        SellCloseClick = true;	

				
						if (pAttachClickEnabled && pAttachmentOrdersButtonOK)
							SelectPlotClickEntry = true;
						
				    }

								
				
				
				
				
				
				
			}
				
							
			
			
			UpdateButtons();
			RefreshPriceButtonPulses();
			RefreshRender(232);
		}



