		void SetATMButton2(int i)
		{
			
			if (!DefaultATMSaved())
			{
				// DefaultAtmStrategy not populated yet — use saved ATM names to set button labels directly
				string savedAtmName = string.Empty;
				int savedQty = 0;
				string savedLabel = string.Empty;
				if (pATMRow == 1) { if (i==1) { savedAtmName=pATMSaveS1; savedQty=pATMQty1; savedLabel=pATMLabel1; } if (i==2) { savedAtmName=pATMSaveS2; savedQty=pATMQty2; savedLabel=pATMLabel2; } if (i==3) { savedAtmName=pATMSaveS3; savedQty=pATMQty3; savedLabel=pATMLabel3; } if (i==4) { savedAtmName=pATMSaveS4; savedQty=pATMQty4; savedLabel=pATMLabel4; } }
				else if (pATMRow == 2) { if (i==1) { savedAtmName=pATMSaveS5; savedQty=pATMQty5; savedLabel=pATMLabel5; } if (i==2) { savedAtmName=pATMSaveS6; savedQty=pATMQty6; savedLabel=pATMLabel6; } if (i==3) { savedAtmName=pATMSaveS7; savedQty=pATMQty7; savedLabel=pATMLabel7; } if (i==4) { savedAtmName=pATMSaveS8; savedQty=pATMQty8; savedLabel=pATMLabel8; } }
				else if (pATMRow == 3) { if (i==1) { savedAtmName=pATMSaveS9; savedQty=pATMQty9; savedLabel=pATMLabel9; } if (i==2) { savedAtmName=pATMSaveS010; savedQty=pATMQty010; savedLabel=pATMLabel010; } if (i==3) { savedAtmName=pATMSaveS011; savedQty=pATMQty011; savedLabel=pATMLabel011; } if (i==4) { savedAtmName=pATMSaveS012; savedQty=pATMQty012; savedLabel=pATMLabel012; } }

				if (!string.IsNullOrWhiteSpace(savedAtmName) && savedQty > 0)
				{
					Button btn = (i==1) ? ATMButton1 : (i==2) ? ATMButton2 : (i==3) ? ATMButton3 : ATMButton4;
					if (btn != null)
					{
						btn.Content = !string.IsNullOrWhiteSpace(savedLabel) ? savedLabel : savedQty.ToString();
						if (btn.ToolTip == null) btn.ToolTip = MakeToolTip();
						((ToolTip)btn.ToolTip).Content = savedAtmName;
					}
				}
				return;
			}

			//Print("SetATMButton2  " + i);
			
			
			string finallabel = string.Empty;
			string atmname = string.Empty;
			
			if (pATMRow == 1)
			{
				
				if (i == 1) atmname = pATMSaveS1;
				if (i == 2) atmname = pATMSaveS2;
				if (i == 3) atmname = pATMSaveS3;
				if (i == 4) atmname = pATMSaveS4;				
				
				if (i == 1) finallabel = pATMLabel1;
				if (i == 2) finallabel = pATMLabel2;
				if (i == 3) finallabel = pATMLabel3;
				if (i == 4) finallabel = pATMLabel4;
			
			}
			else if (pATMRow == 2)
			{
				
				if (i == 1) atmname = pATMSaveS5;
				if (i == 2) atmname = pATMSaveS6;
				if (i == 3) atmname = pATMSaveS7;
				if (i == 4) atmname = pATMSaveS8;
				
				if (i == 1) finallabel = pATMLabel5;
				if (i == 2) finallabel = pATMLabel6;
				if (i == 3) finallabel = pATMLabel7;
				if (i == 4) finallabel = pATMLabel8;
				
			}
			else if (pATMRow == 3)
			{
				
				if (i == 1) atmname = pATMSaveS9;
				if (i == 2) atmname = pATMSaveS010;
				if (i == 3) atmname = pATMSaveS011;
				if (i == 4) atmname = pATMSaveS012;
				
				if (i == 1) finallabel = pATMLabel9;
				if (i == 2) finallabel = pATMLabel010;
				if (i == 3) finallabel = pATMLabel011;
				if (i == 4) finallabel = pATMLabel012;
				
			}


			// Trim whitespace from saved ATM name to prevent matching issues
			if (atmname != null) atmname = atmname.Trim();
			if (finallabel != null) finallabel = finallabel.Trim();

			string finallabel2 = "ATM";

			if (finallabel == "BE")
				finallabel2 = "BE";
			
			
			bool atmUseShortInit = pChartTraderWidth < 139;
			if (i == 1 && ATMButton1 != null) ATMButton1.Content = finallabel2 == "ATM" ? (atmUseShortInit ? "A" : "ATM") : finallabel2;
			if (i == 2 && ATMButton2 != null) ATMButton2.Content = finallabel2 == "ATM" ? (atmUseShortInit ? "A" : "ATM") : finallabel2;
			if (i == 3 && ATMButton3 != null) ATMButton3.Content = finallabel2 == "ATM" ? (atmUseShortInit ? "A" : "ATM") : finallabel2;
			if (i == 4 && ATMButton4 != null) ATMButton4.Content = finallabel2 == "ATM" ? (atmUseShortInit ? "A" : "ATM") : finallabel2;
			

	
			if (i == 1) ATMButtonTool1 = MakeToolTip();
			if (i == 2) ATMButtonTool2 = MakeToolTip();
			if (i == 3) ATMButtonTool3 = MakeToolTip();
			if (i == 4) ATMButtonTool4 = MakeToolTip();

			if (!string.IsNullOrWhiteSpace(atmname))
				finallabel2 = atmname.Trim();
			
			//finallabel2 = finallabel2.Replace("ATM", "");

			if (finallabel2 == "ATM")
				finallabel2 = "Set ATM Strategy";
			
			if (i == 1) ATMButtonTool1.Content = finallabel2;
			if (i == 2) ATMButtonTool2.Content = finallabel2;
			if (i == 3) ATMButtonTool3.Content = finallabel2;
			if (i == 4) ATMButtonTool4.Content = finallabel2;

			if (i == 1) ATMButton1.ToolTip = ATMButtonTool1;
			if (i == 2) ATMButton2.ToolTip = ATMButtonTool2;
			if (i == 3) ATMButton3.ToolTip = ATMButtonTool3;
			if (i == 4) ATMButton4.ToolTip = ATMButtonTool4;
			
			
			if (string.IsNullOrWhiteSpace(atmname))
				return;
			
			
			//int selectedindexatm = GetATMIndexFromName(atmname);
			
			
			
			
			int finalstopQtyAtPrice = 0;
		

		
			
			
			
			if (finallabel != string.Empty)
			{
								
				if (i == 1) ATMButton1.Content = finallabel;
				if (i == 2) ATMButton2.Content = finallabel;
				if (i == 3) ATMButton3.Content = finallabel;
				if (i == 4) ATMButton4.Content = finallabel;
			
			}
			else
