				if (!pPositionSizingIsEnabled) 
				{
					
					//Print(selectedindexatm);
					
				
					if (DefaultAtmStrategy.ContainsKey(atmname))						
						finalstopQtyAtPrice = DefaultAtmStrategy[atmname].EntryQuantity;	
					
					
					//Print(finalstopQtyAtPrice);
					
					
				}
				else
