					//Print(selectedindexatm);
					
				
					//if (selectedindexatm != -20)
					
					if (DefaultAtmStrategy.ContainsKey(atmname))
					{
						
						finalstopQtyAtPrice = PositionSizingGetQuantityNew ((AtmStrategy) DefaultAtmStrategy[atmname].Clone());	
					}
					else
					{
					
						//Print("nokey");
					}
					
				
//					Print(i);
//					Print(atmname);
//					Print(finalstopQtyAtPrice);
					
					
					
					
					
				}				
				
				if (finalstopQtyAtPrice != 0)
