				if (i == 1) pATMQty1 = finalstopQtyAtPrice;
				if (i == 2) pATMQty2 = finalstopQtyAtPrice;
				if (i == 3) pATMQty3 = finalstopQtyAtPrice;
				if (i == 4) pATMQty4 = finalstopQtyAtPrice;				

