		internal void ATM_MouseLeave (object sender, MouseEventArgs e)
        {

//			if (!CheckNewTradeReady())
//				return;

			// prevent mouse from clearing plan after clicking in atm strategy selector
			if (DateTime.Now <= ClickedInATMTime)
			{
				return;

			}

			HoveredATMQuickSelect = null;

			// Bump expiry to the short timer instead of HidePlan — HidePlan wipes
			// OrderPriceToATMDisplayEnd via RemoveAllPlanSentinels, which kills a
			// fresh preview between frames when the user is moving the mouse from
			// one preview-emitting button to another. The 6-second expiry handles
			// the "user really left the button area" case without clobbering
			// handoffs between hover sources.
			if (!_hasPlanInProgress)
				BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);
		}
				
		
		
		private void PreviewMouseWheel3 (object sender, MouseWheelEventArgs e)
		{
			if (IsPanelScrollingRecently()) return;

			if (e.Delta < 0)
				pATMRow++;
			else
				pATMRow--;

			pATMRow = Math.Max(pATMRow, 1);
			pATMRow = Math.Min(pATMRow, 3);

			SetATMButtonLabels();
			UpdateButtons();

			e.Handled = true;
		}
		
		
		
