		public void ATM1Click()
		{
			
			
			
			
			ATM1Time = DateTime.Now.AddSeconds(1);
			ATM1Clicks = ATM1Clicks + 1;
			
			ATM2Clicks = 0;
			ATM3Clicks = 0;
			ATM4Clicks = 0;
			
//			if (ATM1Clicks == 3)
//			{
//				ResetATMButton(1);
				
//				ATM1Time = DateTime.MinValue;

//				return;
//			}
			
			
			string thisatm = pATMSaveS1;
			
			if (pATMRow == 2)
				thisatm = pATMSaveS5;
			if (pATMRow == 3)
				thisatm = pATMSaveS9;			
			
			string thislabel = pATMLabel1.ToUpper();
			
			if (pATMRow == 2)
				thislabel = pATMLabel5.ToUpper();
			if (pATMRow == 3)
				thislabel = pATMLabel9.ToUpper();
			
			if (thislabel == "BE")
			{
				RunBEClick(pBEOffset);
				return;
			}
				
			
			//Print("thisatm " + thisatm);
			
				if (SavingATMButton != 1)
				if (SavingATMButton != 0)
				{
					CancelSelectATM();	
				}
				
				if (SavingATMButton == 1)
				{
					CancelSelectATM();
				}					 
				
				else if (thisatm == "") // || e.)
				{
					ATM1Clicks = 0;
					
					SavingATMButton = 1;
					SetATMButtonNow(pLastATMSelectedS);
					
					
					
//					SavingATMButton = 1;
					
					
//					if (pLastATMSelectedS == "None"
					
//					Print("Hey");
//					Print(pLastATMSelectedS);
					
					
					

						
					//AddMessage(ATMStrategyNewButton, 8, Brushes.Goldenrod);
			
					
					
					//ClearATMButton(1, ATMButton1, ATMButtonTool1);	
				}
				else
				{			
					bool setatm = true;
					
					if (atmStrategySelector.SelectedAtmStrategy != null)
					{						
						if (thisatm == atmStrategySelector.SelectedAtmStrategy.DisplayName)
						{
							SetATM ("None");
							setatm = false;
						}
					}
					
					if (setatm)
						SetATM(thisatm);
					
		
				}
				
				
			if (!_hasPlanInProgress)			
			if (GetAllNonExitOrders(false) == 0 || pAllowMultiplePlans)
			{
				
				ShowPlan(false, "Long");
				RefreshRender(15);
			}

		
		}
		
		
