		private void RunSignalSystemStatus()
		{
			
			
			//Print("Run Now");
			
			if (BuySignalReady || SellSignalReady)
			{
			
				if (pSellSignalPlotIndicator == -1 || pSellSignalPlotPlot == -1 )
				{
					
					AddError("You must select a plot for Sell Signal Entry Level.  Please use the buttons on the left side of the Chart window.");
					
					BuySignalReady = false;
					SellSignalReady = false;
					
					return;
					
					
					
				}

				if (pBuySignalPlotIndicator == -1 || pBuySignalPlotPlot == -1 )
				{
					
					AddError("You must select a plot for Buy Signal Entry Level.  Please use the buttons on the left side of the Chart window.");
					
					BuySignalReady = false;
					SellSignalReady = false;				
					
					return;
					
					
					
				}
				
//				if (pTrendSignalPlotIndicator == -1 || pTrendSignalPlotPlot == -1 )
//				{
					
//					AddError("You must select a plot to determine the Trend Status.  Please use the buttons on the left side of the Chart window.");
					
//					BuySignalReady = false;
//					SellSignalReady = false;
					
//					return;
					
//					// show err
					
//				}
			}
			
			int whatbar = ThisCB - 1;

//			BarsUntilEntry = BarsUntilEntry - 1;
//			BarsUntilEntry = Math.Max(BarsUntilEntry, 0);
			
			//Print("BarsUntilEntry " + BarsUntilEntry);
			
			
			double trendplotprice =  0;
			
			//GetThisPlotSeries
			
			if (pTrendSignalPlotIndicator != -1 && pTrendSignalPlotPlot != -1)
				trendplotprice = GetThisPlotSeries(pTrendSignalPlotIndicator,pTrendSignalPlotPlot).GetValueAt(whatbar);
			
			
				double TrendStatus = 0;
				if (CurrentLastData >= trendplotprice)
					TrendStatus = 1;
				else
					TrendStatus = -1;
				
			
					AnthonyTrendStatus = string.Empty;
							
							if (TrendStatus == 1)
								AnthonyTrendStatus = triup;
							if (TrendStatus == -1)
								AnthonyTrendStatus = tridn;	
							
							
						
			double buyentryprice = 0;
			double sellentryprice = 0;
			
				if (pBuySignalPlotIndicator != -1 && pBuySignalPlotPlot != -1)
				buyentryprice = GetThisPlotSeries(pBuySignalPlotIndicator,pBuySignalPlotPlot).GetValueAt(whatbar);
				buyentryprice = RTTS(buyentryprice);
				
				
			
				if (pSellSignalPlotIndicator != -1 && pSellSignalPlotPlot != -1)
				sellentryprice = GetThisPlotSeries(pSellSignalPlotIndicator,pSellSignalPlotPlot).GetValueAt(whatbar);
				sellentryprice = RTTS(sellentryprice);
				
			
				
				double topprice = Math.Max(buyentryprice, sellentryprice);
				double bottomprice = Math.Min(buyentryprice, sellentryprice);	
					
				
				DoTradingSystemMarketOrders = false;
				if (trendplotprice <= topprice && trendplotprice >= bottomprice)
					DoTradingSystemMarketOrders = true;
				
				
					
			
				
				
				
				RefreshRender(20);

			UpdateButtonLabelsForWidth();

		}




		private void RunSignalButtonClick()
		{
			
			
			//Print("Run Now");
			
			if (BuySignalReady || SellSignalReady)
			{
				
				
				// old logic build for Anthony, don't use it anymore
				
			
				if (pSellSignalPlotIndicator == -1 || pSellSignalPlotPlot == -1 )
				{
					
					AddError("You must select a plot for Sell Signal Entry Level.  Please use the buttons on the left side of the Chart window.");
					
					BuySignalReady = false;
					SellSignalReady = false;
					
					return;
					
					// show err
					
				}

				if (pBuySignalPlotIndicator == -1 || pBuySignalPlotPlot == -1 )
				{
					
					AddError("You must select a plot for Buy Signal Entry Level.  Please use the buttons on the left side of the Chart window.");
					
					BuySignalReady = false;
					SellSignalReady = false;				
					
					return;
					
					// show err
					
				}
				
				
				
				
				
				
//				if (pTrendSignalPlotIndicator == -1 || pTrendSignalPlotPlot == -1 )
//				{
					
//					AddError("You must select a plot to determine the Trend Status.  Please use the buttons on the left side of the Chart window.");
					
//					BuySignalReady = false;
//					SellSignalReady = false;
					
//					return;
					
//					// show err
					
//				}
			}
			
			int whatbar = ThisCB - 1;

			BarsUntilEntry = BarsUntilEntry - 1;
			BarsUntilEntry = Math.Max(BarsUntilEntry, 0);
			
			//Print("BarsUntilEntry " + BarsUntilEntry);
		
				
			double trendplotprice =  0;
			
			if (pTrendSignalPlotIndicator != -1 && pTrendSignalPlotPlot != -1)
				trendplotprice = GetThisPlotSeries(pTrendSignalPlotIndicator,pTrendSignalPlotPlot).GetValueAt(whatbar);
			
			
				double TrendStatus = 0;
				if (CurrentLastData >= trendplotprice)
					TrendStatus = 1;
				else
					TrendStatus = -1;				
				
				double pos = 0;
				
				if (ThisPositionNow() != null)
				{
					if (ThisPositionNow().MarketPosition == MarketPosition.Long)
					{
						pos = 1;
					
					}
					
					if (ThisPositionNow().MarketPosition == MarketPosition.Short)
					{
						pos = -1;
								
					}					
				}
				
//				Print("TrendStatus " + TrendStatus.ToString());
//				Print("pos " + pos.ToString());
				
				
				bool BuyReadyPosition = pos <= 0;
				bool SellReadyPosition = pos >= 0;
				
				bool TimeReady = IsInSession.GetValueAt(ThisCB) == 1;
				
					if (!pUseTimeFilter)
							TimeReady = true;
					
				//Print(TimeReady);
				
				double entryprice = 0;
				
				if (pBuySignalPlotIndicator != -1 && pBuySignalPlotPlot != -1)
				entryprice = GetThisPlotSeries(pBuySignalPlotIndicator,pBuySignalPlotPlot).GetValueAt(whatbar);
				entryprice = RTTS(entryprice);
				
				
				if (BuySignalReady && BuyReadyPosition && TrendStatus == 1 && TimeSlicedSellOrderSequence == 0 && BarsUntilEntry <= 0 && TimeReady && pTradingSystemMode && !DoTradingSystemMarketOrders)
				{
					if (TimeSlicedBuyOrderSequence == 0)
					{
						SetBuyTimeSlicedPrice(entryprice, pSignalPlotOffset);
						
					
					}
					
					
				}
				else
				{
					if (TimeSlicedBuyPricePending())
						CancelTimeSlicedOrder("Buy");					
		
				
				}
				
				if (pSellSignalPlotIndicator != -1 && pSellSignalPlotPlot != -1)
				entryprice = GetThisPlotSeries(pSellSignalPlotIndicator,pSellSignalPlotPlot).GetValueAt(whatbar);
				entryprice = RTTS(entryprice);
				
				if (SellSignalReady && SellReadyPosition && TrendStatus == -1 && TimeSlicedBuyOrderSequence == 0 && BarsUntilEntry <= 0 && TimeReady && pTradingSystemMode && !DoTradingSystemMarketOrders)
				
				{
					
					
					if (TimeSlicedSellOrderSequence == 0)
					{
						SetSellTimeSlicedPrice(entryprice, pSignalPlotOffset);
						
						
					}
					
					
					
				}
				else
				{
				
					if (TimeSlicedSellPricePending())
						CancelTimeSlicedOrder("Sell");	
				}
			
				if (TimeSlicedSellOrderSequence != 0 || TimeSlicedBuyOrderSequence != 0)
				BarsUntilEntry = pBarsToPause;
				
				
				RefreshRender(21);
				RefreshRender(21);
			
		}
		

				
		
	
