		private void BuyClickNow()
		{
			if (!CheckNewTradeReady())
				return;




			if (BuyClickReady)
		    {
		        BuyClickReady = false;
				SelectPlotClickEntry = false;
				_clickEntryAnchorActive = false;

				RemoveATMPlanEntry(12);



		    }
		    else
		    {
				ResetAllActiveClickOrders();

				// Tear down any in-progress plan (the one with the Place Order
				// button) and any sentinel hover previews (Market / Limit /
				// Close Bar / Signal) before arming click mode. Click takes
				// over — the user is committing to click-to-place, so the
				// drawn plan is no longer relevant.
				HidePlan(false);
				IsInPCBuy = false;
				IsInPCSell = false;
				_pcBuyPreviewExpiresAt = DateTime.MinValue;
				_pcSellPreviewExpiresAt = DateTime.MinValue;

				pLastPlanDirection = "Long";
				// Anchor the starting plan price at the chart level directly to the
				// left of the Buy Click button so the preview always appears next to
				// the button on entry, independent of where the mouse last was.
				ResetClickEntryStartingPrice();
				AddATMPlanEntry(12, pShowPlanSeconds333);


				if (myProperties != null)
					myProperties.CrosshairDrawCursorOnly = true;

		        BuyClickReady = true;


				if (pAttachClickEnabled && pAttachmentOrdersButtonOK)
					SelectPlotClickEntry = true;

		    }

			// Pin the hand cursor immediately on mode entry. Users often click
			// the WPF Buy Click button with the mouse already over the chart,
			// so no OnMouseMove fires to pick up the state change -- force an
			// ApplyHoverCursor() pass now so Mouse.OverrideCursor goes active.
			ApplyHoverCursor();

			UpdateButtons();
			RefreshPriceButtonPulses(); // also refreshes button7/8 click-ready pulse
			RefreshRender(246);

		}

		private void SellClickNow()
		{

			if (!CheckNewTradeReady())
				return;

			if (SellClickReady)
		    {
		        SellClickReady = false;
				SelectPlotClickEntry = false;
				_clickEntryAnchorActive = false;

				RemoveATMPlanEntry(12);

		    }
		    else
		    {
				ResetAllActiveClickOrders();

				// Same teardown as BuyClickNow — the drawn plan (Place Order
				// button included) and any sentinel / PC hover preview are
				// dismissed in favor of click-to-place mode.
				HidePlan(false);
				IsInPCBuy = false;
				IsInPCSell = false;
				_pcBuyPreviewExpiresAt = DateTime.MinValue;
				_pcSellPreviewExpiresAt = DateTime.MinValue;

				pLastPlanDirection = "Short";
				// See BuyClickNow: anchor starting plan price at the chart level
				// directly to the left of the Buy Click button.
				ResetClickEntryStartingPrice();
				AddATMPlanEntry(12, pShowPlanSeconds333);
				if (myProperties != null)
					myProperties.CrosshairDrawCursorOnly = true;

		        SellClickReady = true;

				if (pAttachClickEnabled && pAttachmentOrdersButtonOK)
					SelectPlotClickEntry = true;

		    }

			// Same rationale as BuyClickNow — force cursor override immediately
			// so the hand shows up without waiting for an OnMouseMove.
			ApplyHoverCursor();

			UpdateButtons();
			RefreshPriceButtonPulses(); // also refreshes button7/8 click-ready pulse
			RefreshRender(247);

		}

		// Anchor captured on entry into Buy/Sell Click mode. OnRender uses this
		// instead of CurrentMousePrice while the mouse hasn't moved into the chart
		// yet, so the plan preview ALWAYS materializes at the chart level directly
		// to the left of the Buy Click button — regardless of where CurrentMousePrice
		// was left pointing by prior interactions.
		private double _clickEntryAnchorPrice = 0;
		private bool   _clickEntryAnchorActive = false;

		private void ResetClickEntryStartingPrice()
		{
			double resolved = 0;

			// Button-Y geometry: button7's center mapped to chart price.
			try
			{
				ChartScale activeScale = _lastChartScale;
				System.Windows.UIElement panelElem = ChartPanel as System.Windows.UIElement;
				if (button7 != null && panelElem != null && activeScale != null
					&& activeScale.MaxMinusMin > 0 && ChartPanel.H > 0
					&& System.Windows.PresentationSource.FromVisual(button7) != null
					&& System.Windows.PresentationSource.FromVisual(panelElem) != null)
				{
					double btnH = button7.ActualHeight;
					if (double.IsNaN(btnH) || btnH <= 0) btnH = !double.IsNaN(button7.Height) && button7.Height > 0 ? button7.Height : 0;

					var ptDip = button7.TransformToVisual(panelElem).Transform(new System.Windows.Point(0, btnH / 2.0));

					double dipToPxY = 1.0;
					var src = System.Windows.PresentationSource.FromVisual(panelElem);
					if (src != null && src.CompositionTarget != null)
						dipToPxY = src.CompositionTarget.TransformToDevice.M22;
					double chartYPx = ptDip.Y * dipToPxY;

					if (chartYPx < 0) chartYPx = 0;
					if (chartYPx > ChartPanel.H) chartYPx = ChartPanel.H;

					double btnPrice = activeScale.MaxValue - activeScale.MaxMinusMin * (chartYPx / ChartPanel.H);
					if (!double.IsNaN(btnPrice) && !double.IsInfinity(btnPrice) && btnPrice > 0)
						resolved = btnPrice;
				}
			}
			catch { }

			// Fallback: current last price (drawn at the chart's right edge next to
			// the Buy Click button — geometrically "directly to the left" in practice).
			if (resolved <= 0 && CurrentLastData > 0)
				resolved = CurrentLastData;

			if (resolved > 0)
			{
				double snapped = RTTS(resolved);
				CurrentMousePrice = snapped;
				_clickEntryAnchorPrice = snapped;
				_clickEntryAnchorActive = true;
			}
		}


