		// ================================================================
		// Price Based Entry click-time H/L stop + auto-qty integration
		// ================================================================
		// When Advanced Exit Orders Management → Initial Exits = "High / Low"
		// is active, Buy Price / Sell Price clicks recompute the ATM bracket
		// stop from the CLICK price (not CurrentLastData) so the submitted
		// stop lands at the swing low/high ± offset regardless of whether
		// the entry is a stop-entry above market or a limit below. When
		// Position Sizing is also on, qty is derived from that tick distance
		// via GetQtyFromTicksRisk — matching the hover preview.
		private Dictionary<int, double> _clickHLStopSnapshot = new Dictionary<int, double>();

		// NT's Account.OrderUpdate event doesn't replay existing working orders
		// after an indicator reload — it only fires on NEW state changes. So
		// LongEntryOrder2 / ShortEntryOrder2 never get re-bound for orders that
		// were already resting when the indicator was re-instantiated, and the
		// Price button loses its trailing / cancel / pulse wiring. This method
		// proactively scans the account's current orders and re-binds any that
		// match our PBEO / VTFSEO signal pattern. Safe to call repeatedly.
		private void RehydratePriceBasedEntryBindings()
		{
			try
			{
				if (myAccount == null || ThisInstrumment == null) return;
				foreach (Order or in myAccount.Orders.ToList())
				{
					if (or == null) continue;
					if (or.Instrument == null || or.Instrument.FullName != ThisInstrumment.FullName) continue;
					if (or.Name != "Entry") continue;
					if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted) continue;
					if (or.Oco == null || (!or.Oco.StartsWith("PBEO") && !or.Oco.StartsWith("VTFSEO"))) continue;

					if (or.OrderAction == OrderAction.Buy && LongEntryOrder2 == null)
					{
						LongEntryOrder2 = or;
						if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
							PriceBasedLongFrozen = !pPriceBasedInitialTrailingEnabled;
						else
							PriceBasedLongFrozen = false;
					}
					else if (or.OrderAction == OrderAction.SellShort && ShortEntryOrder2 == null)
					{
						ShortEntryOrder2 = or;
						if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
							PriceBasedShortFrozen = !pPriceBasedInitialTrailingEnabled;
						else
							PriceBasedShortFrozen = false;
					}
				}
				UpdateButtons();
			}
			catch { }
		}

		private bool HLStopActiveForClick()
		{
			return pAdvancedExitOrdersManagementEnabled
				&& pInitialExitAdjustmentsEnabled
				&& pInitialExitsType == "High / Low";
		}

		// Mirror SetAllATMTicksATR's compute loop so click-time override is
		// reliable even when the normal maintenance sites haven't fired.
		private void EnsureInitialHLValuesFresh()
		{
			try
			{
				if (BarsArray == null || BarsArray.Length == 0) return;
				int barsIdx = pMTFEnabled && BarsArray.Length > 1 ? 1 : 0;
				if (barsIdx >= CurrentBars.Length) return;

				double hlH = double.MinValue;
				double hlL = double.MaxValue;
				int lookback = Math.Max(0, pInitialExitHLBars);
				for (int hli = 0; hli <= lookback; hli++)
				{
					if (CurrentBars[barsIdx] >= hli)
					{
						hlH = Math.Max(hlH, Highs[barsIdx][hli]);
						hlL = Math.Min(hlL, Lows[barsIdx][hli]);
					}
				}
				if (hlH != double.MinValue) InitialHLHighestHigh = hlH;
				if (hlL != double.MaxValue) InitialHLLowestLow = hlL;
			}
			catch { }
		}

		private int ComputeHLStopTicksForLong(double entryPrice)
		{
			if (ThisTickSize <= 0 || entryPrice <= 0) return 0;
			EnsureInitialHLValuesFresh();
			if (InitialHLLowestLow <= 0 || InitialHLLowestLow >= entryPrice) return 0;
			int ticks = (int) Math.Round((entryPrice - InitialHLLowestLow) / ThisTickSize, 0)
						+ Math.Max(0, pInitialExitHLOffsetTicks);
			ticks = Math.Max(0, ticks);
			if (pInitialExitHLMinStopTicks > 0 && ticks > 0 && ticks < pInitialExitHLMinStopTicks)
				ticks = pInitialExitHLMinStopTicks;
			return ticks;
		}

		private int ComputeHLStopTicksForShort(double entryPrice)
		{
			if (ThisTickSize <= 0 || entryPrice <= 0) return 0;
			EnsureInitialHLValuesFresh();
			if (InitialHLHighestHigh <= 0 || InitialHLHighestHigh <= entryPrice) return 0;
			int ticks = (int) Math.Round((InitialHLHighestHigh - entryPrice) / ThisTickSize, 0)
						+ Math.Max(0, pInitialExitHLOffsetTicks);
			ticks = Math.Max(0, ticks);
			if (pInitialExitHLMinStopTicks > 0 && ticks > 0 && ticks < pInitialExitHLMinStopTicks)
				ticks = pInitialExitHLMinStopTicks;
			return ticks;
		}

		private void OverrideClickHLStops(AtmStrategy atm, int stopTicks)
		{
			_clickHLStopSnapshot.Clear();
			if (atm == null || atm.Brackets == null || stopTicks <= 0) return;
			// Convert the tick distance to whatever native units the ATM
			// strategy stores (Ticks / Currency / Percent / Pips / Price).
			double entryRef = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
			double stopUnits = TicksToBracketUnits(stopTicks, atm, entryRef);
			for (int i = 0; i < atm.Brackets.Length; i++)
			{
				var bb = atm.Brackets[i];
				if (bb == null) continue;
				_clickHLStopSnapshot[i] = bb.StopLoss;
				try { bb.StopLoss = stopUnits; } catch { }
			}
		}

		private void RestoreClickHLStops(AtmStrategy atm)
		{
			if (atm == null || atm.Brackets == null || _clickHLStopSnapshot.Count == 0)
			{
				_clickHLStopSnapshot.Clear();
				return;
			}
			foreach (var kv in _clickHLStopSnapshot)
			{
				int i = kv.Key;
				if (i < 0 || i >= atm.Brackets.Length) continue;
				var bb = atm.Brackets[i];
				if (bb == null) continue;
				try { bb.StopLoss = kv.Value; } catch { }
			}
			_clickHLStopSnapshot.Clear();
		}

		// Qty for a Price Based click. Respects Position Sizing: when on AND
		// a valid H/L stop tick distance is given, derive qty from risk.
		// Otherwise fall through to the user's current pQty.
		private int ComputeClickQty(AtmStrategy atm, int stopTicks)
		{
			if (!pPositionSizingIsEnabled) return pQty;
			if (stopTicks <= 0 || atm == null) return pQty;
			int computed = GetQtyFromTicksRisk(atm, stopTicks);
			return computed > 0 ? computed : pQty;
		}

		private void UpdateStopEntryOrders()
		{



			if (LongEntryOrder2 == null && ShortEntryOrder2 == null)
				return;
			
			double ExecutionHigh = RTTS(SEOLong + pOffsetTicks*ThisTickSize);
			double ExecutionLow = RTTS(SEOShort - pOffsetTicks*ThisTickSize);		
		

			
			if (pPriceBasedEntryOrdersEnabled)
			{
				ExecutionHigh = NextOrderHigh + pOffsetTicks*ThisTickSize;
				ExecutionLow = NextOrderLow - pOffsetTicks*ThisTickSize;
				SEOLong = NextOrderHigh;
				SEOShort = NextOrderLow;
			}			
						
			 // pPriceBasedEntryOrdersCancelIf

						// PriceBasedLong/ShortFrozen = true means the order should NOT trail.
						// In "Trailing Mode" the click handler toggles this flag; in "Cancel"
						// mode the flag just reflects the InitialTrailingEnabled preference.
						if (LongEntryOrder2 != null && !PriceBasedLongFrozen)
						{
							if (LongEntryOrder2.StopPrice > ExecutionHigh)
								MoveOrder(LongEntryOrder2, ExecutionHigh, 0);
						}

						if (ShortEntryOrder2 != null && !PriceBasedShortFrozen)
						{
							if (ShortEntryOrder2.StopPrice < ExecutionLow)
								MoveOrder(ShortEntryOrder2, ExecutionLow, 0);
						}

		}
		
		
