		private void SellThisPlot(int ind, int plot, int bb, int offset)
		{
		
			NextIndicator = ind;
			NextPlot = plot;
			NextOffset = offset;
			
			double price = GetThisPlotValue(ind, plot, bb);

			if (price == 0)
			{
				AddMessage(PBEOReset, 10, Brushes.Goldenrod);
				pPriceBasedIndicator = -1;
				pPriceBasedPlot = -1;					
				return;
			}
			
			
			price = price - pOffsetTicks*ThisTickSize;
			
			SellPriceClick(price);
			
		}
			

		private void BuyThisPlot(int ind, int plot, int bb, int offset)
