		private void BuyPriceButton()
		{
			

			//IsInPCSell = false;
	if (!CheckNewTradeReady())
				return;
						
			if (pPriceBasedEntryOrdersEnabled)
			{
				
				if (pPriceBasedEntryMode == "Indicator")
				{
					if (pPriceBasedIndicator == -1)
					{
						SelectingPlotFor = "Price Based Entry Orders";
						AddMessage(SelectPriceBasedMsg, 15, Brushes.Red);
						
					}
					else
					{
						
						BuyThisPlot(pPriceBasedIndicator, pPriceBasedPlot, 0, pOffsetTicks);
					}
					
					
				}
				else
				{
				
				
					OCOBracketID2 = string.Concat("PBEO",pAccountName,SpreadName,DateTime.Now.Ticks);

					if (pUseOCOStopEntry)
					if (ShortEntryOrder2 != null)
						OCOBracketID2 = ShortEntryOrder2.Oco;

					if (!pUseOCOStopEntry)
						OCOBracketID2 = string.Empty;

					//BuyStopClick ();

					// Guard against the "order placed at ~0 + offset" bug.
					// NextOrderHigh/NextOrderLow start at 0 and are only populated by
					// CalculatePriceBasedEntryOrders(), which runs in OnBarUpdate when
					// State == Realtime and the current bar type matches one of the
					// supported branches. If the indicator just loaded, is replaying
					// historical, or is on an unsupported bar type that falls through
					// CalculatePriceBasedEntryOrders without setting these, they stay
					// at 0 — and the old code would happily place a BuyLimit at
					// (0 + pOffsetTicks*ThisTickSize), i.e. a tick or two above zero,
					// which aggressively fills as a market buy at the current ask.
					if (NextOrderHigh <= 0 || NextOrderLow <= 0)
					{
						AddMessage("Price Entry Orders are not ready yet — waiting on a bar update to compute the next order levels. Try again in a moment, or verify the current bar type is supported.", 10, Brushes.Red);
						UpdateButtons();
						RefreshRender(250);
						return;
					}

					ExecutionHigh = NextOrderHigh + pOffsetTicks*ThisTickSize;
					ExecutionLow = NextOrderLow - pOffsetTicks*ThisTickSize;

					BuyPriceClick(ExecutionHigh);
					
					
					//Print("Priiii");
					
					
					
				}
				
				
				
				
			}
			else
			{
				
				
				OCOBracketID2 = string.Concat("VTFSEO",pAccountName,SpreadName,DateTime.Now.Ticks);
				
				if (pUseOCOStopEntry)
				if (ShortEntryOrder2 != null)
					OCOBracketID2 = ShortEntryOrder2.Oco;
					
				if (!pUseOCOStopEntry)
					OCOBracketID2 = string.Empty;				
				
				BuyStopClick ();
					
				
			}
				
						
						

			UpdateButtons();
			RefreshRender(250);			
			
		}
		
		
		
		
