			private void SellPriceClick (double CurrentMousePrice)
			{
				// Double-click → always cancel resting order, regardless of mode.
				if (ShortEntryOrder2 != null
					&& (DateTime.Now - LastSellPriceClickTime).TotalMilliseconds < PriceBasedDoubleClickMs)
				{
					CancelOrder(ShortEntryOrder2);
					ShortEntryOrder2 = null;
					PriceBasedShortFrozen = false;
					LastSellPriceClickTime = DateTime.MinValue;
					NextIndicator = -1;
					NextPlot = -1;
					NextOffset = -1;
					// Suppress the potential-order / ATM plan preview that is gated on
					// IsInPCSell. The mouse must physically leave Button38 and re-enter
					// before the preview is allowed back (Button38_MouseEnter will set
					// IsInPCSell = true again).
					IsInPCSell = false;
					// The 1st click of the double-click posted a "trailing toggled..." status.
					// Kill it so the user only sees the cancel confirmation.
					RemoveMessage(false, "Use 'Close All' or double click to cancel order.");
					AddMessage("Short '" + PriceEntryOrdersButtonName + "' entry cancelled (double-click).", 6, Brushes.Goldenrod);
					UpdateButtons();
					RefreshPriceButtonPulses();
					RefreshRender(256);
					return;
				}
				LastSellPriceClickTime = DateTime.Now;

				// Existing order → 2nd-click handling controlled by
				// PriceBasedLiveEntryButtonFunctionality ("Cancel" | "Trailing Mode").
				if (ShortEntryOrder2 != null)
				{
					if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
					{
						PriceBasedShortFrozen = !PriceBasedShortFrozen;
						// In Plot mode, keep the order flag's "A" (attach-to-indicator)
						// state in sync with our trailing flag. Clicking Plot to turn
						// trailing off = detach (A click OFF); turning on = re-attach.
						SyncOrderTrackingWithTrailing(ShortEntryOrder2, PriceBasedShortFrozen);
						SetTrailingStatusMessage(PriceBasedShortFrozen);
						UpdateButtons();
						RefreshPriceButtonPulses();
						RefreshRender(256);
						return;
					}

					// "Cancel" mode (or Price Based disabled) → cancel the resting order.
					CancelOrder(ShortEntryOrder2);
					ShortEntryOrder2 = null;
					PriceBasedShortFrozen = false;

					NextIndicator = -1;
					NextPlot = -1;
					NextOffset = -1;
				}
				else
				{
					AtmStrategy atm = atmStrategySelector.SelectedAtmStrategy;

					// H/L stop + auto-qty integration. When Advanced Exit Orders →
					// Initial Exits "High / Low" is on, compute the bracket stop
					// from the CLICK price and override the ATM just for this submit.
					// When Position Sizing is on, derive qty from that tick distance.
					int submitStopTicks = 0;
					int submitQty       = pQty;
					bool hlApplied      = false;
					if (HLStopActiveForClick())
					{
						submitStopTicks = ComputeHLStopTicksForShort(CurrentMousePrice);
						submitQty       = ComputeClickQty(atm, submitStopTicks);
						if (submitStopTicks > 0 && atm != null)
						{
							OverrideClickHLStops(atm, submitStopTicks);
							hlApplied = true;
						}
					}

					try
					{
						if (CurrentMousePrice >= CurrentBid)
						{
							SaveShortOrder2 = true;
							SellLimit(submitQty, atm, "", CurrentMousePrice, pThisEntryLimitClick == "MIT", "Entry");
						}
						else
						{
							SaveShortOrder2 = true;
							SellStop(submitQty, atm, OCOBracketID2, CurrentMousePrice, pUseSLMStopEntry, pSLOffsetPriceEntry, "Entry");
						}
					}
					finally
					{
						if (hlApplied) RestoreClickHLStops(atm);
					}

					// Seed trailing flag from Initial Trailing Enabled when in Trailing Mode.
					// Frozen = "do not follow price".
					if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
						PriceBasedShortFrozen = !pPriceBasedInitialTrailingEnabled;
					else
						PriceBasedShortFrozen = false;

					AddMessage(BuildTrailingStatusMessage(PriceBasedShortFrozen), 10, Brushes.Goldenrod);
				}
				RefreshPriceButtonPulses();
			}

			private void BuyPriceClick  (double CurrentMousePrice)
			{
				// Double-click → always cancel resting order, regardless of mode.
				if (LongEntryOrder2 != null
					&& (DateTime.Now - LastBuyPriceClickTime).TotalMilliseconds < PriceBasedDoubleClickMs)
				{
					CancelOrder(LongEntryOrder2);
					LongEntryOrder2 = null;
					PriceBasedLongFrozen = false;
					LastBuyPriceClickTime = DateTime.MinValue;
					NextIndicator = -1;
					NextPlot = -1;
					NextOffset = -1;
					// Suppress the potential-order / ATM plan preview that is gated on
					// IsInPCBuy. The mouse must physically leave Button37 and re-enter
					// before the preview is allowed back (Button37_MouseEnter will set
					// IsInPCBuy = true again).
					IsInPCBuy = false;
					// The 1st click of the double-click posted a "trailing toggled..." status.
					// Kill it so the user only sees the cancel confirmation.
					RemoveMessage(false, "Use 'Close All' or double click to cancel order.");
					AddMessage("Long '" + PriceEntryOrdersButtonName + "' entry cancelled (double-click).", 6, Brushes.Goldenrod);
					UpdateButtons();
					RefreshPriceButtonPulses();
					RefreshRender(257);
					return;
				}
				LastBuyPriceClickTime = DateTime.Now;

				// Existing order → 2nd-click handling controlled by
				// PriceBasedLiveEntryButtonFunctionality ("Cancel" | "Trailing Mode").
				if (LongEntryOrder2 != null)
				{
					if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
					{
						PriceBasedLongFrozen = !PriceBasedLongFrozen;
						// In Plot mode, keep the order flag's "A" (attach-to-indicator)
						// state in sync with our trailing flag. Clicking Plot to turn
						// trailing off = detach (A click OFF); turning on = re-attach.
						SyncOrderTrackingWithTrailing(LongEntryOrder2, PriceBasedLongFrozen);
						SetTrailingStatusMessage(PriceBasedLongFrozen);
						UpdateButtons();
						RefreshPriceButtonPulses();
						RefreshRender(257);
						return;
					}

					CancelOrder(LongEntryOrder2);
					LongEntryOrder2 = null;
					PriceBasedLongFrozen = false;

					NextIndicator = -1;
					NextPlot = -1;
					NextOffset = -1;
				}
				else
				{
					AtmStrategy atm = atmStrategySelector.SelectedAtmStrategy;

					int submitStopTicks = 0;
					int submitQty       = pQty;
					bool hlApplied      = false;
					if (HLStopActiveForClick())
					{
						submitStopTicks = ComputeHLStopTicksForLong(CurrentMousePrice);
						submitQty       = ComputeClickQty(atm, submitStopTicks);
						if (submitStopTicks > 0 && atm != null)
						{
							OverrideClickHLStops(atm, submitStopTicks);
							hlApplied = true;
						}
					}

					try
					{
						if (CurrentMousePrice <= CurrentAsk)
						{
							SaveLongOrder2 = true;
							BuyLimit(submitQty, atm, "", CurrentMousePrice, pThisEntryLimitClick == "MIT", "Entry");
						}
						else
						{
							SaveLongOrder2 = true;
							BuyStop(submitQty, atm, OCOBracketID2, CurrentMousePrice, pUseSLMStopEntry, pSLOffsetPriceEntry, "Entry");
						}
					}
					finally
					{
						if (hlApplied) RestoreClickHLStops(atm);
					}

					if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
						PriceBasedLongFrozen = !pPriceBasedInitialTrailingEnabled;
					else
						PriceBasedLongFrozen = false;

					AddMessage(BuildTrailingStatusMessage(PriceBasedLongFrozen), 10, Brushes.Goldenrod);
				}
				RefreshPriceButtonPulses();
			}
			
			
	
	
		
		
		
		
		
