		private void AdjustATMStrategyQty2(int qtydown, int loweststoporder)
		{
			
			int stoptotal = qtydown;
			int targettotal = qtydown;
			
			
			List<Order> CancelThese = new List<Order>();	
			
			int lowestqtyforstop1 = 9999999;
			string ocoid = "";
			Order thiso = null;
			
			
			int loweststopnum = loweststoporder;
			
			//Print("GetLowestStopOrder " + loweststopnum);
			
			string lookforstop = "Stop" + loweststopnum.ToString();
			
			//Print(lookforstop);
			
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;
				
				//TrackedOrders(
				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
				OrderTypeOK = true;
				OrderNameOK = or.Name == lookforstop;
				OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				//OrderNameOK = IsStop(or.Name);
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				
				{
					
					
					if (or.Name == lookforstop)
					{
						if (lowestqtyforstop1 == 9999999)
						{
							lowestqtyforstop1 = or.Quantity;
							ocoid = or.Oco;
							thiso = or;
							//Print(lowestqtyforstop1);
						}
						if (or.Quantity < lowestqtyforstop1)
						{
							lowestqtyforstop1 = or.Quantity;
							ocoid = or.Oco;
							thiso = or;
							//Print(lowestqtyforstop1);
							
						}
						
						
						
					}
					
					
				
				}
				
			}
			
			
			foreach (Order or in CancelThese)
			{
				//CancelOrder(or);
			}
			
			
			
			//Print("lowestqtyforstop1 " + lowestqtyforstop1);
			
			if (TotalToClose >= lowestqtyforstop1)
			{
				// cancel order and get next one
			
				CancelOrder(thiso);
				
				
			}
			else
			{
				
				int newqqqq = lowestqtyforstop1 - TotalToClose;
				
				//Print("newqqqq" + newqqqq);
				
				UpdateOrderQty2(ocoid, newqqqq);
				
			}
			
			
			TotalToClose = TotalToClose - lowestqtyforstop1;
			
			
			//Print(TotalToClose);
			
			
			//Print(lowestqtyforstop1 + " " + ocoid);
			
			
			
			//return 0;
						
			
		}
		
		
		private void UpdateOrderQty2 (string ocoid, int newqty)
		{
			
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;
				
				//TrackedOrders(
				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
				OrderTypeOK = true;
				OrderNameOK = IsStop(or.Name) ||  IsTarget(or.Name);
				OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				//OrderNameOK = IsStop(or.Name);
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				
				{
					
					if (or.Oco == ocoid)
					{
						
						Order moveOrder;
						
						moveOrder = or;
						moveOrder.QuantityChanged = newqty;
						
						//if (or.Quantity != newqty)
						myAccount.Change(new[] { moveOrder });						
									
						
						
					}
					
					
				
				}
				
			}
			
			
			
			

	
		}
					

		
	private void MoveAllTargetOrders(double StartPrice, int ticksdiff, string mode, string thisone)
		{
			
		
			
			double thisstartprice = StartPrice;
			double totalmoveticks = 0;

			//Print(thisstartprice);
			
			if (mode == "Close")
				totalmoveticks = -1*FillLimitOrderNowTicks;
				
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;

				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
				OrderNameOK = IsTarget(or.Name);
				
				if (thisone != string.Empty)
				OrderNameOK = or.Name.Contains(thisone);	
				
				OrderTypeOK = or.OrderType == OrderType.Limit || or.OrderType == OrderType.MIT || (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending);
				OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;

				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
						
					bool OKToMove = false;
					
			
					if (or.IsShort) // In Long Trade
					{
						
						NewLimitPrice = RTTS(thisstartprice + totalmoveticks*ThisTickSize);
	
					}
					else // In Short Trade
					{
						NewLimitPrice = RTTS(thisstartprice - totalmoveticks*ThisTickSize);

						//OKToMove = NewStopPrice >= GetCurrentAsk();
						
					}
					
			
					
//					StopLimitOffset = or.StopPrice - or.LimitPrice;
//					NewLimitPrice = NewStopPrice - StopLimitOffset;
								
//					CurrentStopPrice = or.StopPrice;
					
					NewStopPrice = 0;
					
					
					
					if (or.LimitPrice == 0)
					{
						NewStopPrice = NewLimitPrice;
						NewLimitPrice = 0;
						
					}

					
					OKToMove = true;
					
					if ((NewLimitPrice != 0 || NewStopPrice != 0) && OKToMove)
					{
				
				
							Order moveOrder;
							
							moveOrder = or;
							moveOrder.LimitPriceChanged = NewLimitPrice;
							moveOrder.StopPriceChanged = NewStopPrice;		
							
							myAccount.Change(new[] { moveOrder });

						
					}
					
					if (mode == "Close")
						totalmoveticks = totalmoveticks - ticksdiff;
					else
						totalmoveticks = totalmoveticks + ticksdiff;
					
					//Print(or.Name);
				}
				
			}
			
			
		}
		
		
		
