		private void ReverseAll()
		{
			LogDiag("POSITION_MGMT", "ReverseAll");

			
			CancelStopOrders();	
			CancelTargetOrders();
			//CancelAllOrders();
			
			
			
			
			var pos = ThisPositionNow();
			if (pos != null)
			{
				if (pos.MarketPosition == MarketPosition.Long)
				{
					CloseMarket(pos.Quantity*-1);

					SellMarket(pQty, atmStrategySelector.SelectedAtmStrategy, "");
					RefreshRender(257);

				}

				if (pos.MarketPosition == MarketPosition.Short)
				{
					CloseMarket(pos.Quantity);

					BuyMarket(pQty, atmStrategySelector.SelectedAtmStrategy, "");
					RefreshRender(258);

				}					
					
					
					
					
			}
			

			
			
		}		
		

