				if (CloseAllClickedTime < PreviousCloseAllClickedTime.AddMilliseconds(1000))
					return;
				
				
				
				
				int TotalO = 0;
				

				
//				if (pCloseAllEntryFirst)
//					TotalO = GetAllNonExitOrders(true);

// modified to close orders when button was switched to use flatten everything command				
				
				TotalO = GetAllNonExitOrders(true);
				
				if (!pCloseAllEntryFirst)
					TotalO = 0;				
				
				//Print(TotalO);
				
				
				if (TotalO == 0)
					CloseAll();
				
				PreviousCloseAllClickedTime = CloseAllClickedTime;
				
				UpdateButtons();
				
				
				
				
				
				//ClosePosition();
				RefreshRender(260);
							
			
			
		}
		
