		private void BracketButtonClick()
		{
			LogDiag("UI", "BracketButtonClick");

			
			if (!CheckNewTradeReady())
					return;
				
				OCOBracketID = string.Concat("ECTBR",pAccountName,SpreadName,DateTime.Now.Ticks);
				
				CurrentLastDataPlaced = CurrentLastData;
				
				CurrentLastLowPlaced = CurrentLastDataPlaced;
				CurrentLastHighPlaced = CurrentLastDataPlaced;
		
				if (pBracketBasis == "High / Low")
				{
					
					CurrentLastLowPlaced = CurrentLastLow;
					CurrentLastHighPlaced = CurrentLastHigh;
												
				}
							
							
				ExecutionHigh = CurrentLastHighPlaced + pLimitOrderOffset3*ThisTickSize;
				ExecutionLow = CurrentLastLowPlaced - pLimitOrderOffset3*ThisTickSize;
				
				if (pBracketMode == "Close")
				{
					
					BracketIsWaiting = !BracketIsWaiting;
					
				}
					
				
			
				
				
				bool isslm = false;
				
				if (pThisEntryType3 == "SLM")
					isslm = true;
			
							// cancel
							if (BracketLongEntryOrder != null || BracketShortEntryOrder != null)
							{
								CancelOrder(BracketLongEntryOrder);
								BracketLongEntryOrder = null;
								
								BracketIsWaiting = false;
								
	//							CancelOrder(BracketShortEntryOrder);
	//							BracketShortEntryOrder = null;
							}
							else
							{
	//							SaveLongOrder = true;
	//							SaveShortOrder = true;
								
								if (pBracketMode != "Close")
								BracketTrade(ExecutionHigh, ExecutionLow, pSLOffsetBracket, OCOBracketID, pThisEntryType3);
								
								
								
							}
							
							
					
							
							
							
					UpdateButtons();	
							RefreshRender(261);			
			
			
			
		}
		
