		private int GetQtyFromTicksRisk(AtmStrategy thisatm, int ticksrisk)
		{
			// Guard against zero or negative stop ticks (division by zero protection)
			if (ticksrisk <= 0)
				return thisatm != null && thisatm.Brackets != null ? Math.Max(1, thisatm.Brackets.Length) : 1;

			// Guard against zero tick dollars — happens on instruments where
			// PointValue hasn't loaded yet, or on initial render before market
			// data has streamed. Without this, the divide at line ~18849 would
			// produce Infinity / NaN and the position size cast to int would be
			// undefined behavior.
			if (ThisTickDollars <= 0)
				return thisatm != null && thisatm.Brackets != null ? Math.Max(1, thisatm.Brackets.Length) : 1;

			// Guard against zero / negative dollar risk in Dollars mode. In
			// Percent mode the recompute below will populate it from
			// pPositionSizingPercentRisk * account cash value, so only error
			// out for Dollars mode here.
			if (pPositionSizingMode != "Percent" && pPositionSizingDollarsRisk <= 0)
			{
				if (pPositionSizingIsEnabled)
					AddMessage("Position sizing dollar risk is 0 — cannot compute quantity. Set a positive Dollars Risk.", 5, Brushes.Goldenrod);
				return Math.Max(1, pPositionSizingMinSize);
			}


								// start contracts calculate

								bool testp = false;

									int totalstoplossticks = 		ticksrisk;

				double onelotrisk = 	totalstoplossticks * 	ThisTickDollars;
				
				if (testp) Print(totalstoplossticks + " Ticks");
				if (testp) Print( "$ " + onelotrisk);		
						
			
										
					//Print("PS");
				
				 
				double acccashvalue = 0;
				//bool dopositionsizeupdate = true;
				
		
				if (myAccount != null)
				{
					
					acccashvalue = (double) myAccount.GetAccountItem(AccountItem.CashValue, Currency.UsDollar).Value;
					
					
				}
				
				
				if (myAccount == null && pPositionSizingMode == "Percent")
				{
					//dopositionsizeupdate = false;
				
					if (pPositionSizingIsEnabled)
						AddMessage("Your must have an account selected to use '%' mode for Position Sizing.", 5, Brushes.Goldenrod);
						
										
				}
				
				
				
				if (myAccount != null && pPositionSizingMode == "Percent")
				{
					
					
					
				 	double finalaccountvalue = acccashvalue;
					
					if (pPositionSizingAccountSizeOverride != 0)
						finalaccountvalue = pPositionSizingAccountSizeOverride;
					
					
					
					double dollarstoriskbasedonpercent = finalaccountvalue*pPositionSizingPercentRisk/100;
					
					//Print(dollarstoriskbasedonpercent);
					
					dollarstoriskbasedonpercent = Math.Floor(dollarstoriskbasedonpercent);
					
					//Print(dollarstoriskbasedonpercent);
					
					pPositionSizingDollarsRisk = Math.Max(0, (int) dollarstoriskbasedonpercent);
			
					
					if (qudSelector3.Value != pPositionSizingDollarsRisk)
					{
						UpdateQUD = false;
						qudSelector3.Value = pPositionSizingDollarsRisk;						
					}
					
					UpdatePOSDisplay();
					
					// set pPositionSizingDollarsRisk = 
				}
				else
				{
					
					
				}
			

				// Final divide-by-zero guard. The early-return above catches
				// ThisTickDollars <= 0 and ticksrisk <= 0, so onelotrisk should
				// always be > 0 here, but defend against edge cases (e.g.,
				// pPositionSizingMode == "Percent" path may zero out the risk).
				if (onelotrisk <= 0 || pPositionSizingDollarsRisk <= 0)
					return thisatm != null && thisatm.Brackets != null ? Math.Max(1, thisatm.Brackets.Length) : 1;

				double finalposition = 	pPositionSizingDollarsRisk / 	onelotrisk;

				//if (testp) Print(finalposition + " Contracts");

				finalposition = Math.Floor(finalposition);
						
						
				//if (testp) Print(finalposition + " Contracts");		

				finalposition = Math.Min(finalposition, pPositionSizingMaxSize);
				finalposition = Math.Max(finalposition, pPositionSizingMinSize);
				
	
				int totalbrackets = Math.Max(thisatm.Brackets.Length, 1);
				finalposition = Math.Max(finalposition, totalbrackets);
				
				
								
								
				double totalrisk = onelotrisk*finalposition;
				
				//Print("totalrisk " + totalrisk);
								
					//RemoveMessage(false, "The total risk in ");
								
				//Print(totalrisk);
				
				//if (AllMovingStopTicks 
				
				//Print(MovingATMOrders.Count);
				
				
//								if (totalrisk > pPositionSizingDollarsRisk)
//								{
									
//									string DSSSS = GetDollarString("$", pPositionSizingDollarsRisk);
//									DSSSS = DSSSS.Replace(".00", "");
									
									
//									string ssdasf = "The total risk in this trade is greater than the set position sizing maximum risk of " + DSSSS + ".";
						
									
////									if (pRestrictMax)
////									if (MovingATMOrders.Count > 0)
////										ssdasf = "The total risk in this trade will exceed the set position sizing maximum risk of " + DSSSS + ".  You can't move the Stop loss any further.";
									
//									//ssdasf = "Main Order quantity '" + pQty + "' must be equal to or greater than number of Targets in the ATM Strategy '" + totalbrackets + "'.  The Main Order quantity was automatically increased.";
									
//									//AutoSetQud = true;
//									//qudSelector.Value = totalbrackets;
									
//									AddMessage(ssdasf, 10, Brushes.Red);
									
//									//AddError(ssdasf);
									
										
									
//								}										
								
				if (testp) Print("----------------------");
					
			// set the two quantities and display update message
				
				int	thisfinalsize = (int)finalposition;
				
				
			
				return thisfinalsize;
			
			
			
		}
		
