						if (pPositionSizingIsEnabled)
							AddMessage("You must select an ATM Strategy to use Position Sizing.", 5, Brushes.Goldenrod);
						
						
						DisablePositionSizing("1");
						return;
						
					}
				}
				
				if (atmnow != null)
			
				
				{
					
					//Print(StopTicksToName.Count);
					
					
					if (StopTicksToName.Count > 1)
					{
						if (pPositionSizingIsEnabled)
							AddMessage("Your selected ATM Strategy must have identical Stop loss orders at each Target to use Position Sizing.", 5, Brushes.Goldenrod);
						
						
						DisablePositionSizing("2");
						
						
						return;
						
					}
					
					
				}
				
				//if (testp) Print(StopTicksToName.Count);
		
				
					double totalstoplossticks = 0;
				
				
				foreach (KeyValuePair<double, string> KKK in StopTicksToName)
				{
//					Print(KKK.Value);
//					Print(KKK.Key);
					
					
//					if (KKK.Value == "Stop Loss")
//					{
//						totalstoplossticks = KKK.Key;
//						break;
//					}
//					if (KKK.Value.Contains("Stop 1"))
//					{
//						totalstoplossticks = KKK.Key;
//					}						

					//if (KKK.Value.Contains("Stop"))
					{
						totalstoplossticks = Math.Max(totalstoplossticks, KKK.Key); // Use largest stop for risk calculation
					}						
				}
						
				if (totalstoplossticks == 0)
