				}
				
		
				RemoveMessage(false, "The total risk in ");

				int	thisfinalsize = GetQtyFromTicksRisk(atmnow, (int)totalstoplossticks);

				// Re-seed TargetTicksToQty / StopTicksToQty with the position-sized
				// qty. The first GetATMData call (~:20310) used atmnow.EntryQuantity,
				// which becomes stale on every frame after frame 1: the corrective
				// GetATMData inside the qudSelector.Value != pLastQuantity gate
				// (~:20515-20522) only runs when those values disagree, but they
				// match in steady state. Without this re-seed, hover [Price] flashes
				// the correct sized qty for one frame and then reverts to the ATM
				// template's bracket Quantity from frame 2 onward (the bug Steve
				// reported 2026-04-28). Idempotent — GetATMData clears the dicts
				// before re-filling, and is safe to call twice when the gated path
				// also runs on the same frame.
				if (pPositionSizingIsEnabled && thisfinalsize > 0)
					GetATMData(atmnow, thisfinalsize, CurrentLastData);

				//Print("214 " + thisfinalsize);
				
