							//AllNotifications

							// Suppress the message on the first adjust pass after
							// reload — the qudSelector default differs from the
							// restored pLastQuantity for one pass, which fires a
							// spurious "adjusted to X" toast even when the user's
							// qty already matches the computed size.
							if (_psSuppressFirstAdjustMessage)
							{
								_psSuppressFirstAdjustMessage = false;
							}
							else if (pPositionSizingMaxSize == pLastQuantity)
								{
									AddMessage("Position Sizing - Maximum Quantity has been reached at " + pLastQuantity.ToString() + PSAdjustedContacts, 5, Brushes.Goldenrod);

								}

								else if (pPositionSizingMinSize == pLastQuantity)
								{
									AddMessage("Position Sizing - Minimum Quantity has been reached at " + pLastQuantity.ToString() + PSAdjustedContacts, 5, Brushes.Goldenrod);

								}

								else
								{

									RemoveMessage(false, PSAdjustedMessage);
									AddMessage(PSAdjustedMessage + pLastQuantity.ToString() + PSAdjustedContacts, 5, Brushes.Goldenrod);

									//Print(updatecontrols);

								}
								
							//Print();
							
								
									
					//Print("pPositionSizingIsEnabled " + pPositionSizingIsEnabled);
					
				
								
								
								if (updatecontrols)
								{
									//AutoSetQud = true;
									
									IgnoreNextQtyUpdate  = true;
									
									if (qudSelector.Value != pLastQuantity)
									{
										qudSelector.Value = pLastQuantity;
									}
									
									//312 set quantities for targets
									 
									
									//Print("pLastQuantity " + pLastQuantity);
									
									SetATMTargetQtys(atmnow, pLastQuantity, 0, "");

									// StopTicksToQty was populated by the GetATMData at the top
									// of this method BEFORE SetATMTargetQtys wrote the new
									// bracket quantities. Without a refresh the Target / Stop
									// labels read stale qtys for one render frame. Re-read now
									// so all labels update in the same frame as the Entry label.
									GetATMData(atmnow, pLastQuantity, CurrentLastData);

								}
							
						}
					
						
					}
					
					
					if (pPositionSizingQ2)
					{

						pLastQuantity2 = thisfinalsize;
						
						
						if (updatecontrols)
					
						{
									if (qudSelector2.Value != pLastQuantity2)
									{
