									}
									
						}
						
						
						
					}
					
					
					
					
									
				
					
					if (pATMQuickButtonsEnabled)
					{
						//SetATMButtonLabels();
	
						
					}
					
					
				}
				
				

										
				if (updatedisplay)
					RefreshRender(263);
				
				
				
			}
				
			 
