			private void SetATMTargetQtys (NinjaTrader.NinjaScript.AtmStrategy selectedAtmStrategy, int TotalLots, double thisentry, string thisname)
			{

				// Proportional allocation runs unconditionally now. The previous
				// gate on pKeepTargetQuantityProportional could leave this method
				// short-circuited when XML deserialization restored false from an
				// older workspace, which left atmnow.EntryQuantity and bb.Quantity
				// at the ATM template's original values. The first GetATMData
				// call in PositionSizingAdjustQuantities (line 20308) reads
				// atmnow.EntryQuantity and seeds TargetTicksToQty with the
				// un-sized qty (e.g. 10 instead of 7); the corrective second
				// GetATMData call only fires when qudSelector.Value != pLastQuantity
				// (true only on the very first sizing frame). Result before fix:
				// 10-contract ATMs displayed targets/stops at 10 even after the
				// entry sized down to 7. The setting is now force-true at the
				// property level and hidden from all property grids.


				int i = 1;
				
				bool IsPercentBased = selectedAtmStrategy.CalculationMode == CalculationMode.Percent;
				
				
				bool FirstLoop = true;
				
				double Stop1Ticks = 0;
				double Target1Ticks = 0;
				int StopTotalLots = 0;
				int RemainingQ = TotalLots;
				
				
				
				
				

				string atmnamenow = RemoveEndOfLiveATM(selectedAtmStrategy.DisplayName);
				
				
				//Print("hey");
				//Print(atmnamenow);
				
				
				if (!DefaultAtmStrategyPercentages.ContainsKey(atmnamenow))
					return;
					
		
				
				//Print("TotalLots " + TotalLots);
				
				
				if (selectedAtmStrategy != null)
				{
					selectedAtmStrategy.EntryQuantity = TotalLots;
					
					
					foreach( Bracket bb in selectedAtmStrategy.Brackets)
					{

						StopTotalLots = (int) Math.Ceiling(DefaultAtmStrategyPercentages[atmnamenow][i]*TotalLots);
						
						StopTotalLots = Math.Min(StopTotalLots,RemainingQ);
						
//						Print("------------------");
//						Print(StopTotalLots);
									    
						
						bb.Quantity = StopTotalLots;
						
						RemainingQ = RemainingQ - StopTotalLots;

						i++;
			
					}
			
				}
		
				
				RefreshRender(264);
				
				
			}
			
			
			
			
		
