			private string RemoveEndOfLiveATM(string atmfulldisplayname)
			{
				
				if (!atmfulldisplayname.Contains(" - "))
					return atmfulldisplayname;
				
								string input = atmfulldisplayname;
								int index = input.LastIndexOf("-"); // Character to remove "?"
								if (index > 0)
								    input = input.Substring(0, index); // This will remove all text after character ?

								//input = input.Substring(input.Length-2);

								input = input.Remove(input.Length-1);
								
								return input;				
				
			}


			// --- ATM strategy name shortening for the on-chart name chip --------
			// Long ATM template names made the name chip very wide and cluttered
			// the chart. ShortenAtmName trims the name to fit: first an optional
			// hard character cap (pAtmNameMaxChars, 0 = off), then a pixel-width
			// budget (the order flag's own width). Truncation is done in the
			// MIDDLE (head...tail) so a distinguishing prefix AND suffix both
			// survive -- e.g. "ES_Scalp_Conservative_v2" -> "ES_Scalp_...v2".
			private string ShortenAtmName(string name, float widthBudget, SharpDX.DirectWrite.TextFormat fmt)
			{
				if (string.IsNullOrEmpty(name))
					return name;

				string result = name;

				// 1. Hard character cap.
				if (pAtmNameMaxChars > 0 && result.Length > pAtmNameMaxChars)
					result = MiddleEllipsis(name, pAtmNameMaxChars);

				// 2. Pixel-width fit -- binary-search the longest middle-truncated
				// form of the name that fits the budget, never exceeding the cap.
				if (fmt != null && widthBudget > 0 && MeasureCellText(result, fmt).Width > widthBudget)
				{
					int lo = 1, hi = result.Length, best = 1;
					while (lo <= hi)
					{
						int mid = (lo + hi) / 2;
						if (MeasureCellText(MiddleEllipsis(name, mid), fmt).Width <= widthBudget)
						{
							best = mid;
							lo = mid + 1;
						}
						else
							hi = mid - 1;
					}
					result = MiddleEllipsis(name, best);
				}

				return result;
			}

			// Trims s to at most maxLen characters, keeping the head and tail
			// with a single ellipsis character in the middle. The head keeps any
			// odd extra character.
			private string MiddleEllipsis(string s, int maxLen)
			{
				if (string.IsNullOrEmpty(s) || maxLen <= 0)
					return string.Empty;
				if (s.Length <= maxLen)
					return s;
				if (maxLen == 1)
					return "…";

				int keep = maxLen - 1;
				int head = (keep + 1) / 2;
				int tail = keep - head;
				string headPart = s.Substring(0, head);
				string tailPart = tail > 0 ? s.Substring(s.Length - tail) : string.Empty;
				return headPart + "…" + tailPart;
			}

