			private bool ATMSelectorContainsName(string name)
			{
				if (atmStrategySelector == null || string.IsNullOrEmpty(name))
					return false;
				foreach (object o in atmStrategySelector.Items)
				{
					AtmStrategy a = o as AtmStrategy;
					if (a != null && a.DisplayName == name)
