	private void MarketAdjustATM(NinjaTrader.NinjaScript.AtmStrategy selectedAtmStrategy2, int mainq, string ThisLastPlanDirection)
			{

				if (pLastPlanDirection == "Long")
				{

					mainq = mainq *-1;

				}

				// In H/L mode, buy AT or below the low (or sell AT or above the high) means
				// there is no valid H/L-based stop. Restore each bracket's StopLoss from the
				// ATM defaults up front so the per-bracket block below can leave the stop
				// alone and the display/render path sees the standard stop distance.
				if (pInitialExitsType == "High / Low" && selectedAtmStrategy2 != null)
				{
					double hlPriceCheck = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? InitialHLLowestLow : InitialHLHighestHigh;
					double entryRefCheck = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
					int muCheck = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? 1 : -1;
					bool hlWrongSideForPlan = hlPriceCheck <= 0 || entryRefCheck <= 0
						|| (muCheck == 1 && hlPriceCheck >= entryRefCheck)
						|| (muCheck == -1 && hlPriceCheck <= entryRefCheck);
					if (hlWrongSideForPlan)
						RestoreATMStopsToDefault(selectedAtmStrategy2);
				}


				if (selectedAtmStrategy2 != null)
				foreach( Bracket bb in selectedAtmStrategy2.Brackets)
				{






					if (pInitialExitsType == "High / Low")
					{
						// In H/L mode, recalculate stop ticks from planned entry to fixed H/L price (+ offset).
						// If the buy is AT or below the recent low, or the sell is AT or above the recent
						// high, there's no valid H/L stop — leave this bracket's StopLoss alone so the
						// pre-loop RestoreATMStopsToDefault pass keeps the ATM's standard stop.
						double hlPrice = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? InitialHLLowestLow : InitialHLHighestHigh;
						double entryRef = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
						int muHL = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? 1 : -1;
						bool hlWrongSide = hlPrice <= 0 || entryRef <= 0
							|| (muHL == 1 && hlPrice >= entryRef)
							|| (muHL == -1 && hlPrice <= entryRef);
						if (!hlWrongSide)
						{
							int newStopTicks = (int) Math.Round(Math.Abs(entryRef - hlPrice) / ThisTickSize, 0) + pInitialExitHLOffsetTicks;
							if (pInitialExitHLMinStopTicks > 0 && newStopTicks > 0 && newStopTicks < pInitialExitHLMinStopTicks)
								newStopTicks = pInitialExitHLMinStopTicks;
							if (newStopTicks > 0)
								// newStopTicks is in ticks; convert to whatever native units the ATM uses.
								bb.StopLoss = TicksToBracketUnits(newStopTicks, selectedAtmStrategy2, entryRef);
						}
					}
					else
					{
						// mainq is a tick delta; current bb.StopLoss is in native units.
						// Round-trip through ticks so the addition stays in tick-space, then
						// convert back to native units. Identity for Ticks mode.
						double entryRefAdd = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
						double curStopTicks = BracketUnitsToTicks(bb.StopLoss, selectedAtmStrategy2, entryRefAdd);
						bb.StopLoss = TicksToBracketUnits(curStopTicks + mainq, selectedAtmStrategy2, entryRefAdd);
					}

					if (!pRiskRewardPlanIsEnabled || !pRiskRewardEnabled)
					{
						double entryRefT = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
						double curTgtTicks = BracketUnitsToTicks(bb.Target, selectedAtmStrategy2, entryRefT);
						bb.Target = TicksToBracketUnits(curTgtTicks + mainq * -1, selectedAtmStrategy2, entryRefT);
					}
					else
					{
						// TargetTicksToRR is keyed in ticks (populated from
						// BracketUnitsToTicks-converted values), so look up by
						// the tick-equivalent of bb.Target, not raw bb.Target.
						double entryRefRR = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;
						double tgtTicksKey = BracketUnitsToTicks(bb.Target, selectedAtmStrategy2, entryRefRR);
						double rrrr = TargetTicksToRR.ContainsKey(tgtTicksKey) ? TargetTicksToRR[tgtTicksKey] : 1.0;

						// RR is dimensionless: multiplying native bb.StopLoss by RR
						// gives the new bb.Target in the same native units.
						bb.Target = rrrr * bb.StopLoss;
					}
										
					if (bb.StopLoss <= 0 || bb.Target <= 0)
					{
						
						pMarketPlanActive = false;
						HidePlan(false);
					
						
						
						
						ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, true, true);
						return;
					}
					
				}
				
				
			
			}
			
			
			
			
			
			

			private void GetATMData(NinjaTrader.NinjaScript.AtmStrategy selectedAtmStrategy2, int mainq, double ThisEntryPrice)
			{

				//Print(GetATMData);

				//Print(mainq);



					int i = 1;

				TargetTicksToName.Clear();
				StopTicksToName.Clear();

				TargetTicksToQty.Clear();
				StopTicksToQty.Clear();

				TargetTicksToRR.Clear();

				// NOTE: do NOT early-return here on ThisTickSize/ThisTickDollars.
				// ThisTickDollars is set lazily (see line ~4058) and can be 0 during
				// initial bars or instrument swaps. Clear() has already wiped the
				// dictionaries above, so returning early leaves them permanently
				// empty for this frame, wiping the plan visuals. Instead guard
				// division sites individually below.

				bool IsPercentBased = selectedAtmStrategy2 != null && selectedAtmStrategy2.CalculationMode == CalculationMode.Percent;
				bool IsCurrencyBased = selectedAtmStrategy2 != null && selectedAtmStrategy2.CalculationMode == CalculationMode.Currency;

							if (ThisEntryPrice == -10 || ThisEntryPrice == 10)
								ThisEntryPrice = CurrentLastData;

							if (ThisEntryPrice == 12)
								ThisEntryPrice = CurrentMousePrice;



				bool FirstLoop = true;

				double Stop1Ticks = 0;
				double Target1Ticks = 0;
				int StopTotalLots = 0;
				int RemainingQ = 0;

				double StopTicksNow = 0;
				double TargetTicksNow = 0;


				if (selectedAtmStrategy2 != null && selectedAtmStrategy2.Brackets != null)
				foreach( Bracket bb in selectedAtmStrategy2.Brackets)
				{

					//Print(bb.Target);

					// Handles Ticks / Currency / Percent / Pips / Price.
					StopTicksNow   = BracketUnitsToTicks(bb.StopLoss, selectedAtmStrategy2, ThisEntryPrice);
					TargetTicksNow = BracketUnitsToTicks(bb.Target,   selectedAtmStrategy2, ThisEntryPrice);


					if (FirstLoop)
					{


						Stop1Ticks = StopTicksNow;
						Target1Ticks = TargetTicksNow;

//						Print(ThisEntryPrice);
//						Print (bb.StopLoss);

						//Print(Stop1Ticks);

						RemainingQ = mainq;
					}




					//bb.Target = bb.Target + 1;

						// Target

					if (RemainingQ > 0)
					{

						// lots22 defaults to the bracket quantity even when there is no
						// target (stop-only brackets). Previously it stayed 0 and the
						// stop qty silently came out as 0 for those brackets.
						int lots22 = Math.Min(RemainingQ, bb.Quantity);

						if (bb.Target != 0)
						{

							//Print(bb.Quantity);

							//RemainingQ = Math.Min(bb.Quantity

							RemainingQ = RemainingQ - lots22;




							if (TargetTicksToName.ContainsKey(TargetTicksNow))
							{
								TargetTicksToName[TargetTicksNow] = TargetTicksToName[TargetTicksNow] + "/" + i.ToString();
								if (TargetTicksToQty.ContainsKey(TargetTicksNow))
									TargetTicksToQty[TargetTicksNow] = TargetTicksToQty[TargetTicksNow] + lots22;
								else
									TargetTicksToQty[TargetTicksNow] = lots22;
							}
							else
							{
								TargetTicksToName.Add(TargetTicksNow, "Target " + i.ToString());
								TargetTicksToQty.Add(TargetTicksNow, lots22);
							}




						}
						else
						{
							// stop-only bracket: still consume lots so RemainingQ tracks correctly
							RemainingQ = RemainingQ - lots22;
						}

						if (StopTicksToName.ContainsKey(StopTicksNow))
						{
							StopTicksToName[StopTicksNow] = StopTicksToName[StopTicksNow] + "/" + i.ToString();
							if (StopTicksToQty.ContainsKey(StopTicksNow))
								StopTicksToQty[StopTicksNow] = StopTicksToQty[StopTicksNow] + lots22;
							else
								StopTicksToQty[StopTicksNow] = lots22;
						}
						else
						{
							StopTicksToName.Add(StopTicksNow, "Stop " + i.ToString());
							StopTicksToQty.Add(StopTicksNow, lots22);
						}


						double rrrr = 0;

						// Guard against zero stop ticks (degenerate ATM with target but no stop)
						if (pRiskRewardEnabled && StopTicksNow > 0)
							rrrr = TargetTicksNow / StopTicksNow;


						//Print(rrrr

							if (TargetTicksToRR.ContainsKey(TargetTicksNow))
							{
								// When multiple brackets share the same target, keep the existing R/R
								// (they should be identical since they share the same stop)
							}
							else
							{
								TargetTicksToRR.Add(TargetTicksNow, rrrr);
							}







						StopTotalLots = StopTotalLots + lots22;

					}
						// Stop Loss


						//bb.StopStrategy.



					i++;
					FirstLoop = false;

				}
		
				
				if (RemainingQ > 0)
				if (StopTicksToName != null && TargetTicksToName != null)
				{
					if (StopTicksToName.Count == 1 && TargetTicksToName.Count > 1)
					{
						double thisone = 0;
						foreach (KeyValuePair<double, string> KKK in StopTicksToName)
							thisone = KKK.Key;
						
						StopTicksToName[thisone] = "Stop Loss";	
						
					}
					
					// allocate lots for bigger quantities to target 1 and stop 1
					
					int addq = mainq - StopTotalLots;
					
					if (TargetTicksToQty.ContainsKey(Target1Ticks))
						TargetTicksToQty[Target1Ticks] = TargetTicksToQty[Target1Ticks] + addq;
					
					
					if (StopTicksToQty.ContainsKey(Stop1Ticks))
						StopTicksToQty[Stop1Ticks] = StopTicksToQty[Stop1Ticks] + addq;
						
					
					
					//Print(StopTicksToQty[Stop1Ticks]);
					
					
					ThisPlanEntryQ = mainq;
				}
				
				
				
				
				
				// is this needed? // causes major refresh loops
				
				//RefreshRender(267);
				
				
			}
			
										
	
							
							
			static int closestNumber(int n, int m)
		    {
		        // find the quotient
		        int q = n / m;
		 
		        // 1st possible closest number
		        int n1 = m * q;
		 
		        // 2nd possible closest number
		        int n2 = (n * m) > 0 ? (m * (q + 1)) : (m * (q - 1));
		 
		        // if true, then n1 is the required closest number
		        if (Math.Abs(n - n1) < Math.Abs(n - n2))
		            return n1;
		 
		        // else n2 is the required closest number
		        return n2;
		    }
		 
			
			
