		protected void CreateWPFOrderControls()
		{
			try
			{

			// Ensure instrument is set before building panel
			if (ThisInstrumment == null && Instrument != null)
				SetInstrument();

			// Set control sizes early (must be before any controls are created)
			smallControlHeight = pSecondaryControlHeight;
			smallGapH = 3 + Math.Max(0, (pControlGap - 3) / 2);
			primaryFontSize = pPrimaryFontSize;

			// Resolve panel font — default to chart font, persist its name so the property grid dropdown shows it
			if (string.IsNullOrEmpty(pPanelFontFamily))
			{
				if (ChartControl != null && ChartControl.Properties != null && ChartControl.Properties.LabelFont != null && ChartControl.Properties.LabelFont.Family != null)
					pPanelFontFamily = ChartControl.Properties.LabelFont.Family.Source;
				else
					pPanelFontFamily = "Segoe UI";
			}
			try { panelFont = new System.Windows.Media.FontFamily(pPanelFontFamily); }
			catch { panelFont = new System.Windows.Media.FontFamily("Segoe UI"); }

			int MainButtonHeight = pPrimaryControlHeight + 2;

			int MainButtonSpace = pSectionSpacing;
			int MainButtonSpace2 = 0;

			chartWindow			= System.Windows.Window.GetWindow(ChartControl.Parent) as Chart;
			//Print("ECT CreateWPF - chartWindow=" + (chartWindow != null));
			if (chartWindow == null)
			{
				// Chart window not yet attached to the visual tree. Happens when ECT is
				// restored via Chart.Restore from a programmatically-generated template
				// (launchers) because the indicator's State.Historical/Dispatcher callback
				// runs before WPF has composed the chart into its window. Retry at
				// DispatcherPriority.Loaded — that priority fires after the visual tree
				// is loaded, so GetWindow(ChartControl.Parent) will return the Chart.
				// Without this retry the WPF panel only builds after a NinjaScript reload.
				if (ChartControl != null)
					ChartControl.Dispatcher.BeginInvoke(
						System.Windows.Threading.DispatcherPriority.Loaded,
						(Action)(() => { try { CreateWPFOrderControls(); } catch { } }));
				return;
			}
			chartGrid			= chartWindow.MainTabControl.Parent as System.Windows.Controls.Grid;
			//Print("ECT CreateWPF - chartGrid=" + (chartGrid != null));

			try
			{
				var dpiSrc = System.Windows.PresentationSource.FromVisual(chartWindow);
				double dpiX = 96.0, dpiY = 96.0;
				if (dpiSrc != null && dpiSrc.CompositionTarget != null)
				{
					var m = dpiSrc.CompositionTarget.TransformToDevice;
					dpiX = 96.0 * m.M11;
					dpiY = 96.0 * m.M22;
				}
				int dpiPct = (int)Math.Round(dpiX / 96.0 * 100.0);
				LogDiag("UI", "WindowLoaded", "DPI=" + dpiPct + "%|DpiX=" + dpiX.ToString("F0") + "|DpiY=" + dpiY.ToString("F0"));
			}
			catch { }
			
			buttonGrid = new System.Windows.Controls.Grid();

			buttonGrid.PreviewKeyDown += buttonGridKey;
			
			
			chartWindow.KeyDown += chartWindow_KeyDown;
			
			buttonGrid.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = new GridLength(CTLeftSpace) }); // width of market / limit
			buttonGrid.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = new GridLength(1, GridUnitType.Star) }); // fills available width

			// Create StackPanels for collapsible sections layout
			pinnedStack = new System.Windows.Controls.StackPanel();
			pinnedStack.Orientation = System.Windows.Controls.Orientation.Vertical;
			pinnedStack.Margin = new Thickness(3, 0, 3, 0);

			mainPanelStack = new System.Windows.Controls.StackPanel();
			mainPanelStack.Orientation = System.Windows.Controls.Orientation.Vertical;
			mainPanelStack.Margin = new Thickness(3, 0, 3, 0);

			sectionHeaderButtons.Clear();
			sectionContentGrids.Clear();
			styledButtons.Clear();
			tertiaryButtons.Clear();
			allKeyboardQuds.Clear();
			accentStripCache.Clear();
			accentStripRightCache.Clear();
			pulsingButtons.Clear();
			pulseGlowByButton.Clear();
			if (pulseTimer != null) { pulseTimer.Stop(); pulseTimer.Tick -= PulseTimer_Tick; pulseTimer = null; }
			nativeStyledControls.Clear();
			lastMeasuredPanelWidth = -1;
			// Clear brush cache alongside the template cache so any config change that
			// affects brush generation (colors, brightness constants, gradient stops)
			// takes effect on rebuild. Brushes are rebuilt lazily on first button style
			// so the perf cost is negligible.
			buttonBrushCache.Clear();
			cachedPrimaryButtonTemplate = null;
