						// Conditional hover tooltip for the ATM strategy selector:
						// shows the complete strategy name, but ONLY when the name
						// is too long to fit in the closed combo (otherwise the
						// tooltip would just repeat what's already visible). The
						// ToolTipOpening handler re-measures the displayed text on
						// every hover and cancels itself when the name fully fits.
						// ToolTipService must stay enabled for ToolTipOpening to
						// fire — it was previously disabled to suppress the
						// control's default tooltip, which our own ToolTip replaces.
						System.Windows.Controls.ToolTipService.SetIsEnabled(atmStrategySelector, true);
						atmSelectorTip = MakeToolTip();
						atmStrategySelector.ToolTip = atmSelectorTip;
						atmStrategySelector.ToolTipOpening += (o, args) =>
						{
							try
							{
								string fullName;
								if (atmSelectorTip == null || !IsAtmSelectorNameTruncated(out fullName))
								{
									args.Handled = true;
									return;
								}
								atmSelectorTip.Content = fullName;
							}
							catch (Exception)
							{
								args.Handled = true;
							}
						};

