						atmStrategySelector.Account = myAccount;

						// Stable Id derived from instrument + bars period + indicator name. Previously
						// this was Guid.NewGuid() on every panel build, which prevented NT from
						// associating any workspace-restored state (e.g. last-selected ATM template,
						// custom ATM properties) with this selector across reloads. A stable id lets
						// NT recognize "this is the same selector that was here before" and skip work.
						{
							string idSeed = (ThisMasterInstrument != null ? ThisMasterInstrument.Name : "noinst")
								+ "|" + (BarsArray != null && BarsArray.Length > 0 && BarsArray[0] != null ? BarsArray[0].BarsPeriod.ToString() : "nobars")
								+ "|" + ThisName;
							// Hash to a stable 32-char hex string (matches Guid.ToString("N") format)
							using (var md5 = System.Security.Cryptography.MD5.Create())
							{
								byte[] hash = md5.ComputeHash(System.Text.Encoding.UTF8.GetBytes(idSeed));
								var sb = new System.Text.StringBuilder(32);
								for (int i = 0; i < hash.Length; i++) sb.Append(hash[i].ToString("x2"));
								atmStrategySelector.Id = sb.ToString();
							}
						}

						// ── Force immediate population of Items collection ──
						// NT's AtmStrategySelector lazily populates Items only after Account/Instrument/
						// Connection events fire — which can take 5+ seconds after a NinjaScript reload
						// because it waits for the AccountSelector binding to push a value, which itself
						// waits for connection status updates. By calling the internal RebuildItems(account,
						// instrument, id) method directly via reflection, we bypass that wait entirely and
						// populate from local disk templates synchronously. The selector will rebuild again
						// later when Account actually arrives via the binding, but our DefaultAtmStrategy
						// dictionary and ATM quick-select buttons get populated immediately.
						try
						{
							var rebuildMI = atmStrategySelector.GetType().GetMethod(
								"RebuildItems",
								System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
							if (rebuildMI != null)
							{
								rebuildMI.Invoke(atmStrategySelector, new object[]
								{
									atmStrategySelector.Account,    // may be null — RebuildItems handles it
									atmStrategySelector.Instrument,
									atmStrategySelector.Id
								});
							}
						}
						catch (Exception) { }
					
						
					
						
