						//
					

						atmStrategySelector.MouseDoubleClick += (o, args) =>
						{
							//Print("DC");
							
						};
						
						// PreviewMouseUp (tunneling) instead of MouseUp — after a fresh
						// reload NT8's AtmStrategySelector ComboBox would eat the first
						// MouseUp to handle focus / dropdown state, so our handler
						// didn't fire until the second click. Preview fires before the
						// ComboBox consumes the event, so the first click launches the
						// plan immediately.
						atmStrategySelector.PreviewMouseUp += (o, args) =>
						{

							// Bail out entirely when ATM Strategy Planning is off OR
							// the chart-side "ATM Planning" toggle button has it
							// hidden. Without this, clicking the 'i' / dropdown still
							// armed the plan-in-progress flow (sentinel 13, hand
							// cursor, IsMovingPlan, the chart-bottom hint) even
							// though no plan visuals would render — leaving the
							// user with an invisible armed mode.
							if (!pATMPreviewButtonEnabled || !pPlanEnabled)
								return;


							// Reconcile ClicksInATM with the actual visible plan state.
							// Fixes the intermittent "takes two clicks on first load"
							// bug: if the counter got left at 1 by a prior session
							// that was torn down without reaching the hide branch
							// (or by any other state drift), a plan that is NOT
							// currently showing must still launch on the very next
							// click. Force the counter to 0 whenever the visual
							// state confirms no plan is up — that way the post-
							// increment below always lands on the ClicksInATM == 1
							// launch branch.
							if (!_hasPlanInProgress && TotalPlansShowing() == 0)
								ClicksInATM = 0;

							ClicksInATM = ClicksInATM + 1;


							if (ClicksInATM == 1)
							{

								HidePlan(false);

								// Capture the chart-side "ATM Planning" toggle state
								// BEFORE the auto-enable below so we can decide later
								// whether to show the chart-bottom hint message. If the
								// user has the chart-side button toggled off, they're
								// hiding plan visuals — no hint either.
								bool planEnabledAtClick = pPlanEnabled;

								if (!pPlanEnabled)
									pPlanEnabled = true;

								//pIsPlanInProgress = CurrentLastData;

								if (pMarketPlanActiveSaved)
								{
									// Market mode: launch immediately at the last traded
									// price. Plan follows price until user toggles to Price.
									pMarketPlanActive = true;
									SetPlanInProgress(CurrentLastData);
									AddATMPlanEntry(pIsPlanInProgress, 10000);
								}
								else
								{
									// Price mode: mirror the Buy Click / Sell Click flow —
									// start the "moving entry" routine with sentinel 13
									// following the mouse. The next chart click on the entry
									// line hitbox (handled by the Entry 2 click branch at
									// :51798) locks the plan's entry price at the click
									// location via SetPlanInProgress(CurrentMousePrice).
									pMarketPlanActive = false;

									// Default direction when none has been chosen yet so
									// IsMovingPlan is non-empty (the move-flow guard).
									if (pLastPlanDirection != "Long" && pLastPlanDirection != "Short")
										pLastPlanDirection = "Long";

									IsMovingPlan = pLastPlanDirection;
									AddATMPlanEntry(13, 1000);

									// Status hint at chart bottom — tells the user the plan
									// is waiting for a chart click and that the wheel can
									// flip Long/Short. Cleared at every IsMovingPlan = "".
									// Suppress when ATM Strategy Planning is disabled
									// outright (master feature toggle) OR the chart-side
									// "ATM Planning" toggle button had it hidden at click
									// time — in either case the user isn't looking for a
									// plan visual, so the hint would just be noise. Use
									// the captured pre-auto-enable value because the
									// block above forces pPlanEnabled = true.
									if (pATMPreviewButtonEnabled && planEnabledAtClick)
										AddMessage(ATMPlanWaitingForClick, 60, Brushes.Goldenrod);

									// Pin the hand cursor immediately on mode entry — same
									// rationale as BuyClickNow. Without this, the chart
									// cursor stays whatever it was until the next
									// OnRender / MouseMove tick.
									ApplyHoverCursor();
								}

								//ShowPlan(true, pLastPlanDirection);

								// Double refresh so the plan appears on the very next frame
								// instead of waiting for the user's next mouse move to trigger
								// a render pass.
								RefreshRender(268);
								RefreshRender(268);

							}
							
							else if (ClicksInATM == 2)
							{

								ClicksInATM = 0;

								pMarketPlanActive = false;
								IsMovingPlan = "";
								RemoveMessage(false, ATMPlanWaitingForClick);

								HidePlan(false);
								RefreshRender(269);


//								if (pLastPlanDirection == "Short")
//									pLastPlanDirection = "Long";
//								else
//									pLastPlanDirection = "Short";


							}
							else
