			// Enable keyboard typing in QuantityUpDown controls.
			// NinjaTrader's chart window intercepts PreviewKeyDown before our controls see key events.
			// Solution: use AddHandler with handledEventsToo=true on each QUD to catch swallowed keys,
			// then use HandleQtyKeyInput to manually set .Value from accumulated digits.
			System.Windows.Input.KeyEventHandler qudKeyInputHandler = (kSender, kArgs) =>
			{
				if (!pAllowKeyboardQtyEntry) return;
				var qud = kSender as NinjaTrader.Gui.Tools.QuantityUpDown;
				if (qud == null) return;
				if (HandleQtyKeyInput(qud, kArgs.Key))
					kArgs.Handled = true;
			};
			// Click-to-focus: make sure clicking anywhere on the QUD gives it logical
			// keyboard focus so subsequent keystrokes route through our KeyDown handler.
			// Without this, the inner spinner/textbox may keep focus on a sub-element
			// that swallows our handler.
			System.Windows.Input.MouseButtonEventHandler qudFocusOnClick = (mSender, mArgs) =>
			{
				if (!pAllowKeyboardQtyEntry) return;
				var qud = mSender as NinjaTrader.Gui.Tools.QuantityUpDown;
				if (qud == null) return;
				try { System.Windows.Input.Keyboard.Focus(qud); } catch { }
			};

			// Focus glow: shared frozen DropShadowEffect applied to the QUD while it
			// holds keyboard focus, removed on blur. Color tuned to match NinjaTrader's
			// native royal-blue focus border (#26A0DA — the "Windows highlight blue"
			// NT paints on focused text controls) so the glow reads as an extension
			// of NT's own focus styling rather than a custom accent.
			var focusGlow = new System.Windows.Media.Effects.DropShadowEffect
			{
				Color = System.Windows.Media.Color.FromRgb(38, 160, 218), // #26A0DA
				BlurRadius = 12,
				ShadowDepth = 0,
				Opacity = 0.9
			};
			focusGlow.Freeze();
			// Use IsKeyboardFocusWithinChanged instead of Got/LostKeyboardFocus.
			// QUD is a composite control — its inner TextBox grabs focus independently
			// from the outer QUD, and moving the mouse away can trigger an internal
			// focus shuffle that fires LostKeyboardFocus on the outer QUD even though
			// keyboard focus is still logically inside it. IsKeyboardFocusWithin
			// tracks the entire logical subtree and stays true until focus *really*
			// leaves the control.
			System.Windows.DependencyPropertyChangedEventHandler qudFocusWithinChanged = (s, e) =>
			{
				var fe = s as System.Windows.FrameworkElement;
				if (fe == null) return;
				bool hasFocus = (bool)e.NewValue;
				fe.Effect = hasFocus ? focusGlow : null;
			};

			Action<NinjaTrader.Gui.Tools.QuantityUpDown> wireQud = qud =>
			{
				if (qud == null) return;
				qud.AddHandler(System.Windows.UIElement.KeyDownEvent, qudKeyInputHandler, true);
				qud.AddHandler(System.Windows.UIElement.PreviewMouseLeftButtonDownEvent, qudFocusOnClick, true);
				qud.IsKeyboardFocusWithinChanged += qudFocusWithinChanged;
				qud.Focusable = true;
				allKeyboardQuds.Add(qud); // order matters — used by Tab navigation
			};
			// Wire QUDs in the order they appear visually top-to-bottom in the panel.
			// The Tab handler walks this list to find the next visible+enabled control,
			// so correct order is what makes Tab navigation feel natural.
			//
			// Verified section layout (sections via CreateCollapsibleSection ~line 26722,
			// sub-grid row/col assignments via Grid.SetRow/SetColumn):
			//
			//   ATM & Position Sizing:
			//     row 1 atmstrGrid  → OffsetBox16 (col 0, Free SL), OffsetBox17 (col 2, Free PT)
			//     row 3 QtyTIFGrid  → qudSelector (main qty)
			//   Position Management: (no QUDs)
			//   Trailing Stop Loss: TrailingStopGrid → OffsetBox10
			//   Market Entry: (no QUDs)
			//   Limit Entry:  (no QUDs)
			//   Click Entry:  ClickEntryGrid → OffsetBox4
			//   Price Based Entry: StopEntryGrid → OffsetBox14 (col 1, left), OffsetBox13 (col 7, right)
			//   Signal Entry: SignalEntryGrid → OffsetBox15
			//   Close Entry:  CloseEntryGrid → OffsetBox1   ← actually here, not Position Management
			//   Iceberg / Sliced Entry (IcebergButtons rows):
			//     row 3 IcebergQtyVarianceGrid → OffsetBox6 (col 1), OffsetBox7 (col 3)
			//     row 5 IcebergOrderTypeGrid   → OffsetBox2
			//     row 9 TimeSlicedIntervalGrid → OffsetBox8 (col 1), OffsetBox9 (col 5)
			//   Bracket Entry: BracketGrid → OffsetBox3 (col 0), OffsetBox5 (col 4)
			//   Duplicate (bottom): DuplicateGrid → OffsetBox12
			//
			// Note: OffsetBox11 is built but its parent TimeSlicedPriceGrid is never added
			// to the tree (the add line is commented out), so it's effectively dead — skipped.

			// ATM & Position Sizing
			wireQud(OffsetBox16); // Free Edition stop-loss ticks (null in non-Free; wireQud tolerates)
			wireQud(OffsetBox17); // Free Edition profit-target ticks
			wireQud(qudSelector); // main quantity

			// Trailing Stop Loss
			wireQud(OffsetBox10);

			// Click Entry
			wireQud(OffsetBox4);

			// Price Based Entry — col 1 then col 7 left-to-right
			wireQud(OffsetBox14);
			wireQud(OffsetBox13);

			// Signal Entry
			wireQud(OffsetBox15);

			// Close Entry
			wireQud(OffsetBox1);

			// Iceberg / Sliced Entry — Qty Variance row first, then OrderType row, then Time-Sliced row
			wireQud(OffsetBox6);  // Iceberg qty
			wireQud(OffsetBox7);  // Iceberg variance
			wireQud(OffsetBox2);  // Iceberg order type offset
			wireQud(OffsetBox8);  // Time-sliced interval (col 1)
			wireQud(OffsetBox9);  // Time-sliced (col 5)

			// Bracket Entry
			wireQud(OffsetBox3);  // Bracket stop (col 0)
			wireQud(OffsetBox5);  // Bracket target (col 4)

			// Duplicate (bottom of panel)
			wireQud(OffsetBox12);
			
			
			
