			// Build Collapse/Expand All toggle button — will be placed in PNL header row
			System.Windows.Controls.Button collapseAllToggle = null;
			if (pCollapsibleSectionsEnabled && pCollapseAllButtonEnabled)
			{
				// Scale with header font so large font settings don't clip the text.
				// Baseline 20px for the default 11pt header font, ~1.7× ratio above that.
				int toggleHeight = Math.Max(20, (int)(pHeaderFontSize * 1.7));
				double toggleFontSize = pHeaderFontSize;
				collapseAllToggle = new System.Windows.Controls.Button
				{
					Content = "Collapse All ▼",
					HorizontalContentAlignment = System.Windows.HorizontalAlignment.Right,
					Background = System.Windows.Media.Brushes.Transparent,
					Foreground = GetHeaderForegroundBrush(70),
					BorderThickness = new System.Windows.Thickness(0, 0, 0, 1),
					BorderBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(20, 128, 128, 128)),
					Height = toggleHeight,
					Padding = new System.Windows.Thickness(2, 0, 3, 0),
					FontFamily = panelFont,
					FontWeight = System.Windows.FontWeights.SemiBold,
					FontSize = toggleFontSize,
					Cursor = System.Windows.Input.Cursors.Hand,
					FocusVisualStyle = null
				};

				// Custom template to remove default WPF button chrome (gray pressed state)
				var toggleTemplate = new System.Windows.Controls.ControlTemplate(typeof(System.Windows.Controls.Button));
				var toggleBorderFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border));
				toggleBorderFactory.SetValue(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("Background") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
				toggleBorderFactory.SetValue(System.Windows.Controls.Border.BorderBrushProperty, new System.Windows.Data.Binding("BorderBrush") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
				toggleBorderFactory.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Data.Binding("BorderThickness") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
				var toggleCpFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ContentPresenter));
				toggleCpFactory.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, new System.Windows.Data.Binding("HorizontalContentAlignment") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
				toggleCpFactory.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
				toggleCpFactory.SetValue(System.Windows.FrameworkElement.MarginProperty, new System.Windows.Data.Binding("Padding") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
				toggleBorderFactory.AppendChild(toggleCpFactory);
				toggleTemplate.VisualTree = toggleBorderFactory;
				collapseAllToggle.Template = toggleTemplate;

				collapseAllButton = collapseAllToggle;
				var toggleBtnLocal = collapseAllToggle;
				toggleBtnLocal.MouseEnter += (s, ev) =>
				{
					toggleBtnLocal.Foreground = GetHeaderForegroundBrush(220);
				};
				toggleBtnLocal.MouseLeave += (s, ev) =>
				{
					toggleBtnLocal.Foreground = GetHeaderForegroundBrush(70);
				};
				collapseAllState = false;
				toggleBtnLocal.Click += (sender, args) =>
				{
					collapseAllState = !collapseAllState;
					for (int si = 0; si < sectionContentGrids.Count; si++)
					{
						AnimateSectionExpand(sectionContentGrids[si], !collapseAllState);
					}
					foreach (var kvp in new List<string>(sectionExpandedStates.Keys))
