						sectionExpandedStates[kvp] = !collapseAllState;
					}
					for (int si = 0; si < sectionHeaderButtons.Count; si++)
					{
						string txt = sectionHeaderButtons[si].Content.ToString();
						if (txt.Length > 2)
							sectionHeaderButtons[si].Content = (collapseAllState ? "▶ " : "▼ ") + txt.Substring(2);
					}
					UpdateCollapseAllButtonText();
					SaveSectionStates();
					System.Windows.Input.Keyboard.ClearFocus();
				};
			}

