			// ── Market Data Panel (Bid/Ask) ──
			{
				double mdFontSize = pMarketDataFontSize;
				double mdPriceFontSize = mdFontSize;
				double mdRowHeight = Math.Max(mdPriceFontSize + 10, 24);
				var mdFontFamily = panelFont;
				var mdTextBrush = ChartControl.Properties.ChartText;

				// The grey/white shades below are invisible on a light panel — pick
				// light or dark grey/overlay values to match the panel's background.
				bool mdDark = PanelBackgroundIsDark();
				byte mdVolC     = mdDark ? (byte)220 : (byte)55;  // volume number grey
				byte mdDimC     = mdDark ? (byte)180 : (byte)95;  // dim "SPREAD:" label
				byte mdBrightC  = mdDark ? (byte)240 : (byte)20;  // bright spread tick number
				byte mdOverlayC = mdDark ? (byte)255 : (byte)0;   // row separators + spread row bg

				// Color scheme
				var askRedBrush = FrozenRgbBrush(180, 50, 50);
				askRedBrush.Freeze();
				var bidGreenBrush = FrozenRgbBrush(50, 160, 50);
				bidGreenBrush.Freeze();
				var askBarBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(60, 220, 60, 60));
				askBarBrush.Freeze();
				var bidBarBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(60, 60, 200, 60));
				bidBarBrush.Freeze();
				var dimTextBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(140, mdDimC, mdDimC, mdDimC));
				dimTextBrush.Freeze();
				var spreadBgBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(30, mdOverlayC, mdOverlayC, mdOverlayC));
				spreadBgBrush.Freeze();
				var rowSepBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(40, mdOverlayC, mdOverlayC, mdOverlayC));
				rowSepBrush.Freeze();
				var volTextBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(200, mdVolC, mdVolC, mdVolC));
