					FontFamily = mdFontFamily,
					FontSize = mdFontSize - 1,
					Foreground = dimTextBrush,
					VerticalAlignment = System.Windows.VerticalAlignment.Center,
					HorizontalAlignment = System.Windows.HorizontalAlignment.Center
				};
				// Build "SPREAD:   <bold brighter number>  t" as three inline Runs so the tick
				// count stands out. Extra spaces around the number give it visual breathing
				// room. mdSpreadNumberRun is reused on each market-data tick — updating just
				// its Text avoids re-allocating inlines on every update.
				var spreadBrightBrush = new System.Windows.Media.SolidColorBrush(
					System.Windows.Media.Color.FromArgb(230, mdBrightC, mdBrightC, mdBrightC));
				spreadBrightBrush.Freeze();
				mdSpread.Inlines.Add(new System.Windows.Documents.Run("SPREAD:   "));
				mdSpreadNumberRun = new System.Windows.Documents.Run("-")
				{
					FontWeight = System.Windows.FontWeights.Bold,
					Foreground = spreadBrightBrush
				};
				mdSpread.Inlines.Add(mdSpreadNumberRun);
				mdSpread.Inlines.Add(new System.Windows.Documents.Run("  t"));
				spreadBorder.Child = mdSpread;
				System.Windows.Controls.Grid.SetRow(spreadBorder, 1);
				System.Windows.Controls.Grid.SetColumn(spreadBorder, 0);
				System.Windows.Controls.Grid.SetColumnSpan(spreadBorder, 3);
				mdPanel.Children.Add(spreadBorder);
				mdSpreadBorder = spreadBorder;

				// Row separator line above spread
				var sepTop = new System.Windows.Controls.Border()
				{
					Background = rowSepBrush,
