				if (DefaultAtmStrategy.Count == 0)
				{
					// Subscribe to Items collection so we get notified the moment items arrive.
					// ItemCollection implements INotifyCollectionChanged in WPF.
					var notify = atmStrategySelector.Items as System.Collections.Specialized.INotifyCollectionChanged;
					if (notify != null)
					{
						System.Collections.Specialized.NotifyCollectionChangedEventHandler atmItemsHandler = null;
						atmItemsHandler = (s, e) =>
						{
							try
