								InitializeDefaultATM();
								if (DefaultAtmStrategy.Count > 0)
								{
									SetATMButtonLabels();
									notify.CollectionChanged -= atmItemsHandler;
								}
							}
							catch (Exception) { }
						};
						notify.CollectionChanged += atmItemsHandler;
					}
					// Note: OnTimer4Tick (30ms timer) also calls InitializeDefaultATM as a safety net
					// in case the CollectionChanged event was missed.
				}
