		private void UpdatePOSDisplay()
		{
		
			//if (label4 == null) return;
			if (qudSelector3 == null) return;
			if (qudSelector4 == null) return;
			if (label6 == null) return;
			
			
			if (pPositionSizingMode == "Percent")
			{
				label4.Text = "%";
				qudSelector3.Visibility = Visibility.Hidden;
				qudSelector4.Visibility = Visibility.Visible;
				//label6.Visibility = Visibility.Visible;
				
//				posizeGrid.ColumnDefinitions[4].Width = new GridLength(ps1);
//				posizeGrid.ColumnDefinitions[5].Width = new GridLength(ps3);
				
				label6.Text = pPositionSizingPercentRisk.ToString("n1") + " %";
			}
			else
			{
				pPositionSizingDollarsRisk = closestNumber(pPositionSizingDollarsRisk, pPositionSizingDollarsRiskI);
				
				label4.Text = "$";
				qudSelector3.Visibility = Visibility.Visible;
				qudSelector4.Visibility = Visibility.Hidden;
				//label6.Visibility = Visibility.Hidden;
				
//				posizeGrid.ColumnDefinitions[4].Width = new GridLength(ps2);
//				posizeGrid.ColumnDefinitions[5].Width = new GridLength(ps4);
				
				
				
				label6.Text = "$ " + pPositionSizingDollarsRisk.ToString();
				
			}
			
			
			
		}

		private void DisposeWPFOrderControls()
		{
			// Persist section expand/collapse states before disposal
			SaveSectionStates();

//			if (button1 != null)
//				button1.Click -= Button1_PreviewMouseUp;

//			if (button2 != null)
//				button2.Click -= Button2_PreviewMouseUp;



			if (chartWindow != null)
				chartWindow.MainTabControl.SelectionChanged -= TabChangedHandler;

			if (accountSelectorMain != null)
							if (accountSelectorMain.SelectedAccount != null)
							{
								//myAccount = accountSelectorMain.SelectedAccount;
								
								// Unsubscribe to any prior account subscriptions
								accountSelectorMain.SelectedAccount.AccountItemUpdate -= OnAccountItemUpdate2;
								accountSelectorMain.SelectedAccount.ExecutionUpdate -= OnExecutionUpdate2;
								accountSelectorMain.SelectedAccount.OrderUpdate -= OnOrderUpdate2;
								accountSelectorMain.SelectedAccount.PositionUpdate -= OnPositionUpdate2;

						
							}
							
							
			if (accountSelectorMaster != null)
							if (accountSelectorMaster.SelectedAccount != null)
							{
								//myAccount = accountSelectorMain.SelectedAccount;
								
								// Unsubscribe to any prior account subscriptions
								accountSelectorMaster.SelectedAccount.AccountItemUpdate -= OnAccountItemUpdate3;
								accountSelectorMaster.SelectedAccount.ExecutionUpdate -= OnExecutionUpdate3;
								accountSelectorMaster.SelectedAccount.OrderUpdate -= OnOrderUpdate3;
								accountSelectorMaster.SelectedAccount.PositionUpdate -= OnPositionUpdate3;

						
							}
							
							
//			accountSelectorMain.Cleanup();
//            atmStrategySelector.Cleanup();
//			tifSelector1.Cleanup();


			RemoveWPFOrderControls();

			// Final teardown — RemoveWPFOrderControls now preserves the cached panel structure
			// for fast tab switches, so detach keyboard handlers and drop references here.
			try
			{
				if (buttonGrid != null)
					buttonGrid.PreviewKeyDown -= buttonGridKey;
				if (chartWindow != null)
					chartWindow.KeyDown -= chartWindow_KeyDown;
			}
			catch (Exception) { }

			if (panelResizeHandle != null)
			{
				panelResizeHandle.MouseLeftButtonDown -= PanelResize_MouseDown;
				panelResizeHandle.MouseMove -= PanelResize_MouseMove;
				panelResizeHandle.MouseLeftButtonUp -= PanelResize_MouseUp;
			}
			panelResizeHandle = null;
			panelDockPanel = null;
			panelScrollViewer = null;
			panelFadeOverlay = null;
			panelFadeOverlayTop = null;
			panelOuterGrid = null;

			// Clear button-keyed caches to release references for GC
			// (buttonBrushCache is color-keyed and safe to keep across disposal)
			styledButtons.Clear();
			tertiaryButtons.Clear();
			accentStripCache.Clear();
			accentStripRightCache.Clear();
			pulsingButtons.Clear();
			pulseGlowByButton.Clear();
			if (pulseTimer != null) { pulseTimer.Stop(); pulseTimer.Tick -= PulseTimer_Tick; pulseTimer = null; }
		}

		// Detaches OnOrderUpdate2 / OnPositionUpdate2 / OnExecutionUpdate2 /
		// OnAccountItemUpdate2 (and the master-account *3 set) from every account
		// they may have been wired to. Safe to call repeatedly and from any thread:
		// Account.*Update are plain CLR events, so '-=' needs no Dispatcher, and
		// detaching a handler that was never attached is a harmless no-op. Called
		// unconditionally on State.Terminated so a closed-chart instance cannot
		// linger as a zombie still receiving callbacks on the Cbi thread.
		private void DetachAccountEventHandlers()
		{
			try
			{
				Account[] accts = new Account[]
				{
					myAccount,
					_subscribedMainAccount,
					_subscribedMasterAccount,
					accountSelectorMain   != null ? accountSelectorMain.SelectedAccount   : null,
					accountSelectorMaster != null ? accountSelectorMaster.SelectedAccount : null
				};

				foreach (Account a in accts)
				{
					if (a == null)
						continue;

					a.AccountItemUpdate -= OnAccountItemUpdate2;
					a.ExecutionUpdate   -= OnExecutionUpdate2;
					a.OrderUpdate       -= OnOrderUpdate2;
					a.PositionUpdate    -= OnPositionUpdate2;

					a.AccountItemUpdate -= OnAccountItemUpdate3;
					a.ExecutionUpdate   -= OnExecutionUpdate3;
					a.OrderUpdate       -= OnOrderUpdate3;
					a.PositionUpdate    -= OnPositionUpdate3;
				}
			}
			catch { }
		}

		/// True when the panel's effective background is dark, so text and overlays
		/// drawn on the panel should be light. The panel's controls sit on
		/// buttonGrid.Background (the Sim/Live colour) — when that is opaque, text
		/// must contrast with IT, not the chart. Only a transparent panel lets the
		/// chart background show through. Falls back to the chart background, then
		/// the NT8 skin, when the panel colour isn't known yet.
		private bool PanelBackgroundIsDark()
		{
			// GetTextColor returns WhiteSmoke for dark backgrounds, Black for light.
			System.Windows.Media.Brush panelBg = (buttonGrid != null) ? buttonGrid.Background : null;
			bool panelOpaque = false;
			if (panelBg is System.Windows.Media.SolidColorBrush)
				panelOpaque = ((System.Windows.Media.SolidColorBrush)panelBg).Color.A != 0;
			else if (panelBg is System.Windows.Media.GradientBrush)
				panelOpaque = true;

			if (panelOpaque)
				return GetTextColor(panelBg) == System.Windows.Media.Brushes.WhiteSmoke;

			// Transparent panel — the chart background shows through.
			if (ThisChartBackground != null && ThisChartBackground != System.Windows.Media.Brushes.Transparent)
				return GetTextColor(ThisChartBackground) == System.Windows.Media.Brushes.WhiteSmoke;

			// ThisChartBackground isn't populated until first render; read the chart
			// background directly so a panel built before then is still correct.
			if (ChartControl != null && ChartControl.Properties != null
				&& ChartControl.Properties.ChartBackground != null)
				return GetTextColor(ChartControl.Properties.ChartBackground) == System.Windows.Media.Brushes.WhiteSmoke;

			string skinname = NinjaTrader.Core.Globals.GeneralOptions.Skin.ToString();
			return skinname == "NinjaTrader Dark" || skinname == "Dark"
				|| skinname == "Slate Dark" || skinname == "Slate Gray";
		}

		/// Returns a white or black brush for section header / Collapse-All text,
		/// chosen to contrast with the panel's effective background.
		/// Applied at the supplied alpha (idle = 70, hover = 220).
		private System.Windows.Media.SolidColorBrush GetHeaderForegroundBrush(byte alpha)
		{
			byte v = PanelBackgroundIsDark() ? (byte)255 : (byte)0;
			return new System.Windows.Media.SolidColorBrush(
				System.Windows.Media.Color.FromArgb(alpha, v, v, v));
		}

		/// Re-applies section-header / Collapse-All / version-label text colour.
		/// These controls are built before the account handler assigns
		/// buttonGrid.Background, so their first colour is computed against the
		/// wrong surface; this corrects them once the panel background is known.
		private void RefreshSectionHeaderColors()
		{
			System.Windows.Media.SolidColorBrush hb = GetHeaderForegroundBrush(70);
			if (sectionHeaderButtons != null)
				foreach (System.Windows.Controls.Button b in sectionHeaderButtons)
					if (b != null) b.Foreground = hb;
			if (collapseAllButton != null) collapseAllButton.Foreground = hb;
			if (versionLabel != null) versionLabel.Foreground = hb;
		}

		/// Re-applies the Market Data panel's adaptive greys/overlays. Built before
		/// the account handler sets buttonGrid.Background, so without this the
		/// volume/spread text stays shaded for the wrong (chart) background.
		private void RefreshMarketDataColors()
		{
			bool dark = PanelBackgroundIsDark();
			byte volC     = dark ? (byte)220 : (byte)55;
			byte dimC     = dark ? (byte)180 : (byte)95;
			byte brightC  = dark ? (byte)240 : (byte)20;
			byte overlayC = dark ? (byte)255 : (byte)0;
			System.Windows.Media.SolidColorBrush volBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(200, volC, volC, volC));
			if (mdAskVol != null) mdAskVol.Foreground = volBrush;
			if (mdBidVol != null) mdBidVol.Foreground = volBrush;
			if (mdSpread != null) mdSpread.Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(140, dimC, dimC, dimC));
			if (mdSpreadNumberRun != null) mdSpreadNumberRun.Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(230, brightC, brightC, brightC));
			System.Windows.Media.SolidColorBrush sepBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(40, overlayC, overlayC, overlayC));
			if (mdSepTop != null) mdSepTop.Background = sepBrush;
			if (mdSepBot != null) mdSepBot.Background = sepBrush;
			if (mdSpreadBorder != null) mdSpreadBorder.Background = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(30, overlayC, overlayC, overlayC));
		}

		/// Update Collapse All button text based on panel width
		private void UpdateCollapseAllButtonText()
		{
			if (collapseAllButton == null) return;
			bool useShort = pChartTraderWidth < 155;
			if (collapseAllState)
			{
				collapseAllButton.Content = useShort ? "Expand ▶" : "Expand All ▶";
				collapseAllButton.ToolTip = MakeToolTip("Expand Everything");
			}
			else
			{
				collapseAllButton.Content = useShort ? "Collapse ▼" : "Collapse All ▼";
				collapseAllButton.ToolTip = MakeToolTip("Collapse Everything");
			}
		}

		/// Animate section expand/collapse with smooth easing.
		/// EaseOut on both directions — collapse with EaseIn felt sluggish at the start.
		private void AnimateSectionExpand(System.Windows.FrameworkElement contentGrid, bool expand)
		{
			if (contentGrid == null) return;
			var dur = new Duration(TimeSpan.FromMilliseconds(160));
			var ease = new System.Windows.Media.Animation.CubicEase { EasingMode = System.Windows.Media.Animation.EasingMode.EaseOut };

			if (expand)
			{
				contentGrid.Visibility = System.Windows.Visibility.Visible;
				contentGrid.Measure(new System.Windows.Size(contentGrid.ActualWidth > 0 ? contentGrid.ActualWidth : 500, double.PositiveInfinity));
				double targetH = contentGrid.DesiredSize.Height;
				contentGrid.MaxHeight = 0;
				var anim = new System.Windows.Media.Animation.DoubleAnimation(0, targetH, dur);
				anim.EasingFunction = ease;
				anim.Completed += (s2, e2) => { contentGrid.BeginAnimation(System.Windows.FrameworkElement.MaxHeightProperty, null); contentGrid.MaxHeight = double.PositiveInfinity; };
				contentGrid.BeginAnimation(System.Windows.FrameworkElement.MaxHeightProperty, anim);
			}
			else
			{
				double currentH = contentGrid.ActualHeight;
				var anim = new System.Windows.Media.Animation.DoubleAnimation(currentH, 0, dur);
				anim.EasingFunction = ease;
				anim.Completed += (s2, e2) => { contentGrid.BeginAnimation(System.Windows.FrameworkElement.MaxHeightProperty, null); contentGrid.Visibility = System.Windows.Visibility.Collapsed; contentGrid.MaxHeight = double.PositiveInfinity; };
				contentGrid.BeginAnimation(System.Windows.FrameworkElement.MaxHeightProperty, anim);
			}
		}

		/// Sets a section header's Content to "chevron + fitted name", choosing the full or
		/// short name based on the button's measured width. Tag must be a
		/// Tuple<string, string, string>(sectionKey, fullName, shortName).
		private void ApplySectionHeaderLabel(System.Windows.Controls.Button headerButton, bool expanded)
		{
			if (headerButton == null) return;
			var tag = headerButton.Tag as Tuple<string, string, string>;
			if (tag == null) return;
			string fullName = tag.Item2;
			string shortName = tag.Item3;
			// extraPadding 9 reserves room for the "▼ " chevron prefix on top of
			// FitButtonText's built-in +18. Tuned empirically against actual header text.
			string name = (fullName == shortName)
				? fullName
				: FitButtonText(headerButton, fullName, shortName, 9);
			headerButton.Content = (expanded ? "▼ " : "▶ ") + name;
			headerButton.ToolTip = MakeToolTip(expanded ? "Collapse" : "Expand");
		}

		/// Creates a collapsible section with a clickable header. Returns the content Grid where buttons go.
		/// Pass shortName to enable width-based abbreviation when the full name doesn't fit.
		private System.Windows.Controls.Panel CreateCollapsibleSection(
			string sectionName, string sectionKey, bool defaultExpanded,
			System.Windows.Controls.StackPanel parentStack, int topMargin = -1,
			System.Windows.UIElement headerRightContent = null, string shortName = null)
		{
			if (topMargin < 0) topMargin = pHeaderSpacing; // linked to Header Spacing

			if (!sectionExpandedStates.ContainsKey(sectionKey))
				sectionExpandedStates[sectionKey] = defaultExpanded;

			bool isExpanded = sectionExpandedStates[sectionKey];

			// When collapsible sections disabled, just add content directly (no header)
			// but still honor Header Spacing as inter-section spacing.
			if (!pCollapsibleSectionsEnabled)
			{
				var contentGridNoCollapse = new System.Windows.Controls.StackPanel
				{
					Orientation = System.Windows.Controls.Orientation.Vertical,
					Margin = new System.Windows.Thickness(0, topMargin, 0, 0)
				};
				parentStack.Children.Add(contentGridNoCollapse);
				return contentGridNoCollapse;
			}

			// Scale with header font so large font settings don't clip the text.
			// Baseline 20px for the default 11pt header font, ~1.7× ratio above that.
			int headerHeight = Math.Max(20, (int)(pHeaderFontSize * 1.7));
			double headerFontSize = pHeaderFontSize;

			var headerButton = new System.Windows.Controls.Button
			{
				HorizontalContentAlignment = System.Windows.HorizontalAlignment.Left,
				Background = System.Windows.Media.Brushes.Transparent,
				Foreground = GetHeaderForegroundBrush(70),
				BorderThickness = new System.Windows.Thickness(0, 0, 0, 1),
				BorderBrush = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(20, 128, 128, 128)),
				Height = headerHeight,
				Padding = new System.Windows.Thickness(6, 0, 6, 0),
				Margin = new System.Windows.Thickness(0, topMargin, 0, 0),
				FontFamily = panelFont,
				FontWeight = System.Windows.FontWeights.SemiBold,
				FontSize = headerFontSize,
				Cursor = System.Windows.Input.Cursors.Hand,
				FocusVisualStyle = null
			};

			// Custom template to remove default WPF button chrome (blue pressed line)
			var headerTemplate = new System.Windows.Controls.ControlTemplate(typeof(System.Windows.Controls.Button));
			var borderFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border));
			borderFactory.SetValue(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("Background") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			borderFactory.SetValue(System.Windows.Controls.Border.BorderBrushProperty, new System.Windows.Data.Binding("BorderBrush") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			borderFactory.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Data.Binding("BorderThickness") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			var contentPresenterFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ContentPresenter));
			contentPresenterFactory.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, new System.Windows.Data.Binding("HorizontalContentAlignment") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			contentPresenterFactory.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			contentPresenterFactory.SetValue(System.Windows.FrameworkElement.MarginProperty, new System.Windows.Data.Binding("Padding") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			borderFactory.AppendChild(contentPresenterFactory);
			headerTemplate.VisualTree = borderFactory;
			headerButton.Template = headerTemplate;

			// Store (sectionKey, fullName, shortName) so ApplySectionHeaderLabel and the
			// width-refit pass in UpdateButtonLabelsForWidth can pick the right label.
			headerButton.Tag = new Tuple<string, string, string>(sectionKey, sectionName, shortName ?? sectionName);
			ApplySectionHeaderLabel(headerButton, isExpanded);

			var contentGrid = new System.Windows.Controls.StackPanel
			{
				Orientation = System.Windows.Controls.Orientation.Vertical,
				Visibility = isExpanded ? System.Windows.Visibility.Visible : System.Windows.Visibility.Collapsed,
				Margin = new System.Windows.Thickness(0, 0, 0, 0)
			};

			// Hover effect — brighten text only, no background change
			headerButton.MouseEnter += (s, ev) =>
			{
				headerButton.Foreground = GetHeaderForegroundBrush(220);
			};
			headerButton.MouseLeave += (s, ev) =>
			{
				headerButton.Foreground = GetHeaderForegroundBrush(70);
			};

			string capturedKey = sectionKey;
			headerButton.Click += (sender, args) =>
			{
				sectionExpandedStates[capturedKey] = !sectionExpandedStates[capturedKey];
				bool nowExpanded = sectionExpandedStates[capturedKey];
				ApplySectionHeaderLabel(headerButton, nowExpanded);
				SaveSectionStates();
				System.Windows.Input.Keyboard.ClearFocus();

				AnimateSectionExpand(contentGrid, nowExpanded);
			};

			// Track for Collapse/Expand All
			sectionHeaderButtons.Add(headerButton);
			sectionContentGrids.Add(contentGrid);

			var sectionPanel = new System.Windows.Controls.StackPanel { Orientation = System.Windows.Controls.Orientation.Vertical };

			if (headerRightContent != null)
			{
				// Header row: section header on left, extra content on right
				// Move topMargin from headerButton to the Grid wrap so both columns align at the same baseline
				var headerRow = new System.Windows.Controls.Grid();
				headerRow.Margin = headerButton.Margin;
				headerButton.Margin = new System.Windows.Thickness(0);
				headerRow.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });
				headerRow.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = System.Windows.GridLength.Auto });
				System.Windows.Controls.Grid.SetColumn(headerButton, 0);
				System.Windows.Controls.Grid.SetColumn((System.Windows.FrameworkElement)headerRightContent, 1);
				headerRow.Children.Add(headerButton);
				headerRow.Children.Add(headerRightContent);
				sectionPanel.Children.Add(headerRow);
			}
			else
			{
				sectionPanel.Children.Add(headerButton);
			}

			sectionPanel.Children.Add(contentGrid);

			parentStack.Children.Add(sectionPanel);

			return contentGrid;
		}

		private void SaveSectionStates()
		{
			var sb = new System.Text.StringBuilder();
			foreach (var kvp in sectionExpandedStates)
			{
				if (sb.Length > 0) sb.Append(",");
				sb.Append(kvp.Key + "=" + (kvp.Value ? "1" : "0"));
			}
			pSavedSectionStates = sb.ToString();
		}

		private void LoadSectionStates()
		{
			if (string.IsNullOrEmpty(pSavedSectionStates)) return;
			foreach (string pair in pSavedSectionStates.Split(','))
			{
				string[] parts = pair.Split('=');
				if (parts.Length == 2)
					sectionExpandedStates[parts[0]] = parts[1] == "1";
			}
		}

		private void InsertWPFOrderControls()
		{
			//Print("ECT InsertWPF - panelActive=" + panelActive + " chartGrid=" + (chartGrid != null) + " chartWindow=" + (chartWindow != null));
			if (panelActive)
				return;

			// Build the panel structure on first call. Subsequent calls (tab switches) reuse
			// the cached outerPanel/dockPanel/scrollViewer/resizeHandle and skip the rebuild
			// entirely — no XAML parsing, no event handler attachments, no WPF measure pass
			// on a freshly-built tree.
			if (panelOuterGrid == null)
				BuildPanelOuterStructure();

			tabControlStartColumn = System.Windows.Controls.Grid.GetColumn(chartWindow.MainTabControl);

			// a new column is added to the right of MainTabControl
			chartGrid.ColumnDefinitions.Insert((tabControlStartColumn + 1), new System.Windows.Controls.ColumnDefinition() { Width = new GridLength(pChartTraderWidth) });

			// all items to the right of the MainTabControl are shifted to the right
			for (int i = 0; i < chartGrid.Children.Count; i++)
				if (System.Windows.Controls.Grid.GetColumn(chartGrid.Children[i]) > tabControlStartColumn)
					System.Windows.Controls.Grid.SetColumn(chartGrid.Children[i], System.Windows.Controls.Grid.GetColumn(chartGrid.Children[i]) + 1);

			// Place the cached outer panel into the chart grid
			System.Windows.Controls.Grid.SetColumn(panelOuterGrid, System.Windows.Controls.Grid.GetColumn(chartWindow.MainTabControl) + 1);
			System.Windows.Controls.Grid.SetRow(panelOuterGrid, System.Windows.Controls.Grid.GetRow(chartWindow.MainTabControl));
			chartGrid.Children.Add(panelOuterGrid);

			panelActive = true;

			// Hide the entire panel so pinned section (account, PNL) and scrollable content
			// appear together in a single frame once layout and account init are both done.
			panelLayoutReady = false;
			panelAccountReady = (accountSelectorMain != null && accountSelectorMain.SelectedAccount != null);
			if (panelOuterGrid != null)
				panelOuterGrid.Opacity = 0;

			panelDockPanel.Dispatcher.BeginInvoke(System.Windows.Threading.DispatcherPriority.Render, new System.Action(() =>
			{
				try
				{
					// Temporarily force all initially-collapsed sections visible at MaxHeight=0
					// so their buttons get a real ActualWidth measurement during the layout pass.
					// Without this, FitButtonText falls back to a generous estimate and bakes in
					// full-length labels that then flash briefly when the user expands the section.
					var tempVisibleSections = new List<System.Windows.FrameworkElement>();
					for (int si = 0; si < sectionContentGrids.Count; si++)
					{
						var cg = sectionContentGrids[si];
						if (cg != null && cg.Visibility == System.Windows.Visibility.Collapsed)
						{
							cg.MaxHeight = 0;
							cg.Visibility = System.Windows.Visibility.Visible;
							tempVisibleSections.Add(cg);
						}
					}
					if (tempVisibleSections.Count > 0)
					{
						if (panelOuterGrid != null) panelOuterGrid.UpdateLayout();
						else if (panelDockPanel != null) panelDockPanel.UpdateLayout();
					}

					UpdateButtonLabelsForWidth();

					// Force-paint every accent strip BEFORE we let the panel become visible.
					// Without this, buttons whose Loaded event hasn't fired yet enter the
					// visible frame with transparent strips, and the colors then "fade in"
					// once their deferred Loaded handler runs — that's the flash.
					ForceApplyAllAccentStrips();

					foreach (var cg in tempVisibleSections)
					{
						cg.Visibility = System.Windows.Visibility.Collapsed;
						cg.MaxHeight = double.PositiveInfinity;
					}
				}
				catch (Exception) { }
				panelLayoutReady = true;
				TryRevealPanel();
				// Fallback: if account selector hasn't resolved yet (no connections, edge case),
				// force-reveal after all pending dispatcher work completes.
				if (!panelAccountReady && panelDockPanel != null)
				{
					panelDockPanel.Dispatcher.BeginInvoke(System.Windows.Threading.DispatcherPriority.Background, new Action(() =>
					{
						if (panelOuterGrid != null && panelOuterGrid.Opacity == 0)
							panelOuterGrid.Opacity = 1;
					}));
				}
			}));
		}

		private void TryRevealPanel()
		{
			if (panelLayoutReady && panelAccountReady && panelOuterGrid != null)
				panelOuterGrid.Opacity = 1;
		}

		/// <summary>
		/// Builds outerPanel + dockPanel + scrollViewer + resizeHandle and wires up all event
		/// handlers. Does NOT touch chartGrid — attach is done separately by InsertWPFOrderControls.
		/// Called once per indicator instance: either by InsertWPFOrderControls on first activation,
		/// or pre-built from CreateWPFOrderControls (idle dispatcher) for inactive tabs so the first
		/// tab switch is fast.
		/// </summary>
		private void BuildPanelOuterStructure()
		{
			if (panelOuterGrid != null) return;

			// Build outer panel container: resize handle (4px) + content area
			var outerPanel = new System.Windows.Controls.Grid();
			outerPanel.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = new GridLength(4) });   // resize handle
			outerPanel.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition() { Width = new GridLength(1, GridUnitType.Star) }); // content
			panelOuterGrid = outerPanel;

			// Resize handle
			panelResizeHandle = new System.Windows.Controls.Border
			{
				Width = 4,
				Background = System.Windows.Media.Brushes.Transparent,
				Cursor = System.Windows.Input.Cursors.SizeWE,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Left
			};
			panelResizeHandle.MouseLeftButtonDown += PanelResize_MouseDown;
			panelResizeHandle.MouseMove += PanelResize_MouseMove;
			panelResizeHandle.MouseLeftButtonUp += PanelResize_MouseUp;
			panelResizeHandle.MouseEnter += (s, e) => { if (panelResizeHandle != null) panelResizeHandle.Background = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(60, 128, 128, 128)); };
			panelResizeHandle.MouseLeave += (s, e) => { if (panelResizeHandle != null) panelResizeHandle.Background = System.Windows.Media.Brushes.Transparent; };

			System.Windows.Controls.Grid.SetColumn(panelResizeHandle, 0);
			outerPanel.Children.Add(panelResizeHandle);

			// DockPanel: pinned header on top, scrollable content fills remaining space
			panelDockPanel = new System.Windows.Controls.DockPanel();
			panelDockPanel.LastChildFill = true;

			// Pinned header (Setup/ATM, PNL, Collapse All button) - does not scroll
			System.Windows.Controls.DockPanel.SetDock(pinnedStack, System.Windows.Controls.Dock.Top);
			panelDockPanel.Children.Add(pinnedStack);

			// Version label — always pinned to bottom of panel
			double verHeaderFontSize = pHeaderFontSize;
			versionLabel = new System.Windows.Controls.TextBlock()
			{
				Text = "— " + pVersionNumber + " —",
				FontSize = verHeaderFontSize,
				FontFamily = panelFont,
				Foreground = GetHeaderForegroundBrush(70),
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				Margin = new System.Windows.Thickness(0, pHeaderSpacing, 0, 2)
			};
			System.Windows.Controls.DockPanel.SetDock(versionLabel, System.Windows.Controls.Dock.Bottom);
			panelDockPanel.Children.Add(versionLabel);

			// Scrollable content: wraps buttonGrid (which holds mainPanelStack with remaining sections)
			panelScrollViewer = new System.Windows.Controls.ScrollViewer();
			panelScrollViewer.VerticalScrollBarVisibility = System.Windows.Controls.ScrollBarVisibility.Auto;
			panelScrollViewer.HorizontalScrollBarVisibility = System.Windows.Controls.ScrollBarVisibility.Disabled;
			panelScrollViewer.Padding = new System.Windows.Thickness(0);
			panelScrollViewer.Content = buttonGrid;

			// Dark-themed scrollbar
			try
			{
				string scrollXaml = @"<Style xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation'
					xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml'
					TargetType='{x:Type ScrollBar}'>
					<Setter Property='Background' Value='Transparent'/>
					<Setter Property='Width' Value='4'/>
					<Setter Property='Template'>
						<Setter.Value>
							<ControlTemplate TargetType='{x:Type ScrollBar}'>
								<Grid>
									<Track x:Name='PART_Track' IsDirectionReversed='True'>
										<Track.Thumb>
											<Thumb>
												<Thumb.Style>
													<Style TargetType='{x:Type Thumb}'>
														<Setter Property='Background' Value='#40808080'/>
														<Setter Property='Template'>
															<Setter.Value>
																<ControlTemplate TargetType='{x:Type Thumb}'>
																	<Border Background='{TemplateBinding Background}' CornerRadius='4' Margin='0,1,1,1'/>
																</ControlTemplate>
															</Setter.Value>
														</Setter>
														<Style.Triggers>
															<Trigger Property='IsMouseOver' Value='True'>
																<Setter Property='Background' Value='#60AAAAAA'/>
															</Trigger>
															<Trigger Property='IsDragging' Value='True'>
																<Setter Property='Background' Value='#80CCCCCC'/>
															</Trigger>
														</Style.Triggers>
													</Style>
												</Thumb.Style>
											</Thumb>
										</Track.Thumb>
									</Track>
								</Grid>
							</ControlTemplate>
						</Setter.Value>
					</Setter>
				</Style>";
				var scrollStyle = (System.Windows.Style)System.Windows.Markup.XamlReader.Parse(scrollXaml);
				panelScrollViewer.Resources.Add(typeof(System.Windows.Controls.Primitives.ScrollBar), scrollStyle);
			}
			catch (Exception) { }

			// Force the actual ScrollBar width via deep visual tree walk.
			// The ScrollBar may not exist until the template is applied AND content overflows,
			// so we walk on LayoutUpdated and apply width to all ScrollBar descendants.
			// We track which scrollbars we've already styled to avoid repeated work.
			System.Collections.Generic.HashSet<System.Windows.Controls.Primitives.ScrollBar> styledScrollBars = new System.Collections.Generic.HashSet<System.Windows.Controls.Primitives.ScrollBar>();
			System.EventHandler scrollLayoutHandler = null;
			scrollLayoutHandler = (s, e) =>
			{
				try
				{
					ForceScrollBarWidth(panelScrollViewer, 10, styledScrollBars);
					UpdatePanelFadeOverlayVisibility();
				}
				catch (Exception) { }
			};
			panelScrollViewer.LayoutUpdated += scrollLayoutHandler;

			// Forward mouse wheel events from the ScrollViewer to the chart so that
			// Y-scroll, OneClick mode, and qty-scroll still work when the cursor is
			// over the WPF panel.  Without this, the ScrollViewer eats the event.
			panelScrollViewer.PreviewMouseWheel += (s, ev) =>
			{
				// Only forward if the panel itself doesn't need to scroll,
				// OR if the chart Y-scroll / OneClick / QtyOrder features are active
				bool panelNeedsScroll = panelScrollViewer.ScrollableHeight > 0;
				bool chartNeedsWheel = pUseYScroll || InOneClick || BuyClickReady || SellClickReady || QtyOrder != null || QtyOrderLIT != null || SyntheticQtyKey != null;

				if (chartNeedsWheel)
				{
					// Let the chart handler process it instead of the ScrollViewer
					ev.Handled = true;
					ChartControl_PreviewMouseWheel(s, ev);
				}
				// else: let ScrollViewer handle it normally (panel scroll).
				// lastPanelScrollTime is updated only in ScrollChanged (fires when the
				// panel ACTUALLY scrolls), NOT here — setting it here would block
				// button wheel handlers permanently since panelNeedsScroll is true
				// whenever the panel has enough content to scroll.
			};

			// Snapshot the persisted scroll position BEFORE wiring the ScrollChanged
			// handler. When the ScrollViewer first lays out content it fires
			// ScrollChanged with VerticalOffset = 0, which would otherwise wipe
			// pSavedScrollPosition to 0 before the restore handler can use it.
			// Capturing into a local decouples the restore from the save path.
			double initialScrollToRestore = pSavedScrollPosition;

			// Save scroll position when user scrolls, and update the bottom fade overlay.
			// Also record the scroll timestamp so button-level wheel handlers can
			// detect "panel is actively scrolling" and yield instead of hijacking.
			panelScrollViewer.ScrollChanged += (s, e) =>
			{
				if (panelScrollViewer != null)
					pSavedScrollPosition = panelScrollViewer.VerticalOffset;
				// Only record "panel is scrolling" when there's actual vertical movement.
				// ScrollChanged also fires for extent/viewport changes from layout updates
				// (button label width changes, section expand/collapse, etc.), which would
				// otherwise keep IsPanelScrollingRecently() true for 800ms and silently
				// suppress button-level wheel handlers like BE offset on button13.
				if (e.VerticalChange != 0)
					lastPanelScrollTime = DateTime.Now;
				UpdatePanelFadeOverlayVisibility();
			};

			// Restore saved scroll position after layout is ready.
			// Clamp against the actual scrollable range — if sections were collapsed
			// between sessions the previously-saved offset may exceed the new max
			// and would silently snap to an unexpected location.
			if (initialScrollToRestore > 0)
			{
				EventHandler restoreHandler = null;
				restoreHandler = (s, e) =>
				{
					if (panelScrollViewer != null && panelScrollViewer.ScrollableHeight > 0)
					{
						double target = Math.Min(initialScrollToRestore, panelScrollViewer.ScrollableHeight);
						panelScrollViewer.ScrollToVerticalOffset(target);
						panelScrollViewer.LayoutUpdated -= restoreHandler;
					}
				};
				panelScrollViewer.LayoutUpdated += restoreHandler;
			}

			// Wrap the scroll viewer in a Grid so we can overlay soft fades on the top and
			// bottom edges. Hint that more content is above/below the visible area, and avoid
			// rough-edge clipping above the version label.
			var scrollWrapper = new System.Windows.Controls.Grid();
			scrollWrapper.Children.Add(panelScrollViewer);
			panelFadeOverlayTop = new System.Windows.Controls.Border()
			{
				Height = 12,
				VerticalAlignment = System.Windows.VerticalAlignment.Top,
				IsHitTestVisible = false,
				Visibility = System.Windows.Visibility.Collapsed
			};
			panelFadeOverlay = new System.Windows.Controls.Border()
			{
				Height = 12,
				VerticalAlignment = System.Windows.VerticalAlignment.Bottom,
				IsHitTestVisible = false,
				Visibility = System.Windows.Visibility.Collapsed
			};
			scrollWrapper.Children.Add(panelFadeOverlayTop);
			scrollWrapper.Children.Add(panelFadeOverlay);
			RebuildPanelFadeBrush();

			panelDockPanel.Children.Add(scrollWrapper);

			System.Windows.Controls.Grid.SetColumn(panelDockPanel, 1);
			outerPanel.Children.Add(panelDockPanel);

			// Refresh panel layout/styling when the tab becomes visible.
			// Inactive tabs don't render WPF visuals, so accent strips, native control borders,
			// and width-dependent layouts can be stale until the tab is activated.
			// Both Loaded and IsVisibleChanged fire on first attach — refreshScheduled dedupes.
			Action scheduleRefresh = () =>
			{
				if (refreshScheduled) return;
				refreshScheduled = true;
				try
				{
					panelDockPanel.Dispatcher.BeginInvoke(System.Windows.Threading.DispatcherPriority.Loaded, new Action(() =>
					{
						refreshScheduled = false;
						try { RefreshPanelStyling(); } catch (Exception) { }
					}));
				}
				catch (Exception) { refreshScheduled = false; }
			};
			System.Windows.DependencyPropertyChangedEventHandler visHandler = (s, e) =>
			{
				if (panelDockPanel.IsVisible) scheduleRefresh();
			};
			panelDockPanel.IsVisibleChanged += visHandler;
			panelDockPanel.Loaded += (s, e) => scheduleRefresh();
		}

		private void PanelResize_MouseDown(object sender, System.Windows.Input.MouseButtonEventArgs e)
		{
			isPanelResizing = true;
			resizeStartX = e.GetPosition(chartGrid).X;
			resizeStartWidth = pChartTraderWidth;
			panelResizeHandle.CaptureMouse();
			e.Handled = true;
		}

		private void PanelResize_MouseMove(object sender, System.Windows.Input.MouseEventArgs e)
		{
			if (!isPanelResizing) return;
			double delta = resizeStartX - e.GetPosition(chartGrid).X;
			int newWidth = Math.Max(100, Math.Min(500, resizeStartWidth + (int)delta));
			pChartTraderWidth = newWidth;
			// Update the chartGrid column width
			int colIndex = System.Windows.Controls.Grid.GetColumn((System.Windows.UIElement)((System.Windows.FrameworkElement)panelResizeHandle).Parent);
			if (colIndex >= 0 && colIndex < chartGrid.ColumnDefinitions.Count)
				chartGrid.ColumnDefinitions[colIndex].Width = new GridLength(newWidth);
			UpdateButtonLabelsForWidth();
			UpdatePNLBox();
			// Show width tooltip while resizing
			if (panelResizeHandle != null)
				panelResizeHandle.ToolTip = MakeToolTip(newWidth + "px");
			e.Handled = true;
		}

		private void PanelResize_MouseUp(object sender, System.Windows.Input.MouseButtonEventArgs e)
		{
			isPanelResizing = false;
			panelResizeHandle.ReleaseMouseCapture();
			e.Handled = true;
		}

		// ═══════════════════════════════════════════════════════════════════
		// Custom Button Styling — Rounded corners, gradients, hover, press
		// ═══════════════════════════════════════════════════════════════════

		private int accentStripWidth = 5; // color-coded left accent strip width on primary buttons (Buy/Sell, Market, Limit, Click, Close, Reverse)
		private int accentStripWidthSecondary = 3; // secondary buttons (SLM, MIT, IPA, Next, cancel buttons)
		private int accentStripWidthTertiary = 1; // tertiary/mini square buttons (T, $, X, IB, show/hide account)
		private double accentBrighten = 0.85; // how much to brighten button color for accent strip (multiplier: 0=same, 1=2x)
		private double accentBrightenSecondary = 0.65; // dimmer brighten for secondary strips so they don't visually overpower
		private double cornerRadius = 4.0; // corner radius for all styled buttons
		private double hoverBrighten = 0.25; // how much to lighten on hover (0-1)
		private double pressDarken = 0.20; // how much to darken on press (0-1)
		private double gradientTopLighten = 0.08; // subtle gradient: top is this much lighter
		private double gradientBottomDarken = 0.04; // subtle gradient: bottom is this much darker

		/// <summary>
		/// Sets a button's background to a gradient and stores the base color in Tag for hover/press effects.
		/// Use this instead of direct .Background = assignments on styled buttons.
		/// </summary>
		private void SetStyledBackground(System.Windows.Controls.Button btn, Brush brush)
		{
			if (btn == null) return;
			var color = BrushToColor(brush);
			btn.Tag = color;
			btn.Background = MakeGradientBrush(color);

			// Update accent strip color if present (buy/sell buttons)
			UpdateAccentStrip(btn, color);
		}

		/// True if a button is sized as a secondary control (uses the smaller 3px accent strip).
		/// Same heuristic ApplyButtonStyle uses to pick the cached template.
		private bool IsSecondaryButton(System.Windows.Controls.Button btn)
		{
			return btn != null
				&& !double.IsNaN(btn.Height)
				&& btn.Height <= smallControlHeight + 0.5;
		}

		private System.Windows.Media.Brush PickAccentBrush(System.Windows.Controls.Button btn, ButtonBrushSet set)
		{
			return IsSecondaryButton(btn) ? set.AccentSecondary : set.Accent;
		}

		private System.Windows.Media.Color GetAccentColor(System.Windows.Media.Color color, bool isSecondary = false)
		{
			// Luminance check: active buttons have bright colors, inactive have dim colors
			double luminance = (0.299 * color.R + 0.587 * color.G + 0.114 * color.B) / 255.0;
			if (luminance > 0.4)
			{
				// Bright/active button — white accent. Secondary uses lower alpha so the
				// thin 3px strip doesn't optically dominate the small button.
				byte a = (byte)(isSecondary ? 160 : 200);
				return System.Windows.Media.Color.FromArgb(a, 255, 255, 255);
			}
			else
			{
				// Dim/inactive button — subtle brighten of base color. Secondary uses a
				// smaller multiplier so the strip stays visually subordinate.
				return BrightenColor(color, isSecondary ? accentBrightenSecondary : accentBrighten);
			}
		}

		private void UpdateAccentStrip(System.Windows.Controls.Button btn, System.Windows.Media.Color color)
		{
			// Don't overwrite the pulse color for buttons currently trailing — the pulse
			// brush is a fixed gold so left + right always match.
			bool skipLeft = pulsingButtons != null && pulsingButtons.Contains(btn);
			if (skipLeft) return;

			try
			{
				// Fast path: use cached Border ref + cached accent brush, skipping ApplyTemplate, FindName, and brush alloc
				System.Windows.Controls.Border cachedAccent;
				if (accentStripCache.TryGetValue(btn, out cachedAccent) && cachedAccent != null)
				{
					cachedAccent.Background = PickAccentBrush(btn, GetButtonBrushSet(color));
					return;
				}

				if (btn.Template != null && btn.IsLoaded)
				{
					btn.ApplyTemplate();
					var accent = btn.Template.FindName("accentStrip", btn) as System.Windows.Controls.Border;
					if (accent != null)
					{
						accentStripCache[btn] = accent;
						accent.Background = PickAccentBrush(btn, GetButtonBrushSet(color));
						return; // success
					}
				}
			}
			catch { }

			// Template not yet applied — defer via Loaded handler + dispatcher fallback
			System.Windows.RoutedEventHandler loadedHandler = null;
			loadedHandler = (s, e) =>
			{
				btn.Loaded -= loadedHandler;
				ApplyAccentStripDeferred(btn);
			};
			btn.Loaded += loadedHandler;

			// Also defer via dispatcher in case Loaded already fired
			if (btn.IsLoaded)
			{
				ApplyAccentStripDeferred(btn);
			}
		}

		// ================================================================
		// Trailing-active pulse — left + right edge accent strips
		// ================================================================
		// When a Price Based Entry order is resting, its Buy/Sell Price button gets
		// a breathing pulse on both edge accent strips + a subtle outer glow:
		//   Active — trailing ON  : bold pulse (strips 0.25↔1.0, glow 0.15↔1.0)
		//   Steady — trailing OFF : gentle flow (strips 0.45↔0.75, glow 0.10↔0.30)
		// When the button is disabled, hidden, the feature is off, or the order is
		// gone, ResetPulseDecorations wipes the strips, glow, and any animation
		// state. Driven from every order/state-change site via RefreshPriceButtonPulses.

		private System.Windows.Controls.Border ResolveRightAccent(System.Windows.Controls.Button btn)
		{
			if (btn == null) return null;
			System.Windows.Controls.Border cached;
			if (accentStripRightCache.TryGetValue(btn, out cached) && cached != null)
				return cached;
			try
			{
				if (btn.Template == null) return null;
				btn.ApplyTemplate();
				var accentR = btn.Template.FindName("accentStripRight", btn) as System.Windows.Controls.Border;
				if (accentR != null)
				{
					accentStripRightCache[btn] = accentR;
					return accentR;
				}
			}
			catch { }
			return null;
		}

		// Toggle pulse state for a single button. Idempotent — safe to call on every
		// order state change.
		private System.Windows.Media.SolidColorBrush GetPulseAccentBrush()
		{
			if (pulseAccentBrush == null)
			{
				pulseAccentBrush = new System.Windows.Media.SolidColorBrush(pulseAccentColor);
				pulseAccentBrush.Freeze();
			}
			return pulseAccentBrush;
		}

		private System.Windows.Media.Effects.DropShadowEffect GetOrCreateGlow(System.Windows.Controls.Button btn)
		{
			System.Windows.Media.Effects.DropShadowEffect glow;
			if (pulseGlowByButton.TryGetValue(btn, out glow) && glow != null) return glow;
			glow = new System.Windows.Media.Effects.DropShadowEffect
			{
				Color       = pulseGlowColor, // bright halo, independent of strip color
				BlurRadius  = 14,
				ShadowDepth = 0,
				Opacity     = 1.0,
			};
			pulseGlowByButton[btn] = glow;
			return glow;
		}

		// Fully resets the pulse decorations on a button. Idempotent — safe to call
		// on every state change, including when the button becomes disabled / hidden
		// or its order is gone.
		private void ResetPulseDecorations(System.Windows.Controls.Button btn)
		{
			if (btn == null) return;
			try
			{
				pulsingButtons.Remove(btn);
				pulseModeByButton.Remove(btn);

				System.Windows.Controls.Border leftAcc;
				if (accentStripCache.TryGetValue(btn, out leftAcc) && leftAcc != null)
					leftAcc.Opacity = 1.0;

				var rightAcc = ResolveRightAccent(btn);
				if (rightAcc != null)
				{
					rightAcc.Opacity = 1.0;
					rightAcc.Background = System.Windows.Media.Brushes.Transparent;
				}

				// Restore the left strip's natural per-button accent color.
				var baseColor = (btn.Tag is System.Windows.Media.Color)
					? (System.Windows.Media.Color)btn.Tag
					: BrushToColor(btn.Background);
				UpdateAccentStrip(btn, baseColor);

				btn.Effect = null;
			}
			catch { }
			if (pulsingButtons.Count == 0) StopPulseTimer();
		}

		private void ApplyPulseMode(System.Windows.Controls.Button btn, PulseMode mode)
		{
			if (btn == null) return;
			try
			{
				var brush = GetPulseAccentBrush();
				System.Windows.Controls.Border leftAcc;
				if (accentStripCache.TryGetValue(btn, out leftAcc) && leftAcc != null)
					leftAcc.Background = brush;
				else
					UpdateAccentStrip(btn, (btn.Tag is System.Windows.Media.Color) ? (System.Windows.Media.Color)btn.Tag : BrushToColor(btn.Background));

				var rightAcc = ResolveRightAccent(btn);
				if (rightAcc != null) rightAcc.Background = brush;

				var glow = GetOrCreateGlow(btn);
				btn.Effect = glow;

				pulseModeByButton[btn] = mode;

				if (mode == PulseMode.Active)
				{
					// Animated — join the timer set.
					if (pulsingButtons.Add(btn) && pulsingButtons.Count == 1)
						StartPulseTimer();
				}
				else // Steady — static glow, no animation
				{
					pulsingButtons.Remove(btn);
					// Nail down a single fixed opacity so it doesn't flicker even if the
					// timer is running for the other side's Active pulse.
					if (leftAcc != null) leftAcc.Opacity = 1.0;
					if (rightAcc != null) rightAcc.Opacity = 1.0;
					if (glow != null)    glow.Opacity    = 0.35; // fixed steady glow
					if (pulsingButtons.Count == 0) StopPulseTimer();
				}
			}
			catch { }
		}

		private void StartPulseTimer()
		{
			if (pulseTimer == null)
			{
				pulseTimer = new System.Windows.Threading.DispatcherTimer();
				pulseTimer.Interval = TimeSpan.FromMilliseconds(40); // 25 FPS — smooth, cheap
				pulseTimer.Tick += PulseTimer_Tick;
			}
			pulseStart = DateTime.Now;
			if (!pulseTimer.IsEnabled) pulseTimer.Start();
		}

		private void StopPulseTimer()
		{
			if (pulseTimer != null && pulseTimer.IsEnabled)
				pulseTimer.Stop();
		}

		private void PulseTimer_Tick(object sender, EventArgs e)
		{
			if (pulsingButtons.Count == 0) { StopPulseTimer(); return; }
			try
			{
				double t = (DateTime.Now - pulseStart).TotalMilliseconds;
				double phase = (t / 650.0) * Math.PI;             // ~1.3 s period
				double wave  = 0.5 + 0.5 * Math.Cos(phase);       // 0 → 1 → 0 ...

				// Active only: edges swing widely; glow breathes but capped so it isn't blinding.
				double stripOpacity = 0.25 + 0.75 * wave;         // 0.25 ↔ 1.00
				double glowOpacity  = 0.30 + 0.40 * wave;         // 0.30 ↔ 0.70 — dimmer than before

				// Iterate a snapshot so the tick is tolerant of the set mutating
				// from a concurrent RefreshPriceButtonPulses triggered by Dispatcher work.
				foreach (var btn in new List<System.Windows.Controls.Button>(pulsingButtons))
				{
					if (btn == null) continue;

					System.Windows.Controls.Border leftAcc;
					if (accentStripCache.TryGetValue(btn, out leftAcc) && leftAcc != null)
						leftAcc.Opacity = stripOpacity;
					var rightAcc = ResolveRightAccent(btn);
					if (rightAcc != null) rightAcc.Opacity = stripOpacity;
					System.Windows.Media.Effects.DropShadowEffect glow;
					if (pulseGlowByButton.TryGetValue(btn, out glow) && glow != null)
						glow.Opacity = glowOpacity;
				}
			}
			catch { }
		}

		// Recomputes the current pulse state for button37/38 from the live order +
		// frozen flags + button enabled/visible. Also refreshes the tooltip content
		// so the user sees the live trailing status on hover. Called from every site
		// that can flip those flags.
		private void RefreshPriceButtonPulses()
		{
			// This walks WPF DependencyObject properties (IsEnabled, Visibility) and
			// mutates visual tree elements, so it MUST run on the UI dispatcher.
			// OnOrderUpdate / BuyPriceClick callers may be on the data thread; marshal
			// cross-thread calls via InvokeAsync.
			if (ChartControl == null) return;
			if (ChartControl.Dispatcher.CheckAccess())
			{
				RefreshPriceButtonPulsesUIThread();
			}
			else
			{
				ChartControl.Dispatcher.InvokeAsync((Action)RefreshPriceButtonPulsesUIThread);
			}
		}

		private void RefreshPriceButtonPulsesUIThread()
		{
			try
			{
				ApplyPulseForSide(button37, LongEntryOrder2  != null, PriceBasedLongFrozen);
				ApplyPulseForSide(button38, ShortEntryOrder2 != null, PriceBasedShortFrozen);

				if (tooltip37 != null) tooltip37.Content = BuildPriceButtonTooltip(LongEntryOrder2 != null, PriceBasedLongFrozen);
				if (tooltip38 != null) tooltip38.Content = BuildPriceButtonTooltip(ShortEntryOrder2 != null, PriceBasedShortFrozen);

				// Buy Click / Sell Click: pulse while the click-entry mode is armed.
				// Mirrors the Price Based "Active" pulse -- animated accent strips +
				// breathing glow until the user either places the order or toggles off.
				ApplyGenericActivePulse(button7, BuyClickReady,  /*pulse*/ true);
				ApplyGenericActivePulse(button8, SellClickReady, /*pulse*/ true);
				if (tooltip7 != null) tooltip7.Content = BuildClickEntryTooltip("Buy",  BuyClickReady);
				if (tooltip8 != null) tooltip8.Content = BuildClickEntryTooltip("Sell", SellClickReady);

				// Each side pulses independently -- Buy primary + Buy directional
				// share Buy-side state; Sell primary + Sell directional share
				// Sell-side state. Directionals always match the glow/pulse of
				// their same-side primary. Pulse phase is still synchronized
				// via the shared pulseTimer so both members of a lit side
				// animate in lock-step.

				// Close Bar Entry:
				//   Buy side  -> button9 (directional)
				//   Sell side -> button10 (directional)
				//   Main      -> button5 (lights for either side; pulses if either is clicking)
				bool buyCloseActive  = BuyCloseReady  || BuyCloseClick;
				bool sellCloseActive = SellCloseReady || SellCloseClick;
				ApplyGenericActivePulse(button9,  buyCloseActive,  /*pulse*/ BuyCloseClick);
				ApplyGenericActivePulse(button10, sellCloseActive, /*pulse*/ SellCloseClick);
				ApplyGenericActivePulse(button5,  buyCloseActive || sellCloseActive,
				                                  /*pulse*/ BuyCloseClick || SellCloseClick);

				// Iceberg -- button3 (Buy), button4 (Sell). No separate main button
				// -- directionals carry the whole per-side state.
				bool buyIceActive  = BuyIcebergClick  || IcebergBuyOrderSequence  != 0;
				bool sellIceActive = SellIcebergClick || IcebergSellOrderSequence != 0;
				ApplyGenericActivePulse(button3, buyIceActive,  /*pulse*/ BuyIcebergClick);
				ApplyGenericActivePulse(button4, sellIceActive, /*pulse*/ SellIcebergClick);

				// Time Sliced -- button18 (Buy), button19 (Sell). Same per-side pattern.
				bool buySlicedActive  = BuyTimeSlicedClick  || TimeSlicedBuyOrderSequence  != 0;
				bool sellSlicedActive = SellTimeSlicedClick || TimeSlicedSellOrderSequence != 0;
				ApplyGenericActivePulse(button18, buySlicedActive,  /*pulse*/ BuyTimeSlicedClick);
				ApplyGenericActivePulse(button19, sellSlicedActive, /*pulse*/ SellTimeSlicedClick);
			}
			catch { }
		}

		// Generic active-state pulse helper. Used by click-entry and any future
		// button that needs a simple "active -> pulse, inactive -> reset" pattern.
		// When pulse=false the active state renders as a steady (non-animated)
		// glow -- same visual as PulseMode.Steady on the Price Based buttons.
		private void ApplyGenericActivePulse(System.Windows.Controls.Button btn, bool active, bool pulse)
		{
			if (btn == null) return;
			bool usable = btn.IsEnabled && btn.Visibility == System.Windows.Visibility.Visible;
			if (!usable || !active)
			{
				ResetPulseDecorations(btn);
				return;
			}
			ApplyPulseMode(btn, pulse ? PulseMode.Active : PulseMode.Steady);
		}

		// Decide None / Steady / Active for a single side and dispatch to the
		// appropriate helper. Centralising this ensures every "off" condition
		// (button disabled, hidden, feature disabled, no order) fully resets
		// the pulse decorations via the same path.
		private void ApplyPulseForSide(System.Windows.Controls.Button btn, bool hasOrder, bool frozen)
		{
			if (btn == null) { ResetPulseDecorations(btn); return; }

			bool usable = btn.IsEnabled
				&& btn.Visibility == System.Windows.Visibility.Visible
				&& pPriceBasedEntryOrdersEnabled;

			if (!usable || !hasOrder)
			{
				ResetPulseDecorations(btn);
				return;
			}

			ApplyPulseMode(btn, frozen ? PulseMode.Steady : PulseMode.Active);
		}

		private string BuildPriceButtonTooltip(bool hasOrder, bool frozen)
		{
			if (!hasOrder) return "Click to place a Price Based entry.";
			if (frozen)    return "Order Resting — Trailing: OFF\nClick to toggle trailing ON. Double-click or Close All to cancel.";
			return "Order Trailing — follows new bars\nClick to toggle trailing OFF. Double-click or Close All to cancel.";
		}

		// Tooltip content for the Buy Click / Sell Click buttons.
		// Updated on every RefreshPriceButtonPulses pass so the hint matches
		// the current armed / disarmed state.
		private string BuildClickEntryTooltip(string side, bool ready)
		{
			if (ready) return "Armed. Click chart to place, or click button to cancel.";
			return "Arm " + side + " Click. Next chart click places a " + side.ToLower() + " order.";
		}

		// Bottom-of-window status toast shown when the Price/Plot button is clicked.
		// frozen=true  → Order Resting (trailing off)
		// frozen=false → Order Trailing
		private string BuildTrailingStatusMessage(bool frozen)
		{
			string state = frozen ? "Order Resting." : "Order Trailing.";
			return state + " Use 'Close All' or double click to cancel order.";
		}

		// Replaces the bottom-of-window resting/trailing status so the two
		// states never stack. Without this helper, clicking Plot/Price to
		// toggle between trailing-on and trailing-off would add the new
		// message on top of the old one (both show at once, as in the
		// reported screenshot). Remove both possible prior variants first,
		// then add the current one.
		private void SetTrailingStatusMessage(bool frozen)
		{
			RemoveMessage(false, "Order Resting.");
			RemoveMessage(false, "Order Trailing.");
			AddMessage(BuildTrailingStatusMessage(frozen), 10, Brushes.Goldenrod);
		}

		// Plot-mode sync: the user wants clicking the Plot button (which toggles
		// our trailing flag) to also flip the order flag's attach-to-indicator
		// state, exactly as if they clicked the 'A' button on the order flag.
		// Only applies in Plot mode (Indicator) with a selected plot. Uses the
		// same SetOrderIndicatorTracking("On Off") path as the A button so all
		// side effects (immediate-move-to-plot on re-enable, etc.) match.
		private void SyncOrderTrackingWithTrailing(Order or, bool frozen)
		{
			if (or == null) return;
			if (pPriceBasedEntryMode != "Indicator") return;
			if (pPriceBasedIndicator == -1 || pPriceBasedPlot == -1) return;

			bool desiredTracking = !frozen;
			if (or.IsTrackingEnabled != desiredTracking)
				SetOrderIndicatorTracking(or, pPriceBasedIndicator, pPriceBasedPlot, "On Off");
		}

		/// Builds vertical gradient brushes for the top and bottom scroll-area fades.
		/// The bottom brush fades from transparent (top) → panel bg (bottom) so content
		/// scrolling past the bottom edge eases into the version label instead of being
		/// sharply clipped. The top brush is the mirror image: panel bg (top) → transparent
		/// (bottom), so content scrolled up off the top edge eases out cleanly.
		private void RebuildPanelFadeBrush()
		{
			if (panelFadeOverlay == null && panelFadeOverlayTop == null) return;
			System.Windows.Media.Color bgCol;
			var bg = (buttonGrid != null) ? buttonGrid.Background as System.Windows.Media.SolidColorBrush : null;
			if (bg != null) bgCol = bg.Color;
			else            bgCol = System.Windows.Media.Color.FromRgb(30, 30, 30); // fallback
			var transparent = System.Windows.Media.Color.FromArgb(0, bgCol.R, bgCol.G, bgCol.B);

			if (panelFadeOverlay != null)
			{
				var gradBottom = new System.Windows.Media.LinearGradientBrush();
				gradBottom.StartPoint = new System.Windows.Point(0, 0);
				gradBottom.EndPoint   = new System.Windows.Point(0, 1);
				gradBottom.GradientStops.Add(new System.Windows.Media.GradientStop(transparent, 0.0));
				gradBottom.GradientStops.Add(new System.Windows.Media.GradientStop(bgCol, 1.0));
				gradBottom.Freeze();
				panelFadeOverlay.Background = gradBottom;
			}

			if (panelFadeOverlayTop != null)
			{
				var gradTop = new System.Windows.Media.LinearGradientBrush();
				gradTop.StartPoint = new System.Windows.Point(0, 0);
				gradTop.EndPoint   = new System.Windows.Point(0, 1);
				gradTop.GradientStops.Add(new System.Windows.Media.GradientStop(bgCol, 0.0));
				gradTop.GradientStops.Add(new System.Windows.Media.GradientStop(transparent, 1.0));
				gradTop.Freeze();
				panelFadeOverlayTop.Background = gradTop;
			}
		}

		/// Shows each fade only when there's scrollable content beyond that edge.
		/// Bottom: visible when not at the bottom. Top: visible when not at the top.
		private void UpdatePanelFadeOverlayVisibility()
		{
			if (panelScrollViewer == null) return;
			double offset = panelScrollViewer.VerticalOffset;
			double scrollable = panelScrollViewer.ScrollableHeight;

			if (panelFadeOverlay != null)
			{
				bool moreBelow = scrollable > 0 && offset < scrollable - 0.5;
				var target = moreBelow ? System.Windows.Visibility.Visible : System.Windows.Visibility.Collapsed;
				if (panelFadeOverlay.Visibility != target)
					panelFadeOverlay.Visibility = target;
			}

			if (panelFadeOverlayTop != null)
			{
				bool moreAbove = scrollable > 0 && offset > 0.5;
				var target = moreAbove ? System.Windows.Visibility.Visible : System.Windows.Visibility.Collapsed;
				if (panelFadeOverlayTop.Visibility != target)
					panelFadeOverlayTop.Visibility = target;
			}
		}

		/// Re-applies styling to all tracked buttons and native controls.
		/// Called when the panel becomes visible (tab activation) since inactive tabs
		/// don't render WPF visuals and styling can be stale.
		private void RefreshPanelStyling()
		{
			// Force a layout pass — inactive tabs skip layout, so controls exist but never measured/arranged.
			// Batch invalidations on children, then call UpdateLayout() once on the root to do a single pass.
			try
			{
				if (mainPanelStack != null) { mainPanelStack.InvalidateMeasure(); mainPanelStack.InvalidateArrange(); }
				if (pinnedStack != null) { pinnedStack.InvalidateMeasure(); pinnedStack.InvalidateArrange(); }
				if (panelScrollViewer != null) { panelScrollViewer.InvalidateMeasure(); panelScrollViewer.InvalidateArrange(); }
				if (panelOuterGrid != null) panelOuterGrid.UpdateLayout();
				else if (panelDockPanel != null) panelDockPanel.UpdateLayout();
			}
			catch (Exception) { }

			// Re-apply background colors to panel containers
			try
			{
				if (buttonGrid != null && buttonGrid.Background != null)
				{
					if (pinnedStack != null) pinnedStack.Background = buttonGrid.Background;
					if (panelDockPanel != null) panelDockPanel.Background = buttonGrid.Background;
					if (mainPanelStack != null) mainPanelStack.Background = buttonGrid.Background;
					if (panelScrollViewer != null) panelScrollViewer.Background = buttonGrid.Background;
					RebuildPanelFadeBrush();
				}
			}
			catch (Exception) { }

			// Re-apply accent strips on all styled buttons. Uses the synchronous force-apply
			// path so a tab switch never exposes a frame with un-colored accent strips.
			ForceApplyAllAccentStrips();

			// Re-apply borders on native controls (account selector, ATM selector, etc.)
			foreach (var ctrl in nativeStyledControls)
			{
				if (ctrl == null) continue;
				try { ApplyBordersRecursive(ctrl); }
				catch (Exception) { }
			}

			// Recalculate width-dependent layouts
			try { UpdateButtonLabelsForWidth(); } catch (Exception) { }
		}

		private void ApplyAccentStripDeferred(System.Windows.Controls.Button btn)
		{
			btn.Dispatcher.BeginInvoke(System.Windows.Threading.DispatcherPriority.Loaded, new Action(() =>
			{
				try
				{
					if (btn.Template == null) btn.ApplyTemplate();
					var accent = btn.Template.FindName("accentStrip", btn) as System.Windows.Controls.Border;
					if (accent != null)
					{
						accentStripCache[btn] = accent;
						var currentColor = (btn.Tag is System.Windows.Media.Color) ? (System.Windows.Media.Color)btn.Tag : BrushToColor(btn.Background);
						accent.Background = PickAccentBrush(btn, GetButtonBrushSet(currentColor));
					}
				}
				catch { }
			}));
		}

		/// Synchronously walks every styled button, force-applies its template, and paints
		/// the accent strip in its current color. Used at panel insertion time so the user
		/// never sees a frame with a transparent (un-colored) accent strip.
		private void ForceApplyAllAccentStrips()
		{
			foreach (var btn in styledButtons)
			{
				if (btn == null) continue;
				try
				{
					System.Windows.Controls.Border accent;
					if (!accentStripCache.TryGetValue(btn, out accent) || accent == null)
					{
						if (btn.Template == null) continue;
						btn.ApplyTemplate();
						accent = btn.Template.FindName("accentStrip", btn) as System.Windows.Controls.Border;
						if (accent == null) continue;
						accentStripCache[btn] = accent;
					}
					var currentColor = (btn.Tag is System.Windows.Media.Color)
						? (System.Windows.Media.Color)btn.Tag
						: BrushToColor(btn.Background);
					accent.Background = PickAccentBrush(btn, GetButtonBrushSet(currentColor));
				}
				catch { }
			}
		}

		/// <summary>
		/// Applies a custom ComboBox template that removes the blue hover/focus border.
		/// Uses TemplateBinding so Background/BorderBrush/Foreground are respected.
		/// </summary>
		private void ApplyComboBoxStyle(System.Windows.Controls.ComboBox cb)
		{
			if (cb == null) return;
			cb.FocusVisualStyle = null;
			cb.BorderBrush = ControlBorderBrush;

			// Custom template: rounded corners + triangle arrow on closed state,
			// default NinjaTrader dark popup for the dropdown list
			string cr = cornerRadius.ToString(System.Globalization.CultureInfo.InvariantCulture);
			string xaml = @"<ControlTemplate xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation'
				xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml'
				TargetType='{x:Type ComboBox}'>
				<Grid>
					<ToggleButton x:Name='ToggleButton'
						IsChecked='{Binding IsDropDownOpen, Mode=TwoWay, RelativeSource={RelativeSource TemplatedParent}}'
						ClickMode='Press' Focusable='False'>
						<ToggleButton.Template>
							<ControlTemplate TargetType='{x:Type ToggleButton}'>
								<Border Background='{Binding Background, RelativeSource={RelativeSource AncestorType={x:Type ComboBox}}}'
									BorderBrush='{Binding BorderBrush, RelativeSource={RelativeSource AncestorType={x:Type ComboBox}}}'
									BorderThickness='1' CornerRadius='" + cr + @"'>
									<Grid>
										<Grid.ColumnDefinitions>
											<ColumnDefinition />
											<ColumnDefinition Width='18' />
										</Grid.ColumnDefinitions>
										<Path Grid.Column='1' HorizontalAlignment='Center' VerticalAlignment='Center'
											Data='M 0 0 L 4 4 L 8 0 Z'
											Fill='{Binding Foreground, RelativeSource={RelativeSource AncestorType={x:Type ComboBox}}}' />
									</Grid>
								</Border>
							</ControlTemplate>
						</ToggleButton.Template>
					</ToggleButton>
					<ContentPresenter IsHitTestVisible='False'
						Content='{TemplateBinding SelectionBoxItem}'
						ContentTemplate='{TemplateBinding SelectionBoxItemTemplate}'
						ContentStringFormat='{TemplateBinding SelectionBoxItemStringFormat}'
						Margin='5,2,23,2' VerticalAlignment='Center' HorizontalAlignment='Left' />
					<Popup x:Name='PART_Popup'
						IsOpen='{TemplateBinding IsDropDownOpen}'
						Placement='Bottom' Focusable='False' AllowsTransparency='True'>
						<Grid MaxHeight='{TemplateBinding MaxDropDownHeight}' MinWidth='{TemplateBinding ActualWidth}'
							SnapsToDevicePixels='True'>
							<Border Background='#252525' BorderBrush='#555555' BorderThickness='1' Padding='0,2'>
								<ScrollViewer SnapsToDevicePixels='True'>
									<StackPanel IsItemsHost='True' KeyboardNavigation.DirectionalNavigation='Contained' />
								</ScrollViewer>
							</Border>
						</Grid>
					</Popup>
				</Grid>
			</ControlTemplate>";

			try
			{
				cb.Template = (System.Windows.Controls.ControlTemplate)System.Windows.Markup.XamlReader.Parse(xaml);
			}
			catch (Exception) { /* fallback to default template if parsing fails */ }

			// Style dropdown items: proper height + dark hover highlight instead of bright blue
			string itemXaml = @"<Style xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation'
				xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml'
				TargetType='{x:Type ComboBoxItem}'>
				<Setter Property='Padding' Value='6,4,6,4' />
				<Setter Property='Background' Value='Transparent' />
				<Setter Property='Foreground' Value='#DDDDDD' />
				<Setter Property='Template'>
					<Setter.Value>
						<ControlTemplate TargetType='{x:Type ComboBoxItem}'>
							<Border x:Name='Bd' Background='{TemplateBinding Background}'
								Padding='{TemplateBinding Padding}' SnapsToDevicePixels='True'>
								<ContentPresenter VerticalAlignment='Center' />
							</Border>
							<ControlTemplate.Triggers>
								<Trigger Property='IsHighlighted' Value='True'>
									<Setter TargetName='Bd' Property='Background' Value='#3A3A3A' />
								</Trigger>
								<Trigger Property='IsSelected' Value='True'>
									<Setter TargetName='Bd' Property='Background' Value='#444444' />
								</Trigger>
							</ControlTemplate.Triggers>
						</ControlTemplate>
					</Setter.Value>
				</Setter>
			</Style>";

			try
			{
				cb.ItemContainerStyle = (System.Windows.Style)System.Windows.Markup.XamlReader.Parse(itemXaml);
			}
			catch (Exception) { /* fallback to default item style if parsing fails */ }

			// Hover highlight — lighten background like buttons do
			var cbBaseColor = BrushToColor(cb.Background);
			cb.Tag = cbBaseColor;
			cb.Background = MakeGradientBrush(cbBaseColor);

			cb.MouseEnter += (s, e) =>
			{
				if (cb.Tag is System.Windows.Media.Color bc)
					cb.Background = MakeGradientBrush(LightenColor(bc, hoverBrighten));
			};
			cb.MouseLeave += (s, e) =>
			{
				if (cb.Tag is System.Windows.Media.Color bc)
					cb.Background = MakeGradientBrush(bc);
			};
		}

		/// Applies rounded corners and matching border to any NinjaTrader native control
		/// by walking its visual tree after it loads. Works for TifSelector, AccountSelector,
		/// AtmStrategySelector, QuantityUpDown, and any other FrameworkElement.
		private void ApplyNativeControlStyle(System.Windows.FrameworkElement ctrl)
		{
			if (ctrl == null) return;

			ctrl.FocusVisualStyle = null;

			ctrl.Loaded += (s, e) =>
			{
				try
				{
					ApplyBordersRecursive(ctrl);
				}
				catch (Exception) { }
			};

			if (!nativeStyledControls.Contains(ctrl)) nativeStyledControls.Add(ctrl);
		}

		private void RestoreAndRestyle(System.Windows.FrameworkElement ctrl)
		{
			if (ctrl == null) return;
			ctrl.Visibility = System.Windows.Visibility.Visible;
			ctrl.Dispatcher.BeginInvoke(System.Windows.Threading.DispatcherPriority.Loaded, new Action(() =>
			{
				try { ApplyBordersRecursive(ctrl); } catch (Exception) { }
			}));
		}

		private void ApplyBordersRecursive(System.Windows.DependencyObject parent)
		{
			if (parent == null) return;
			int count = System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent);
			for (int i = 0; i < count; i++)
			{
				var child = System.Windows.Media.VisualTreeHelper.GetChild(parent, i);
				if (child is System.Windows.Controls.Border border)
				{
					border.CornerRadius = new System.Windows.CornerRadius(cornerRadius);
					border.BorderBrush = ControlBorderBrush;
				}
				ApplyBordersRecursive(child);
			}
		}

		/// <summary>
		/// Removes blue hover/focus borders from NinjaTrader QuantityUpDown controls
		/// by walking the visual tree after load and applying animation overrides
		/// (animation priority is higher than template triggers in WPF).
		/// </summary>
		private void ApplySpinnerStyle(NinjaTrader.Gui.Tools.QuantityUpDown qud)
		{
			if (qud == null) return;
			qud.FocusVisualStyle = null;
			qud.BorderBrush = ControlBorderBrush;

			// LayoutUpdated fires after the control template is fully applied,
			// which may happen later than Loaded (NinjaTrader applies templates lazily).
			// We run SuppressBlueBorders on the first few LayoutUpdated passes to catch it.
			int layoutPasses = 0;
			EventHandler layoutHandler = null;
			layoutHandler = (s, e) =>
			{
				SuppressBlueBorders(qud);
				layoutPasses++;
				if (layoutPasses >= 3)
					qud.LayoutUpdated -= layoutHandler;
			};
			qud.LayoutUpdated += layoutHandler;

			System.Windows.RoutedEventHandler loadedHandler = null;
			loadedHandler = (s, e) =>
			{
				SuppressBlueBorders(qud);
				qud.Loaded -= loadedHandler;
			};

			if (qud.IsLoaded)
				SuppressBlueBorders(qud);
			else
				qud.Loaded += loadedHandler;

			// NOTE: we intentionally do NOT suppress blue borders on GotFocus /
			// GotKeyboardFocus anymore. NinjaTrader's template paints a blue outline
			// when the control has focus — letting it show through gives the user a
			// visible "this is the currently focused box" indicator for Tab navigation
			// (which otherwise has no keyboard affordance). The initial-load suppression
			// above is still active, so the QUD still boots up dark-themed; only the
			// focus-time highlight is preserved.
		}

		/// <summary>
		/// Walks the visual tree and applies an animation override on all Border.BorderBrush
		/// Returns true if the key is a numeric input key (digits, backspace, delete, arrows, minus, tab, enter).
		/// </summary>
		private bool IsNumericInputKey(System.Windows.Input.Key key)
		{
			return (key >= System.Windows.Input.Key.D0 && key <= System.Windows.Input.Key.D9) ||
				(key >= System.Windows.Input.Key.NumPad0 && key <= System.Windows.Input.Key.NumPad9) ||
				key == System.Windows.Input.Key.Back || key == System.Windows.Input.Key.Delete ||
				key == System.Windows.Input.Key.Tab || key == System.Windows.Input.Key.Enter ||
				key == System.Windows.Input.Key.Left || key == System.Windows.Input.Key.Right ||
				key == System.Windows.Input.Key.OemMinus || key == System.Windows.Input.Key.Subtract;
		}

		private string qtyTypingBuffer = "";
		private NinjaTrader.Gui.Tools.QuantityUpDown qtyTypingTarget = null;
		// Single persistent buffer-clear timer — restart it on each keystroke instead of
		// allocating a fresh DispatcherTimer (the old approach leaked closures and could
		// race against newer timers replacing the field).
		private System.Windows.Threading.DispatcherTimer qtyTypingTimer = null;

		/// <summary>
		/// Handles keyboard digit entry for a QuantityUpDown control.
		/// Accumulates typed digits and sets the value after a brief pause.
		/// Also handles Tab/Shift+Tab to walk between visible+enabled QUDs.
		/// </summary>
		private bool HandleQtyKeyInput(NinjaTrader.Gui.Tools.QuantityUpDown qud, System.Windows.Input.Key key)
		{
			if (!pAllowKeyboardQtyEntry) return false;

			// Tab: walk to the next (or previous, with Shift) QUD that is currently
			// visible to the user. "Visible" here means the full WPF IsVisible chain —
			// element is in the tree, no ancestor is Collapsed/Hidden. This naturally
			// skips QUDs whose section is disabled (never added to the tree) or
			// collapsed (ancestor StackPanel has Visibility.Collapsed).
			if (key == System.Windows.Input.Key.Tab)
			{
				if (allKeyboardQuds == null || allKeyboardQuds.Count == 0) return false;
				int idx = allKeyboardQuds.IndexOf(qud);
				if (idx < 0) return false;

				bool shiftHeld = (System.Windows.Input.Keyboard.Modifiers & System.Windows.Input.ModifierKeys.Shift) != 0;
				int step = shiftHeld ? -1 : 1;
				int n = allKeyboardQuds.Count;
				for (int attempt = 1; attempt <= n; attempt++)
				{
					int next = ((idx + step * attempt) % n + n) % n;
					var target = allKeyboardQuds[next];
					if (target == null) continue;
					if (!target.IsEnabled) continue;
					if (!target.IsVisible) continue;
					try
					{
						// Commit any in-progress buffer before moving focus
						qtyTypingBuffer = "";
						qtyTypingTarget = target;
						System.Windows.Input.Keyboard.Focus(target);
					}
					catch { }
					return true;
				}
				// No eligible target — still consume the Tab so NT's chart doesn't act on it
				return true;
			}

			int digit = -1;
			if (key >= System.Windows.Input.Key.D0 && key <= System.Windows.Input.Key.D9)
				digit = key - System.Windows.Input.Key.D0;
			else if (key >= System.Windows.Input.Key.NumPad0 && key <= System.Windows.Input.Key.NumPad9)
				digit = key - System.Windows.Input.Key.NumPad0;

			bool isMinus = key == System.Windows.Input.Key.OemMinus || key == System.Windows.Input.Key.Subtract;
			bool isBackspace = key == System.Windows.Input.Key.Back;
			bool isDelete = key == System.Windows.Input.Key.Delete;
			bool isEnter = key == System.Windows.Input.Key.Enter;

			if (digit < 0 && !isMinus && !isBackspace && !isDelete && !isEnter)
				return false;

			// Reset buffer if targeting a different control
			if (qtyTypingTarget != qud)
			{
				qtyTypingBuffer = "";
				qtyTypingTarget = qud;
			}

			if (isEnter)
			{
				// Commit and clear
				qtyTypingBuffer = "";
				qtyTypingTarget = null;
				System.Windows.Input.Keyboard.ClearFocus();
				return true;
			}

			if (isBackspace)
			{
				if (qtyTypingBuffer.Length > 0)
					qtyTypingBuffer = qtyTypingBuffer.Substring(0, qtyTypingBuffer.Length - 1);
				else
					qtyTypingBuffer = "";
			}
			else if (isDelete)
			{
				qtyTypingBuffer = "";
			}
			else if (isMinus)
			{
				if (qud.IsNegativeValueAllowed)
				{
					if (qtyTypingBuffer.StartsWith("-"))
						qtyTypingBuffer = qtyTypingBuffer.Substring(1);
					else
						qtyTypingBuffer = "-" + qtyTypingBuffer;
				}
				else return true;
			}
			else
			{
				qtyTypingBuffer += digit.ToString();
			}

			// Apply value
			int val = 0;
			if (qtyTypingBuffer.Length > 0 && qtyTypingBuffer != "-")
			{
				if (int.TryParse(qtyTypingBuffer, out val))
				{
					val = Math.Max(qud.Minimum, Math.Min(qud.Maximum, val));
					qud.Value = val;
				}
			}
			else if (qtyTypingBuffer == "" || qtyTypingBuffer == "-")
			{
				// Clamp to the QUD's own minimum (which may be 1 for qty selectors)
				// instead of slamming it to 0 and letting WPF fight back.
				qud.Value = Math.Max(qud.Minimum, 0);
			}

			// Auto-clear buffer after 2 seconds of no typing.
			// Lazy-init a single persistent timer; restart it on each keystroke.
			if (qtyTypingTimer == null)
			{
				qtyTypingTimer = new System.Windows.Threading.DispatcherTimer();
				qtyTypingTimer.Interval = TimeSpan.FromSeconds(2);
				qtyTypingTimer.Tick += (s, e) =>
				{
					qtyTypingBuffer = "";
					qtyTypingTarget = null;
					if (qtyTypingTimer != null) qtyTypingTimer.Stop();
				};
			}
			qtyTypingTimer.Stop();
			qtyTypingTimer.Start();

			return true;
		}

		/// <summary>
		/// Walks the visual tree and applies an animation override on all Border.BorderBrush
		/// properties so template triggers (blue highlight) can never take effect.
		/// </summary>
		private void SuppressBlueBorders(System.Windows.DependencyObject parent)
		{
			int count = System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent);
			for (int i = 0; i < count; i++)
			{
				var child = System.Windows.Media.VisualTreeHelper.GetChild(parent, i);

				if (child is System.Windows.Controls.Control ctrl)
					ctrl.FocusVisualStyle = null;

				if (child is System.Windows.Controls.Border border && border.BorderThickness.Left > 0)
				{
					// Animation priority overrides template triggers in WPF
					var anim = new System.Windows.Media.Animation.ObjectAnimationUsingKeyFrames();
					anim.KeyFrames.Add(new System.Windows.Media.Animation.DiscreteObjectKeyFrame(
						ControlBorderBrush, System.Windows.Media.Animation.KeyTime.FromTimeSpan(TimeSpan.Zero)));
					anim.Freeze();
					border.BeginAnimation(System.Windows.Controls.Border.BorderBrushProperty, anim);
				}

				SuppressBlueBorders(child);
			}
		}

		/// <summary>
		/// Finds the first TextBlock in the visual tree, skipping Popup children (dropdown items).
		/// </summary>
		private System.Windows.Controls.TextBlock FindFirstTextBlock(System.Windows.DependencyObject parent)
		{
			int count = System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent);
			for (int i = 0; i < count; i++)
			{
				var child = System.Windows.Media.VisualTreeHelper.GetChild(parent, i);
				if (child is System.Windows.Controls.Primitives.Popup)
					continue;
				if (child is System.Windows.Controls.TextBlock tb)
					return tb;
				var result = FindFirstTextBlock(child);
				if (result != null) return result;
			}
			return null;
		}

		// ── "Is Master" row integration with Accounts Dashboard (ADA) ──
		// Reads the AppDomain-shared registry that ADA publishes (key
		// ADA_COPIER_SHARED_KEY). Gracefully no-ops when ADA is not
		// installed (key absent). See aiDuplicateAccountActions.cs →
		// PublishCopierSharedState for the slot layout.
		private System.Collections.Concurrent.ConcurrentDictionary<int, object[]> GetADACopierRegistry()
		{
			try
			{
				return AppDomain.CurrentDomain.GetData(ADA_COPIER_SHARED_KEY)
					as System.Collections.Concurrent.ConcurrentDictionary<int, object[]>;
			}
			catch { return null; }
		}

		/// <summary>
		/// Gathers the ADA registry entries where the master account equals the
		/// given account name AND the chart's current instrument is tracked.
		/// Returns an empty list when ADA is not installed, no entries match,
		/// or the selected account is null. Never throws.
		///
		/// Also opportunistically sweeps stale entries — if an ADA instance
		/// terminated abnormally and left its closures in the dictionary, the
		/// getter will throw (ObjectDisposed, NullReference, etc.), so we drop
		/// the entry here. Prevents unbounded growth.
		/// </summary>
		private List<object[]> GetMatchingCopierEntries(string selectedAccountName)
		{
			var matches = new List<object[]>();
			if (string.IsNullOrEmpty(selectedAccountName)) return matches;
			var reg = GetADACopierRegistry();
			if (reg == null) return matches;
			Instrument ci = Instrument;
			if (ci == null) return matches;

			List<int> stale = null;
			foreach (var kvp in reg)
			{
				try
				{
					object[] slots = kvp.Value;
					if (slots == null || slots.Length < 4) continue;
					var masterGetter = slots[0] as Func<string>;
					var appliesPred  = slots[2] as Func<object, bool>;
					if (masterGetter == null || appliesPred == null) continue;

					string m = masterGetter();
					if (string.IsNullOrEmpty(m) || m != selectedAccountName) continue;
					if (!appliesPred(ci)) continue;

					matches.Add(slots);
				}
				catch
				{
					// Dead closure from a terminated ADA instance — mark for removal
					// after the enumeration (can't mutate reg while iterating).
					if (stale == null) stale = new List<int>();
					stale.Add(kvp.Key);
				}
			}
			if (stale != null)
			{
				for (int i = 0; i < stale.Count; i++)
				{
					object[] removed;
					reg.TryRemove(stale[i], out removed);
				}
			}
			return matches;
		}

		/// <summary>
		/// Builds the row (label on the left, toggle button on the right).
		/// Called every time CreateWPFOrderControls runs — panel can rebuild
		/// on settings changes or tab switches, and the old row was removed
		/// from its parent during dispose. Building fresh avoids a disconnected-
		/// row class of bug. The refresh timer reads the field so it always
		/// updates whichever row is current.
		/// </summary>
		private void BuildCopierMasterRow()
		{

			int rowHeight = pPrimaryControlHeight; // match other primary buttons (button5, button6, button20, etc.)
			int buttonWidth = 90; // default — fits "COPY OFF" / "COPY ON"; RefreshCopierMasterRow widens when a [N] count is present

			copierMasterRow = new System.Windows.Controls.Grid
			{
				// +3 top (2 prior + 1 new) between account selector and row; +2 bottom between row and PNL.
				Margin = new System.Windows.Thickness(0, Math.Max(1, pControlGap) + 3, 0, 2),
				Visibility = System.Windows.Visibility.Collapsed
			};
			copierMasterRow.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });
			copierMasterRow.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = System.Windows.GridLength.Auto });

			// Label matches collapsible-section-header styling (Foreground alpha 70 white,
			// panelFont). Bold per request.
			copierMasterLabel = new System.Windows.Controls.TextBlock
			{
				Text = "Master",
				VerticalAlignment = System.Windows.VerticalAlignment.Center,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
				FontFamily = panelFont,
				FontSize = primaryFontSize,
				FontWeight = System.Windows.FontWeights.Normal,
				Margin = new System.Windows.Thickness(0),
				Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(70, 255, 255, 255))
			};
			System.Windows.Controls.Grid.SetColumn(copierMasterLabel, 0);
			copierMasterRow.Children.Add(copierMasterLabel);

			// Build with same property shape as primary buttons (button5/6/20):
			// explicit BorderBrush, Padding=0, and no FontFamily/Size overrides so
			// ApplyButtonStyle's template governs the visual chrome.
			copierMasterToggleBtn = new System.Windows.Controls.Button
			{
				Content = "COPY OFF",
				BorderBrush = ControlBorderBrush,
				Height = rowHeight,
				Width = buttonWidth,
				FontFamily = panelFont,
				FontSize = primaryFontSize,
				FontWeight = System.Windows.FontWeights.Normal,
				VerticalContentAlignment = System.Windows.VerticalAlignment.Center,
				Padding = new System.Windows.Thickness(0),
				Cursor = System.Windows.Input.Cursors.Hand,
				FocusVisualStyle = null
			};
			ApplyButtonStyle(copierMasterToggleBtn, "neutral");
			copierMasterToggleBtn.Click += (s, e) => { OnCopierMasterToggleClick(); };
			System.Windows.Controls.Grid.SetColumn(copierMasterToggleBtn, 1);
			copierMasterRow.Children.Add(copierMasterToggleBtn);
		}

		/// <summary>
		/// Sets row visibility, button text, and background to reflect current
		/// ADA state for the currently-selected account + current instrument.
		/// Safe to call from the UI thread at any time. Cheap — just a few
		/// delegate calls and a property write.
		/// </summary>
		private void RefreshCopierMasterRow()
		{
			if (copierMasterRow == null) return;
			try
			{
				string acctName = (myAccount != null) ? myAccount.Name
								 : (accountSelectorMain != null && accountSelectorMain.SelectedAccount != null
									? accountSelectorMain.SelectedAccount.Name : null);

				var matches = GetMatchingCopierEntries(acctName);
				int n = matches.Count;

				// Clear displayed blocker messages when no matching ADA window
				// reports a conflict anymore. Honours a 4-second grace period
				// per-blocker so clicks on exact-duplicate configs (where ADA's
				// CopierMainButton auto-clears one window's accounts, effectively
				// "resolving" the conflict in the same turn we added the warning)
				// don't flash-and-vanish.
				if (_copierDisplayedBlockers.Count > 0)
				{
					bool anyConflict = false;
					for (int i = 0; i < matches.Count; i++)
					{
						var conflictGetter = (matches[i].Length > 6) ? matches[i][6] as Func<bool> : null;
						if (conflictGetter != null)
						{
							try { if (conflictGetter()) { anyConflict = true; break; } } catch { }
						}
					}
					if (!anyConflict)
					{
						DateTime cutoff = DateTime.Now.AddSeconds(-4);
						System.Collections.Generic.List<string> toClear = null;
						foreach (var kv in _copierDisplayedBlockers)
						{
							if (kv.Value <= cutoff)
							{
								if (toClear == null) toClear = new System.Collections.Generic.List<string>();
								toClear.Add(kv.Key);
							}
						}
						if (toClear != null)
						{
							for (int k = 0; k < toClear.Count; k++)
							{
								try { RemoveMessage(true, toClear[k]); } catch { }
								_copierDisplayedBlockers.Remove(toClear[k]);
							}
						}
					}
				}

				if (n == 0)
				{
					if (copierMasterRow.Visibility != System.Windows.Visibility.Collapsed)
						copierMasterRow.Visibility = System.Windows.Visibility.Collapsed;
					return;
				}

				// Drain ADA-side blocker messages each tick. HandleConflictResult
				// populates slot [5] when the periodic check auto-disables the
				// copier due to a cross-window conflict. Slot [5] is read-and-
				// clear, so we just show whatever's there and track for cleanup.
				for (int i = 0; i < matches.Count; i++)
				{
					if (matches[i].Length <= 5) continue;
					var msgGetter = matches[i][5] as Func<string>;
					if (msgGetter == null) continue;
					string m = null;
					try { m = msgGetter(); } catch { }
					if (string.IsNullOrEmpty(m)) continue;
					if (_copierDisplayedBlockers.ContainsKey(m)) continue; // already showing
					string mShort = m.Length > 120 ? m.Substring(0, 120) + "..." : m;
					LogDiag("COPIER", "BlockerShown", "Source=Drain|Msg=" + mShort.Replace("|", ";"));
					AddMessage(m, 10, System.Windows.Media.Brushes.Goldenrod);
					_copierDisplayedBlockers[m] = DateTime.Now;
				}

				// Drain ADA-side "conflict resolved" messages (slot [7]) each
				// tick. Shown in green with a 10s life. When a resolved toast
				// fires, also immediately clear any lingering goldenrod blocker
				// messages we pushed — they're now obsolete.
				for (int i = 0; i < matches.Count; i++)
				{
					if (matches[i].Length <= 7) continue;
					var resolvedGetter = matches[i][7] as Func<string>;
					if (resolvedGetter == null) continue;
					string rm = null;
					try { rm = resolvedGetter(); } catch { }
					if (string.IsNullOrEmpty(rm)) continue;

					int clearedBlockers = _copierDisplayedBlockers.Count;
					if (_copierDisplayedBlockers.Count > 0)
					{
						foreach (var kv in _copierDisplayedBlockers)
						{
							try { RemoveMessage(true, kv.Key); } catch { }
						}
						_copierDisplayedBlockers.Clear();
					}
					string rmShort = rm.Length > 120 ? rm.Substring(0, 120) + "..." : rm;
					LogDiag("COPIER", "ResolvedShown", "ClearedBlockers=" + clearedBlockers + "|Msg=" + rmShort.Replace("|", ";"));
					AddMessage(rm, 10, System.Windows.Media.Brushes.LimeGreen);
				}

				// Aggregate = "any on". When some windows are ON and some are OFF,
				// button shows ON. Clicking then turns all OFF.
				bool anyOn = false;
				for (int i = 0; i < matches.Count; i++)
				{
					var enabledGetter = matches[i][1] as Func<bool>;
					if (enabledGetter != null && enabledGetter()) { anyOn = true; break; }
				}

				string label = (anyOn ? "COPY ON" : "COPY OFF") + (n > 1 ? (" [" + n + "]") : "");
				if (copierMasterToggleBtn != null)
				{
					copierMasterToggleBtn.Content = label;

					// Narrow when just "COPY ON"/"COPY OFF"; widen only when a count is shown.
					double targetWidth = (n > 1) ? 110 : 90;
					if (copierMasterToggleBtn.Width != targetWidth)
						copierMasterToggleBtn.Width = targetWidth;

					// Tooltip: total follower-account count across all matching windows.
					int totalFollowers = 0;
					for (int i = 0; i < matches.Count; i++)
					{
						var cntGetter = (matches[i].Length > 4) ? matches[i][4] as Func<int> : null;
						if (cntGetter != null)
						{
							try { totalFollowers += cntGetter(); } catch { }
						}
					}
					string tip = n > 1
						? (totalFollowers + " Follower account" + (totalFollowers == 1 ? "" : "s") + " across " + n + " windows")
						: (totalFollowers + " Follower account" + (totalFollowers == 1 ? "" : "s"));
					var existingCopierTt = copierMasterToggleBtn.ToolTip as ToolTip;
					if (existingCopierTt == null || !object.Equals(existingCopierTt.Content, tip))
						copierMasterToggleBtn.ToolTip = MakeToolTip(tip);
				}

				// Only restyle when state actually changes — otherwise a refresh
				// tick during hover overwrites the hover color applied by
				// StyledButton_MouseEnter. SetStyledBackground updates btn.Tag
				// (used for hover/press calculations), so it must still run on
				// actual transitions.
				int desiredState = anyOn ? 1 : 0;
				if (_copierBtnStyleState != desiredState)
				{
					// Log only on transition (not every refresh tick) so entries correspond to real
					// state changes. -1 means this is the first observation since ECT load.
					string acctNameForLog = (myAccount != null) ? myAccount.Name : null;
					LogDiag("COPIER", "AggregateState",
						"Account=" + (acctNameForLog ?? "?")
						+ "|WindowCount=" + matches.Count
						+ "|AnyOn=" + anyOn
						+ "|PrevState=" + (_copierBtnStyleState == -1 ? "init" : (_copierBtnStyleState == 1 ? "on" : "off")));

					System.Windows.Media.Brush bg = anyOn
						? new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(255, 45, 130, 55))
						: new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(255, 85, 85, 85));
					SetStyledBackground(copierMasterToggleBtn, bg);
					_copierBtnStyleState = desiredState;
				}

				if (copierMasterRow.Visibility != System.Windows.Visibility.Visible)
					copierMasterRow.Visibility = System.Windows.Visibility.Visible;
			}
			catch { /* never let a transient ADA-side race break the panel */ }
		}

		/// <summary>
		/// Toggle-all behaviour: if any matching window is OFF, turn them ALL on.
		/// If all are ON, turn them ALL off. Button label shows aggregate state
		/// (ON only when every matching window is enabled).
		/// </summary>
		private void OnCopierMasterToggleClick()
		{
			try
			{
				string acctName = (myAccount != null) ? myAccount.Name : null;
				var matches = GetMatchingCopierEntries(acctName);
				if (matches.Count == 0)
				{
					LogDiag("COPIER", "Toggle", "Account=" + (acctName ?? "?") + "|WindowCount=0|Skipped=true");
					return;
				}

				// Aggregate = "any on". If any window is currently ON, turn ALL off;
				// otherwise turn ALL on.
				bool anyOn = false;
				for (int i = 0; i < matches.Count; i++)
				{
					var g = matches[i][1] as Func<bool>;
					if (g != null && g()) { anyOn = true; break; }
				}
				bool newVal = !anyOn;

				LogDiag("COPIER", "Toggle",
					"Account=" + (acctName ?? "?")
					+ "|WindowCount=" + matches.Count
					+ "|PrevAnyOn=" + anyOn
					+ "|NewValue=" + (newVal ? "ON" : "OFF"));

				int setterInvoked = 0;
				for (int i = 0; i < matches.Count; i++)
				{
					var setter = matches[i][3] as Action<bool>;
					if (setter == null) continue;
					try { setter(newVal); setterInvoked++; } catch (Exception setEx) { LogDiagEx("COPIER", "SetterInvoke", setEx); }
				}
				LogDiag("COPIER", "SettersApplied", "Invoked=" + setterInvoked + "|Total=" + matches.Count);

				// Surface any ADA-side blocker message at the bottom of the ECT panel
				// (e.g. cross-window conflict, master not connected). Slot [5] is
				// read-and-clear. Show the first non-empty message found.
				string blocker = null;
				for (int i = 0; i < matches.Count; i++)
				{
					int sl = matches[i].Length;
					var msgGetter = (sl > 5) ? matches[i][5] as Func<string> : null;
					string m = null;
					if (msgGetter != null)
					{
						try { m = msgGetter(); } catch { }
					}
					if (!string.IsNullOrEmpty(m) && blocker == null) blocker = m;
				}
				if (!string.IsNullOrEmpty(blocker))
				{
					string blockerShort = blocker.Length > 120 ? blocker.Substring(0, 120) + "..." : blocker;
					LogDiag("COPIER", "BlockerShown", "Source=Toggle|Msg=" + blockerShort.Replace("|", ";"));
					AddMessage(blocker, 10, System.Windows.Media.Brushes.Goldenrod);
					_copierDisplayedBlockers[blocker] = DateTime.Now;
				}

				RefreshCopierMasterRow();
			}
			catch (Exception ex) { LogDiagEx("COPIER", "OnToggleClick", ex); }
		}

		/// <summary>
		/// 1-second UI-thread poll so row reflects external state changes
		/// (ADA user toggles CopierIsEnabled in the other window, or changes
		/// its master account). Stopped in State.Terminated.
		/// </summary>
		private void StartCopierMasterRefreshTimer()
		{
			if (copierMasterRefreshTimer != null) return;
			copierMasterRefreshTimer = new System.Windows.Threading.DispatcherTimer
			{
				Interval = TimeSpan.FromMilliseconds(1000)
			};
			copierMasterRefreshTimer.Tick += (s, e) => { RefreshCopierMasterRow(); };
			copierMasterRefreshTimer.Start();
		}
		// ── End "Is Master" row ────────────────────────────────────────

		/// <summary>
		/// Makes an AccountSelector show the END of the account name when text overflows,
		/// by applying a RenderTransform that shifts text left so the end is always visible.
		/// </summary>
		private void SetupAccountEndVisible(NinjaTrader.Gui.Tools.AccountSelector acctSel)
		{
			if (acctSel == null) return;

			// Show tooltip with full account name when the text is truncated
			acctSel.MouseEnter += (s, e) =>
			{
				try
				{
					string name = acctSel.SelectedAccount != null ? acctSel.SelectedAccount.Name : null;
					if (string.IsNullOrEmpty(name)) { acctSel.ToolTip = null; return; }

					// Measure the text to see if it's being truncated
					var typeface = new System.Windows.Media.Typeface(acctSel.FontFamily, acctSel.FontStyle, acctSel.FontWeight, acctSel.FontStretch);
					var ft = new System.Windows.Media.FormattedText(
						name,
						System.Globalization.CultureInfo.CurrentCulture,
						System.Windows.FlowDirection.LeftToRight,
						typeface, acctSel.FontSize,
						System.Windows.Media.Brushes.Black, 1.0);

					double avail = acctSel.ActualWidth - 22; // minus dropdown arrow
					if (avail > 0 && ft.Width > avail)
						acctSel.ToolTip = MakeToolTip(name);
					else
						acctSel.ToolTip = null;
				}
				catch { }
			};

			acctSel.MouseLeave += (s, e) =>
			{
				acctSel.ToolTip = null;
			};
		}

		/// <summary>
		/// Creates a LinearGradientBrush from a base color — lighter at top, darker at bottom.
		/// </summary>
		private System.Windows.Media.LinearGradientBrush MakeGradientBrush(System.Windows.Media.Color baseColor)
		{
			var lighter = LightenColor(baseColor, gradientTopLighten);
			var darker = DarkenColor(baseColor, gradientBottomDarken);
			var gb = new System.Windows.Media.LinearGradientBrush(lighter, darker, 90.0);
			gb.Freeze();
			return gb;
		}

		/// <summary>
		/// Returns a cached set of base/hover/press brushes for the given base color.
		/// Brushes are frozen and shared across all buttons of the same color.
		/// </summary>
		private ButtonBrushSet GetButtonBrushSet(System.Windows.Media.Color baseColor)
		{
			ButtonBrushSet set;
			if (buttonBrushCache.TryGetValue(baseColor, out set)) return set;
			set = new ButtonBrushSet();
			set.Base = MakeGradientBrush(baseColor);
			set.Hover = MakeGradientBrush(LightenColor(baseColor, hoverBrighten));
			var pressBrush = new System.Windows.Media.SolidColorBrush(DarkenColor(baseColor, pressDarken));
			pressBrush.Freeze();
			set.Press = pressBrush;
			var accentBrush = new System.Windows.Media.SolidColorBrush(GetAccentColor(baseColor, false));
			accentBrush.Freeze();
			set.Accent = accentBrush;
			var accentSecondaryBrush = new System.Windows.Media.SolidColorBrush(GetAccentColor(baseColor, true));
			accentSecondaryBrush.Freeze();
			set.AccentSecondary = accentSecondaryBrush;
			buttonBrushCache[baseColor] = set;
			return set;
		}

		private System.Windows.Media.Color LightenColor(System.Windows.Media.Color c, double amount)
		{
			byte r = (byte)Math.Min(255, c.R + (255 - c.R) * amount);
			byte g = (byte)Math.Min(255, c.G + (255 - c.G) * amount);
			byte b = (byte)Math.Min(255, c.B + (255 - c.B) * amount);
			return System.Windows.Media.Color.FromArgb(c.A, r, g, b);
		}

		/// <summary>
		/// Brightens a color by scaling RGB channels up proportionally, preserving hue and saturation.
		/// Unlike LightenColor (which blends toward white), this multiplies channels so colors stay vivid.
		/// amount 0 = unchanged, 1 = double brightness (clamped to 255).
		/// </summary>
		private System.Windows.Media.Color BrightenColor(System.Windows.Media.Color c, double amount)
		{
			double scale = 1.0 + amount;
			byte r = (byte)Math.Min(255, (int)(c.R * scale));
			byte g = (byte)Math.Min(255, (int)(c.G * scale));
			byte b = (byte)Math.Min(255, (int)(c.B * scale));
			return System.Windows.Media.Color.FromArgb(c.A, r, g, b);
		}

		private System.Windows.Media.Color DarkenColor(System.Windows.Media.Color c, double amount)
		{
			byte r = (byte)Math.Max(0, c.R * (1 - amount));
			byte g = (byte)Math.Max(0, c.G * (1 - amount));
			byte b = (byte)Math.Max(0, c.B * (1 - amount));
			return System.Windows.Media.Color.FromArgb(c.A, r, g, b);
		}

		private System.Windows.Media.Color BrushToColor(Brush brush)
		{
			if (brush is System.Windows.Media.SolidColorBrush scb) return scb.Color;
			if (brush is System.Windows.Media.LinearGradientBrush lgb && lgb.GradientStops.Count > 0)
			{
				// Use the middle stop or average
				var mid = lgb.GradientStops[lgb.GradientStops.Count / 2];
				return mid.Color;
			}
			return System.Windows.Media.Colors.Gray;
		}

		/// <summary>
		/// Applies the custom rounded-corner template with gradient, hover, and press effects.
		/// buttonType: "buy", "sell", or "neutral" — controls accent strip color.
		/// </summary>
		/// Walks the visual tree under the given parent and forces the width of all
		/// vertical ScrollBar descendants. Tracks which we've already styled to avoid
		/// re-applying every layout pass.
		private void ForceScrollBarWidth(System.Windows.DependencyObject parent, double width, System.Collections.Generic.HashSet<System.Windows.Controls.Primitives.ScrollBar> styled)
		{
			if (parent == null) return;
			int count = System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent);
			for (int i = 0; i < count; i++)
			{
				var child = System.Windows.Media.VisualTreeHelper.GetChild(parent, i);
				var sb = child as System.Windows.Controls.Primitives.ScrollBar;
				if (sb != null && sb.Orientation == System.Windows.Controls.Orientation.Vertical)
				{
					if (!styled.Contains(sb))
					{
						sb.Width = width;
						sb.MaxWidth = width;
						sb.MinWidth = width;
						sb.Background = System.Windows.Media.Brushes.Transparent;
						styled.Add(sb);
					}
				}
				ForceScrollBarWidth(child, width, styled);
			}
		}

		private System.Windows.Controls.ControlTemplate BuildAccentButtonTemplate(int stripW)
		{
			var template = new System.Windows.Controls.ControlTemplate(typeof(System.Windows.Controls.Button));
			var outerBorder = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "outerBorder");
			outerBorder.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(cornerRadius));
			outerBorder.SetValue(System.Windows.Controls.Border.BorderBrushProperty, new System.Windows.Data.Binding("BorderBrush") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Data.Binding("BorderThickness") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("Background") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.UIElement.ClipToBoundsProperty, true);

			// Single-cell Grid: ContentPresenter spans the full button width so text
			// stays optically centered, while the accent Border is overlaid on the
			// left edge as a fixed-width left-aligned element (does not consume layout space).
			var gridFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Grid));

			var cp = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ContentPresenter));
			cp.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Center);
			cp.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			cp.SetValue(System.Windows.FrameworkElement.MarginProperty, new System.Windows.Data.Binding("Padding") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });

			var accent = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "accentStrip");
			accent.SetValue(System.Windows.Controls.Border.BackgroundProperty, System.Windows.Media.Brushes.Transparent);
			accent.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Left);
			accent.SetValue(System.Windows.FrameworkElement.WidthProperty, (double)stripW);
			accent.SetValue(System.Windows.UIElement.IsHitTestVisibleProperty, false);
			accent.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(Math.Max(0, cornerRadius - 1), 0, 0, Math.Max(0, cornerRadius - 1)));

			// Right-edge accent strip — transparent by default. Only the Price Based Entry
			// buttons (Button37/38) light this up when their order is actively trailing.
			var accentR = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "accentStripRight");
			accentR.SetValue(System.Windows.Controls.Border.BackgroundProperty, System.Windows.Media.Brushes.Transparent);
			accentR.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Right);
			accentR.SetValue(System.Windows.FrameworkElement.WidthProperty, (double)stripW);
			accentR.SetValue(System.Windows.UIElement.IsHitTestVisibleProperty, false);
			accentR.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(0, Math.Max(0, cornerRadius - 1), Math.Max(0, cornerRadius - 1), 0));

			// ContentPresenter first so the accents paint over the (mostly empty) edges.
			gridFactory.AppendChild(cp);
			gridFactory.AppendChild(accent);
			gridFactory.AppendChild(accentR);
			outerBorder.AppendChild(gridFactory);

			template.VisualTree = outerBorder;
			template.Seal();
			return template;
		}

		private void ApplyButtonStyle(System.Windows.Controls.Button btn, string buttonType, string buttonSize = null)
		{
			if (btn == null) return;

			// Store the original base color for hover/press calculations
			var baseColor = BrushToColor(btn.Background);
			btn.Tag = baseColor;

			// Apply gradient background (cached, frozen, shared by color)
			btn.Background = GetButtonBrushSet(baseColor).Base;

			// Pick size variant. Explicit "tertiary" opt-in for tiny square mini-buttons
			// (T, $, X, IB, show/hide account); otherwise fall back to height heuristic.
			bool isTertiary = buttonSize == "tertiary";
			bool isSecondaryHeight = !isTertiary && !double.IsNaN(btn.Height) && btn.Height <= smallControlHeight + 0.5;

			// Use cached template (one per variant) — major perf win
			if (isTertiary)
			{
				if (cachedTertiaryButtonTemplate == null)
					cachedTertiaryButtonTemplate = BuildAccentButtonTemplate(accentStripWidthTertiary);
				btn.Template = cachedTertiaryButtonTemplate;
			}
			else if (isSecondaryHeight)
			{
				if (cachedSecondaryButtonTemplate == null)
					cachedSecondaryButtonTemplate = BuildAccentButtonTemplate(accentStripWidthSecondary);
				btn.Template = cachedSecondaryButtonTemplate;
			}
			else
			{
				if (cachedPrimaryButtonTemplate == null)
					cachedPrimaryButtonTemplate = BuildAccentButtonTemplate(accentStripWidth);
				btn.Template = cachedPrimaryButtonTemplate;
			}

			// Mark the button so PickAccentBrush/IsSecondaryButton can tell tertiaries apart
			// from regular secondaries without needing another Tag (Tag already holds baseColor).
			if (isTertiary) tertiaryButtons.Add(btn);

			btn.FontSize = (isSecondaryHeight || isTertiary) ? pButtonFontSize : primaryFontSize;
			if (panelFont != null) btn.FontFamily = panelFont;

			// Hover and press events
			btn.MouseEnter += StyledButton_MouseEnter;
			btn.MouseLeave += StyledButton_MouseLeave;
			btn.PreviewMouseLeftButtonDown += StyledButton_MouseDown;
			btn.PreviewMouseLeftButtonUp += StyledButton_MouseUp;

			// Track for visibility-change refresh
			styledButtons.Add(btn);
		}

		/// <summary>
		/// Applies styling to direction toggle buttons — rounded on outer corners, flat on the joined side.
		/// side: "left" means flat on right (toggle joins button on its right), "right" means flat on left.
		/// </summary>
		private System.Windows.Controls.ControlTemplate BuildToggleTemplate(string side)
		{
			var template = new System.Windows.Controls.ControlTemplate(typeof(System.Windows.Controls.Button));
			var border = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "outerBorder");
			double r = cornerRadius;
			if (side == "left")
				border.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(r, 0, 0, r));
			else
				border.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(0, r, r, 0));
			border.SetValue(System.Windows.Controls.Border.BorderBrushProperty, new System.Windows.Data.Binding("BorderBrush") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			border.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Data.Binding("BorderThickness") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			border.SetValue(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("Background") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });

			var cp = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ContentPresenter));
			cp.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Center);
			cp.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			border.AppendChild(cp);

			template.VisualTree = border;
			template.Seal();
			return template;
		}

		private void ApplyToggleStyle(System.Windows.Controls.Button btn, string side, string buttonType)
		{
			if (btn == null) return;

			var baseColor = BrushToColor(btn.Background);
			btn.Tag = baseColor;
			btn.Background = GetButtonBrushSet(baseColor).Base;

			if (side == "left")
			{
				if (cachedToggleLeftTemplate == null) cachedToggleLeftTemplate = BuildToggleTemplate("left");
				btn.Template = cachedToggleLeftTemplate;
			}
			else
			{
				if (cachedToggleRightTemplate == null) cachedToggleRightTemplate = BuildToggleTemplate("right");
				btn.Template = cachedToggleRightTemplate;
			}

			btn.FontSize = (!double.IsNaN(btn.Height) && btn.Height <= smallControlHeight + 0.5) ? pButtonFontSize : primaryFontSize;
			if (panelFont != null) btn.FontFamily = panelFont;

			btn.MouseEnter += StyledButton_MouseEnter;
			btn.MouseLeave += StyledButton_MouseLeave;
			btn.PreviewMouseLeftButtonDown += StyledButton_MouseDown;
			btn.PreviewMouseLeftButtonUp += StyledButton_MouseUp;
			styledButtons.Add(btn);
		}

		/// <summary>
		/// Also flatten the joined side of the main button that has a toggle attached.
		/// side: "left" means toggle is on left so main button is flat on left, "right" means flat on right.
		/// </summary>
		private System.Windows.Controls.ControlTemplate BuildFlatSideTemplate(string flatSide, int stripW)
		{
			var template = new System.Windows.Controls.ControlTemplate(typeof(System.Windows.Controls.Button));
			var outerBorder = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "outerBorder");
			double r = cornerRadius;
			if (flatSide == "right")
				outerBorder.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(r, 0, 0, r));
			else
				outerBorder.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(0, r, r, 0));

			outerBorder.SetValue(System.Windows.Controls.Border.BorderBrushProperty, new System.Windows.Data.Binding("BorderBrush") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Data.Binding("BorderThickness") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("Background") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });
			outerBorder.SetValue(System.Windows.UIElement.ClipToBoundsProperty, true);

			// Single-cell Grid: ContentPresenter spans the full button width so text
			// stays optically centered, while the accent Border is overlaid on the
			// left edge as a fixed-width left-aligned element (does not consume layout space).
			var gridFactory = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Grid));

			var cp = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ContentPresenter));
			cp.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Center);
			cp.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			cp.SetValue(System.Windows.FrameworkElement.MarginProperty, new System.Windows.Data.Binding("Padding") { RelativeSource = new System.Windows.Data.RelativeSource(System.Windows.Data.RelativeSourceMode.TemplatedParent) });

			var accent = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border), "accentStrip");
			accent.SetValue(System.Windows.Controls.Border.BackgroundProperty, System.Windows.Media.Brushes.Transparent);
			accent.SetValue(System.Windows.FrameworkElement.HorizontalAlignmentProperty, System.Windows.HorizontalAlignment.Left);
			accent.SetValue(System.Windows.FrameworkElement.WidthProperty, (double)stripW);
			accent.SetValue(System.Windows.UIElement.IsHitTestVisibleProperty, false);
			double leftR = flatSide == "left" ? 0 : Math.Max(0, cornerRadius - 1);
			accent.SetValue(System.Windows.Controls.Border.CornerRadiusProperty, new System.Windows.CornerRadius(leftR, 0, 0, leftR));

			gridFactory.AppendChild(cp);
			gridFactory.AppendChild(accent);
			outerBorder.AppendChild(gridFactory);

			template.VisualTree = outerBorder;
			template.Seal();
			return template;
		}

		private void ApplyButtonStyleWithFlatSide(System.Windows.Controls.Button btn, string buttonType, string flatSide)
		{
			if (btn == null) return;

			var baseColor = BrushToColor(btn.Background);
			btn.Tag = baseColor;
			btn.Background = GetButtonBrushSet(baseColor).Base;

			bool isSecondary = !double.IsNaN(btn.Height) && btn.Height <= smallControlHeight + 0.5;

			if (isSecondary)
			{
				if (flatSide == "left")
				{
					if (cachedFlatLeftSecondaryTemplate == null) cachedFlatLeftSecondaryTemplate = BuildFlatSideTemplate("left", 3);
					btn.Template = cachedFlatLeftSecondaryTemplate;
				}
				else
				{
					if (cachedFlatRightSecondaryTemplate == null) cachedFlatRightSecondaryTemplate = BuildFlatSideTemplate("right", 3);
					btn.Template = cachedFlatRightSecondaryTemplate;
				}
			}
			else
			{
				if (flatSide == "left")
				{
					if (cachedFlatLeftPrimaryTemplate == null) cachedFlatLeftPrimaryTemplate = BuildFlatSideTemplate("left", accentStripWidth);
					btn.Template = cachedFlatLeftPrimaryTemplate;
				}
				else
				{
					if (cachedFlatRightPrimaryTemplate == null) cachedFlatRightPrimaryTemplate = BuildFlatSideTemplate("right", accentStripWidth);
					btn.Template = cachedFlatRightPrimaryTemplate;
				}
			}

			btn.FontSize = isSecondary ? pButtonFontSize : primaryFontSize;
			if (panelFont != null) btn.FontFamily = panelFont;

			btn.MouseEnter += StyledButton_MouseEnter;
			btn.MouseLeave += StyledButton_MouseLeave;
			btn.PreviewMouseLeftButtonDown += StyledButton_MouseDown;
			btn.PreviewMouseLeftButtonUp += StyledButton_MouseUp;
			styledButtons.Add(btn);
		}

		// ── Hover / Press event handlers ──

		private void StyledButton_MouseEnter(object sender, System.Windows.Input.MouseEventArgs e)
		{
			var btn = sender as System.Windows.Controls.Button;
			// While Buy/Sell Click is armed, suppress hover styling on the Buy
			// Click / Sell Click buttons themselves so they stay locked to their
			// active pulse state and don't flicker when the cursor passes over.
			if ((BuyClickReady || SellClickReady) && (btn == button7 || btn == button8))
				return;
			if (btn != null && btn.Tag is System.Windows.Media.Color)
			{
				btn.Background = GetButtonBrushSet((System.Windows.Media.Color)btn.Tag).Hover;
			}
		}

		private void StyledButton_MouseLeave(object sender, System.Windows.Input.MouseEventArgs e)
		{
			var btn = sender as System.Windows.Controls.Button;
			if ((BuyClickReady || SellClickReady) && (btn == button7 || btn == button8))
				return;
			if (btn != null && btn.Tag is System.Windows.Media.Color)
			{
				btn.Background = GetButtonBrushSet((System.Windows.Media.Color)btn.Tag).Base;
			}
		}

		private void StyledButton_MouseDown(object sender, System.Windows.Input.MouseButtonEventArgs e)
		{
			var btn = sender as System.Windows.Controls.Button;
			if ((BuyClickReady || SellClickReady) && (btn == button7 || btn == button8))
				return;
			if (btn != null && btn.Tag is System.Windows.Media.Color)
			{
				btn.Background = GetButtonBrushSet((System.Windows.Media.Color)btn.Tag).Press;
			}
		}

		private void StyledButton_MouseUp(object sender, System.Windows.Input.MouseButtonEventArgs e)
		{
			var btn = sender as System.Windows.Controls.Button;
			if ((BuyClickReady || SellClickReady) && (btn == button7 || btn == button8))
				return;
			if (btn != null && btn.Tag is System.Windows.Media.Color)
			{
				// Return to hover state since mouse is still over button
				btn.Background = GetButtonBrushSet((System.Windows.Media.Color)btn.Tag).Hover;
			}
		}

		// Measures whether fullText fits in the button's current width; returns shortText if not
		private string FitButtonText(System.Windows.Controls.Button btn, string fullText, string shortText, double extraPadding = 0)
		{
			if (btn == null) return fullText;
			double availWidth = btn.ActualWidth;
			if (availWidth <= 0) availWidth = Math.Max(0, (pChartTraderWidth - 20) / 2); // estimate before layout for typical 2-column button rows

			var typeface = new System.Windows.Media.Typeface(
				btn.FontFamily, btn.FontStyle, btn.FontWeight, btn.FontStretch);
			var ft = new System.Windows.Media.FormattedText(
				fullText,
				System.Globalization.CultureInfo.CurrentCulture,
				System.Windows.FlowDirection.LeftToRight,
				typeface,
				btn.FontSize > 0 ? btn.FontSize : 12,
				System.Windows.Media.Brushes.Black,
				1.0);

			return ft.Width + 18 + extraPadding > availWidth ? shortText : fullText;
		}

		// 3-tier version: tries full → mid → short
		private string FitButtonText3(System.Windows.Controls.Button btn, string fullText, string midText, string shortText)
		{
			string result = FitButtonText(btn, fullText, midText);
			if (result == midText)
				result = FitButtonText(btn, midText, shortText);
			return result;
		}

		private void UpdateButtonLabelsForWidth()
		{
			if (button1 == null) return;

			// Skip if panel width hasn't changed since last fit pass — FormattedText allocs are expensive
			double curWidth = (button1.ActualWidth > 0) ? button1.ActualWidth : pChartTraderWidth;
			if (Math.Abs(curWidth - lastMeasuredPanelWidth) < 0.5) return;
			lastMeasuredPanelWidth = curWidth;

			UpdateCollapseAllButtonText();

			// Market buttons — sync pair
			{
				string m1 = FitButtonText(button1, "Market", "Mkt");
				string m2 = FitButtonText(button2, "Market", "Mkt");
				string mkt = (m1 == "Mkt" || m2 == "Mkt") ? "Mkt" : "Market";
				button1.Content = mkt;
				button2.Content = mkt;
			}

			// Click buttons — sync pair; skip if showing "Cancel"
			if (button7 != null && button8 != null
				&& button7.Content.ToString() != "Cancel" && button8.Content.ToString() != "Cancel")
			{
				// Base decision on Sell Click (longer text) to ensure both fit
				string c2 = FitButtonText3(button8, "Sell Click", "Click", "Clk");
				if (c2 == "Clk") { button7.Content = "Clk"; button8.Content = "Clk"; }
				else if (c2 == "Click") { button7.Content = "Click"; button8.Content = "Click"; }
				else { button7.Content = "Buy Click"; button8.Content = "Sell Click"; }
			}
			else
			{
				if (button7 != null && button7.Content.ToString() != "Cancel")
					button7.Content = FitButtonText3(button7, "Buy Click", "Click", "Clk");
				if (button8 != null && button8.Content.ToString() != "Cancel")
					button8.Content = FitButtonText3(button8, "Sell Click", "Click", "Clk");
			}

			// Signal buttons — sync pair
			if (button23 != null && button24 != null)
			{
				string s1 = FitButtonText(button23, "Signal", "Sig");
				string s2 = FitButtonText(button24, "Signal", "Sig");
				string sig = (s1 == "Sig" || s2 == "Sig") ? "Sig" : "Signal";
				button23.Content = sig;
				button24.Content = sig;
			}

			// Close buttons — sync pair
			if (button9 != null && button10 != null)
			{
				string cl1 = FitButtonText(button9, "Close", "Cls");
				string cl2 = FitButtonText(button10, "Close", "Cls");
				string cls = (cl1 == "Cls" || cl2 == "Cls") ? "Cls" : "Close";
				button9.Content = cls;
				button10.Content = cls;
			}

			// Iceberg buttons — sync pair
			if (button3 != null && button4 != null)
			{
				string i1 = FitButtonText(button3, "Iceberg", "Ice");
				string i2 = FitButtonText(button4, "Iceberg", "Ice");
				string ice = (i1 == "Ice" || i2 == "Ice") ? "Ice" : "Iceberg";
				button3.Content = ice;
				button4.Content = ice;
			}

			// Sliced buttons — sync pair
			if (button18 != null && button19 != null)
			{
				string sl1 = FitButtonText(button18, "Sliced", "Slc");
				string sl2 = FitButtonText(button19, "Sliced", "Slc");
				string slc = (sl1 == "Slc" || sl2 == "Slc") ? "Slc" : "Sliced";
				button18.Content = slc;
				button19.Content = slc;
			}

			// Close All button
			if (button5 != null && button5.Content.ToString() != "Cancel All")
				button5.Content = FitButtonText(button5, "Close All", "Close");

			// Reverse button — skip if showing Cancel or Exit
			if (button21 != null && button21.Content.ToString() != "Cancel" && button21.Content.ToString() != "Exit")
				button21.Content = FitButtonText(button21, "Reverse", "Rev", 6);

			// Main Position Management Reverse button — only refit when actually
			// showing Reverse/Rev (button13 also hosts BE and Close X% variants)
			if (button13 != null)
			{
				string b13 = button13.Content.ToString();
				if (b13 == "Reverse" || b13 == "Rev")
					button13.Content = FitButtonText(button13, "Reverse", "Rev", 6);
			}

			// Section header labels — swap full/short name based on current width.
			// Only sections that were created with a shortName are affected.
			for (int i = 0; i < sectionHeaderButtons.Count; i++)
			{
				var hb = sectionHeaderButtons[i];
				if (hb == null) continue;
				var tag = hb.Tag as Tuple<string, string, string>;
				if (tag == null || tag.Item2 == tag.Item3) continue;
				bool expanded = sectionExpandedStates.ContainsKey(tag.Item1) && sectionExpandedStates[tag.Item1];
				ApplySectionHeaderLabel(hb, expanded);
			}

			// Size toggle — abbreviate based on available width
			if (toggle13 != null)
			{
				string sizeState = pPositionSizingIsEnabled ? "ON" : "OFF";
				toggle13.Content = FitButtonText3(toggle13, "SIZE " + sizeState, "SIZE", "SZ");
			}

			// Next Trade / Continuous button
			if (button25 != null)
				button25.Content = FitButtonText(button25, pSignalAutoEnabled ? "Continuous" : "Next Trade", pSignalAutoEnabled ? "Cont" : "Next", 2);

			// Update PNL display widths
			if (PNLGrid != null)
			{
				double pnlWidth = pChartTraderWidth - CTLeftSpace - CTLeftSpace - endadd + 2;
				PNLGrid.Width = pnlWidth;
				PNLBox.Width = pnlWidth;

				if (pProfitAndLossEntry == "Show")
				{
					double pnlInner = pChartTraderWidth - CTLeftSpace - CTLeftSpace - endadd + 2;
					double halfGap = 1;
					double entryW = Math.Floor(pnlInner / 2);
					double qtyW = pnlInner - entryW - halfGap;
					QTYBox.Width = qtyW;
					EntryBox.Width = entryW;
				}
				else
				{
					double pnlInner2 = pChartTraderWidth - CTLeftSpace - CTLeftSpace - endadd + 2;
					QTYBox.Width = pnlInner2 - 15 - 1;
					EntryBox.Width = 15;
				}
			}

			// BracketGrid: collapse SL offset spinner (col4) when panel is narrow
			if (OffsetBox5 != null && BracketGrid != null && BracketGrid.ColumnDefinitions.Count > 4)
			{
				if (pChartTraderWidth < 155)
				{
					OffsetBox5.Visibility = System.Windows.Visibility.Collapsed;
					BracketGrid.ColumnDefinitions[3].Width = new GridLength(0);
					BracketGrid.ColumnDefinitions[4].Width = new GridLength(0);
					BracketGrid.ColumnDefinitions[4].MinWidth = 0;
				}
				else
				{
					RestoreAndRestyle(OffsetBox5);
					BracketGrid.ColumnDefinitions[3].Width = new GridLength(smallGapH);
					BracketGrid.ColumnDefinitions[4].Width = new GridLength(1, GridUnitType.Star);
					BracketGrid.ColumnDefinitions[4].MinWidth = 38;
				}
			}

			// ── OffsetBox4 responsive: hide spinner when not needed (STP/LMT/MIT) or panel narrow ──
			if (OffsetBox4 != null && ClickEntryGrid != null && ClickEntryGrid.ColumnDefinitions.Count > 5)
			{
				bool offsetNeeded = pUseSLM || pThisEntryLimitClick == "LIT";
				int narrowThreshold = pOCOButtonEnabled ? 155 : 120;
				if (!offsetNeeded || pChartTraderWidth < narrowThreshold)
				{
					OffsetBox4.Visibility = System.Windows.Visibility.Collapsed;
					ClickEntryGrid.ColumnDefinitions[4].Width = new GridLength(0);
					ClickEntryGrid.ColumnDefinitions[5].Width = new GridLength(0);
				}
				else
				{
					RestoreAndRestyle(OffsetBox4);
					ClickEntryGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
					ClickEntryGrid.ColumnDefinitions[5].Width = new GridLength(48);
				}
			}

			// CloseEntryGrid (Close Entry row): hide OffsetBox1 when narrow to give Reverse button room
			// Columns: [0:spacer][1:dropdown 54px][2:gap][3:spinner 48-70px][4:gap][5:button 1*]
			if (OffsetBox1 != null && CloseEntryGrid != null && CloseEntryGrid.ColumnDefinitions.Count > 5)
			{
				if (pChartTraderWidth < 155)
				{
					OffsetBox1.Visibility = System.Windows.Visibility.Collapsed;
					CloseEntryGrid.ColumnDefinitions[3].Width = new GridLength(0);
					CloseEntryGrid.ColumnDefinitions[3].MinWidth = 0;
					CloseEntryGrid.ColumnDefinitions[4].Width = new GridLength(0);
				}
				else
				{
					RestoreAndRestyle(OffsetBox1);
					CloseEntryGrid.ColumnDefinitions[3].Width = new GridLength(48);
					CloseEntryGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
				}
			}

			// SignalEntryGrid (Signal Entry row): hide OffsetBox15 when narrow to give Next Trade button room
			// Columns: [0:spacer][1:dropdown 54px][2:gap][3:spinner 48-70px][4:gap][5:button 1*]
			if (OffsetBox15 != null && SignalEntryGrid != null && SignalEntryGrid.ColumnDefinitions.Count > 5)
			{
				if (pChartTraderWidth < 155)
				{
					OffsetBox15.Visibility = System.Windows.Visibility.Collapsed;
					SignalEntryGrid.ColumnDefinitions[3].Width = new GridLength(0);
					SignalEntryGrid.ColumnDefinitions[3].MinWidth = 0;
					SignalEntryGrid.ColumnDefinitions[4].Width = new GridLength(0);
				}
				else
				{
					RestoreAndRestyle(OffsetBox15);
					SignalEntryGrid.ColumnDefinitions[3].Width = new GridLength(48);
					SignalEntryGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
				}
			}

			// ATM buttons — abbreviate "ATM" to "A" based on panel width so all 4 switch together
			bool atmUseShort = pChartTraderWidth < 139;
			if (ATMButton1 != null && ATMButton1.Content != null) { string ac1 = ATMButton1.Content.ToString(); if (ac1 == "ATM" || ac1 == "A") ATMButton1.Content = atmUseShort ? "A" : "ATM"; }
			if (ATMButton2 != null && ATMButton2.Content != null) { string ac2 = ATMButton2.Content.ToString(); if (ac2 == "ATM" || ac2 == "A") ATMButton2.Content = atmUseShort ? "A" : "ATM"; }
			if (ATMButton3 != null && ATMButton3.Content != null) { string ac3 = ATMButton3.Content.ToString(); if (ac3 == "ATM" || ac3 == "A") ATMButton3.Content = atmUseShort ? "A" : "ATM"; }
			if (ATMButton4 != null && ATMButton4.Content != null) { string ac4 = ATMButton4.Content.ToString(); if (ac4 == "ATM" || ac4 == "A") ATMButton4.Content = atmUseShort ? "A" : "ATM"; }

			// TrailingStopGrid (Trailing Stop): collapse spinner when narrow, expand when wide
			if (OffsetBox10 != null && TrailingStopGrid != null && TrailingStopGrid.ColumnDefinitions.Count > 2)
			{
				if (pChartTraderWidth < 140)
				{
					OffsetBox10.Visibility = System.Windows.Visibility.Collapsed;
					TrailingStopGrid.ColumnDefinitions[1].Width = new GridLength(0);
					TrailingStopGrid.ColumnDefinitions[2].Width = new GridLength(0);
					TrailingStopGrid.ColumnDefinitions[2].MinWidth = 0;
				}
				else
				{
					RestoreAndRestyle(OffsetBox10);
					TrailingStopGrid.ColumnDefinitions[1].Width = new GridLength(smallGapH);
					TrailingStopGrid.ColumnDefinitions[2].Width = new GridLength(1, GridUnitType.Star);
					TrailingStopGrid.ColumnDefinitions[2].MinWidth = 38;
				}
			}

			// QtyTIFGrid: collapse TIF/contract type when panel is narrow, qty fills full width
			// Columns: [0:qty Star][1:gap 5][2:TIF fixed]
			if (QtyTIFGrid != null && QtyTIFGrid.ColumnDefinitions.Count >= 3)
			{
				if (pChartTraderWidth < 135)
				{
					if (tifSelector1 != null) tifSelector1.Visibility = System.Windows.Visibility.Collapsed;
					if (ctype != null) ctype.Visibility = System.Windows.Visibility.Collapsed;
					QtyTIFGrid.ColumnDefinitions[1].Width = new GridLength(0);
					QtyTIFGrid.ColumnDefinitions[2].Width = new GridLength(0);
				}
				else
				{
					if (tifSelector1 != null) RestoreAndRestyle(tifSelector1);
					if (ctype != null) ctype.Visibility = System.Windows.Visibility.Visible;
					QtyTIFGrid.ColumnDefinitions[1].Width = new GridLength(smallGapH);
					QtyTIFGrid.ColumnDefinitions[2].Width = new GridLength(widetif);
				}
			}

			// QtyTIFGrid2 (Iceberg): same collapse behavior
			if (QtyTIFGrid2 != null && QtyTIFGrid2.ColumnDefinitions.Count >= 3)
			{
				if (pChartTraderWidth < 140)
				{
					if (tifSelector2 != null) tifSelector2.Visibility = System.Windows.Visibility.Collapsed;
					QtyTIFGrid2.ColumnDefinitions[1].Width = new GridLength(0);
					QtyTIFGrid2.ColumnDefinitions[2].Width = new GridLength(0);
				}
				else
				{
					if (tifSelector2 != null) RestoreAndRestyle(tifSelector2);
					QtyTIFGrid2.ColumnDefinitions[1].Width = new GridLength(smallGapH);
					QtyTIFGrid2.ColumnDefinitions[2].Width = new GridLength(58);
				}
			}

			// IcebergQtyVarianceGrid (Iceberg qty/variance row): collapse variance spinner + % label when narrow
			// Cols: [0:spacer][1:qty Star][2:gap][3:variance 48][4:gap][5:% label 20]
			if (IcebergQtyVarianceGrid != null && IcebergQtyVarianceGrid.ColumnDefinitions.Count >= 6)
			{
				if (pChartTraderWidth < 140)
				{
					if (OffsetBox7 != null) OffsetBox7.Visibility = System.Windows.Visibility.Collapsed;
					if (label2 != null) label2.Visibility = System.Windows.Visibility.Collapsed;
					IcebergQtyVarianceGrid.ColumnDefinitions[2].Width = new GridLength(0);
					IcebergQtyVarianceGrid.ColumnDefinitions[3].Width = new GridLength(0);
					IcebergQtyVarianceGrid.ColumnDefinitions[4].Width = new GridLength(0);
					IcebergQtyVarianceGrid.ColumnDefinitions[5].Width = new GridLength(0);
				}
				else
				{
					if (OffsetBox7 != null) RestoreAndRestyle(OffsetBox7);
					if (label2 != null) label2.Visibility = System.Windows.Visibility.Visible;
					IcebergQtyVarianceGrid.ColumnDefinitions[2].Width = new GridLength(smallGapH);
					IcebergQtyVarianceGrid.ColumnDefinitions[3].Width = new GridLength(48);
					IcebergQtyVarianceGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
					IcebergQtyVarianceGrid.ColumnDefinitions[5].Width = new GridLength(20);
				}
			}

			// IcebergOrderTypeGrid (Iceberg order type): smart collapse of T button and offset spinner
			// Cols: [0:spacer][1:dropdown 62][2:gap][3:T btn 21][4:gap][5:spinner 41][6:gap][7:IPA Star min34]
			//
			// Collapse priority as panel narrows: spinner first, then T button, then IPA
			// is allowed to shrink. The thresholds here are tuned so IPA's MinWidth (34)
			// is never violated at the "show everything" tier — otherwise WPF would
			// overflow or clip the IPA label.
			//
			// Width math (with default smallGapH=3, dropdown=62, T=21, spinner=41, IPA min=34):
			//   All visible:    62 + 3 + 21 + 3 + 41 + 3 + 34 = 167  → need panel inner ≥ 167 → panel ≥ ~178
			//   No spinner:     62 + 3 + 21 + 3 + 34           = 123  → panel ≥ ~134
			//   No T + no spin: 62 + 3 + 34                    =  99  → panel ≥ ~110
			if (IcebergOrderTypeGrid != null && IcebergOrderTypeGrid.ColumnDefinitions.Count > 7)
			{
				bool isMarketMode = pIcebergEntryMode == "Market";
				bool tOff = !pIcebergOffsetTrailing;
				int smallGapW = smallGapH;

				if (isMarketMode)
				{
					// Market mode: T and offset are irrelevant — collapse both
					if (toggle5 != null) toggle5.Visibility = System.Windows.Visibility.Collapsed;
					if (OffsetBox2 != null) OffsetBox2.Visibility = System.Windows.Visibility.Collapsed;
					IcebergOrderTypeGrid.ColumnDefinitions[1].Width = new GridLength(62);
					IcebergOrderTypeGrid.ColumnDefinitions[2].Width = new GridLength(smallGapW); // gap between dropdown and IPA
					IcebergOrderTypeGrid.ColumnDefinitions[3].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[4].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[5].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[6].Width = new GridLength(0);
				}
				else if (pChartTraderWidth < 135)
				{
					// Very narrow: collapse both T and offset spinner
					if (toggle5 != null) toggle5.Visibility = System.Windows.Visibility.Collapsed;
					if (OffsetBox2 != null) OffsetBox2.Visibility = System.Windows.Visibility.Collapsed;
					IcebergOrderTypeGrid.ColumnDefinitions[1].Width = new GridLength(62);
					IcebergOrderTypeGrid.ColumnDefinitions[2].Width = new GridLength(smallGapW);
					IcebergOrderTypeGrid.ColumnDefinitions[3].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[4].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[5].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[6].Width = new GridLength(0);
				}
				else if (pChartTraderWidth < 180 || tOff)
				{
					// Narrow or T off: collapse offset spinner, keep T visible
					if (toggle5 != null) toggle5.Visibility = System.Windows.Visibility.Visible;
					if (OffsetBox2 != null) OffsetBox2.Visibility = System.Windows.Visibility.Collapsed;
					IcebergOrderTypeGrid.ColumnDefinitions[1].Width = new GridLength(62);
					IcebergOrderTypeGrid.ColumnDefinitions[2].Width = new GridLength(smallGapW);
					IcebergOrderTypeGrid.ColumnDefinitions[3].Width = new GridLength(21);
					IcebergOrderTypeGrid.ColumnDefinitions[4].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[5].Width = new GridLength(0);
					IcebergOrderTypeGrid.ColumnDefinitions[6].Width = new GridLength(smallGapW);
				}
				else
				{
					// Wide enough: show everything
					if (toggle5 != null) toggle5.Visibility = System.Windows.Visibility.Visible;
					if (OffsetBox2 != null) RestoreAndRestyle(OffsetBox2);
					IcebergOrderTypeGrid.ColumnDefinitions[1].Width = new GridLength(62);
					IcebergOrderTypeGrid.ColumnDefinitions[2].Width = new GridLength(smallGapW);
					IcebergOrderTypeGrid.ColumnDefinitions[6].Width = new GridLength(smallGapW);
					IcebergOrderTypeGrid.ColumnDefinitions[3].Width = new GridLength(21);
					IcebergOrderTypeGrid.ColumnDefinitions[4].Width = new GridLength(smallGapW);
					IcebergOrderTypeGrid.ColumnDefinitions[5].Width = new GridLength(41);
				}
			}

			// TimeSlicedIntervalGrid (Time Sliced interval): collapse variance spinner when narrow
			// Cols: [0:spacer][1:interval Star][2:gap][3:STOP btn][4:gap][5:variance 48][6:gap][7:% label]
			if (OffsetBox9 != null && TimeSlicedIntervalGrid != null && TimeSlicedIntervalGrid.ColumnDefinitions.Count > 7)
			{
				if (pChartTraderWidth < 160)
				{
					OffsetBox9.Visibility = System.Windows.Visibility.Collapsed;
					TimeSlicedIntervalGrid.ColumnDefinitions[4].Width = new GridLength(0);
					TimeSlicedIntervalGrid.ColumnDefinitions[5].Width = new GridLength(0);
					TimeSlicedIntervalGrid.ColumnDefinitions[6].Width = new GridLength(0);
					TimeSlicedIntervalGrid.ColumnDefinitions[7].Width = new GridLength(0);
				}
				else
				{
					RestoreAndRestyle(OffsetBox9);
					TimeSlicedIntervalGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
					TimeSlicedIntervalGrid.ColumnDefinitions[5].Width = new GridLength(48);
					TimeSlicedIntervalGrid.ColumnDefinitions[6].Width = new GridLength(smallGapH);
					TimeSlicedIntervalGrid.ColumnDefinitions[7].Width = new GridLength(20);
				}
			}

			// TimeSlicedPriceGrid (Time Sliced price): collapse offset spinner when narrow
			// Cols: [0:spacer][1:dropdown Star][2:gap][3:BO PB btn][4:gap][5:offset 42][6:gap][7:T btn 22]
			if (OffsetBox11 != null && TimeSlicedPriceGrid != null && TimeSlicedPriceGrid.ColumnDefinitions.Count > 7)
			{
				if (pChartTraderWidth < 155)
				{
					OffsetBox11.Visibility = System.Windows.Visibility.Collapsed;
					TimeSlicedPriceGrid.ColumnDefinitions[4].Width = new GridLength(0);
					TimeSlicedPriceGrid.ColumnDefinitions[5].Width = new GridLength(0);
				}
				else
				{
					RestoreAndRestyle(OffsetBox11);
					TimeSlicedPriceGrid.ColumnDefinitions[4].Width = new GridLength(smallGapH);
					TimeSlicedPriceGrid.ColumnDefinitions[5].Width = new GridLength(42);
				}
			}

			// ClickEntryGrid (Click Entry): collapse OCO button when very narrow
			// Cols when OCO enabled: [0:spacer][1:MIT Star][2:gap][3:SLM Star][4:gap][5:spinner 48][6:gap][7:OCO Star]
			if (button28 != null && ClickEntryGrid != null && ClickEntryGrid.ColumnDefinitions.Count > 7)
			{
				if (pChartTraderWidth < 120)
				{
					button28.Visibility = System.Windows.Visibility.Collapsed;
					ClickEntryGrid.ColumnDefinitions[6].Width = new GridLength(0);
					ClickEntryGrid.ColumnDefinitions[7].Width = new GridLength(0);
				}
				else
				{
					button28.Visibility = System.Windows.Visibility.Visible;
					ClickEntryGrid.ColumnDefinitions[6].Width = new GridLength(smallGapH);
					ClickEntryGrid.ColumnDefinitions[7].Width = new GridLength(1, GridUnitType.Star);
				}
			}

			// StopEntryGrid (Price Based Entry Orders): responsive collapse
			// Cols: [0:spacer][1:OffsetBox14 Star][2:gap][3:button32 OCO Star][4:gap][5:button31 STP/SLM Star][6:gap][7:OffsetBox13 SL offset Star]
			// STP mode: offset always hidden. SLM mode: OCO hides first, then offset.
			if (StopEntryGrid != null && StopEntryGrid.ColumnDefinitions.Count > 7)
			{
				int panelInner = pChartTraderWidth - 6;
				bool showOCO = true;
				bool showOffset = pUseSLMStopEntry;

				if (pUseSLMStopEntry)
				{
					// SLM: need room for 4 Star cols (offset+oco+stp+ticks) + 3 gaps
					int neededAll = 4 * 41 + 3 * pControlGap;
					// need room for 3 Star cols (offset+stp+ticks) + 2 gaps (no OCO)
					int neededNoOCO = 3 * 41 + 2 * pControlGap;

					if (panelInner < neededNoOCO)
					{
						// Very narrow: hide both OCO and offset
						showOCO = false;
						showOffset = false;
					}
					else if (panelInner < neededAll)
					{
						// Medium: hide OCO first, keep offset
						showOCO = false;
					}
				}
				else
				{
					// STP: offset always hidden, decide OCO
					int neededOCO = 3 * 41 + 2 * pControlGap;
					if (panelInner < neededOCO)
						showOCO = false;
				}

				// Apply SL offset (col 7)
				if (!showOffset)
				{
					if (OffsetBox13 != null) OffsetBox13.Visibility = System.Windows.Visibility.Collapsed;
					StopEntryGrid.ColumnDefinitions[6].Width = new GridLength(0);
					StopEntryGrid.ColumnDefinitions[7].Width = new GridLength(0);
					StopEntryGrid.ColumnDefinitions[7].MinWidth = 0;
					StopEntryGrid.ColumnDefinitions[7].MaxWidth = double.PositiveInfinity;
				}
				else
				{
					if (OffsetBox13 != null) RestoreAndRestyle(OffsetBox13);
					StopEntryGrid.ColumnDefinitions[6].Width = new GridLength(smallGapH);
					StopEntryGrid.ColumnDefinitions[7].Width = new GridLength(1, GridUnitType.Star);
					StopEntryGrid.ColumnDefinitions[7].MinWidth = 38;
					StopEntryGrid.ColumnDefinitions[7].MaxWidth = 48;
				}

				// Apply OCO button (col 3)
				if (button32 != null)
				{
					if (!showOCO)
					{
						button32.Visibility = System.Windows.Visibility.Collapsed;
						StopEntryGrid.ColumnDefinitions[2].Width = new GridLength(0);
						StopEntryGrid.ColumnDefinitions[3].Width = new GridLength(0);
					}
					else
					{
						button32.Visibility = System.Windows.Visibility.Visible;
						StopEntryGrid.ColumnDefinitions[2].Width = new GridLength(smallGapH);
						StopEntryGrid.ColumnDefinitions[3].Width = new GridLength(1, GridUnitType.Star);
					}
				}
			}
		}

		/// <summary>
		/// Single source of truth for Order Panel Display defaults.
		/// To change a default: update it HERE. Field initializers are overwritten by SetDefaults.
		/// </summary>
		private void ResetOrderPanelDisplayDefaults()
		{
			// Resets every property in the Order Panel Display input section plus the panel's
			// persisted UI state (section expand/collapse, scroll position). Does NOT reset
			// Quantity, Account, Panel Enabled, or Orders Enabled — those are user trading
			// state, not cosmetic.
			pChartTraderWidth = 200;
			pCollapsibleSectionsEnabled = true;
			pCollapseAllButtonEnabled = true;
			pButtonHeight = 28;
			pPrimaryControlHeight = 26;
			pSecondaryControlHeight = 21;
			pSectionSpacing = 2;
			pControlGap = 3;
			pHeaderSpacing = 5;
			pPrimaryFontSize = 14;
			pButtonFontSize = 12;
			pHeaderFontSize = 11;
			pPanelFontFamily = "";
			pMarketDataFontSize = 12;
			pAllowKeyboardQtyEntry = true;
			pColorBuyEMA2 = FrozenRgbBrush(0, 80, 0);
			pColorBuyEMA = Brushes.Lime;
			pColorSellEMA2 = FrozenRgbBrush(80, 0, 0);
			pColorSellEMA = Brushes.Red;
			pColorNeutralEMA2 = Brushes.DimGray;
			pColorNeutralEMA = Brushes.White;
			pColorButtonReverse = FrozenRgbBrush(70, 50, 20);
			pColorButtonCloseAll = FrozenRgbBrush(70, 50, 20);
			pColorButtonMoveAllExits = FrozenRgbBrush(70, 50, 20);
			pColorButtonOrderType = FrozenRgbBrush(40, 40, 40);
			pColorButtonOrderType4 = FrozenRgbBrush(70, 50, 20);
			pSpaceBetweenGroups = 20;
			pSimBackColor = FrozenRgbBrush(20, 40, 60);
			pLiveBackColor = Brushes.Transparent;

			// Clear persisted UI state so the panel rebuilds with default section layout.
			// The in-memory dictionary also needs to be cleared — LoadSectionStates is a no-op
			// when the persisted string is empty, so the dict would otherwise keep stale entries
			// from the previous session.
			pSavedSectionStates = "";
			pSavedScrollPosition = 0;
			if (sectionExpandedStates != null) sectionExpandedStates.Clear();
		}

