			pThisSummaryTypeMode = "None";
			pThisSummaryExitOrderMode = "Points";
			pOrderSummaryColor = Brushes.LightGray;
			pAttachButtonsHoverEnabled = true;
			pAtmNameButtonEnabled = true;
