			pOrderFlagRounding = 6;
			pScaleByOrders = false;
		}

		private void RemoveWPFOrderControls()
		{
			if (!panelActive)
				return;

			// Save section states before removing
			SaveSectionStates();

			// Find the outer panel (parent of resize handle) to remove from chart grid
			System.Windows.UIElement panelToRemove = panelOuterGrid;
			if (panelToRemove == null)
			{
				if (panelResizeHandle != null && panelResizeHandle.Parent != null)
					panelToRemove = panelResizeHandle.Parent as System.Windows.UIElement;
				else if (panelScrollViewer != null)
					panelToRemove = panelScrollViewer;
				else
					panelToRemove = buttonGrid;
			}

			int removeCol = System.Windows.Controls.Grid.GetColumn(panelToRemove);

			chartGrid.ColumnDefinitions.RemoveAt(removeCol);
			chartGrid.Children.Remove(panelToRemove);

			// Shift columns left
			for (int i = 0; i < chartGrid.Children.Count; i++)
				if (System.Windows.Controls.Grid.GetColumn(chartGrid.Children[i]) > 0 && System.Windows.Controls.Grid.GetColumn(chartGrid.Children[i]) > removeCol)
					System.Windows.Controls.Grid.SetColumn(chartGrid.Children[i], System.Windows.Controls.Grid.GetColumn(chartGrid.Children[i]) - 1);

			// NOTE: panelOuterGrid / panelDockPanel / panelScrollViewer / panelResizeHandle are
			// intentionally kept alive so the next InsertWPFOrderControls can reuse them via the
			// fast-path. All event handlers and the dark scrollbar style remain attached to the
			// preserved instances. Final teardown happens in DisposeWPFOrderControls.

			panelActive = false;
		}

		private bool TabSelected()
		{
			bool tabSelected = false;

			// loop through each tab and see if the tab this indicator is added to is the selected item
			foreach (System.Windows.Controls.TabItem tab in chartWindow.MainTabControl.Items)
				if ((tab.Content as ChartTab).ChartControl == ChartControl && tab == chartWindow.MainTabControl.SelectedItem)
					tabSelected = true;

			return tabSelected;
		}

		private void TabChangedHandler(object sender, System.Windows.Controls.SelectionChangedEventArgs e)
		{
			if (e.AddedItems.Count <= 0)
				return;

			tabItem = e.AddedItems[0] as System.Windows.Controls.TabItem;
			if (tabItem == null)
				return;

			chartTab = tabItem.Content as NinjaTrader.Gui.Chart.ChartTab;
			if (chartTab == null)
				return;

			if (TabSelected() && pOrderPanelOn)
				InsertWPFOrderControls();
			else
				RemoveWPFOrderControls();
		}
		
		
		
