		private int TotalPlansShowing()
		{
			// Hoist DateTime.Now (it allocates internally), drop the unneeded
			// .ToList() snapshot (no mutation inside the loop), and break on
			// first match -- we only need a boolean "any in future" result.
			DateTime nowSnap = DateTime.Now;
			foreach (KeyValuePair<double, DateTime> KKK in OrderPriceToATMDisplayEnd)
			{
				if (KKK.Value > nowSnap) return 1;
			}
			return 0;
											
		}
					
							
							
							
