		private string LimitDisplay2(string dir, int offset)
		{
		
			offset = offset*-1;
			
			if (dir == "Sell")
				offset = offset*-1;
			
			if (offset == 0) return "";
			
			if (offset > 0) return " +"+offset.ToString();
			if (offset < 0) return " "+offset.ToString();
			
			return "";
		}
		
		
		private string LimitDisplay(string dir, string type)
		{
		
			if (type == "Ask") return "Ask";
			if (type == "Bid") return "Bid";
			
			if (dir == "Buy")
			{
				if (type == "Offer") return "Ask";
				if (type == "Spread") return "Bid";
				
			}
			if (dir == "Sell")
			{
				if (type == "Offer") return "Bid";
				if (type == "Spread") return "Ask";
				
			}
			return "";
		}
 
		private bool IsActiveATM()
		{
			
			for (int i = 1; i <=20; i++)
			{
				string ss = " - " + i.ToString();
				if (chartTraderATM.SelectedAtmStrategy.DisplayName.EndsWith(ss))
					return true;				
			}
			
			return false;
			

			
		}
		
			    public static string sep(string s)
		    {
		        int l = s.IndexOf(" -");
		        if (l >0)
		        {
		            return s.Substring(0, l);
		        }
		        return "";

		    }
			
	
			
			
       private void UnattachAllStops()
		{
		
			foreach (Order or in myAccount.Orders)
			{
				
						OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
						OrderTypeOK = or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.StopMarket;
						OrderNameOK = or.Name == "Stop1" ||  or.Name == "Stop2" ||  or.Name == "Stop3";
						OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				OrderNameOK = IsStop(or.Name);
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
						
					ClearTrackedOrders(or);
				}
				
			}
			
					

		}
		
		
		
			
        private void UnattachAll()
		{
		
			foreach (Order or in myAccount.Orders)
			{
				
						OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
						OrderTypeOK = or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.StopMarket;
						OrderNameOK = or.Name == "Stop1" ||  or.Name == "Stop2" ||  or.Name == "Stop3";
						OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				OrderNameOK = IsStop(or.Name);
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
						
				

					
					
					
					if (!or.IsTrackingEnabled)
					{
					//	Print(or.TrackingIndicator.ToString());
						or.TrackingIndicator = EMA(1000);
						//or.tr
						or.IsTrackingConfigured = true;
						or.IsTrackingEnabled = true;
						
					
						
					}
					
					//Print(or.BacktestPassNumber);
					
					//Print(instruction);
				
					
					//Print(or.Name);
				}
				
			}
			
					

		}
		
		
		
