		private string GetLastDrawingObjectString()
		{
			
			string finds = string.Empty;

			
			string LongObjectName = "";
			string ShortObjectName = "";
	
			if (pChartMarkerType == "Arrow")
			{
				LongObjectName = "ArrowUp";
				ShortObjectName = "ArrowDown";				
			}
			else if (pChartMarkerType == "Triangle")
			{
				LongObjectName = "TriangleUp";
				ShortObjectName = "TriangleDown";
				
			}
			else
			{
				LongObjectName = pChartMarkerType;
				ShortObjectName = pChartMarkerType;
			}
			
						
				
				
				
				
				
			foreach (DrawingTool draw in DrawObjects.Reverse().ToList())	
            {			
//				if (ThisTypeName != "ArrowUp" && ThisTypeName != "ArrowDown" && ThisTypeName != "Dot" && ThisTypeName != "Diamond" && ThisTypeName != "Square" && ThisTypeName != "ArrowUp" && ThisTypeName != "ArrowDown")
//					continue;
				
				string ThisTypeName = draw.GetType().Name;
				
				if (ThisTypeName != LongObjectName && ThisTypeName != ShortObjectName)
					continue;			
				if (draw.IsUserDrawn)
					continue;
				
				finds = draw.Tag;
				
				return finds;
				
			}
			
			return finds;
			
		}
		
