// Add these class-level fields:
private Dictionary<string, string> plotNameCache = new Dictionary<string, string>();
private bool cacheBuilt = false;
private int lastIndicatorCount = 0;

private void BuildPlotNameCache()
{
    plotNameCache.Clear();
    
    int b = 0;
    foreach (IndicatorBase ii in ChartControl.Indicators)
    {
        // Skip unwanted indicators
        if (ii.Description.Contains("Key Levels Confluence") || 
            ii.Description.Contains("Price Action Confluence"))
            continue;
            
        if (ii.Panel >= 0 && ii.Panel != ChartBars.Panel)
            continue;
            
        if (ii.Plots.Length == 0 || ii.State != State.Realtime)
            continue;
        
        // Cache reflection results once per indicator
        string indicatorName = ii.Name;
        string periodString = string.Empty;
        string extraString = string.Empty;
        
        // Get Period and other properties via reflection (once)
        PropertyInfo[] properties = ii.GetType().GetProperties();
        foreach (PropertyInfo info in properties)
        {
            if (info.Name == "Period")
            {
                object obj = info.GetValue(ii, null);
                periodString = obj?.ToString() ?? string.Empty;
            }
            else if (indicatorName == "Bollinger" && info.Name == "NumStdDev")
            {
                object obj = info.GetValue(ii, null);
                extraString = obj?.ToString() ?? string.Empty;
            }
        }
        
        // Detect secondary data series and get its description
        string dataSeriesSuffix = string.Empty;
        try
        {
            bool isSecondary = (ii.Values.Length > 0 && ii.Values[0].Count > 0 && ii.Values[0].Count < ThisCB * 0.8);
            if (isSecondary && ii.BarsArray != null && ii.BarsArray.Length > 0 && ii.BarsArray[0] != null)
            {
                dataSeriesSuffix = " (" + ii.BarsArray[0].BarsPeriod.ToString() + ")";
                dataSeriesSuffix = dataSeriesSuffix.Replace("Minute", "Min");
                dataSeriesSuffix = dataSeriesSuffix.Replace("Second", "Sec");
                dataSeriesSuffix = dataSeriesSuffix.Replace("Volume", "Vol");
            }
        }
        catch { }

        // Cache all plots for this indicator
        int a = 0;
        foreach (Plot pp in ii.Plots)
        {
            if (pp.Name.Contains("IgnorePlot"))
                continue;

            string cacheKey = $"{b}_{a}";
            string plotName = BuildPlotName(pp.Name, indicatorName, periodString, extraString, false) + dataSeriesSuffix;
            plotNameCache[cacheKey] = plotName;

            string cacheKeyExtended = $"{b}_{a}_ext";
            string plotNameExtended = BuildPlotName(pp.Name, indicatorName, periodString, extraString, true) + dataSeriesSuffix;
            plotNameCache[cacheKeyExtended] = plotNameExtended;

            a++;
        }
        
        b++;
    }
    
    cacheBuilt = true;
    lastIndicatorCount = ChartControl.Indicators.Count;
}

private string BuildPlotName(string plotName, string indicatorName, string periodString, string extraString, bool extended)
{
    string finalPlotName = plotName;
    
    // Handle Bollinger bands
    if (indicatorName == "Bollinger")
    {
        if (!extended)
        {
            periodString = string.Empty;
        }
        else
        {
            string finalInputs = periodString + "," + extraString;
            finalPlotName = "BB(" + finalInputs + ") " + plotName;
        }
    }
    
    // Add period if available
    if (!string.IsNullOrEmpty(periodString) && !finalPlotName.Contains("BB("))
    {
        finalPlotName = periodString + " " + plotName;
    }
    
    // Remove ThisPName if present
    if (finalPlotName.Contains(ThisPName))
    {
        finalPlotName = finalPlotName.Replace(ThisPName, "");
    }
    
    // Replace special plot names
    string atrName = "ATR x " + pATRMultiplier.ToString();
    string ftName = "Fixed (" + pFixedTicks.ToString() + " Ticks)";
    
    finalPlotName = finalPlotName.Replace("ATR LongPlot", atrName)
                                 .Replace("ATR ShortPlot", atrName)
                                 .Replace("Fixed Tick LongPlot", ftName)
                                 .Replace("Fixed Tick ShortPlot", ftName);
    
    return finalPlotName;
}

private string GetThisPlotName(int inn, int plotnumber, bool extended)
{
    // Rebuild cache if indicators changed
    if (!cacheBuilt || ChartControl.Indicators.Count != lastIndicatorCount)
    {
        BuildPlotNameCache();
    }
    
    if (inn == -1 || plotnumber == -1)
        return string.Empty;
    
    // Lookup from cache
    string cacheKey = extended ? $"{inn}_{plotnumber}_ext" : $"{inn}_{plotnumber}";
    
    if (plotNameCache.TryGetValue(cacheKey, out string result))
    {
        return result;
    }
    
    return string.Empty;
}				
	
		
		
		
	
		private int CountVisiblePlots(int indicatorIndex)
		{
			int b = 0;
			int visiblePlots = 0;
			foreach (IndicatorBase ii in ChartControl.Indicators)
			{
				if (ii.Description.Contains("Key Levels Confluence")) continue;
				if (ii.Description.Contains("Price Action Confluence")) continue;
				if (ii.Panel >= 0 && ii.Panel != ChartBars.Panel) continue;
				if (ii.Plots.Length == 0) continue;
				if (ii.State != State.Realtime) continue;

				if (b == indicatorIndex)
				{
					foreach (Plot pp in ii.Plots)
					{
						if (!pp.Name.Contains("IgnorePlot") && !pp.Name.Contains(ThisPName))
							visiblePlots++;
					}
					return visiblePlots;
				}
				b++;
			}
			return 0;
		}

		// Safely read a plot value, handling both primary and secondary data series indicators
		// For primary series indicators: barIndex maps directly to Values[plotIndex]
		// For secondary series indicators: Values count differs from primary bars,
		//   so we clamp to the indicator's own bar count and search for valid data
		private double SafeGetPlotValue(IndicatorBase ii, int plotIndex, int barIndex)
		{
			try
			{
				if (ii == null || plotIndex < 0 || plotIndex >= ii.Values.Length)
					return double.MinValue;

				ISeries<double> vals = ii.Values[plotIndex];
				int count = vals.Count;

				if (count == 0)
					return double.MinValue;

				// Clamp to valid range
				int idx = Math.Min(barIndex, count - 1);
				if (idx < 0) idx = 0;

				// Try direct read
				double v = vals.GetValueAt(idx);
				if (!double.IsNaN(v))
					return v;

				// If NaN, search backwards for valid value
				for (int back = 1; back <= 200 && (idx - back) >= 0; back++)
				{
					v = vals.GetValueAt(idx - back);
					if (!double.IsNaN(v))
						return v;
				}

				return double.MinValue;
			}
			catch
			{
				return double.MinValue;
			}
		}

		// Get plot value for an indicator that may be on a secondary data series,
		// using a time-based lookup instead of bar index
		private double SafeGetPlotValueByTime(IndicatorBase ii, int plotIndex, DateTime barTime)
		{
			try
			{
				if (ii == null || plotIndex < 0 || plotIndex >= ii.Values.Length)
					return double.MinValue;

				ISeries<double> vals = ii.Values[plotIndex];
				int count = vals.Count;

				if (count == 0)
					return double.MinValue;

				// For indicators with their own BarsArray, find the bar at or before barTime
				if (ii.BarsArray != null && ii.BarsArray.Length > 0 && ii.BarsArray[0] != null)
				{
					Bars indBars = ii.BarsArray[0];
					int barCount = indBars.Count;

					if (barCount == 0)
						return double.MinValue;

					// Search from the end backwards to find the bar at or just before barTime
					int foundIdx = -1;
					int searchStart = Math.Min(count - 1, barCount - 1);

					for (int i = searchStart; i >= 0 && i >= searchStart - 500; i--)
					{
						try
						{
							DateTime t = indBars.GetTime(i);
							if (t <= barTime)
							{
								foundIdx = i;
								break;
							}
						}
						catch { continue; }
					}

					if (foundIdx >= 0 && foundIdx < count)
					{
						// Search from foundIdx backwards for a non-zero, non-NaN value
						for (int si = foundIdx; si >= 0 && si >= foundIdx - 50; si--)
						{
							if (si < count)
							{
								double v = vals.GetValueAt(si);
								if (!double.IsNaN(v) && v != 0)
									return v;
							}
						}
					}
				}

				// Fallback: search backwards from end for non-zero, non-NaN value
				for (int i = count - 1; i >= 0 && i >= count - 200; i--)
				{
					double v = vals.GetValueAt(i);
					if (!double.IsNaN(v) && v != 0)
						return v;
				}

				return double.MinValue;
			}
			catch
			{
				return double.MinValue;
			}
		}

