		private int NumberOfActiveStrategies ()
		{
			if (atmStrategySelector == null)
				return 0;

			// Cached result is valid as long as Items.Count hasn't changed. The Items.Count
			// check is O(1) and acts as a lightweight invalidation key — when NT rebuilds the
			// items list (account changed, server-side ATMs arrived, etc.), Count changes and
			// we recompute. Keeps this off the hot path for the 16 callers that hit it
			// repeatedly during render and order updates.
			int curCount = atmStrategySelector.Items.Count;
			if (cachedNumberOfActiveStrategies >= 0 && cachedNumberOfActiveStrategiesItemsCount == curCount)
				return cachedNumberOfActiveStrategies;

			int iio = 0;
			int result = 0;
			foreach (object aaa in atmStrategySelector.Items)
			{
				AtmStrategy FinalATMStrategy = null;
				try { FinalATMStrategy = (AtmStrategy) aaa; }
				catch (Exception) { }

				if (FinalATMStrategy != null && TheFirstATM == FinalATMStrategy.DisplayName)
				{
					result = iio - 4;
					break;
				}
				iio++;
			}

			cachedNumberOfActiveStrategies = result;
			cachedNumberOfActiveStrategiesItemsCount = curCount;
			return result;
		}
	
