//														{		
//															if (tr2.IsTrailMode)
//															{
//																tr2.IsTrailMode = false;
//																// watch for next change and change back to true
																
//																if (!SetTrailModeTrueOnAccepted.Contains(o))
//																SetTrailModeTrueOnAccepted.Add(o);
																
																
																
//															}
//														}
															
														
													}
													if (action == "+-")
													{
														
														if (o.IsLong)
															newoffset = pTrailingStopOffset*1;
														if (o.IsShort)
															newoffset = pTrailingStopOffset*-1;
														
														tr2.OffsetTicks = newoffset;
														
															if (pTrailingStopIsEnabled && pTrailingStopType == "Fixed Tick")
																tr2.OffsetTicks = 0;
															
//														if (inn == ThisIndicatorSequence && pn == 0)  // previous bar low
//															newoffset = tr2.OffsetTicks + 1;
														
//														if (inn == ThisIndicatorSequence && pn == 1)  // previous bar high
//															newoffset = tr2.OffsetTicks - 1;
														
//														tr2.OffsetTicks = newoffset;	
														
//														if (AllowMoveDown)
//														{		
															if (tr2.IsTrailMode)
															{
																tr2.IsTrailMode = false;
																// watch for next change and change back to true
																
																if (!SetTrailModeTrueOnAccepted.Contains(o))
																SetTrailModeTrueOnAccepted.Add(o);
																
																
																
															}
//														}
															
														
													}													
													
													
													
													
													if (action == "IsTrailMode")
													{
														if (tr2.IsTrailMode)
														{
															tr2.IsTrailMode = false;
															
														}
														else
														{
															tr2.IsTrailMode = true;
														}

													}
											
													
													if (action == "Change Plot")
													{
														
														
														
														tr2.Plot = pn;
														
														if (tr2.IsTrailMode)
														{
															tr2.IsTrailMode = false;
															// watch for next change and change back to true
															
															if (!SetTrailModeTrueOnAccepted.Contains(o))
															SetTrailModeTrueOnAccepted.Add(o);
														}
													}
													
													
												}
												
											}
											
											
											// new tracked order 
											
											TrackedOrder tr3 = new TrackedOrder();
											if (!trexists)
											{
												
//				                                tr3.OffsetTicks = pTrailingStopOffset;
												
//												if (o.IsShort)
//												tr3.OffsetTicks = -1*pTrailingStopOffset;	
												
												
												
												o.TrackingIndicator = ii;
												
												tr3.Order = o;
												
												
												int finalattachment = pAttachDefaultOffset;
												
												if (NextOffset != -1)
												{
													
													finalattachment = NextOffset;
													NextOffset = -1;
													
												}
												
											
												
												if (o.IsLong)
													tr3.OffsetTicks = finalattachment;
												if (o.IsShort)
													tr3.OffsetTicks = finalattachment*-1;
										
												if (inn == ThisIndicatorSequence && pn == 0) // previous bar low
													tr3.OffsetTicks = finalattachment*-1;
												
												if (inn == ThisIndicatorSequence && pn == 1) // previous bar high
													tr3.OffsetTicks = finalattachment;
														
												
												if (IsStopLoss && pAdvancedExitOrdersManagementEnabled)
												{
													
													if (o.IsLong)
														tr3.OffsetTicks = pTrailingStopOffset*1;
													if (o.IsShort)
														tr3.OffsetTicks = pTrailingStopOffset*-1;
														
															if (pTrailingStopIsEnabled && pTrailingStopType == "Fixed Tick")
																tr3.OffsetTicks = 0;															
												}
												
												
												
												
												if (pAttachDefaultMode == "Track")
				                                	tr3.IsTrailMode = false;
												else
													tr3.IsTrailMode = true;
												
												if (IsStopLoss)
													tr3.IsTrailMode = true;
												
													if (action == "Change Plot")
														if (tr3.IsTrailMode)
														{
															tr3.IsTrailMode = false;
															// watch for next change and change back to true
															
															if (!SetTrailModeTrueOnAccepted.Contains(o))
															SetTrailModeTrueOnAccepted.Add(o);
														}
														
												//if (action == "Change Plot")
				                                tr3.Plot = pn;	
												
			                                	ii.TrackedOrders.Add(tr3);
												o.IsTrackingEnabled = true;
												
												
											}
											

											//
											
											
											
											
			                              	o.IsTrackingConfigured = true;								
										 	
											//if (or.ist
											
											//Print(action);
											
											if (action == "On Off")
											{

												if (IsStopLoss && pAdvancedExitOrdersManagementEnabled)
												{

													o.IsTrackingEnabled = pTrailingStopIsEnabled;
												}
												else
												{

													if (o.IsTrackingEnabled)
													{
														o.IsTrackingEnabled = false;

													}
													else
													{
														// FEATURE: when re-enabling attachment on an order that
														// already has a stored plot, move it immediately to the
														// plot's current price instead of waiting for the next
														// NinjaTrader tracking tick. Looks up the matching tracked
														// order's stored Plot AND OffsetTicks (the caller passes
														// HoveredPlot via pn, which can be -1 / stale when the
														// user clicks the 'A' button instead of a plot — so we
														// re-read from the tracked order entry to get the order's
														// actual stored plot index).
														try
														{
															int storedPlot = pn;
															int storedOffsetTicks = 0;
															foreach (TrackedOrder lookupTr in ii.TrackedOrders)
															{
																if (lookupTr.Order != null && lookupTr.Order.OrderId == o.OrderId)
																{
																	storedPlot = lookupTr.Plot;
																	storedOffsetTicks = lookupTr.OffsetTicks;
																	break;
																}
															}
															double plotValueNow = GetThisPlotValue(inn, storedPlot, 0);
															if (plotValueNow > 0)
															{
																double targetPrice = RTTS(plotValueNow + storedOffsetTicks * ThisTickSize);
																if (targetPrice > 0)
																	MoveOrder(o, targetPrice, 0);
															}
														}
														catch { /* never let an immediate-move failure block the toggle */ }

														o.IsTrackingEnabled = true;

													}
												}
													
												
												
	
											}
											
											
											
//						                    Print("-------------");
														 
//											Print(o.Name);
//						                    Print(o.OrderId);

//											Print(action);
//											Print(ii.TrackedOrders.Count);											
								
						
											//Print(SetTrailModeTrueOnAccepted.Count);
									

			                }
							else
							{
//								if (ii.TrackedOrders != null)
//									ii.TrackedOrders.Clear();
							}

			
			
							//Print(ii.TrackedOrders.Count);
							
							b++;
							
			
			 	    }
							
						
						
						
						
					
									
				}
				catch (Exception ex)
				{
					//if (TestRender) Print("OnMarketDepth: " + ex.Message + " ");
					
					// Print(ex.Message);
					
				}
			
			


        }
		
