		private void ClearTrackedOrders(Order ooo)
        {

            //Print("Gettrackedo -----------------------");

			
			ooo.IsTrackingEnabled = false;
			
			
			
			
			List<TrackedOrder> RemoveTrackedOrders = new List<TrackedOrder>();	
			foreach (IndicatorBase ii in ChartControl.Indicators)
           // foreach (IndicatorBase ii in chartTrader.TrackableIndicators)
            {
				
						if (ii.Description.Contains("Key Levels Confluence"))
							continue;
						if (ii.Description.Contains("Price Action Confluence"))
							continue;	

				if (ii.TrackedOrders != null)
				for (int i = ii.TrackedOrders.Count - 1; i >= 0; i--)
				{
					
					bool shouldRemoveCondition = ii.TrackedOrders[i].Order == ooo;
				    // Do processing here, then...
					
					//Print(ii.TrackedOrders[i].Order.OrderState);
					
				    if (shouldRemoveCondition || ii.TrackedOrders[i].Order.OrderState == OrderState.Cancelled)
				    {
				        ii.TrackedOrders.RemoveAt(i);
				    }
				}


//				RemoveTrackedOrders.Clear();

//                foreach (TrackedOrder or in ii.TrackedOrders)
//                {
//					if (or.Order == ooo)
//					{
//						Print(ooo.Name);
//						RemoveTrackedOrders.Add(or);
//					}

//                }


//				foreach (TrackedOrder or in RemoveTrackedOrders)
//					ii.TrackedOrders.Remove(or);


                
            }

			ooo.IsTrackingConfigured = false;

        }

		
		
		
		
   
	

		
