		private void OnOrderUpdate3 (object sender, OrderEventArgs  e)
		{
			if (Instrument != null && e.Order != null && e.Order.Instrument != null && e.Order.Instrument.FullName == Instrument.FullName)
			{
				OrderState s = e.Order.OrderState;
				if (s == OrderState.Working || s == OrderState.Filled || s == OrderState.Cancelled || s == OrderState.Rejected || s == OrderState.PartFilled)
					LogDiag("DUPLICATE", "OrderUpdate", "OrderId=" + e.Order.OrderId + ", State=" + s);
			}
		}

