					string NameD = FinalNameID + string.Concat("-", pDuplicateStatus, "-", pMasterAccount);
					
					
					bool istriggerp = ThisOrder.OrderType == OrderType.Limit && ThisOrder.StopPrice != 0;
					double ticksoff = 0;	
					
					
						bool ISSLM = false;
						bool ISMIT = false;
						
						if (ThisOrder.OrderType == OrderType.StopLimit || istriggerp)
							ISSLM = true;
						
						if (ThisOrder.OrderType == OrderType.MIT)
						{
							ISMIT = true;	
							
							
						}
						
						
						if (ISSLM)
						{
								ticksoff = (ThisOrder.StopPrice - ThisOrder.LimitPrice)/TickSize;
							
							if (ThisOrder.IsLong)
							ticksoff = ticksoff * -1;
							
						}
					
						
						
						
					if (ThisOrder.OrderType == OrderType.StopLimit || ThisOrder.OrderType == OrderType.StopMarket || istriggerp)
					{
				
//						if (ThisOrder.Name.Contains("Stop"))
//							FinalOCOID = ThisOrder.Oco + "EXIT";

						
						
						
						
						if (pDuplicateStatus == "Copy")
						{
							
							//Print(ISSLM);
							
							
							
							
							if (ThisOrder.IsLong)
								BuyStop (ThisOrder.Quantity, null, FinalOCOID, priccccce, ISSLM, (int)ticksoff, NameD);
							else
								SellStop (ThisOrder.Quantity, null, FinalOCOID, priccccce, ISSLM, (int)ticksoff, NameD);							
							
						}
						else
						{
						
							if (ThisOrder.IsShort)
								BuyLimit(ThisOrder.Quantity, null, FinalOCOID, priccccce, ISMIT, NameD);
							else
								SellLimit(ThisOrder.Quantity, null, FinalOCOID, priccccce, ISMIT, NameD);
						
						}
						
					}
					else
					{
					
						if (pDuplicateStatus == "Copy")
						{
						
							if (ThisOrder.IsLong)
								BuyLimit(ThisOrder.Quantity, null, FinalOCOID, priccccce, ISMIT, NameD);
							else
								SellLimit(ThisOrder.Quantity, null, FinalOCOID, priccccce, ISMIT, NameD);												
							
						}
						else
						{
							
							// if fade make all stop market
							ISSLM = false;
							
							
							if (ThisOrder.IsShort)
								BuyStop (ThisOrder.Quantity, null, FinalOCOID, priccccce, ISSLM, 0, NameD);
							else
								SellStop (ThisOrder.Quantity, null, FinalOCOID, priccccce, ISSLM, 0, NameD);		
						
						}
			
						
					}
					
					//ThisOrder.Name.Replace("Target","Stop")
				
				}
				

		}
		

