		private void OnExecutionUpdate2 (object sender, ExecutionEventArgs e)
		{
			// PERF DIAG 2026-05-20: time the handler to find the NT 8.1.7.0 close-stall.
			long _perfT0_OEU2 = System.Diagnostics.Stopwatch.GetTimestamp();
			int _perfTid_OEU2 = System.Threading.Thread.CurrentThread.ManagedThreadId;
			if (Instrument != null && e.Execution != null && e.Execution.Instrument != null && e.Execution.Instrument.FullName == Instrument.FullName)
				LogDiag("EXECUTION", "Fill", "OrderId=" + (e.Execution.Order != null ? e.Execution.Order.OrderId : "null") + ", Qty=" + e.Quantity + ", Price=" + e.Price + ", Action=" + (e.Execution.Order != null ? e.Execution.Order.OrderAction.ToString() : "?"));

			// Refresh per-contract commission cache for Net-mode unrealized PnL.
			// Brokers vary: most populate ex.Commission per fill; Tradovate
			// reports 0 here and only updates account-level realized totals
			// when round-trips close. The lazy fallback in UpdatePNLBox handles
			// the Tradovate case.
			if (e.Execution != null
				&& e.Execution.Instrument != null
				&& ThisInstrumment != null
				&& e.Execution.Instrument == ThisInstrumment
				&& e.Execution.Commission > 0
				&& e.Execution.Quantity > 0)
			{
				cachedPerContractCommission = e.Execution.Commission / e.Execution.Quantity;
				commissionCacheInitialized  = true;
			}

			// Any fill on this instrument changes Instrument-mode realized PnL —
			// flag the cache so UpdatePNLBox recomputes on its next call.
			if (e.Execution != null
				&& e.Execution.Instrument != null
				&& ThisInstrumment != null
				&& e.Execution.Instrument == ThisInstrumment)
			{
				_instrumentRealizedDirty = true;
			}

			  
			//if (ReturnAllMain)
			
			
			//return;
			
			//ThisPositionNow().
		
			
			//Print(e.pos)
			
			//UpdateQTYBox (ThisPositionNow());
			
			
			
			
			
			
			if (pExecutionsDisplay != "None")
				RunExecutions();

			double _perfMs_OEU2 = (System.Diagnostics.Stopwatch.GetTimestamp() - _perfT0_OEU2) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
			if (_perfMs_OEU2 > 5.0) LogDiag("PERF", "OEU2_SLOW", "Ms=" + _perfMs_OEU2.ToString("F1") + "|Tid=" + _perfTid_OEU2);



		}
		
		
		
		// Per-order last-logged state for ORDER_UPDATE dedupe. NinjaTrader re-fires
		// OnOrderUpdate with an unchanged state many times per order (every move /
		// touch of a resting order), which made ORDER_UPDATE ~60% of the daily log.
		private readonly Dictionary<string, OrderState> _lastLoggedOrderState = new Dictionary<string, OrderState>();

		// True while a chart-refresh callback is already queued on the dispatcher, so
		// a burst of order-state events (e.g. Move All Exits over many orders)
		// collapses into one InvalidateVisual instead of one refresh per event.
		private volatile bool _renderRefreshQueued = false;

		private void OnOrderUpdate2 (object sender, OrderEventArgs  e)
		{
			// PERF DIAG 2026-05-20: time the handler to find the NT 8.1.7.0 close-stall.
			long _perfT0_OOU2 = System.Diagnostics.Stopwatch.GetTimestamp();
			int _perfTid_OOU2 = System.Threading.Thread.CurrentThread.ManagedThreadId;
			if (Instrument != null && e.Order != null && e.Order.Instrument != null && e.Order.Instrument.FullName == Instrument.FullName)
			{
				OrderState s = e.Order.OrderState;
				if (s == OrderState.Working || s == OrderState.Filled || s == OrderState.Cancelled || s == OrderState.Rejected || s == OrderState.PartFilled)
				{
					// Log only on an actual state transition for this OrderId.
					string oid = e.Order.OrderId;
					OrderState lastState;
					if (!_lastLoggedOrderState.TryGetValue(oid, out lastState) || lastState != s)
					{
						LogDiag("ORDER_UPDATE", s.ToString(), "OrderId=" + oid + ", Name=" + e.Order.Name + ", Type=" + e.Order.OrderType + ", Qty=" + e.Order.Quantity);
						if (_lastLoggedOrderState.Count > 2000)
							_lastLoggedOrderState.Clear();
						_lastLoggedOrderState[oid] = s;
					}
				}
			}
			
			  
			//if (ReturnAllMain)
			
			//return;
			
		 
			// bracket trade
			
			Order ThisOrder = e.Order;
			
				
		
			//ThisOrder.UserData.
			
			if (e.Order.Instrument != ThisInstrumment)
				return;
			// iceberg
		// Force render refresh when order state changes to reduce visual lag
			if (ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.Accepted ||
				ThisOrder.OrderState == OrderState.ChangePending || ThisOrder.OrderState == OrderState.ChangeSubmitted ||
				ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled ||
				ThisOrder.OrderState == OrderState.Rejected)
			{
				try
				{
					if (ChartControl != null && !_renderRefreshQueued)
					{
						_renderRefreshQueued = true;
						ChartControl.Dispatcher.BeginInvoke(new Action(() =>
						{
							_renderRefreshQueued = false;
							try { if (ChartControl != null) ChartControl.InvalidateVisual(); }
							catch { }
						}));
					}
				}
				catch { _renderRefreshQueued = false; }
			}

			// When an order reaches a terminal state (Cancelled/Filled), we may
			// have just drained the last working order while the position is
			// already flat. Try the auto-reset then — the helper no-ops if the
			// account is still holding a position or has any working orders.
			if (ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled)
			{
				// ChartControl == null means this indicator is terminated (its
				// chart was closed). There is no UI to reset, and
				// TryAutoResetATMOnFlatAndEmpty touches WPF objects that may only
				// be accessed on the UI thread — this handler runs on a Cbi
				// background thread. Skip entirely when there is no chart; only
				// hop to the UI thread when one exists.
				if (ChartControl != null)
					ChartControl.Dispatcher.InvokeAsync((Action)(() => { TryAutoResetATMOnFlatAndEmpty(); }));
			}
			
	// efficiency test for order display
			
			
			
//			if (ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled)
	
//			TriggerCustomEvent(o =>
//   			{
      
//				TotalTheOrders();
				
				
			
//			}, null);
			
			
			// resolves issue with fmso@protonmail.com in website chat, with trailing stops and FS template
			
			
			
//			if (ThisOrder.OrderState == OrderState.TriggerPending && ThisOrder.Name.Contains("SimStop"))
//			{
//				Print("ThisOrder.LimitPrice = 0;");
//				//ThisOrder.LimitPrice = 0;
//				double sdfgd = ThisOrder.StopPrice;
				
//				//MoveOrder(ThisOrder, sdfgd, 0);
				
//				Order moveOrder;
				
//				moveOrder = ThisOrder;
//				moveOrder.LimitPrice = 0;
				
//				//if (or.Quantity != newqty)
