					{
						// Matching-target guard: only auto-enroll when this stop has a
						// paired target in the same OCO. Without a target there is
						// nothing for RR to move, so enrollment is a no-op that just
						// pollutes RRIsOnOrders and confuses the toggle UI.
						Order __rrMatchT = GetMatchingTarget(ThisOrder.Oco);
						if (__rrMatchT != null)
						{
							lock (_accountStateLock) { RRIsOnOrders.Add(ThisOrder); }

							// Snapshot initial RR ratio from the ATM bracket at submit time.
							// Used later by CheckMoveStops so the computed target is immune
							// to mid-trade ATM template edits.
							AtmStrategy __rrAtm = GetOrderATM(ThisOrder);
							if (__rrAtm != null)
							{
								int __rrIdx = 0;
								foreach (Bracket __rrBb in __rrAtm.Brackets)
								{
									__rrIdx++;
									if (__rrBb.Target != 0 && __rrBb.StopLoss != 0 && ThisOrder.Name.Contains(__rrIdx.ToString()))
									{
										double __rrRatio = (double) __rrBb.Target / (double) __rrBb.StopLoss;
