//						ThisOrder.OrderState = OrderState.TriggerPending;
//						ThisOrder.OrderType = OrderType.Limit;
//						ThisOrder.CustomOrder = cccc;
//						ThisOrder.CustomOrder.Update();
//					}
					
					
//				}
				
//			}
			
			
			
			
			
			// linked orders
			
			if (pLinkButtonsIsOn)
			{
				
				
				
				if (pLinkOnPlaceOrder || LinkNextOrder)
					
				{
					//Print(LinkNextOrder + " " + ThisOrder.Name + " " + ThisOrder.OrderState.ToString());
					
					if (ThisOrder.OrderState == OrderState.Initialized || ThisOrder.OrderState == OrderState.Submitted)
					if (ThisOrder.OrderType != OrderType.Market)
					{
						
					
						//Print(LinkNextOrder + " " + ThisOrder.Name);
						
						if (ThisOrder.Name == "Entry" || (ThisOrder.Name == "" && LinkNextOrder))
						{
							
							
							//Print("linking");
						
							
							LinkNextOrder = false;
							
							
							if (!pLinkMultipleOrders)
								lock (_accountStateLock) { LinkedOrders.Clear(); }
								
							// entry orders or blank orders with link next order
							if (!LinkedOrders.Contains(ThisOrder))
							lock (_accountStateLock) { LinkedOrders.Add(ThisOrder); }
							
							
						}
						
						LinkNextOrder = false;

					}
					
					if (LinkedOrders.Contains(ThisOrder))
					if (ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Rejected) // ||ThisOrder.OrderState == OrderState.)
					{
						
						
						lock (_accountStateLock) { LinkedOrders.Remove(ThisOrder); }
					}
				}
				
			}
				
			
			
			
			
			
			
			
			
			//Print("1 " + ThisOrder.OrderState.ToString());
			
		
			
			// atm strategy display timer
			//
			// Fire AddATMPlanEntry ONCE per OrderId — only on the first
			// Accepted / Working / TriggerPending update we see for that
			// order. Subsequent updates (price modifications via manual
			// drag, server-side ATM moves, etc.) are skipped so the plan
			// doesn't re-appear every time an order is moved. The user
			// must manually re-show via the ATM-name chip on the order
			// flag if they want the plan visible again after a move.
			//
			// Cleanup happens further below when the order transitions to
			// Filled / Cancelled / Rejected, so the set doesn't grow.
			// Fire on Submitted/Initialized too — order has been created
			// locally and the flag is now drawing (in pending-gray), but
			// the plan won't render unless this price is in the display-end
			// dict. Bumping early means the plan shows immediately on
			// click, no blink. Dedupe keeps it from re-firing as the order
			// transitions Submitted -> Accepted -> Working.
			if (ThisOrder.OrderState == OrderState.Submitted || ThisOrder.OrderState == OrderState.Initialized
				|| ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.Working
				|| ThisOrder.OrderState == OrderState.TriggerPending)
			{
				string oidKey = ThisOrder.OrderId;
				if (!string.IsNullOrEmpty(oidKey) && !_planAutoShownForOrderId.Contains(oidKey))
				{
					_planAutoShownForOrderId.Add(oidKey);

					double finalprice = ThisOrder.LimitPrice;

					if (ThisOrder.OrderType == OrderType.StopLimit || ThisOrder.OrderType == OrderType.StopMarket || ThisOrder.OrderType == OrderType.MIT || (ThisOrder.StopPrice != 0 && ThisOrder.OrderState == OrderState.TriggerPending))
						finalprice = ThisOrder.StopPrice;

					AddATMPlanEntry(finalprice, pShowPlanSeconds333);
				}
			}
			else if (ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Rejected)
			{
				// Cleanup so the dedupe set doesn't grow without bound — and so
				// a future order with a recycled OrderId (rare but possible) still
				// gets its initial-placement auto-show.
				string oidKey = ThisOrder.OrderId;
				if (!string.IsNullOrEmpty(oidKey))
					_planAutoShownForOrderId.Remove(oidKey);
			}
			
			
			
			
			
			
			// slows chart down significantly
			
//			if (pOrdersDisplayOn)
//			{
//					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
//					{
				
//						RefreshRender(1113);

//					}));					
					
//			}
			
			
			
		


			
			// stop scanning plots to attach an order if it is filled or cancelled
			
			
			if (ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Rejected)
			{
				
				lock (_accountStateLock)
				{
					if (MovingOrders.Contains(ThisOrder))
						MovingOrders.Remove(ThisOrder);

					if (SelectedOrders.Contains(ThisOrder))
						SelectedOrders.Remove(ThisOrder);
				}
			}
		
			
			
		

			// attach click entry orders immediately if a plot is clicked
			
			if (NextIndicator != -1)
			if (ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.TriggerPending)
			{
				
				
				SetOrderIndicatorTracking(ThisOrder, NextIndicator, NextPlot, "Change Plot");	
				
				NextIndicator = -1;
				NextPlot = -1;
				
			}
			
			
			// attach stop loss orders immediately
			
			
//			if (pTrailingStopIsEnabled)
//			if (ThisOrder.OrderState == OrderState.Accepted)
//			{
//				if (ThisOrder.IsTrackingEnabled == false)
//				if (ThisOrder.Name.Contains("Stop"))
//				{
					
//					//Print("do stop loss tracking");
//					TrackStopLossOrders2(0, 0, "Change Plot");
					
//				}
//			}			
			
			
			
			
			if (pTrailingStopIsEnabled)
			if (ThisOrder.OrderState == OrderState.Accepted)
			{
				
				if (ThisOrder.Name.Contains("Stop"))
				{
					
					// add 
					
					string pTrailingStopStartMode = "Immediately";
					
					
					// set initial trailing stop
					
					if (pTrailingStopStartMode == "Immediately")				
						UpdateTrailingStopNow(true, true);
					if (pTrailingStopStartMode == "Decrease Only")	
						UpdateTrailingStopNow(true, false);
					
					
					
				}
			}			
			
			
			
			
						
				
			
			
			
			
			
			if (SetTrailModeTrueOnAccepted.Contains(ThisOrder))
			if (ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled)
			{
				
				
				SetOrderIndicatorTracking(ThisOrder, 0, 0, "IsTrailMode");	
				SetTrailModeTrueOnAccepted.Remove(ThisOrder);
			}
				
			
			
			if (ThisOrder.OrderState == OrderState.Cancelled)
			{
				if (IgnoreThisCancel)
				{
					IgnoreThisCancel = false;
				}
				else
				{
					if (ThisOrder.Oco.Contains(IcebergBuyID))
					if (IcebergBuyOrderSequence != 0)
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
				
						
						CancelTimeSlicedOrder("Buy");			
				
				
				
					
						IcebergBuyOrderSequence = 0;
						IcebergBuyAllOrderQty.Clear();
						InProfitActionCurrentPrice = 0;
						InProfitActionTriggered = false;
						InProfitActionIcebergClick = false;
						UpdateButtons();
						
						
						return;

					}));
						
						
						
					if (ThisOrder.Oco.Contains(IcebergSellID))
					if (IcebergSellOrderSequence != 0)
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
					
					
					CancelTimeSlicedOrder("Sell");	
					
						IcebergSellOrderSequence = 0;
						IcebergSellAllOrderQty.Clear();
						InProfitActionCurrentPrice = 0;
						InProfitActionTriggered = false;
						InProfitActionIcebergClick = false;
						UpdateButtons();
						
						
						return;

					}));					

					
					if (ThisOrder.Oco.Contains(TimeSlicedBuyID))
					if (TimeSlicedBuyOrderSequence != 0)
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
				
						CancelIcebergOrder("Buy");			
				
			
							TimeSlicedBuyOrderSequence = 0;
							TimeSlicedBuyAllOrderQty.Clear();
							InProfitActionCurrentPrice = 0;
							InProfitActionIcebergClick = false;
							UpdateButtons();
							
						
						return;

					}));
						
						
						
					if (ThisOrder.Oco.Contains(TimeSlicedSellID))
					if (TimeSlicedSellOrderSequence != 0)
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						
						
						CancelIcebergOrder("Sell");	
						
							TimeSlicedSellOrderSequence = 0;
							TimeSlicedSellAllOrderQty.Clear();
							InProfitActionCurrentPrice = 0;
							InProfitActionIcebergClick = false;
							UpdateButtons();
						
						
						return;

					}));
					
					
				}
				
				
			}
			
			
			
			if (ThisOrder.OrderState == OrderState.Filled)
			{
				
				
				//
				
				
				if (ThisOrder.Oco.Contains(TimeSlicedBuyID))
				{
			
					if (InProfitActionCurrentPrice == 0 && TimeSlicedBuyOrderSequence != 0)
					//if (ThisOrder.Oco.Contains("-1-"))
					{
						InProfitActionCurrentPrice = RTTS(ThisOrder.AverageFillPrice + InProfitActionCurrentTicks * ThisTickSize);
						//Print(InProfitActionCurrentPrice);
					}
					
					
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{	
						if (TimeSlicedFinishAtMarket)
						{
							
							TimeSlicedBuyOrderSequence = TimeSlicedBuyOrderSequence + 1;
		
							if (TimeSlicedBuyOrderSequence < TimeSlicedBuyAllOrderQty.Count)
							{
									
			
								PlaceITSOrder("Time Sliced", TimeSlicedBuyOrderSequence, "", BuyName);
								
								
								
							}
							else
							{
								//Print("Reset Buy Time Sliced");
								
								TimeSlicedBuyOrderSequence = 0;
								TimeSlicedBuyAllOrderQty.Clear();
								InProfitActionCurrentPrice = 0; 
								InProfitActionTriggered = false;
								InProfitActionTimeSlicedClick = false;
								TimeSlicedFinishAtMarket = false;
								
								UpdateButtons();
								
								StartTimeBuyTimeSliced = DateTime.MaxValue;
								RemainingTimeTimeSliced = TimeSpan.Zero;
								
								RefreshRender(1113);

							}

						}
						
		

					}));
						
						
					return;
				
			}
				
				
				
				if (ThisOrder.Oco.Contains(TimeSlicedSellID))
				{
					if (InProfitActionCurrentPrice == 0 && TimeSlicedSellOrderSequence != 0)
					//if (ThisOrder.Oco.Contains("-1-"))
					{
						InProfitActionCurrentPrice = RTTS(ThisOrder.AverageFillPrice - InProfitActionCurrentTicks * ThisTickSize);
	//					Print(InProfitActionCurrentTicks);
					}
					
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{	
						if (TimeSlicedFinishAtMarket)
						{
							
							TimeSlicedSellOrderSequence = TimeSlicedSellOrderSequence + 1;

							if (TimeSlicedSellOrderSequence < TimeSlicedSellAllOrderQty.Count)
							{

								PlaceITSOrder("Time Sliced", TimeSlicedSellOrderSequence, "", SellName);
								
							}
							else
							{
								TimeSlicedSellOrderSequence = 0;
								TimeSlicedSellAllOrderQty.Clear();
								InProfitActionCurrentPrice = 0;
								InProfitActionTriggered = false;
								InProfitActionTimeSlicedClick = false;
								TimeSlicedFinishAtMarket = false;
								
								UpdateButtons();
								
								StartTimeSellTimeSliced = DateTime.MaxValue;
								RemainingTimeTimeSliced = TimeSpan.Zero;
								
								RefreshRender(1113);

							}
							
						

						}
						


					}));
						
						
					return;					
					
					
					
					
				}
				
				
				
//				Print("on order o");
//				Print(ThisOrder.Oco + "  " + IcebergBuyID);
				
				
				if (ThisOrder.Oco.Contains(IcebergBuyID))
				//if (IcebergBuyOrderSequence != 0)
				ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
			
				//	Print("NEXT ICE 1");
					
					if (InProfitActionCurrentPrice == 0 && IcebergBuyOrderSequence != 0)
					//if (ThisOrder.Oco.Contains("-1-"))
					{
						InProfitActionCurrentPrice = RTTS(ThisOrder.AverageFillPrice + InProfitActionCurrentTicks * ThisTickSize);
					}
					
					IcebergBuyOrderSequence = IcebergBuyOrderSequence + 1;
					
					
					//Print("DSAFSA   " + IcebergOrderSequence + " <  " + (AllIcebergOrderQty.Count));
					
					if (IcebergBuyOrderSequence < IcebergBuyAllOrderQty.Count)
					{
						
						
						PlaceITSOrder("Iceberg", 0, "", "Buy");
						
						//Print("NEXT ICE 2");
						
					}
					else
					{
						IcebergBuyOrderSequence = 0;
						IcebergBuyAllOrderQty.Clear();
						InProfitActionCurrentPrice = 0;
						InProfitActionTriggered = false;
						InProfitActionIcebergClick = false;
						UpdateButtons();
						
					}
					
					
					//Print("Ice " + IcebergOrderSequence);
					
					return;

				}));
					
					
					
				if (ThisOrder.Oco.Contains(IcebergSellID))
				//if (IcebergSellOrderSequence != 0)
				ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
					
					if (InProfitActionCurrentPrice == 0 && IcebergSellOrderSequence != 0)
					//if (ThisOrder.Oco.Contains("-1-"))
					{
						InProfitActionCurrentPrice = RTTS(ThisOrder.AverageFillPrice - InProfitActionCurrentTicks * ThisTickSize);
					}		
					
					IcebergSellOrderSequence = IcebergSellOrderSequence + 1;
					
					
					//Print("DSAFSA   " + IcebergOrderSequence + " <  " + (AllIcebergOrderQty.Count));
					
					if (IcebergSellOrderSequence < IcebergSellAllOrderQty.Count)
					{
						
						
						PlaceITSOrder("Iceberg", 0, "", "Sell");
						
						
					}
					else
					{
						IcebergSellOrderSequence = 0;
						IcebergSellAllOrderQty.Clear();
						InProfitActionCurrentPrice = 0;
						InProfitActionTriggered = false;
						InProfitActionIcebergClick = false;
						UpdateButtons();
						
					}
					
					
					//Print("Ice " + IcebergOrderSequence);
					
					return;

				}));					
					
				
				
				
			}
			
			
			
			
			
			if (ThisOrder.OrderState == OrderState.Filled)
			{
				if (MovingOrder != null)
				{
					if (ThisOrder == MovingOrder)
						MovingOrder = null;
					
				}
				
				if (MovingOrders.Count > 0)
				lock (_accountStateLock)
				{
					if (ThisOrder == MovingOrder)
						MovingOrder = null;

					foreach (Order oo in MovingOrders.ToList())
					{
						if (oo == ThisOrder)
							DeleteOrders.Add(oo);
						
					}
					
					foreach (Order oo in DeleteOrders)
					{
						MovingOrders.Remove(oo);
						
					}				
					DeleteOrders.Clear();
					
				}
			}
			
			
//			if (BracketLongEntryOrder == null && SaveLongOrder)
//			{						
//				BracketLongEntryOrder = ThisOrder;
//				SaveLongOrder = false;
				
//				UpdateButtons();
//			}
			
			
			
			
			
			if (ThisOrder == SignalEntryBuyOrder)
			if (ThisOrder.OrderState == OrderState.Rejected)
			{
				
						if (pRejectedStopEntryAction == "Market")
						{
							BuyMarket(SignalEntryBuyOrder.Quantity, atmStrategySelector.SelectedAtmStrategy, "");
						}
						if (pRejectedStopEntryAction == "Limit")
						{
							
							
							int qttttty = SignalEntryBuyOrder.Quantity;
							double pprrr = SignalEntryBuyOrder.StopPrice;
							SignalEntryBuyOrder = null;
							
							
							SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.Limit, tifSelector1.SelectedTif, qttttty, pprrr, 0, "", "Entry", null);				
							SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);	
						}			
						
						
						
						
				
				
				SignalEntryBuyOrder = null;
				
				UpdateButtons();
			}
					
			
			
		
			
			if (ThisOrder == SignalEntrySellOrder)
			if (ThisOrder.OrderState == OrderState.Rejected)
			{
				
				
						if (pRejectedStopEntryAction == "Market")
						{
									
						
							SellMarket(SignalEntrySellOrder.Quantity, atmStrategySelector.SelectedAtmStrategy, "");
				
						}
						if (pRejectedStopEntryAction == "Limit")
						{
							
							
							int qttttty = SignalEntrySellOrder.Quantity;
							double pprrr = SignalEntrySellOrder.StopPrice;
							SignalEntrySellOrder = null;
							
							
							SignalEntrySellOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Sell, OrderType.Limit, tifSelector1.SelectedTif, qttttty, pprrr, 0, "", "Entry", null);				
							SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntrySellOrder);	
						}			
						
						
						
				
				SignalEntrySellOrder = null;
				
				UpdateButtons();
			}			
			
			
			
			
			
			
			
			
			
			
			
			
			if (ThisOrder == BracketLongEntryOrder)
			if (ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Rejected)
			{
				BracketLongEntryOrder = null;
				
				UpdateButtons();
			}
			
			
			
			
			
			if (ThisOrder == BracketShortEntryOrder)
			if (ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Rejected)
			{
				BracketShortEntryOrder = null;
				
				UpdateButtons();
			}		
			
			
			
			
			
			// Targets Trading Pro Scalper
			
			
			// NinjaScript Reload / workspace restore: re-bind working Price/Stop
			// entry orders that we submitted earlier but lost the reference for
			// during indicator re-instantiation. Without this, the Price Based
			// Entry button loses its color highlight, trailing toggle, and cancel
			// wiring on reload. Identified by signal name "Entry" plus our OCO
			// prefix ("PBEO" for the Price Based flow, "VTFSEO" for the non-
			// Price-Based stop-entry flow).
			if (LongEntryOrder2 == null && ThisOrder != null && ThisOrder.Name == "Entry"
				&& ThisOrder.OrderAction == OrderAction.Buy
				&& (ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.Accepted)
				&& ThisOrder.Oco != null
				&& (ThisOrder.Oco.StartsWith("PBEO") || ThisOrder.Oco.StartsWith("VTFSEO")))
			{
				LongEntryOrder2 = ThisOrder;
				if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
					PriceBasedLongFrozen = !pPriceBasedInitialTrailingEnabled;
				else
					PriceBasedLongFrozen = false;
				UpdateButtons();
			}
			if (ShortEntryOrder2 == null && ThisOrder != null && ThisOrder.Name == "Entry"
				&& ThisOrder.OrderAction == OrderAction.SellShort
				&& (ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.Accepted)
				&& ThisOrder.Oco != null
				&& (ThisOrder.Oco.StartsWith("PBEO") || ThisOrder.Oco.StartsWith("VTFSEO")))
			{
				ShortEntryOrder2 = ThisOrder;
				if (pPriceBasedEntryOrdersEnabled && pPriceBasedLiveEntryButtonFunctionality == "Trailing Mode")
					PriceBasedShortFrozen = !pPriceBasedInitialTrailingEnabled;
				else
					PriceBasedShortFrozen = false;
				UpdateButtons();
			}

			if (LongEntryOrder2 == null && SaveLongOrder2)
			{
				LongEntryOrder2 = ThisOrder;
				SaveLongOrder2 = false;

				UpdateButtons();
			}
			
			if (ThisOrder == LongEntryOrder2)
			if (ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Rejected)
			{

				IsInPCBuy = false;


				LongEntryOrder2 = null;
				// Price-based freeze state is bound to this working order.
				PriceBasedLongFrozen = false;
				RefreshPriceButtonPulses();

				if (pUseOCOStopEntry)
					SellStopReady = false;

				UpdateButtons();
			}
			
			
			
			if (ShortEntryOrder2 == null && SaveShortOrder2)
			{						
				ShortEntryOrder2 = ThisOrder;
				SaveShortOrder2 = false;
				
				UpdateButtons();
			}
			
			if (ThisOrder == ShortEntryOrder2)
			if (ThisOrder.OrderState == OrderState.Filled || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Rejected)
			{

				IsInPCSell = false;

				ShortEntryOrder2 = null;
				// Price-based freeze state is bound to this working order.
				PriceBasedShortFrozen = false;
				RefreshPriceButtonPulses();

				if (pUseOCOStopEntry)
					BuyStopReady = false;

				UpdateButtons();
			}					
					
			
			double _perfMs_OOU2 = (System.Diagnostics.Stopwatch.GetTimestamp() - _perfT0_OOU2) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
			if (_perfMs_OOU2 > 5.0) LogDiag("PERF", "OOU2_SLOW", "Ms=" + _perfMs_OOU2.ToString("F1") + "|Tid=" + _perfTid_OOU2 + "|State=" + (e != null && e.Order != null ? e.Order.OrderState.ToString() : "?") + "|Name=" + (e != null && e.Order != null ? e.Order.Name : "?"));

			// order totals and flags

			TriggerCustomEvent(o =>
   			{
      
				//TotalTheOrders();
				
				
				
				if (ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.ChangePending || ThisOrder.OrderState == OrderState.Cancelled || ThisOrder.OrderState == OrderState.Filled)
					SetOrderFlags();
				
			
			}, null);
			
				

			
			
			

		}		


			
		
		private void DrawQTYBox (int q, double newpospri, int thisdir)
		{
				
			if (ChartControl != null)
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{
			
				
				
				
				
				
				// sai kodi
				
				if (IsSai)
					; // Print("DrawQTYBox");

				QTYBox.Text = q.ToString();
				
				LastQtyUpdate = q;
				
				
				
				if (q == 0)
					QTYBox.Text = ps0string;
				
				QTYBox.Background = pPNLBackgroundColor;
				QTYBox.Foreground = pPNLFlatTextColor;

				if (thisdir == 1)
				{
					QTYBox.Background = pPNLProfitColor;
					QTYBox.Foreground = GetTextColor(pPNLProfitColor);

				}
				if (thisdir == -1)
				{
					QTYBox.Background = pPNLLossColor;
					QTYBox.Foreground = GetTextColor(pPNLLossColor);

				}
				
					
				
				
				if(pProfitAndLossEntry == "Show")
				{
					QTYBox.Width = 93;
					EntryBox.Width = 94;	
					double pnlInner = pChartTraderWidth - CTLeftSpace - CTLeftSpace - endadd + 2;
					double halfGap = 1;
					double entryW = Math.Floor(pnlInner / 2);
					double qtyW = pnlInner - entryW - halfGap;
					QTYBox.Width = qtyW;
					EntryBox.Width = entryW;				
					
					
					
					if (q == 0)
					
						EntryBox.Text = entry0string;
					else
						EntryBox.Text = AllPriceMarker(newpospri);		
					
						EntryBox.Background = pPNLBackgroundColor;
						EntryBox.Foreground = pPNLFlatTextColor;
			
				}
				else
				{
					
					double pnlInner2 = pChartTraderWidth - CTLeftSpace - CTLeftSpace - endadd + 2;
					QTYBox.Width = pnlInner2 - 15 - 1;

					EntryBox.Width = 15;
					EntryBox.Text = "";

					EntryBox.Background = pColorButtonOrderType;
					EntryBox.Foreground = Brushes.White;
					
					
				}
				
				
			}));
				
		}
					
