		private int LastQtyUpdate = 0;
		
			
		
		private void UpdateQTYBox ()
		{
			
//			if (LastPositionUpdate == null)
//				return;
			
//			if (ThisPositionNow() == null)
//				return;
			
		
			Position pp = ThisPositionNow();
				
			
			
			// does not work
			//Position pp = LastPositionUpdate;
			
			
			
			//Print(" this POS " + LastPositionUpdate.Quantity);
			
			
			
			if (ChartControl != null)
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{
			
				
				
				int q = 0;
					
				int thisdir = 0;
				
				double pr = 0;
				
				if (pp != null)
				{
					q = pp.Quantity;
					
					if (pp.MarketPosition == MarketPosition.Long)
						thisdir = 1;
					if (pp.MarketPosition == MarketPosition.Short)
						thisdir = -1;
					
					pr = pp.AveragePrice;
				}
					
				
			
				DrawQTYBox(q, pr, thisdir);
				
				SentToChartQty = q;
				
				
			}));
				
		}
			
		
		
	
		
		
		
