		private void UpdatePNLBox ()
		{
			if (myAccount == null) return;

			//Print("UpdatePNLBox");

//			if (ThisPositionNow() == null)
//				return;


			// sai kodi

				if (IsSai)
					; // Print("UpdatePNLBox");
				
				
				
			
			
			Position pp = ThisPositionNow();
			
				
	
				
			double amount = 0;
			string ssss = "";
			
				double totalrealized = 0;
				double totalunrealized = 0;
			double totalunrealizedchart = 0;

		//	Print(CurrentLastData);
			
			double CurrentLastData222 = CurrentLastData;
			CurrentLastData222 = CurrentLast;
//			if (CurrentLast == 0)
//				return;
			
				
				
				if (pp != null)
				{

					totalunrealized = pp.GetUnrealizedProfitLoss(PerformanceUnit.Currency,CurrentLastData222);

							if (pProfitAndLossType2 == "Points")
							{
								totalunrealized = pp.GetUnrealizedProfitLoss(PerformanceUnit.Points,CurrentLastData222);

							}
							if (pProfitAndLossType2 == "Ticks")
							{
								totalunrealized = pp.GetUnrealizedProfitLoss(PerformanceUnit.Ticks,CurrentLastData222);

							}


					totalunrealizedchart = pp.GetUnrealizedProfitLoss(PerformanceUnit.Currency,CurrentLastData222);

							if (pProfitAndLossType == "Points")
							{
								totalunrealizedchart = pp.GetUnrealizedProfitLoss(PerformanceUnit.Points,CurrentLastData222);

							}
							if (pProfitAndLossType == "Ticks")
							{
								totalunrealizedchart = pp.GetUnrealizedProfitLoss(PerformanceUnit.Ticks,CurrentLastData222);

							}

					// Subtract commissions from unrealized PnL when in Net mode.
					// Two prior bugs fixed:
					//   1. Dollar commissions were unconditionally subtracted from
					//      totalunrealizedchart, even when the chart display was in
					//      Ticks or Points (e.g. a $10 commission produced "-10 ticks").
					//   2. The commission figure was the account session-cumulative
					//      delta (grossRealized - netRealized) — i.e. every closed
					//      trade's commission added together — applied to a single
					//      open position. Different accounts therefore showed wildly
					//      different offsets, and the offset grew with each closed
					//      trade.
					// Fix: estimate THIS open position's round-trip commission from
					// the cached per-contract rate (refreshed in OnExecutionUpdate2),
					// and apply only to dollar-denominated displays.
					if (pProfitAndLossDisplayType == "Net" && pShowCommissionsOptions && pp.Quantity > 0)
					{
						// Lazy seed: on first use (e.g. workspace reload with an
						// existing position) populate the cache from existing
						// executions so we don't have to wait for the next fill.
						if (!commissionCacheInitialized)
						{
							DateTime latest = DateTime.MinValue;
							foreach (Execution ex in myAccount.Executions)
							{
								if (ex.Instrument != ThisInstrumment) continue;
								if (ex.Quantity <= 0 || ex.Commission <= 0) continue;
								if (ex.Time > latest)
								{
									cachedPerContractCommission = ex.Commission / ex.Quantity;
									latest = ex.Time;
								}
							}

							// Tradovate fallback: ex.Commission is reported as 0
							// per fill. Derive a per-contract per-side rate from
							// session realized totals (gross - net = commissions
							// paid this session) divided by total exit-side
							// contracts. Halve it — sessionCommissions covers the
							// full round-trip (entry+exit fills), the cached rate
							// represents a single side.
							if (cachedPerContractCommission == 0)
							{
								double grossR = myAccount.Get(AccountItem.GrossRealizedProfitLoss, Currency.UsDollar);
								double netR   = myAccount.Get(AccountItem.RealizedProfitLoss,      Currency.UsDollar);
								double sessionCommissions = grossR - netR;
								if (sessionCommissions > 0)
								{
									int closedContracts = 0;
									foreach (Execution ex in myAccount.Executions)
									{
										if (ex.Instrument != ThisInstrumment) continue;
										if (!ex.IsEntry) closedContracts += ex.Quantity;
									}
									if (closedContracts > 0)
										cachedPerContractCommission = (sessionCommissions / closedContracts) / 2.0;
								}
							}

							// Mark initialized only when we got a non-zero rate;
							// otherwise re-seed on next call (e.g. Tradovate's
							// first trade ever — gross unrealized until first
							// close gives us a rate to work with).
							if (cachedPerContractCommission > 0)
								commissionCacheInitialized = true;
						}

						// Round-trip commission for the open position
						// (entry fill + future exit fill).
						double positionCommissionDollars = pp.Quantity * 2 * cachedPerContractCommission;

						if (pProfitAndLossType2 == "Currency")
						{
							totalunrealized = totalunrealized - positionCommissionDollars;
						}

						if (pProfitAndLossType == "Currency")
						{
							totalunrealizedchart = totalunrealizedchart - positionCommissionDollars;
						}
					}



					amount = totalunrealized;

							//Print(amount);
				}
				else
				{
					
					if (pProfitAndLossDisplayType == "None" || FirstRender)	
					{
						ssss = flatstring;
					}
					else
					{
					
						if (pProfitAndLossDisplayType == "Net")
						{
							// Use RealizedProfitLoss directly - already has commissions subtracted (works for Tradovate)
							totalrealized = myAccount.Get(AccountItem.RealizedProfitLoss, Currency.UsDollar);

						}
						if (pProfitAndLossDisplayType == "Gross")
						totalrealized = myAccount.Get(AccountItem.GrossRealizedProfitLoss, Currency.UsDollar);
							
						amount = totalrealized;
						
						//Print(totalrealized);
						
						if (pProfitAndLossType3 == "Instrument")
						{
							// Cached result path: the heavy execution-walk below
							// only runs when _instrumentRealizedDirty is set
							// (new fill, account change, or session reset). On
							// every other UpdatePNLBox call (per render frame)
							// we just reuse the previously computed dollars.
							if (!_instrumentRealizedDirty)
							{
								amount = _cachedInstrumentRealized;
							}
							else
							{
								int LastEntry = 1;
								int LastDir = 1;
								double TotalLongPrices = 0;
								int TotalLongQty = 0;
								double TotalShortPrices = 0;
								int TotalShortQty = 0;
	
								double ThisCommission = 0;
	
								int LastPosition = 0;
	
								List<double> AllLongEntries = _allLongEntriesScratch;
								AllLongEntries.Clear();
								
								//Print(LastSessionStart);
								
								
								foreach (Execution ex in myAccount.Executions)
								{
									//Print(ex.Time);
									
									if (ex.Instrument != ThisInstrumment)
										continue;
									
									if (ex.Time <= LastSessionStart)
										continue;
								
	//								if (ex.IsEntry && ex.MarketPosition == MarketPosition.Long)
	//									LastEntry = 1;
									
	//								if (ex.IsEntry && ex.MarketPosition == MarketPosition.Short)
	//									LastEntry = -1;
	
	//								LastDir = LastEntry;
									
	//								if (LastEntry == 1 && ex.IsExit)
	//									LastDir = -1;
	//								if (LastEntry == -1 && ex.IsExit)
	//									LastDir = 1;						
									
	//								if (LastDir == 1)
	//								{
	//									totallongqty = totallongqty + ex.Quantity;
	//									totallongprices = totallongprices + ex.Price*ex.Quantity;
										
	//								}
									
	//								if (LastDir == -1)
	//								{
	//									totalshortqty = totalshortqty + ex.Quantity;
	//									totalshortprices = totalshortprices + ex.Price*ex.Quantity;
										
	//								}
									
									
									ThisCommission = ex.Quantity > 0 ? ex.Commission / ex.Quantity : 0;
	
											
									for (int i = 1; i <= ex.Quantity; i++)
									{
	
										
										
										
										if (ex.IsEntry)
										{
											if (ex.MarketPosition == MarketPosition.Long)
											{
												LastPosition = LastPosition + 1;
												
											
												if (LastPosition > 0)
												{
													LastDir = 1;
													AllLongEntries.Add(ex.Price);
												}
												else
												{
													TotalLongQty = TotalLongQty + 1;
													TotalLongPrices = TotalLongPrices + ex.Price;
													
													
											
													TotalShortQty = TotalShortQty + 1;
													TotalShortPrices = TotalShortPrices + AllLongEntries[0];
													
													AllLongEntries.RemoveAt(0);												
													
													
												}
											}
											if (ex.MarketPosition == MarketPosition.Short)
											{
												LastPosition = LastPosition - 1;
												
												
												
												if (LastPosition < 0)
												{
													LastDir = -1;
													AllLongEntries.Add(ex.Price);
												}
												else
												{
													
													TotalLongQty = TotalLongQty + 1;
													TotalLongPrices = TotalLongPrices + AllLongEntries[0];
											
													TotalShortQty = TotalShortQty + 1;
													TotalShortPrices = TotalShortPrices + ex.Price;
													
													
													AllLongEntries.RemoveAt(0);											
													
												}
											}										
											
										}
										else
										{
											
											if (LastDir == 1)
											{
												
												//Print(AllLongEntries[0]);
	
												if (LastPosition > 0)
												{
													TotalLongQty = TotalLongQty + 1;
													TotalLongPrices = TotalLongPrices + AllLongEntries[0];
													
													
											
													TotalShortQty = TotalShortQty + 1;
													TotalShortPrices = TotalShortPrices + ex.Price;
													
													
													AllLongEntries.RemoveAt(0);
													
												//	Print(ex.Price);
												}
											
												
												if (!ex.IsEntry)
													LastPosition = LastPosition - 1;
												
														
												
											}
											
											if (LastDir == -1)
											{
	
												
												if (LastPosition < 0 && !ex.IsEntry)
												{
													TotalLongQty = TotalLongQty + 1;
													TotalLongPrices = TotalLongPrices + ex.Price;
													
													
											
													TotalShortQty = TotalShortQty + 1;
													TotalShortPrices = TotalShortPrices + AllLongEntries[0];
													
													AllLongEntries.RemoveAt(0);
													
													//Print(ex.Price);
												}
												
												if (!ex.IsEntry)
													LastPosition = LastPosition + 1;
																							
	
														
											}
											
											
											
										}
										
										
									
										
										//Print(Z.LastPosition + "  " + Z.AllLongEntries.Count);
										
									}
									
									
									
																	
									
									
									
									
									
									
									
									//Print(ex.Time + "  " + LastEntry);
									
								}
								
								
								double averagelongprice = 0;
								double averageshortprice = 0;
								double moneyforthisi = 0;
								
								if (TotalLongPrices != 0 && TotalShortPrices != 0)
								{
								
									averagelongprice = TotalLongPrices / TotalLongQty;
									averageshortprice = TotalShortPrices / TotalShortQty;
									
				//					Print("averagelongprice: " + averagelongprice + " " + totallongqty);
				//					Print("averageshortprice: " + averageshortprice + " " + totalshortqty);
									
									moneyforthisi = Math.Round(((averageshortprice-averagelongprice)/ThisTickSize)*TotalLongQty, 0)*ThisTickDollars;
								
								}
								
								//Print("$ " + moneyforthisi.ToString());
								//
								//if (!pShowRealizedPNLWhenFlat)
									
								if (pProfitAndLossDisplayType == "Net")
								{
									// Prefer the per-contract rate from the last
									// iterated execution (brokers that populate
									// ex.Commission). Fall back to the cached rate
									// from OnExecutionUpdate2 / lazy seed (handles
									// Tradovate via session realized-totals derivation
									// scoped to this instrument's closed contracts).
									//
									// Previous code subtracted account-wide
									// grossRealized - netRealized, which mixed in
									// commissions from any other instrument traded
									// today and inflated the loss figure.
									double perContract = ThisCommission > 0 ? ThisCommission : cachedPerContractCommission;
									if (perContract > 0)
									{
										moneyforthisi = moneyforthisi - TotalLongQty * 2 * perContract;
									}
									// If still zero, no commission rate is known yet
									// (e.g. Tradovate's first round-trip of the
									// session). Display gross — under-counting once
									// is preferable to subtracting a wildly inflated
									// session-cumulative figure.
								}
	
								_cachedInstrumentRealized = moneyforthisi;
								_instrumentRealizedDirty  = false;
								amount = moneyforthisi;
							} // end recompute branch (matches `if (_instrumentRealizedDirty) else`)
						}
						
						
						
						
						
						//
						
						
					}
					
					
				}
				
			
			SentToChartPNL = totalunrealizedchart;
			
				
//				TriggerCustomEvent(o =>
//				   			{
				      
								
							
				
			
			if (ChartControl != null)
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{


				//PNLBox.Text = "$" + Math.Round(amount,2).ToString("n2");

				PNLBox.Text = GetDollarString("$", amount);
				
				if (pp != null) // if we have a position give option to display in points or ticks
				{
					if (pProfitAndLossType2 == "Points")
					{
						PNLBox.Text = AllPriceMarker(amount);
						
					}						
					if (pProfitAndLossType2 == "Ticks")
					{
						PNLBox.Text = Math.Round(amount, 0).ToString();
						
					}
				}
			
				
				PNLBox.Background = pPNLBackgroundColor;

//				if (amount == 0)
//				{
//					PNLBox.Foreground = Brushes.White;
//					//PNLBox.Foreground = Brushes.Black;

//				}



				if (amount > 0)
				{
					PNLBox.Foreground = pPNLProfitColor;
					//PNLBox.Foreground = Brushes.Black;

				}

				else
				{
					PNLBox.Foreground = pPNLLossColor;
					//PNLBox.Foreground = Brushes.White;

				}

				if (ssss == flatstring)
				{
					PNLBox.Text = ssss;
					PNLBox.Foreground = pPNLFlatTextColor;
				}
				
				
				if (ThisPositionNow() != null) // in a position
					if (!pPNLIsVisible || pProfitAndLossDisplayType == "None")
					{
						PNLBox.Text = flatstring;
						PNLBox.Foreground = Brushes.DimGray;
					}
					
					
				if (pShowInstrumentOptions)
				{
					if (ThisPositionNow() != null)
					{
						pnli.Visibility = Visibility.Hidden;
					}
					else
					{
						pnli.Visibility = Visibility.Visible;
						
						if (pProfitAndLossType3 == "Instrument")
						{
							pnli.Text = ThisMasterInstrument.Name;
						}
						else
						{
							pnli.Text = "All";
						}
										
					}
				}
				
				
				
				
				
			}));
				
				
					//}, null);
		}
	
	
	
		
					
	
		
