		private Position ThisPositionNow()
		{


			if (myAccount != null)
			foreach (Position pos in myAccount.Positions.ToList())
			{
				if (ThisInstrumment != null && pos.Instrument != null && pos.Instrument.FullName == ThisInstrumment.FullName)
					return pos;

			}

			return null;
		}
		
		private MarketPosition GetMarketPosition()
		{
			
			
			if (myAccount != null)
			foreach (Position pos in myAccount.Positions.ToList())
			{
				if (ThisInstrumment != null && pos.Instrument != null && pos.Instrument.FullName == ThisInstrumment.FullName)
				{
					return pos.MarketPosition;

				}

			}

			
			
			return MarketPosition.Flat;
		}
		
		
		private void CancelOrder(Order o)
		{	
			LogDiag("ORDER", "CancelOrder", "OrderId=" + (o != null ? o.OrderId : "null") + ", Name=" + (o != null ? o.Name : "null"));
				myAccount.Cancel(new[] { o });		
		}
		

