	private void MoveOrder(Order o, double ThisMousePrice, int TotalTicks)
		{
		

			

				
			
			
			Account aaa = myAccount;
					
			if (IsDuplicateOrder)
			{
				aaa = accountSelectorMaster.SelectedAccount;
				IsDuplicateOrder = false;
			}
					
			
			//foreach (Order or in aaa.Orders.ToList())
			//{
				
				NewStopPrice = 0;
				NewLimitPrice = 0;
				
			
				Order or = o;
				
				//TrackedOrders(
						//OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
						//OrderTypeOK = or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.StopMarket;
						//OrderNameOK = or.Name == "Stop1" ||  or.Name == "Stop2" ||  or.Name == "Stop3";
						OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				//OrderNameOK = IsStop(or.Name);
				
				// TriggerPending is MIT
				
				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
				OrderTypeOK = true;
				OrderNameOK = true;
				
			
			
				//if (or == o)
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
					//Print("fff");
					
					
					//Print(or.OrderType.ToString());
					
					
					bool OKToMove = false;
					
					bool limit1 = or.StopPrice == 0;
					bool limit2 = or.OrderState == OrderState.Working;
					bool limit3 = limit1 || limit2;
					
					if (or.OrderType == OrderType.Limit && limit3)
					//if (or.OrderType == OrderType.Limit)
					{
						
						NewLimitPrice = ThisMousePrice;
						
						if (TotalTicks != 0)
						NewLimitPrice = RTTS(or.LimitPrice+TotalTicks*ThisTickSize);
						
						OKToMove = true;
					}
					else if (or.OrderType == OrderType.MIT || or.OrderType == OrderType.Market)
					{
						
						
						//Print(ThisMousePrice);
						
						
						//NewLimitPrice = ThisMousePrice;
						//StopLimitOffset = or.StopPrice - or.LimitPrice;
						//NewStopPrice = NewLimitPrice - StopLimitOffset;
						
						NewStopPrice = ThisMousePrice;
						
						if (TotalTicks != 0)
						NewStopPrice = RTTS(or.StopPrice+TotalTicks*ThisTickSize);
					
						
						
						
						NewLimitPrice = 0;
						
						OKToMove = true;
					}		
					else
					{
						
//						if (or.OrderState == OrderState.TriggerPending)
//						{
//							NewStopPrice = ThisMousePrice;
//							StopLimitOffset = or.LimitPrice - or.StopPrice;
//							NewLimitPrice = NewStopPrice - StopLimitOffset;						
//						}
//						else
						{
							NewStopPrice = ThisMousePrice;
							
							if (TotalTicks != 0)
							NewStopPrice = RTTS(or.StopPrice+TotalTicks*ThisTickSize);
							
							StopLimitOffset = or.StopPrice - or.LimitPrice;
							NewLimitPrice = NewStopPrice - StopLimitOffset;						
						}

									
						CurrentStopPrice = or.StopPrice;
						
						if (or.LimitPrice == 0)
							NewLimitPrice = 0;						
						
						if (or.IsShort) // In Long Trade
						{


							
							OKToMove = NewStopPrice <= GetCurrentBid();
						
							if (UseLastPriceForClickOrders)
							{
								OKToMove = NewStopPrice <= CurrentLastData;
							}
							
						}
						else // In Short Trade
						{
						

							OKToMove = NewStopPrice >= GetCurrentAsk();
							
							if (UseLastPriceForClickOrders)
							{
								OKToMove = NewStopPrice >= CurrentLastData;
							}
							
						}
						
						if (or.OrderState == OrderState.TriggerPending)
						{
							OKToMove = true;	
						}
						
						if (!OKToMove)
						{
							string ordertype = "Stop Market";
							
							if (or.OrderType == OrderType.StopLimit)
								ordertype = "Stop Limit";
							
							//Print(NewStopPrice);
							
							
							if (or.IsShort) 
								AddMessage (ordertype + " order price cannot be changed to above the market.", 8, Brushes.Red);
							else
								AddMessage (ordertype + " order price cannot be changed to below the market.", 8, Brushes.Red);							
							//or.OrderType.ToString();
							
						}
						
					
					}
					
					if (OKToMove)
						
					{
					//if (NewStopPrice != 0 && OKToMove)
						
								// ability to cancel and replace orders for td
							
						
						//IsTDAmeritrade = true;
						
								if (IsTDAmeritrade)
								{
								
									
									if (or.Oco != string.Empty)
									{
									
										ThisOCOToReplaceOrders.Add(or.Oco);
										
										NewLimitPrices.Add(or.Name, NewLimitPrice);
										NewStopPrices.Add(or.Name, NewStopPrice);
										
										CancelOrder(or);
										
										
										return;
									}
									

									
									if (or.OrderState != OrderState.TriggerPending)
									{
									
										
										Order NewOrder = myAccount.CreateOrder(or.Instrument, or.OrderAction, or.OrderType, or.TimeInForce, or.Quantity, NewLimitPrice, NewStopPrice, or.Oco, or.Name, null);
										
													
		
										int orrrrr = 0;
										string sadfdgh = string.Empty;
										
										if (IsTarget(or.Name))
										{

											sadfdgh = or.Name.Replace("Target", "");
											orrrrr = Convert.ToInt32(sadfdgh);
															
											IgnoreNextExitCancel.Add(orrrrr);
										}
										if (IsStop(or.Name))
										{
						
											sadfdgh = or.Name.Replace("Stop", "");
											orrrrr = Convert.ToInt32(sadfdgh);
															
											IgnoreNextExitCancel.Add(orrrrr);
										}
										
										
										
										CancelOrder(or);
										
										
										SubmitOrder(null, NewOrder);
										
										return;
									}

									
								}
									
								
								
								
								
								
								
							Order moveOrder;
							
							moveOrder = or;
							
							//Print(NewLimitPrice + " NewLimitPrice");
							//Print(NewStopPrice + " NewStopPrice");
							
							//if (or.OrderType == OrderType.Limit || or.OrderType == OrderType.StopLimit) 
								
							if (NewLimitPrice != 0)
								moveOrder.LimitPriceChanged = NewLimitPrice;
							
							//if (or.OrderType == OrderType.StopMarket || or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.MIT) 
								
							if (NewStopPrice != 0)
								moveOrder.StopPriceChanged = NewStopPrice;		

							
							

								
								
							aaa.Change(new[] { moveOrder });
							

					}
					
					//Print(or.Name);
				}
				
		//	}
			
					

		}
		
		
		private string OnBarCloseOCO = string.Empty;
				
		private void BuyNow (string WhichEntry, int BB)
		{
			
				
//			ThisPreviousBarHigh = Highs[0][BB];
//			ThisPreviousBarLow = Lows[0][BB];
//			ThisPreviousBarClose = Closes[0][BB];
//			ThisPreviousBarMiddle = RTTS((ThisPreviousBarHigh+ThisPreviousBarLow)/2);
			
			
			ThisPreviousBarHigh = OnBarPBHigh;
			ThisPreviousBarLow = OnBarPBLow;
			ThisPreviousBarClose = OnBarPBClose;
			
			if (BB == 0)
			{
				ThisPreviousBarHigh = OnBarCBHigh;
				ThisPreviousBarLow = OnBarCBLow;
				ThisPreviousBarClose = OnBarCBClose;				
			}
			
			
			ThisPreviousBarMiddle = RTTS((ThisPreviousBarHigh+ThisPreviousBarLow)/2);
			
		
			
			
			
			string ThisPriceBasis = pCloseBarBasis;
			int		thisoffset = pLimitOrderOffset1;
			string		thisordert = pThisEntryType1;	
			
				if (WhichEntry == "Signal")
				{
					ThisPriceBasis = pSignalBarBasis;
					thisoffset = pLimitOrderOffset2;
					thisordert = pSignalEntryOrderType;					
				}
			
			
			
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{
				
				
				//Print("BuyClose " + ThisPreviousBarClose);
				
				
//				Print("BuyNow");
//				Print(thisordert);
				
//				if (BracketLongEntryOrder != null)
//					CancelOrder(BracketLongEntryOrder);
					
//				if (BracketShortEntryOrder != null)
//					CancelOrder(BracketShortEntryOrder);
				
		
				if (thisordert == "PLOT")
				{
					BuyThisPlot(pPriceBasedIndicator, pPriceBasedPlot, 0, pLimitOrderOffset2);
				}				
				
				
				if (thisordert == "MKT")
				{
					BuyMarket(pQty, atmStrategySelector.SelectedAtmStrategy, "");
				}
				
				if (thisordert == "ICE")
				{
					StartIcebergOrder("Buy");
				}				
				if (thisordert == "SLI")
				{
					StartTimeSlicedOrder(BuyName, "Market");
				}									
				//EntryOrderPrice = RTTS(CurrentLastData - thisoffset*ThisTickSize);
				//EntryOrderPrice = CurrentAsk - thisoffset*ThisTickSize;
				
				
				
				if (thisordert == "LMT")
				{
			
					//BuyLimit(pQty, atmStrategySelector.SelectedAtmStrategy, "", RTTS(EntryOrderPrice), false, "Entry"); 
					
					// added so we can cancel order when a new order is placed
					
//					if (SignalEntryBuyOrder != null)
//						CancelOrder(SignalEntryBuyOrder);
//					if (SignalEntrySellOrder != null)
//						CancelOrder(SignalEntrySellOrder);	
					
					
						EntryOrderPrice = ThisPreviousBarClose - thisoffset*ThisTickSize;
						if (ThisPriceBasis == "Middle")
							EntryOrderPrice = ThisPreviousBarMiddle - thisoffset*ThisTickSize;			
						if (ThisPriceBasis == "High / Low")
							EntryOrderPrice = ThisPreviousBarLow - thisoffset*ThisTickSize;
			

					SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.Limit, tifSelector1.SelectedTif, pQty, RTTS(EntryOrderPrice), 0, "", "Entry", null);
										
					SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);	
			
				
				}
				
				
				if (thisordert == "STP" || thisordert == "SLM")
				{
					
					//Print(thisordert + " " + "UUU");

						EntryOrderPrice = ThisPreviousBarClose + thisoffset*ThisTickSize;
						if (ThisPriceBasis == "Middle")
							EntryOrderPrice = ThisPreviousBarMiddle + thisoffset*ThisTickSize;									
						if (ThisPriceBasis == "High / Low")
							EntryOrderPrice = ThisPreviousBarHigh + thisoffset*ThisTickSize;
	
					bool IsInvalidStopEntry = EntryOrderPrice < CurrentAsk;
					
					
//					IsInvalidStopEntry = false;

//					Print("CurrentAsk" + CurrentAsk);
//					Print("EntryOrderPrice" + EntryOrderPrice);
//					Print(IsInvalidStopEntry);
					
					if (IsInvalidStopEntry && pInvalidStopEntryAction != "None") // not a valid buy stop, so go market instead
					{
						if (pInvalidStopEntryAction == "Market")
						{
							BuyMarket(pQty, atmStrategySelector.SelectedAtmStrategy, "");
						}
						if (pInvalidStopEntryAction == "Limit")
						{
							SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.Limit, tifSelector1.SelectedTif, pQty, RTTS(EntryOrderPrice), 0, OnBarCloseOCO, "Entry", null);				
							SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);	
						}						
					}
					else
					{
						
						
						
						double SLMPrice = RTTS(EntryOrderPrice+pSLOffsetReg*ThisTickSize);
			
						if (thisordert == "STP")

							SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.StopMarket, tifSelector1.SelectedTif, pQty, 0, RTTS(EntryOrderPrice), OnBarCloseOCO, "Entry", null);
						else
							SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.StopLimit, tifSelector1.SelectedTif, pQty, SLMPrice, RTTS(EntryOrderPrice), OnBarCloseOCO, "Entry", null);
									
								
											
						if (thisordert == "SLM")
						if (SLMPrice < EntryOrderPrice)
						{

							CustomOrder cccc = new CustomOrder();
							cccc.IsSimulatedStopEnabled = true;
							cccc.VolumeTrigger = 1;
							
			//					entryOrder.OrderState = OrderState.TriggerPending;
							
							SignalEntryBuyOrder.CustomOrder = cccc;
							
			//					entryOrder.CustomOrder.IsSimulatedStopConfigured = true;
			//					entryOrder.CustomOrder.IsSimulatedStopEnabled = true;
							
							
						}
				
				
				
						SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);	
			
					}
				
				}				

				if (thisordert == "MIT")
				{
					EntryOrderPrice = ThisPreviousBarClose - thisoffset*ThisTickSize;
					if (ThisPriceBasis == "Middle")
						EntryOrderPrice = ThisPreviousBarMiddle - thisoffset*ThisTickSize;
					if (ThisPriceBasis == "High / Low")
						EntryOrderPrice = ThisPreviousBarLow - thisoffset*ThisTickSize;

					SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.MIT, tifSelector1.SelectedTif, pQty, 0, RTTS(EntryOrderPrice), OnBarCloseOCO, "Entry", null);
					SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);
				}

				if (thisordert == "LIT")
				{
					double triggerPrice = ThisPreviousBarClose - thisoffset*ThisTickSize;
					if (ThisPriceBasis == "Middle")
						triggerPrice = ThisPreviousBarMiddle - thisoffset*ThisTickSize;
					if (ThisPriceBasis == "High / Low")
						triggerPrice = ThisPreviousBarLow - thisoffset*ThisTickSize;

					double litLimitPrice = RTTS(triggerPrice - pLITOffset*ThisTickSize);

					SignalEntryBuyOrder = myAccount.CreateOrder(ThisInstrumment, OrderAction.Buy, OrderType.Limit, tifSelector1.SelectedTif, pQty, litLimitPrice, RTTS(triggerPrice), OnBarCloseOCO, "Entry", null);
					SubmitOrder(atmStrategySelector.SelectedAtmStrategy, SignalEntryBuyOrder);
				}
				
				
				
						

			}));
			
		}
		
