//				if (!pAutoEnabled)
//				{
//					DisableTheSystem();
//				}
				
			}));			
		}
		
		
		
		
		
		
		
		
		
		private bool IsDuplicateOrder = false;
		
		
		private void BuyLimit (int pQty, AtmStrategy ThisATM, string OCOID, double FinalPrice, bool pUseMIT, string ThisName)
		{
			LogDiag("ORDER", "BuyLimit", "Qty=" + pQty + ", Price=" + FinalPrice + ", MIT=" + pUseMIT + ", ATM=" + (ThisATM != null ? ThisATM.DisplayName : "None") + ", OCO=" + OCOID + ", Name=" + ThisName);

			if (myAccount == null)
				return;
		
			
			WatchForExitID = true;
			
	
			OrderType OT = OrderType.Limit;			
			SLMPrice = 0;
			
			if (pThisEntryLimitClick == "MIT")
			{					
				OT = OrderType.MIT;
				SLMPrice = FinalPrice;
				FinalPrice = 0;
			}

			Account aaa = myAccount;
			
			if (IsDuplicateOrder)
			{
				aaa = accountSelectorMaster.SelectedAccount;
				IsDuplicateOrder = false;
			}
			
//			Print(FinalPrice);
//			Print(pQty);
//			Print(ThisName);
			//Print(FinalPrice);
			
			
			Order entryOrder = aaa.CreateOrder(ThisInstrumment, OrderAction.Buy, OT, tifSelector1.SelectedTif, pQty, FinalPrice, SLMPrice, OCOID, ThisName, null);

			// Scale-In check for BuyLimit
			if (pScaleIntoExistingATM && ThisATM != null)
			{
				AtmStrategy existingATM = FindActiveATMForPosition();
				if (existingATM != null) { ScalePositionPending(pQty, OrderAction.Buy, OT, FinalPrice, SLMPrice, OCOID, ThisName, existingATM); return; }
			}

			if (ThisATM == null)
			{
				aaa.Submit(new[] { entryOrder });
			}
			else
			{
				StartAtmStrategyWithDrafts(ThisATM, entryOrder);
				if (pScaleIntoExistingATM) lastCreatedATM = ThisATM;
			}
		

			
		}

		private void SellLimit (int pQty, AtmStrategy ThisATM, string OCOID, double FinalPrice, bool pUseMIT, string ThisName)
		{
			LogDiag("ORDER", "SellLimit", "Qty=" + pQty + ", Price=" + FinalPrice + ", MIT=" + pUseMIT + ", ATM=" + (ThisATM != null ? ThisATM.DisplayName : "None") + ", OCO=" + OCOID + ", Name=" + ThisName);

			WatchForExitID = true;
			
			
			OrderType OT = OrderType.Limit;			
			//CurrentType = "LIMIT";
			SLMPrice = 0;
			
			if (pUseMIT)
			{					
				OT = OrderType.MIT;
				//CurrentType = "MIT";
				SLMPrice = FinalPrice;
				FinalPrice = 0;
			}
			
