	private void AddMessageWithUrl(string msg, int sec, Brush be, string url, bool forceShow = false)
		{
			MessageAlerts Z = new MessageAlerts();
			Z.Name = msg;
			DateTime nowMsg = DateTime.Now;
			Z.StartTime = nowMsg;
			Z.ExpireTime = nowMsg.AddSeconds(sec);
			Z.BrushE = be;
			Z.Switch = true;
			Z.Url = url ?? "";

			bool DuplicateMessage = false;

			foreach (MessageAlerts D in AllMessages)
			{
				if (D.Name == msg && D.Switch)
				{
					DuplicateMessage = true;
					D.StartTime = nowMsg;
					D.ExpireTime = nowMsg.AddSeconds(sec);
					D.DuplicateCount = D.DuplicateCount + 1;
				}
			}

			if (!DuplicateMessage)
				AllMessages.Add(Z);

			if (ChartControl != null)
				RefreshRender(1113);
		}

	private void RemoveMessage (bool rend, string msg)
		{
			// LEAK FIX (deep-dive Finding #6): previously this just set
			// D.Switch = false on matching entries, leaving them in the list
			// forever. Paired with the OnTimer3Tick expiration change, this
			// ensures removed messages are also physically dropped.
			AllMessages.RemoveAll(D => D.Name != null && D.Name.Contains(msg));

			if (rend)
			RefreshRender(1113);

		}

		
		
		private void LogDiag(string category, string action, string details = null)
		{
			if (_logQueue == null) return;
			string ts = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss.fff");
			string line;
			if (details != null)
				line = string.Concat("[", ts, "] ", _logInstanceTag, " [", category, "] ", action, " | ", details);
			else
				line = string.Concat("[", ts, "] ", _logInstanceTag, " [", category, "] ", action);
			_logQueue.Enqueue(line);
		}

		private void LogDiagEx(string category, string context, Exception ex)
		{
			if (_logQueue == null || ex == null) return;
			LogDiag(category, "ERROR " + context, "Type=" + ex.GetType().Name + ", Msg=" + ex.Message);
		}

		private void LogFlushCallback(object state)
		{
			if (_logQueue == null || _logQueue.IsEmpty) return;
			var batch = new List<string>(64);
			string item;
			while (_logQueue.TryDequeue(out item))
				batch.Add(item);
			if (batch.Count == 0) return;
			lock (_logWriteLock)
			{
				try
				{
					string today = DateTime.Now.ToString("yyyy-MM-dd");
					if (_logWriter == null || _logCurrentDate != today)
					{
						if (_logWriter != null)
						{
							try { _logWriter.Flush(); _logWriter.Close(); } catch { }
						}
						EnsureLogDirectory();
						string filePath = Path.Combine(_logDirectoryPath, "ECT_" + today + ".log");
						var fs = new FileStream(filePath, FileMode.Append, FileAccess.Write, FileShare.ReadWrite);
						_logWriter = new StreamWriter(fs, System.Text.Encoding.UTF8);
						_logWriter.AutoFlush = false;
						_logCurrentDate = today;
					}
					for (int i = 0; i < batch.Count; i++)
						_logWriter.WriteLine(batch[i]);
					_logWriter.Flush();
				}
				catch { }
			}
		}

		private static void EnsureLogDirectory()
		{
			if (_logDirectoryPath == null)
				_logDirectoryPath = Path.Combine(
					NinjaTrader.Core.Globals.UserDataDir,
					"Affordable Indicators", "Enhanced Chart Trader", "log");
			if (!Directory.Exists(_logDirectoryPath))
				Directory.CreateDirectory(_logDirectoryPath);
		}

		private void RefreshLogInstanceTag()
		{
			string instName = Instrument != null ? Instrument.FullName : "?";
			string acctName = myAccount != null ? myAccount.Name : (!string.IsNullOrEmpty(pAccountName) ? pAccountName : "?");
			string bpName = BarsPeriod != null ? (BarsPeriod.Value + " " + BarsPeriod.BarsPeriodType.ToString()) : "?";
			_logInstanceTag = "[" + instName + "|" + bpName + "|" + acctName + "|#" + _logInstanceId + "]";
		}

		private void LogSessionHeader()
		{
			if (_logSessionHeaderWritten) return;
			_logSessionHeaderWritten = true;
			string bp = BarsPeriod != null ? (BarsPeriod.Value + " " + BarsPeriod.BarsPeriodType.ToString()) : "?";
			string cfg = "v=" + pCurrentVersionName
				+ ", BP=" + bp
				+ ", Master=" + (pMasterAccount ?? "none")
				+ ", Dup=" + pDuplicateSendEnabled
				+ ", Trail=" + pTrailingStopIsEnabled + "/" + (pTrailingStopType ?? "?")
				+ ", Signal=" + pSignalEntryOrdersEnabled + "/" + (pSignalEntryType ?? "?")
				+ ", Click=" + pClickEntryOrdersEnabled
				+ ", Mkt=" + pMarketEntryOrdersEnabled
				+ ", Ice=" + pIcebergEntryOrdersEnabled
				+ ", TS=" + pTimeSlicedEntryOrdersEnabled
				+ ", Brk=" + pBracketEntryOrdersEnabled
				+ ", PosSz=" + EnablePositionSizing
				+ ", MachineId=" + (NinjaTrader.Cbi.License.MachineId ?? "?")
				+ ", RenderDiag=" + pRenderDiagMode;
			LogDiag("SYSTEM", "SessionStart", cfg);
		}

		private static void PurgeOldLogs()
		{
			if (_logPurgeComplete) return;
			_logPurgeComplete = true;
			try
			{
				EnsureLogDirectory();
				DateTime cutoff = DateTime.Now.AddDays(-14);
				foreach (string f in Directory.GetFiles(_logDirectoryPath, "ECT_*.log"))
				{
					try
					{
						if (File.GetLastWriteTime(f) < cutoff)
							File.Delete(f);
					}
					catch { }
				}
			}
			catch { }
		}

		private class RandomGenerator    
		{    
		    // Generate a random number between two numbers    
		    public int RandomNumber(int min, int max)    
		    {    
		        Random random = new Random();    
		        return random.Next(min, max);    
		    }    
		    
		    // Generate a random string with a given size    
		    public string RandomString(int size, bool lowerCase)    
		    {    
		        StringBuilder builder = new StringBuilder();    
		        Random random = new Random();    
		        char ch;    
		        for (int i = 0; i < size; i++)    
		        {    
		            ch = Convert.ToChar(Convert.ToInt32(Math.Floor(26 * random.NextDouble() + 65)));    
		            builder.Append(ch);    
		        }    
		        if (lowerCase)    
		            return builder.ToString().ToLower();    
		        return builder.ToString();    
		    }    
		    
		    // Generate a random password    
		    public string RandomPassword()    
		    {    
		        StringBuilder builder = new StringBuilder();    
		        builder.Append(RandomString(4, true));    
		        builder.Append(RandomNumber(1000, 9999));    
		        builder.Append(RandomString(2, false));    
		        return builder.ToString();    
		    }    
		}    		
		
		
		
