		private void CancelEntryOrderByOCOID(string id)
		{
					foreach (Order or in myAccount.Orders.ToList())
								{
									
								
									OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending || or.OrderState == OrderState.ChangeSubmitted
										|| or.OrderState == OrderState.CancelPending || or.OrderState == OrderState.CancelSubmitted || or.OrderState == OrderState.TriggerPending;
									OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
									OrderNameOK = !IsTarget(or.Name) && !IsStop(or.Name);
									
									//OrderTypeOK = or.OrderType != OrderType.Market;	
									OrderTypeOK = true;
								
									
									if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)						
									if (or.Oco.Contains(id))
									{
										
										//if (thisbutton.Value.Width == or.StopPrice)
											CancelOrder(or);
						
										
									}
									
								}
								
			
		}
		
		
		
		private void MoveITSEntryOrder(string otype, int seq, string mode)
		{
		
			// MODE = Fill or Trail
			
			string IcebergBuyID2 = string.Empty;
			string IcebergSellID2 = string.Empty;
			
			if (otype == "Iceberg")
			{
				IcebergBuyID2 = IcebergBuyID;
				IcebergSellID2 = IcebergSellID;
			}
			else
			{
				IcebergBuyID2 = TimeSlicedBuyID;
				IcebergSellID2 = TimeSlicedSellID;				
			}
			
			
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;
				
				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending  || or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelPending || or.OrderState == OrderState.CancelSubmitted;
				OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				OrderNameOK = !IsTarget(or.Name) && !IsStop(or.Name);
				OrderTypeOK = or.Oco.Contains(IcebergBuyID2) || or.Oco.Contains(IcebergSellID2);		

				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)	
				{
					//Print("fff");
					
					bool OKToMove = false;
					
					int pIcebergOffsetTrail = pIcebergOffset;
					
					
					if (or.OrderType == OrderType.Limit || or.OrderType == OrderType.MIT || (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending))
					{
						if (or.Oco.Contains(IcebergBuyID2))
						{
							
							if (mode == "Trail")
							{
								if (pIcebergOffsetBasis == "Bid / Ask")
									IcebergEntryPrice = RTTS(CurrentAsk - pIcebergOffsetTrail*ThisTickSize);
								else if (pIcebergOffsetBasis == "Last")
									IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffsetTrail*ThisTickSize);
								else if (pIcebergOffsetBasis == "DRO")						
									IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffsetTrail*ThisTickSize);							
								
								if (IcebergEntryPrice > or.LimitPrice)
								{
									NewLimitPrice = IcebergEntryPrice;
									OKToMove = true;									
								}															
							}							
							
							if (mode == "Fill")
							{
								NewLimitPrice = RTTS(CurrentLastData + FillLimitOrderNowTicks*ThisTickSize);
								OKToMove = true;																
							}
						
						}
						else
						{
													
							if (mode == "Trail")
							{
								if (pIcebergOffsetBasis == "Bid / Ask")
									IcebergEntryPrice = RTTS(CurrentBid + pIcebergOffsetTrail*ThisTickSize);
								else if (pIcebergOffsetBasis == "Last")
									IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffsetTrail*ThisTickSize);
								else if (pIcebergOffsetBasis == "DRO")						
									IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffsetTrail*ThisTickSize);							
								
								if (IcebergEntryPrice < or.LimitPrice)
								{
									NewLimitPrice = IcebergEntryPrice;
									OKToMove = true;								
								}															
							}
							
							if (mode == "Fill")
							{
								NewLimitPrice = RTTS(CurrentLastData - FillLimitOrderNowTicks*ThisTickSize);
								OKToMove = true;																
							}		
							
						}
						

						

					}
					else if (or.OrderType == OrderType.StopMarket || or.OrderType == OrderType.StopLimit)
					{
	
						if (or.Oco.Contains(IcebergBuyID2))
						{
							
							if (mode == "Trail")
							{
								if (pIcebergOffsetBasis == "Bid / Ask")
									IcebergEntryPrice = RTTS(CurrentAsk + pIcebergOffsetTrail*ThisTickSize + ThisTickSize);
								else if (pIcebergOffsetBasis == "Last")
									IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffsetTrail*ThisTickSize + ThisTickSize);
								else if (pIcebergOffsetBasis == "DRO")						
									IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffsetTrail*ThisTickSize + ThisTickSize);
								
								if (IcebergEntryPrice < or.StopPrice)
								{
									NewStopPrice = IcebergEntryPrice;
									OKToMove = true;									
								}															
							}							
							
							if (mode == "Fill")
							{
								NewStopPrice = RTTS(CurrentLastData - FillLimitOrderNowTicks*ThisTickSize);
								OKToMove = false;																
							}
						
						}
						else
						{
													
							if (mode == "Trail")
							{
								if (pIcebergOffsetBasis == "Bid / Ask")
									IcebergEntryPrice = RTTS(CurrentBid - pIcebergOffsetTrail*ThisTickSize - ThisTickSize);
								else if (pIcebergOffsetBasis == "Last")
									IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffsetTrail*ThisTickSize - ThisTickSize);
								else if (pIcebergOffsetBasis == "DRO")						
									IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffsetTrail*ThisTickSize - ThisTickSize);
								
								if (IcebergEntryPrice > or.StopPrice)
								{
									NewStopPrice = IcebergEntryPrice;
									OKToMove = true;								
								}															
							}
							
							if (mode == "Fill")
							{
								NewStopPrice = RTTS(CurrentLastData + FillLimitOrderNowTicks*ThisTickSize);
								OKToMove = false;																
							}		
							
						}		
						
						
//						NewLimitPrice = ThisMousePrice;
//						StopLimitOffset = or.StopPrice - or.LimitPrice;
//						NewStopPrice = NewLimitPrice - StopLimitOffset;
//						OKToMove = true;
					}		
//					else
//					{
//						NewStopPrice = ThisMousePrice;
//						StopLimitOffset = or.StopPrice - or.LimitPrice;
//						NewLimitPrice = NewStopPrice - StopLimitOffset;
									
//						CurrentStopPrice = or.StopPrice;
						
//						if (or.LimitPrice == 0)
//							NewLimitPrice = 0;						
						
//						if (or.IsShort) // In Long Trade
//						{

							
//							OKToMove = NewStopPrice <= GetCurrentBid();
							
//						}
//						else // In Short Trade
//						{
						

//							OKToMove = NewStopPrice >= GetCurrentAsk();
							
//						}
					
//					}
					
					if (or.OrderType == OrderType.MIT || or.OrderType == OrderType.Market)
					//if (or.OrderType == OrderType.MIT)
					{
						NewStopPrice = NewLimitPrice;
					
						NewLimitPrice = 0;
						
					}
					
					else if (or.OrderType != OrderType.Limit)
					{
						
						StopLimitOffset = or.StopPrice - or.LimitPrice;
						NewLimitPrice = NewStopPrice - StopLimitOffset;
						
						if (or.LimitPrice == 0)
							NewLimitPrice = 0;						
					}
										

					if (mode == "Fill")
					if (!OKToMove)
					{
						// cancel stop entry order and send market order
						
						IgnoreThisCancel = true;
						
						//int qqqq = or.Quantity;
						
						CancelEntryOrderByOCOID(or.Oco);	
						
					//	Print("PlaceITSOrder");
						
					
						
						if (or.Oco.Contains(IcebergBuyID2))
						{
							
							ChartControl.Dispatcher.InvokeAsync((Action)(() =>{ PlaceITSOrder(otype, seq, "Market", "Buy"); }));
						
						}
						else
						{
							
							ChartControl.Dispatcher.InvokeAsync((Action)(() =>{ PlaceITSOrder(otype, seq, "Market", "Sell"); }));
						}
						
						
						
					}
					
					
					//if (OKToMove)
					//if (NewStopPrice != 0 && OKToMove)
						//instruction = OIF_ChangeOrder(0,NewLimitPrice,NewStopPrice,or.OrderId.ToString(),"");
					
					//Submit();
					
					
					if (OKToMove)
					{
					
					
						
							Order moveOrder;
							
							moveOrder = or;
							moveOrder.LimitPriceChanged = NewLimitPrice;
							moveOrder.StopPriceChanged = NewStopPrice;		
							
							myAccount.Change(new[] { moveOrder });
							

					
					}
					
					
					//Print(or.Name);
				}

			}



		}

