		private void CancelTimeSlicedOrder(string dir)
		{

		
			
			InProfitActionCurrentPrice = 0;
			InProfitActionTriggered = false;
			InProfitActionTimeSlicedClick = false;
			
			TimeSlicedFinishAtMarket = false;
			
			if (dir == "Buy")
			{
				
				if (TimeSlicedBuyOrderSequence != 0)
				{				
					TimeSlicedBuyAllOrderQty.Clear();
					TimeSlicedBuyOrderSequence = 0;
				
				}
				
				BuyTimeSlicedAtOrAbove = 0;
				BuyTimeSlicedAtOrBelow = 0;			

				CancelEntryOrderByOCOID(TimeSlicedBuyID);				
				
			}
			else
			{
				
				if (TimeSlicedSellOrderSequence != 0)
				{
					TimeSlicedSellAllOrderQty.Clear();
					TimeSlicedSellOrderSequence = 0;
					
					
				}
				
				SellTimeSlicedAtOrAbove = 0;
				SellTimeSlicedAtOrBelow = 0;	
				
				CancelEntryOrderByOCOID(TimeSlicedSellID);					
				
			}
			

			UpdateButtons();
		}		
		
		
		private void CancelIcebergOrder(string dir)
		{
			InProfitActionCurrentPrice = 0;
			InProfitActionTriggered = false;
			InProfitActionIcebergClick = false;
			
			if (dir == "Buy")
			{
				
				if (IcebergBuyOrderSequence != 0)
				{				
					IcebergBuyAllOrderQty.Clear();
					IcebergBuyOrderSequence = 0;

				}
				
				BuyIcebergAtOrAbove = 0;
				BuyIcebergAtOrBelow = 0;			
				
				CancelEntryOrderByOCOID(IcebergBuyID);				
				
			}
			else
			{
				
				if (IcebergSellOrderSequence != 0)
				{
					IcebergSellAllOrderQty.Clear();
					IcebergSellOrderSequence = 0;

				}
				
				SellIcebergAtOrAbove = 0;
				SellIcebergAtOrBelow = 0;	
				
				CancelEntryOrderByOCOID(IcebergSellID);					
				
			}
			

			UpdateButtons();
			
		}
		
		
