		private List<int> RandomListQty (int pQty, int pIcebergDisplayQty, int pIcebergVariance)
		{
			
			bool Test = false;
			
			
			List<int> IcebergBuyAllOrderQty = new List<int>();	
			
				IcebergBuyAllOrderQty.Clear();
				IcebergBuyAllOrderQty.Add(0);
			
				
				
				int MinQty = pIcebergDisplayQty - (int) Math.Round((double)pIcebergDisplayQty*((double)pIcebergVariance/(double)100), 0);
				int MaxQty = pIcebergDisplayQty + (int) Math.Round((double)pIcebergDisplayQty*((double)pIcebergVariance/(double)100), 0);
				
				MinQty = Math.Max(MinQty, 1);
			
//				if (Test) Print("Min Qty: " + MinQty + "  Max Qty: " + MaxQty);
//				if (Test) Print (IcebergBuyID);
//				if (Test) Print("-------------------------------------------");
				
				int TotalOrderSize = pQty;
				int TotalQtyAdded = 0;
				
				int NextQty = 0;
			    Random RandomQty = new Random();  
			    
				
				do
				{
					
					NextQty = (int) RandomQty.Next(MinQty, MaxQty);
					NextQty = Math.Min(NextQty, TotalOrderSize-TotalQtyAdded);
					
					
					IcebergBuyAllOrderQty.Add(NextQty);
					TotalQtyAdded = TotalQtyAdded + NextQty;	
						
					if (Test)  Print(NextQty);
					
				}	
				while (TotalQtyAdded < TotalOrderSize); // do
						
						
				
//				if (Test) Print("-------------------------------------------");
//				if (Test) Print(TotalQtyAdded.ToString() + " Contracts In " + (IcebergBuyAllOrderQty.Count-1).ToString() + " Orders.");
//				if (Test) Print("-------------------------------------------");
				
				
				//IcebergBuyOrderSequence = 1;
				
				//IcebergBuyEntryMode = pIcebergEntryMode;					
				
					
			return IcebergBuyAllOrderQty;

			
		}
		
		private List<int> RandomListTimes (int pQty, int pMainTimeMS, int pTimeVariance)
		{
			
			bool Test = false;
			
			
			List<int> IcebergBuyAllOrderQty = new List<int>();	
			
				IcebergBuyAllOrderQty.Clear();
				IcebergBuyAllOrderQty.Add(0);
			
				
				
				int MinQty = pMainTimeMS - (int) Math.Round((double)pMainTimeMS*((double)pTimeVariance/(double)100), 0);
				int MaxQty = pMainTimeMS + (int) Math.Round((double)pMainTimeMS*((double)pTimeVariance/(double)100), 0);
				
				MinQty = Math.Max(MinQty, 10);
			
				if (Test) Print("Min MS: " + MinQty + "  Max MS: " + MaxQty);
				//if (Test) Print (IcebergBuyID);
				if (Test) Print("-------------------------------------------");
				
				int TotalOrderSize = pQty;
				int TotalQtyAdded = 0;
				
				int NextQty = 0;
			    Random RandomQty = new Random();  
			    
				
				do
				{
					
					NextQty = (int) RandomQty.Next(MinQty, MaxQty);
					//NextQty = Math.Min(NextQty, TotalOrderSize-TotalQtyAdded);
					
					
					IcebergBuyAllOrderQty.Add(NextQty);
					TotalQtyAdded = TotalQtyAdded + 1;	
						
					if (Test)  Print(NextQty);
					
				}	
				while (TotalQtyAdded < pQty); // do
						
						
				
				if (Test) Print("-------------------------------------------");
				if (Test) Print("Total Trades: " + (IcebergBuyAllOrderQty.Count-1).ToString() + " Times.");
				if (Test) Print("-------------------------------------------");
				
				
				//IcebergBuyOrderSequence = 1;
				
				//IcebergBuyEntryMode = pIcebergEntryMode;					
				
					
			return IcebergBuyAllOrderQty;

			
		}
		
		
