		private void StartTimeSlicedOrder(string ThisTimeSlicedDirection, string type)
		{
			
		
			if (!CheckNewTradeReady())
				return;
			

			if (!ITSATMOK())
				return;
			
			bool Test = false;
			
			
			if (Test) Print(ThisTimeSlicedDirection);
			
			if (ThisTimeSlicedDirection == "Buy")
			{
				if (TimeSlicedBuyPricePending())
						CancelTimeSlicedOrder("Buy");		
				
				
				
				
				
				
				// anthony custom
				
				
				if (pSignalAutoEnabled)
				{
					ClosePosition();
					
				}
				
				
				if (pTradingSystemMode)
				{
				
					if (!pSignalAutoEnabled && BuySignalReady)
					{
							BuySignalReady = false;
							UpdateButtons();
					}
						
						
								//if (pTradingSystemMode)
								//ClosePosition();
								
				}
					
				
				
			}
			else
			{
				if (TimeSlicedSellPricePending())
						CancelTimeSlicedOrder("Sell");	
				
				
	
				// anthony custom
				
				
					
				if (pSignalAutoEnabled)
				{
					ClosePosition();
					
				}
				
				
				if (pTradingSystemMode)
				{
				
					if (!pSignalAutoEnabled && SellSignalReady)
					{
							SellSignalReady = false;
							UpdateButtons();
					}
						
						
						
//								if (pTradingSystemMode)
//								ClosePosition();
								
				}					
					
			}
			
			
			
			IsSignalTrailWorking = false;

			int finalmssss = pTimeSlicedIntervalValue1;
			
	
			if (pTimeSlicedIntervalType == "Sec")
				finalmssss = pTimeSlicedIntervalValue2*1000;
		
			if (pTimeSlicedIntervalType == "Min")
				finalmssss = pTimeSlicedIntervalValue3*1000*60;				
		
	
     

			
			
			InProfitActionCurrentTicks = pIcebergTicksInProfitToCancel;

//			IcebergBuyID = IcebergName + "-" + BuyName + "-" + ThisInstrumment.FullName + "-" + RandomID.RandomString(10, false) + "-";
//			IcebergSellID = IcebergName + "-" + SellName + "-" + ThisInstrumment.FullName + "-" + RandomID.RandomString(10, false) + "-";
						
			TimeSlicedBuyID = TimeSlicedName + "-" + BuyName + "-" + ThisInstrumment.FullName.Replace(" ","") + "-" + RandomID.RandomString(10, false) + "-";
			TimeSlicedSellID = TimeSlicedName + "-" + SellName + "-" + ThisInstrumment.FullName.Replace(" ","") + "-" + RandomID.RandomString(10, false) + "-";
			
			
			if (ThisTimeSlicedDirection == BuyName)
			{
				

				if (TimeSlicedBuyOrderSequence != 0)
					return;
				
				
				
				
				
				TimeSlicedBuyAllOrderQty.Clear();
				TimeSlicedBuyAllOrderQty = new List<int>(RandomListQty(pLastQuantity2, pIcebergDisplayQty, pIcebergVariance));	
				
				TimeSlicedBuyAllMS.Clear();
				TimeSlicedBuyAllMS = new List<int>(RandomListTimes(TimeSlicedBuyAllOrderQty.Count-1, finalmssss, pTimeSlicedIntervalVariance));
			
				TimeSlicedBuyOrderSequence = 1;
				
				TimeSlicedBuyEntryMode = pIcebergEntryMode;		
				
				StartTimeBuyTimeSliced = DateTime.Now.AddMilliseconds(TimeSlicedBuyAllMS[TimeSlicedBuyOrderSequence]);
				
			}
			else
			{
				

				if (TimeSlicedSellOrderSequence != 0)
					return;

				
				
				
				TimeSlicedSellAllOrderQty.Clear();
				TimeSlicedSellAllOrderQty = new List<int>(RandomListQty(pLastQuantity2, pIcebergDisplayQty, pIcebergVariance));	
				
				TimeSlicedSellAllMS.Clear();
				TimeSlicedSellAllMS = new List<int>(RandomListTimes(TimeSlicedSellAllOrderQty.Count-1, finalmssss, pTimeSlicedIntervalVariance));
				
				TimeSlicedSellOrderSequence = 1;
				
				TimeSlicedSellEntryMode = pIcebergEntryMode;				
				
				StartTimeSellTimeSliced = DateTime.Now.AddMilliseconds(TimeSlicedSellAllMS[TimeSlicedSellOrderSequence]);
			}
						
			

			
		
			
			PlaceITSOrder("Time Sliced", 0, "", ThisTimeSlicedDirection);

		}

