		private void StartIcebergOrder(string ThisIcebergDirection)
		{
			
			if (!CheckNewTradeReady())
				return;
			
			if (!ITSATMOK())
				return;
			
			bool Test = false;
			
			
			if (Test) Print(ThisIcebergDirection);
			

			
			InProfitActionCurrentTicks = pIcebergTicksInProfitToCancel;

   	
			IcebergBuyID = IcebergName + "-" + BuyName + "-" + ThisInstrumment.FullName.Replace(" ","") + "-" + RandomID.RandomString(10, false) + "-";
			IcebergSellID = IcebergName + "-" + SellName + "-" + ThisInstrumment.FullName.Replace(" ","") + "-" + RandomID.RandomString(10, false) + "-";
			
			if (ThisIcebergDirection == BuyName)
			{
				

				if (IcebergBuyOrderSequence != 0)
					return;
				
				
				
				
				
				IcebergBuyAllOrderQty.Clear();
				IcebergBuyAllOrderQty = new List<int>(RandomListQty(pLastQuantity2, pIcebergDisplayQty, pIcebergVariance));		

				IcebergBuyOrderSequence = 1;
				
				IcebergBuyEntryMode = pIcebergEntryMode;					
				
			}
			else
			{
				

				if (IcebergSellOrderSequence != 0)
					return;

				
				
				
				IcebergSellAllOrderQty.Clear();
				IcebergSellAllOrderQty = new List<int>(RandomListQty(pLastQuantity2, pIcebergDisplayQty, pIcebergVariance));	
				
				IcebergSellOrderSequence = 1;
				
				IcebergSellEntryMode = pIcebergEntryMode;				
				
				
			}
						
			
			
		
			
			
			
			
			
			PlaceITSOrder("Iceberg", 0, "", ThisIcebergDirection);
			

			
		}
		
