		private void PlaceITSOrder(string syntype, int seq, string mode, string ThisIcebergDirection)
		{	
			
			string FinalEntryMode = IcebergBuyEntryMode;
			List<int> AllDisplayOrderQty = new List<int>(IcebergBuyAllOrderQty);	
			string FinalID = IcebergBuyID;
			int FinalOrderSequence = IcebergBuyOrderSequence;
			
			
			
			
			if (syntype == "Iceberg")
			{
				
					FinalEntryMode = IcebergBuyEntryMode;
					AllDisplayOrderQty = new List<int>(IcebergBuyAllOrderQty);	
					FinalID = IcebergBuyID;
					FinalOrderSequence = IcebergBuyOrderSequence;
		
				if (ThisIcebergDirection == SellName)
				{

							
					
					 FinalEntryMode = IcebergSellEntryMode;
					AllDisplayOrderQty = new List<int>(IcebergSellAllOrderQty);	
					 FinalID = IcebergSellID;
					 FinalOrderSequence = IcebergSellOrderSequence;			
					
				}				
				
			}
			else
			{
				
					 FinalEntryMode = TimeSlicedBuyEntryMode;
					AllDisplayOrderQty = new List<int>(TimeSlicedBuyAllOrderQty);	
					 FinalID = TimeSlicedBuyID;
					 FinalOrderSequence = TimeSlicedBuyOrderSequence;	
				
				if (ThisIcebergDirection == SellName)
				{
					
					 FinalEntryMode = TimeSlicedSellEntryMode;
					AllDisplayOrderQty = new List<int>(TimeSlicedSellAllOrderQty);	
					 FinalID = TimeSlicedSellID;
					 FinalOrderSequence = TimeSlicedSellOrderSequence;			
					
				}		
				
				
			}
			
		
			if (mode == "Market")
				FinalEntryMode = "Market";

			if (seq != 0)
				FinalOrderSequence = seq; 
			

			//Print(FinalOrderSequence);
			
		
			if (FinalEntryMode == "Market")
				
			{
				FinalID = FinalID + "M-";
			}
			
			
			FinalID = FinalID + FinalOrderSequence.ToString() + "-";
			//bool Test = true;
			
			int ThisNextQty = AllDisplayOrderQty[FinalOrderSequence];
			
			
			
//			Print(FinalID);
//			Print(FinalEntryMode);
//			Print(ThisIcebergDirection);
			
			

			if (!ITSATMOK())
				return;
							
			
			if (FinalEntryMode == "Market")
			{
				
//				Print("Market Entry");
				
				if (ThisIcebergDirection == BuyName)
					BuyMarket (ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID);
				else
					SellMarket (ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID);
				
			}
			else if (FinalEntryMode == "Limit")
			{
				
				bool IsMIT = pIcebergLimitOrderMode == "MIT";
				
				
				if (ThisIcebergDirection == BuyName)
				{
								
		
		
					if (pIcebergOffsetBasis == "Bid / Ask")
						IcebergEntryPrice = RTTS(CurrentAsk - pIcebergOffset*ThisTickSize);
					else if (pIcebergOffsetBasis == "Last")
						IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffset*ThisTickSize);
					else if (pIcebergOffsetBasis == "DRO")						
						IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffset*ThisTickSize);
					
					BuyLimit(ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID, IcebergEntryPrice, IsMIT, "Entry");
					
				}
				else
				{
					
					if (pIcebergOffsetBasis == "Bid / Ask")
						IcebergEntryPrice = RTTS(CurrentBid + pIcebergOffset*ThisTickSize);
					else if (pIcebergOffsetBasis == "Last")
						IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffset*ThisTickSize);
					else if (pIcebergOffsetBasis == "DRO")						
						IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffset*ThisTickSize);
					
					SellLimit(ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID, IcebergEntryPrice, IsMIT, "Entry");
					
				}
				
				
				
				
				
				
			}
			else if (FinalEntryMode == "Stop")
			{
				bool IsSLM = pIcebergStopOrderMode == "Stop Limit";
				
				if (ThisIcebergDirection == BuyName)
				{
								
		
		
					if (pIcebergOffsetBasis == "Bid / Ask")
						IcebergEntryPrice = RTTS(CurrentAsk + pIcebergOffset*ThisTickSize + ThisTickSize);
					else if (pIcebergOffsetBasis == "Last")
						IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffset*ThisTickSize + ThisTickSize);
					else if (pIcebergOffsetBasis == "DRO")						
						IcebergEntryPrice = RTTS(CurrentLastData + pIcebergOffset*ThisTickSize + ThisTickSize);
					
					
					BuyStop(ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID, IcebergEntryPrice, IsSLM, pIcebergSLOffsetReg, "Entry");

				}
				else
				{
					
					if (pIcebergOffsetBasis == "Bid / Ask")
						IcebergEntryPrice = RTTS(CurrentBid - pIcebergOffset*ThisTickSize - ThisTickSize);
					else if (pIcebergOffsetBasis == "Last")
						IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffset*ThisTickSize - ThisTickSize);
					else if (pIcebergOffsetBasis == "DRO")						
						IcebergEntryPrice = RTTS(CurrentLastData - pIcebergOffset*ThisTickSize - ThisTickSize);
					
					SellStop(ThisNextQty, atmStrategySelector.SelectedAtmStrategy, FinalID, IcebergEntryPrice, IsSLM, pIcebergSLOffsetReg, "Entry");

				}				
			}
			
			
			
	}
		
		
		
