		private void UpdateStopLoss(string Mode, double ThisPrice, bool allowmovebackward)
		{
			LogDiag("STOP_TARGET", "UpdateStopLoss", "Mode=" + Mode + ", Price=" + ThisPrice + ", AllowBackward=" + allowmovebackward);
			
		
			//Print("UpdateStopLoss");
		
			if (Mode == "BE" && ThisPositionNow() == null)
				return;

			int pBEOff = pBEOffset;
			
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;
				
				//TrackedOrders(
						OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
						OrderTypeOK = or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.StopMarket;// || or.OrderType == OrderType.;
						OrderNameOK = IsStop(or.Name);
						OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
	
		
				if (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending)
					OrderTypeOK = true;
					
//				if (OrderStateOK)
//				{
//					Print(or.OrderType);
					
//					Print("OrderTypeOK " + OrderTypeOK);
//					Print("OrderNameOK " + OrderNameOK);
//					Print("OrderInstrumentOK " + OrderInstrumentOK);
					
//				}
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
						
					
					
					
					bool OKToMove = false;
					
		
					if (Mode == "TRAIL")
						NewStopPrice = RTTS(ThisPrice);
										
					
					if (or.IsShort) // In Long Trade
					{
						if (Mode == "BE")
							NewStopPrice = RTTS(ThisPositionNow().AveragePrice + pBEOff*ThisTickSize);




//						if (Mode == "SA")
//							NewStopPrice = LongSAPrice;

						OKToMove = (Mode == "BE")
							? NewStopPrice <  GetCurrentBid() - beStopBufferTicks * ThisTickSize
							: NewStopPrice <= GetCurrentBid();

						if (UseLastPriceForClickOrders && Mode != "BE")
						{
							OKToMove = NewStopPrice <= CurrentLastData;
						}

						if (!allowmovebackward)
						if (Mode == "TRAIL")
						if (NewStopPrice <= or.StopPrice)
							OKToMove = false;

					}
					else // In Short Trade
					{
						if (Mode == "BE")
							NewStopPrice = RTTS(ThisPositionNow().AveragePrice - pBEOff*ThisTickSize);;

//						if (Mode == "SA")
//							NewStopPrice = ShortSAPrice;

						OKToMove = (Mode == "BE")
							? NewStopPrice >  GetCurrentAsk() + beStopBufferTicks * ThisTickSize
							: NewStopPrice >= GetCurrentAsk();

						if (UseLastPriceForClickOrders && Mode != "BE")
						{
							OKToMove = NewStopPrice >= CurrentLastData;
						}


						if (!allowmovebackward)
						if (Mode == "TRAIL")
						if (NewStopPrice >= or.StopPrice)
							OKToMove = false;


					}
					
						
					//Print(or.OrderUpdates.Count);
					
					StopLimitOffset = or.StopPrice - or.LimitPrice;
					NewLimitPrice = NewStopPrice - StopLimitOffset;
								
					CurrentStopPrice = or.StopPrice;
					
					if (or.LimitPrice == 0)
						NewLimitPrice = 0;
					
					
					//Print(NewStopPrice);
					
					
					
					
					
					if (NewStopPrice != 0 && OKToMove)
					{
						// Re-validate against live ask/bid right before submission to avoid
						// a stale sample landing on the gateway as InvalidPrice.
						bool stillOK = (Mode != "BE") ||
							(or.IsShort
								? NewStopPrice <  GetCurrentBid() - beStopBufferTicks * ThisTickSize
								: NewStopPrice >  GetCurrentAsk() + beStopBufferTicks * ThisTickSize);

						if (stillOK)
						{
							Order moveOrder;

							moveOrder = or;
							moveOrder.LimitPriceChanged = NewLimitPrice;
							moveOrder.StopPriceChanged = NewStopPrice;

							myAccount.Change(new[] { moveOrder });
						}
						else
						{
							LogDiag("STOP_TARGET", "UpdateStopLoss",
								"BE skipped on re-check: New=" + NewStopPrice +
								", Bid=" + GetCurrentBid() + ", Ask=" + GetCurrentAsk());
						}
							
						
							//Print(moveOrder.tra
							//RefreshRender(1113);
							
							
//							or.LimitPrice = NewLimitPrice;
//							or.StopPrice = NewStopPrice;		
							
//							myAccount.Change(new[] { or });
		
					
						
					}
					
					
					
					
					//Print(or.Name);
				}
				
			}
			
					

		}
		
		
		
		
		
		
		
		
		
		
		
		private void UpdateProfitTargets(string Mode, int pBEOffset)
		{
			LogDiag("STOP_TARGET", "UpdateProfitTargets", "Mode=" + Mode + ", BEOffset=" + pBEOffset);

			if (ThisPositionNow() == null)
				return;

			double CurrentPositionPrice = ThisPositionNow().AveragePrice;
			
			
			foreach (Order or in myAccount.Orders.ToList())
			{
				
				NewStopPrice = 0;
				
				//TrackedOrders(
						OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
						//OrderTypeOK = or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.StopMarket;
						//OrderNameOK = or.Name == "Stop1" ||  or.Name == "Stop2" ||  or.Name == "Stop3";
						OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
				
				OrderNameOK = IsTarget(or.Name);
				OrderTypeOK = true;
				
				if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
				{
						
				
				
					bool OKToMove = false;
					
					if (or.IsShort) // In Long Trade
					{
						
						
						if (Mode == "BE")
							NewLimitPrice = RTTS(CurrentPositionPrice + pBEOffset*ThisTickSize);
						
				
//						if (Mode == "SA")
//							NewStopPrice = LongSAPrice;
						
						//OKToMove = NewStopPrice <= GetCurrentBid();
						
					}
					else // In Short Trade
					{
						if (Mode == "BE")
							NewLimitPrice = RTTS(CurrentPositionPrice - pBEOffset*ThisTickSize);
						
//						if (Mode == "SA")
//							NewStopPrice = ShortSAPrice;

						//OKToMove = NewStopPrice >= GetCurrentAsk();
						
					}
					
					
					
					
//					StopLimitOffset = or.StopPrice - or.LimitPrice;
//					NewLimitPrice = NewStopPrice - StopLimitOffset;
								
//					CurrentStopPrice = or.StopPrice;
					
					
					//if (or.LimitPrice == 0)
					if (or.OrderType == OrderType.MIT || (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending))
					{
						NewStopPrice = NewLimitPrice;
						NewLimitPrice = 0;

					}

					
					OKToMove = true;
					
					

					
					if ((NewLimitPrice != 0 || NewStopPrice != 0) && OKToMove)
					{
						
						
						Order moveOrder;	
						moveOrder = or;
					

						
							if (NewLimitPrice != 0)
							moveOrder.LimitPriceChanged = NewLimitPrice;
							
							if (NewStopPrice != 0)
							moveOrder.StopPriceChanged = NewStopPrice;		
							
							myAccount.Change(new[] { moveOrder });
							
							//RefreshRender(1113);
							
							
//							or.LimitPrice = NewLimitPrice;
//							or.StopPrice = NewStopPrice;		
							
//							myAccount.Change(new[] { or });
		
		
						
					}
					
					
					
					
				}
				
			}
			
					

		}
	
