			int closeatmarketqqq = 0;
			
			 
			
		
			
			// added to cancel target orders instead of moving them
			
			if (!MoveTargetsToClose)
			{
				
				CancelStopOrders();
				targetordersqqqq = 0;
				
			}
			
			
			// everything else
			
			
			
			
			
			
			
			
			// market close
			
//			if (ThisPositionNow() != null)
