//						}							
						
//					}
					
					
	
//				}
	
//			}
			
			poss = 0;
			
			if (ThisPositionNow() != null)
			{
				poss = ThisPositionNow().Quantity;
				
				if (ThisPositionNow().MarketPosition == MarketPosition.Long)
					poss = poss*-1;
				

				
			}
			
				closeatmarketqqq = poss - targetordersqqqq;
				int totalqty = Math.Abs(closeatmarketqqq);
			
			
				//Print(closeatmarketqqq);
				
				if (closeatmarketqqq != 0)
				{
					if (pIcebergEntryOrdersEnabled && totalqty > pIcebergDisplayQty)
					{
					//	 split closing orders up into smaller orders
						
						List<int> CloseMarketOrders = new List<int>(RandomListQty (totalqty, pIcebergDisplayQty, pIcebergVariance));	
						 
						if (closeatmarketqqq < 0)
