		private void OnTimer3Tick(object sender, EventArgs e)
		{


			//return;


			//Print(ClearBackgroundTime);

			// Bound the OrderPriceToATMDisplayEnd dict by dropping expired non-sentinel
			// entries. Without this, real-price entries accumulate forever and eventually
			// overflow the .ToList() / new T[Count] allocations elsewhere.
			PruneExpiredPlanEntries();

			if (ClickedInATMTime != DateTime.MinValue)
			if (DateTime.Now >= ClickedInATMTime)
			{

				ClickedInATMTime = DateTime.MinValue;
				HoveredATMQuickSelect = null;	
				
				
			}
			
			if (ClickedMarketLimitTime != DateTime.MinValue)
			if (DateTime.Now >= ClickedMarketLimitTime)
			{

				ClickedMarketLimitTime = DateTime.MinValue;
				
			}				
			
			
			if (ClearBackgroundTime != DateTime.MinValue)
			if (DateTime.Now >= ClearBackgroundTime)
			{
				
				
				ClearBackgroundColor();
				ClearBackgroundTime = DateTime.MinValue;
			}
				
			if (ThisPositionNow() == null)
			{
				//Print("310posnull");	
				
				if (LastQtyUpdate != 0)
				{
					UpdatePNLBox();
					UpdateQTYBox();
				}
				
			}
			
					
					
					
			//SetOrderFlags();
			
		
				
			if (TestLoad)
			if (State == State.Historical)
			{
				
			
				double perc = Math.Round(BarsProcessed/BarsRemaining*100, 0);
				
				string ssss = perc + " %";
				EndLoad = DateTime.Now;
				TotalLoadTime = EndLoad.Subtract(StartLoad);
				
				if (ssss.Contains("N"))
					ssss = string.Empty;
				
				// Print(TotalLoadTime.Seconds + "." + TotalLoadTime.Milliseconds + "   " + ssss);
				//Print(BarsProcessed);
				//Print(BarsRemaining);
				//Print(ssss);
				
				
				//Draw.TextFixed(this, "infobox", ssss, TextPosition.BottomLeft);
				
				//Draw.TextFixed(this, ssss, TextPosition.BottomLeft, Brushes.Green, new Gui.Tools.SimpleFont("Arial", 25), Brushes.Transparent, Brushes.Transparent, 100);
				RefreshRender(1114);
				
				
				
			}
			
			if (AllMessages.Count > 0)
			{
				// LEAK FIX (deep-dive Finding #6): previously this loop set
				// D.Switch = false on expired entries but left them in the
				// list. Combined with RemoveMessage() (which also only flipped
				// Switch) this meant AllMessages grew monotonically for the
				// life of the session — every warning / error / info box ever
				// shown stayed in memory as a dead entry, and every render
				// frame iterated all of them to skip the Switch == false
				// ones. Now expired entries are physically removed.
				DateTime nowForExpire = DateTime.Now;
				int removedCount = AllMessages.RemoveAll(D => D.Switch == false || (D.Switch && nowForExpire >= D.ExpireTime));
				if (removedCount > 0)
					RefreshRender(1115);
			}
				
		}
		
	
		
		private bool MyAccountNull = true;
		private bool MyAccountNull2 = true;
		
		
		private void OnTimer4Tick(object sender, EventArgs e)
		{


			DateTime timerNow = DateTime.Now;

			bool Reffffff = false;

			if (timerNow > ATM1Time)
			{
				
				if (ATM1Time != DateTime.MinValue)
				{
					ATM1Clicks = 0;
					Reffffff = true;
				}
				
				ATM1Time = DateTime.MinValue;
			}
		
			if (timerNow > ATM2Time)
			{
				
				if (ATM2Time != DateTime.MinValue)
				{
					ATM2Clicks = 0;
					Reffffff = true;
				}
				
				ATM2Time = DateTime.MinValue;
			}
			
			if (timerNow > ATM3Time)
			{
				
				if (ATM3Time != DateTime.MinValue)
				{
					ATM3Clicks = 0;
					Reffffff = true;
				}
				
				ATM3Time = DateTime.MinValue;
			}
			
			if (timerNow > ATM4Time)
			{
				
				if (ATM4Time != DateTime.MinValue)
				{
					ATM4Clicks = 0;
					Reffffff = true;
				}
				
				ATM4Time = DateTime.MinValue;
			}			
			
			
			if (MyAccountNull && myAccount != null)
			{
				MyAccountNull = false;
	
				UpdateButtons();
			}
			
			
			
			if (Reffffff)
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
			{
				//Print("Reffffff = true;");
				
				
				RefreshRender(1116);

			}));
			
	
			
			//return;				
			
			if (atmStrategySelector != null)
			{
			
				
				//Print("MyAccountNull2 = " + MyAccountNull2);
				
				if (MyAccountNull2)
				{
					InitializeDefaultATM();
					if (pATMQuickButtonsEnabled && DefaultAtmStrategy.Count > 0)
						SetATMButtonLabels();
				}

					
				
				
				
			}
				
	

	
					
			if (State == State.Realtime)
				if (pBidAskEnabled)
				{
					// Legacy (hidden)
					if (ask1 != null)
						ask1.Text = ThisAsk;
					if (bid1 != null)
						bid1.Text = ThisBid;

					// ── Update Market Data Panel ──
					if (mdAskPrice != null && mdBidPrice != null)
					{
						try
						{
							if (ThisAskPrice > 0)
								mdAskPrice.Text = AllPriceMarker(ThisAskPrice);
							if (ThisBidPrice > 0)
								mdBidPrice.Text = AllPriceMarker(ThisBidPrice);

							mdAskVol.Text = ThisAskVolume > 0 ? ThisAskVolume.ToString() : "";
							mdBidVol.Text = ThisBidVolume > 0 ? ThisBidVolume.ToString() : "";

							// Spread — update only the bold-number Run so the "SPREAD: " prefix
							// and " t" suffix stay in their non-bold inline Runs.
							if (ThisAskPrice > 0 && ThisBidPrice > 0 && mdSpreadNumberRun != null)
							{
								double spreadTicks = (ThisAskPrice - ThisBidPrice) / TickSize;
								mdSpreadNumberRun.Text = spreadTicks.ToString("0.#");
							}

							// Volume bars — scale relative to max of both sides, decay max slowly
							double maxNow = Math.Max(ThisAskVolume, ThisBidVolume);
							if (maxNow > mdMaxVol)
								mdMaxVol = maxNow;
							else
								mdMaxVol = mdMaxVol * 0.995 + maxNow * 0.005; // slow decay

							if (mdMaxVol > 0 && mdAskVolBar != null && mdBidVolBar != null && mdPanel != null)
							{
								// Bar column is col2 (1* star) — use its actual width as the max fill
								double barMaxWidth = mdPanel.ColumnDefinitions.Count > 2 ? mdPanel.ColumnDefinitions[2].ActualWidth - 4 : 40;
								if (barMaxWidth < 10) barMaxWidth = 40;
								mdAskVolBar.Width = Math.Max(2, ThisAskVolume / mdMaxVol * barMaxWidth);
								mdBidVolBar.Width = Math.Max(2, ThisBidVolume / mdMaxVol * barMaxWidth);
							}
						}
						catch (Exception) { }
					}
				}
							
	
					
//			if (State == State.Realtime)
//				if (pBidAskEnabled)
//				ChartControl.Dispatcher.InvokeAsync((Action)(() =>{
						
//					if (ask1 != null)
//						ask1.Text = ThisAsk;
					
//					if (bid1 != null)
//						bid1.Text = ThisBid;
					
					
////					bid1.Height = Math.Max(ChartControl.Properties.LabelFont.Size, 12);
////					ask1.Height = Math.Max(ChartControl.Properties.LabelFont.Size, 12);
									
					
					
//					}));
				
				
					
			
			// helped with performance
			
			//return;
				
				
						
			// PERF FIX (deep-dive Round 3): these two refresh blocks fire every
			// 30 ms (~33 fps) on the timer4 tick. The first kept the chart
			// re-rendering at high frame rate whenever a time-sliced order was
			// active (for the countdown timer on the flag); the second whenever
			// the user was in any selected-orders / plot-picking state.
			// Walking away with Buy/Sell Click active or with an order selected
			// would keep the chart rendering at 33 fps for HOURS, instead of
			// idling. That sustained render rate amplifies any small per-frame
			// allocation by ~30× compared to idle, accumulating GC pressure
			// over long sessions. Throttled both to 200 ms (5 fps) — plenty
			// for a countdown / cursor hint and ~6× less CPU/GC work.
			if (TimeSlicedBuyOrderSequence != 0 || TimeSlicedSellOrderSequence != 0)
			if ((timerNow - LastTimer4TimeSlicedRefresh).TotalMilliseconds >= 200)
			{
				LastTimer4TimeSlicedRefresh = timerNow;
				ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
					RefreshRender(1117);
				}));
			}



            if (SelectedOrders.Count > 0  || SelectPlotClickEntry || SelectingPlotFor != string.Empty)
            if ((timerNow - LastTimer4PlotPickRefresh).TotalMilliseconds >= 200)
            {
                LastTimer4PlotPickRefresh = timerNow;
                ChartControl.Dispatcher.InvokeAsync((Action)(() =>
                {
                    RefreshRender(1118);
                }));
            }
			
			
			
			
		}
		
		
				
		
