		// Cycle the initial exits (stop source) type: Default -> H/L -> ATR -> Default
		// and re-apply the ATM tick overrides so targets/stops visually update.
		// Shared by the existing "Initial Exits" button and the new stop-source badge
		// drawn on the plan display.
		private void CycleInitialExitsType()
		{
			CycleInitialExitsType(false);
		}

		// liveOrderContext = true when the IE: badge was clicked on a plan that
		// belongs to a live resting order. In that case the selector-side ATM
		// mutations and ShowPlan() must be skipped: the caller re-applies the
		// new stop source to the ORDER'S own ATM at the order's entry price and
		// re-arms visibility via AddATMPlanEntry(orderEntryPrice, ...). Running
		// the selector path here would (a) mutate the user's default ATM at
		// CurrentLastData and (b) AddATMPlanEntry(10 or -10, ...) — spawning a
		// second, market-price plan on top of the live order's plan.
		private void CycleInitialExitsType(bool liveOrderContext)
		{
			if (pInitialExitsType == "Default")
				pInitialExitsType = "High / Low";
			else if (pInitialExitsType == "High / Low")
				pInitialExitsType = "ATR";
			else
				pInitialExitsType = "Default";

			if (atmStrategySelector == null || atmStrategySelector.SelectedAtmStrategy == null)
			{
				AddMessage(ATMStrategyRequiredATR, 8, Brushes.Red);
				return;
			}

			if (!liveOrderContext)
			{
				if (pInitialExitsType == "ATR" || pInitialExitsType == "High / Low")
				{
					SetAllATMTicksATR();
				}
				else
				{
					if (atmStrategySelector.SelectedIndex > 3 + NumberOfActiveStrategies())
					{
						bool ATMIS = ATMIsSame(atmStrategySelector.SelectedAtmStrategy, null);
						bool hasDrafts = AtmHasStopStrategyDrafts(atmStrategySelector.SelectedAtmStrategy);
						if (!ATMIS || hasDrafts)
						{
							ResetATMStrategyToDefault(atmStrategySelector.SelectedAtmStrategy, false, true);
							ClearStopStrategyDrafts();
							foreach (Order or in LinkedOrders.ToList())
							{
								ResetATMStrategy(or);
							}
						}
					}
				}

				// Preserve the current direction. ShowPlan("") falls through to the
				// short branch and removes the long sentinel, which made the plan
				// visually disappear when the user clicked the IE badge on a long
				// plan's stop line.
				ShowPlan(false, pLastPlanDirection);
			}

			// Sync the left-side "Initial Exits" menu button so its label and
			// on/off style reflect the new pInitialExitsType. Without this, the
			// button still shows the previous mode after cycling via the plan's
			// IE badge.
			foreach (KeyValuePair<double, ButtonZ> thisbutton in AllButtonZ3.ToList())
			{
				if (thisbutton.Value.Text == "Initial Exits")
				{
					thisbutton.Value.Switch = (pInitialExitsType != "Default");
					thisbutton.Value.Name = GetATRLabel();
				}
			}

			UpdateButtons();
		}

		// Short badge label for the current stop source mode.
		private string GetStopSourceBadge()
		{
			if (pInitialExitsType == "ATR")        return "ATR";
			if (pInitialExitsType == "High / Low") return "H/L";
			return "None";
		}

		// === ATM Stop Strategy reflection reader ===
		// NT8 attaches a StopStrategy object to each Bracket inside an AtmStrategy.
		// Property names have shifted across NT8 versions, so we read everything via
		// reflection (and try a few likely names) to stay compatible. Returns null
		// when nothing readable is present so the render code can skip drawing.

		private class AtmAutoTrailStep
		{
			public int StopLoss;
			public int ProfitTrigger;
			public int Frequency;
		}

		private class AtmStopStrategyInfo
		{
			public bool HasAutoBE;
			public int  AutoBEProfitTrigger;
			public int  AutoBEPlus;

			public List<AtmAutoTrailStep> AutoTrailSteps = new List<AtmAutoTrailStep>();
			public bool HasAutoTrail { get { return AutoTrailSteps.Count > 0; } }

			public bool HasSimulatedStop;
			public int  SimulatedStopVolume;

			// Set to true when one or more values came from a per-trade draft override
			// rather than the underlying ATM template. Used by the renderer so we can
			// flag overridden values visually (e.g., asterisk in the label).
			public bool HasDraftOverride;
		}

		// === Per-trade stop strategy drafts ===
		// When the user adjusts a stop-strategy value (Auto BE trigger, Trail step,
		// etc.) on the plan display BEFORE the trade fires, we don't want to mutate
		// the shared NT8 ATM template (that would persist across all future trades
		// using that ATM). Instead we save the modification to an in-memory "draft"
		// keyed by the ATM display name + bracket index. When the trade fires, the
		// drafts get applied to the live AtmStrategy instance via NT8's update API
		// and then cleared. While the plan is visible, the renderer overlays drafts
		// on top of the values it reads from the template so the user sees their
		// edits immediately.
		//
		// IMPORTANT: drafts are intentionally NOT persisted across plan hide/show
		// or chart reload. They are scoped to a single planning session.

		private class StopStrategyDraft
		{
			public int? AutoBEProfitTrigger;
			public int? AutoBEPlus;
			// null = use template; non-null = full override of the trail step list
			public List<AtmAutoTrailStep> TrailStepOverrides;
		}

		// Key: "<atmDisplayName>|<bracketIdx>". Bracket idx is 0-based.
		// Cleared by ClearStopStrategyDrafts() when the plan is hidden, the trade
		// is committed, or the user cancels.
		private Dictionary<string, StopStrategyDraft> _stopStrategyDrafts
			= new Dictionary<string, StopStrategyDraft>();

		// === Click-move-click state for stop-strategy markers ===
		// Set when the user clicks a stop-strategy marker (Auto BE line, Trail
		// step line). The render loop overrides the marker's price with the
		// current mouse price while this is non-null. Cleared by the next click
		// (commits the move) or by Escape / right-click / HidePlan (cancels).
		private enum MoveKind { AutoBETrigger, TrailStepTrigger }
		private class MovingStopStrategyItem
		{
			public NinjaTrader.NinjaScript.AtmStrategy Atm;
			public int BracketIdx;
			public MoveKind Kind;
			public int StepIdx;          // only meaningful for TrailStepTrigger
			public int OriginalTicks;    // pre-move value for revert
			// Cached side of trade at the moment the move started (1 long, -1 short)
			public int Mu;
			public double EntryPrice;
		}
		private MovingStopStrategyItem _movingStopStrategyItem = null;

		// Helper: convert current mouse position into a profit-trigger tick count
		// relative to the entry, clamped to >= 1. Used during a move phase.
		private int MouseToProfitTicks(double entry, int mu)
		{
			if (ThisTickSize <= 0) return 1;
			double profitPoints = (CurrentMousePrice - entry) * mu;
			int ticks = (int)Math.Round(profitPoints / ThisTickSize, 0);
			return Math.Max(1, ticks);
		}

		// Commit the currently-active move to the draft dictionary.
		private void CommitActiveStopStrategyMove()
		{
			var mv = _movingStopStrategyItem;
			if (mv == null) return;

			int newTicks = MouseToProfitTicks(mv.EntryPrice, mv.Mu);

			if (mv.Kind == MoveKind.AutoBETrigger)
			{
				SetDraftAutoBEProfitTrigger(mv.Atm, mv.BracketIdx, newTicks);
			}
			else if (mv.Kind == MoveKind.TrailStepTrigger)
			{
				// We need the current SL/Freq for this step since SetDraftTrailStep
				// replaces the full step entry. Pull them from whatever the overlay
				// reader currently returns so draft SL/Freq nudges are preserved.
				var info = ReadAtmStopStrategyInfo(mv.Atm, mv.BracketIdx);
				int sl = 0, freq = 0;
				if (info != null && mv.StepIdx >= 0 && mv.StepIdx < info.AutoTrailSteps.Count)
				{
					sl = info.AutoTrailSteps[mv.StepIdx].StopLoss;
					freq = info.AutoTrailSteps[mv.StepIdx].Frequency;
				}
				SetDraftTrailStep(mv.Atm, mv.BracketIdx, mv.StepIdx, sl, newTicks, freq);
			}

			_movingStopStrategyItem = null;
		}

		// Drop the active move without saving (Escape / right-click / HidePlan).
		private void CancelActiveStopStrategyMove()
		{
			_movingStopStrategyItem = null;
		}

		// === Dirty-marker hover tooltip ===
		// When the mouse is over a target/stop/stop-strategy marker that is
		// currently showing a "* " prefix (dirty), render a small floating box
		// near the line explaining the diff from the default template. Called
		// from the render loop once per plan after all marker rects have been
		// registered in AllATMStrategyLevelButtons.
		//
		// This method is entirely self-contained: it walks the hit rects,
		// finds the one under the mouse, figures out what changed, builds a
		// short multi-line text block, and draws a box.

		private void DrawDirtyMarkerTooltip(ChartControl chartControl, ChartScale chartScale, NinjaTrader.NinjaScript.AtmStrategy planAtm, int planMu, double planEntry, BracketDefaultLines planDefaults)
		{
			if (RenderTarget == null || planAtm == null) return;
			if (AllATMStrategyLevelButtons == null || AllATMStrategyLevelButtons.Count == 0) return;

			// === In-progress move tooltip ===
			// If a stop-strategy move is active, show a "from → to" diff against
			// the snapshot taken when the move started. This works regardless of
			// what the mouse is hovering — the tooltip anchors to the mouse rect
			// or falls back to the entry rect.
			if (_movingStopStrategyItem != null && _movingStopStrategyItem.Atm == planAtm)
			{
				try
				{
					var mv = _movingStopStrategyItem;
					int currentTicks = MouseToProfitTicks(mv.EntryPrice, mv.Mu);
					int delta = currentTicks - mv.OriginalTicks;
					string kindLabel = mv.Kind == MoveKind.AutoBETrigger
						? "Auto BE trigger"
						: ("Trail " + (mv.StepIdx + 1).ToString() + " trigger");

					var moveLines = new List<string>();
					moveLines.Add("From:    " + mv.OriginalTicks.ToString() + "t");
					moveLines.Add("To:      " + currentTicks.ToString() + "t");
					moveLines.Add("Delta:   " + (delta >= 0 ? "+" : "") + delta.ToString() + "t");
					moveLines.Add("");
					moveLines.Add("Click to commit. Right-click / Esc to cancel.");

					// Anchor to the SS_ rect for this move if we can find it.
					SharpDX.RectangleF anchor = new SharpDX.RectangleF(0, 0, 0, 0);
					string wantPrefix = mv.Kind == MoveKind.AutoBETrigger
						? ("SS_BE_" + mv.BracketIdx.ToString())
						: ("SS_Trail_" + mv.BracketIdx.ToString() + "_" + mv.StepIdx.ToString());
					foreach (var kv in AllATMStrategyLevelButtons)
					{
						if (kv.Value != null && kv.Value.Name == wantPrefix)
						{
							anchor = kv.Value.ThisRectA;
							break;
						}
					}
					DrawTooltipBox(kindLabel + " (moving)", moveLines, anchor);
					return;
				}
				catch { }
			}

			ATMMoveDetails hovered = FindHoveredButton();
			string hoverKindTag = null; // "Target" / "Stop" / "SS"
			if (hovered != null && hovered.Name != null)
			{
				if (hovered.Name.StartsWith("SS_")) hoverKindTag = "SS";
				else if (hovered.Name.StartsWith("Target ")) hoverKindTag = "Target";
				else if (hovered.Name.StartsWith("Stop ") || hovered.Name == "Stop Loss") hoverKindTag = "Stop";
			}
			if (hovered == null || hoverKindTag == null) return;

			// Build the tooltip body lines based on what's hovered.
			var lines = new List<string>();
			string header = null;

			try
			{
				if (hoverKindTag == "Target")
				{
					int bi = ParseBracketIdxFromLineName(hovered.Name);
					if (bi < 0 || planDefaults == null || bi >= planDefaults.TargetTicks.Count) return;

					double defTicks = planDefaults.TargetTicks[bi];
					// Find the current ticks by walking TargetTicksToName for a matching name.
					int nowTicks = 0;
					foreach (var t in TargetTicksToName)
					{
						if (t.Value == hovered.Name) { nowTicks = (int)t.Key; break; }
					}
					if (defTicks <= 0 || nowTicks <= 0) return;
					if ((int)defTicks == nowTicks) return; // not actually dirty

					header = hovered.Name + " (modified)";
					lines.Add("Default:  " + ((int)defTicks).ToString() + "t");
					lines.Add("Now:      " + nowTicks.ToString() + "t");
					lines.Add("Change:   " + (nowTicks - (int)defTicks >= 0 ? "+" : "") + (nowTicks - (int)defTicks).ToString() + "t");
				}
				else if (hoverKindTag == "Stop")
				{
					int bi = ParseBracketIdxFromLineName(hovered.Name);

					// Find the current ticks.
					int nowTicks = 0;
					foreach (var t in StopTicksToName)
					{
						if (t.Value == hovered.Name) { nowTicks = (int)t.Key; break; }
					}
					if (nowTicks <= 0) return;

					// Default ticks — only meaningful for a per-bracket line.
					int defTicks = 0;
					if (bi >= 0 && planDefaults != null && bi < planDefaults.StopTicks.Count)
						defTicks = (int)planDefaults.StopTicks[bi];

					bool linesDiffer = (defTicks > 0 && defTicks != nowTicks);

					// Also look up the bracket-level draft (Auto BE, trail).
					StopStrategyDraft draft = null;
					if (bi >= 0)
						draft = TryGetDraft(planAtm, bi);

					bool haveDraftChanges = draft != null && (draft.AutoBEProfitTrigger.HasValue || draft.AutoBEPlus.HasValue || draft.TrailStepOverrides != null);

					if (!linesDiffer && !haveDraftChanges) return; // not actually dirty

					header = hovered.Name + " (modified)";
					if (defTicks > 0)
					{
						lines.Add("Default:  " + defTicks.ToString() + "t");
						lines.Add("Now:      " + nowTicks.ToString() + "t");
						if (defTicks != nowTicks)
							lines.Add("Change:   " + (nowTicks - defTicks >= 0 ? "+" : "") + (nowTicks - defTicks).ToString() + "t");
					}

					// Include stop-strategy diffs on this bracket.
					if (bi >= 0)
					{
						var ssDiffs = BuildStopStrategyDiffLines(planAtm, bi);
						if (ssDiffs != null && ssDiffs.Count > 0)
						{
							if (lines.Count > 0) lines.Add("");
							lines.Add("Stop strategy:");
							foreach (var d in ssDiffs) lines.Add("  " + d);
						}
					}
				}
				else if (hoverKindTag == "SS")
				{
					// SS_BE_<bi>, SS_Trail_<bi>_<si>, SS_Sim_<bi>
					int bi;
					if (!ParseStopStrategyBracketIdx(hovered.Name, out bi)) return;

					var ssDiffs = BuildStopStrategyDiffLines(planAtm, bi);
					if (ssDiffs == null || ssDiffs.Count == 0) return;

					header = "Stop strategy (modified)";
					foreach (var d in ssDiffs) lines.Add(d);
				}
			}
			catch { return; }

			if (lines.Count == 0 || header == null) return;

			// Render the box near the mouse.
			DrawTooltipBox(header, lines, hovered.ThisRectA);
		}

		// Build a list of "<field>  <default>  →  <now>" strings describing how
		// the ATM's stop strategy for a specific bracket has been modified,
		// combining both template-mutation changes and pending drafts.
		private List<string> BuildStopStrategyDiffLines(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			var result = new List<string>();
			if (atm == null) return result;
			try
			{
				// "Default" = what the saved DefaultAtmStrategy clone holds.
				// "Now"     = what ReadAtmStopStrategyInfo returns (template + drafts).
				if (DefaultAtmStrategy == null) return result;
				string name = atm.DisplayName;
				if (string.IsNullOrEmpty(name) || !DefaultAtmStrategy.ContainsKey(name)) return result;
				var defAtm = DefaultAtmStrategy[name];
				if (defAtm == null) return result;

				var defInfo = ReadAtmStopStrategyTemplate(defAtm, bracketIdx);
				var nowInfo = ReadAtmStopStrategyInfo(atm, bracketIdx);
				if (defInfo == null && nowInfo == null) return result;

				// Auto BE
				int defBeT = defInfo != null ? defInfo.AutoBEProfitTrigger : 0;
				int nowBeT = nowInfo != null ? nowInfo.AutoBEProfitTrigger : 0;
				if (defBeT != nowBeT && (defBeT > 0 || nowBeT > 0))
					result.Add("Auto BE trigger  " + defBeT.ToString() + "t  →  " + nowBeT.ToString() + "t");

				int defBeP = defInfo != null ? defInfo.AutoBEPlus : 0;
				int nowBeP = nowInfo != null ? nowInfo.AutoBEPlus : 0;
				if (defBeP != nowBeP)
					result.Add("Auto BE plus     " + defBeP.ToString() + "t  →  " + nowBeP.ToString() + "t");

				// Trail steps — walk in parallel up to max(count).
				int defCount = defInfo != null ? defInfo.AutoTrailSteps.Count : 0;
				int nowCount = nowInfo != null ? nowInfo.AutoTrailSteps.Count : 0;
				int maxCount = Math.Max(defCount, nowCount);
				for (int i = 0; i < maxCount; i++)
				{
					int defPt = i < defCount ? defInfo.AutoTrailSteps[i].ProfitTrigger : 0;
					int nowPt = i < nowCount ? nowInfo.AutoTrailSteps[i].ProfitTrigger : 0;
					int defSl = i < defCount ? defInfo.AutoTrailSteps[i].StopLoss      : 0;
					int nowSl = i < nowCount ? nowInfo.AutoTrailSteps[i].StopLoss      : 0;
					int defFq = i < defCount ? defInfo.AutoTrailSteps[i].Frequency     : 0;
					int nowFq = i < nowCount ? nowInfo.AutoTrailSteps[i].Frequency     : 0;

					string lbl = "Trail " + (i + 1).ToString();
					if (defPt != nowPt) result.Add(lbl + " trigger    " + defPt.ToString() + "t  →  " + nowPt.ToString() + "t");
					if (defSl != nowSl) result.Add(lbl + " stop       " + defSl.ToString() + "t  →  " + nowSl.ToString() + "t");
					if (defFq != nowFq) result.Add(lbl + " freq       " + defFq.ToString() + "t  →  " + nowFq.ToString() + "t");
				}

				// Simulated stop
				if (defInfo != null && nowInfo != null)
				{
					if (defInfo.HasSimulatedStop != nowInfo.HasSimulatedStop ||
						defInfo.SimulatedStopVolume != nowInfo.SimulatedStopVolume)
					{
						result.Add("Sim stop vol    " + defInfo.SimulatedStopVolume.ToString() + "  →  " + nowInfo.SimulatedStopVolume.ToString());
					}
				}
			}
			catch { }
			return result;
		}

		// Draw a small tooltip box containing a header line and body lines.
		// Positioned near anchorRect so it doesn't cover the line being described.
		private void DrawTooltipBox(string header, List<string> body, SharpDX.RectangleF anchorRect)
		{
			if (RenderTarget == null || CellFormat == null) return;

			// Measure the widest line so we can size the box.
			float maxW = 0, totalH = 0;
			float lineGap = 2;

			// LEAK FIX (deep-dive Finding #10): allocate the TextLayouts INSIDE
			// the try so that any exception between the first alloc and the
			// finally still releases everything. Previously the try block
			// started AFTER the layouts were allocated, so a DirectWrite throw
			// during measurement leaked them.
			SharpDX.DirectWrite.TextLayout hLayout = null;
			List<SharpDX.DirectWrite.TextLayout> bodyLayouts = new List<SharpDX.DirectWrite.TextLayout>();
			try
			{
				hLayout = new SharpDX.DirectWrite.TextLayout(NinjaTrader.Core.Globals.DirectWriteFactory, header, CellFormat, 10000, 10000);
				maxW = Math.Max(maxW, hLayout.Metrics.Width);
				totalH += hLayout.Metrics.Height;

				foreach (var line in body)
				{
					var bl = new SharpDX.DirectWrite.TextLayout(NinjaTrader.Core.Globals.DirectWriteFactory, line, CellFormat, 10000, 10000);
					bodyLayouts.Add(bl);
					maxW = Math.Max(maxW, bl.Metrics.Width);
					totalH += bl.Metrics.Height + lineGap;
				}

				float padX = 6, padY = 4;
				float boxW = maxW + padX * 2;
				float boxH = totalH + padY * 2 + lineGap;

				// Position: prefer just above the anchor rect, shifted right a bit.
				// Clamp so the box stays inside the chart panel.
				float boxX = anchorRect.Left + 12;
				float boxY = anchorRect.Top - boxH - 4;
				if (boxY < ChartPanel.Y + 2) boxY = anchorRect.Bottom + 4; // below if no room above
				if (boxX + boxW > ChartPanel.X + ChartPanel.W - 2)
					boxX = ChartPanel.X + ChartPanel.W - boxW - 2;
				if (boxX < ChartPanel.X + 2) boxX = ChartPanel.X + 2;

				var boxRect = new SharpDX.RectangleF(boxX, boxY, boxW, boxH);

				// Collision avoidance: if the box overlaps the anchor rect (the
				// thing it's describing), shift it vertically away from the
				// anchor so the user can still see what they're hovering. Try
				// the opposite vertical side first; if that also collides,
				// fall back to the original position. Done after clamping so
				// horizontal clamping is preserved.
				bool overlapsAnchor =
					boxRect.Right > anchorRect.Left && boxRect.Left < anchorRect.Right &&
					boxRect.Bottom > anchorRect.Top && boxRect.Top < anchorRect.Bottom;
				if (overlapsAnchor && anchorRect.Width > 0 && anchorRect.Height > 0)
				{
					float altBoxY = (boxY < anchorRect.Top)
						? anchorRect.Bottom + 4   // tooltip was above; flip below
						: anchorRect.Top - boxH - 4; // tooltip was below; flip above
					// Only accept the flip if it stays inside the chart panel.
					if (altBoxY >= ChartPanel.Y + 2 && altBoxY + boxH <= ChartPanel.Y + ChartPanel.H - 2)
					{
						boxY = altBoxY;
						boxRect = new SharpDX.RectangleF(boxX, boxY, boxW, boxH);
					}
				}

				// Box background + border.
				SafeFillRectangle(boxRect, ChartBackgroundBrushDX);
				SafeFillRectangle(boxRect, ChartBackgroundShade1BrushDX);
				var stratStroke = GetStopStrategyStrokeSafe();
				SharpDX.Direct2D1.Brush borderBrush = stratStroke != null ? stratStroke.BrushDX : ChartTextBrushDX;
				if (borderBrush != null)
					SafeDrawRectangle(boxRect, borderBrush, 1f);

				// Header: small y offset then each body line below.
				var oldAA = RenderTarget.AntialiasMode;
				RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

				float y = boxY + padY;
				var headerRect = new SharpDX.RectangleF(boxX + padX, y, maxW, hLayout.Metrics.Height);
				SafeDrawText(header, CellFormat, headerRect, (borderBrush ?? ChartTextBrushDX));
				y += hLayout.Metrics.Height + lineGap;

				for (int i = 0; i < body.Count; i++)
				{
					var bl = bodyLayouts[i];
					var r = new SharpDX.RectangleF(boxX + padX, y, maxW, bl.Metrics.Height);
					SafeDrawText(body[i], CellFormat, r, ChartTextBrushDX);
					y += bl.Metrics.Height + lineGap;
				}

				RenderTarget.AntialiasMode = oldAA;
			}
			catch { }
			finally
			{
				if (hLayout != null) { try { hLayout.Dispose(); } catch { } }
				foreach (var bl in bodyLayouts) { try { bl.Dispose(); } catch { } }
			}
		}

		// === Centralized hit-test ===
		// Finds the highest-priority button currently under the mouse. Used by
		// click routing, hover detection, and the dirty-marker tooltip — three
		// systems that previously walked AllATMStrategyLevelButtons separately
		// and could disagree on which button "won" in overlapping rects.
		//
		// Iteration is by Priority descending; ties broken by insertion order
		// (later inserts win, since they were drawn on top).
		private ATMMoveDetails FindHoveredButton()
		{
			if (AllATMStrategyLevelButtons == null || AllATMStrategyLevelButtons.Count == 0)
				return null;

			ATMMoveDetails best = null;
			int bestPriority = int.MinValue;
			double bestSeq = double.MinValue;

			foreach (var kv in AllATMStrategyLevelButtons)
			{
				var btn = kv.Value;
				if (btn == null) continue;
				if (!MouseIn(btn.ThisRectA, 0, 0)) continue;

				if (btn.Priority > bestPriority ||
					(btn.Priority == bestPriority && kv.Key > bestSeq))
				{
					best = btn;
					bestPriority = btn.Priority;
					bestSeq = kv.Key;
				}
			}
			return best;
		}

		// Backwards-compat wrapper. Returns the hovered button only if it's
		// a stop-strategy marker (SS_BE_*, SS_Trail_*, SS_Sim_*).
		private ATMMoveDetails FindHoveredStopStrategyButton()
		{
			var hit = FindHoveredButton();
			if (hit != null && hit.Name != null && hit.Name.StartsWith("SS_"))
				return hit;
			return null;
		}

		// Parse an SS_* rect name into (kind, stepIdx). Returns false if the
		// name is not a recognized stop-strategy rect name.
		//   "SS_BE_<bracketIdx>"              → AutoBETrigger, stepIdx = -1
		//   "SS_Trail_<bracketIdx>_<stepIdx>" → TrailStepTrigger, stepIdx = <stepIdx>
		//   "SS_Sim_<bracketIdx>"             → not editable, returns false
		private bool ParseStopStrategyRectName(string name, out MoveKind kind, out int stepIdx)
		{
			kind = MoveKind.AutoBETrigger;
			stepIdx = -1;
			if (string.IsNullOrEmpty(name)) return false;
			if (name.StartsWith("SS_BE_"))
			{
				kind = MoveKind.AutoBETrigger;
				return true;
			}
			if (name.StartsWith("SS_Trail_"))
			{
				kind = MoveKind.TrailStepTrigger;
				// Format: SS_Trail_<bracketIdx>_<stepIdx>
				int lastUnderscore = name.LastIndexOf('_');
				if (lastUnderscore < 0) return false;
				string tail = name.Substring(lastUnderscore + 1);
				int parsed;
				if (!int.TryParse(tail, out parsed)) return false;
				stepIdx = parsed;
				return true;
			}
			return false;
		}

		// Parse the bracket index from any SS_* rect name.
		//   "SS_BE_0"       → 0
		//   "SS_Trail_1_2"  → 1
		//   "SS_Sim_0"      → 0
		private bool ParseStopStrategyBracketIdx(string name, out int bracketIdx)
		{
			bracketIdx = -1;
			if (string.IsNullOrEmpty(name)) return false;
			try
			{
				if (name.StartsWith("SS_BE_"))
				{
					return int.TryParse(name.Substring("SS_BE_".Length), out bracketIdx);
				}
				if (name.StartsWith("SS_Sim_"))
				{
					return int.TryParse(name.Substring("SS_Sim_".Length), out bracketIdx);
				}
				if (name.StartsWith("SS_Trail_"))
				{
					// Format: SS_Trail_<bi>_<si>
					string rest = name.Substring("SS_Trail_".Length);
					int us = rest.IndexOf('_');
					if (us <= 0) return false;
					return int.TryParse(rest.Substring(0, us), out bracketIdx);
				}
			}
			catch { }
			return false;
		}

		// Clear the draft for a single marker (right-click on a marker that is
		// NOT currently being moved). Preserves drafts on sibling markers.
		private void ResetDraftForMarker(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx, MoveKind kind, int stepIdx)
		{
			if (atm == null) return;
			var d = TryGetDraft(atm, bracketIdx);
			if (d == null) return;

			if (kind == MoveKind.AutoBETrigger)
			{
				d.AutoBEProfitTrigger = null;
				d.AutoBEPlus = null;
			}
			else if (kind == MoveKind.TrailStepTrigger)
			{
				if (d.TrailStepOverrides != null && stepIdx >= 0 && stepIdx < d.TrailStepOverrides.Count)
				{
					// Null-out this step by clearing its overrides. Easiest approach:
					// set the step to zero values so the render-time overlay's
					// "if > 0" filter drops it. If every step is zero, wipe the list.
					d.TrailStepOverrides[stepIdx] = new AtmAutoTrailStep();
					bool anyRealLeft = false;
					foreach (var s in d.TrailStepOverrides)
					{
						if (s.StopLoss > 0 || s.ProfitTrigger > 0 || s.Frequency > 0) { anyRealLeft = true; break; }
					}
					if (!anyRealLeft) d.TrailStepOverrides = null;
				}
			}

			// If the whole draft is now empty, drop the key entirely.
			if (d.AutoBEProfitTrigger == null && d.AutoBEPlus == null && d.TrailStepOverrides == null)
			{
				string k = DraftKey(atm, bracketIdx);
				if (k != null) _stopStrategyDrafts.Remove(k);
			}
		}

		private string DraftKey(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			if (atm == null) return null;
			string name = null;
			try { name = atm.DisplayName; } catch { }
			if (string.IsNullOrEmpty(name)) name = "?";
			return name + "|" + bracketIdx.ToString();
		}

		private StopStrategyDraft GetOrCreateDraft(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			string k = DraftKey(atm, bracketIdx);
			if (k == null) return null;
			StopStrategyDraft d;
			if (!_stopStrategyDrafts.TryGetValue(k, out d))
			{
				d = new StopStrategyDraft();
				_stopStrategyDrafts[k] = d;
			}
			return d;
		}

		private StopStrategyDraft TryGetDraft(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			string k = DraftKey(atm, bracketIdx);
			if (k == null) return null;
			StopStrategyDraft d;
			return _stopStrategyDrafts.TryGetValue(k, out d) ? d : null;
		}

		// Stub setters — future click/drag handlers will call these to mutate the
		// draft. They do NOT touch the underlying NT8 ATM template.
		private void SetDraftAutoBEProfitTrigger(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx, int value)
		{
			var d = GetOrCreateDraft(atm, bracketIdx);
			if (d == null) return;
			d.AutoBEProfitTrigger = Math.Max(0, value);
		}

		private void SetDraftAutoBEPlus(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx, int value)
		{
			var d = GetOrCreateDraft(atm, bracketIdx);
			if (d == null) return;
			d.AutoBEPlus = value;
		}

		private void SetDraftTrailStep(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx, int stepIdx, int stopLoss, int profitTrigger, int frequency)
		{
			var d = GetOrCreateDraft(atm, bracketIdx);
			if (d == null) return;
			if (d.TrailStepOverrides == null)
				d.TrailStepOverrides = new List<AtmAutoTrailStep>();
			while (d.TrailStepOverrides.Count <= stepIdx)
				d.TrailStepOverrides.Add(new AtmAutoTrailStep());
			d.TrailStepOverrides[stepIdx].StopLoss = stopLoss;
			d.TrailStepOverrides[stepIdx].ProfitTrigger = profitTrigger;
			d.TrailStepOverrides[stepIdx].Frequency = frequency;
		}

		// Wipe all per-trade drafts. Called when the plan is hidden or the trade
		// fires (after drafts are applied to the live ATM).
		private void ClearStopStrategyDrafts()
		{
			_stopStrategyDrafts.Clear();
		}

		// ─── ATM CalculationMode unit conversion helpers ─────────────────────
		// NinjaTrader's AtmStrategy stores Bracket.StopLoss / Bracket.Target in
		// the units selected by CalculationMode (Ticks / Currency / Percent /
		// Pips / Price). The render and qty-calc paths in this indicator work
		// in TICK space, so every read of bb.StopLoss / bb.Target needs to be
		// normalized to ticks, and every write of a tick value needs to be
		// converted back to native units. Use these helpers everywhere.

		// Standard pip size for the current instrument's tick size. Forex
		// 5-decimal pairs (tick=0.00001) and 3-decimal JPY pairs (tick=0.001)
		// have 10 ticks per pip; legacy 4-decimal / 2-decimal use 1 tick per
		// pip. Non-forex falls through to 1 tick per pip (Pips mode is rarely
		// used outside forex but the conversion stays sensible).
		private double GetTicksPerPip()
		{
			if (ThisTickSize <= 0) return 1.0;
			double pipSize = ThisTickSize >= 0.005 ? 0.01 : 0.0001;
			double tpp = pipSize / ThisTickSize;
			return tpp < 1.0 ? 1.0 : Math.Round(tpp);
		}

		// Convert a Bracket.StopLoss or Bracket.Target value from its native
		// CalculationMode units into ticks. entryPrice is only consulted when
		// the strategy is in Percent mode. Returns 0 if the conversion is not
		// computable (missing tick size, missing entry, etc.) so the caller
		// gets a safe falsy value instead of NaN/Infinity.
		private double BracketUnitsToTicks(double bracketValue, NinjaTrader.NinjaScript.AtmStrategy atm, double entryPrice)
		{
			if (atm == null) return bracketValue;
			switch (atm.CalculationMode)
			{
				case CalculationMode.Currency:
					if (ThisTickDollars <= 0) return 0;
					return Math.Round(bracketValue / ThisTickDollars, 0);
				case CalculationMode.Percent:
					if (ThisTickSize <= 0 || entryPrice <= 0) return 0;
					return Math.Round(entryPrice * bracketValue / 100.0 / ThisTickSize, 0);
				case CalculationMode.Pips:
					return Math.Round(bracketValue * GetTicksPerPip(), 0);
				case CalculationMode.Price:
					if (ThisTickSize <= 0) return 0;
					return Math.Round(bracketValue / ThisTickSize, 0);
				case CalculationMode.Ticks:
				default:
					return bracketValue;
			}
		}

		// Inverse of BracketUnitsToTicks: given a tick distance, produce the
		// native value to assign to Bracket.StopLoss / Bracket.Target so the
		// stop/target effectively equals that many ticks. entryPrice is only
		// consulted in Percent mode.
		private double TicksToBracketUnits(double ticks, NinjaTrader.NinjaScript.AtmStrategy atm, double entryPrice)
		{
			if (atm == null) return ticks;
			switch (atm.CalculationMode)
			{
				case CalculationMode.Currency:
					return ticks * ThisTickDollars;
				case CalculationMode.Percent:
					if (entryPrice <= 0) return 0;
					return ticks * ThisTickSize / entryPrice * 100.0;
				case CalculationMode.Pips:
				{
					double tpp = GetTicksPerPip();
					return tpp > 0 ? ticks / tpp : ticks;
				}
				case CalculationMode.Price:
					return ticks * ThisTickSize;
				case CalculationMode.Ticks:
				default:
					return ticks;
			}
		}

		// Snapshot of a bracket's target/stop tick distances, cached per plan frame
		// so we don't have to recompute it once per target and once per stop inside
		// the render loops. Built from DefaultAtmStrategy[name] if available, else
		// left empty (no dirty detection possible).
		private class BracketDefaultLines
		{
			// Per-bracket tick distance for the target and stop. Indices align
			// with atm.Brackets[i] by position, so "Target 1" = TargetTicks[0].
			public List<double> TargetTicks = new List<double>();
			public List<double> StopTicks = new List<double>();
		}

		// Build BracketDefaultLines from the saved default ATM clone. Handles
		// every CalculationMode (Ticks, Currency, Percent, Pips, Price) via
		// BracketUnitsToTicks so default ticks can be compared against current
		// ticks in the render loop (which runs in tick-space regardless of
		// source calc mode).
		private BracketDefaultLines GetBracketDefaultLines(NinjaTrader.NinjaScript.AtmStrategy currentAtm)
		{
			var result = new BracketDefaultLines();
			if (currentAtm == null) return result;
			try
			{
				string name = currentAtm.DisplayName;
				if (string.IsNullOrEmpty(name)) return result;
				if (DefaultAtmStrategy == null || !DefaultAtmStrategy.ContainsKey(name))
					return result;

				var def = DefaultAtmStrategy[name];
				if (def == null || def.Brackets == null) return result;

				double entryRef = CurrentLastData; // used only by Percent mode

				foreach (var bb in def.Brackets)
				{
					if (bb == null)
					{
						result.TargetTicks.Add(0);
						result.StopTicks.Add(0);
						continue;
					}

					result.TargetTicks.Add(BracketUnitsToTicks(bb.Target,   def, entryRef));
					result.StopTicks.Add  (BracketUnitsToTicks(bb.StopLoss, def, entryRef));
				}
			}
			catch { }
			return result;
		}

		// Parse "Target 1" / "Target 1/2/3" / "Stop Loss" into a 0-based bracket
		// index. "Stop Loss" indicates a merged single-stop entry and returns -1.
		private int ParseBracketIdxFromLineName(string name)
		{
			if (string.IsNullOrEmpty(name)) return -1;
			if (name == "Stop Loss") return -1;

			string prefix = null;
			if (name.StartsWith("Target ")) prefix = "Target ";
			else if (name.StartsWith("Stop "))   prefix = "Stop ";
			if (prefix == null) return -1;

			string rest = name.Substring(prefix.Length);
			int slash = rest.IndexOf('/');
			string firstNum = slash > 0 ? rest.Substring(0, slash) : rest;
			int n;
			if (int.TryParse(firstNum, out n) && n > 0) return n - 1;
			return -1;
		}

		// Are there any per-trade stop-strategy drafts for the given ATM?
		// Used by the reset-button UI so that pending draft edits show as
		// "not default" even if the underlying template values haven't changed.
		private bool AtmHasStopStrategyDrafts(NinjaTrader.NinjaScript.AtmStrategy atm)
		{
			if (atm == null || _stopStrategyDrafts == null || _stopStrategyDrafts.Count == 0)
				return false;
			try
			{
				string prefix = (atm.DisplayName ?? "?") + "|";
				foreach (var k in _stopStrategyDrafts.Keys)
				{
					if (k != null && k.StartsWith(prefix))
					{
						var d = _stopStrategyDrafts[k];
						if (d == null) continue;
						if (d.AutoBEProfitTrigger.HasValue) return true;
						if (d.AutoBEPlus.HasValue)         return true;
						if (d.TrailStepOverrides != null && d.TrailStepOverrides.Count > 0) return true;
					}
				}
			}
			catch { }
			return false;
		}

		// TODO: ApplyStopStrategyDraftsToLiveAtm — called from the order-fill flow
		// once an ATM strategy instance is live for the trade. Walks _stopStrategyDrafts
		// and pushes each value into the running ATM via NT8's
		// AtmStrategy.ChangeStopTarget / direct StopStrategy mutation paths. Stub
		// for now — will be wired when the click/drag UI lands.

		// Cache the reflection lookups so we don't pay PropertyInfo / FieldInfo cost
		// every render frame. Keyed by Type so multiple ATMs share the lookups.
		private Dictionary<Type, System.Reflection.PropertyInfo[]> _ssPropCache
			= new Dictionary<Type, System.Reflection.PropertyInfo[]>();

		private object SsRead(object obj, params string[] names)
		{
			if (obj == null) return null;
			var t = obj.GetType();
			System.Reflection.PropertyInfo[] props;
			if (!_ssPropCache.TryGetValue(t, out props))
			{
				props = t.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
				_ssPropCache[t] = props;
			}
			foreach (var n in names)
			{
				foreach (var p in props)
				{
					if (p.Name == n)
					{
						try { return p.GetValue(obj, null); } catch { return null; }
					}
				}
			}
			// fallback: try fields (public + non-public)
			try
			{
				foreach (var n in names)
				{
					var f = t.GetField(n, System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.NonPublic);
					if (f != null) return f.GetValue(obj);
				}
			}
			catch { }
			return null;
		}

		private int SsReadInt(object obj, params string[] names)
		{
			object v = SsRead(obj, names);
			if (v == null) return 0;
			try { return Convert.ToInt32(v); } catch { return 0; }
		}

		private bool SsReadBool(object obj, params string[] names)
		{
			object v = SsRead(obj, names);
			if (v == null) return false;
			try { return Convert.ToBoolean(v); } catch { return false; }
		}

		// Mirror-write helpers: set a property/field via reflection using the
		// first matching name. Returns true on success. Used by the drafts
		// commit path to push user edits into a live AtmStrategy template.
		private bool SsWrite(object obj, object value, params string[] names)
		{
			if (obj == null) return false;
			var t = obj.GetType();
			System.Reflection.PropertyInfo[] props;
			if (!_ssPropCache.TryGetValue(t, out props))
			{
				props = t.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
				_ssPropCache[t] = props;
			}
			foreach (var n in names)
			{
				foreach (var p in props)
				{
					if (p.Name == n && p.CanWrite)
					{
						try
						{
							object converted = Convert.ChangeType(value, p.PropertyType);
							p.SetValue(obj, converted, null);
							return true;
						}
						catch { }
					}
				}
			}
			// Fallback to fields (public + non-public instance)
			try
			{
				foreach (var n in names)
				{
					var f = t.GetField(n, System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.NonPublic);
					if (f != null)
					{
						object converted = Convert.ChangeType(value, f.FieldType);
						f.SetValue(obj, converted);
						return true;
					}
				}
			}
			catch { }
			return false;
		}

		private bool SsWriteInt(object obj, int value, params string[] names)
		{
			return SsWrite(obj, value, names);
		}

		// Read RAW template values from atm.Brackets[bracketIdx].StopStrategy via
		// reflection with no draft overlay. Returns an info object even if all
		// values are zero — the snapshot-and-restore path needs to preserve
		// "no-value" states so we can write them back on restore. Includes
		// zero-value trail steps so the step index aligns across reads.
		private AtmStopStrategyInfo ReadAtmStopStrategyTemplate(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			var info = new AtmStopStrategyInfo();
			if (atm == null) return info;
			try
			{
				if (atm.Brackets == null || atm.Brackets.Length == 0) return info;
				if (bracketIdx < 0 || bracketIdx >= atm.Brackets.Length) return info;
				var bb = atm.Brackets[bracketIdx];
				if (bb == null) return info;

				object ss = null;
				try
				{
					var ssProp = bb.GetType().GetProperty("StopStrategy");
					if (ssProp != null) ss = ssProp.GetValue(bb, null);
				}
				catch { }
				if (ss == null) return info;

				// --- Auto Breakeven ---
				int beTrigger = SsReadInt(ss, "AutoBreakEvenProfitTrigger", "BreakEvenProfitTrigger", "AutoBreakevenProfitTrigger");
				int bePlus    = SsReadInt(ss, "AutoBreakEvenPlus", "BreakEvenPlus", "AutoBreakevenPlus");
				bool beEnabled = beTrigger > 0
					|| SsReadBool(ss, "IsAutoBreakEvenEnabled", "AutoBreakEvenEnabled", "IsAutoBreakeven", "BreakEvenEnabled");
				info.AutoBEProfitTrigger = beTrigger;
				info.AutoBEPlus = bePlus;
				info.HasAutoBE = beEnabled && beTrigger > 0;

				// --- Auto Trail steps (keep zero-value entries so indices align) ---
				object trailColl = SsRead(ss, "AutoTrails", "AutoTrailSteps", "TrailSteps", "AutoTrailStops");
				if (trailColl is System.Collections.IEnumerable)
				{
					foreach (var step in (System.Collections.IEnumerable)trailColl)
					{
						if (step == null) { info.AutoTrailSteps.Add(new AtmAutoTrailStep()); continue; }
						int sl   = SsReadInt(step, "StopLoss", "Stop", "StopTicks");
						int pt   = SsReadInt(step, "ProfitTrigger", "Trigger", "ProfitTriggerTicks");
						int freq = SsReadInt(step, "Frequency", "FrequencyTicks", "Freq");
						info.AutoTrailSteps.Add(new AtmAutoTrailStep { StopLoss = sl, ProfitTrigger = pt, Frequency = freq });
					}
				}

				// --- Simulated stop ---
				bool simEnabled = SsReadBool(ss, "IsSimulatedStop", "SimulatedStopEnabled", "IsSimulatedStopEnabled");
				int  simVolume  = SsReadInt(ss, "SimulatedStopVolumeTrigger", "SimulatedStopVolume", "VolumeTrigger");
				info.SimulatedStopVolume = simVolume;
				info.HasSimulatedStop = simEnabled && simVolume > 0;
			}
			catch { }
			return info;
		}

		// Read template + overlay per-trade draft modifications. Returns null if
		// no displayable values remain after overlay — the render path uses this.
		private AtmStopStrategyInfo ReadAtmStopStrategyInfo(NinjaTrader.NinjaScript.AtmStrategy atm, int bracketIdx)
		{
			try
			{
				var info = ReadAtmStopStrategyTemplate(atm, bracketIdx);
				if (info == null) return null;

				// Strip zero-value trail steps for render purposes (template keeps
				// them around for snapshot, but the marker block only renders real).
				var realSteps = new List<AtmAutoTrailStep>();
				foreach (var s in info.AutoTrailSteps)
				{
					if (s.StopLoss > 0 || s.ProfitTrigger > 0 || s.Frequency > 0)
						realSteps.Add(s);
				}
				info.AutoTrailSteps = realSteps;

				// --- Overlay per-trade draft modifications, if any ---
				var draft = TryGetDraft(atm, bracketIdx);
				if (draft != null)
				{
					if (draft.AutoBEProfitTrigger.HasValue)
					{
						info.AutoBEProfitTrigger = draft.AutoBEProfitTrigger.Value;
						info.HasAutoBE = info.AutoBEProfitTrigger > 0;
						info.HasDraftOverride = true;
					}
					if (draft.AutoBEPlus.HasValue)
					{
						info.AutoBEPlus = draft.AutoBEPlus.Value;
						info.HasDraftOverride = true;
					}
					if (draft.TrailStepOverrides != null)
					{
						info.AutoTrailSteps = new List<AtmAutoTrailStep>();
						foreach (var s in draft.TrailStepOverrides)
						{
							if (s.StopLoss > 0 || s.ProfitTrigger > 0 || s.Frequency > 0)
								info.AutoTrailSteps.Add(new AtmAutoTrailStep { StopLoss = s.StopLoss, ProfitTrigger = s.ProfitTrigger, Frequency = s.Frequency });
						}
						info.HasDraftOverride = true;
					}
				}

				if (!info.HasAutoBE && !info.HasAutoTrail && !info.HasSimulatedStop)
					return null;

				return info;
			}
			catch
			{
				return null;
			}
		}

		// === Snapshot + apply + restore path ===
		// Template-mutate with snapshot-and-restore. Walks all brackets, snapshots
		// each bracket's StopStrategy values via ReadAtmStopStrategyTemplate, then
		// pushes draft values into the live template via reflection write. The
		// caller submits the ATM inside a try and restores inside a finally, so
		// the user's saved ATM template is guaranteed to be unmodified after the
		// commit returns — even if StartAtmStrategy throws.
		private class StopStrategySnapshot
		{
			public NinjaTrader.NinjaScript.AtmStrategy Atm;
			public Dictionary<int, AtmStopStrategyInfo> PerBracket = new Dictionary<int, AtmStopStrategyInfo>();
		}

		private StopStrategySnapshot ApplyStopStrategyDraftsToLiveAtm(NinjaTrader.NinjaScript.AtmStrategy atm)
		{
			var snap = new StopStrategySnapshot { Atm = atm };
			if (atm == null || atm.Brackets == null || _stopStrategyDrafts == null || _stopStrategyDrafts.Count == 0)
				return snap;

			// Collect any reflection failures so we can warn the user once at
			// the end. NT8's reflection writes silently fail when a property
			// name is not in our fallback list — without this tracking, the
			// user would never know their draft edits weren't applied.
			var failures = new List<string>();

			try
			{
				for (int i = 0; i < atm.Brackets.Length; i++)
				{
					var draft = TryGetDraft(atm, i);
					if (draft == null) continue;

					// Snapshot this bracket's template values BEFORE we mutate them.
					snap.PerBracket[i] = ReadAtmStopStrategyTemplate(atm, i);

					var bb = atm.Brackets[i];
					if (bb == null) continue;

					object ss = null;
					try
					{
						var ssProp = bb.GetType().GetProperty("StopStrategy");
						if (ssProp != null) ss = ssProp.GetValue(bb, null);
					}
					catch { }
					if (ss == null)
					{
						if (draft.AutoBEProfitTrigger.HasValue || draft.AutoBEPlus.HasValue || draft.TrailStepOverrides != null)
							failures.Add("Bracket " + (i + 1).ToString() + ": StopStrategy property not found on Bracket type");
						continue;
					}

					if (draft.AutoBEProfitTrigger.HasValue)
					{
						bool ok = SsWriteInt(ss, draft.AutoBEProfitTrigger.Value,
							"AutoBreakEvenProfitTrigger", "BreakEvenProfitTrigger", "AutoBreakevenProfitTrigger");
						if (!ok) failures.Add("Bracket " + (i + 1).ToString() + ": AutoBE trigger write failed (no matching property)");
					}
					if (draft.AutoBEPlus.HasValue)
					{
						bool ok = SsWriteInt(ss, draft.AutoBEPlus.Value,
							"AutoBreakEvenPlus", "BreakEvenPlus", "AutoBreakevenPlus");
						if (!ok) failures.Add("Bracket " + (i + 1).ToString() + ": AutoBE plus write failed (no matching property)");
					}

					if (draft.TrailStepOverrides != null)
					{
						object trailColl = SsRead(ss, "AutoTrails", "AutoTrailSteps", "TrailSteps", "AutoTrailStops");
						// Use IList for both read and write — same access pattern.
						// If the collection isn't an IList we can't index into
						// it for writes, so log the failure.
						var list = trailColl as System.Collections.IList;
						if (list == null)
						{
							failures.Add("Bracket " + (i + 1).ToString() + ": AutoTrails collection not an IList — trail step writes skipped");
						}
						else
						{
							for (int s = 0; s < draft.TrailStepOverrides.Count && s < list.Count; s++)
							{
								var dstep = draft.TrailStepOverrides[s];
								var tstep = list[s];
								if (tstep == null) continue;
								bool ok1 = SsWriteInt(tstep, dstep.StopLoss,      "StopLoss", "Stop", "StopTicks");
								bool ok2 = SsWriteInt(tstep, dstep.ProfitTrigger, "ProfitTrigger", "Trigger", "ProfitTriggerTicks");
								bool ok3 = SsWriteInt(tstep, dstep.Frequency,     "Frequency", "FrequencyTicks", "Freq");
								if (!ok1 || !ok2 || !ok3)
									failures.Add("Bracket " + (i + 1).ToString() + " Trail step " + (s + 1).ToString() + ": one or more field writes failed");
							}
						}
					}
				}
			}
			catch (Exception ex)
			{
				if (TestRender) Print("ApplyStopStrategyDraftsToLiveAtm: " + ex.Message);
				failures.Add("Exception: " + ex.Message);
			}

			// Always Print failures (not gated on TestRender) so the user sees
			// silent reflection failures in the NT8 Output window. Drafts that
			// don't apply silently are dangerous — the user expects their
			// edits to take effect on the live trade.
			if (failures.Count > 0)
			{
				try
				{
					// Print("[aiEnhancedChartTrader] Stop-strategy draft commit had " + failures.Count.ToString() + " failure(s):");
					for (int f = 0; f < failures.Count; f++)
						; // Print("  • " + failures[f]);
					AddMessage("Some stop-strategy edits could not be applied — see Output window.", 10, Brushes.Goldenrod);
				}
				catch { }
			}

			return snap;
		}

		private void RestoreStopStrategySnapshot(StopStrategySnapshot snap)
		{
			if (snap == null || snap.Atm == null || snap.PerBracket == null || snap.PerBracket.Count == 0)
				return;

			try
			{
				var atm = snap.Atm;
				if (atm.Brackets == null) return;

				foreach (var kv in snap.PerBracket)
				{
					int i = kv.Key;
					var orig = kv.Value;
					if (orig == null) continue;
					if (i < 0 || i >= atm.Brackets.Length) continue;
					var bb = atm.Brackets[i];
					if (bb == null) continue;

					object ss = null;
					try
					{
						var ssProp = bb.GetType().GetProperty("StopStrategy");
						if (ssProp != null) ss = ssProp.GetValue(bb, null);
					}
					catch { }
					if (ss == null) continue;

					SsWriteInt(ss, orig.AutoBEProfitTrigger,
						"AutoBreakEvenProfitTrigger", "BreakEvenProfitTrigger", "AutoBreakevenProfitTrigger");
					SsWriteInt(ss, orig.AutoBEPlus,
						"AutoBreakEvenPlus", "BreakEvenPlus", "AutoBreakevenPlus");

					object trailColl = SsRead(ss, "AutoTrails", "AutoTrailSteps", "TrailSteps", "AutoTrailStops");
					if (trailColl is System.Collections.IList)
					{
						var list = (System.Collections.IList)trailColl;
						for (int s = 0; s < orig.AutoTrailSteps.Count && s < list.Count; s++)
						{
							var ostep = orig.AutoTrailSteps[s];
							var tstep = list[s];
							if (tstep == null) continue;
							SsWriteInt(tstep, ostep.StopLoss,      "StopLoss", "Stop", "StopTicks");
							SsWriteInt(tstep, ostep.ProfitTrigger, "ProfitTrigger", "Trigger", "ProfitTriggerTicks");
							SsWriteInt(tstep, ostep.Frequency,     "Frequency", "FrequencyTicks", "Freq");
						}
					}
				}
			}
			catch (Exception ex)
			{
				if (TestRender) Print("RestoreStopStrategySnapshot: " + ex.Message);
			}
		}

		// Single entry point for submitting an ATM strategy trade with any
		// pending stop-strategy drafts applied. Uses snapshot-and-restore so
		// the user's saved ATM template is guaranteed to be unmodified after
		// this returns, even if StartAtmStrategy throws.
		//
		// Drafts are only CLEARED on a successful submission. If the submission
		// throws (margin error, validation failure, connectivity), the drafts
		// stay in place so the user can fix the issue and retry without losing
		// their stop-strategy edits.
		private void StartAtmStrategyWithDrafts(NinjaTrader.NinjaScript.AtmStrategy atm, Order entryOrder)
		{
			if (atm == null || entryOrder == null) return;
			LogDiag("ATM", "StartAtmWithDrafts", "ATM=" + atm.DisplayName + ", Action=" + entryOrder.OrderAction + ", Qty=" + entryOrder.Quantity);

			// Fast path: no drafts → just submit.
			if (_stopStrategyDrafts == null || _stopStrategyDrafts.Count == 0)
			{
				NinjaTrader.NinjaScript.AtmStrategy.StartAtmStrategy(atm, entryOrder);
				return;
			}

			StopStrategySnapshot snap = null;
			bool submittedOk = false;
			try
			{
				snap = ApplyStopStrategyDraftsToLiveAtm(atm);
				NinjaTrader.NinjaScript.AtmStrategy.StartAtmStrategy(atm, entryOrder);
				submittedOk = true;
			}
			finally
			{
				// Always restore the template snapshot — the user's saved ATM
				// template must never carry the temporary draft mutations,
				// regardless of whether StartAtmStrategy succeeded or threw.
				try { RestoreStopStrategySnapshot(snap); } catch { }

				// Only clear drafts if the trade was actually submitted. On
				// failure, drafts persist so the user can retry.
				if (submittedOk)
				{
					ClearStopStrategyDrafts();
				}
			}
		}

		// Convenience wrapper that returns the info for whichever bracket is
		// currently relevant (defaults to bracket 0 — the first target).
		private AtmStopStrategyInfo ReadAtmStopStrategyInfo(NinjaTrader.NinjaScript.AtmStrategy atm)
		{
			return ReadAtmStopStrategyInfo(atm, 0);
		}

		// === Hovered-target detection helper ===
		// Walks the just-populated AllATMStrategyLevelButtons dictionary and returns
		// the bracket index (0-based) of whichever "Target N" line the mouse is
		// currently hovering over. Returns -1 when nothing is hovered or the name
		// can't be parsed. The marker block uses this to decide which bracket's
		// stop strategy details to surface — see the multi-target hover behavior.
		private int GetHoveredTargetBracketIdx()
		{
			if (AllATMStrategyLevelButtons == null || AllATMStrategyLevelButtons.Count == 0)
				return -1;

			foreach (var kv in AllATMStrategyLevelButtons)
			{
				var btn = kv.Value;
				if (btn == null || btn.Name == null) continue;
				if (!btn.Name.StartsWith("Target ")) continue;
				if (!MouseIn(btn.ThisRectA, 0, 0)) continue;

				// Name format: "Target 1" or combined like "Target 1/2/3".
				string suffix = btn.Name.Substring("Target ".Length);
				string firstNum = suffix;
				int slash = suffix.IndexOf('/');
				if (slash > 0) firstNum = suffix.Substring(0, slash);

				int n;
				if (int.TryParse(firstNum, out n) && n > 0)
					return n - 1; // convert to 0-based bracket index
			}
			return -1;
		}

		// Lazily ensure the stop-strategy stroke has a live RenderTarget and a valid
		// BrushDX before we hand it to DrawPlanOrder / DrawRectangle. Returns null if
		// the stroke cannot be made render-ready on this frame — callers should skip
		// drawing rather than crash. Covers the case where the user picks a new
		// color/dash for StopStrategyStroke in the properties panel and NT8 creates
		// a fresh Stroke instance with no RenderTarget assigned.
		private Stroke GetStopStrategyStrokeSafe()
		{
			if (RenderTarget == null)
				return null;

			if (pStopStrategyStroke == null)
				return null;

			try
			{
				if (pStopStrategyStroke.RenderTarget != RenderTarget)
					pStopStrategyStroke.RenderTarget = RenderTarget;

				if (pStopStrategyStroke.BrushDX == null)
					return null;
			}
			catch
			{
				return null;
			}

			return pStopStrategyStroke;
		}

		// Bump the expiration timestamp for every sentinel plan key at once.
		// Replaces the repeated 8-check blocks that manually bump 10/-10/11/-11/12/-12/13/-13.
		// Sentinels are integers in [-13,13] (only 27 candidates) — probe directly
		// instead of enumerating the whole dict. Avoids the .ToList() OverflowException
		// that fires once OrderPriceToATMDisplayEnd grows past what a double[] can hold.
		private void BumpAllPlanSentinelTimestamps(int seconds)
		{
			DateTime exp = DateTime.Now.AddSeconds(seconds);
			for (int i = -13; i <= 13; i++)
			{
				double key = i;
				if (OrderPriceToATMDisplayEnd.ContainsKey(key))
					OrderPriceToATMDisplayEnd[key] = exp;
			}
		}

		// Remove all sentinel plan keys. Used by HidePlan so nothing leaks.
		private void RemoveAllPlanSentinels()
		{
			for (int i = -13; i <= 13; i++)
			{
				double key = i;
				if (OrderPriceToATMDisplayEnd.ContainsKey(key))
					OrderPriceToATMDisplayEnd.Remove(key);
			}
		}

		// Reusable scratch list for pruning OrderPriceToATMDisplayEnd. Avoids
		// per-call allocation in the per-frame / per-tick prune path.
		private List<double> _expiredPlanKeysScratch = new List<double>();

		// Drop expired non-sentinel entries from OrderPriceToATMDisplayEnd so the
		// dict can't grow without bound. Sentinels are preserved (they're managed
		// by Bump/RemoveAllPlanSentinels). Called from OnTimerTick3.
		private void PruneExpiredPlanEntries()
		{
			DateTime now = DateTime.Now;
			_expiredPlanKeysScratch.Clear();
			foreach (var kvp in OrderPriceToATMDisplayEnd)
			{
				bool isSentinel = kvp.Key >= -13 && kvp.Key <= 13 && kvp.Key == Math.Truncate(kvp.Key);
				if (!isSentinel && kvp.Value < now)
					_expiredPlanKeysScratch.Add(kvp.Key);
			}
			for (int i = 0; i < _expiredPlanKeysScratch.Count; i++)
				OrderPriceToATMDisplayEnd.Remove(_expiredPlanKeysScratch[i]);
			_expiredPlanKeysScratch.Clear();
		}
	
		
		
		private int TotalPendingEntryOrdersWithATMStrategy(bool show)
		{
			int totalorders = 0;
				if (myAccount != null)
				foreach (Order or in myAccount.Orders.ToList())
				{
					
					Order ThisOrder = or;
					
					// atm strategy display timer
					if (ThisOrder.OrderState == OrderState.Accepted || ThisOrder.OrderState == OrderState.Working || ThisOrder.OrderState == OrderState.TriggerPending)
					{
						
						//Print(ThisOrder.OrderId);
						
						double finalprice = ThisOrder.LimitPrice;
						
						if (ThisOrder.OrderType == OrderType.StopLimit || ThisOrder.OrderType == OrderType.StopMarket || ThisOrder.OrderType == OrderType.MIT || (ThisOrder.StopPrice != 0 && ThisOrder.OrderState == OrderState.TriggerPending))
							finalprice = ThisOrder.StopPrice;
						
						
						
						//Print(finalprice);
						
						if (show)
						AddATMPlanEntry(finalprice, pShowPlanSeconds333);
						totalorders = totalorders + 1;
					}
					
			
				}	
				
				return totalorders;
			
		}
		
		private void InitializeAllPlans()
		{
			int totalorders = TotalPendingEntryOrdersWithATMStrategy(true);
			
		
				
				if (totalorders == 0)
					LaunchPlan(false);
				
		}
		
		private void AddATMPlanEntry(double ThisPrice, int Seconds)
		{
					// Remove all OTHER plans immediately so only one shows at a time
					// — but only in single-plan mode. When pAllowMultiplePlans is on,
					// the user has explicitly opted into stacking plans (one per
					// live order, plus a fresh preview plan, etc.), so showing one
					// plan must not wipe the others. Without this gate, clicking an
					// ATM chip on a live order's flag wiped any plan-in-progress
					// the user had set up at a different price.
					if (!pAllowMultiplePlans)
					{
						// Use the scratch list pattern to avoid allocating a full
						// snapshot of the keys (which threw OverflowException once
						// the dict grew large).
						_expiredPlanKeysScratch.Clear();
						foreach (double key in OrderPriceToATMDisplayEnd.Keys)
						{
							if (key != ThisPrice)
								_expiredPlanKeysScratch.Add(key);
						}
						for (int _i = 0; _i < _expiredPlanKeysScratch.Count; _i++)
							OrderPriceToATMDisplayEnd.Remove(_expiredPlanKeysScratch[_i]);
						_expiredPlanKeysScratch.Clear();
					}

					// Always recompute LastPlanEntry from the current bar / in-progress price.
					// Previously this only ran when the key was first added, leaving a stale
					// entry preview if the user toggled LMT/MKT or the bar advanced.
					{

						string ThisPriceBasis = pCloseBarBasis;
						int		thisoffset = pLimitOrderOffset1;
						string		thisordert = pThisEntryType1;

						if (ThisPrice == 10 || ThisPrice == -10)
							//if (WhichEntry == "Signal")
							{
								ThisPriceBasis = pSignalBarBasis;
								thisoffset = pLimitOrderOffset2;
								thisordert = pSignalEntryOrderType;
							}

						if (ThisPrice == 10 || ThisPrice == -10)
							LastPlanEntry = CurrentLastData;

						if (ThisPrice == 10 || ThisPrice == 11)
						{
							// Long entry: LMT/LIT offset below price (pullback), STP/SLM/MIT offset above price (breakout)
							bool isLimitType = (thisordert == "LMT" || thisordert == "LIT" || thisordert == "MIT");
							if (thisordert == "MKT" || thisordert == "ICE")
							{
								LastPlanEntry = CurrentLastData;
							}
							else if (ThisPriceBasis == "Close")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastData - thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastData + thisoffset*ThisTickSize);
							}
							else if (ThisPriceBasis == "Middle")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastMiddle - thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastMiddle + thisoffset*ThisTickSize);
							}
							else if (ThisPriceBasis == "High / Low")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastHigh - thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastHigh + thisoffset*ThisTickSize);
							}


						}
						if (ThisPrice == -10 || ThisPrice == -11)
						{
							// Short entry: LMT/LIT offset above price (pullback), STP/SLM/MIT offset below price (breakdown)
							bool isLimitType = (thisordert == "LMT" || thisordert == "LIT" || thisordert == "MIT");
							if (thisordert == "MKT" || thisordert == "ICE")
							{
								LastPlanEntry = CurrentLastData;
							}
							else if (ThisPriceBasis == "Close")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastData + thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastData - thisoffset*ThisTickSize);
							}
							else if (ThisPriceBasis == "Middle")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastMiddle + thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastMiddle - thisoffset*ThisTickSize);
							}
							else if (ThisPriceBasis == "High / Low")
							{
								if (isLimitType)
									LastPlanEntry = RTTS(CurrentLastLow + thisoffset*ThisTickSize);
								else
									LastPlanEntry = RTTS(CurrentLastLow - thisoffset*ThisTickSize);
							}
						}



						if (_hasPlanInProgress)
						{
							// Apply order type offset to the in-progress plan entry
							LastPlanEntry = pIsPlanInProgress;
							bool isLimitTypeIP = (thisordert == "LMT" || thisordert == "LIT" || thisordert == "MIT");
							if (thisordert != "MKT" && thisordert != "ICE")
							{
								if (pLastPlanDirection == "Long" || pLastPlanDirection == "")
								{
									if (isLimitTypeIP)
										LastPlanEntry = RTTS(pIsPlanInProgress - thisoffset*ThisTickSize);
									else
										LastPlanEntry = RTTS(pIsPlanInProgress + thisoffset*ThisTickSize);
								}
								else
								{
									if (isLimitTypeIP)
										LastPlanEntry = RTTS(pIsPlanInProgress + thisoffset*ThisTickSize);
									else
										LastPlanEntry = RTTS(pIsPlanInProgress - thisoffset*ThisTickSize);
								}
							}
						}
					}

					// AddOrUpdate the sentinel entry with the fresh expiration timestamp.
					DateTime exp = DateTime.Now.AddSeconds(Seconds);
					if (OrderPriceToATMDisplayEnd.ContainsKey(ThisPrice))
						OrderPriceToATMDisplayEnd[ThisPrice] = exp;
					else
						OrderPriceToATMDisplayEnd.Add(ThisPrice, exp);

		}
		
	
		
		public void RunBEClick (int pBEOffset)
		{
			if (ThisPositionNow() != null)
							{
								if (ThisPositionNow().MarketPosition == MarketPosition.Long) // In Long Trade
								{
									
									NewLimitPrice = RTTS(ThisPositionNow().AveragePrice + pBEOffset*ThisTickSize);

									if (NewLimitPrice <= CurrentLastData)
									{
										if (pBEMoveStops) UpdateStopLoss("BE", 0, true);
									}
									else
									{
										if (pBEMoveTargets) UpdateProfitTargets("BE", pBEOffset);
									}


								}

								if (ThisPositionNow().MarketPosition == MarketPosition.Short) // In Short Trade
								{
									//if (Mode == "BE")
										NewLimitPrice = RTTS(ThisPositionNow().AveragePrice - pBEOffset*ThisTickSize);;

			//						if (Mode == "SA")
			//							NewStopPrice = ShortSAPrice;

									//OKToMove = NewStopPrice >= GetCurrentAsk();

									if (NewLimitPrice >= CurrentLastData)
									{
										if (pBEMoveStops) UpdateStopLoss("BE", 0, true);
									}
									else
									{
										if (pBEMoveTargets) UpdateProfitTargets("BE", pBEOffset);
									}
								
								}
								
								
							}
							
							return;
							
		}
		
		
						
					
