		// ATM color palette for color-coding order flags by strategy
		private static readonly System.Windows.Media.Color[] ATMColorPalette = new System.Windows.Media.Color[]
		{
			System.Windows.Media.Color.FromRgb(70, 130, 180),  // steel blue
			System.Windows.Media.Color.FromRgb(180, 100, 60),  // burnt orange
			System.Windows.Media.Color.FromRgb(100, 170, 100), // sage green
			System.Windows.Media.Color.FromRgb(160, 90, 160),  // muted purple
			System.Windows.Media.Color.FromRgb(180, 160, 60),  // olive gold
			System.Windows.Media.Color.FromRgb(80, 160, 160),  // teal
			System.Windows.Media.Color.FromRgb(170, 80, 80),   // dusty red
			System.Windows.Media.Color.FromRgb(120, 140, 180), // slate blue
		};

		private Dictionary<string, SharpDX.Direct2D1.SolidColorBrush> cachedATMColorBrushes = new Dictionary<string, SharpDX.Direct2D1.SolidColorBrush>();

		private SharpDX.Direct2D1.Brush GetATMColorBrush(AtmStrategy atm)
		{
			D2DThreadCheck("GetATMColorBrush");
			if (atm == null || RenderTarget == null) return null;
			string name = RemoveEndOfLiveATM(atm.DisplayName);
			SharpDX.Direct2D1.SolidColorBrush cached;
			if (cachedATMColorBrushes.TryGetValue(name, out cached) && cached != null && !cached.IsDisposed)
				return cached;
			int idx = Math.Abs(name.GetHashCode()) % ATMColorPalette.Length;
			var c = ATMColorPalette[idx];
			var brush = new SharpDX.Direct2D1.SolidColorBrush(RenderTarget, new SharpDX.Color4(c.R/255f, c.G/255f, c.B/255f, 0.7f));
			cachedATMColorBrushes[name] = brush;
			return brush;
		}

		// --- ATM Scale-In/Out Methods ---

		private AtmStrategy FindActiveATMForPosition()
		{
			if (myAccount == null) return null;
			Position pos = ThisPositionNow();
			if (pos == null || pos.Quantity == 0) return null;
			if (lastCreatedATM != null)
			{
				try { foreach (object aaa in myAccount.Strategies) if (aaa == (object)lastCreatedATM) return lastCreatedATM; } catch { }
				lastCreatedATM = null;
			}
			try
			{
				foreach (Order or in myAccount.Orders.ToList())
				{
					if (or.Instrument != ThisInstrumment) continue;
					if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted) continue;
					object owner = or.GetOwnerStrategy();
					if (owner != null) return (AtmStrategy)owner;
				}
			}
			catch { }
			return null;
		}

		private void ScalePosition(int pQty, OrderAction action, AtmStrategy existingATM)
		{
			if (myAccount == null || existingATM == null || pQty <= 0) return;
			LogDiag("ORDER", "ScalePosition", "Qty=" + pQty + ", Action=" + action);
			Order scaleOrder = myAccount.CreateOrder(ThisInstrumment, action, OrderType.Market, tifSelector1.SelectedTif, pQty, 0, 0, "", "Entry", null);
			myAccount.Submit(new[] { scaleOrder });
			pendingScaleEntry = scaleOrder;
			pendingScaleATM = existingATM;
		}

		private void ScalePositionPending(int pQty, OrderAction action, OrderType ot, double limitPrice, double stopPrice, string ocoId, string name, AtmStrategy existingATM)
		{
			if (myAccount == null || existingATM == null || pQty <= 0) return;
			Account aaa = myAccount;
			if (IsDuplicateOrder) { aaa = accountSelectorMaster.SelectedAccount; IsDuplicateOrder = false; }
			Order scaleOrder = aaa.CreateOrder(ThisInstrumment, action, ot, tifSelector1.SelectedTif, pQty, limitPrice, stopPrice, ocoId, name, null);
			aaa.Submit(new[] { scaleOrder });
			pendingScaleEntry = scaleOrder;
			pendingScaleATM = existingATM;
		}

		private void AdjustATMOrderQuantities(AtmStrategy existingATM)
		{
			if (existingATM == null || myAccount == null) return;
			Position pos = ThisPositionNow();
			if (pos == null || pos.Quantity == 0) return;
			int newTotalQty = Math.Abs(pos.Quantity);
			SetATMTargetQtys(existingATM, newTotalQty, pos.AveragePrice, "");
			try
			{
				foreach (Order or in myAccount.Orders.ToList())
				{
					if (or.Instrument != ThisInstrumment) continue;
					if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted) continue;
					if (or.GetOwnerStrategy() != (object)existingATM) continue;
					if (or.Name == "Entry") continue;
					int targetQty = newTotalQty;
					if (existingATM.Brackets != null && existingATM.Brackets.Length > 1)
						foreach (Bracket bb in existingATM.Brackets) if (bb.Quantity > 0) { targetQty = bb.Quantity; break; }
					if (or.Quantity != targetQty) { Order moveOrder = or; moveOrder.QuantityChanged = targetQty; myAccount.Change(new[] { moveOrder }); }
				}
			}
			catch { }
		}

		private void CheckPendingScaleFill(Order filledOrder)
		{
			if (pendingScaleEntry == null || pendingScaleATM == null) return;
			if (filledOrder == pendingScaleEntry && filledOrder.OrderState == OrderState.Filled)
			{
				try { ChartControl.Dispatcher.InvokeAsync(new Action(() => { AdjustATMOrderQuantities(pendingScaleATM); pendingScaleEntry = null; pendingScaleATM = null; })); }
				catch { pendingScaleEntry = null; pendingScaleATM = null; }
			}
		}

