			ConfiguringTrailingStop = -1;
			SelectingPlotFor = string.Empty;
		}
				
		
		
		
		private void CheckMoveStops(Order oo)
		{
			
			
			
			if (IsStop(oo.Name))
					{
					
						if (pAdvancedExitOrdersManagementEnabled)
						if (pTrailingStopIsEnabled)
						if (pTrailingStopDisableOnManualMove)
						{
							//Log(LogIndicatorDisplayName + " | " + myAccount.Name + " | " + Instrument.FullName + " | " + " Trailing Stop Is Disabled", LogLevel.Information);
							
							pTrailingStopIsEnabled = false;
							UpdateButtons();	
							
						}
						
						
					//	Print("RRIsOnOrders.Count " + RRIsOnOrders.Count);
						
						
						if (pRiskRewardEnabled && RRIsOnOrders.Contains(oo))
						{
							// ─────────────────────────────────────────────────────────
							// Risk/Reward target re-scaling on stop drag.
							//
							// Absolute-formula model (replaces the old delta model):
							//   newRisk     = |newStopPrice - avgEntry|
							//   newTargetD  = newRisk * initialRR
							//   newTarget   = avgEntry + (long ? +newTargetD : -newTargetD)
							//
							// Old delta model (REMOVED):
							//   changeInTarget = changeInStop * RR * -1
							// That was structurally wrong for any stop move toward entry:
							// breakeven drove the target across the market and instant-
							// filled the trade. The absolute formula anchors target to
							// avgEntry instead, so risk reduction also reduces target
							// (per user spec — reducing risk SHOULD reduce target in
							// proportion), but the market-clamp below prevents the
							// resulting target from ever crossing current price.
							// ─────────────────────────────────────────────────────────

							double avgEntry = ThisPositionNow().AveragePrice;
							if (avgEntry == 0)
							{
								// Position not open (or flat) — no anchor, skip.
								return;
							}

							// Prefer the snapshot captured at submit time; fall back to
							// live ATM read if the stop was enrolled via the on-chart
							// toggle (no snapshot) or if the dict entry is missing.
							double initialRR = 0;
							if (!RRInitialRatio.TryGetValue(oo, out initialRR) || initialRR <= 0)
							{
								AtmStrategy atmFallback = GetOrderATM(oo);
								if (atmFallback != null)
								{
									int idx = 0;
									foreach (Bracket bb in atmFallback.Brackets)
									{
										idx++;
										if (bb.Target != 0 && bb.StopLoss != 0 && oo.Name.Contains(idx.ToString()))
										{
											initialRR = (double) bb.Target / (double) bb.StopLoss;
											break;
										}
									}
								}
							}
							if (initialRR <= 0) return;

							Order MatchTO = GetMatchingTarget(oo.Oco);
							if (MatchTO == null) return;

							double MatchT = MatchTO.StopPrice != 0 ? MatchTO.StopPrice : MatchTO.LimitPrice;
							if (MatchT == 0) return;

							bool isLongExit = MatchT > avgEntry;  // target sits on the profit side of entry

							// New stop price is CurrentMousePrice (the drop point).
							double newStop = CurrentMousePrice;
							double newRisk = Math.Abs(newStop - avgEntry);
							double newTargetDist = newRisk * initialRR;
							double newTargetPrice = isLongExit ? (avgEntry + newTargetDist) : (avgEntry - newTargetDist);
							newTargetPrice = RTTS(newTargetPrice);

							// ─── Market-cross clamp ──────────────────────────────────
							// If the computed target would land on the wrong side of
							// the current market, it would fill instantly — which is
							// exactly the breakeven failure mode we're eliminating.
							// Abort the target move and flash a chart status message
							// so the user knows why the target stayed put.
							// Close[0] is the market reference (always available, no
							// realtime-state gate needed). Equal-to-market also counts
							// as a crossing since it would fill on the next trade.
							double marketRef = Close[0];
							bool wouldCross = isLongExit
								? (newTargetPrice <= marketRef)
								: (newTargetPrice >= marketRef);

							if (wouldCross)
							{
								AddMessage("Risk / Reward: target move aborted — would cross current market", 8, Brushes.Orange);
								return;
							}

							// Normal path: move the target to its new absolute price.
							MoveOrder(MatchTO, newTargetPrice, 0);
						}
						
						
						
						
					}
						
					
					
	}
		
