		internal void OnChartContextMenuOpening(object sender, System.Windows.Controls.ContextMenuEventArgs e)
		{
			try
			{
				RemoveContextMenuOrderItems();

				if (pRightClickEntryMode == "None") return;

				if (_lastChartScale == null || ChartPanel == null) return;
				if (ChartPanel.H <= 0) return;

				_ctxMenuPrice = RTTS(_lastChartScale.MaxValue - _lastChartScale.MaxMinusMin * ((FinalYPixel - ChartPanel.Y) / ChartPanel.H));
				if (_ctxMenuPrice <= 0) return;

				// Find the chart's context menu
				System.Windows.Controls.ContextMenu menu = null;
				var fe = sender as System.Windows.FrameworkElement;
				if (fe != null && fe.ContextMenu != null) menu = fe.ContextMenu;
				if (menu == null && ChartControl != null) menu = ChartControl.ContextMenu;
				if (menu == null) return;

				// Find insertion index — before "Drawing Tools"
				int insertIdx = menu.Items.Count;
				for (int i = 0; i < menu.Items.Count; i++)
				{
					var mi = menu.Items[i] as System.Windows.Controls.MenuItem;
					if (mi == null) continue;
					string h = mi.Header != null ? mi.Header.ToString().Replace("_", "").Trim() : "";
					if (h.StartsWith("Drawing Tools", StringComparison.OrdinalIgnoreCase))
					{
						insertIdx = i;
						break;
					}
				}

				string priceStr = _ctxMenuPrice.ToString(PriceString);
				double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentBid;
				bool aboveMarket = _ctxMenuPrice >= refPrice;

				if (pRightClickEntryMode == "Simple")
				{
					// Simple mode: Buy and Sell with qty, order type, price, ATM name
					// Buy always above Sell
					string buyType = GetSimpleOrderTypeLabel(true, aboveMarket);
					string sellType = GetSimpleOrderTypeLabel(false, aboveMarket);
					string qtyStr = pQty.ToString();
					string atmName = "";
					try
					{
						if (atmStrategySelector != null && atmStrategySelector.SelectedAtmStrategy != null)
							atmName = " (" + atmStrategySelector.SelectedAtmStrategy.DisplayName + ")";
					}
					catch { }

					InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " " + buyType + " @ " + priceStr, atmName, OnCtxSimpleBuyClick);
					InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " " + sellType + " @ " + priceStr, atmName, OnCtxSimpleSellClick);

					// OCO toggle
					if (pOCOButtonEnabled)
						InsertCtxMenuItemColored(menu, ref insertIdx, pIsOCO ? "OCO: On" : "OCO: Off", OnCtxOCOToggleClick, null);

					// Flatten Everything + Cancel All Orders
					InsertCtxMenuItemColored(menu, ref insertIdx, "Flatten Everything", OnCtxFlattenEverythingClick, null);
					InsertCtxMenuItemColored(menu, ref insertIdx, "Cancel All Orders", OnCtxCancelAllOrdersClick, null);
				}
				else // NinjaTrader mode
				{
					bool litEnabled = pLITEntryOrdersPermission && pLITEntryOrdersEnabled;
					string qtyStr = pQty.ToString();
					string atmNameNT = "";
					try
					{
						if (atmStrategySelector != null && atmStrategySelector.SelectedAtmStrategy != null)
							atmNameNT = " (" + atmStrategySelector.SelectedAtmStrategy.DisplayName + ")";
					}
					catch { }

					if (aboveMarket)
					{
						// Sell items on top
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " Limit @ " + priceStr, atmNameNT, OnCtxSellLimitClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " MIT @ " + priceStr, atmNameNT, OnCtxSellMITClick);
						if (litEnabled)
							InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " LIT @ " + priceStr, atmNameNT, OnCtxSellLITClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " Stop @ " + priceStr, atmNameNT, OnCtxBuyStopClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " Stop Limit @ " + priceStr, atmNameNT, OnCtxBuyStopLimitClick);
					}
					else
					{
						// Buy items on top
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " Limit @ " + priceStr, atmNameNT, OnCtxBuyLimitClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " MIT @ " + priceStr, atmNameNT, OnCtxBuyMITClick);
						if (litEnabled)
							InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Buy " + qtyStr + " LIT @ " + priceStr, atmNameNT, OnCtxBuyLITClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " Stop @ " + priceStr, atmNameNT, OnCtxSellStopClick);
						InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Sell " + qtyStr + " Stop Limit @ " + priceStr, atmNameNT, OnCtxSellStopLimitClick);
					}

					// OCO toggle
					if (pOCOButtonEnabled)
						InsertCtxMenuItemColored(menu, ref insertIdx, pIsOCO ? "OCO: On" : "OCO: Off", OnCtxOCOToggleClick, null);

					// Flatten Everything + Cancel All Orders
					InsertCtxMenuItemColored(menu, ref insertIdx, "Flatten Everything", OnCtxFlattenEverythingClick, null);
					InsertCtxMenuItemColored(menu, ref insertIdx, "Cancel All Orders", OnCtxCancelAllOrdersClick, null);
				}

				// Bottom separator
				_ctxMenuSepBottom = new System.Windows.Controls.Separator();
				menu.Items.Insert(insertIdx, _ctxMenuSepBottom);
				insertIdx++;

				// Send Diagnostics
				InsertCtxMenuItemWithAtm(menu, ref insertIdx, "Send Diagnostics", " (Affordable Indicators)", OnCtxSendDiagnosticsClick);
				_ctxMenuSepDiag = new System.Windows.Controls.Separator();
				menu.Items.Insert(insertIdx, _ctxMenuSepDiag);
			}
			catch { }
		}

		private string GetSimpleOrderTypeLabel(bool isBuy, bool aboveMarket)
		{
			// Above market: sell side = limit/MIT/LIT, buy side = stop
			// Below market: buy side = limit/MIT/LIT, sell side = stop
			bool isLimitSide = (isBuy && !aboveMarket) || (!isBuy && aboveMarket);

			if (isLimitSide)
			{
				// Use the currently selected limit type from the panel
				if (pThisEntryLimitClick == "MIT") return "MIT";
				if (pThisEntryLimitClick == "LIT" && pLITEntryOrdersPermission && pLITEntryOrdersEnabled) return "LIT";
				return "Limit";
			}
			else
			{
				// Stop side — show SLM if enabled, otherwise Stop
				if (pUseSLM) return "Stop Limit";
				return "Stop";
			}
		}

		private void OnCtxSimpleBuyClick(object sender, System.Windows.RoutedEventArgs e)
		{
			try
			{
				LogDiag("CTX_MENU", "SimpleBuy");
				double refPrice = UseLastPriceForClickOrders ? CurrentLastData : CurrentAsk;
				bool isLimit = _ctxMenuPrice <= refPrice;

				if (pLinkButtonsIsOn && pLinkOnPlaceOrder) LinkNextOrder = true;

				if (isLimit)
				{
					if (pThisEntryLimitClick == "LIT" && pLITEntryOrdersPermission && pLITEntryOrdersEnabled)
					{
						CurrentMousePrice = _ctxMenuPrice;
						PlaceCustomOrder("BUY", "LIT", "");
					}
					else
					{
						BuyLimit(pQty, atmStrategySelector.SelectedAtmStrategy, BuildCtxOCOID(), _ctxMenuPrice, pThisEntryLimitClick == "MIT", "Entry");
					}
				}
				else
				{
					BuyStop(pQty, atmStrategySelector.SelectedAtmStrategy, BuildCtxOCOID(), _ctxMenuPrice, pUseSLM, pSLOffsetReg, "Entry");
				}

				AfterCtxOrderPlaced();
			}
			catch { }
		}

