		private void InsertCtxMenuItem(System.Windows.Controls.ContextMenu menu, ref int idx, string header, System.Windows.RoutedEventHandler handler)
		{
			var mi = new System.Windows.Controls.MenuItem();
			mi.Header = header;
			mi.Click += handler;
			menu.Items.Insert(idx, mi);
			_ctxOrderMenuItems.Add(mi);
			idx++;
		}

		private System.Windows.Controls.MenuItem InsertCtxMenuItemColored(System.Windows.Controls.ContextMenu menu, ref int idx, string header, System.Windows.RoutedEventHandler handler, System.Windows.Media.Brush foreground)
		{
			var mi = new System.Windows.Controls.MenuItem();
			mi.Header = header;
			mi.FontWeight = System.Windows.FontWeights.SemiBold;
			if (foreground != null)
				mi.Foreground = foreground;
			mi.Click += handler;
			menu.Items.Insert(idx, mi);
			_ctxOrderMenuItems.Add(mi);
			idx++;
			return mi;
		}

		private void InsertCtxMenuItemWithAtm(System.Windows.Controls.ContextMenu menu, ref int idx, string orderText, string atmText, System.Windows.RoutedEventHandler handler)
		{
			var mi = new System.Windows.Controls.MenuItem();
			mi.FontWeight = System.Windows.FontWeights.SemiBold;

			if (!string.IsNullOrEmpty(atmText))
			{
				var tb = new System.Windows.Controls.TextBlock();
				tb.Inlines.Add(new System.Windows.Documents.Run(orderText));
				var atmRun = new System.Windows.Documents.Run(atmText);
				atmRun.Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(65, 255, 255, 255));
				tb.Inlines.Add(atmRun);
				mi.Header = tb;
			}
			else
			{
				mi.Header = orderText;
			}

			mi.Click += handler;
			menu.Items.Insert(idx, mi);
			_ctxOrderMenuItems.Add(mi);
			idx++;
		}

		private string BuildCtxOCOID()
		{
			if (!pIsOCO) return string.Empty;
			string oco = string.Concat("Click", SpreadName, LastOCOID);
			if (IsTDAmeritrade) oco = string.Empty;
			return oco;
		}

