		private void RemoveContextMenuOrderItems()
		{
			try
			{
				for (int i = 0; i < _ctxOrderMenuItems.Count; i++)
				{
					var mi = _ctxOrderMenuItems[i];
					if (mi != null)
					{
						mi.Click -= OnCtxBuyLimitClick;
						mi.Click -= OnCtxBuyMITClick;
						mi.Click -= OnCtxBuyLITClick;
						mi.Click -= OnCtxBuyStopClick;
						mi.Click -= OnCtxBuyStopLimitClick;
						mi.Click -= OnCtxSellLimitClick;
						mi.Click -= OnCtxSellMITClick;
						mi.Click -= OnCtxSellLITClick;
						mi.Click -= OnCtxSellStopClick;
						mi.Click -= OnCtxSellStopLimitClick;
						mi.Click -= OnCtxSimpleBuyClick;
						mi.Click -= OnCtxSimpleSellClick;
						mi.Click -= OnCtxFlattenEverythingClick;
						mi.Click -= OnCtxCancelAllOrdersClick;
						mi.Click -= OnCtxSendDiagnosticsClick;
						var p = mi.Parent as System.Windows.Controls.ContextMenu;
						if (p != null) p.Items.Remove(mi);
					}
				}
				_ctxOrderMenuItems.Clear();

				if (_ctxMenuSepTop != null)
				{
					var p = _ctxMenuSepTop.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_ctxMenuSepTop);
					_ctxMenuSepTop = null;
				}
				if (_ctxMenuSepBottom != null)
				{
					var p = _ctxMenuSepBottom.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_ctxMenuSepBottom);
					_ctxMenuSepBottom = null;
				}
				if (_ctxMenuSepDiag != null)
				{
					var p = _ctxMenuSepDiag.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_ctxMenuSepDiag);
					_ctxMenuSepDiag = null;
				}
			}
			catch { }
		}


		private void OnCtxSendDiagnosticsClick(object sender, System.Windows.RoutedEventArgs e)
		{
			LogDiag("UI", "SendDiagnostics");
			if (_isSendingTemplate) return;
			_isSendingTemplate = true;

			try
			{
				// --- Capture screenshot BEFORE showing toast, so the toast does not appear in the image ---
				byte[] screenshotBytes = null;
				try
				{
					Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
					if (cw != null)
					{
						var wih = new System.Windows.Interop.WindowInteropHelper(cw);
						IntPtr hwnd = wih.Handle;
						if (hwnd != IntPtr.Zero)
						{
							SetForegroundWindow(hwnd);
							System.Threading.Thread.Sleep(100);

							AITR_RECT rc;
							GetWindowRect(hwnd, out rc);
							int width = rc.Right - rc.Left;
							int height = rc.Bottom - rc.Top;
							if (width > 0 && height > 0)
							{
								IntPtr hdcScreen = GetDC(IntPtr.Zero);
								IntPtr hdcMem = CreateCompatibleDC(hdcScreen);
								IntPtr hBitmap = CreateCompatibleBitmap(hdcScreen, width, height);
								IntPtr hOld = SelectObject(hdcMem, hBitmap);

								BitBlt(hdcMem, 0, 0, width, height, hdcScreen, rc.Left, rc.Top, 0x00CC0020);

								SelectObject(hdcMem, hOld);

								var bmpSource = System.Windows.Interop.Imaging.CreateBitmapSourceFromHBitmap(
									hBitmap, IntPtr.Zero, System.Windows.Int32Rect.Empty,
									BitmapSizeOptions.FromEmptyOptions());

								var encoder = new PngBitmapEncoder();
								encoder.Frames.Add(BitmapFrame.Create(bmpSource));
								using (var ms = new System.IO.MemoryStream())
								{
									encoder.Save(ms);
									screenshotBytes = ms.ToArray();
								}

								DeleteObject(hBitmap);
								DeleteDC(hdcMem);
								ReleaseDC(IntPtr.Zero, hdcScreen);
							}
						}
					}
				}
				catch { }

				// Show toast only after screenshot is captured
				AddMessage("Sending information to the Affordable Indicators team...", 10, Brushes.Goldenrod);

				// --- Capture chart template XML via reflection ---
				byte[] templateBytes = null;
				try
				{
					Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
					if (cw != null)
					{
						System.Xml.Linq.XDocument doc = new System.Xml.Linq.XDocument(new System.Xml.Linq.XElement("NinjaTrader"));
						bool saved = false;

						System.Reflection.MethodInfo saveMethod = typeof(Chart).GetMethod("Save",
							System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance,
							null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement), typeof(bool) }, null);
						if (saveMethod != null)
						{
							saveMethod.Invoke(cw, new object[] { doc, doc.Root, true });
							saved = true;
						}

						if (!saved)
						{
							saveMethod = typeof(Chart).GetMethod("Save",
								System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance,
								null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement) }, null);
							if (saveMethod != null)
							{
								saveMethod.Invoke(cw, new object[] { doc, doc.Root });
								saved = true;
							}
						}

						if (saved)
						{
							string xml = doc.ToString();
							if (xml.Length > 50)
								templateBytes = System.Text.Encoding.UTF8.GetBytes(xml);
						}
					}
				}
				catch { }

				// Flush ECT diagnostic log on UI thread; zipping happens off-UI below
				try { EnsureLogDirectory(); LogFlushCallback(null); } catch { }
				string ectLogDir = _logDirectoryPath;
				string userDataDir = NinjaTrader.Core.Globals.UserDataDir;

				string email = pLicensingEmailAddress ?? "";
				string machineId = NinjaTrader.Cbi.License.MachineId ?? "";
				string version = pVersionNumber ?? "";
				string product = ThisName ?? "";

				System.Threading.Tasks.Task.Run(() =>
				{
					try
					{
						// --- Zip log files (background thread so the chart stays interactive) ---
						byte[] logsZipBytes = null;
						try
						{
							string logPath = System.IO.Path.Combine(userDataDir, "log");
							if (System.IO.Directory.Exists(logPath))
								logsZipBytes = ZipDirectoryForDiagnostics(logPath);
						}
						catch { }

						// --- Zip trace files ---
						byte[] traceZipBytes = null;
						try
						{
							string tracePath = System.IO.Path.Combine(userDataDir, "trace");
							if (System.IO.Directory.Exists(tracePath))
								traceZipBytes = ZipDirectoryForDiagnostics(tracePath);
						}
						catch { }

						// --- Zip ECT diagnostic logs ---
						byte[] ectLogsZipBytes = null;
						try
						{
							if (!string.IsNullOrEmpty(ectLogDir) && System.IO.Directory.Exists(ectLogDir))
								ectLogsZipBytes = ZipDirectoryForDiagnostics(ectLogDir);
						}
						catch { }

						// --- Zip ADS diagnostic logs (sibling indicator) ---
						byte[] adsLogsZipBytes = null;
						try
						{
							string adsLogPath = System.IO.Path.Combine(
								userDataDir,
								"Affordable Indicators", "Accounts Dashboard", "log");
							if (System.IO.Directory.Exists(adsLogPath))
								adsLogsZipBytes = ZipDirectoryForDiagnostics(adsLogPath);
						}
						catch { }

						if (screenshotBytes == null && templateBytes == null && logsZipBytes == null && traceZipBytes == null && ectLogsZipBytes == null && adsLogsZipBytes == null)
						{
							try
							{
								ChartControl.Dispatcher.InvokeAsync(() =>
								{
									RemoveMessage(false, "Sending information");
									AddMessage("Nothing to send — capture failed.", 8, Brushes.Red);
								});
							}
							catch { }
							return;
						}

						string boundary = "----AiTemplateBoundary" + DateTime.Now.Ticks.ToString("x");
						string dateStr = DateTime.UtcNow.ToString("yyyy-MM-dd");
						string apiKey = DiagnosticsGenerateApiKey(email, machineId, dateStr);

						try { System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12; } catch { }

						HttpWebRequest request = (HttpWebRequest)WebRequest.Create(_sendTemplateEndpoint);
						request.Method = "POST";
						request.ContentType = "multipart/form-data; boundary=" + boundary;
						request.UserAgent = "NinjaTrader-aiEnhancedChartTrader/" + version;
						request.Timeout = 120000;
						request.ReadWriteTimeout = 120000;
						request.Headers.Add("X-AI-Api-Key", apiKey);
						request.Headers.Add("X-AI-Date", dateStr);
						try { request.Proxy = System.Net.WebRequest.GetSystemWebProxy(); if (request.Proxy != null) request.Proxy.Credentials = System.Net.CredentialCache.DefaultNetworkCredentials; } catch { request.Proxy = null; }

						using (var requestStream = request.GetRequestStream())
						{
							DiagnosticsWriteField(requestStream, boundary, "email", email);
							DiagnosticsWriteField(requestStream, boundary, "machine_id", machineId);
							DiagnosticsWriteField(requestStream, boundary, "version", version);
							DiagnosticsWriteField(requestStream, boundary, "product", product);
							DiagnosticsWriteField(requestStream, boundary, "timestamp", DateTime.UtcNow.ToString("o"));

							if (screenshotBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "screenshot", "chart_screenshot.png", "image/png", screenshotBytes);

							if (templateBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "template", "chart_template.xml", "application/xml", templateBytes);

							if (logsZipBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "logs", "logs.zip", "application/zip", logsZipBytes);

							if (traceZipBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "trace", "trace.zip", "application/zip", traceZipBytes);

							if (ectLogsZipBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "custom_ect", "custom_ect.zip", "application/zip", ectLogsZipBytes);

							if (adsLogsZipBytes != null)
								DiagnosticsWriteFile(requestStream, boundary, "custom_ads", "custom_ads.zip", "application/zip", adsLogsZipBytes);

							byte[] closingBytes = System.Text.Encoding.UTF8.GetBytes("--" + boundary + "--\r\n");
							requestStream.Write(closingBytes, 0, closingBytes.Length);
						}

						int maxRetries = 3;
						int retryDelayMs = 2000;
						bool success = false;
						for (int attempt = 1; attempt <= maxRetries && !success; attempt++)
						{
							try
							{
								using (HttpWebResponse response = (HttpWebResponse)request.GetResponse())
								using (StreamReader reader = new StreamReader(response.GetResponseStream()))
								{
									reader.ReadToEnd();
								}
								success = true;
							}
							catch
							{
								if (attempt < maxRetries)
									System.Threading.Thread.Sleep(retryDelayMs);
								else
									throw;
							}
						}

						try
						{
							ChartControl.Dispatcher.InvokeAsync(() =>
							{
								RemoveMessage(false, "Sending information");
								AddMessage("Information sent successfully!", 8, Brushes.Green);
							});
						}
						catch { }
					}
					catch (Exception ex)
					{
						// Print("SendDiagnostics upload error: " + ex.Message);
						try
						{
							ChartControl.Dispatcher.InvokeAsync(() =>
							{
								RemoveMessage(false, "Sending information");
								AddMessage("Send failed: " + ex.Message, 10, Brushes.Red);
							});
						}
						catch { }
					}
					finally
					{
						_isSendingTemplate = false;
					}
				});
			}
			catch (Exception ex)
			{
				// Print("SendDiagnostics error: " + ex.Message);
				RemoveMessage(false, "Sending information");
				AddMessage("Send failed: " + ex.Message, 10, Brushes.Red);
				_isSendingTemplate = false;
			}
		}

		private string DiagnosticsGenerateApiKey(string email, string machineId, string dateStr)
		{
			string message = email + "|" + machineId + "|" + dateStr;
			byte[] keyBytes = System.Text.Encoding.UTF8.GetBytes(_sendTemplateSecret);
			byte[] messageBytes = System.Text.Encoding.UTF8.GetBytes(message);
			using (var hmac = new System.Security.Cryptography.HMACSHA256(keyBytes))
			{
				byte[] hash = hmac.ComputeHash(messageBytes);
				return BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
			}
		}

		private void DiagnosticsWriteField(System.IO.Stream stream, string boundary, string name, string value)
		{
			string header = "--" + boundary + "\r\n"
				+ "Content-Disposition: form-data; name=\"" + name + "\"\r\n\r\n"
				+ value + "\r\n";
			byte[] headerBytes = System.Text.Encoding.UTF8.GetBytes(header);
			stream.Write(headerBytes, 0, headerBytes.Length);
		}

		private void DiagnosticsWriteFile(System.IO.Stream stream, string boundary, string fieldName, string fileName, string mimeType, byte[] data)
		{
			string header = "--" + boundary + "\r\n"
				+ "Content-Disposition: form-data; name=\"" + fieldName + "\"; filename=\"" + fileName + "\"\r\n"
				+ "Content-Type: " + mimeType + "\r\n\r\n";
			byte[] headerBytes = System.Text.Encoding.UTF8.GetBytes(header);
			stream.Write(headerBytes, 0, headerBytes.Length);
			stream.Write(data, 0, data.Length);
			byte[] newline = System.Text.Encoding.UTF8.GetBytes("\r\n");
			stream.Write(newline, 0, newline.Length);
		}

		private byte[] ZipDirectoryForDiagnostics(string dirPath)
		{
			string tempZip = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "aitr_" + Guid.NewGuid().ToString("N") + ".zip");
			try
			{
				using (var package = System.IO.Packaging.Package.Open(tempZip, System.IO.FileMode.Create))
				{
					string[] files = System.IO.Directory.GetFiles(dirPath, "*", System.IO.SearchOption.TopDirectoryOnly);
					foreach (string filePath in files)
					{
						try
						{
							string entryName = System.IO.Path.GetFileName(filePath);
							Uri partUri = new Uri("/" + Uri.EscapeDataString(entryName), UriKind.Relative);
							var part = package.CreatePart(partUri, "application/octet-stream", System.IO.Packaging.CompressionOption.Fast);
							using (var partStream = part.GetStream())
							using (var fs = new System.IO.FileStream(filePath, System.IO.FileMode.Open, System.IO.FileAccess.Read, System.IO.FileShare.ReadWrite))
							{
								fs.CopyTo(partStream);
							}
						}
						catch { }
					}
				}
				return System.IO.File.ReadAllBytes(tempZip);
			}
			finally
			{
				try { if (System.IO.File.Exists(tempZip)) System.IO.File.Delete(tempZip); } catch { }
			}
		}

        internal void OnMouseDown(object sender, MouseButtonEventArgs e)
        {
			// Licensing banner click. Banner draws over the whole chart panel
			// when !Permission, so any left-click while it's visible triggers
			// the appropriate flow: email popup for the email banners, or a
			// NinjaScript reload for the Machine ID banner.
			if (!Permission && e.ChangedButton == MouseButton.Left)
			{
				bool _isEmailPrompt = false;
				bool _isMachineIdPrompt = false;
				foreach (string s in AllErrorMessages)
				{
					if (s == null) continue;
					if (s.Contains("Hello!") || s.Contains("was not found"))
						_isEmailPrompt = true;
					else if (s.Contains("NinjaTrader Machine ID"))
						_isMachineIdPrompt = true;
				}

				// Fallback: if no message was recorded but the email is missing/invalid,
				// still treat as an email-prompt click.
				if (!_isEmailPrompt && !_isMachineIdPrompt
					&& (string.IsNullOrEmpty(pLicensingEmailAddress) || !pLicensingEmailAddress.Contains("@")))
				{
					_isEmailPrompt = true;
				}

				if (_isMachineIdPrompt && ChartControl != null)
				{
					// User has finished registering the Machine ID — reload
					// NinjaScript so licensing re-checks.
					try
					{
						ChartControl.Dispatcher.InvokeAsync(new Action(() =>
						{
							try
							{
								System.Windows.Window _win = System.Windows.Window.GetWindow(ChartControl);
								if (_win != null)
								{
									_win.Activate();
									System.Windows.Forms.SendKeys.SendWait("{F5}");
								}
							}
							catch { }
						}));
					}
					catch { }
				}
				else if (_isEmailPrompt && ChartControl != null)
				{
					try
					{
						ChartControl.Dispatcher.InvokeAsync(new Action(() =>
						{
							try
							{
								aiEnhancedChartTraderEmailEntryWindow _emailWin = new aiEnhancedChartTraderEmailEntryWindow()
								{
									selectedIndicator = this
								};
								try { _emailWin.Owner = System.Windows.Window.GetWindow(ChartControl); } catch { }
								_emailWin.ShowDialog();

								if (_emailWin.Confirmed)
								{
									try
									{
										System.Windows.Window _win = System.Windows.Window.GetWindow(ChartControl);
										if (_win != null)
										{
											_win.Activate();
											System.Windows.Forms.SendKeys.SendWait("{F5}");
										}
									}
									catch { }
								}
							}
							catch { }
						}));
					}
					catch { }
				}

				e.Handled = true;
				return;
			}

			// Panel header click
			if (e.ChangedButton == MouseButton.Left && MouseIn(headerRect, 3, 3))
			{
				draggingPanelId = PANEL_ID;
				dragStartY = (float)FinalYPixel;
				dragOffsetY = 0;
				if (ChartPanel != null) ChartPanel.CaptureMouse();
				e.Handled = true;
				return;
			}

			// Left-side panel button priority. When a pending order is on the
			// chart, order-flag hit rects are expanded by 2000 px (see the
			// ExpandRect calls at :78867, :72985, :73007, :80727) to cover the
			// order line for drag-to-move. On some chart widths those rects
			// bleed into the left-side button panel zone and the "move all at
			// this price" handler at :50723 returns before the button-dispatch
			// loop at :51241 can run — symptom: buttons below "Order Panel"
			// stop responding whenever a pending order exists.
			//
			// Fix: if the click lands inside the panel zone (B23) AND any
			// AllButtonZ3 button is hit, jump straight to the dispatch label
			// and skip every order hit-test in between.
			if (e.ChangedButton == MouseButton.Left && MouseIn(B23, 0, 0))
			{
				foreach (KeyValuePair<double, ButtonZ> _btnGate in AllButtonZ3)
				{
					if (MouseIn(_btnGate.Value.Rect, MenuButtonExpandP, MenuButtonExpandP))
					{
						goto PanelButtonDispatch;
					}
				}
			}

			if (e.ChangedButton == MouseButton.Right)
			{
				// Right-click disarms One Click mode without opening context menu
				if (InOneClick)
				{
					ResetAllActiveClickOrders();
					RefreshRender(250);
					e.Handled = true;
					return;
				}

				// Right-click has special meaning for stop-strategy markers:
				//   - cancel an in-progress move (revert to original)
				//   - reset a marker's draft to template when hovered (but no
				//     move is in progress)
				// All other right-clicks are ignored (preserves existing behavior).
				//
				// Right-click is now a uniform "cancel / reset" gesture across
				// all click-move-click flows. Handles in priority order:
				//   1. Cancel in-progress stop-strategy move
				//   2. Cancel in-progress target/stop move
				//   3. Cancel in-progress entry repositioning
				//   4. Reset hovered stop-strategy marker's draft to template
				// Cancellations 2 and 3 work even when stop-strategy management
				// is disabled, since they apply to non-stop-strategy moves.

				if (MovingATMOrders != null && MovingATMOrders.Count > 0)
				{
					// Cancel an in-progress target/stop move. The next render
					// will see the empty list and stop drawing the moving line.
					MovingATMOrders.Clear();
					RefreshRender(1200);
					return;
				}

				if (IsMovingPlan != null && IsMovingPlan != "")
				{
					// Cancel an in-progress entry-line reposition.
					IsMovingPlan = "";
					RemoveATMPlanEntry(13);
					RemoveMessage(false, ATMPlanWaitingForClick);
					RefreshRender(1200);
					return;
				}

				// H/L swing outline right-click → cycle stop source back to
				// Default. Cheaper than hunting for the SRC badge. Hit rect
				// is registered with lower priority than markers so it only
				// fires when nothing more specific is under the mouse.
				try
				{
					var hlHit = FindHoveredButton();
					if (hlHit != null && hlHit.Name == "HLOutline")
					{
						// Cycle until we hit Default (max 3 cycles since
						// CycleInitialExitsType walks Default → H/L → ATR → Default).
						int safety = 4;
						while (pInitialExitsType != "Default" && safety-- > 0)
							CycleInitialExitsType();
						RefreshRender(1202);
						return;
					}
				}
				catch { }

				// Master switch: skip the entire stop-strategy right-click
				// block when management is disabled. CancelActiveStopStrategyMove
				// is still safe to call (it just clears state) but the field
				// will be null because the click handler that creates moves is
				// also gated below.
				if (!pStopStrategyManagementDisabled)
				{
					if (_movingStopStrategyItem != null)
					{
						CancelActiveStopStrategyMove();
						RefreshRender(1200);
						return;
					}

					// Look for a stop-strategy hit rect under the mouse. If found,
					// clear that marker's draft.
					try
					{
						var hit = FindHoveredStopStrategyButton();
						if (hit != null)
						{
							MoveKind kind; int stepIdx;
							if (ParseStopStrategyRectName(hit.Name, out kind, out stepIdx))
							{
								int bi;
								ParseStopStrategyBracketIdx(hit.Name, out bi);
								ResetDraftForMarker(hit.ThisATM, bi, kind, stepIdx);
								RefreshRender(1201);
								return;
							}
						}
					}
					catch { }
				}

				return;
			}


			if (e.ChangedButton == MouseButton.Middle)
			{

//				if (MovingATMOrders.Count > 0)
//					MovingATMOrders.Clear();

//				ATMStrategyMoving = null;
//				ATMOrderSelected = null;



				return;
			}

			// NOTE: The unified hit-test resolver (ResolveHoverCategory) is
			// called ONCE PER FRAME at the top of OnRender, not here in
			// OnMouseDown. An earlier version of this code also ran the
			// resolver at the top of OnMouseDown (plus re-set MP /
			// FinalXPixel / FinalYPixel beforehand), which broke regular
			// order move and qty click handlers even though the resolver
			// itself wasn't involved in those paths. Reverted that — all
			// OnMouseDown hit tests now use the standard flow: MP is set
			// at :45406, the legacy foreach loops run with the same
			// FinalXPixel/Y that OnMouseMove already populated, and the
			// ATM plan line click loop uses a small local clickNearOrderMove
			// bool (further down) to enforce order-wins-over-plan-line
			// priority. The resolver's work is confined to OnRender where
			// it drives exclusive hover glow via HoverIsOrderOrHigher().

			// === Click-entry commit — HIGHEST PRIORITY =========================
			//
			// If the user has Buy Click / Sell Click / Iceberg / Time Sliced /
			// Buy Close / Sell Close / Move Targets / Move Stops active, a
			// click on the chart MUST commit that mode — no matter what else
			// the click might also hit.
			//
			// Why this is at the top of OnMouseDown: the stop-strategy marker
			// intercept just below (Auto BE / Trail markers rendered on ATM
			// plan stop lines) runs BEFORE the old click-entry handlers at
			// :45280, so if the user was placing a Buy Click near an Auto BE
			// marker, the stop-strategy block would swallow the click and
			// start a marker-move instead of placing the order. Same pattern
			// applies to any other future hit-test that runs above the old
			// click-entry block. Hoisting the commit-first-then-return here
			// makes click-entry modes modal — exactly like the move-completion
			// fix we did earlier for MovingOrder / MovingOrders.
			//
			// The old click-entry handlers down at ~:45280 are left in place
			// as a safety net / dead-code fallback; they won't fire because
			// this block always returns.
			{
				bool anyClickEntryActive =
					BuyClickReady || SellClickReady ||
					BuyCloseClick || SellCloseClick ||
					BuyIcebergClick || SellIcebergClick ||
					BuyTimeSlicedClick || SellTimeSlicedClick ||
					MoveTargetsClick || MoveStopsClick;

				if (anyClickEntryActive)
				{
					// Make sure MP is current for any downstream CurrentMousePrice
					// consumers. (CurrentMousePrice itself is already updated in
					// OnMouseMove, which fires before OnMouseDown.)
					this.MP = e.GetPosition(this.ChartPanel);

					// Block order placement when clicking on the Y axis (price scale)
					// — the user is dragging to rescale, not placing an order.
					if (MP.X >= ChartPanel.W || FinalXPixel >= ChartPanel.X + ChartPanel.W)
						goto SkipClickEntry;

					// Move Targets / Move Stops — click commits the move at the
					// current mouse price. Mirrors the :45070 handler.
					if (MoveTargetsClick || MoveStopsClick)
					{
						if (MoveTargetsClick)
						{
							MoveTargetsClick = false;
							ChartControl.Dispatcher.InvokeAsync((Action)(() =>
							{
								MoveAllTargetOrders(CurrentMousePrice, pMoveAllExitsTargetOffset, "Click", "");
							}));
						}
						if (MoveStopsClick)
						{
							MoveStopsClick = false;
							ChartControl.Dispatcher.InvokeAsync((Action)(() =>
							{
								MoveAllStopLossOrders(CurrentMousePrice, pMoveAllExitsStopOffset);
							}));
						}
						MoveExitsClick = false;
						UpdateButtons();
						RefreshRender(1160);
						return;
					}

					// Iceberg Buy — store the trigger price at above / below
					// ask/bid or start the order if at-market. Mirrors :45117.
					if (BuyIcebergClick)
					{
						if (CurrentMousePrice > CurrentAsk)
							BuyIcebergAtOrAbove = CurrentMousePrice;
						else if (CurrentMousePrice < CurrentBid)
							BuyIcebergAtOrBelow = CurrentMousePrice;
						else if (IcebergBuyOrderSequence == 0)
							StartIcebergOrder(BuyName);

						AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
						BuyIcebergClick = false;
						UpdateButtons();
						RefreshRender(1161);
						return;
					}

					// Iceberg Sell — mirror of BuyIcebergClick.
					if (SellIcebergClick)
					{
						if (CurrentMousePrice > CurrentAsk)
							SellIcebergAtOrAbove = CurrentMousePrice;
						else if (CurrentMousePrice < CurrentBid)
							SellIcebergAtOrBelow = CurrentMousePrice;
						else if (IcebergSellOrderSequence == 0)
							StartIcebergOrder(SellName);

						AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
						SellIcebergClick = false;
						UpdateButtons();
						RefreshRender(1162);
						return;
					}

					// Time Sliced Buy / Sell — set the trigger price. Mirrors :45184.
					if (BuyTimeSlicedClick)
					{
						BuyTimeSlicedClick = false;
						SetBuyTimeSlicedPrice(CurrentMousePrice, 0);
						AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
						RefreshRender(1163);
						return;
					}
					if (SellTimeSlicedClick)
					{
						SellTimeSlicedClick = false;
						SetSellTimeSlicedPrice(CurrentMousePrice, 0);
						AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
						RefreshRender(1164);
						return;
					}

					// Buy Close / Sell Close — place a close-above / close-below
					// custom order at the clicked price. Mirrors :45240.
					if (BuyCloseClick || SellCloseClick)
					{
						double closeRefClick = CurrentLast > 0 ? CurrentLast : CurrentLastData;
						string closettyppe = (CurrentMousePrice > closeRefClick) ? "Above" : "Below";
						string thisnaaa = BuyCloseClick ? "BUY" : "SELL";
						PlaceCustomOrder(thisnaaa, "Close", closettyppe);

						BuyCloseClick = false;
						SellCloseClick = false;
						SelectPlotClickEntry = false;

						UpdateButtons();
						RefreshRender(1165);
						return;
					}

					// Buy Click — place at the clicked price. Mirrors :45280.
					//
					// If the user was in plot-selection mode (SelectPlotClickEntry
					// — enabled when pAttachClickEnabled && pAttachmentOrdersButtonOK
					// at BuyClickNow:~16523) AND the click landed on a plot,
					// stash HoveredIndicator/HoveredPlot into NextIndicator /
					// NextPlot BEFORE placing. For REAL orders (BuyLimit/BuyStop
					// path) this is consumed by OnOrderUpdate at :35738 to
					// attach the order to the plot after it's accepted. For LIT
					// orders (PlaceCustomOrder path) the attach is handled
					// directly via HoveredIndicator at :45198. Either way, we
					// must clear SelectPlotClickEntry here so the selecting-plot
					// cursor mode deactivates — without this the fallback
					// SelectPlotClickEntry block at :45987 never runs (we return
					// first) and the mode sticks.
					LogDiag("CLICK_ENTRY", "Commit", "Buy=" + BuyClickReady + ", Sell=" + SellClickReady);
					UseMarketOrderOnNextClick = Keyboard.IsKeyDown(Key.LeftShift) || Keyboard.IsKeyDown(Key.RightShift);

					if (BuyClickReady)
					{
						if (SelectPlotClickEntry && HoveredPlot != -1)
						{
							NextIndicator = HoveredIndicator;
							NextPlot = HoveredPlot;
						}
						SelectPlotClickEntry = false;
						BuyThisPrice(CurrentMousePrice);
						return;
					}

					// Sell Click — mirror of BuyClickReady.
					if (SellClickReady)
					{
						if (SelectPlotClickEntry && HoveredPlot != -1)
						{
							NextIndicator = HoveredIndicator;
							NextPlot = HoveredPlot;
						}
						SelectPlotClickEntry = false;
						SellThisPrice(CurrentMousePrice);
						return;
					}
				}
			}
			SkipClickEntry:
			// === End click-entry commit block ==================================

			// === Order flag priority guard =====================================
			//
			// Compute whether the click lands on an order-flag move rect early,
			// so downstream handlers with wide hit rects (iceberg / time-sliced
			// move rects extend 2000 px right, MoveInProfitActionRect can span
			// the plan width, PlaceOrderRect sits at the plan entry) can skip
			// themselves when an order flag is under the cursor. Without this
			// guard, clicking on an order flag that happens to sit on the same
			// Y level as a pending iceberg / TS or in-profit-action strip will
			// trigger the wider rect instead of starting the flag move.
			//
			// Uses the same ±5 px Y slop as the existing :48076 computation so
			// behavior matches the ATM plan line guard already in place.
			//
			// Must run BEFORE any ChartControl.MP-dependent checks; uses
			// OnMouseMove's cached FinalXPixel/Y via MouseIn.
			// earlyClickNearOrderMove — click is on a REAL order's move rect
			// (AllOrderMoveButtons / AllLITOrderMoveButtons). Used to gate
			// iceberg / time-sliced / MoveInProfitAction / PlaceOrder handlers
			// so real-order clicks win over those wider rects.
			// Use `exmbl, exmbl` to match the actual order-move click handler
			// rect (see :52244). Was ±5 px Y, which gated iceberg/TS/plan
			// handlers off in a 5 px zone where the order-move click handler
			// itself also missed (it uses exmbl) — so clicks in that zone
			// silently did nothing.
			bool earlyClickNearOrderMove = false;
			if (AllOrderMoveButtons != null)
			{
				foreach (KeyValuePair<double, OrderDetails> omBtn in AllOrderMoveButtons)
				{
					if (MouseIn(omBtn.Value.ThisRectA, exmbl, exmbl))
					{
						earlyClickNearOrderMove = true;
						break;
					}
				}
			}
			if (!earlyClickNearOrderMove && AllLITOrderMoveButtons != null)
			{
				foreach (KeyValuePair<double, OrderDetails> omBtn in AllLITOrderMoveButtons)
				{
					if (MouseIn(omBtn.Value.ThisRectA, exmbl, exmbl))
					{
						earlyClickNearOrderMove = true;
						break;
					}
				}
			}

			// earlyClickOnAnyOrderElement — click is on ANY order-related
			// rect (real order, LIT, iceberg, time-sliced). Used to gate the
			// ATM planning handlers (stop-strategy markers, plan lines) so
			// they NEVER steal clicks meant for order flags. This is
			// SEPARATE from earlyClickNearOrderMove because the iceberg / TS
			// move-rect handlers are gated on !earlyClickNearOrderMove — if
			// we used a single variable, those handlers would skip themselves
			// when clicking on an iceberg (since the iceberg rect would be
			// part of "near order move").
			bool earlyClickOnAnyOrderElement = earlyClickNearOrderMove
				|| MouseIn(IcebergBuyOrderMoveRect, 0, 5)
				|| MouseIn(IcebergSellOrderMoveRect, 0, 5)
				|| MouseIn(TimeSlicedBuyOrderMoveRect, 0, 5)
				|| MouseIn(TimeSlicedSellOrderMoveRect, 0, 5);
			// === End order flag priority guard =================================

			// === ATM plan toggle priority guard ================================
			// MoveInProfitActionRect (set in DrawInProfitActionLines) and
			// PlaceOrderRect span the plan entry line. Without this guard, a
			// click on an ATM plan toggle (Hide, Now/Price, R/R, IE, Split,
			// Entry direction, StopSrc) at the entry-line Y would be eaten by
			// the wide-rect handlers below and never reach the
			// AllATMStrategyLevelButtons dispatch loop. Most visible symptom:
			// Hide shows hover glow but click does nothing when the plan is
			// attached to a live resting order (which is when the IPA rect
			// happens to render across the entry line).
			//
			// Pre-scan AllATMStrategyLevelButtons for a hit; gate downstream
			// wide-rect handlers on this so plan toggles win the click.
			// Exclude PlaceOrderRect hits from the toggle pre-scan. The Place
			// Order button is rendered centered on the entry line (y1), so it
			// sits inside the entry-row plan-line drag rect (ThisRectA). Without
			// this exclusion, clicking the Place Order button sets
			// earlyClickOnAtmPlanToggle = true, which then gates off the Place
			// Order handler at :50009 — so the button visually responds to hover
			// but the click does nothing. Toggles (Hide / R/R / IE / direction)
			// are on the left side of the line; PlaceOrderRect is to the right
			// of the entry text, so excluding PlaceOrderRect hits here does not
			// affect any toggle's win-the-click behavior.
			bool earlyClickOnPlaceOrder = (PlaceOrderRect.Width > 0) && MouseIn(PlaceOrderRect, exmbl, exmbl);
			bool earlyClickOnAtmPlanToggle = false;
			if (AllATMStrategyLevelButtons != null && !earlyClickOnPlaceOrder)
			{
				foreach (KeyValuePair<double, ATMMoveDetails> _atmBtn in AllATMStrategyLevelButtons)
				{
					if (_atmBtn.Value != null && MouseIn(_atmBtn.Value.ThisRectA, exmbl, exmbl))
					{
						earlyClickOnAtmPlanToggle = true;
						break;
					}
				}
			}

			// === Stop-strategy marker click handling (left button only) ===
			// If a move is already in progress: this click commits the move.
			// Otherwise: if the mouse is over a stop-strategy marker, start a move.
			// Falls through to the existing hit-test chain if nothing matches.
			//
			// Master switch: when stop-strategy management is disabled, skip
			// the entire block. _movingStopStrategyItem will be null because
			// the only path that creates it is also gated below.
			if (!pStopStrategyManagementDisabled && _movingStopStrategyItem != null)
			{
				// Second click of a click-move-click — commit at current mouse.
				CommitActiveStopStrategyMove();
				RefreshRender(1202);
				return;
			}
			if (!pStopStrategyManagementDisabled)
			{
				ATMMoveDetails hit = null;
				// Order flag clicks always win: if the click lands on ANY
				// order-related rect (real order, LIT, iceberg, time-sliced),
				// skip the stop-strategy marker hit-test so Auto BE / Trail
				// markers sitting behind the flag can't steal the click.
				// Uses the broader earlyClickOnAnyOrderElement so iceberg
				// and TS pending flags are covered too.
				if (!earlyClickOnAnyOrderElement)
				{
					try { hit = FindHoveredStopStrategyButton(); } catch { }
				}
				if (hit != null)
				{
					MoveKind kind; int stepIdx;
					if (ParseStopStrategyRectName(hit.Name, out kind, out stepIdx))
					{
						int bi;
						ParseStopStrategyBracketIdx(hit.Name, out bi);

						// Snapshot the current value so Escape can revert.
						int origTicks = 0;
						try
						{
							var info = ReadAtmStopStrategyInfo(hit.ThisATM, bi);
							if (info != null)
							{
								if (kind == MoveKind.AutoBETrigger) origTicks = info.AutoBEProfitTrigger;
								else if (kind == MoveKind.TrailStepTrigger && stepIdx >= 0 && stepIdx < info.AutoTrailSteps.Count)
									origTicks = info.AutoTrailSteps[stepIdx].ProfitTrigger;
							}
						}
						catch { }

						// Compute mu / entry from the current plan direction so
						// the move math doesn't depend on where the click came
						// from in the render loop.
						int mu2 = (pLastPlanDirection == "Short") ? -1 : 1;
						double entry2 = (LastPlanEntry != 0) ? LastPlanEntry : CurrentLastData;
						if (hit.EntryPrice != 0) entry2 = hit.EntryPrice;

						// Mutual exclusion: starting a stop-strategy move cancels
						// any in-progress target/stop move so the user can't end
						// up dragging two things at once.
						if (MovingATMOrders != null && MovingATMOrders.Count > 0)
							MovingATMOrders.Clear();

						_movingStopStrategyItem = new MovingStopStrategyItem
						{
							Atm = hit.ThisATM,
							BracketIdx = bi,
							Kind = kind,
							StepIdx = stepIdx,
							OriginalTicks = origTicks,
							Mu = mu2,
							EntryPrice = entry2,
						};
						RefreshRender(1203);
						return;
					}
				}
			}
				
			
			//Print("MouseUp");
			
			
			//e.GetType
			
            this.MP = e.GetPosition(this.ChartPanel);

			//return;
			
            IsDragging = true;

				
				
		
				
			if (AllErrorMessages.Count > 0)
			{
				AllErrorMessages.Clear();
				RefreshRender(1123);
				return;
				
			}
			
			
		
			

				if (MouseIn(ClickEntryCancelRect,exmbl,exmbl))
				{
					BuyClickReady = false;
					SellClickReady = false;

					BuyIcebergClick = false;
					SellIcebergClick = false;

					BuyTimeSlicedClick = false;
					SellTimeSlicedClick = false;

					BuyCloseClick = false;
					SellCloseClick = false;

					MoveTargetsClick = false;
					MoveStopsClick = false;
					MoveExitsClick = false;

					// Cancel any in-progress stop-strategy / target / stop move
					// so we don't return to a stuck "waiting for drop click"
					// state after the cancel button is hit.
					_movingStopStrategyItem = null;
					if (MovingATMOrders != null) MovingATMOrders.Clear();

					UpdateButtons();

					RefreshRender(1124);

					return;

				}

			if (MoveExitsClick)
			{
				
				MoveExitsClick = false;
				
				
				
				if (MoveTargetsClick)
				{
					
					MoveTargetsClick = false;					
						   
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						
						MoveAllTargetOrders(CurrentMousePrice, pMoveAllExitsTargetOffset, "Click", "");
						
					}));

					
					
				}
				if (MoveStopsClick)
				{
					
					MoveStopsClick = false;
						
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						
						MoveAllStopLossOrders(CurrentMousePrice, pMoveAllExitsStopOffset);
						
					}));
				}
				
				
				UpdateButtons();
				RefreshRender(1125);
				
				return;
					
					
			}
			
			
								

				if (BuyIcebergClick)				
				{
					
					if (CurrentMousePrice > CurrentAsk)
					{
						BuyIcebergAtOrAbove = CurrentMousePrice;
					}       
					else if (CurrentMousePrice < CurrentBid)
					{
						BuyIcebergAtOrBelow = CurrentMousePrice;
					}	
					else
					{
						if (IcebergBuyOrderSequence == 0)
							StartIcebergOrder(BuyName);
					}

					AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
					
					BuyIcebergClick = false;
					UpdateButtons();
					RefreshRender(1126);
					
					
					
					
				
					return;
					
				}
				
				if (SellIcebergClick)				
				{
					
					if (CurrentMousePrice > CurrentAsk)
					{
						SellIcebergAtOrAbove = CurrentMousePrice;
					}       
					else if (CurrentMousePrice < CurrentBid)
					{
						SellIcebergAtOrBelow = CurrentMousePrice;
					}	
					else
					{
						if (IcebergSellOrderSequence == 0)
							StartIcebergOrder(SellName);
					}
					
					AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
					
					
					
					SellIcebergClick = false;
					UpdateButtons();
					RefreshRender(1127);
					
					
					
					
					
					return;
					
				}
				
	
				
				
				if (BuyTimeSlicedClick)				
				{
					
					BuyTimeSlicedClick = false;					
					SetBuyTimeSlicedPrice(CurrentMousePrice, 0);
					
					AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
					
					RefreshRender(1128);
					
					
					
					return;
					
				}
				
				if (SellTimeSlicedClick)				
				{
					
					SellTimeSlicedClick = false;					
					SetSellTimeSlicedPrice(CurrentMousePrice, 0);
					
					AddATMPlanEntry(CurrentMousePrice, pShowPlanSeconds333);
					
					RefreshRender(1129);
					
					
					
					return;
					
				}
				
					
			
				if (SelectPlotClickEntry)
				{
					//Print("Indicator:" +pTrailingStopIndicator);
					//Print("Plot:" +pTrailingStopPlot);

					// Reject plot clicks past the right edge of the last bar.
					// The plot line can be rendered extending to the right of
					// the hard-right bar, but attaching an order to that
					// "future" segment is almost always a misclick -- the plot
					// has no real value there yet.
					bool pastRightEdge = false;
					try
					{
						if (BarsArray != null && BarsArray[0] != null && BarsArray[0].Count > 0)
						{
							int lastBarIdx = Math.Min(ChartBars.ToIndex, BarsArray[0].Count - 1);
							double lastBarX = ChartControl.GetXByBarIndex(ChartBars, lastBarIdx);
							if (FinalXPixel > lastBarX)
								pastRightEdge = true;
						}
					}
					catch { /* chart not ready -- fall through to legacy behavior */ }

					if (HoveredPlot != -1 && !pastRightEdge)
					{
						NextIndicator = HoveredIndicator;
						NextPlot = HoveredPlot;
					}

					SelectPlotClickEntry = false;

					//RefreshRender(1113);
				//	return;

				}
				
				
				if (BuyCloseClick || SellCloseClick)
				{
					string closettyppe = string.Empty;

					double closeRefClick2 = CurrentLast > 0 ? CurrentLast : CurrentLastData;
					if (CurrentMousePrice > closeRefClick2)
					{
						closettyppe = "Above";

					}
					else
					{
						closettyppe = "Below";

					}

					string thisnaaa = "SELL";
					if (BuyCloseClick) thisnaaa = "BUY";

					PlaceCustomOrder(thisnaaa,"Close",closettyppe);
									
					

					BuyCloseClick = false;
					SellCloseClick = false;
					
							
					SelectPlotClickEntry = false;
							
							
					UpdateButtons();
					
					
					RefreshRender(1130);
					return;					
					
				}
				
				
				
				
				if (BuyClickReady && MP.X < ChartPanel.W && FinalXPixel < ChartPanel.X + ChartPanel.W)
				{

					BuyThisPrice(CurrentMousePrice);
					return;
				}

				if (SellClickReady && MP.X < ChartPanel.W && FinalXPixel < ChartPanel.X + ChartPanel.W)
				{

					SellThisPrice(CurrentMousePrice);
					return;
				}
								
				
			
	

			
			if (InProfitActionIcebergClick) 
			{
				
				InProfitActionCurrentPrice = CurrentMousePrice;
				
	
					if (IcebergBuyOrderSequence != 0)
					{
						InProfitActionCurrentTicks = (int) Math.Round((InProfitActionCurrentPrice - ThisPositionNow().AveragePrice)/ThisTickSize);
						
						
					}
					
					if (IcebergSellOrderSequence != 0)
					{
									
						InProfitActionCurrentTicks = (int) Math.Round((ThisPositionNow().AveragePrice - InProfitActionCurrentPrice)/ThisTickSize);
					}
			
				
					//Print(InProfitActionCurrentTicks);
				
					InProfitActionIcebergClick = false;
					
					RefreshRender(1131);
					RefreshRender(1132);
					
					
				return;
				
				
			}
				
		
		
	
		

		 
			
			// Live-order ATM chip click — toggles the plan display for that order.
			// Wins priority over plan toggles / order-move below because the chip
			// renders to the LEFT of the flag (its own rect) and is the only way
			// to show/hide the plan for a live resting order. _liveOrderChipRect
			// is populated each render frame in DrawOrders only when the chip is
			// currently visible (mouse over flag, chip, or corridor), so dispatch
			// here only fires when the user can actually see the chip.
			if (_liveOrderChipRect != null && _liveOrderChipRect.Count > 0)
			{
				foreach (KeyValuePair<string, SharpDX.RectangleF> kv in _liveOrderChipRect)
				{
					if (MouseIn(kv.Value, exmbl, exmbl))
					{
						double chipPrice;
						if (_liveOrderChipPrice.TryGetValue(kv.Key, out chipPrice) && chipPrice != 0)
						{
							// Toggle plan visibility for this order's price.
							// Currently showing = key present AND expiration in future.
							bool currentlyShowing = OrderPriceToATMDisplayEnd.ContainsKey(chipPrice)
								&& OrderPriceToATMDisplayEnd[chipPrice] > DateTime.Now;

							if (currentlyShowing)
							{
								OrderPriceToATMDisplayEnd.Remove(chipPrice);
							}
							else
							{
								// Use the standard plan-display duration
								// (pShowPlanSeconds333) so the plan auto-fades
								// like it does on initial placement. User can
								// click the chip again to refresh, or click
								// again before fade to manually hide.
								AddATMPlanEntry(chipPrice, pShowPlanSeconds333);
							}
							RefreshRender(1170);

							// Keep the hand cursor pinned across the click — the
							// chip rect doesn't disappear (mouse hasn't moved), so
							// the cursor should remain Hand. Without this explicit
							// push, NT can momentarily revert the cursor before the
							// next OnRender's ApplyHoverCursor restores it.
							UpdateHoverCursor();
						}
						return;
					}
				}
			}

			if (MouseIn(PlaceOrderRect,exmbl,exmbl) && !earlyClickNearOrderMove && !earlyClickOnAtmPlanToggle)
				{

					if (!IsHardRightEdge)
					{
						// Show the warning here (on the actual click attempt) rather
						// than on every hover frame at the draw site, so the hint only
						// surfaces when the user actually tries to use the button.
						AddMessage("You must be viewing the current bar to place an order using this button.", 5, Brushes.Goldenrod);
						return;
					}

					if (pMarketPlanActive)
					{
						
						if (pThisSummary44TypeMode == "Market Entry Orders")
						{
							if (pLastPlanDirection == "Long")
								BuyMarketButton();
							if (pLastPlanDirection == "Short")
								SellMarketButton();							
						}
						else if (pThisSummary44TypeMode == "Limit Entry Orders 1")
						{
							if (pLastPlanDirection == "Long")
								BuyLimitButton(pLimitOrderOffset4, pLimit1EntryType, pLimit1EntryBasis);
							if (pLastPlanDirection == "Short")
								SellLimitButton(pLimitOrderOffset4, pLimit1EntryType, pLimit1EntryBasis);
							
						}
						else if (pThisSummary44TypeMode == "Limit Entry Orders 2")
						{
							if (pLastPlanDirection == "Long")
								BuyLimitButton(pLimitOrderOffset5, pLimit2EntryType, pLimit2EntryBasis);
							if (pLastPlanDirection == "Short")
								SellLimitButton(pLimitOrderOffset5, pLimit2EntryType, pLimit2EntryBasis);
							
						}						
					}
					else
					{
						// Prefer the locked plan-in-progress price when present, otherwise
						// fall back to the currently drawn entry-line price (LastPlanEntry).
						// In the Buy/Sell Click preview state (no plan placed yet),
						// pIsPlanInProgress is 0 and BuyThisPrice(0) silently does nothing —
						// LastPlanEntry tracks the actual line price after the sentinel
						// 12/13 mouse reassignment, so click executes at what the user sees.
						double placeClickPrice = (pIsPlanInProgress != 0) ? pIsPlanInProgress : LastPlanEntry;

						if (pLastPlanDirection == "Long")
						{

							if (!CheckNewTradeReady())
								return;
							else
								BuyThisPrice(placeClickPrice);
						}
						else
						if (pLastPlanDirection == "Short")
						{
							if (!CheckNewTradeReady())
								return;
							else
								SellThisPrice(placeClickPrice);
						}




					}
					

					
					HidePlan(false);
					ClicksInATM = 0;
					RemoveATMPlanEntry(pIsPlanInProgress);
					
					
					
					RefreshRender(1133);
					
					return;
					
				}	
				
				
				
				
			
				if (MouseIn(ModeInProfitActionRect,exmbl,exmbl))
				{
					if (pIcebergInProfitActionAction == "Cancel")												
					{
						pIcebergInProfitActionAction = "Fill";
					}
					else if (pIcebergInProfitActionAction == "Fill")
					{
						pIcebergInProfitActionAction = "Cancel";
					}			
					
					RefreshRender(1134);
					
					return;
					
				}	
				
				
				
				
				if (MouseIn(MoveInProfitActionRect,exmbl,exmbl) && !earlyClickNearOrderMove && !earlyClickOnAtmPlanToggle)
				{
					InProfitActionIcebergClick = true;
					return;
				}

				// Skip iceberg / time-sliced move/cancel actions when the click
				// landed on one of the synthetic flag's qty-adjust rects. The
				// iceberg / TS move rects are extended 2000 px to the right
				// (ExpandRect(ThisRect,0,2000,...)) so they overlap the qty
				// text area, and without this guard clicking the qty number
				// would cancel/re-arm the pending order instead of starting
				// a quantity adjustment. AllOrderQuantityButtons contains the
				// SYN:* entries registered by DrawSyntheticOrders for the
				// iceberg / time-sliced flags.
				bool clickedSyntheticQty = false;
				if (pAllowOrderQuantityAdjustment)
				{
					foreach (var qtyBtn in AllOrderQuantityButtons)
					{
						if (qtyBtn.Value.Name != null && qtyBtn.Value.Name.StartsWith("SYN:")
							&& MouseIn(qtyBtn.Value.ThisRectA, exmbl, exmbl))
						{
							clickedSyntheticQty = true;
							break;
						}
					}
				}

				if (MouseIn(IcebergBuyOrderCancelRect,exmbl,exmbl))
				{
					BuyIcebergAtOrAbove = 0;
					BuyIcebergAtOrBelow = 0;

					UpdateButtons();

					RefreshRender(1135);

					return;

				}
				if (MouseIn(IcebergBuyOrderMoveRect,0,0) && !BuyIcebergClick && !clickedSyntheticQty && !earlyClickNearOrderMove)
				{
					if (BuyIcebergAtOrAbove != 0 || BuyIcebergAtOrBelow != 0)
					{
						BuyIcebergAtOrAbove = 0;
						BuyIcebergAtOrBelow = 0;
						BuyIcebergClick = true;

					}

					UpdateButtons();

					RefreshRender(1136);

					return;

				}

				if (MouseIn(IcebergSellOrderCancelRect,exmbl,exmbl))
				{

					SellIcebergAtOrAbove = 0;
					SellIcebergAtOrBelow = 0;

					UpdateButtons();

					RefreshRender(1137);

					return;

				}
				if (MouseIn(IcebergSellOrderMoveRect,0,0) && !SellIcebergClick && !clickedSyntheticQty && !earlyClickNearOrderMove)
				{


					if (SellIcebergAtOrAbove != 0 || SellIcebergAtOrBelow != 0)
					{
						SellIcebergAtOrAbove = 0;
						SellIcebergAtOrBelow = 0;
						SellIcebergClick = true;

					}


					UpdateButtons();

					RefreshRender(1138);

					return;

				}



				if (MouseIn(TimeSlicedBuyOrderCancelRect,exmbl,exmbl))
				{

					CancelTimeSlicedOrder("Buy");


//					BuyTimeSlicedAtOrAbove = 0;
//					BuyTimeSlicedAtOrBelow = 0;

//					UpdateButtons();

					RefreshRender(1139);

					return;

				}

				if (MouseIn(TimeSlicedBuyOrderMoveRect,0,0) && !BuyTimeSlicedClick && !clickedSyntheticQty && !earlyClickNearOrderMove)
				{
//					if (BuyTimeSlicedAtOrAbove != 0 || BuyTimeSlicedAtOrBelow != 0)
//					{
//						BuyTimeSlicedAtOrAbove = 0;
//						BuyTimeSlicedAtOrBelow = 0;
//						BuyTimeSlicedClick = true;

//					}

				if (TimeSlicedBuyPricePending())
						CancelTimeSlicedOrder("Buy");
					BuyTimeSlicedClick = true;

					UpdateButtons();

					RefreshRender(1140);

					return;

				}

				if (MouseIn(TimeSlicedSellOrderCancelRect,exmbl,exmbl))
				{

					CancelTimeSlicedOrder("Sell");

//					SellTimeSlicedAtOrAbove = 0;
//					SellTimeSlicedAtOrBelow = 0;

//					UpdateButtons();

					RefreshRender(1141);

					return;

				}
				if (MouseIn(TimeSlicedSellOrderMoveRect,0,0) && !SellTimeSlicedClick && !clickedSyntheticQty && !earlyClickNearOrderMove)
				{


//					if (SellTimeSlicedAtOrAbove != 0 || SellTimeSlicedAtOrBelow != 0)
//					{
//						SellTimeSlicedAtOrAbove = 0;
//						SellTimeSlicedAtOrBelow = 0;
//						SellTimeSlicedClick = true;

//					}



				if (TimeSlicedSellPricePending())
						CancelTimeSlicedOrder("Sell");
				SellTimeSlicedClick = true;


					UpdateButtons();

					RefreshRender(1142);

					return;

				}
				
				
				
			
				if (MouseIn(MoveOrderCancelRect1,exmbl,exmbl))
				{
					MovingOrder = null;
					MovingOrders.Clear();

					UpdateHoverCursor();
					RefreshRender(1143);

					return;

				}

				if (MouseIn(MoveOrderCancelRect2,exmbl,exmbl))
				{
					MovingOrder = null;
					MovingOrders.Clear();

					UpdateHoverCursor();
					RefreshRender(1144);

					return;

				}

				// === Move completion — HIGH PRIORITY ===
				//
				// If a move is in progress, clicking ANYWHERE on the chart
				// must commit the move. This block is intentionally placed
				// very early in OnMouseDown — right after the move-cancel
				// rects — so that the move always completes regardless of
				// what else the click might also hit.
				//
				// Why this was a bug: the original placement of this block
				// was much further down, after ALL the order-attachment and
				// quantity-button loops and after several early-return paths.
				// If the click happened to land on one of those (e.g. another
				// ATM strategy plan line, a different order's attach button),
				// that handler's `return` swallowed the click and the move
				// never committed. The user reported this exact symptom with
				// ATM plan line clicks. Commit-first-then-consume fixes it
				// for every possible overlap.
				//
				// Safety: if a move completes here, we `return` immediately so
				// the click doesn't also trigger unrelated handlers (e.g.
				// starting a new move on a different order the click happened
				// to overlap). The user can start a new move with a fresh
				// click. This matches how professional trading platforms
				// handle modal operations.
				if (MovingOrder != null)
				{
					CheckMoveStops(MovingOrder);

					if (pAttachMoveDisableTracking)
						DisableTrackedOrders(MovingOrder);

					MoveOrder(MovingOrder, CurrentMousePrice, 0);

					// If the click landed on a plot, attach this order to it.
					// Mirrors the behavior of the SelectedOrders attach loop at
					// :47291 — without this, the order snaps to the plot's
					// price (because CurrentMousePrice happens to equal the
					// plot value) but the attach is never persisted.
					if (HoveredIndicator != -1 && HoveredPlot != -1)
						SetOrderIndicatorTracking(MovingOrder, HoveredIndicator, HoveredPlot, "Change Plot");

					MovingOrder = null;

					// Clear plot-selection cursor mode. The flag-body click that
					// started the move added the order to SelectedOrders (via
					// pAttachMoveEnableTracking at :47999), which is one of the
					// conditions IsSelectingAPlot watches at :60595. Without
					// this clear, the cursor stays in "select a plot" mode
					// after the move commits because we return before reaching
					// the legacy SelectedOrders.Clear() at :47324.
					SelectedOrders.Clear();

					// Intentionally do NOT call UpdateHoverCursor() here.
					// The mouse is sitting on the just-dropped order's new
					// position; clicking again would start another move, so
					// the hand cursor should persist. Clearing the override
					// here would flip to arrow and only resync to hand once
					// the user moves the mouse. Leaving the drag-time override
					// in place keeps the hand visible until OnMouseMove fires
					// with fresh AllOrderMoveButtons hit-test data and
					// re-evaluates naturally.
					RefreshRender(1150);
					return;
				}

				if (MovingOrders.Count > 0)
				{
					bool clickedAPlot = HoveredIndicator != -1 && HoveredPlot != -1;
					foreach (Order oo in MovingOrders)
					{
						CheckMoveStops(oo);

						if (pAttachMoveDisableTracking)
							DisableTrackedOrders(oo);

						MoveOrder(oo, CurrentMousePrice, 0);

