						// configured (the 'A' button branch at :46989
						// adds the order to SelectedOrders, then this
						// loop runs on the next click when the plot is
						// hovered).
						try
						{
							int storedOffsetTicks = 0;
							int storedPlot = HoveredPlot;
							if (or.TrackingIndicator != null)
							{
								foreach (TrackedOrder lookupTr in or.TrackingIndicator.TrackedOrders)
								{
									if (lookupTr.Order != null && lookupTr.Order.OrderId == or.OrderId)
									{
										storedOffsetTicks = lookupTr.OffsetTicks;
										storedPlot = lookupTr.Plot;
										break;
									}
								}
							}
							double plotValueNow = GetThisPlotValue(HoveredIndicator, storedPlot, 0);
							if (plotValueNow > 0)
							{
								double targetPrice = RTTS(plotValueNow + storedOffsetTicks * ThisTickSize);
								if (targetPrice > 0)
