			// SelectingPlotForCustomOrder = cod.FPrice without actually
			// attaching anything — it just arms plot-selection mode. The
			// NEXT click (this one) must:
			//   1. Set the order's AttachedIndicator / AttachedPlot so the
			//      plot attachment is persisted.
			//   2. Compute the plot's current price + offset and move the
			//      order there immediately — matching the behavior the user
			//      gets when 'A' is clicked on an already-tracking-configured
			//      order (see the cod.AttachedConfigured branch at :46790).
			//   3. Clear the plot-selection mode and return so the downstream
			//      LIT move loop at :47613 doesn't also fire (it would re-
			//      call MoveCustomOrder with CurrentMousePrice, not the plot
			//      price, and would NOT set the attach fields because the
			//      existing order's Switch flag is false).
			if (SelectingPlotForCustomOrder != 0)
			{
				if (HoveredIndicator != -1 && HoveredPlot != -1
					&& AllCustomOrders.ContainsKey(SelectingPlotForCustomOrder))
				{
					CustomOrderDetails origCod = AllCustomOrders[SelectingPlotForCustomOrder];

					// Write the attach fields onto the original order so
					// MoveCustomOrder's Z copy picks them up at :45095.
					origCod.AttachedIndicator = HoveredIndicator;
					origCod.AttachedPlot = HoveredPlot;
					origCod.AttachedConfigured = true;

					// Compute target price from the plot value + the order's
					// saved offset, same formula used by the already-tracking
					// 'A' path at :46796.
					double plotPriceNow = GetThisPlotValue(HoveredIndicator, HoveredPlot, 0);
					double plotTargetPrice = RTTS(plotPriceNow + origCod.AttachedOffset * ThisTickSize);

					if (origCod.FPrice != plotTargetPrice)
						MoveCustomOrder(origCod, plotTargetPrice);

					SelectingPlotForCustomOrder = 0;
					RefreshRender(1167);
					return;
				}

				// Click landed somewhere that isn't a plot — cancel plot
				// selection without side effects.
				SelectingPlotForCustomOrder = 0;
			}
			
			
			
