			// Guard: ATM strategy plan lines lose priority when the click
			// is near an order flag's move rect. Plan lines use a ±5 px Y
			// slop and span the plan width, so they can intercept clicks
			// that the user actually meant for a nearby order flag.
			//
			// Note: the order-move loop at :47575 already runs first, so
			// if a click cleanly hits an order-move rect, it will have
			// returned before we get here. This guard covers the case
			// where the order-move loop missed by a pixel or two but the
			// click was STILL more plausibly targeting the order than the
			// plan line.
			//
			// Using a local bool computed inline here (instead of reading
			// the unified resolver's result) because the resolver is only
			// refreshed once per OnRender frame, and by the time the click
			// reaches this loop, several earlier handlers could have
			// changed state. The resolver stays authoritative for OnRender
			// hover glow (via HoverIsOrderOrHigher) — click paths use
			// local inline checks like the one below.
			// Reuse the broader earlyClickOnAnyOrderElement computed at the
			// top of OnMouseDown — covers real orders, LIT, iceberg, and
			// time-sliced rects, so plan lines never steal clicks meant for
			// ANY kind of order flag.
			bool clickNearOrderMove = earlyClickOnAnyOrderElement;

			// Iterate by Priority descending (then by insertion order descending
			// for ties), so the highest-priority hit wins regardless of when
			// the rect was added during the render loop. This makes click
			// routing deterministic instead of dependent on draw order.
			foreach (KeyValuePair<double, ATMMoveDetails> thisbutton in
				AllATMStrategyLevelButtons.OrderByDescending(kv => kv.Value != null ? kv.Value.Priority : 0)
				                          .ThenByDescending(kv => kv.Key))
                {

					CurrentButtonAll++;

					//foreach (SharpDX.RectangleF R in BlockTradeButtons)
					//{

					if (clickNearOrderMove)
						continue;

						if (MouseIn(thisbutton.Value.ThisRectA,exmbl,exmbl))
						{
							CurrentButton = CurrentButtonAll;



							if (thisbutton.Value.Name == "Now") // entry linemark
							{

																
								
								if (pMarketPlanActive)
								{
									pMarketPlanActive = false;
									
								}
								else if (_hasPlanInProgress)
								{
									pMarketPlanActive = true;
									
									RemoveATMPlanEntry(pIsPlanInProgress);
									SetPlanInProgress(CurrentLastData);
									AddATMPlanEntry(pIsPlanInProgress, 10000);	
									
									
									
								}
								
								pMarketPlanActiveSaved = pMarketPlanActive;
								
								
								RefreshRender(1111);
								
								UpdateButtons();
								
								return;										
								
							
							}
							
							else if (thisbutton.Value.Name == "Hide") // entry-line Hide button
							{
								// Tear down every preview source so a click here is
								// final — no lingering sentinel or PC flag will
								// re-draw the plan next frame.
								IsInPCBuy = false;
								IsInPCSell = false;
								_pcBuyPreviewExpiresAt = DateTime.MinValue;
								_pcSellPreviewExpiresAt = DateTime.MinValue;

								HoveredATMQuickSelect = null;

								AddNextOrder = false;

								// Cancel a plan move in progress (post-'i' Price-mode
								// flow). Without this, IsMovingPlan stays non-empty after
								// HidePlan removes the sentinel — the plan visually
								// disappears but the user is stuck in move mode: the
								// hand cursor stays pinned and the next chart click
								// would re-place the plan at the click location.
								if (IsMovingPlan != null && IsMovingPlan != "")
								{
									IsMovingPlan = "";
									RemoveMessage(false, ATMPlanWaitingForClick);
								}

								// Live-order plan: HidePlan() only clears sentinel/in-progress
								// state, so for plans driven by a live resting order it would
								// be a no-op. Remove this order's display-end entry so the
								// plan stops rendering in the AllEntryOrders loop next frame.
								// Re-arms naturally when user explicitly hovers the order flag
								// (which calls AddATMPlanEntry).
								if (thisbutton.Value.ThisOrder != null)
								{
									double hidePrice = thisbutton.Value.EntryPrice;
									if (OrderPriceToATMDisplayEnd.ContainsKey(hidePrice))
										OrderPriceToATMDisplayEnd.Remove(hidePrice);
								}

								HidePlan(false);

								// Release the hand-cursor override now that the move
								// state has cleared. ApplyHoverCursor at next OnRender
								// would catch this too, but pinning it explicitly here
								// avoids one frame of stale Hand cursor.
								ApplyHoverCursor();

								RefreshRender(1118);
								return;
							}
							else if (thisbutton.Value.Name == "RiskReward") // entry linemark
							{


								pRiskRewardPlanIsEnabled = !pRiskRewardPlanIsEnabled;



								// RESET NUMBER OF SECONDS IN DISPLAY

								if (thisbutton.Value.ThisOrder != null)
								{
									AddATMPlanEntry(thisbutton.Value.EntryPrice, pShowPlanSeconds333);


								}
								else
								{
									BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);
								}




								RefreshRender(1111);
								return;


							}
							else if (thisbutton.Value.Name == "StopSrc") // stop source badge on plan
							{
								// Cycle Default -> H/L -> ATR -> Default and re-apply ATM ticks.
								// For a live resting order, pass liveOrderContext=true so the
								// cycle doesn't touch the selector's default ATM or spawn an
								// extra market-price preview plan via ShowPlan() — the block
								// below re-applies the new stop source to the ORDER'S own ATM
								// at the order's entry price, and visibility is re-armed via
								// AddATMPlanEntry(EntryPrice, ...) further down.
								bool isLiveOrderPlan = thisbutton.Value.ThisOrder != null;
								CycleInitialExitsType(isLiveOrderPlan);

								// For live-order plans, the visible plan reads stops from the
								// ORDER'S ATM (thisbutton.Value.ThisATM) using the order's
								// entry price — which is generally a different ATM instance
								// and a different reference price than the selector's. Without
								// this re-apply, the IE: badge label updates but the plan's
								// stop line stays put. Default mode mirrors the same Default
								// branch CycleInitialExitsType uses for the selector.
								if (thisbutton.Value.ThisOrder != null
									&& thisbutton.Value.ThisATM != null
									&& thisbutton.Value.EntryPrice != 0)
								{
									if (pInitialExitsType == "ATR" || pInitialExitsType == "High / Low")
									{
										ApplyStopSourceToATM(thisbutton.Value.ThisATM, thisbutton.Value.EntryPrice);
									}
									else // Default
									{
										if (atmStrategySelector != null
											&& atmStrategySelector.SelectedIndex > 3 + NumberOfActiveStrategies())
										{
											bool atmIsClean = ATMIsSame(thisbutton.Value.ThisATM, null);
											bool hasDrafts = AtmHasStopStrategyDrafts(thisbutton.Value.ThisATM);
											if (!atmIsClean || hasDrafts)
												ResetATMStrategyToDefault(thisbutton.Value.ThisATM, false, true);
										}
									}
								}

								// Keep the plan visible after the click
								if (thisbutton.Value.ThisOrder != null)
									AddATMPlanEntry(thisbutton.Value.EntryPrice, pShowPlanSeconds333);
								else
									BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);

								RefreshRender(1111);
								return;
							}
							else if (thisbutton.Value.Name == "Entry 2") // entry linemark
							{

								
								if (IsMovingPlan == "")
								{
									HidePlan(false);
									
									IsMovingPlan = pLastPlanDirection;
									
									RemoveATMPlanEntry(pIsPlanInProgress);
									AddATMPlanEntry(13, 1000);									
									
									
								}
								else
								{

									HidePlan(false);

									IsMovingPlan = "";
									RemoveMessage(false, ATMPlanWaitingForClick);


									RemoveATMPlanEntry(13);


									//Print("CurrentMousePrice  " + CurrentMousePrice);

									SetPlanInProgress(CurrentMousePrice);
									pMarketPlanActive = false;
									pMarketPlanActiveSaved = pMarketPlanActive;

									AddATMPlanEntry(pIsPlanInProgress, 10000);
									
									
									
								}
								
								//Print("Entry 2");
								
								
								//MovingATMPlans.Add(thisbutton.Value);
								
//								if (!thisbutton.Value.Switch) // if not a custom order
//								LaunchPlan(false);
								
								RefreshRender(1111);
								return;	
								
							
							}														
								
							else if (thisbutton.Value.Name == "Entry") // change plan dir
							{

								if (!BuyCloseReady && !SellCloseReady)
								if (pLastPlanDirection == "Long")
								{
									pLastPlanDirection = "Short";



								}
								else
								{
									pLastPlanDirection = "Long";
								}


								if (IsMovingPlan != "")
								{
									// Plan is being moved (sentinel 13 follows mouse). Keep
									// the move state alive with the new direction so the next
									// chart click locks the plan using the flipped L/S — do
									// NOT call LaunchPlan here, that would clear sentinel 13
									// and the user would lose their mouse-anchored entry line.
									IsMovingPlan = pLastPlanDirection;
								}
								else
								{
									if (!_hasPlanInProgress)
									if (!thisbutton.Value.Switch) // if not a custom order
									LaunchPlan(true);
								}

								RefreshRender(1111);
								return;


							}
							
							
						

							else if (thisbutton.Value.Name != null && thisbutton.Value.Name.StartsWith("Split"))
							{
								// Split a merged stop or target group. Z.Name format:
								// "Split|<lineName>" e.g. "Split|Stop 1/2/3". The line
								// name carries the bracket numbers; SplitMergedBrackets
								// spreads them outward from the innermost-stays anchor.
								// Must come BEFORE the Stop/Target branches because
								// "SplitStop"-style names would also match Contains("Stop").
								int barIdx = thisbutton.Value.Name.IndexOf('|');
								if (barIdx > 0 && barIdx < thisbutton.Value.Name.Length - 1)
								{
									string mergedName = thisbutton.Value.Name.Substring(barIdx + 1);
									bool isStopSplit = mergedName.StartsWith("Stop");
									SplitMergedBrackets(thisbutton.Value.ThisATM, mergedName, isStopSplit);
								}

								RefreshRender(1112);
								return;
							}
							else if (thisbutton.Value.Name.Contains("Stop"))
							{

								//Print("Stop Clicked " + thisbutton.Value.ThisATM.DisplayName);

								// Mutual exclusion: starting a target/stop move cancels
								// any in-progress stop-strategy move so the user can't
								// end up dragging two things at once.
								_movingStopStrategyItem = null;

								// Manually moving a stop means the user is overriding the
								// automatic ATR / High-Low stop computation. Flip Initial
								// Exits back to Default so the dragged price sticks instead
								// of being recalculated on the next render/hover.
								if (pInitialExitsType != "Default")
									pInitialExitsType = "Default";

								// Add EVERY stop Z that shares this same plan AND chart-Y
								// pixel as the clicked one. Same-level stops can end up in
								// separate StopTicksToName dict keys when bb.StopLoss values
								// have tiny floating-point gaps that round to the same price
								// visually but to different doubles internally — without this,
								// only the clicked bracket would move. The drag handler
								// iterates MovingATMOrders and calls SetATMStopLoss for each,
								// so adding the matching Zs here is enough.
								AddSameLevelMovingMembers(thisbutton.Value, "Stop");


								if (!_hasPlanInProgress)
								if (!thisbutton.Value.Switch) // if not a custom order
								LaunchPlan(false);

								RefreshRender(1111);
								return;


							}
							else if (thisbutton.Value.Name.Contains("Target"))
							{



								//	Print("Target Clicked " + thisbutton.Value.ThisATM.DisplayName);


								// Mutual exclusion: starting a target/stop move cancels
								// any in-progress stop-strategy move.
								_movingStopStrategyItem = null;

								// Same-level multi-bracket merge — see Stop branch above.
								AddSameLevelMovingMembers(thisbutton.Value, "Target");


								if (!_hasPlanInProgress)
								if (!thisbutton.Value.Switch) // if not a custom order
								LaunchPlan(false);

								RefreshRender(1111);
								return;


							}
							
							

						
						//Print("atmhovered");
							
							
							
							//return;
						}
		
                }
			
				
				
				
				
				
				
