		private void SendScreenshots()
		{
			
			ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						
						//Print("Screenshot");
						
						RenderTargetBitmap	screenCapture	= chart.GetScreenshot(ShareScreenshotType.Chart);
						outputFrame							= BitmapFrame.Create(screenCapture);

						if (screenCapture != null)
						{
							try
							{
								
								string locccccc = string.Format(@"{0}\{1}", Core.Globals.UserDataDir, "SendViaEmail.png");
								
								PngBitmapEncoder png = new PngBitmapEncoder();
								png.Frames.Add(outputFrame);
								using (Stream stream = File.Create(locccccc)) png.Save(stream);
								//Print("Screenshot saved to " + locccccc);
								
								//
								
								string pEmailAddress = "4199660700@vzwpix.com";
								string pEmailAddress2 = "7632421012@vzwpix.com";
								string pEmailAddress3 = "4199666006@vzwpix.com";
								//pEmailAddress = "4199666006@vtext.com";
								
								string emailMessage = "message test";
								string emailsub = "";
								//SendMail(pEmailAddress,"",emailMessage);
								
								//Print(locccccc);
								
								double amount = myAccount.Get(AccountItem.RealizedProfitLoss, Currency.UsDollar);
								
								emailMessage = myAccount.Name + " - " + GetDollarString("$", amount);
								
								Share("Email", emailMessage, locccccc, new object[]{pEmailAddress, emailsub});
								Share("Email", emailMessage, locccccc, new object[]{pEmailAddress2, emailsub});
