		void RefreshRender(int id)
		{
			ChartControl.InvalidateVisual();
		}

		// Re-entrancy guard. ChartControl.InvalidateVisual() is NOT an async
		// invalidate: NinjaTrader chains it synchronously through
		// UpdateFormDataBoxCrossHair() -> Control.Update() -> a nested OnPaint
		// -> RenderToTarget -> OnRender. Calling it from inside OnRender
		// re-enters the Direct2D render target (single-threaded, non-
		// re-entrant) and corrupts its clip/draw state, surfacing at EndDraw
		// as D2DERR_WRONG_STATE + D2DERR_PUSH_POP_UNBALANCED -> chart freeze.
		// Any invalidate requested from the render thread must be posted to
		// the dispatcher so it runs AFTER the current frame's EndDraw.
		void DeferRenderInvalidate()
		{
			try
			{
				if (ChartControl != null)
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						try { if (ChartControl != null) ChartControl.InvalidateVisual(); }
						catch { }
					}));
			}
			catch { }
		}


