		private int LeftOfOrders = 0;
		private int TopOfOrders = 0;
		private float LeftmostFlagX = float.MaxValue;
		// Persists the last observed leftmost order/preview flag X across
		// frames so the ATM plan draw (DrawPlanOrder) has a sensible left
		// edge even on the very first frame of a new click-entry session
		// (before the click-entry preview flag's DrawSyntheticOrders pass
		// has populated LeftmostFlagX). Without this fallback the plan
		// draws at its wide default on frame 0 and snaps narrower on
		// frame 1 -- visible flicker.
		private float _lastGoodLeftmostFlagX = float.MaxValue;

		// Single source of truth for the ATM plan's left edge. All sites
		// that need a plan-width x1 (DrawPlanOrder lines, RR fill block,
		// anything else) MUST call this so the fill rectangle and the
		// plan lines never diverge. Prefers LeftmostFlagX measured this
		// frame (from DrawOrders / DrawClickEntry / DrawSyntheticOrders),
		// falls back to the last-seen good measurement across frames, and
		// finally to the default wide value when nothing else exists.
		//
		// Previously returned false in the third case and callers skipped
		// the plan render entirely — this killed ALL hover previews on a
		// fresh chart that has no live orders and no click-entry mode
		// armed, because nothing else populates LeftmostFlagX. Now returns
		// true with the default so the plan always renders; the fallback
		// also caches into _lastGoodLeftmostFlagX so subsequent frames
		// stay at the same width (no flicker-on-first-frame regression).
		private bool TryResolvePlanLeftX(int rightsideis, double linewidd, out double x1)
		{
			if (LeftmostFlagX < float.MaxValue)
			{
				x1 = LeftmostFlagX + 10;
				return true;
			}
			if (_lastGoodLeftmostFlagX < float.MaxValue)
			{
				x1 = _lastGoodLeftmostFlagX + 10;
				return true;
			}
			x1 = rightsideis - linewidd;
			_lastGoodLeftmostFlagX = (float) x1 - 10;
			return true;
		}

