		private void CancelQtyAdjustment()
		{
			QtyOrder = null;
			QtyOrderLIT = null;
			SyntheticQtyKey = null;
			NewQuantityUpdate = -1;
		}

		// Derive the SyntheticQtyKey from a synthetic flag "type" string used
		// by DrawSyntheticOrders (e.g. "BUY ICEBERG", "SELL TIME SLICED"). For
		// anything that isn't a pending iceberg or time-sliced flag, returns
		// null so the caller can fall through to normal LIT / non-qty logic.
		private string GetSyntheticQtyKeyForType(string type)
		{
			if (string.IsNullOrEmpty(type)) return null;
			bool isIce = type.Contains("ICEBERG");
			bool isTS  = type.Contains("TIME SLICED");
			if (!isIce && !isTS) return null;
			bool isBuy = type.Contains("BUY");
			if (isIce) return isBuy ? "ICE_BUY" : "ICE_SELL";
			return isBuy ? "TS_BUY" : "TS_SELL";
		}
		
