		private void SetAllATMTicksATR()
		{
			if (atmStrategySelector != null && atmStrategySelector.SelectedAtmStrategy != null)
				ApplyStopSourceToATM(atmStrategySelector.SelectedAtmStrategy, CurrentLastData);
		}

		// Re-applies the current pInitialExitsType (HL / ATR) to a specific ATM
		// at a specific entry price. Extracted from SetAllATMTicksATR so live-order
		// plan IE: clicks can update the order's own ATM (not just the selector's).
		// Default mode is handled by the caller (ResetATMStrategyToDefault).
		private void ApplyStopSourceToATM(AtmStrategy targetATM, double entryPrice)
		{
			if (targetATM == null) return;
			if (pInitialExitsType == "High / Low")
					{
						// High/Low mode: set stop at fixed H/L price level
						int hlStopTicks = 0;

						// Ensure H/L values are current (recalculate now if needed).
						// Wrapped in try/catch because the IE toggle can fire before
						// BarsArray / CurrentBars have stabilized for the selected
						// barsIdx (NT8 throws "barsAgo needed to be between 0 and N"
						// when the internal bounds check sees a mismatch). Skip the
						// recompute in that case and let the live H/L values from
						// OnBarUpdate fill in on the next tick.
						if (InitialHLLowestLow == 0 || InitialHLHighestHigh == 0)
						{
							try
							{
								int barsIdx = pMTFEnabled && BarsArray.Length > 1 ? 1 : 0;
								if (barsIdx < 0 || barsIdx >= BarsArray.Length || BarsArray[barsIdx] == null
									|| CurrentBars == null || barsIdx >= CurrentBars.Length
									|| CurrentBars[barsIdx] < 0)
								{
									// bar state not ready — skip this recompute
								}
								else
								{
									int maxLookback = Math.Min(pInitialExitHLBars, CurrentBars[barsIdx]);
									double hlH = double.MinValue;
									double hlL = double.MaxValue;
									for (int hli = 0; hli <= maxLookback; hli++)
									{
										hlH = Math.Max(hlH, Highs[barsIdx][hli]);
										hlL = Math.Min(hlL, Lows[barsIdx][hli]);
									}
									if (hlH != double.MinValue) InitialHLHighestHigh = hlH;
									if (hlL != double.MaxValue) InitialHLLowestLow = hlL;
								}
							}
							catch { /* bar data transiently unavailable — leave prior H/L values */ }
						}

						if (pLastPlanDirection == "Long" || pLastPlanDirection == "")
						{
							// Long: stop at lowest low (pushed further below by the offset)
							if (InitialHLLowestLow > 0 && InitialHLLowestLow < entryPrice)
								hlStopTicks = (int) Math.Round((entryPrice - InitialHLLowestLow) / ThisTickSize, 0) + pInitialExitHLOffsetTicks;
						}
						else
						{
							// Short: stop at highest high (pushed further above by the offset)
							if (InitialHLHighestHigh > 0 && InitialHLHighestHigh > entryPrice)
								hlStopTicks = (int) Math.Round((InitialHLHighestHigh - entryPrice) / ThisTickSize, 0) + pInitialExitHLOffsetTicks;
						}

						// Enforce the H/L minimum stop size so tight swings don't produce
						// an unreasonably small stop. Wrong-side entries still leave
						// hlStopTicks at 0 and fall through to RestoreATMStopsToDefault.
						if (pInitialExitHLMinStopTicks > 0 && hlStopTicks > 0 && hlStopTicks < pInitialExitHLMinStopTicks)
							hlStopTicks = pInitialExitHLMinStopTicks;

						if (hlStopTicks > 0)
							SetATMStopLoss(targetATM, hlStopTicks, entryPrice, 0, "StopLoss", true);
						else
							RestoreATMStopsToDefault(targetATM);
					}
					else
					{
						// ATR mode
						if (InitialStopLossATRM != 0)
							SetATMStopLoss(targetATM, InitialATRStopTicks, entryPrice, 0, "StopLoss", true);

						if (pTarget1ATRM != 0)
							SetATMTarget(targetATM, InitialATRT1Ticks, entryPrice, "Target1", true);

						if (pTarget2ATRM != 0)
							SetATMTarget(targetATM, InitialATRT2Ticks, entryPrice, "Target2", true);

						if (pTarget3ATRM != 0)
							SetATMTarget(targetATM, InitialATRT3Ticks, entryPrice, "Target3", true);
					}
		}

		// When H/L mode can't produce a valid stop (buy below the recent low,
		// or sell above the recent high), revert the ATM's bracket StopLoss
		// values to the strategy's stored defaults so the order sizes by the
		// standard stop rather than by a stale H/L distance from a prior setup.
		private void RestoreATMStopsToDefault(AtmStrategy ThisATM)
		{
			if (ThisATM == null) return;

			AtmStrategy defaultATM = null;
			string displayName = ThisATM.DisplayName;

			if (DefaultAtmStrategy.ContainsKey(displayName))
				defaultATM = (AtmStrategy) DefaultAtmStrategy[displayName].Clone();

			if (defaultATM == null || defaultATM.Brackets == null) return;

			Bracket[] defaultBrackets = defaultATM.Brackets;
			int i = 0;
			foreach (Bracket bb in ThisATM.Brackets)
			{
				if (i < defaultBrackets.Length)
					bb.StopLoss = defaultBrackets[i].StopLoss;
				i++;
			}

			if (pPositionSizingIsEnabled)
				PositionSizingAdjustQuantities(true, ThisATM, true);
		}
		
		
		
		
