		// Adds the clicked stop/target Z to MovingATMOrders, plus every other
		// stop/target Z in AllATMStrategyLevelButtons that shares the same plan
		// (ThisATM + ThisOrder) AND lands at the same chart-Y pixel as the
		// clicked one. Used by the Stop/Target click branches so that
		// same-level stops/targets always move together — including the case
		// where StopTicksToName / TargetTicksToName put them in separate keys
		// because of floating-point gaps that look identical visually but
		// aren't binary-identical doubles.
		private void AddSameLevelMovingMembers(ATMMoveDetails clicked, string namePrefix)
		{
			if (clicked == null) return;
			if (!MovingATMOrders.Contains(clicked))
				MovingATMOrders.Add(clicked);

			float clickedY = clicked.ThisRectA.Y + clicked.ThisRectA.Height * 0.5f;
			AtmStrategy clickedATM = clicked.ThisATM;
			Order clickedOrder = clicked.ThisOrder;

			foreach (var kv in AllATMStrategyLevelButtons)
			{
				var Z = kv.Value;
				if (Z == null) continue;
				if (Z == clicked) continue;
				if (Z.Name == null || !Z.Name.Contains(namePrefix)) continue;
				if (Z.ThisATM != clickedATM) continue;
				if (Z.ThisOrder != clickedOrder) continue;

				float zY = Z.ThisRectA.Y + Z.ThisRectA.Height * 0.5f;
				if (Math.Abs(zY - clickedY) > 2f) continue; // 2-px tolerance — same chart row

				if (!MovingATMOrders.Contains(Z))
					MovingATMOrders.Add(Z);
			}
		}

		// Spreads a merged stop or target group outward from entry. Innermost
		// (lowest bracket number) stays at its current price; each subsequent
		// bracket steps further from entry by ~25 chart pixels (converted to
		// ticks via the live chart scale so the visual spacing stays
		// consistent at any zoom).
		//
		// mergedName is the line name as it appears in StopTicksToName /
		// TargetTicksToName for a multi-bracket level — e.g. "Stop 1/2/3" or
		// "Target 2/4". Bracket numbers are 1-based and refer to their order
		// in atm.Brackets.
		private void SplitMergedBrackets(AtmStrategy atm, string mergedName, bool isStop)
		{
			if (atm == null || string.IsNullOrEmpty(mergedName)) return;

			// Parse bracket indices out of the line name.
			int firstSpace = mergedName.IndexOf(' ');
			if (firstSpace < 0 || firstSpace >= mergedName.Length - 1) return;
			string idxList = mergedName.Substring(firstSpace + 1);
			List<int> bracketIdxs = new List<int>();
			foreach (string p in idxList.Split('/'))
			{
				int n;
				if (int.TryParse(p.Trim(), out n)) bracketIdxs.Add(n);
			}
			if (bracketIdxs.Count < 2) return;
			bracketIdxs.Sort();

			// Per-step distance: aim for ~25 chart pixels of visual gap, expressed in ticks.
			// Target gap is DPI-scaled so a high-DPI chart gets a proportionally wider
			// visual gap (~25 perceived pixels) instead of a half-sized one.
			int stepTicks = 4; // sane fallback if chart scale isn't ready yet
			try
			{
				if (_lastChartScale != null && _lastChartScale.MaxMinusMin > 0
					&& ChartPanel.H > 0 && ThisTickSize > 0)
				{
					double pxPerPrice = ChartPanel.H / _lastChartScale.MaxMinusMin;
					double pxPerTick = pxPerPrice * ThisTickSize;
					if (pxPerTick > 0)
						stepTicks = Math.Max(1, (int)Math.Round(S(25f) / pxPerTick));
				}
			}
			catch { }

			double entryRef = LastPlanEntry > 0 ? LastPlanEntry : CurrentLastData;

			// Walk brackets in order; rank ascends among the brackets in the
			// merged group (rank 0 = innermost = stays). Brackets outside the
			// group are untouched. Compute the tick delta, then round-trip via
			// native units so the math is correct for every CalculationMode
			// (Ticks / Currency / Percent / Pips / Price).
			int i = 1;
			int rank = 0;
			foreach (Bracket bb in atm.Brackets)
			{
				if (bracketIdxs.Contains(i))
				{
					if (rank > 0)
					{
						int tickDelta = rank * stepTicks;
						if (isStop)
						{
							double curTicks = BracketUnitsToTicks(bb.StopLoss, atm, entryRef);
							bb.StopLoss = TicksToBracketUnits(curTicks + tickDelta, atm, entryRef);
						}
						else
						{
							double curTicks = BracketUnitsToTicks(bb.Target, atm, entryRef);
							bb.Target = TicksToBracketUnits(curTicks + tickDelta, atm, entryRef);
						}
					}
					rank++;
				}
				i++;
			}

			// Manual edits like this should override the auto-stop modes for
			// the rest of the session — same rationale as drag-moving a stop.
			if (isStop && pInitialExitsType != "Default")
				pInitialExitsType = "Default";
		}

		private void HidePlan(bool showforever)
		{

			// Clear the preview Entry-type override so a stale value from
			// (say) a Limit hover doesn't leak into the next preview source.
			_previewEntryTypeOverride = "";

			//Print("HidePlan");


			if (_hasPlanInProgress)
			{
				RemoveATMPlanEntry(pIsPlanInProgress);
				ClearPlanInProgress();
			}

			//pMarketPlanActive = false;


			if (pPlanEnabled)
			{
				// Clear every sentinel plan key (10/-10/11/-11/12/-12/13/-13) so
				// signal-bar / close-bar / mouse plans do not leak across Hide cycles.
				RemoveAllPlanSentinels();
			}

			// NOTE: do NOT clear stop-strategy drafts here. HidePlan is called by
			// the entry-move flow (click entry → move → click again) which calls
			// HidePlan twice per move to rebuild the plan at the new entry price.
			// Clearing drafts here would wipe the user's adjustments every time
			// they repositioned the entry. Drafts persist until:
			//   - The trade fires (StartAtmStrategyWithDrafts → ClearStopStrategyDrafts)
			//   - The user clicks the ATM reset button
			//   - The user cycles the stop source back to Default

			// Cancel any in-progress stop-strategy move so we don't return to
			// a stuck "waiting for drop click" state next time the plan shows.
			_movingStopStrategyItem = null;

		}		
		
		
		
