		private int InBlockNow = 0;
		private int InBlockNowP = 0;
		
		
		
		
		
		internal void OnMouseMove(object sender, MouseEventArgs e)
    	{



//			try
//			{



			IsMovingSomethingLast = IsMovingSomething;
			IsMovingSomething = false;

			// While Buy/Sell Click is armed the user is deliberating over entry
			// price. Keep the ATM plan preview alive indefinitely by rolling its
			// expiration forward on every mouse move so the normal timeout can't
			// fire and make the preview vanish while they hover the chart.
			if (BuyClickReady || SellClickReady)
				BumpAllPlanSentinelTimestamps(pShowPlanSeconds333);

			// Real mouse movement over the chart releases the click-entry starting
			// anchor so the plan switches from the button-Y reset price to live
			// tracking of the cursor.
			if (_clickEntryAnchorActive)
				_clickEntryAnchorActive = false;

            this.MP = e.GetPosition(this.ChartPanel);

			//Print(MP.Y);

			FinalXPixel = MP.X / 100 * dpiX;
			FinalYPixel = ChartPanel.Y + MP.Y / 100 * dpiY;


			FinalXPixel = ChartPanel.X + FinalXPixel;

			// Keep CurrentMousePrice synchronized with the live mouse position.
			// Previously this was only recomputed in OnRender, so any OnMouseDown
			// / click-entry / plan-drag handler that fires between an OnMouseMove
			// and the next render frame would read a stale price — observed as
			// orders snapping to the previous mouse location when moved, buy/sell
			// clicks placing at the wrong level, and ATM plan lines jumping. Use
			// the same formula OnRender uses so the two paths stay in lockstep.
			try
			{
				if (_lastChartScale != null && _lastChartScale.MaxMinusMin > 0 && ChartPanel.H > 0)
					CurrentMousePrice = RTTS(_lastChartScale.MaxValue - _lastChartScale.MaxMinusMin * ((FinalYPixel - ChartPanel.Y) / ChartPanel.H));
			}
			catch { }
			
			
//			Print(FinalXPixel);
			
			//return;	
			
			
