			// (R/R, IE, Hide) only update their hover glow on the chart's
			// incidental tick-driven redraws — making hover-in/out feel laggy
			// vs. the Entry text (whose rect overlaps the price line that
			// redraws on every tick).
			double hoveredPlanKey = 0;
