				// new double[Count] allocation that previously threw OverflowException
				// once the dict grew large. Index-based access can race with data-thread
				// add/remove (out-of-range), so we catch and move on.
				try
				{
					int _kc = OrderPriceToATMDisplayEnd.Count;
					for (int _ki = 0; _ki < _kc; _ki++)
					{
						double key = OrderPriceToATMDisplayEnd.Keys[_ki];
						// Extend short-timer entries (hover previews, PC previews) but
						// don't shorten long-timer entries like the 10000s plan-in-
						// progress sentinel.
						if (OrderPriceToATMDisplayEnd[key] < exp)
