								var s = kvp.Value;
								if (s.Length < SL_SLOT_SIZE) continue;
								float otherY = (float)s[SL_HEADERY];
								float otherH = (float)s[SL_HEADERH];
								if (myCenterY > otherY && myCenterY < otherY + otherH)
