			// (new category or new resolved target). Within the same hover
			// region the chart's own redraw cadence is sufficient — no need
			// to invalidate on every mouse pixel, which used to cost a full
			// repaint per WPF mouse-move event. Hover boundary crossings
			// (e.g. cursor leaves the order flag, enters a toggle text,
			// moves between live orders) still trigger immediately so glow /
			// Hide-button / cursor transitions stay pixel-snappy. Resolver
			// is run once here against the freshly-set FinalXPixel / Y so
			// the comparison is against a current value, not the stale one
			// from the previous OnRender. Wrapped in try/catch since some
			// resolver branches throw during init.
			try
			{
				HitCategory freshCat = ResolveHoverCategory();
				object freshTarget = resolvedHoverTarget; // set as a side-effect of ResolveHoverCategory
				if (freshCat != _lastHoverCategory
					|| !object.ReferenceEquals(freshTarget, _lastHoverTarget))
				{
					_lastHoverCategory = freshCat;
					_lastHoverTarget   = freshTarget;
					RefreshRender(8001);
				}
			}
			catch { }

		}

		// Computes and applies the chart cursor based on current mouse position
		// (resolvedHoverCategory is re-queried fresh) and active-drag state.
		// While dragging an order or group of orders, keep hand cursor pinned
		// regardless of current hit-test — user is in the middle of a move gesture.
		private void UpdateHoverCursor()
		{
			if (ChartControl == null) return;
			bool clickable;
			bool dragging = (MovingOrder != null) || (MovingOrders != null && MovingOrders.Count > 0);
			if (dragging)
			{
				clickable = true;
			}
			else
			{
				var cat = ResolveHoverCategory();
				clickable = (cat != HitCategory.None && cat != HitCategory.Background);
			}

			// Live-order ATM chip rects aren't part of ResolveHoverCategory
			// (they're populated each render frame in DrawOrders, not in the
			// hit-test resolver). Check them here so the hand cursor activates
			// the moment the cursor lands on a chip — without this, the
			// resolver returns Background → cursor flips to Arrow → next
			// render sets it back to Hand → visible flicker on chip entry.
			if (!clickable && _liveOrderChipRect != null && _liveOrderChipRect.Count > 0)
			{
				foreach (KeyValuePair<string, SharpDX.RectangleF> kv in _liveOrderChipRect)
				{
					if (MouseIn(kv.Value, exmbl, exmbl))
					{
						clickable = true;
						break;
					}
				}
			}

			_hoverClickableThisFrame = clickable;
			ApplyHoverCursor();
		}

		
		
		
		
		
	
