		protected override void OnMarketData (MarketDataEventArgs e)
		{
			long _perfMDNow = System.Diagnostics.Stopwatch.GetTimestamp();
			if (_perfMktDataLast != 0) { double _perfMDGap = (_perfMDNow - _perfMktDataLast) * 1000.0 / System.Diagnostics.Stopwatch.Frequency; if (_perfMDGap > 2000.0) LogDiag("PERF", "MktData_GAP", "GapMs=" + _perfMDGap.ToString("F0")); }
			_perfMktDataLast = _perfMDNow;

			//return;
			
			LastTickTime = e.Time;
			LastTickTimeClock = DateTime.Now;
			
			spreadtickvsclock = e.Time.Subtract(DateTime.Now);
		
			
			
			
			
			if (!MarketDataOK)
			{
				//Print("is market data");
		
				MarketDataOK = true;
				
			}
					
			
			
		
		
			if (State == State.Realtime)
			{
			
				if(e.MarketDataType == MarketDataType.Bid)
					CurrentBid = e.Price;
				
				if(e.MarketDataType == MarketDataType.Ask)
					CurrentAsk = e.Price;
				
				if(e.MarketDataType == MarketDataType.Last)
					CurrentLastData = e.Price;			
				
				
				
				if(CurrentLastData >= CurrentAsk)
					CurrentDataTrend = 1;
				if(CurrentLastData <= CurrentBid)
					CurrentDataTrend = -1;
								
				
				// block trades for volumetric bars
				
					if(e.MarketDataType == MarketDataType.Last)
					if (pOrderFlowEntryOrdersEnabled)
					if (pIsVolumetricBars && !OrderFlowIndicatorReady)
					if (BuySignalReady || SellSignalReady)
					if (pSignalEntryType == "Order Flow - Block")
					{
						
						BuySignalIn = false;	
						SellSignalIn = false;	
						
						int minvol = pMinBlockTrade;
						
						if (CurrentDataTrend == 1 && e.Volume >= minvol)
							BuySignalIn = true;
						
						if (CurrentDataTrend == -1 && e.Volume >= minvol)
							SellSignalIn = true;						
						
//						Print("BuySignalIn " + BuySignalIn);
//						Print("SellSignalIn " + SellSignalIn);
						
						
						
	
							bool BuySignalIsIn = BuySignalIn;
							bool SellSignalIsIn = SellSignalIn;
	
							BuySignalIn = false;
							SellSignalIn = false;
						
							bool SomeSignalIsIn = BuySignalIsIn || SellSignalIsIn;
						
							bool Condition1 = pBuySignalMode == "Long" && BuySignalIsIn;
							bool Condition2 = pBuySignalMode == "Short" && SellSignalIsIn;
							bool Condition3 = pSellSignalMode == "All" && SomeSignalIsIn;
						
							if (BuySignalReady)
							if (Condition1 || Condition2 || Condition3)
							{
								
								
								BuySignalIn = true;
								RunSignalOnClose();
								
							
							}
							
							
							
							Condition1 = pSellSignalMode == "Long" && BuySignalIsIn;
							Condition2 = pSellSignalMode == "Short" && SellSignalIsIn;
							Condition3 = pSellSignalMode == "All" && SomeSignalIsIn;
													
							
							if (SellSignalReady)
							if (Condition1 || Condition2 || Condition3)
							{
								
					
								SellSignalIn = true;
								RunSignalOnClose();

							}
											
						
						
						
						
						
//						if (BuySignalIn || SellSignalIn)
//						if (BuySignalReady || SellSignalReady)
//						{
						
//									//BuySignalIn = true;
//									RunSignalOnClose();
//						}
						
						
						
						
						
						
						
					}
					
					
				//Print(CurrentBid);
				
				//return;
			
					
			
				if(e.MarketDataType == MarketDataType.Ask)
				{
					ThisAsk = AllPriceMarker(e.Price) + "       " + e.Volume;
					ThisAskPrice = e.Price;
					ThisAskVolume = e.Volume;
				}

				if(e.MarketDataType == MarketDataType.Bid)
				{
					ThisBid = AllPriceMarker(e.Price) + "       " + e.Volume;
					ThisBidPrice = e.Price;
					ThisBidVolume = e.Volume;
				}
				
			
//				if (State == State.Realtime)
