//				ChartControl.Dispatcher.InvokeAsync((Action)(() =>{
						
//					if (ask1 != null)
//						ask1.Text = ThisAsk;
					
//					if (bid1 != null)
//						bid1.Text = ThisBid;
					
					
					
					
//					}));
			}
			
			
			
			
			
			
			
			
		}
		
		
