							NextOrderHigh = LastBarHigh + ThisValue*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarHigh - (ThisValue*2)*ThisTickSize - ThisTickSize;
							
						}
						
						if (LastBarHigh > LastBarLow)
						{
							NextOrderHigh = LastBarLow + (ThisValue*2)*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarLow - ThisValue*ThisTickSize - ThisTickSize;

						}					
											
						
						
					}				
					
					else if (chartssss.Contains("UniR T") || chartssss.Contains("UniRenko T") || chartssss.Contains("PROFITPLUS"))
					{
					
						PriceEntryOrdersButtonName = "Renko";
						
						
						
						
	//					Print("-------------------");
