						// Closes[0][1]
						
						if (LastBarClose > LastBarOpen)
						{
							NextOrderHigh = LastBarClose + ThisValue*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarClose - ThisValue2*ThisTickSize - ThisTickSize;
	//						NextOrderHigh = Opens[0][1] + (ThisValue+ThisValue+ThisBaseValue)*ThisTickSize + ThisTickSize;
	//						NextOrderLow = Opens[0][1] - (ThisValue2+ThisBaseValue+ThisValue)*ThisTickSize - ThisTickSize;						
						}
						
						if (LastBarClose < LastBarOpen)
						{
							NextOrderHigh = LastBarClose + ThisValue2*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarClose - ThisValue*ThisTickSize - ThisTickSize;
						
						}		
						
	//					NextOrderHigh = LastBarHigh;
						
	//					NextOrderHigh = NextOrderLow;
						
						
					}
					else if (chartssss.Contains("ninZaRenko"))
