						PriceEntryOrdersButtonName = "Renko";
						
						
						
	//					Print("-------");
	//					Print(BarsArray[0].BarsPeriod.BaseBarsPeriodValue); // nothing
	//					Print(BarsArray[0].BarsPeriod.Value); // brick size
	//					Print(BarsArray[0].BarsPeriod.Value2); // trend threashold
						
				
											
						if (LastBarClose > LastBarOpen)
						{
							NextOrderHigh = LastBarHigh + ThisValue2*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarHigh - (ThisValue+ThisValue-ThisValue2)*ThisTickSize - ThisTickSize;
							
						}
						
						if (LastBarClose < LastBarOpen)
						{
							NextOrderHigh = LastBarLow + (ThisValue+ThisValue-ThisValue2)*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarLow - ThisValue2*ThisTickSize - ThisTickSize;

						}	
						
								
//						Print("LastBarHigh " + LastBarHigh);
//						Print("ThisValue2 " + ThisValue2);
//						Print("ThisValue " + ThisValue);
						
					}
					else if (chartssss.Contains("tdRenkoBar"))
					{
				
						PriceEntryOrdersButtonName = "Renko";
						
						
	//					Print("-------");
	//					Print(BarsArray[0].BarsPeriod.BaseBarsPeriodValue); // nothing
	//					Print(BarsArray[0].BarsPeriod.Value); // brick size
	//					Print(BarsArray[0].BarsPeriod.Value2); // trend threashold
						
						int ticktrendup = (int) Math.Ceiling((double)BarsArray[0].BarsPeriod.Value/2);
						int ticktrenddown = (int) Math.Floor((double)BarsArray[0].BarsPeriod.Value/2);
							
	//					Print("ticktrendup " + ticktrendup);
	//					Print("ticktrenddown " + ticktrenddown);
						
						if (LastBarClose > LastBarOpen)
						{
							NextOrderHigh = LastBarHigh + ticktrendup*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarHigh - (ThisValue+ticktrenddown)*ThisTickSize - ThisTickSize;
							
						}
						
						if (LastBarClose < LastBarOpen)
						{
							NextOrderHigh = LastBarLow + (ThisValue+ticktrendup)*ThisTickSize + ThisTickSize;
							NextOrderLow = LastBarLow - ticktrenddown*ThisTickSize - ThisTickSize;

						}	
						
						
						
					}
					else
					{
						
						
					
						// compatability warning 
						
						
					}
					
					
					
					// moved here to handle multiple bars in a row, keep updating until the price is correct
					
					// moved to timer event to avoid freezing
					
					
					
					if (IsFirstTickOfBar)
					{
					
						// update orders if they are working
						
						
						//UpdateStopEntryOrders(); 
					
	//					if (SEOLong != 0)
	//					if (SEOLong != SEOLongP)
	//					{
	//						UpdateStopEntryOrders();
