	//						UpdateStopEntryOrders();
	//					}
						
						
					}
					

						
					
				//chartssss = "RJay's  RenkoSpectrum 3.0 Bars  100 - 20";
					
	
				} // end of break mode
				else if (pPriceBasedEntryMode == "Pullback")
				{
					
					
					
				}
				
				
				
				
				
				if (pPriceBasedEntryButtonLabel != string.Empty)
				{
					PriceEntryOrdersButtonName = pPriceBasedEntryButtonLabel;
					
					
				}
				
