		}
		
		
		
		
		
		
	
					private void EnterOnBarClose(int ThisBB)
					{					
						int BB = ThisBB;
						
						if (BuyCloseReady)
					    {

							
							bool SendTrade = false;
					
							 	
							
							//Print(CurrentBars[0] + " Close[0] " + Close[0].ToString() + " Open " + Open[0].ToString());
					
							
							// 2 means the last bar closed as a doji and it can count for either a long or short bar
							
							
							
							if (pBuyCloseMode == "Long")
							{

								if (BarCloseCountLong[BB] >= pCloseBarSequence)
									SendTrade = true;
								
							}
							
							else if (pBuyCloseMode == "Short")
							{
								
								if (BarCloseCountShort[BB] >= pCloseBarSequence)
									SendTrade = true;
								
							}
							else
							{
								SendTrade = true;
							}
			
							if (pOnCloseCancel)
							{
								BuyCloseReady = false;	
								UpdateButtons();
							
							}
							
							
							if (SendTrade)
							{
								if (pCloseBarEntryExitPositionEnabled || pOnCloseReverse)
								{
									MarketPosition CurrentMP = MarketPosition.Flat;
									
									if (ThisPositionNow() != null)
										CurrentMP = ThisPositionNow().MarketPosition;
									
									if (CurrentMP == MarketPosition.Short)
									{
										ClosePosition(); 

										if (!pOnCloseReverse)
											SendTrade = false;
									}
								}
													
								
								if (SendTrade)
								{
//									ThisPreviousBarHigh = Highs[0][1];
//									ThisPreviousBarLow = Lows[0][1];
//									ThisPreviousBarClose = Closes[0][1];
									
									BuyNow("Close", ThisBB);
						
								}

								BuyCloseReady = false;
								//SellCloseReady = false;
								UpdateButtons();	
							
							}						
							
					        
					    }
						
						
						
						if (SellCloseReady)
					    {

							bool SendTrade = false;
					
							
							
							
							if (pSellCloseMode == "Long")
							{

								if (BarCloseCountLong[BB] >= pCloseBarSequence)
									SendTrade = true;
																
							}
							else if (pSellCloseMode == "Short")
							{

								if (BarCloseCountShort[BB] >= pCloseBarSequence)
									SendTrade = true;
								
							}
							else
							{
								SendTrade = true;
							}
							
							if (pOnCloseCancel)
							{
								SellCloseReady = false;	
								UpdateButtons();
							
							}
							
							
							
							if (SendTrade)
							{
								if (pCloseBarEntryExitPositionEnabled || pOnCloseReverse)
								{
									MarketPosition CurrentMP = MarketPosition.Flat;
									
									if (ThisPositionNow() != null)
										CurrentMP = ThisPositionNow().MarketPosition;
									
									if (CurrentMP == MarketPosition.Long)
									{
										ClosePosition(); 
										
										if (!pOnCloseReverse)
											SendTrade = false;
									}
								}								
								
								if (SendTrade)
								{
//									ThisPreviousBarHigh = Highs[0][1];
//									ThisPreviousBarLow = Lows[0][1];
//									ThisPreviousBarClose = Closes[0][1];
									
									
									
									SellNow("Close", ThisBB);
								
								}
								
								//BuyCloseReady = false;
								SellCloseReady = false;
								UpdateButtons();	
								
							
							}	

						
							
					        
					    }
						
						
	}
		
		
		
					private void SendBracket()
					{
						
						//Print("sending bracket on bar up");
									
							//CurrentLastDataPlaced = CurrentLastData;
						
						

							
							
							
							if (FinalBracketSeconds == 0)
							{
								
								CurrentLastLowPlaced = LastBarClose;
								CurrentLastHighPlaced = LastBarClose;
								 
								if (pBracketBasis == "High / Low")
								{
									
									CurrentLastLowPlaced = LastBarLow;
									CurrentLastHighPlaced = LastBarHigh;
																
								}
								
								
							}
							else
							{
								
								
								
								CurrentLastLowPlaced = CurrentLastData;
								CurrentLastHighPlaced = CurrentLastData;
								 
								if (pBracketBasis == "High / Low")
								{
									
									CurrentLastLowPlaced = CurrentLastLow;
									CurrentLastHighPlaced = CurrentLastHigh;
																
								}
															
								
								
							}

							
							ExecutionHigh = CurrentLastHighPlaced + pLimitOrderOffset3*ThisTickSize;
							ExecutionLow = CurrentLastLowPlaced - pLimitOrderOffset3*ThisTickSize;
							
							
//							Print("ExecutionHigh " + ExecutionHigh);
//							Print("ExecutionLow " + ExecutionLow);
								
								
							
							
							ChartControl.Dispatcher.InvokeAsync((Action)(() =>{
								
								
								//BracketIsWaiting
							
					
							BracketTrade(ExecutionHigh, ExecutionLow, pSLOffsetBracket, OCOBracketID, pThisEntryType3);
								
								
								
								
								}));
							
							BracketIsWaiting = false;
							UpdateButtons();
							
							
							
					}
						
					
					
					
		double FinalBracketSeconds = 0;
		double FinalCloseBarSeconds = 0;
					
					
		bool IsFirstRun = true;

		// PERF DIAG 2026-05-20: gap timers for the per-tick / per-frame hot paths.
		// A large gap between consecutive entries means that thread stalled.
		private long _perfBarUpdLast = 0;
		private long _perfMktDataLast = 0;
		private long _perfRenderLast = 0;

		protected override void OnBarUpdate()
		{
			long _perfBUNow = System.Diagnostics.Stopwatch.GetTimestamp();
			if (_perfBarUpdLast != 0) { double _perfBUGap = (_perfBUNow - _perfBarUpdLast) * 1000.0 / System.Diagnostics.Stopwatch.Frequency; if (_perfBUGap > 2000.0) LogDiag("PERF", "BarUpdate_GAP", "GapMs=" + _perfBUGap.ToString("F0")); }
			_perfBarUpdLast = _perfBUNow;
			if (BarsInProgress < 0 || CurrentBars == null || BarsArray == null) return;
			if (BarsArray.Length == 0 || BarsArray[0] == null) return;
			if (CurrentBars[0] < 0) return;
			if (Bars == null || ChartControl == null) return;
			if (Direction == null || Direction2 == null) return;
			// Defensive: multi-series collections and primary series must be initialized.
			// On some workspace-restore / disconnected-data paths these can be null briefly
			// at bar 0 before DataLoaded finishes priming the series. Cheap O(1) guard.
			if (Highs == null || Lows == null || Closes == null || Opens == null || Times == null) return;
			if (Highs[0] == null || Lows[0] == null || Closes[0] == null || Opens[0] == null || Times[0] == null) return;
			if (BarsArray[0].Count == 0 || Highs[0].Count == 0) return;
			// Defensive: named Series<T> fields touched at bar 0 when stale user-defaults
			// enable features (CloseBar / StopEntry / Session). If DataLoaded init was
			// skipped/aborted these will be null and we'd NPE before the feature gate runs.
			if (BarCloseCountLong == null || BarCloseCountShort == null) return;
			if (FinalHigh == null || FinalLow == null) return;
			if (CurrentHigh == null || CurrentLow == null || CurrentHighBar == null || CurrentLowBar == null || CurrentHighStatus == null || CurrentLowStatus == null) return;
			if (DR1 == null || DR2 == null) return;
			if (IsInSession == null) return;

			// Final safety net: any unforeseen NPE (e.g. stale user-default settings
			// referencing things that no longer exist) gets logged once and the bar is
			// skipped, instead of NT unloading the indicator. Try/catch overhead in
			// modern .NET is ~1-2ns when no exception is thrown.
			try
			{
//			if (CurrentBars[0] == 0)
//			{

//				Print("AutoScale " + IsAutoScale);

//			}
			
			
			//Print(pIsPlanInProgress);
			
			// Plot 19 ("moving" reference line) — written here on the calc thread.
			// Previously written from DrawMoveOrders via TriggerCustomEvent (i.e.
			// from inside OnRender), which marshalled a plot mutation into the open
			// Direct2D batch — a render-target corruption risk.
			if (BarsInProgress == 0 && ((MovingOrder != null) || (MovingOrders != null && MovingOrders.Count > 0)))
			{
				Values[19][0] = Closes[0][0];
				PlotBrushes[19][0] = Brushes.Gray;
			}

			// Plot 20 (click-entry cursor flag) — written here on the calc thread,
			// same reason as plot 19. Active for ~1s after DrawClickEntry last ran.
			if (BarsInProgress == 0 && _clickRefBrush != null
				&& (DateTime.UtcNow.Ticks - _clickRefTicks) < 10000000L)
			{
				Values[20][0] = _clickRefPrice;
				PlotBrushes[20][0] = _clickRefBrush;
			}

			if (BarsInProgress == 1)
			{
				
			
				
				return;
				
			}

			
			//Print(CurrentLastData);
			
		

			OnBarCBHigh = Highs[0][0];
			OnBarCBLow = Lows[0][0];
			OnBarCBClose = Closes[0][0];
			
			if (CurrentBars[0] > 0)
			{
				
				OnBarPBHigh = Highs[0][1];
				OnBarPBLow = Lows[0][1];
				OnBarPBClose = Closes[0][1];
			}
	
			
			bool IsCurrentBarNow2 = CurrentBars[0] == BarsArray[0].Count - 1;
			
//			if (IsCurrentBarNow2 && !IsFirstTickAfterLoad)
//			{
//				IsFirstTickAfterLoad = true;
				
//			}
			
			if (IsCurrentBarNow2 && IsFirstTickAfterLoad2)
				IsFirstTickAfterLoad = true;
				
//			if (IsFirstTickAfterLoad)
//			Print("IsFirstTickAfterLoad");
			
			
			// process higher time frame bars
			
			
			if (BarsInProgress != 0)
				return;
			
			
			if (IsFirstRun)
			{
	
				if (BarsPeriod.BarsPeriodType == BarsPeriodType.Minute || BarsPeriod.BarsPeriodType == BarsPeriodType.Second)
				{
					FinalBracketSeconds = pBracketEarlySeconds;
					
					FinalCloseBarSeconds = pCloseBarEarlySeconds;
					
					
				}
				else
				{
				
					FinalBracketSeconds = 0;
					FinalCloseBarSeconds = 0;
				}			
  
				IsFirstRun = false;
				
			}
		
			
			
			
			
			if (State == State.Realtime)
			if (!connected)
			{
				connected = true;
				RemoveMessage(false, "You must connect to a data feed to place entry orders.");
				RemoveMessage(false, "You must connect to a data feed to use the Enhanced Chart Trader.");
			}
		
			if (!Permission)
				return;		
			
			
			//if (State == State.Historical)
			CurrentLastData = Closes[0][0];
			
			if (State == State.Realtime)
			if (pMarketPlanActive)
			if (IsMovingPlan == "")
			if (CurrentLastData != 0)
			if (CurrentLastData != CurrentLastDataPrevious)				
			{

				RemoveATMPlanEntry(pIsPlanInProgress);
				SetPlanInProgress(CurrentLastData);			
				AddATMPlanEntry(pIsPlanInProgress, 10000);	
				
			}
			
			CurrentLastDataPrevious = CurrentLastData;
			
			//Print("444 " + CurrentLastData);
			
			
			CurrentLastHigh = Highs[0][0];
			CurrentLastLow = Lows[0][0];
			CurrentLastTime = Times[0][0].AddSeconds(-1*FinalBracketSeconds);
			CurrentLastMiddle = RTTS((CurrentLastHigh+CurrentLastLow)/2);
			
//			Print("CurrentLastHigh " + CurrentLastHigh);
//			Print("CurrentLastLow " + CurrentLastLow);
			
			
			if (CurrentBar > 0)
			{		
				LastBarLow = Lows[0][1];
				LastBarHigh = Highs[0][1];
				LastBarClose = Closes[0][1];
				LastBarOpen = Opens[0][1];
				
			}

			ThisCB = CurrentBars[0];
			
			
			
			
			
			// timer
			
			// uses for exit on close
			
			if (pExitOnCloseButtonEnabled)
			{
	                if (Close[0] > Open[0])
	                    Direction[0] = 1;
	                else if (Close[0] < Open[0])
	                    Direction[0] = -1;
	                else if (CurrentBars[0] == 0)
	                    Direction[0] = 0;
	                else
	                    Direction[0] = 0;
			
			}
			
			
			
			
			if (pCloseBarEntryOrdersEnabled)
	     	if (BarsInProgress == 0)
	            {
					
					// not currently being used
					
//	                BodyHigh[0] = Math.Max(Closes[0][0], Opens[0][0]);
//	                BodyLow[0] = Math.Min(Closes[0][0], Opens[0][0]);

//	                WickHigh[0] = Highs[0][0];
//	                WickLow[0] = Lows[0][0];


//	                if (Close[0] > Open[0])
//	                    Direction[0] = 1;
//	                else if (Close[0] < Open[0])
//	                    Direction[0] = -1;
//	                else if (CurrentBars[0] == 0)
//	                    Direction[0] = 1;
//	                else
//	                    Direction[0] = Direction[1];
					
							//ring[] {"All", "None", "Previous"} );
							
					
				
				
							
						if (pCloseEntryDojiMode == "All")
						{
			                if (Close[0] > Open[0])
			                    Direction2[0] = 1;
			                else if (Close[0] < Open[0])
			                    Direction2[0] = -1;
			                else
			                    Direction2[0] = 2;
							
							
						}
						else if (pCloseEntryDojiMode == "None")
						{				
			                if (Close[0] > Open[0])
			                    Direction2[0] = 1;
			                else if (Close[0] < Open[0])
			                    Direction2[0] = -1;
			                else
			                    Direction2[0] = 0;	
							
						}
						else if (pCloseEntryDojiMode == "Previous")
						{				
			                if (Close[0] > Open[0])
			                    Direction2[0] = 1;
			                else if (Close[0] < Open[0])
			                    Direction2[0] = -1;
			                else if (CurrentBars[0] == 0)
			                    Direction2[0] = 0;
			                else
			                    Direction2[0] = Direction2[1];	
							
						}
						
						if (CurrentBars[0] == 0)
						{
							BarCloseCountLong[0] = 0;
							BarCloseCountShort[0] = 0;
							
							if (Direction2[0] == 1 || Direction2[0] == 2)
								BarCloseCountLong[0] = 1;
							
							if (Direction2[0] == -1 || Direction2[0] == 2)
								BarCloseCountShort[0] = 1;
							
						}
						else
						{
							
							if (Direction2[0] == 1 || Direction2[0] == 2)
								BarCloseCountLong[0] = BarCloseCountLong[1] + 1;
							else
								BarCloseCountLong[0] = 0;
							
							if (Direction2[0] == -1 || Direction2[0] == 2)
								BarCloseCountShort[0] = BarCloseCountShort[1] + 1;	
							else
								BarCloseCountShort[0] = 0;
							
						}
					
							
						
	            }

         
			
			if (pPriceBasedEntryOrdersEnabled)
			if (BarsInProgress == 0)
			if (CurrentBars[0] > 0)
			{
				// Keep NextOrderHigh / NextOrderLow populated from the last loaded
				// bar in ALL states (historical + realtime), not just Realtime. This
				// way the Price button's hover preview and click flow have valid
				// levels even when the market is closed / no ticks are flowing — it
				// simply uses the last closed bar's computed values.
				CalculatePriceBasedEntryOrders();

				// The cancel-if feature still only fires on realtime bar opens.
				if (State == State.Realtime)
				if (IsFirstTickOfBar)
				if (pPriceBasedEntryOrdersCancelIf)
				{
					if (LongEntryOrder2 != null)
					{
						if (Closes[0][1] < Opens[0][1])
						{
							CancelOrder(LongEntryOrder2);
							AddMessage2("Long '" + PriceEntryOrdersButtonName + "' Entry Order was cancelled because the bar closed down.", 10, Brushes.Goldenrod);
						}
					}

					if (ShortEntryOrder2 != null)
					{
						if (Closes[0][1] > Opens[0][1])
						{
							CancelOrder(ShortEntryOrder2);
							AddMessage2("Short '" + PriceEntryOrdersButtonName + "' Entry Order was cancelled because the bar closed up.", 10, Brushes.Goldenrod);
						}
					}
				}
			}
				
			
		
			
			
			
			
			
				
			if (pStopEntryOrdersEnabled)
			if (BarsInProgress == 0)
			{
				
				
				
				FinalHigh[0] = High[0];
				FinalLow[0] = Low[0];	
				


				if (CurrentBar < 1)
					return;

				CurrentHigh[0] = CurrentHigh[1];
				CurrentLow[0] = CurrentLow[1];
				CurrentHighBar[0] = CurrentHighBar[1];
				CurrentLowBar[0] = CurrentLowBar[1];
				CurrentHighStatus[0] = CurrentHighStatus[1];
				CurrentLowStatus[0] = CurrentLowStatus[1];			
				
				
				
	//			if (Low[0] == Close[0] && High[1] == Close[1])
	//			{
	//				CurrentHigh[0] = High[0];
	//				CurrentHighBar[0] = CurrentBar;
	//				CurrentHighStatus[0] = 0;
	//			}

	//			if (High[0] == Close[0] && Low[1] == Close[1])
	//			{
	//				CurrentLow[0] = Low[0];
	//				CurrentLowBar[0] = CurrentBar;
	//				CurrentLowStatus[0] = 0;
	//			}
				
				if (CurrentBar < 3)
					return;
				
				
				if (High[3] <= High[2] && High[1] <= High[2])
				{
					CurrentHigh[0] = High[2];
					CurrentHighBar[0] = CurrentBar-2;
					CurrentHighStatus[0] = 0;
				}

				if (Low[3] >= Low[2] && Low[1] >= Low[2])
				{
					CurrentLow[0] = Low[2];
