								AllowNextLongImmediately = false;
								
								// submit long trade
								BuySignalIn = true;
								RunSignalOnClose();
								
								//Print("LastOrderFlowLongSignal " + LastOrderFlowLongSignal);
								
							}
							
							
							
							Condition1 = pSellSignalMode == "Long" && LastOrderFlowLongSignal != 0;
							Condition2 = pSellSignalMode == "Short" && LastOrderFlowShortSignal != 0;
							Condition3 = pSellSignalMode == "All" && SomeSignalIsIn;
													
							if (SellSignalReady)
							if (AllowNextShortImmediately)
							if (Condition1 || Condition2 || Condition3)
							{
								
								AllowNextShortImmediately = false;
								
								// submit short trade
								SellSignalIn = true;
								RunSignalOnClose();

								//Print("LastOrderFlowShortSignal " + LastOrderFlowShortSignal);
								
							}
					
						
						
					}
					
						
						
					if (IsFirstTickOfBar)
					{
					
						if (pIsOCO)
						
							OnBarCloseOCO = "Close" + DateTime.Now.Ticks.ToString();
						else
							OnBarCloseOCO = string.Empty;
						
					}
					
					
					// close bar entry orders
					
					
					
					if (FinalCloseBarSeconds == 0)
					if (IsFirstTickOfBar)
					{
					
						
						EnterOnBarClose(1);
						
						
					}	// end first tick of bar
					
					
					
					
					
					
					
					if (IsFirstTickOfBar)	
					if (pBracketEntryOrdersEnabled)
					if (pBracketMode == "Close")
					if (BracketIsWaiting && FinalBracketSeconds == 0)
					{
			
						
						SendBracket();
					
							
						
					}
				
							
							
						
					
					if (pIcebergEntryOrdersEnabled)
					{
									
						
						
						
						
							
							if (BuyIcebergAtOrAbove != 0 && CurrentLast >= BuyIcebergAtOrAbove)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartIcebergOrder("Buy");}));
								BuyIcebergAtOrAbove = 0;
								
							}
							if (BuyIcebergAtOrBelow != 0 && CurrentLast <= BuyIcebergAtOrBelow)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartIcebergOrder("Buy");}));
								BuyIcebergAtOrBelow = 0;
								
							}
													
		
							if (SellIcebergAtOrAbove != 0 && CurrentLast >= SellIcebergAtOrAbove)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartIcebergOrder("Sell");}));
								SellIcebergAtOrAbove = 0;
								
							}
							if (SellIcebergAtOrBelow != 0 && CurrentLast <= SellIcebergAtOrBelow)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartIcebergOrder("Sell");}));
								SellIcebergAtOrBelow = 0;
								
							}						
					
					
					
							if (pIcebergOffsetTrailing)
							{
								if (IcebergBuyOrderSequence != 0 || IcebergSellOrderSequence != 0)
								{
//									Print("IcebergBuyOrderSequence: " + IcebergBuyOrderSequence);
//									Print("IcebergSellOrderSequence: " + IcebergSellOrderSequence);
									
									
									ChartControl.Dispatcher.InvokeAsync((Action)(() =>{   MoveITSEntryOrder("Iceberg", 0, "Trail");  }));
								}
								
								
							}
					
						

							if (pIcebergInProfitActionEnabled)
							if (InProfitActionCurrentPrice != 0)
							{
			
								//Print(InProfitActionCurrentPrice);
								
							
								if (IcebergBuyOrderSequence != 0)
								{
									
										if (CurrentLastData >= InProfitActionCurrentPrice && !InProfitActionTriggered)
										{
											
											if (pIcebergInProfitActionAction == "Cancel")												
											{
												
												
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{  CancelIcebergOrder("Buy");  }));
											}
											else if (pIcebergInProfitActionAction == "Fill")
											{
												IcebergBuyEntryMode = "Market";
												
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{ MoveITSEntryOrder("Iceberg", 0, "Fill");	  }));
											}									
								
											InProfitActionTriggered = true;
										}
									
								}
								
								if (IcebergSellOrderSequence != 0)
								{
										if (CurrentLastData <= InProfitActionCurrentPrice && !InProfitActionTriggered)
										{
											
											if (pIcebergInProfitActionAction == "Cancel")												
											{
												
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{  CancelIcebergOrder("Sell");  }));
												
											}
											else if (pIcebergInProfitActionAction == "Fill")
											{
												IcebergSellEntryMode = "Market";
												
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{  MoveITSEntryOrder("Iceberg", 0, "Fill");  }));
												
											}										
											
											InProfitActionTriggered = true;
											
										}				
							
								}
						
						

				
							}
									
						
						
						
					}
		
					
				
					
					
					
						
						
					
				
				if (pTimeSlicedEntryOrdersEnabled)
					{
									
						
						
						
						
							
							if (BuyTimeSlicedAtOrAbove != 0 && CurrentLast >= BuyTimeSlicedAtOrAbove)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartTimeSlicedOrder(BuyName, "Price");}));
								BuyTimeSlicedAtOrAbove = 0;
								
							}
							if (BuyTimeSlicedAtOrBelow != 0 && CurrentLast <= BuyTimeSlicedAtOrBelow)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartTimeSlicedOrder(BuyName, "Price");}));
								BuyTimeSlicedAtOrBelow = 0;
								
							}
													
		
							if (SellTimeSlicedAtOrAbove != 0 && CurrentLast >= SellTimeSlicedAtOrAbove)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartTimeSlicedOrder(SellName, "Price");;}));
								SellTimeSlicedAtOrAbove = 0;
								
							}
							if (SellTimeSlicedAtOrBelow != 0 && CurrentLast <= SellTimeSlicedAtOrBelow)
							{
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>{StartTimeSlicedOrder(SellName, "Price");;}));
								SellTimeSlicedAtOrBelow = 0;
								
							}						
					
					
					
							if (pIcebergOffsetTrailing)
							{
								if (TimeSlicedBuyOrderSequence != 0 || TimeSlicedSellOrderSequence != 0)
								{
//									Print("TimeSlicedBuyOrderSequence: " + TimeSlicedBuyOrderSequence);
//									Print("TimeSlicedSellOrderSequence: " + TimeSlicedSellOrderSequence);
									
									
									ChartControl.Dispatcher.InvokeAsync((Action)(() =>{   MoveITSEntryOrder("TimeSliced", 0, "Trail");   }));
								}
								
								
							}
					
						
//							bool dooo = false;
							
//							if(dooo)

							if (pIcebergInProfitActionEnabled)
							if (InProfitActionCurrentPrice != 0)
							{
			
								//Print(TimeSlicedInProfitActionCurrentPrice);
								
							
								if (TimeSlicedBuyOrderSequence != 0)
								{
									
										if (CurrentLastData >= InProfitActionCurrentPrice && !InProfitActionTriggered)
										{
											
											if (pIcebergInProfitActionAction == "Cancel")												
											{
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{    CancelTimeSlicedOrder(BuyName);  }));
												
											}
											else if (pIcebergInProfitActionAction == "Fill")
											{
												
												
												TimeSlicedFinishAtMarket = true;
												if (TimeSlicedBuyEntryMode == "Market")
												{
													TimeSlicedBuyOrderSequence = TimeSlicedBuyOrderSequence + 1;
													
													ChartControl.Dispatcher.InvokeAsync((Action)(() =>{   PlaceITSOrder("Time Sliced", TimeSlicedBuyOrderSequence, "", BuyName);   }));
												}
												else
												{
													ChartControl.Dispatcher.InvokeAsync((Action)(() =>{    MoveITSEntryOrder("TimeSliced", 0, "Fill");  }));
													
												}
												
												TimeSlicedBuyEntryMode = "Market";
												
												

												//StartTimeBuyTimeSliced = DateTime.Now.AddMilliseconds(pTimeSlicedFinishAtMarketMilliseconds);
			
											}									
								
											InProfitActionTriggered = true;
										}
									
								}
								
								if (TimeSlicedSellOrderSequence != 0)
								{
										if (CurrentLastData <= InProfitActionCurrentPrice && !InProfitActionTriggered)
										{
											
											if (pIcebergInProfitActionAction == "Cancel")												
											{
												
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>{   CancelTimeSlicedOrder(SellName);   }));
											}
											else if (pIcebergInProfitActionAction == "Fill")
											{
												TimeSlicedFinishAtMarket = true;
												if (TimeSlicedSellEntryMode == "Market")
												{
													TimeSlicedSellOrderSequence = TimeSlicedSellOrderSequence + 1;
													
													ChartControl.Dispatcher.InvokeAsync((Action)(() =>{  PlaceITSOrder("Time Sliced", TimeSlicedSellOrderSequence, "", SellName);    }));
												}
												else
												{
													
													
													ChartControl.Dispatcher.InvokeAsync((Action)(() =>{   MoveITSEntryOrder("TimeSliced", 0, "Fill");   }));
												}
												
												TimeSlicedSellEntryMode = "Market";
												
												//StartTimeSellTimeSliced = DateTime.Now.AddMilliseconds(pTimeSlicedFinishAtMarketMilliseconds);

											}										
											
											
											InProfitActionTriggered = true;
										}				
							
								}
						
						

				
							}
									
						
						
						
					}
		
					
				
					
					
					
					
					
				} // end state = real time
				
				
				
				
			
			
			
				
				
			if (IsFirstTickAfterLoad)
				IsFirstTickAfterLoad2 = false;

			IsFirstTickAfterLoad = false;


			}
			catch (Exception ex)
			{
				// Route into the existing ECT diagnostic logger (daily ECT_YYYY-MM-DD.log
				// files, included by the Send Diagnostics button). Cap repeats so a
				// per-bar failure can't flood the log.
				if (_obuCatchCount < _obuCatchMax)
				{
					_obuCatchCount++;
					int cb = -1;
					try { cb = (CurrentBars != null && CurrentBars.Length > 0) ? CurrentBars[0] : -1; } catch {}
					string instr = "(unknown)";
					try { if (Bars != null && Bars.Instrument != null) instr = Bars.Instrument.FullName; } catch {}
					string details =
						"Type=" + ex.GetType().Name +
						", Msg=" + ex.Message +
						", State=" + State +
						", Bar=" + cb +
						", Instr=" + instr +
						", Stack=" + (ex.StackTrace ?? "(null)").Replace("\r", " ").Replace("\n", " | ");
					LogDiag("ERROR", "OnBarUpdate", details);
				}
			}
        }
		private int _obuCatchCount = 0;
		private const int _obuCatchMax = 50;

		
										
				
				
			//Print(ClearBackgroundTime);
			

			
			
				private void UpdateTrailingStopNow(bool isfirsttick, bool allowmovebackward)
				{
					if (ThisPositionNow() == null)
						return;
					
					
					
					
						
						double LongTrailingStopValue = 0;
						double ShortTrailingStopValue = 0;
							
						double LongTrailingStopValue2 = 0;
						double ShortTrailingStopValue2 = 0;
					
					
					
						// contantly running this
						
						if (pTrailingStopType == "Fixed Tick")
						{
							//pTrailingStopType = "Fixed Tick";
							LongTrailingStopValue = HighestPriceInTrade - pFixedTicks*ThisTickSize; // long = high in trade - ticks
							ShortTrailingStopValue = LowestPriceInTrade + pFixedTicks*ThisTickSize; // short = low in trade + ticks		
							
							LongTrailingStopValue2 = LongTrailingStopValue;
							ShortTrailingStopValue2 = ShortTrailingStopValue;
							
						}
						else if (pTrailingStopType == "ATR")
						{
							//pTrailingStopType = "ATR";
							LongTrailingStopValue = HighestPriceInTrade - ATRTotal - pTSOffsetATR*ThisTickSize; // long = high in trade - atr mult
							ShortTrailingStopValue = LowestPriceInTrade + ATRTotal + pTSOffsetATR*ThisTickSize; // short = low in trade + atr mult	
							
							LongTrailingStopValue2 = LongTrailingStopValue;
							ShortTrailingStopValue2 = ShortTrailingStopValue;
							
						}
					
					
	
						if (isfirsttick)
						{
	
							
							if (pTrailingStopType == "High / Low")
							{
							 
								LongTrailingStopValue = LastTSBarLow - pTSOffsetBar*ThisTickSize;
								ShortTrailingStopValue = LastTSBarHigh + pTSOffsetBar*ThisTickSize;
								
								LongTrailingStopValue2 = LongTrailingStopValue;
								ShortTrailingStopValue2 = ShortTrailingStopValue;
								
							}
							else if (pLastCB5SelectedIndex >= totaltrailingstoptypes)
							{						
								int trailingstoparraynumber = pLastCB5SelectedIndex-totaltrailingstoptypes;

								int LongInd = pAllTrailingStopsIndicator[trailingstoparraynumber];
								int ShortInd = pAllTrailingStopsIndicator2[trailingstoparraynumber];
								int LongPlot = pAllTrailingStopsPlot[trailingstoparraynumber];
								int ShortPlot = pAllTrailingStopsPlot2[trailingstoparraynumber];
								int ThisOffTicks = pAllTrailingStopsOffsets[trailingstoparraynumber];							

								LongTrailingStopValue = GetThisPlotValue(LongInd, LongPlot, 0);
								ShortTrailingStopValue = GetThisPlotValue(ShortInd, ShortPlot, 0);
								
								LongTrailingStopValue2 = LongTrailingStopValue - ThisOffTicks*ThisTickSize;
								ShortTrailingStopValue2 = ShortTrailingStopValue + ThisOffTicks*ThisTickSize;

								
								//pAllTrailingStopsGeneratedName
								
							}
						
							
						}
			
			
						

						
							bool allowthemove = true;
							
							if (!isfirsttick)
							{
								if (DateTime.Now >= LastTrailingStopMoveTime)
								{

									LastTrailingStopMoveTime = DateTime.Now.AddMilliseconds(pMilliSecondsBetweenTrailingStopMoves);
									
									
								}
								else
								{
								
									allowthemove = false;
								}
								
							}
							
			
//							Print("UpdateTrailingStopNow");
//							Print("LongTrailingStopValue " + LongTrailingStopValue);
//							Print("ShortTrailingStopValue " + ShortTrailingStopValue);
							
							if (allowthemove)
							{
								
								
								ChartControl.Dispatcher.InvokeAsync((Action)(() =>
								{
							
									if (ThisPositionNow().MarketPosition == MarketPosition.Long)
									{
										if (LongTrailingStopValue != 0)
										UpdateStopLoss("TRAIL", LongTrailingStopValue2, allowmovebackward);
									}
									else if (ThisPositionNow().MarketPosition == MarketPosition.Short)
									{
										if (ShortTrailingStopValue != 0)
										UpdateStopLoss("TRAIL", ShortTrailingStopValue2, allowmovebackward);
									}
								
								}));
								
							}
							

						
						
						
				}
		
		
				
		private void calculateBar(int ii)
		{
			
			if (BarItems[ii] != null)
				{
					//Print(CurrentBars[0] + "--------");
					
					
					
//    				BarVolume[ii] = BarItems[ii].tv;

					//if (BarVolume[ii] == 0)
					//	AddError("You have missing tick data.  Please connect to a data feed.");
					
				
//					BarBid[ii] = BarItems[ii].bv;
//					BarAsk[ii] = BarItems[ii].av;
//					BarDelta[ii] = BarItems[ii].dv;
				
//					BarBidPercent[ii] = BarBid[ii] / BarVolume[ii] * 100;
//					BarAskPercent[ii] = BarAsk[ii] / BarVolume[ii] * 100;
//					BarDeltaPercent[ii] = BarAskPercent[ii] - BarBidPercent[ii];
					
					BarItems[ii].AskI = new List<double>();
					BarItems[ii].BidI = new List<double>();
						

					SD.Clear();
					BarItems[ii].UnfinishedAuctions.Clear();
					BarItems[ii].Magnets.Clear();
					
					double deltamax = -99999;
					double deltamin = 99999;
					
				
					foreach (KeyValuePair<double, RowData> pair in BarItems[ii].l.ToList()) //.OrderBy(key=> key.))
					{
						
						
						SD.Add(pair.Key,pair.Value);
						
						
						double price = pair.Key;
						
						bool IsTopPrice = price == Highs[0][ii];
						bool IsBottomPrice = price == Lows[0][ii];
							
						//Print(price + " " + BarItems[ii].l[price].bv + " " + BarItems[ii].l[price].av + " ");
						
						double bidv = BarItems[ii].l[price].bv;
						double askv = BarItems[ii].l[price].av;
						double deltav = askv - bidv;
						
						deltamax = Math.Max(deltamax, deltav);
						deltamin = Math.Min(deltamin, deltav);
						
						// bid / ask imbalances
						
						double askratio = getAskImbalanceRatio(BarItems[ii].l,price);
						double bidratio = getBidImbalanceRatio(BarItems[ii].l,price);
						
						
						//Print(askratio);
						double bidv2 = 0;
						double askv2 = 0;
						
						if (BarItems[ii].l.ContainsKey(RTTS(price-TickSize)))
						{
							bidv2 = BarItems[ii].l[RTTS(price-TickSize)].bv;
						}
						if (BarItems[ii].l.ContainsKey(RTTS(price+TickSize)))
						{
							askv2 = BarItems[ii].l[RTTS(price+TickSize)].av;
						}	
						

						
						double AskS = Math.Max(askv2,1);
						double BidS = Math.Max(bidv2,1);
						

						double AskMin = (double)BarItems[ii].av/(double)BarItems[ii].l.Count/(double)100*pVolumeQualifier;
						double BidMin = (double)BarItems[ii].bv/(double)BarItems[ii].l.Count/(double)100*pVolumeQualifier;
						
						AskMin = 0;
						BidMin = 0;
						
//						if (CurrentBars[0] == 320)
//						{
//							Print(price + "  " + BidS + "  " + BidMin);
//						}
						
						if (askratio >= pImbalanceOffset && BidS >= BidMin)
						{
							BarItems[ii].AskI.Add(price);
						}
						if (bidratio >= pImbalanceOffset && AskS >= AskMin)
						{
							BarItems[ii].BidI.Add(price);
						}
						
						// magnets
						
						//BarItems[ii].Magnets.Clear();
						
						
//						if (Math.Abs(bidv - askv) <= pMAGSpreadMax && askv >= pMAGSizeMin && bidv >= pMAGSizeMin)
//						{
//							Level LLL = new Level();
//							LLL.Price = price;
//							LLL.EndBar = 0;
							
//							BarItems[ii].Magnets.Add(LLL);
//						}
						
						
						
						// unfinished auctions
						
						//BarItems[ii].UnfinishedAuctions.Clear();
						
//						if (IsTopPrice || IsBottomPrice)
//						{
//							if (bidv != 0 && askv != 0)
//							{
//								Level LLL = new Level();
//								LLL.Price = price;
//								LLL.EndBar = 0;
								
//								BarItems[ii].UnfinishedAuctions.Add(LLL);	
								
//							}
							
//						}
						
						
						
					}
					
					BarItems[ii].dvmax = deltamax;
					BarItems[ii].dvmin = deltamin;
					
					
					// loop through prices in order
					
					bool IsWashLong = true;
					bool IsWashShort = true;
					
					bool topdone = false;
					
					int totalbidlevels = 1;
					int totalasklevels = 1;
					double POC = 0;
					int start = 0;
					double pavol = 0;
					double pbvol = 0;
					double maxvol = 0;
					double ThisPOC = 0;
					double thisvwap = 0;
					
//					double thisvah1 = 0;
//					double thisval1 = 0;
//					double thisvah2 = 0;
//					double thisval2 = 0;
			
					double VWAPTotal = 0;
					//double AllVolume = Profiles[ind].tv;
					
					//double lowestprice = 99999999;
					//double highestprice = 0;
					
					double clustertop = 0;
					double clusterbottom = 0;
					double currentcluster = 0;
					double largestcluster = 0;
					
					ArrayList	lastHighCache	= new ArrayList();
				
					lastHighCache.Clear();
					
					
					foreach (KeyValuePair<double, RowData> pair in SD.ToList()) //.OrderBy(key=> key.))
					{
						double price = pair.Key;
						double avol = pair.Value.av;
						double bvol = pair.Value.bv;
						double tvol = pair.Value.tv;
						
						
//						lastHighCache.Add(tvol);
//						if (lastHighCache.Count > pClusterSize)
//							lastHighCache.RemoveAt(0);
						
//						currentcluster = 0;
						
//						if (lastHighCache.Count == pClusterSize)
//						{
							
//							for (int i=0; i < pClusterSize; i++)
//								currentcluster = currentcluster + (double) lastHighCache[i];
							
//							if (currentcluster > largestcluster)
//							{
//								largestcluster = currentcluster;
//								clustertop = price;
//								clusterbottom = clustertop - (pClusterSize-1)*TickSize;
								
//							}		
							
							
//						}
						

						
						VWAPTotal = VWAPTotal + tvol*price;
						
						if (tvol > maxvol)
						{
							maxvol = tvol;
							ThisPOC = price;
						}
							
						
						if (start != 0)
						{
							if (bvol > pbvol && !topdone)
							{
								totalbidlevels = totalbidlevels + 1;
							}
							else
							{
								topdone = true;
							}
							
							if (avol < pavol)
							{
								totalasklevels = totalasklevels + 1;
							}
							else
							{
								totalasklevels = 1;
							}
							
						}
						
						
						//bool IsTopPrice = price == Highs[0][0];
						//bool IsBottomPrice = price == Lows[0][0];
							
						//Print(price + " " + pair.Value.bv + " " + pair.Value.av + " ");
						
						// looping bottom of bar to the top 
						
						IsWashLong = true;
						
						pavol = avol;
						pbvol = bvol;
						start = 1;
					}
					
					thisvwap = VWAPTotal / BarItems[ii].tv;
					
					BarItems[ii].POC = ThisPOC;
					BarItems[ii].VWAP = thisvwap;
					
					BarItems[ii].ClusterTop = clustertop;
					BarItems[ii].ClusterBottom = clusterbottom;					
								
//					LongSignals[ii] = 0;
//					ShortSignals[ii] = 0;
					
					
					// washouts
					
					
					bool ShortSignalOK = false;
		
					if (pHighLowRangeFilter)
					{
								
						//if (Highs[0].IsValidPlot(CurrentBars[0]-1))
						if (Highs[0][ii] > Highs[0][ii+1] && (!pHighLowRangeFilter2 || Closes[0][ii] <= Opens[0][ii]))		
							ShortSignalOK = true;
					}
					else
					{
						if (!pHighLowRangeFilter2 || Closes[0][ii] <= Opens[0][ii])	
						ShortSignalOK = true;
						
					}
		
					bool LongSignalOK = false;
					
					if (pHighLowRangeFilter)
					{
								
						//if (Lows[0].IsValidPlot(CurrentBars[0]-1))
						if (Lows[0][ii] < Lows[0][ii+1] && (!pHighLowRangeFilter2 || Closes[0][ii] >= Opens[0][ii]))				
						LongSignalOK = true;
					}
					else
					{
						if (!pHighLowRangeFilter2 || Closes[0][0] >= Opens[0][0])
						LongSignalOK = true;
						
					}
		
		
					if (totalbidlevels >= pMinimumDecliningLevels && LongSignalOK)
					{
						//LongSignals[ii] = totalbidlevels;
					}
					
					if (totalasklevels >= pMinimumDecliningLevels && ShortSignalOK)
					{
						//ShortSignals[ii] = totalasklevels;
					}
					
					
					
					// add Zones (Imbalance)
					
					
					//Print("-------------");
					ZoneItems[ii] = new ZoneItem();
									
					
					ZoneItems[ii].ResistanceZones = new List<Zone>();
					ZoneItems[ii].SupportZones = new List<Zone>();
		
					double bottomn = 0;
					int csize = 0;
					Zone Z;		
					
					// support / ask
					foreach(double d in BarItems[ii].BidI.OrderBy(d => d))
					{
						// going bottom to top
						//Print(i);
						
						
						//Print(d + " " + csize);
						
						// logic to qualify a zone
						
						if (d <= Highs[0][ii])
						{
							if (bottomn == 0)
							{
								bottomn = d;
								csize++;
							}
							else
							{
								if (RTTS(bottomn + TickSize*csize) == d)
								{
									csize++;
									
									
								}
								else
								{
									if (csize >= pMinZWidth)
									{
										Z = new Zone();
										Z.BottomPrice = bottomn;
										Z.TopPrice = bottomn + (csize-1)*TickSize;
										Z.TicksWidth = csize;
										Z.TestedPrice = 0;
										Z.IsBroken = false;
										Z.IsHidden = false;
										Z.EndBar = 0;
										
										
										ZoneItems[ii].ResistanceZones.Add(Z);
										
										//Print(bottomn + "  " + csize);
									}
									
									csize = 1;
									bottomn = d;
									
								}
							}
						}
					}
					
					if (csize >= pMinZWidth)
					{
						Z = new Zone();
						Z.BottomPrice = bottomn;
						Z.TopPrice = bottomn + (csize-1)*TickSize;
						Z.TicksWidth = csize;
						Z.TestedPrice = 0;
						Z.IsBroken = false;
						Z.IsHidden = false;
						Z.EndBar = 0;
						
						//SupplyZones.Add(CurrentBar,
						ZoneItems[ii].ResistanceZones.Add(Z);
						
						
					}
			
					csize = 0;
								
					foreach(double d in BarItems[ii].AskI.OrderBy(d => d))
					{
						if (d <= Highs[0][ii])
						{
							if (bottomn == 0)
							{
								bottomn = d;
								csize++;
							}
							else
							{
								if (RTTS(bottomn + TickSize*csize) == d)
								{
									csize++;
								}
								else
								{
									if (csize >= pMinZWidth)
									{
										Z = new Zone();
										Z.BottomPrice = bottomn;
										Z.TopPrice = bottomn + (csize-1)*TickSize;
										Z.TicksWidth = csize;
										Z.TestedPrice = 0;
										Z.IsBroken = false;
										Z.IsHidden = false;
										Z.EndBar = 0;
										
										//SupplyZones.Add(CurrentBar,
										ZoneItems[ii].SupportZones.Add(Z);
										
										//Print(bottomn + "  " + csize);
									}
									
									csize = 1;
									bottomn = d;
									
								}

							}
						}
						
					}
					
					if (csize >= pMinZWidth)
					{
						Z = new Zone();
						Z.BottomPrice = bottomn;
						Z.TopPrice = bottomn + (csize-1)*TickSize;
						Z.TicksWidth = csize;
						Z.TestedPrice = 0;
						Z.IsBroken = false;
						Z.IsHidden = false;
						Z.EndBar = 0;
						
						//SupplyZones.Add(CurrentBar,
						ZoneItems[ii].SupportZones.Add(Z);


					}



				}

			}

