		{
			
			//return;
			
			
			//Print("SetOrderFlags");
			
			if (myAccount == null)
				return;
			
			if (pScaleByOrders)
				return;
			
		//	return;
			
			
					// Values[19][0] = 0;
		
					// order y axis flags
					
//				TriggerCustomEvent(o =>
//	   			{
	      
//					Values[19][0] = 0;
//					Values[20][0] = 0;
//					Values[21][0] = 0;
					
					
//				}, null);					
					
					int currentplot = 25; // start value for all orders
					for (int i = currentplot-1; i <= Values.Length-1; i++)
					{
//						Values[i][0]=0;
//						Values[i][1]=0;

						// fixed when working on scaling
						// still doesn't work
						PlotBrushes[i].Reset();
						Values[i].Reset(0);
						Values[i].Reset(1);

						//Print(Values[i].GetValueAt(CurrentBar-1));
					}
					// atmPlanPlotCursor is reset inside OnRender (unconditional)
					// — not here — because SetOrderFlags has early-return guards
					// (myAccount == null, pScaleByOrders) that would leave the
					// cursor stale across frames if we depended on this block.
					
				
					
					bool dododod = pOrdersDisplayOn;
					
					//dododod = false;
					
					
					//if (dododod)						
					// position price flag
					if (ThisPositionNow() != null)
					{
						
						Values[currentplot-1][0] = ThisPositionNow().AveragePrice;	
					
							if (ThisPositionNow().MarketPosition == MarketPosition.Long)
								PlotBrushes[currentplot-1][0] = Brushes.Lime;
							else
								PlotBrushes[currentplot-1][0] = Brushes.Red;
						
					}

						
					//TotalOrdersPrices.Clear();
					TotalOrdersPrices2.Clear();

					if (myAccount == null)
						return;
					
			
					
					
//					bool gdsfgsg2 = false;
//					if (gdsfgsg2)
						
					if (pOrdersDisplayOn)
						foreach (Order or in myAccount.Orders.ToList())
						{
							
							
								
							double ThisPrice = or.StopPrice;

							if (or.OrderType == OrderType.Limit && (or.StopPrice == 0 || or.OrderState == OrderState.Working))
							{
								ThisPrice = or.LimitPrice;
							}

							// MIT orders may report price via StopPrice or LimitPrice depending on connection
							if (or.OrderType == OrderType.MIT && ThisPrice == 0)
							{
								ThisPrice = or.LimitPrice;
							}

							// Fallback for TriggerPending orders with no StopPrice
							if (or.OrderState == OrderState.TriggerPending && ThisPrice == 0 && or.LimitPrice != 0)
							{
								ThisPrice = or.LimitPrice;
							}

							int thisq = 1;
						
							thisq = or.Quantity;
							
//							if (TotalOrdersPrices.ContainsKey(ThisPrice))
//							thisq = TotalOrdersPrices[ThisPrice];
							
							
				OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending || or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelPending || or.OrderState == OrderState.CancelSubmitted || or.OrderState == OrderState.TriggerPending;
				
							
							//OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.TriggerPending;
							
							
							
							OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
							OrderNameOK = true;

							OrderTypeOK = or.OrderType != OrderType.Market;

							// Rithmic/APEX reports MIT orders as OrderType.Market with TriggerPending state
							if (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending && or.StopPrice != 0)
								OrderTypeOK = true;

							bool showorder = OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK;
								
							//showorder = false;
							
						if (or.OrderState == OrderState.Cancelled)
							showorder = false;
						if (or.OrderState == OrderState.Filled)
							showorder = false;
						
						
						
							
							if (showorder)						
							//if (IsStop(or.Name))
							{
								

								if (!TotalOrdersPrices2.ContainsKey(ThisPrice))
								{
									TotalOrdersPrices2.Add(ThisPrice, thisq);
									// Clamp to the Values[] plot array. Order-flag plots occupy
								// Values[25 .. Length-1] and currentplot is bumped once per
								// distinct order price. With more order prices than plot
								// slots, Values[currentplot] ran off the end — the
								// "Index was outside the bounds of the array" error raised
								// from the TriggerCustomEvent callback, which left the plot
								// arrays half-built for OnRender to read. Orders past the
								// last slot now simply get no Y-axis flag instead of crashing.
								if (currentplot < Values.Length)
								{
								Values[currentplot][0] = ThisPrice;
									
									int totalatprice = 0;
									
									if (TotalOrdersPrices.ContainsKey(ThisPrice))
										totalatprice = TotalOrdersPrices[ThisPrice];
											
									
									//Print(totalatprice);
									
									
									if (totalatprice > 1)
									{
										PlotBrushes[currentplot][0] = pOrderSummaryColor;
									}
									else if (pOrderColorDisplayMode == "Buy / Sell")
									{
										// Buy/Sell mode: targets and stops get their own override
										// colors (Buy / Sell - Target / Buy / Sell - Stop); other
										// live orders get Buy / Sell - Buy / Buy / Sell - Sell.
										// Pending states are handled by the change-brush branch
										// above (pOrderChangeColor) so we don't need to cover
										// them here.
										if (IsTarget(or.Name))
										{
											PlotBrushes[currentplot][0] = pOrderBuySellTargetColor;
										}
										else if (or.Name.Contains("SimStop") || IsStop(or.Name))
										{
											PlotBrushes[currentplot][0] = pOrderBuySellStopColor;
										}
										else
										{
											bool isBuySide = or.OrderAction == OrderAction.Buy || or.OrderAction == OrderAction.BuyToCover;
											PlotBrushes[currentplot][0] = isBuySide ? pOrderBuySideColor : pOrderSellSideColor;
										}
									}
									else if (or.OrderState == OrderState.TriggerPending)
									{

										PlotBrushes[currentplot][0] = pOrderTriggerPending;
									}
									else if (IsTarget(or.Name))
									{

										PlotBrushes[currentplot][0] = pOrderTargetColor;


									}
									else if (or.Name.Contains("SimStop"))
									{
										PlotBrushes[currentplot][0] = pOrderStopColor;


									}
									else if (IsStop(or.Name))
									{
										PlotBrushes[currentplot][0] = pOrderStopColor;


									}


									else if (or.OrderType == OrderType.Limit && (or.StopPrice == 0 || or.OrderState == OrderState.Working))
									{
										PlotBrushes[currentplot][0] = pOrderLimitColor;


									}
									else if (or.OrderType == OrderType.MIT || or.OrderType == OrderType.Market)
									{
										PlotBrushes[currentplot][0] = pOrderMITColor;


									}
									else if (or.OrderType == OrderType.StopLimit || or.OrderType == OrderType.Limit)
									{
										PlotBrushes[currentplot][0] = pOrderStopLimitColor;

									}
									else if (or.OrderType == OrderType.StopMarket)
									{
										PlotBrushes[currentplot][0] = pOrderStopMarketColor;


									}					
							
									currentplot = currentplot + 1;
								}
									
									
								}
								else
								{
								
										// added try catch for lilly error targets trading pro
									try  
										{ 
											
				
												int newq =  TotalOrdersPrices2[ThisPrice] +  thisq;
												TotalOrdersPrices2[ThisPrice] = newq;
											
										}
										catch (Exception ex)
										{
											
										}
																
						
								}
								
//								if (TotalOrdersPrices[ThisPrice] > 1)
//								{
									
//									//Print(TotalOrdersPrices[ThisPrice]);
									
//									//if (!AllOrderPrices.ContainsKey(ThisPrice))
//									//	AllOrderPrices.Add(ThisPrice, startright - 30);
								
//								}
								
									
							}
								
						
					
							
						}
						
						
		}

		
			private TimeSpan OutTS (TimeSpan InTS, int HoursFromEST)
		{
			
			TimeSpan FinalTS;
				
				if (InTS.Hours < Math.Abs(HoursFromEST))
					FinalTS = new TimeSpan(0,HoursFromEST+InTS.Hours+24,0,0);	
				else
					FinalTS = InTS.Subtract(new TimeSpan(0,Math.Abs(HoursFromEST),0,0));	
									
				return FinalTS;
				
		}
		
		
		
