        private bool MouseIn(SharpDX.RectangleF RR, int XF, int YF)
        {

			if (FinalXPixel != 0)
            if (FinalXPixel >= RR.Left - XF && FinalXPixel <= RR.Right + XF+1 && FinalYPixel >= RR.Top - YF && FinalYPixel <= RR.Bottom + YF)
                return true;
           
                return false;

        }

		// Cross-price overlap: shift label left if its Y-band overlaps any already-drawn label
		private float GetOverlapShift(float labelTop, float labelBottom, float currentStartRight)
		{
			float shifted = currentStartRight;
			for (int i = 0; i < OccupiedLabelBands.Count; i++)
			{
				float bandTop = OccupiedLabelBands[i][0];
				float bandBottom = OccupiedLabelBands[i][1];
				float bandLeftX = OccupiedLabelBands[i][2];
				// HARDENING: Math.Min(x, NaN) returns NaN, so a single non-finite
				// bandLeftX would poison `shifted` into NaN — and a NaN flag X
				// fed to a Direct2D draw call silently corrupts the render target
				// (D2DERR_WRONG_STATE at EndDraw, frozen chart). Skip bad bands.
				if (float.IsNaN(bandLeftX) || float.IsInfinity(bandLeftX))
					continue;
				if (bandTop < labelBottom && bandBottom > labelTop)
				{
					shifted = Math.Min(shifted, bandLeftX);
				}
			}
			// Never hand back a non-finite shift; fall back to the unshifted X.
			if (float.IsNaN(shifted) || float.IsInfinity(shifted))
				return currentStartRight;
			return shifted;
		}

		private void RecordLabelBand(float top, float bottom, float leftX)
		{
			// HARDENING: never record a non-finite band — a NaN/Infinity leftX
			// would poison GetOverlapShift for every later overlapping label
			// (Math.Min(x, NaN) == NaN), yielding a NaN flag position that
			// silently corrupts Direct2D. A bad band is dropped, not stored.
			if (float.IsNaN(top) || float.IsNaN(bottom) || float.IsNaN(leftX)
				|| float.IsInfinity(top) || float.IsInfinity(bottom) || float.IsInfinity(leftX))
				return;
			OccupiedLabelBands.Add(new float[] { top, bottom, leftX });
		}

