												AllTrades[AllTrades.Count-1].DollarsProfit += Z.DollarsProfit;
												AllTrades[AllTrades.Count-1].PointsProfit = AllTrades[AllTrades.Count-1].DollarsProfit / (AllTrades[AllTrades.Count-1].Quantityy * ThisPointDollars);
												AllTrades[AllTrades.Count-1].TicksProfit = (int)(AllTrades[AllTrades.Count-1].PointsProfit / ThisTickSize);
											}
											else
