												AllTrades.Add(Z);
											}
																				
											
											//Print("S5");
											
											//Print(thisqclosed == AllShortEntries[0].Quantityy);
											
											if (thisqclosed == AllShortEntries[0].Quantityy)
												AllShortEntries.RemoveAt(0);
											else
												AllShortEntries[0].Quantityy = AllShortEntries[0].Quantityy - thisqclosed;
										
											quantityclosed = quantityclosed + thisqclosed;
											
											//Print("S6");
											
											//Print("Long 2");
											
											
										}
										else
										{
										
											Z.Quantityy = ex.Quantity;
											
											//Z.Quantityy = ex.Quantity - thisqclosed;
											Z.FPrice = ex.Price;				
								            Z.TimeOfEntry = ex.Time;
											AllLongEntries.Add(Z);
											
											quantityclosed = ex.Quantity;
											
										
											
										}
										
										
									//}	
								
								
										numberofloops = numberofloops + 1;
										
									// Body
								} while (quantityclosed < ex.Quantity && numberofloops < 10);

								//Print("S7");
								
							
							}
					
						}
							
						
						
						if (ex.MarketPosition == MarketPosition.Short) // short execution
						{
						
							if (AllLongEntries.Count == 0) // if no long position, then add to short
							{
							
									//AllShortEntries.Add(Z);
							
								if (IsAdd)
								{
									var lastEntry = AllShortEntries[AllShortEntries.Count-1];
									double totalQty = lastEntry.Quantityy + ex.Quantity;
									lastEntry.FPrice = (lastEntry.FPrice * lastEntry.Quantityy + ex.Price * ex.Quantity) / totalQty;
									lastEntry.Quantityy = (int)totalQty;
								}
								else
								{
									AllShortEntries.Add(Z);
								}
								
								
								
								
								
							}
							else
							{
	//							for(int i = 1; i <= ex.Quantity; i++)
	//							{
									
	//								Z = new TradeDetails();
									
									
	//								if (AllLongEntries.Count != 0)
	//								{
									
	//									Z.FPrice = AllLongEntries[0].FPrice;			
