	//									Z.FPriceOut = ex.Price;
	//									Z.TimeOfExit = ex.Time;
	//									Z.Direction = ex.Quantity;
										
	//									AllTrades.Add(Z);
	//									AllLongEntries.RemoveAt(0);
									
									
	//								}
	//								else
	//								{
									
										
	//									Z.FPrice = ex.Price;				
	//						            Z.TimeOfEntry = ex.Time;
	//									AllShortEntries.Add(Z);
										
	//								}
									
									
	//							}	
								
								
									
								int quantityclosed = 0;
								int thisqclosed = 0;
								int numberofloops = 0;
								
								do
								{
							


									//for(int i = 1; i <= ex.Quantity; i++)
									//{
										
										Z = new TradeDetails();
										
										
										
										if (AllLongEntries.Count != 0)
										{
										
											
											thisqclosed = Math.Min(ex.Quantity - quantityclosed, AllLongEntries[0].Quantityy);
											
											//thisqclosed = ; // added to fix bug
											
											//if (thisqclosed <= 0)
											//	thisqclosed = ex.Quantity;
											//thisqclosed = Math.Max(thisqclosed, ex.Quantity); // added to fix bug 8/22/2023
											
											Z.FPrice = AllLongEntries[0].FPrice;			
							           		Z.TimeOfEntry = AllLongEntries[0].TimeOfEntry;
											Z.FPriceOut = ex.Price;
											Z.TimeOfExit = ex.Time;
								
											
											Z.Quantityy = thisqclosed;
											Z.TradeDirection = 1;
											
											Z.PointsProfit = (Z.FPriceOut - Z.FPrice);
											Z.TicksProfit = (int) (Z.PointsProfit / ThisTickSize);
											Z.DollarsProfit	= Z.PointsProfit * Z.Quantityy * ThisPointDollars;
											
											Z.TradeExitName = ex.Name;
											
											//Print("thisqclosed " + thisqclosed.ToString());
											
											if (IsAdd)
