		public override void OnRenderTargetChanged()
		{
			_ortcCount++;
			// Death-spiral detection (rate-independent): a healthy chart renders
			// many frames between render-target recreations; a corrupt-RT spiral
			// renders ~none. A run of >=6 consecutive recreations with <=2 real
			// renders between them IS the spiral -> trip the circuit breaker
			// (see OnRender). Realtime-only so chart-load RT churn is ignored.
			if (State == State.Realtime)
			{
				long _ortcNow = System.Diagnostics.Stopwatch.GetTimestamp();
				if (_onRenderSinceOrtc <= 2) _tightOrtcRun++;
				else _tightOrtcRun = 0;
				_onRenderSinceOrtc = 0;
				if (_tightOrtcRun >= 6)
				{
					if (!_renderCircuitOpen)
						LogDiag("RENDER", "SpiralDetected", "tightRun=" + _tightOrtcRun + " ortcCount=" + _ortcCount + " -- render-target recreation spiral; circuit breaker engaged\n" + System.Environment.StackTrace);
					_renderCircuitOpen = true;
					_renderCircuitCooldownTicks = _ortcNow + (long)(2.0 * System.Diagnostics.Stopwatch.Frequency);
				}
			}
			LogDiag("RENDER", "OnRenderTargetChanged", "thread=" + System.Threading.Thread.CurrentThread.ManagedThreadId + " rtNull=" + (RenderTarget == null) + " count=" + _ortcCount);
			foreach (var kvp in cachedATMColorBrushes)
				if (kvp.Value != null && !kvp.Value.IsDisposed) kvp.Value.Dispose();
			cachedATMColorBrushes.Clear();







//				if (!Permission)
//					return;
		  // Explicitly set the Stroke RenderTarget
		
			
			
			
			
			if (RenderTarget != null)
			{
				
				pBrush03.RenderTarget = RenderTarget;
				pBrush04.RenderTarget = RenderTarget;
				
				
				if (pHighlightStroke != null)
				pHighlightStroke.RenderTarget = RenderTarget;
				//pHighlightStroke.Opacity = 50;
				//pHighlightStroke.Brush = GetOutlineColor(myProperties.ChartBackground, true);
				
				
				
				pOneWidthStroke.RenderTarget = RenderTarget;
				pTwoWidthStroke.RenderTarget = RenderTarget;
				SolidStroke.RenderTarget = RenderTarget;
	
				
				
				pLastPriceLine2Stroke.RenderTarget = RenderTarget;
				pLastPriceLineStroke.RenderTarget = RenderTarget;
//				pBarOutlineStroke.RenderTarget = RenderTarget;
				pBarUpOutlineStroke.RenderTarget = RenderTarget;
				pBarDnOutlineStroke.RenderTarget = RenderTarget;
				pBarNeOutlineStroke.RenderTarget = RenderTarget;
				if (pStopStrategyStroke != null)
					pStopStrategyStroke.RenderTarget = RenderTarget;
				
				
				pOrderUpOutlineStroke.RenderTarget = RenderTarget;
				pOrderDnOutlineStroke.RenderTarget = RenderTarget;
				pOrderBothOutlineStroke.RenderTarget = RenderTarget;
				

				pInActionStroke.RenderTarget = RenderTarget;
				
//				pGridLineHStroke.RenderTarget = RenderTarget;
//				pGridLineVStroke.RenderTarget = RenderTarget;
				
				
//				pBrush09.RenderTarget = RenderTarget;
//				pBrush10.RenderTarget = RenderTarget;	
//				pBrush11.RenderTarget = RenderTarget;
//				pBrush12.RenderTarget = RenderTarget;
//				pBrush13.RenderTarget = RenderTarget;
//				pBrush14.RenderTarget = RenderTarget;
//				pBrush15.RenderTarget = RenderTarget;
//				pBrush16.RenderTarget = RenderTarget;
//				pBrush17.RenderTarget = RenderTarget;
//				pBrush18.RenderTarget = RenderTarget;
//				pBrush19.RenderTarget = RenderTarget;
//				pBrush20.RenderTarget = RenderTarget;
				
				pWinningTradeOutlineStroke.RenderTarget = RenderTarget;
				pLosingTradeOutlineStroke.RenderTarget = RenderTarget;
	
		
				ThisStroke.RenderTarget = RenderTarget;
				ThisStrokeH.RenderTarget = RenderTarget;
				
				
				
		
			
				
//				pBarUpOutlineStroke8.RenderTarget = RenderTarget;
//				pBarDnOutlineStroke8.RenderTarget = RenderTarget;
			}
			
			
			
			
			
			
			  
			if (ChartBackgroundShade1BrushDX != null)
			{
			    ChartBackgroundShade1BrushDX.Dispose();
			}

			if (RenderTarget != null)
			{
				ChartBackgroundShade1BrushDX = ThisChartBackground.ToDxBrush(RenderTarget);
				ChartBackgroundShade1BrushDX.Opacity = 25/100f;
			}

			// Rendering Optimization: Create static brushes and flag dynamic brushes for refresh
			CreateStaticBrushes();
			CreateAdditionalStaticBrushes();
			CreateWorkingBrushes();
			propertyBrushesNeedRefresh = true;
			orderBrushesNeedRefresh = true;
			additionalBrushesNeedRefresh = true;
			marketDepthBrushesNeedRefresh = true;
			triangleBrushesNeedRefresh = true;
			textFormatsNeedRefresh = true;
			DisposeAllCachedTextFormats();

			// Plan label TextLayout cache is tied to CellFormat (which is rebuilt
			// with the text formats above). Drop it so next render refills clean.
			DisposePlanLabelLayoutCache();
		}
		
		private void ClearBrush(ref SharpDX.Direct2D1.Brush BBB)
		{
			if (BBB != null)
			{
				BBB.Dispose();
				BBB = null;
			}
		}

		// --- Rendering Optimization: Cached brush creation/disposal ---
		private void DisposeStaticBrushes()
		{
			if (cachedBlackBrushDX != null) { cachedBlackBrushDX.Dispose(); cachedBlackBrushDX = null; }
			if (cachedRoyalBlueBrushDX != null) { cachedRoyalBlueBrushDX.Dispose(); cachedRoyalBlueBrushDX = null; }
			if (cachedRedErrorBrushDX != null) { cachedRedErrorBrushDX.Dispose(); cachedRedErrorBrushDX = null; }
			if (cachedBlackPrintBrushDX != null) { cachedBlackPrintBrushDX.Dispose(); cachedBlackPrintBrushDX = null; }
			if (cachedTransparentBrushDX != null) { cachedTransparentBrushDX.Dispose(); cachedTransparentBrushDX = null; }
			if (cachedWhiteBrushDX != null) { cachedWhiteBrushDX.Dispose(); cachedWhiteBrushDX = null; }
			if (cachedGreenBrushDX != null) { cachedGreenBrushDX.Dispose(); cachedGreenBrushDX = null; }
			if (cachedRedBrushDX != null) { cachedRedBrushDX.Dispose(); cachedRedBrushDX = null; }
		}

		private void CreateStaticBrushes()
		{
			if (RenderTarget == null) return;
			DisposeStaticBrushes();
			cachedBlackBrushDX = Brushes.Black.ToDxBrush(RenderTarget);
			cachedRoyalBlueBrushDX = Brushes.RoyalBlue.ToDxBrush(RenderTarget);
			cachedRedErrorBrushDX = Brushes.Red.ToDxBrush(RenderTarget);
			cachedRedErrorBrushDX.Opacity = 25/100f;
			cachedBlackPrintBrushDX = Brushes.Black.ToDxBrush(RenderTarget);
			cachedBlackPrintBrushDX.Opacity = 30/100f;
			cachedTransparentBrushDX = Brushes.Transparent.ToDxBrush(RenderTarget);
			cachedWhiteBrushDX = Brushes.White.ToDxBrush(RenderTarget);
			cachedGreenBrushDX = Brushes.Green.ToDxBrush(RenderTarget);
			cachedRedBrushDX = Brushes.Red.ToDxBrush(RenderTarget);
		}

