			if (ChartBackgroundFade2BrushDX != null) { ChartBackgroundFade2BrushDX.Dispose(); ChartBackgroundFade2BrushDX = null; }
			if (ChartBackgroundMenuFadeBrushDX != null) { ChartBackgroundMenuFadeBrushDX.Dispose(); ChartBackgroundMenuFadeBrushDX = null; }
			if (ChartBackgroundErrorBrushDX != null) { ChartBackgroundErrorBrushDX.Dispose(); ChartBackgroundErrorBrushDX = null; }
			if (buttonBrushDX != null) { buttonBrushDX.Dispose(); buttonBrushDX = null; }
			if (buttonHBrushDX != null) { buttonHBrushDX.Dispose(); buttonHBrushDX = null; }
			if (buttonFHBrushDX != null) { buttonFHBrushDX.Dispose(); buttonFHBrushDX = null; }
			if (buttonFOFFBrushDX != null) { buttonFOFFBrushDX.Dispose(); buttonFOFFBrushDX = null; }
			if (buttonFONBrushDX != null) { buttonFONBrushDX.Dispose(); buttonFONBrushDX = null; }
			if (CrossHairBrushDX != null) { CrossHairBrushDX.Dispose(); CrossHairBrushDX = null; }
