		private bool PropertyBrushesChanged()
		{
			if (propertyBrushesNeedRefresh) return true;
			if (ChartControl == null) return false;
			return lastChartText != ChartControl.Properties.ChartText
				|| lastChartBackground != ChartControl.Properties.ChartBackground
				|| lastChartAxisBrush != pChartAxisBrush
				|| lastColorButtonsOff != pColorButtonsOff
				|| lastCrossHairBrush != pCrossHairBrush
				|| lastButtonHighlightMode != pButtonHighlightMode
				|| lastOnOpacity != pOnOpacity
				|| lastCrossHairOpacity != pCrossHairOpacity;
		}

