		// --- Hover cursor feedback ---
		// Tracks whether any clickable chart element is under the mouse this frame.
		// OnRender resets this at top, hover-detection blocks set it true,
		// ApplyHoverCursor() at end of OnRender pushes it to ChartControl.Cursor only on change.
		private bool _hoverClickableThisFrame = false;
		// Panel-button/header hover is tracked separately so that mouse-event-driven
		// UpdateHoverCursor() (which calls ResolveHoverCategory, unaware of panel buttons)
		// can't clobber our Hand cursor between renders and produce visible flicker.
		private bool _panelHoverClickableThisFrame = false;
		private System.Windows.Input.Cursor _lastAppliedChartCursor = null;
		private bool _overrideCursorActive = false; // true while Mouse.OverrideCursor is our hand

		private void ApplyHoverCursor()
		{
			if (ChartControl == null) return;

			// While an order drag OR a click-entry mode is in progress, the
			// chart cursor is a modal state -- the entry order visually tracks
			// the mouse (for Buy Click / Sell Click) or the whole gesture is
			// mid-drag (for MovingOrder*). ChartControl.Cursor alone isn't
			// reliable in these states -- WPF's Mouse.Capture path and NT's
			// chart drag behavior can replace the cursor mid-gesture.
			// Mouse.OverrideCursor is application-scoped and wins against
			// both. It is cleared as soon as the modal state ends so the
			// normal ChartControl.Cursor path takes back over.
			bool dragging =
				(MovingOrder != null)
				|| (MovingOrders != null && MovingOrders.Count > 0)
				|| BuyClickReady || SellClickReady
				|| BuyCloseClick || SellCloseClick
				|| BuyIcebergClick || SellIcebergClick
				|| BuyTimeSlicedClick || SellTimeSlicedClick
				|| MoveTargetsClick || MoveStopsClick
				|| InProfitActionIcebergClick
				// ATM plan move (post-'i' Price-mode placement flow): the
				// sentinel-13 entry line tracks the mouse until the user
				// clicks to lock the price. Same modal state as Buy/Sell
				// Click, so the hand cursor should be pinned for the whole
				// duration. Without this, Mouse.OverrideCursor = null and
				// the chart's normal arrow cursor takes over while the line
				// is still floating with the mouse.
				|| (IsMovingPlan != null && IsMovingPlan != "");

			if (dragging)
			{
				if (!_overrideCursorActive)
				{
					try { System.Windows.Input.Mouse.OverrideCursor = System.Windows.Input.Cursors.Hand; } catch { }
					_overrideCursorActive = true;
				}
				return;
			}

			// Drag ended -> release the app-wide override if we set it.
			if (_overrideCursorActive)
			{
				try { System.Windows.Input.Mouse.OverrideCursor = null; } catch { }
				_overrideCursorActive = false;
				_lastAppliedChartCursor = null; // force re-apply below
			}

			// Combine non-panel hit-test hover (set by UpdateHoverCursor via
			// ResolveHoverCategory) with panel-button/header hover (set only in
			// OnRender). Keeping these separate avoids the mouse-event path
			// overwriting panel hover between frames (visible as cursor flicker).
			bool localHover = _hoverClickableThisFrame || _panelHoverClickableThisFrame;

			// Shared hover coordination: publish our hover state and read the
			// union across all panel indicators on this chart so that KL / PA /
			// OrderFlow can't inadvertently overwrite our Hand with Arrow (or
			// vice-versa) during their own OnRender pass.
			bool anyHover = localHover;
			try
			{
				var reg = GetHoverRegistry();
				var dict = reg.GetOrAdd(panelHash, k => new ConcurrentDictionary<string, bool>());
				dict[PANEL_ID] = localHover;
				foreach (var kvp in dict) if (kvp.Value) { anyHover = true; break; }
			}
			catch { }

			var want = anyHover
				? System.Windows.Input.Cursors.Hand
				: System.Windows.Input.Cursors.Arrow;
			if (want == _lastAppliedChartCursor) return;
			_lastAppliedChartCursor = want;
			try { ChartControl.Cursor = want; } catch { /* chart may be disposed mid-render */ }
		}

		// --- Additional static brushes (constant colors) ---
		private void DisposeWorkingBrushes()
		{
			if (workingBrushA != null) { workingBrushA.Dispose(); workingBrushA = null; }
			if (workingBrushB != null) { workingBrushB.Dispose(); workingBrushB = null; }
		}

		private void CreateWorkingBrushes()
		{
			if (RenderTarget == null) return;
			DisposeWorkingBrushes();
			workingBrushA = new SharpDX.Direct2D1.SolidColorBrush(RenderTarget, SharpDX.Color.Black);
			workingBrushB = new SharpDX.Direct2D1.SolidColorBrush(RenderTarget, SharpDX.Color.Black);
		}

		// Set a working brush color from a WPF Brush (no allocation)
		private void SetWorkingBrushColor(SharpDX.Direct2D1.SolidColorBrush target, Brush wpfBrush, float opacity = 1.0f)
		{
			if (wpfBrush is SolidColorBrush scb)
			{
				var c = scb.Color;
				target.Color = new SharpDX.Color(c.R, c.G, c.B, c.A);
			}
			target.Opacity = opacity;
		}

