				|| lastClickDNColor != pClickDNColor
				|| lastBuyOneClickColor1 != pBuyOneClickColor1
				|| lastSellOneClickColor1 != pSellOneClickColor1
				|| lastOnOpacity22 != pOnOpacity22
				|| lastColorBuyPlan2 != pColorBuyPlan2
				|| lastColorSellPlan2 != pColorSellPlan2
				|| lastCustomOrderBuyColor != pCustomOrderBuyColor
				|| lastCustomOrderSellColor != pCustomOrderSellColor
				|| lastOrderLITColor != pOrderLITColor
				|| lastBarCounterColor != pBarCounterColor
				|| lastChartBackground != ChartControl.Properties.ChartBackground;
		}

