			lastBidOutColor1 = pBidOutColor1;
			lastAskOpacity = pAskOpacity;
			lastAskOpacity2 = pAskOpacity2;
			lastBidOpacity = pBidOpacity;
			lastBidOpacity2 = pBidOpacity2;
			marketDepthBrushesNeedRefresh = false;
		}

		private bool MarketDepthBrushesChanged()
		{
			if (marketDepthBrushesNeedRefresh) return true;
			return lastAskHistColor1 != pAskHistColor1
				|| lastAskHistColor2 != pAskHistColor2
				|| lastAskOutColor1 != pAskOutColor1
				|| lastBidHistColor1 != pBidHistColor1
				|| lastBidHistColor2 != pBidHistColor2
				|| lastBidOutColor1 != pBidOutColor1
				|| lastAskOpacity != pAskOpacity
				|| lastAskOpacity2 != pAskOpacity2
				|| lastBidOpacity != pBidOpacity
				|| lastBidOpacity2 != pBidOpacity2;
		}

		// --- Triangle brushes ---
		private void DisposeTriangleBrushes()
		{
			if (BidTriBrushDX != null) { BidTriBrushDX.Dispose(); BidTriBrushDX = null; }
			if (AskTriBrushDX != null) { AskTriBrushDX.Dispose(); AskTriBrushDX = null; }
			if (ExitTriBrushDX != null) { ExitTriBrushDX.Dispose(); ExitTriBrushDX = null; }
		}

		private void CreateTriangleBrushes()
		{
			if (RenderTarget == null) return;
			DisposeTriangleBrushes();
			BidTriBrushDX = pColorBid2Tri.ToDxBrush(RenderTarget);
			AskTriBrushDX = pColorAskTri.ToDxBrush(RenderTarget);
			ExitTriBrushDX = pColorExitTri.ToDxBrush(RenderTarget);
			lastColorBid2Tri = pColorBid2Tri;
			lastColorAskTri = pColorAskTri;
			lastColorExitTri = pColorExitTri;
			triangleBrushesNeedRefresh = false;
		}

		private bool TriangleBrushesChanged()
		{
			if (triangleBrushesNeedRefresh) return true;
			return lastColorBid2Tri != pColorBid2Tri
				|| lastColorAskTri != pColorAskTri
				|| lastColorExitTri != pColorExitTri;
		}

		private void DisposeAllCachedTextFormats()
		{
			if (cachedBottomTextFormat != null) { cachedBottomTextFormat.Dispose(); cachedBottomTextFormat = null; }
			if (cachedCenterTextFormat != null) { cachedCenterTextFormat.Dispose(); cachedCenterTextFormat = null; }
			if (cachedButtonTextFormat != null) { cachedButtonTextFormat.Dispose(); cachedButtonTextFormat = null; }
			if (cachedChartFontAdFormat != null) { cachedChartFontAdFormat.Dispose(); cachedChartFontAdFormat = null; }
			if (cachedChartMenuBtnFormat != null) { cachedChartMenuBtnFormat.Dispose(); cachedChartMenuBtnFormat = null; }
			if (cachedTextFont66Format != null) { cachedTextFont66Format.Dispose(); cachedTextFont66Format = null; }
			if (cachedTextFont8Format != null) { cachedTextFont8Format.Dispose(); cachedTextFont8Format = null; }
			if (cachedTextFont8WrapFormat != null) { cachedTextFont8WrapFormat.Dispose(); cachedTextFont8WrapFormat = null; }
			if (cachedTextFontTimeFormat != null) { cachedTextFontTimeFormat.Dispose(); cachedTextFontTimeFormat = null; }
			DisposeCloseBoldFormats();
			// TextLayouts in _measureLayoutCache hold references to the
			// TextFormats we just disposed. Flush them in lock-step so no
			// stale layout survives a format refresh.
			DisposeMeasureLayoutCache();
			// Cached order/flag text sizes are font-specific — flush on rebuild too.
			_orderTextSizeCache66.Clear();
			_orderTextSizeCacheAd.Clear();
		}

		private void DisposeCloseBoldFormats()
		{
			if (closeBoldFormatsByH == null) return;
			foreach (var kv in closeBoldFormatsByH)
				if (kv.Value != null) kv.Value.Dispose();
			closeBoldFormatsByH.Clear();
		}

		// Returns a bold-X TextFormat sized for the given cancel-button box height.
		// Formula: max(pTextFont66.Size + 2, boxHeight * 0.65). At default flag
		// settings the floor matches the original size; bigger flags get a bigger X.
		private SharpDX.DirectWrite.TextFormat GetCloseBoldFormat(float boxHeight)
		{
			float desired = Math.Max((float)pTextFont66.Size + 2f, boxHeight * 0.65f);
			int key = (int)Math.Round(desired);
			if (key < 6) key = 6; // safety floor
			SharpDX.DirectWrite.TextFormat tf;
			if (closeBoldFormatsByH.TryGetValue(key, out tf) && tf != null) return tf;
			tf = new SharpDX.DirectWrite.TextFormat(
				Core.Globals.DirectWriteFactory,
				pTextFont66.Family.ToString(),
				SharpDX.DirectWrite.FontWeight.Bold,
				SharpDX.DirectWrite.FontStyle.Normal,
				SharpDX.DirectWrite.FontStretch.Normal,
				key);
			tf.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			tf.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			tf.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
			closeBoldFormatsByH[key] = tf;
			return tf;
		}

		private void CreateCachedTextFormats()
		{
			DisposeAllCachedTextFormats();
			// Font sizes are not DPI-scaled — NT8's chart RenderTarget already
			// handles font DPI, so applying S() here double-scaled at high DPI
			// (e.g. 250% rendered text 2.5× too large). Spacing/stroke widths
			// continue to use S()/DS() as needed.
			cachedTextFont66Format    = new SimpleFont(pTextFont66.Family.ToString(),   (float)pTextFont66.Size)  .ToDirectWriteTextFormat();
			cachedTextFont8Format     = new SimpleFont(pTextFont8.Family.ToString(),    (float)pTextFont8.Size)   .ToDirectWriteTextFormat();
			cachedTextFont8WrapFormat = new SimpleFont(pTextFont8.Family.ToString(),    (float)pTextFont8.Size)   .ToDirectWriteTextFormat();
			cachedTextFontTimeFormat  = new SimpleFont(pTextFontTime.Family.ToString(), (float)pTextFontTime.Size).ToDirectWriteTextFormat();

			// Pre-set alignment/wrap once at creation. Render hot paths
			// previously re-wrote these three properties every frame at lines
			// ~74156, ~73165, ~73417, ~73419. Moving the writes here means
			// the inner loops just point CellFormat at the right pre-configured
			// format. Saves a few hundred property writes per render frame on
			// a busy chart and eliminates a "who mutated the shared format
			// last" foot-gun.
			cachedTextFont8Format.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Center;
			cachedTextFont8Format.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			cachedTextFont8Format.WordWrapping       = SharpDX.DirectWrite.WordWrapping.NoWrap;

			cachedTextFont8WrapFormat.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Center;
			cachedTextFont8WrapFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			cachedTextFont8WrapFormat.WordWrapping       = SharpDX.DirectWrite.WordWrapping.Wrap;

			cachedTextFontTimeFormat.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Center;
			cachedTextFontTimeFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			cachedTextFontTimeFormat.WordWrapping       = SharpDX.DirectWrite.WordWrapping.NoWrap;
			if (ThisChartFontAd != null)
				cachedChartFontAdFormat = new SimpleFont(ThisChartFontAd.Family.ToString(), (float)ThisChartFontAd.Size).ToDirectWriteTextFormat();
			else
				cachedChartFontAdFormat = new SimpleFont(pTextFont66.Family.ToString(), (float)pTextFont66.Size).ToDirectWriteTextFormat();

			// Chart menu button text format — sized by the dedicated
			// pChartMenuTextSize property so it's independent of the ATM
			// planning label size (pATMTextSizeAdjust). Uses the chart's
			// label font family with a floor of 11.
			if (cachedChartMenuBtnFormat != null) cachedChartMenuBtnFormat.Dispose();
			{
				string menuFontFamily = myProperties != null ? myProperties.LabelFont.Family.ToString() : "Arial";
				double menuFontSize = myProperties != null ? Math.Max(11, myProperties.LabelFont.Size + pChartMenuTextSize) : 12;
				var menuSimpleFont = new SimpleFont(menuFontFamily, (float)menuFontSize);
				cachedChartMenuBtnFormat = menuSimpleFont.ToDirectWriteTextFormat();
			}

			// Close-button "X" formats are now sized per-box-height via GetCloseBoldFormat.
			// Clear the cache here so font-family/property changes invalidate sized variants.
			DisposeCloseBoldFormats();

			textFormatsNeedRefresh = false;
		}

		// Order flag rounded rectangle helpers - fall back to sharp when rounding is 0.
		// Radius is DPI-scaled so corners stay visually proportional at 150-250%.
		private void FillOrderRect(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			if (!RectOK(rect, "FillOrderRect")) return;
			if (pOrderFlagRounding > 0)
			{
				float r = S(pOrderFlagRounding);
				SafeFillRoundedRectangle(new SharpDX.Direct2D1.RoundedRectangle() { Rect = rect, RadiusX = r, RadiusY = r }, brush);
			}
			else
				SafeFillRectangle(rect, brush);
		}

		private void FillOrderRect(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush, int radiusOverride)
		{
			if (!RectOK(rect, "FillOrderRect2")) return;
			if (radiusOverride > 0)
			{
				float r = S(radiusOverride);
				SafeFillRoundedRectangle(new SharpDX.Direct2D1.RoundedRectangle() { Rect = rect, RadiusX = r, RadiusY = r }, brush);
			}
			else
				SafeFillRectangle(rect, brush);
		}

		// Draw a crisp 1px aliased rectangle border (for buttons)
		private void DrawButtonBorder(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			if (!RectOK(rect, "DrawButtonBorder")) return;
			var savedAA = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.Aliased;
			SafeDrawRectangle(rect, brush);
			RenderTarget.AntialiasMode = savedAA;
		}

		private void DrawOrderRect(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush, float strokeWidth)
		{
			if (!RectOK(rect, "DrawOrderRect")) return;
			if (pOrderFlagRounding > 0)
			{
				float r = S(pOrderFlagRounding);
				SafeDrawRoundedRectangle(new SharpDX.Direct2D1.RoundedRectangle() { Rect = rect, RadiusX = r, RadiusY = r }, brush, strokeWidth);
			}
			else
				SafeDrawRectangle(rect, brush, strokeWidth);
		}
		/// <summary>
		/// Draws a soft opaque background behind floating text labels (ATM tooltips, plan labels, etc.)
		/// Uses layered chart-background fills for a smooth fade from transparent edges to solid center.
		/// </summary>
		private void DrawTextBackground(SharpDX.RectangleF textRect, int padding = 3)
		{
			if (ChartBackgroundShade1BrushDX == null) return;

			// Soft fade backdrop — matches the visual language of the hover
			// version in DrawTextToggleHoverGlow, just at lower intensity. Five
			// layered rounded rectangles, innermost most opaque (chart-bg
			// punches through anything drawn under), outermost most transparent
			// so the edge dissolves into the chart background instead of
			// stopping at a hard rect boundary. On hover the same shape grows
			// brighter / wider; idle and hover read as the same family.
			//
			// Plain RenderTarget.Fill* (no *Both), so opacity mutation is safe
			// from the AllDrawings replay cache (CLAUDE.md §6).
			float prevBdOp = ChartBackgroundShade1BrushDX.Opacity;
			float baseRadius = DS(4f);
			int[]   xPads     = { padding,     padding + 1, padding + 3, padding + 5, padding + 7 };
			int[]   yPads     = { 0,           1,           2,           3,           4           };
			float[] opacities = { 0.55f, 0.38f, 0.22f, 0.12f, 0.06f };
			for (int i = 0; i < xPads.Length; i++)
			{
				ChartBackgroundShade1BrushDX.Opacity = opacities[i];
				SafeFillRoundedRectangle(
					new SharpDX.Direct2D1.RoundedRectangle()
					{
						Rect    = ExpandRect(textRect, xPads[i], yPads[i]),
						RadiusX = baseRadius + i,
						RadiusY = baseRadius + i,
					},
					ChartBackgroundShade1BrushDX);
			}
			ChartBackgroundShade1BrushDX.Opacity = prevBdOp;
		}

		// Text-shaped backdrop "halo" for plan-line text toggles in their
		// non-hovered state. Uses the SAME 8-direction offset technique as
		// the hover halo in DrawTextToggleHoverGlow, but in the chart-bg
		// color instead of the text-highlight color. The chart-bg pixels
		// drawn around each character mask candles / grid / plan strokes
		// rendered behind, so the actual text drawn on top reads cleanly
		// without needing a rectangular backdrop chip.
		//
		// Hover and non-hover now share the same visual language —
		// fuzzy halo that hugs the text shape — and the hover version just
		// turns up the brightness (text-highlight color halo + bright label
		// redraw on top) instead of changing the shape.
		//
		// Plain RenderTarget.DrawText (no *Both), so opacity mutation is
		// safe from the AllDrawings replay cache (CLAUDE.md §6).
		private void DrawTextHaloBackdrop(SharpDX.RectangleF textRect, string textLabel, SharpDX.DirectWrite.TextFormat textFormat)
		{
			if (ChartBackgroundBrushDX == null) return;
			if (string.IsNullOrEmpty(textLabel) || textFormat == null) return;

			SharpDX.Direct2D1.AntialiasMode savedAA = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

			// Multi-ring halo: each ring is 8 offset text draws around the
			// label, with the outermost rings dimmer so the halo fades smoothly
			// into the chart background. Result is a wider, softer chart-bg
			// aura around the characters that lifts the text off candles /
			// grid / strokes drawn behind without a hard rectangle edge.
			//
			// Drawn outer-to-inner so the inner (most opaque) draws sit on top,
			// keeping the area immediately around the text crisply chart-bg.
			//
			// Plain RenderTarget.DrawText (no *Both), so opacity mutation is
			// safe from the AllDrawings replay cache (CLAUDE.md §6).
			float prevBgOp = ChartBackgroundBrushDX.Opacity;

			// Outer rings: increasing offset, decreasing opacity.
			// Tuning: ring radii in px (DPI-scaled), opacity per ring.
			// Drawn outer-to-inner so the inner ring sits on top.
			float[] radii     = { 5f,   4f,   3f,   2f,   1f   };
			float[] opacities = { 0.20f, 0.35f, 0.55f, 0.80f, 1.0f };

			// 16-direction sampling per ring — every 22.5°. With only 8
			// directions (cardinals + diagonals), the offset copies at
			// larger radii (>=3 px) show as visibly separate ghost
			// glyphs in the cardinal / diagonal axes — the "choppy"
			// halo look. 16 directions fill the gaps so the halo reads
			// as a smooth continuous aura around each character.
			const int dirs = 16;
			double angleStep = 2.0 * Math.PI / dirs;
			for (int ring = 0; ring < radii.Length; ring++)
			{
				float radius = DS(radii[ring]);
				ChartBackgroundBrushDX.Opacity = opacities[ring];
				for (int d = 0; d < dirs; d++)
				{
					double angle = d * angleStep;
					float ox = (float)(Math.Cos(angle) * radius);
					float oy = (float)(Math.Sin(angle) * radius);
					SharpDX.RectangleF rr = textRect;
					rr.X += ox; rr.Y += oy;
					SafeDrawText(textLabel, textFormat, rr, ChartBackgroundBrushDX);
				}
			}

			ChartBackgroundBrushDX.Opacity = prevBgOp;
			RenderTarget.AntialiasMode = savedAA;
		}

		// Shared hover glow for the 5 text toggles on plan lines (Hide,
		// Now/Price, R/R, IE:, plus the Entry direction label). Three rounded-
		// rectangle fade layers behind the text that match the chart-background
		// shade (same brush DrawTextBackground uses), so the halo reads as an
		// extension of the existing label chip rather than a white glow. The
		// text is redrawn on top in the highlight color to signal hover state.
		// Geometry: wider horizontally than tall — matches how the labels
		// visually read (short height, longer words). Fully DPI-aware via DS().
		private void DrawTextToggleHoverGlow(SharpDX.RectangleF textRect, string textLabel, SharpDX.DirectWrite.TextFormat textFormat, bool addBackdrop = true)
		{
			if (ChartOrdersHighlightBrushDX == null) return;

			SharpDX.Direct2D1.AntialiasMode savedAA = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

			// Hover-only backdrop reinforcement: stack a few more chart-bg
			// layers on top of the baseline DrawTextBackground (which the
			// caller already drew at 4×0.25 ≈ 0.68 effective opacity). The
			// caller's label has already been drawn over that backdrop too,
			// but the halo + label below will redraw the text on top, so the
			// only visible effect of these extra layers is the chart-bg under
			// the glow becoming nearly solid — making the toggle clearly
			// "lifted" off the chart on hover. Non-hovered toggles stay at the
			// soft 4-layer baseline.
			//
			// The Place Order button passes addBackdrop=false because it
			// already has its own colored Buy/Sell fill. Painting chart-bg
			// over that would wash it out around the text and looked blurry.
			if (addBackdrop && ChartBackgroundShade1BrushDX != null)
			{
				// Soft fade backdrop — replaces the prior 4-layer hard
				// rectangle fills. Layered rounded rectangles at increasing
				// expansion and DECREASING opacity so the outer edge fades
				// into the chart background instead of stopping at a hard
				// rect boundary. Mirrors the 4-layer fade glow approach used
				// for plan-line hover (DrawPlanOrder, ~:80604).
				//
				// Inner layers: smaller expansion, higher opacity → solid
				//   chart-bg under the text so it punches through everything
				//   drawn under it (candles, grid lines, plan strokes).
				// Outer layers: wider expansion, lower opacity → soft halo
				//   that dissolves into the chart bg, no visible edge.
				//
				// Rounded corners (DPI-scaled radius) keep the shape feeling
				// like an integrated lift rather than a stamped rectangle.
				// All draws go straight to RenderTarget (no *Both), so
				// opacity mutation is safe from the AllDrawings replay cache
				// (CLAUDE.md §6).
				float prevBdOp = ChartBackgroundShade1BrushDX.Opacity;
				float baseRadius = DS(4f);
				// 5 layers: from innermost (most opaque, smallest) to outermost (most transparent, widest).
				// xPad: horizontal expansion. yPad: vertical (start tight, expand outward).
				// Inner opacity capped so the box never fully masks what's behind —
				// candles / grid stay subtly visible through the lift, just dimmed.
				int[]   xPads     = { 2, 3, 4, 5, 6 };
				int[]   yPads     = { 0, 1, 2, 3, 4 };
				float[] opacities = { 0.35f, 0.25f, 0.18f, 0.10f, 0.05f };
				for (int i = 0; i < xPads.Length; i++)
				{
					ChartBackgroundShade1BrushDX.Opacity = opacities[i];
					SafeFillRoundedRectangle(
						new SharpDX.Direct2D1.RoundedRectangle()
						{
							Rect    = ExpandRect(textRect, xPads[i], yPads[i]),
							RadiusX = baseRadius + i,
							RadiusY = baseRadius + i,
						},
						ChartBackgroundShade1BrushDX);
				}
				ChartBackgroundShade1BrushDX.Opacity = prevBdOp;
			}

			// Soft text glow — no pill, no outline. Re-renders the label in
			// the highlight color at moderate opacity, offset 1 px in each of
			// the 8 surrounding pixels, to produce a fuzzy halo around the
			// characters themselves. The label is then drawn on top so the
			// glow appears to radiate from the text. Reads as "this is
			// hot/active" without taking up extra real estate or drawing a
			// defined shape that bleeds into adjacent plan elements.
			//
			// Tuning notes:
			//   * Halo opacity 0.20 — soft fuzzy glow around the characters
			//     without overpowering the chart-bg backdrop the toggle sits
			//     on. The backdrop (DrawTextBackground, layered chart-bg
			//     fills) carries most of the visual weight; the halo is just
			//     the "this is hot" tint.
			//   * Top label opacity 0.85 — softer than pure white.
			//
			// Brush opacity is mutated and restored within this function.
			// Safe because all draw calls go straight to RenderTarget (no
			// FillRectBoth / DrawTextBoth — those would cache the brush ref
			// into AllDrawings and replay at whatever opacity it had).
			float prevHaloOpacity = ChartOrdersHighlightBrushDX.Opacity;
			ChartOrdersHighlightBrushDX.Opacity = 0.20f;

			float off = DS(1f);
			SharpDX.RectangleF r;
			// Cardinals
			r = textRect; r.X -= off;             SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.X += off;             SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.Y -= off;             SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.Y += off;             SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			// Diagonals
			r = textRect; r.X -= off; r.Y -= off; SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.X += off; r.Y -= off; SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.X -= off; r.Y += off; SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);
			r = textRect; r.X += off; r.Y += off; SafeDrawText(textLabel, textFormat, r, ChartOrdersHighlightBrushDX);

			ChartOrdersHighlightBrushDX.Opacity = prevHaloOpacity;

			// Label on top — slightly off-white (0.85 opacity) for a softer
			// finish against the glow. Falls back to the highlight brush if
			// cachedWhiteBrushDX hasn't been initialized yet (very early frames).
			SharpDX.Direct2D1.Brush labelBrush = cachedWhiteBrushDX != null ? cachedWhiteBrushDX : ChartOrdersHighlightBrushDX;
			float prevLabelOpacity = labelBrush.Opacity;
			labelBrush.Opacity = 0.85f;
			SafeDrawText(textLabel, textFormat, textRect, labelBrush);
			labelBrush.Opacity = prevLabelOpacity;

			RenderTarget.AntialiasMode = savedAA;
		}

