		private void FillHeaderButton(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			float r = S(chartButtonRadius + 2);
			SharpDX.RectangleF extended = new SharpDX.RectangleF(rect.Left, rect.Top, rect.Width, rect.Height + r);
			var saved = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;
			SafeFillRoundedRectangle(new SharpDX.Direct2D1.RoundedRectangle() { Rect = extended, RadiusX = r, RadiusY = r }, brush);
			SafeFillRectangle(new SharpDX.RectangleF(rect.Left, rect.Top, r, r), brush);
			RenderTarget.AntialiasMode = saved;
		}

		private Dictionary<string, SharpDX.Size2F> panelTextMeasureCache = new Dictionary<string, SharpDX.Size2F>();

		private SharpDX.Size2F PanelMeasureText(string text, SharpDX.DirectWrite.TextFormat format)
		{
			SharpDX.Size2F size;
			if (panelTextMeasureCache.TryGetValue(text, out size))
				return size;
			using (var layout = new SharpDX.DirectWrite.TextLayout(Core.Globals.DirectWriteFactory, text, format, 10000, 10000))
			{
				size = new SharpDX.Size2F(layout.Metrics.Width, layout.Metrics.Height);
			}
			panelTextMeasureCache[text] = size;
			return size;
		}

