		private bool BetaAttachEnabled = true;
		private int SelectedStopRender = 8;
		private int CurrentStopRender = 0;
		
		
		
		
		private bool TestRender = false;	
		
		private bool _d2dProbeTripped;
		private int _renderTestPrevN = -1;
		private long _renderTestPrevTicks;

		// Diagnostic instrumentation 2026-05-21. RenderTest is called at 25
		// points spanning OnRender, so it doubles as a checkpoint grid for two
		// problems the ECT_*.log otherwise can't localize:
		//  - D2DStateProbe: a draw call given NaN/degenerate geometry corrupts
		//    the render target SILENTLY — the void DrawXxx/FillXxx calls just
		//    batch the bad command and never throw; the error only surfaces at
		//    NinjaTrader's EndDraw as D2DERR_WRONG_STATE, with no clue which
		//    call did it. Flush() DOES throw on a corrupt target, so calling it
		//    at each checkpoint makes the first D2DStateProbe line localize the
		//    bad draw to between two checkpoints.
		//  - SlowSpan: logs the wall time of each checkpoint-to-checkpoint span
		//    so the phase behind the 1-2 FPS render gap is identifiable.
		private bool RenderTest(int CurrentStopRender)
		{
			if (RenderTarget != null)
			{
				int _prevN = _renderTestPrevN;
				long _nowT = System.Diagnostics.Stopwatch.GetTimestamp();
				if (_renderTestPrevTicks != 0)
				{
					double _spanMs = (_nowT - _renderTestPrevTicks) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
					if (_spanMs > 50.0)
						LogDiag("RENDER", "SlowSpan", "checkpoint " + _prevN + "->" + CurrentStopRender + " = " + _spanMs.ToString("F0") + "ms");
				}
				_renderTestPrevN = CurrentStopRender;
				_renderTestPrevTicks = _nowT;
				try { RenderTarget.Flush(); }
				catch (Exception _probeEx)
				{
					if (!_d2dProbeTripped)
					{
						_d2dProbeTripped = true;
						LogDiag("RENDER", "D2DStateProbe", "corruption detected at checkpoint " + CurrentStopRender + " — bad draw is between RenderTest(" + _prevN + ") and RenderTest(" + CurrentStopRender + ") | " + _probeEx.Message);
					}
				}
			}

			if (!TestRender)
				return false;

			// Print(SelectedStopRender + " " + CurrentStopRender);

			return (SelectedStopRender == CurrentStopRender);
		}
		
