		// --- Clip-stack guard ---------------------------------------------------
		// D2D requires PushAxisAlignedClip / PopAxisAlignedClip to balance within a
		// frame; an unbalanced stack throws D2DERR_PUSH_POP_UNBALANCED at EndDraw and
		// freezes the chart. PushClipDX / PopClipDX track depth so a stray Pop is
		// dropped (and logged) and a leaked Push is drained at the end of OnRender.
		private int _clipPushDepth;

		// Panel clip toggle. 26.5.21.12 set this true to test whether the new
		// axis-aligned panel clip caused the freeze — it did NOT (the freeze
		// reproduced with clipping fully off), so clipping is re-enabled here
		// to avoid leaving the panel content unclipped.
		private bool _clipDisabled = false;

		private void PushClipDX(SharpDX.RectangleF rect, SharpDX.Direct2D1.AntialiasMode aa)
		{
			if (_clipDisabled) return;
			if (RenderTarget == null) return;
			// A degenerate or non-finite clip rect drives the render target into an
			// error state (D2DERR_WRONG_STATE), which then cascades into the
			// D2DERR_PUSH_POP_UNBALANCED freeze. Skip the push if the rect is not a
			// valid, positive, finite rectangle — the !(x > 0) form also rejects NaN.
			if (!(rect.Width > 0f) || !(rect.Height > 0f)
				|| float.IsNaN(rect.Left) || float.IsNaN(rect.Top)
				|| float.IsInfinity(rect.Left) || float.IsInfinity(rect.Top)
				|| float.IsInfinity(rect.Width) || float.IsInfinity(rect.Height))
			{
				LogDiag("RENDER", "ClipRectInvalid",
					"L=" + rect.Left + " T=" + rect.Top + " W=" + rect.Width + " H=" + rect.Height);
				return;
			}
			try { RenderTarget.PushAxisAlignedClip(rect, aa); _clipPushDepth++; }
			catch (Exception ex) { LogDiagEx("RENDER", "PushClip", ex); }
		}

		private void PopClipDX()
		{
			if (_clipDisabled) return;
			if (RenderTarget == null) return;
			if (_clipPushDepth <= 0)
			{
				LogDiag("RENDER", "ClipUnderflow", "Pop with no matching Push (skipped)");
				return;
			}
			try { RenderTarget.PopAxisAlignedClip(); }
			catch (Exception ex) { LogDiagEx("RENDER", "PopClip", ex); }
			_clipPushDepth--;
		}

		// --- Direct2D geometry hardening ---------------------------------------
		// A SharpDX draw call given a non-finite (NaN/Infinity) or absurd
		// coordinate, or a degenerate rect (width/height <= 0), can silently
		// corrupt the render target — the chart then freezes until Reload
		// NinjaScript. The order-flag draw wrappers route through RectOK so a
		// bad rect is dropped (and logged, capped) instead of poisoning D2D.
		private int _badRectLogCount;
		// Click-entry cursor reference (plot 20) — set by DrawClickEntry on the
		// render thread, applied to the plot by OnBarUpdate on the calc thread.
		private double _clickRefPrice;
		private System.Windows.Media.Brush _clickRefBrush;
		private long _clickRefTicks;
		private static bool BadF(double v)
		{
			return double.IsNaN(v) || double.IsInfinity(v) || v > 1e7 || v < -1e7;
		}
		private static bool BadRect(SharpDX.RectangleF r)
		{
			return BadF(r.Left) || BadF(r.Top) || BadF(r.Width) || BadF(r.Height)
				|| r.Width <= 0f || r.Height <= 0f;
		}
		private bool RectOK(SharpDX.RectangleF r, string where)
		{
			if (RenderTarget == null) return false;
			if (BadRect(r))
			{
				if (_badRectLogCount < 30)
				{
					_badRectLogCount++;
					LogDiag("RENDER", "BadRectSkipped", where + " L=" + r.Left + " T=" + r.Top + " W=" + r.Width + " H=" + r.Height);
				}
				return false;
			}
			return true;
		}

		// --- 26.5.21.14: comprehensive Direct2D draw-call hardening ----------
		// Every RenderTarget.DrawXxx / FillXxx call in this file is routed
		// through these wrappers. A non-finite (NaN/Infinity) or absurd
		// coordinate, or a null/disposed brush, handed to a Direct2D draw call
		// silently corrupts the render target: the void draw call batches the
		// bad command and the failure only surfaces at NinjaTrader's EndDraw as
		// D2DERR_WRONG_STATE, freezing the chart. The wrappers drop a draw whose
		// geometry or brush is invalid (logged, capped) instead of poisoning
		// D2D. For valid input they call straight through — no behaviour change.
		private int _safeDrawSkipLog;
		private void SafeDrawSkip(string what)
		{
			if (_safeDrawSkipLog < 40)
			{
				_safeDrawSkipLog++;
				LogDiag("RENDER", "SafeDrawSkipped", what);
			}
		}
		private bool RectFin(SharpDX.RectangleF r)
		{
			return !BadF(r.Left) && !BadF(r.Top) && !BadF(r.Width) && !BadF(r.Height);
		}
		private bool BrushOK(SharpDX.Direct2D1.Brush b)
		{
			return b != null && !b.IsDisposed;
		}

		// --- 26.5.21.15: off-thread Direct2D access tripwire -----------------
		// Direct2D's render target is single-threaded. If any background thread
		// (an OnOrderUpdate2 / OnExecutionUpdate2 / OnPositionUpdate2 handler —
		// they run on NinjaTrader account threads) reaches a D2D call, it races
		// OnRender and silently corrupts the render target, surfacing as
		// D2DERR_WRONG_STATE at EndDraw. Every D2D entry point calls
		// D2DThreadCheck; if one ever runs on a thread other than the render
		// thread, the call and its full stack trace are logged so the exact
		// off-thread code path is named.
		private int _renderThreadId;
		private volatile bool _renderActive;
		private int _offThreadD2DLog;
		private int _ortcCount;
		private void D2DThreadCheck(string where)
		{
			int rt = _renderThreadId;
			if (rt == 0) return;
			int tid = System.Threading.Thread.CurrentThread.ManagedThreadId;
			if (tid == rt) return;
			if (_offThreadD2DLog < 25)
			{
				_offThreadD2DLog++;
				LogDiag("RENDER", "OffThreadD2D", where + " | thread=" + tid
					+ " renderThread=" + rt + " renderActive=" + _renderActive
					+ "\n" + System.Environment.StackTrace);
			}
		}

		private void SafeFillRectangle(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			D2DThreadCheck("FillRectangle");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("FillRectangle/brush"); return; }
			if (!RectFin(rect)) { SafeDrawSkip("FillRectangle/rect"); return; }
			RenderTarget.FillRectangle(rect, brush);
		}
		private void SafeDrawRectangle(SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush, float strokeWidth = 1f, SharpDX.Direct2D1.StrokeStyle style = null)
		{
			D2DThreadCheck("DrawRectangle");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("DrawRectangle/brush"); return; }
			if (!RectFin(rect) || BadF(strokeWidth)) { SafeDrawSkip("DrawRectangle/geom"); return; }
			RenderTarget.DrawRectangle(rect, brush, strokeWidth, style);
		}
		private void SafeFillRoundedRectangle(SharpDX.Direct2D1.RoundedRectangle rr, SharpDX.Direct2D1.Brush brush)
		{
			D2DThreadCheck("FillRoundedRectangle");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("FillRoundedRectangle/brush"); return; }
			if (!RectFin(rr.Rect) || BadF(rr.RadiusX) || BadF(rr.RadiusY)) { SafeDrawSkip("FillRoundedRectangle/geom"); return; }
			RenderTarget.FillRoundedRectangle(rr, brush);
		}
		private void SafeDrawRoundedRectangle(SharpDX.Direct2D1.RoundedRectangle rr, SharpDX.Direct2D1.Brush brush, float strokeWidth = 1f, SharpDX.Direct2D1.StrokeStyle style = null)
		{
			D2DThreadCheck("DrawRoundedRectangle");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("DrawRoundedRectangle/brush"); return; }
			if (!RectFin(rr.Rect) || BadF(rr.RadiusX) || BadF(rr.RadiusY) || BadF(strokeWidth)) { SafeDrawSkip("DrawRoundedRectangle/geom"); return; }
			RenderTarget.DrawRoundedRectangle(rr, brush, strokeWidth, style);
		}
		private void SafeDrawLine(SharpDX.Vector2 p1, SharpDX.Vector2 p2, SharpDX.Direct2D1.Brush brush, float strokeWidth = 1f, SharpDX.Direct2D1.StrokeStyle style = null)
		{
			D2DThreadCheck("DrawLine");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("DrawLine/brush"); return; }
			if (BadF(p1.X) || BadF(p1.Y) || BadF(p2.X) || BadF(p2.Y) || BadF(strokeWidth)) { SafeDrawSkip("DrawLine/geom"); return; }
			RenderTarget.DrawLine(p1, p2, brush, strokeWidth, style);
		}
		private void SafeDrawText(string text, SharpDX.DirectWrite.TextFormat format, SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			D2DThreadCheck("DrawText");
			if (RenderTarget == null) return;
			if (string.IsNullOrEmpty(text)) return;
			if (format == null || format.IsDisposed) { SafeDrawSkip("DrawText/format"); return; }
			if (!BrushOK(brush)) { SafeDrawSkip("DrawText/brush"); return; }
			if (!RectFin(rect)) { SafeDrawSkip("DrawText/rect"); return; }
			RenderTarget.DrawText(text, format, rect, brush);
		}
		private void SafeFillEllipse(SharpDX.Direct2D1.Ellipse el, SharpDX.Direct2D1.Brush brush)
		{
			D2DThreadCheck("FillEllipse");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("FillEllipse/brush"); return; }
			if (BadF(el.Point.X) || BadF(el.Point.Y) || BadF(el.RadiusX) || BadF(el.RadiusY)) { SafeDrawSkip("FillEllipse/geom"); return; }
			RenderTarget.FillEllipse(el, brush);
		}
		private void SafeDrawEllipse(SharpDX.Direct2D1.Ellipse el, SharpDX.Direct2D1.Brush brush, float strokeWidth = 1f, SharpDX.Direct2D1.StrokeStyle style = null)
		{
			D2DThreadCheck("DrawEllipse");
			if (RenderTarget == null) return;
			if (!BrushOK(brush)) { SafeDrawSkip("DrawEllipse/brush"); return; }
			if (BadF(el.Point.X) || BadF(el.Point.Y) || BadF(el.RadiusX) || BadF(el.RadiusY) || BadF(strokeWidth)) { SafeDrawSkip("DrawEllipse/geom"); return; }
			RenderTarget.DrawEllipse(el, brush, strokeWidth, style);
		}
		private void SafeFillGeometry(SharpDX.Direct2D1.Geometry geom, SharpDX.Direct2D1.Brush brush)
		{
			D2DThreadCheck("FillGeometry");
			if (RenderTarget == null) return;
			if (geom == null || geom.IsDisposed) { SafeDrawSkip("FillGeometry/geom"); return; }
			if (!BrushOK(brush)) { SafeDrawSkip("FillGeometry/brush"); return; }
			RenderTarget.FillGeometry(geom, brush);
		}
		private void SafeDrawGeometry(SharpDX.Direct2D1.Geometry geom, SharpDX.Direct2D1.Brush brush, float strokeWidth = 1f, SharpDX.Direct2D1.StrokeStyle style = null)
		{
			D2DThreadCheck("DrawGeometry");
			if (RenderTarget == null) return;
			if (geom == null || geom.IsDisposed) { SafeDrawSkip("DrawGeometry/geom"); return; }
			if (!BrushOK(brush)) { SafeDrawSkip("DrawGeometry/brush"); return; }
			if (BadF(strokeWidth)) { SafeDrawSkip("DrawGeometry/width"); return; }
			RenderTarget.DrawGeometry(geom, brush, strokeWidth, style);
		}

		private int _onRenderDepth = 0;

		// --- Render-target death-spiral circuit breaker ---
		// A corrupt render target makes NinjaTrader's EndDraw fail; NT then
		// recreates the RT -> OnRenderTargetChanged -> ECT re-renders -> the
		// fresh RT is corrupted again -> ... a self-sustaining loop that freezes
		// the chart until "Reload NinjaScript". When OnRenderTargetChanged fires
		// far above any normal rate the circuit opens and ECT renders nothing,
		// letting the RT complete a clean EndDraw so the chart self-recovers.
		// Spiral detector: between two render-target recreations a healthy
		// chart renders many frames; a corrupt-RT spiral renders ~none (every
		// EndDraw fails). _onRenderSinceOrtc counts real renders since the last
		// recreation; a run of recreations with <=2 renders between them is the
		// spiral. Rate-independent, so it catches slow spirals too.
		private int  _onRenderSinceOrtc = 0;
		private int  _tightOrtcRun = 0;
		private volatile bool _renderCircuitOpen = false;
		private long _renderCircuitCooldownTicks = 0;
		private bool _renderCircuitLogged = false;

		protected override void OnRender(ChartControl chartControl, ChartScale chartScale)
		{
			// Re-entrancy tripwire + guard. The Direct2D render target is
			// single-threaded and non-re-entrant. If a synchronous repaint
			// (InvalidateVisual -> Control.Update) or a pumped message
			// re-enters OnRender mid-frame, the nested frame double-enters
			// BeginDraw / clip state and corrupts the target -> at EndDraw:
			// D2DERR_WRONG_STATE + D2DERR_PUSH_POP_UNBALANCED -> chart freeze.
			// Skip the nested frame and log the trigger's stack trace.
			int _rDepth = System.Threading.Interlocked.Increment(ref _onRenderDepth);
			try
			{
				if (_rDepth > 1)
				{
					LogDiag("RENDER", "ReentrantOnRender", "depth=" + _rDepth + "\n" + System.Environment.StackTrace);
					return;
				}
				if (_renderCircuitOpen)
				{
					if (System.Diagnostics.Stopwatch.GetTimestamp() < _renderCircuitCooldownTicks)
					{
						if (!_renderCircuitLogged)
						{
							LogDiag("RENDER", "CircuitOpen", "render-target recreation spiral detected -- ECT rendering suspended so the chart can recover; ortcCount=" + _ortcCount);
							_renderCircuitLogged = true;
						}
						return;
					}
					_renderCircuitOpen = false;
					_tightOrtcRun = 0;
					_onRenderSinceOrtc = 0;
					if (_renderCircuitLogged)
					{
						LogDiag("RENDER", "CircuitClosed", "render-target spiral ended -- ECT rendering resumed; ortcCount=" + _ortcCount);
						_renderCircuitLogged = false;
					}
				}
				_onRenderSinceOrtc++;
				OnRenderImpl(chartControl, chartScale);
			}
			finally { System.Threading.Interlocked.Decrement(ref _onRenderDepth); }
		}

		private void OnRenderImpl(ChartControl chartControl, ChartScale chartScale)
		{
			long _perfRNow = System.Diagnostics.Stopwatch.GetTimestamp();
			if (_perfRenderLast != 0) { double _perfRGap = (_perfRNow - _perfRenderLast) * 1000.0 / System.Diagnostics.Stopwatch.Frequency; if (_perfRGap > 1500.0) LogDiag("PERF", "Render_GAP", "GapMs=" + _perfRGap.ToString("F0")); }
			_perfRenderLast = _perfRNow;
			_panelHoverClickableThisFrame = false;
			_renderThreadId = System.Threading.Thread.CurrentThread.ManagedThreadId;
			_renderActive = true;
			// Reset the per-frame D2D-state / checkpoint-timing probe (see RenderTest).
			_d2dProbeTripped = false; _renderTestPrevN = -1; _renderTestPrevTicks = 0;

			// Lazy-register: if State.DataLoaded ran before ChartPanel was ready,
			// panelHash is still 0 and our panel is absent from the shared registry,
			// so its header never draws. Register on the first render instead.
			if (panelHash == 0 && ChartPanel != null)
				RegisterPanel();

			// Lazy-subscribe mouse/keyboard handlers: the DataLoaded subscribe is
			// guarded by `if (ChartControl != null)`, so on workspace restore races
			// the handlers can end up unsubscribed — header renders but isn't
			// hoverable or clickable. Subscribe once, on first render when ready.
			if (!_ectEventHandlersSubscribed && ChartControl != null && ChartPanel != null)
			{
				try
				{
					ChartControl.MouseMove += new MouseEventHandler(OnMouseMove);
					ChartControl.MouseDown += new MouseButtonEventHandler(OnMouseDown);
					ChartControl.MouseUp += new MouseButtonEventHandler(OnMouseUp);
					ChartControl.MouseEnter += new MouseEventHandler(OnMouseEnter);
					ChartControl.MouseLeave += new MouseEventHandler(OnMouseLeave);
					ChartPanel.MouseDoubleClick += new MouseButtonEventHandler(OnMouseDoubleClick);
					ChartPanel.MouseWheel += new MouseWheelEventHandler(OnPanelMouseWheel);
					ChartPanel.ContextMenuOpening += new System.Windows.Controls.ContextMenuEventHandler(OnChartContextMenuOpening);
					ChartControl.PreviewMouseWheel += ChartControl_PreviewMouseWheel;
					ChartControl.PreviewKeyDown += ChartControl_PreviewKeyDown;
					ChartControl.PreviewKeyUp += ChartControl_PreviewKeyUp;
					ChartControl.KeyDown += ChartControl_KeyDown;
					_ectEventHandlersSubscribed = true;
				}
				catch { }
			}

			_lastChartScale = chartScale;

			// Cache DateTime.Now ONCE for the whole frame — every other expiry
			// check / timestamp comparison below reads _frameNow instead of
			// calling DateTime.Now repeatedly (was a syscall hit 10-20× per
			// frame). Sub-second drift across a single OnRender pass is
			// inconsequential for the UI windows it controls (ATM display
			// timer, PC preview expiry, etc.).
			_frameNow = DateTime.Now;

			// Compute the plan-font DPI scale once per frame so DrawPlanOrder
			// (called 10-15× per frame across all plan levels) doesn't repeat
			// the try/catch + division on every call.
			try { _planFontScaleCached = (float)Math.Max(1.0, myProperties.LabelFont.Size / 12.0); }
			catch { _planFontScaleCached = 1f; }

			// Drop the PC hover preview flags once the leave-timer elapses. While
			// the mouse is over Button37/38 the expiry is DateTime.MaxValue, so
			// the flag only clears after MouseLeave sets _frameNow + pShowPlanSeconds333.
			if (IsInPCBuy && _frameNow >= _pcBuyPreviewExpiresAt)
				IsInPCBuy = false;
			if (IsInPCSell && _frameNow >= _pcSellPreviewExpiresAt)
				IsInPCSell = false;

			//if (ReturnAllMain)


			//return;


			//return;



			// added to remove dot from moving orders

			if (IsInHitTest)
				return;

			// Banner guard: only needs RenderTarget + ChartControl, not
			// ThisMasterInstrument (which may be null before DataLoaded runs).
			// Checked BEFORE the main ThisMasterInstrument null-return below.
			if (RenderTarget == null || ChartControl == null)
				return;

			// When unlicensed, draw ONLY the licensing banner and bail. OnBarUpdate
			// bails at !Permission, leaving data-state uninitialized, and
			// CreateWPFOrderControls is also Permission-gated so cached TextFormats
			// and panel state are never built. Without this early return the main
			// draw path below dereferences uninitialized SharpDX resources →
			// AccessViolationException on the first render pass. The banner-only
			// path uses brushes that are created in OnRenderTargetChanged (which is
			// NOT Permission-gated) so it's safe.
			if (!Permission)
			{
				// Lazy-create center TextFormat — normally created further down in
				// OnRender but we skip that path when unlicensed.
				if (cachedCenterTextFormat == null && ChartControl != null
					&& ChartControl.Properties != null && ChartControl.Properties.LabelFont != null)
				{
					try
					{
						cachedCenterTextFormat = new SimpleFont(ChartControl.Properties.LabelFont.Family.ToString(), 16).ToDirectWriteTextFormat();
						cachedCenterTextFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
						cachedCenterTextFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
						cachedCenterTextFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
					}
					catch { }
				}

				// Lazy-create just the brushes we need. CreatePropertyBrushes()
				// depends on ThisChartBackground + GetOutlineColor helpers that
				// aren't ready this early in the indicator lifecycle, so call the
				// minimal ToDxBrush conversions directly.
				if (ChartTextBrushDX == null && ChartControl != null && ChartControl.Properties != null && ChartControl.Properties.ChartText != null)
				{
					try { ChartTextBrushDX = ChartControl.Properties.ChartText.ToDxBrush(RenderTarget); } catch { }
				}
				if (ChartBackgroundBrushDX == null && ChartControl != null && ChartControl.Properties != null && ChartControl.Properties.ChartBackground != null)
				{
					try { ChartBackgroundBrushDX = ChartControl.Properties.ChartBackground.ToDxBrush(RenderTarget); } catch { }
				}
				if (ChartBackgroundErrorBrushDX == null)
				{
					try
					{
						ChartBackgroundErrorBrushDX = Brushes.Red.ToDxBrush(RenderTarget);
						ChartBackgroundErrorBrushDX.Opacity = 25/100f;
					}
					catch { }
				}
				if (cachedDodgerBlue18BrushDX == null)
				{
					try
					{
						cachedDodgerBlue18BrushDX = Brushes.DodgerBlue.ToDxBrush(RenderTarget);
						cachedDodgerBlue18BrushDX.Opacity = 18/100f;
					}
					catch { }
				}

				if (!IsInHitTest
					&& ChartBackgroundBrushDX != null
					&& ChartBackgroundErrorBrushDX != null
					&& ChartTextBrushDX != null
					&& cachedCenterTextFormat != null)
				{
					// Compose banner text. Prefer AllErrorMessages (what AddError
					// populates during LicenseWordPress), fall back to LicensingMessage,
					// and if BOTH are empty (e.g. licensing call not yet run) show a
					// generic prompt so the user never sees a silent empty chart.
					string bannerText = string.Empty;
					if (AllErrorMessages.Count > 0)
					{
						// Was O(n²) string + concat in a loop. Build once via StringBuilder.
						_indicatorNameBuilder.Clear();
						for (int _emi = 0; _emi < AllErrorMessages.Count; _emi++)
							_indicatorNameBuilder.Append(AllErrorMessages[_emi]).Append("\r\n\r\n");
						bannerText = _indicatorNameBuilder.ToString();
					}
					else if (!string.IsNullOrEmpty(LicensingMessage))
					{
						bannerText = LicensingMessage + "\r\n\r\n";
					}
					else
					{
						bannerText = "Hello! You are using software from 'Affordable Indicators, Inc.' on this computer for the first time!\r\n\r\nPlease enter the 'Email Address' connected to your Affordable Indicators, Inc. website account.\r\n\r\nClick now to enter your email address.";
					}
					bannerText = bannerText.TrimEnd();

					var bannerBgError = ChartBackgroundErrorBrushDX;
					if ((bannerText.Contains("Hello!") || bannerText.Contains("NinjaTrader Machine ID") || bannerText.Contains("was not found")) && cachedDodgerBlue18BrushDX != null)
						bannerBgError = cachedDodgerBlue18BrushDX;

					SharpDX.RectangleF bannerRect = new SharpDX.RectangleF(ChartPanel.X, ChartPanel.Y, ChartPanel.W, ChartPanel.H);
					SharpDX.Direct2D1.AntialiasMode prevAA = RenderTarget.AntialiasMode;
					RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.Aliased;

					SafeFillRectangle(bannerRect, ChartBackgroundBrushDX);
					SafeFillRectangle(bannerRect, bannerBgError);
					SafeDrawText(bannerText, cachedCenterTextFormat, ExpandRect(bannerRect, -10, 0), ChartTextBrushDX);

					RenderTarget.AntialiasMode = prevAA;
				}
				return;
			}

			// Licensed path still needs ThisMasterInstrument before touching
			// tick-size / point-value / price math.
			if (ThisMasterInstrument == null)
				return;

			// Clip chart content away from panel zone
			// Panel-zone clip removed: was excluding [0, panelZoneW+8] from chart
			// content drawing while menu was open. With a left Y-axis present,
			// this caused indicator content to extend past the right side of the
			// chart drawable area by exactly the left-axis width (a visible band
			// drawing over the right Y-axis area). The panel's own backdrop is
			// fully opaque and covers indicator content drawn behind it, so the
			// clip was an optimization, not a correctness requirement.
			bool panelClipActive = false;

			CurrentStopRender = 0;

			// Reset all click-mode hit-test rects to zero at the very top of every
			// OnRender BEFORE any draw code that might throw. If a later phase
			// throws and the outer try/catch swallows it, these rects still need
			// to be in a known-good state — otherwise OnMouseDown's hit-test for
			// (e.g.) ClickEntryCancelRect can match a stale rect from a previous
			// successful frame and silently swallow every chart click in
			// click-entry mode (the symptom: "buy/sell click button shows active
			// but clicking the chart does nothing in this window").
			ClickEntryCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);
			IcebergBuyOrderCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);
			IcebergBuyOrderMoveRect = new SharpDX.RectangleF(0, 0, 0, 0);
			IcebergSellOrderCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);
			IcebergSellOrderMoveRect = new SharpDX.RectangleF(0, 0, 0, 0);
			TimeSlicedBuyOrderCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);
			TimeSlicedBuyOrderMoveRect = new SharpDX.RectangleF(0, 0, 0, 0);
			TimeSlicedSellOrderCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);
			TimeSlicedSellOrderMoveRect = new SharpDX.RectangleF(0, 0, 0, 0);

			if (RenderTest(0)) return; // 0

			// Snapshot myAccount.Orders OUTSIDE _accountStateLock. It is
			// NinjaTrader's own collection, guarded by NT's internal lock — our
			// lock gives no protection over it (the copy can still throw if an
			// NT account thread mutates it mid-enumeration, hence the
			// try/catch). Worse, holding _accountStateLock across this
			// enumeration DEADLOCKS the chart: the render thread would hold
			// _accountStateLock and wait on NT's Orders lock, while an NT
			// account thread holds NT's Orders lock and waits on
			// _accountStateLock inside OnOrderUpdate2 — a lock-order inversion.
			// That froze the chart for ~5s of total ECT-log silence after a
			// burst of multi-order clicks. Build into a buffer and swap on
			// success; a failed copy keeps last frame's snapshot rather than a
			// half-filled one. The _render* snapshot fields are read only by
			// the render path (this thread), so no lock is needed to publish
			// them.
			string _ordersSnapErr = null;
			if (myAccount != null)
			{
				try
				{
					_renderOrdersSnapshotBuild.Clear();
					_renderOrdersSnapshotBuild.AddRange(myAccount.Orders);
					var _swapOrders = _renderOrdersSnapshot;
					_renderOrdersSnapshot = _renderOrdersSnapshotBuild;
					_renderOrdersSnapshotBuild = _swapOrders;
				}
				catch (Exception _exOrdersSnap)
				{
					_ordersSnapErr = _exOrdersSnap.Message;
				}
			}
			else
				_renderOrdersSnapshot.Clear();

			// Snapshot the ECT-owned order collections under _accountStateLock.
			// OnOrderUpdate2 fires on many NinjaTrader threadpool threads at
			// once (proven in ECT_*.log: overlapping OOU2_ENTER/OOU2_EXIT
			// across 20+ thread ids) and mutates LinkedOrders / MovingOrders /
			// RRIsOnOrders. Without these snapshots the render path enumerated
			// the live collections, and a concurrent Add/Remove threw mid-frame
			// — a half-drawn frame with an unbalanced Direct2D clip that
			// corrupted the render target (D2DERR_WRONG_STATE) and froze the
			// chart until Reload NinjaScript. The lock spans only these pure
			// in-process List copies — never a NinjaTrader call — so it cannot
			// deadlock.
			lock (_accountStateLock)
			{
				// Rebuild the HashSet mirror of LinkedOrders once per frame so the
				// per-entry-order render loop can do O(1) Contains checks instead
				// of O(n) List.Contains.
				_linkedOrdersSetCache.Clear();
				for (int _li = 0; _li < LinkedOrders.Count; _li++)
				{
					var _lo = LinkedOrders[_li];
					if (_lo != null) _linkedOrdersSetCache.Add(_lo);
				}

				_renderMovingOrdersSnapshot.Clear();
				for (int _mi = 0; _mi < MovingOrders.Count; _mi++)
					_renderMovingOrdersSnapshot.Add(MovingOrders[_mi]);

				_renderRRIsOnOrdersSnapshot.Clear();
				for (int _ri = 0; _ri < RRIsOnOrders.Count; _ri++)
					_renderRRIsOnOrdersSnapshot.Add(RRIsOnOrders[_ri]);

				// DIAGNOSTIC (RenderDiagMode == 1): neutralize the order-moving
				// state for this whole frame so every moving-order-specific
				// render path behaves as if nothing is being moved. Restored at
				// the end of OnRender. If the click-an-order freeze stops while
				// this is on, the corruption is in the moving-order draw path.
				_diagMovingNeutralized = false;
				if (pRenderDiagMode == 1 && (MovingOrder != null || MovingOrders.Count > 0))
				{
					_diagSavedMovingOrder = MovingOrder;
					_diagSavedMovingOrders.Clear();
					_diagSavedMovingOrders.AddRange(MovingOrders);
					MovingOrder = null;
					MovingOrders.Clear();
					_renderMovingOrdersSnapshot.Clear();
					_diagMovingNeutralized = true;
				}
			}
			if (_ordersSnapErr != null)
				LogDiag("RENDER", "OrdersSnapshotSkipped", _ordersSnapErr);

			//Print("OnRender: " + DateTime.Now + " " + CurrentBar);
	
//			if (MouseWheelDone)
//			{
				
//				chartScale.Properties.YAxisRangeType = YAxisRangeType.Automatic;	
			
//				MouseWheelDone = false;
//			}
			
		
			
			
			
			// main try
			
			try  	
			{ 
			
			
					
												
			
			
				
//				if (!Permission)
//					return;
				
				try  
				{ 
					
					//if(Bars == null || ThisMasterInstrument == null || IsInHitTest || CurrentBar < 0 || !isActiveTab(chartControl))
//					{ 
//						return;
//					}
				
					
					
				}
				catch (Exception ex)
				{
					LogDiag("RENDER", "Start", ex.ToString()); if (TestRender) Print("OnRenderStart: " + ThisMasterInstrument.Name + " " + ex.Message + " " + DateTime.Now.ToString("T"));
					
