						// SelectedAtmStrategy==null (ATM not yet populated) and gets dropped
						// by the inner gate in the AddNextOrder render block; meanwhile
						// ShowPlan already set AddNextOrder=true. Without this guard the
						// FirstATMLoader pass immediately flips AddNextOrder back to false,
						// the second frame also skips, and the user's first hover produces
						// no visible preview. Preserve AddNextOrder when a sentinel preview
						// key (10/-10/11/-11/12/-12/13/-13) is present in the display dict.
						bool hasPendingSentinel = false;
						foreach (double _k in OrderPriceToATMDisplayEnd.Keys)
