			// "Width (Pixels)" (pMoveOrdersNewLeft) is the distance from the
			// right edge of the chart to the right edge of the order-flag stack.
			// A large value pushes flags further left; on a narrow chart window
			// that can push the entire flag off the left side of the chart and
			// the user can no longer see order details, cancel buttons, etc.
			//
			// Treat the user's value as a MAXIMUM and automatically clamp it
			// down so the flag content always has a reasonable body budget on
			// the left side. We guarantee at least `minFlagBudget` pixels of
			// room to the left of the flag's right edge, where minFlagBudget
			// scales with chart width but is bounded to a sane range. That way:
			//   * On a wide chart, effective == user value (no change).
			//   * On a narrow chart, effective drops below the user value so
			//     the flag body stays visible.
			{
				int chartW = ChartPanel != null ? ChartPanel.W : 0;
				if (chartW <= 0)
				{
					effectiveMoveOrdersNewLeft = pMoveOrdersNewLeft;
				}
				else
				{
					// Minimum body budget for the flag stack: 30% of chart width,
					// clamped to [140, 320] px. 140 keeps the quantity + type
					// label readable on very small charts; 320 prevents giving
					// more room than a reasonable flag would ever use.
					int minFlagBudget = (int)(chartW * 0.30f);
					if (minFlagBudget < 140) minFlagBudget = 140;
					if (minFlagBudget > 320) minFlagBudget = 320;

					int maxLeft = chartW - minFlagBudget - maininitialspace;
					if (maxLeft < 0) maxLeft = 0;

					effectiveMoveOrdersNewLeft = pMoveOrdersNewLeft < maxLeft
						? pMoveOrdersNewLeft
						: maxLeft;
				}
			}

			// Per-render reset of ATM plan Y-axis flag slots.
			//
			// DrawPlanOrder allocates plot indices from the top of the Values[]
			// array (counting DOWN from Values.Length - 1) so ATM plan levels
			// don't collide with the live-order plots that grow upward from
			// plot 25 in SetOrderFlags.
			//
			// Clearing must happen UNCONDITIONALLY every render — not inside
			// SetOrderFlags() (which has early-return guards on `myAccount`
			// and `pScaleByOrders`) and not inside the plan draw loop (which
			// only runs when the user has an in-progress plan). Otherwise a
			// plan that existed last frame but not this frame would leave
			// stale Y-axis flags until something else happened to reset them.
			//
			// We only clear the slots that were actually written by
			// DrawPlanOrder in the previous frame (tracked via
			// atmPlanPlotLastLow). That avoids blowing away any live-order
			// plot slots that happen to sit above Values.Length - 40 in the
			// rare case of many simultaneous live orders.
			{
				int topSlot = Values.Length - 1;
				if (atmPlanPlotLastLow <= topSlot)
				{
					int clearFrom = topSlot;
					int clearTo = atmPlanPlotLastLow;
					if (clearTo < 25) clearTo = 25;
					for (int i = clearFrom; i >= clearTo; i--)
					{
						try
						{
							PlotBrushes[i].Reset();
							Values[i].Reset(0);
						}
						catch { /* plot may not be fully initialized yet */ }
					}
				}
				atmPlanPlotCursor = topSlot;
				atmPlanPlotLastLow = int.MaxValue; // will be updated as DrawPlanOrder runs
			}

			// Unified hit-test resolver pre-pass — decide which HitCategory
			// owns the cursor this frame. Drives HOVER GLOW gating via
			// HoverIsOrderOrHigher() — see DrawPlanOrder at :73175 and
			// :73587. See the big comment block at the field declaration
			// (around line 980) for the full architecture.
			//
			// NOTE: click paths (in OnMouseDown) do NOT read this field.
			// An earlier attempt to centralize click priority through the
			// resolver broke regular order-move and qty click handlers
			// because the resolver runs once per frame and OnMouseDown
			// handlers expected fresh inline state. OnMouseDown uses small
			// local bool checks (like clickNearOrderMove in the ATM plan
			// line loop) when it needs priority enforcement. The resolver
			// stays authoritative for hover glow; clicks use direct geometry.
			//
			// Runs from the last-populated hit-test dicts (previous frame's
			// AllOrderMoveButtons, etc.) because mouse position is stable
			// between OnMouseMove calls so last-frame spatial data is still
			// accurate for the current cursor.
			resolvedHoverCategory = ResolveHoverCategory();

			// Any resolved hover above Background (order flag, plan line, button, etc.)
			// is clickable-or-draggable from the user's perspective — show a hand cursor.
			if (resolvedHoverCategory != HitCategory.None && resolvedHoverCategory != HitCategory.Background)
				_hoverClickableThisFrame = true;

			// Live-order takeover of an active hover preview. When a sentinel /
			// PC hover preview is currently showing (from one of the 5 hover
			// sources: Market / Limit / Close Bar / Signal / Price-Based) AND
			// the cursor is now over a live order's flag, hide the preview and
			// refresh the order's own plan timer so the user transitions from
			// preview to that order's ATM plan in a single motion. Only fires
			// when a preview is actually active — normal flag hover behavior
			// (no preview to swap from) is untouched.
			if (resolvedHoverCategory == HitCategory.FlagBody && resolvedHoverTarget is OrderDetails)
			{
				// PC flag check is O(1) and the most common preview source while
				// hovering a chart entry button — short-circuit before scanning
				// the (potentially large) OrderPriceToATMDisplayEnd dict for
				// sentinel keys. Hoist DateTime.Now out of the loop too. Only
				// scans when there is at least one entry AND PC isn't already
				// active. Common case: zero foreach iterations per frame.
				bool pcActive = IsInPCBuy || IsInPCSell;
				bool sentinelActive = false;
				if (!pcActive && OrderPriceToATMDisplayEnd.Count > 0)
				{
					DateTime nowSnap = DateTime.Now;
					foreach (KeyValuePair<double, DateTime> kvp in OrderPriceToATMDisplayEnd)
					{
						double k = kvp.Key;
						if (k >= -13 && k <= 13 && k == Math.Truncate(k) && kvp.Value > nowSnap)
						{
							sentinelActive = true;
							break;
						}
					}
				}

				if (sentinelActive || pcActive)
				{
					OrderDetails od = resolvedHoverTarget as OrderDetails;
					Order targetOrd = od != null ? od.ThisOrder : null;
					if (targetOrd != null)
					{
						double targetPrice = targetOrd.LimitPrice;
						if (targetOrd.OrderType == OrderType.StopMarket
							|| targetOrd.OrderType == OrderType.StopLimit
							|| targetOrd.OrderType == OrderType.MIT
							|| (targetOrd.StopPrice != 0 && targetOrd.OrderState == OrderState.TriggerPending))
							targetPrice = targetOrd.StopPrice;

						if (targetPrice != 0)
						{
							// Drop sentinel + PC state so nothing competes with
							// the live-order plan AddATMPlanEntry registers below.
							RemoveAllPlanSentinels();
							IsInPCBuy = false;
							IsInPCSell = false;
							_pcBuyPreviewExpiresAt = DateTime.MinValue;
							_pcSellPreviewExpiresAt = DateTime.MinValue;
							_previewEntryTypeOverride = "";

							AddATMPlanEntry(targetPrice, pShowPlanSeconds333);
						}
					}
				}
			}

