			            if (movingOr.OrderType == OrderType.StopMarket || movingOr.OrderType == OrderType.StopLimit || movingOr.OrderType == OrderType.MIT
			                || (movingOr.OrderType == OrderType.Market && movingOr.OrderState == OrderState.TriggerPending))
			            {
			                movingPrice = movingOr.StopPrice;
			            }
			            else if (movingOr.OrderType == OrderType.Limit)
			            {
			                movingPrice = movingOr.LimitPrice;
			            }
			            
			            if (movingPrice != 0 && !excludedPrices.Contains(movingPrice))
			                excludedPrices.Add(movingPrice);
			        }
			    }
			    
