			        if (MovingOrder.OrderType == OrderType.StopMarket || MovingOrder.OrderType == OrderType.StopLimit || MovingOrder.OrderType == OrderType.MIT
			            || (MovingOrder.OrderType == OrderType.Market && MovingOrder.OrderState == OrderState.TriggerPending))
			        {
