			           // Print("HoveredPriceLevel" + priceLevel);
			           
			            HoveredPriceLevel = priceLevel;
			            CurrentMousePrice = RTTS(HoveredPriceLevel);
			            IsMouseNearPriceLevel = true;
			            break; // Found one, exit loop
			        }
			    }									
			}
						
						
			
			
			
			// Snap during ATM plan stop/target moves. Mirrors the live-order
			// snap above but uses Z.LinePrice from the line drag rects in
			// AllATMStrategyLevelButtons. Filtered to Priority == PLAN_LINE
			// (line drag rects only — skip toggle chips whose Y center is
			// offset above their parent line). Uses Z.LinePrice directly
			// for the snap target so the click finalizes at exactly the
			// snap target's price — no half-tick reverse-mapping error.
			//
			// Identity-based exclusion: the moving line is RE-REGISTERED in
			// AllATMStrategyLevelButtons each render frame with a fresh Z at
			// its new price. MovingATMOrders holds the Z reference from the
			// click frame. Match by (Name, ATM ref, Order ref) so the moving
			// line is excluded regardless of where it's drawn this frame.
			//
			// No string-key allocation: the previous version built "Name|atmId|
			// ordId" strings (one per moving Z + one per candidate Z) and
			// hashed them every snap frame — 50+ allocations per drag frame.
			// Direct ReferenceEquals over MovingATMOrders is O(M*N) where M is
			// tiny (1-3 moving Zs) and N is the candidate count, so the inner
			// loop is cheaper than the string hashing it replaced.
			if (pSnapOrdersPixels > 0 && MovingATMOrders != null && MovingATMOrders.Count > 0
				&& _lastChartScale != null)
			{
				int movingCount = MovingATMOrders.Count;
				foreach (var kv in AllATMStrategyLevelButtons)
				{
					var Z = kv.Value;
					if (Z == null) continue;
					if (Z.Priority != HIT_PRIORITY_PLAN_LINE) continue;
					if (Z.LinePrice <= 0) continue;

					// Restrict snap targets to OTHER stops / targets in the same
					// plan. The entry line is always present on a plan, and
					// snapping to it during a stop/target drag isn't what the
					// user thinks of as "snap to nearby line" — it just
					// interferes with placing a stop near the entry. Stop-strategy
					// markers (SS_*) are already filtered out by the PLAN_LINE
					// priority check above (they use SS_MARKER priority).
					string nm = Z.Name;
					if (nm == null) continue;
					if (!nm.StartsWith("Stop") && !nm.StartsWith("Target")) continue;

					// Identity exclusion — match the moving line(s) by Name +
					// ATM ref + Order ref. Use ReferenceEquals so two distinct
					// AtmStrategy instances with identical contents still hash
					// differently.
					bool excluded = false;
					for (int mi = 0; mi < movingCount; mi++)
					{
						var movingZ = MovingATMOrders[mi];
						if (movingZ == null) continue;
						if (movingZ.Name != nm) continue;
						if (!object.ReferenceEquals(movingZ.ThisATM, Z.ThisATM)) continue;
						if (!object.ReferenceEquals(movingZ.ThisOrder, Z.ThisOrder)) continue;
						excluded = true;
						break;
					}
					if (excluded) continue;

					double linePixelY;
					try { linePixelY = _lastChartScale.GetYByValue(Z.LinePrice); }
					catch { continue; }

					if (Math.Abs(FinalYPixel - linePixelY) <= pSnapOrdersPixels)
					{
						CurrentMousePrice = RTTS(Z.LinePrice);
						break;
					}
				}
			}


