													KKK.Value == expectExact ||
													KKK.Value.StartsWith(expectComboLo) ||
													KKK.Value.EndsWith(expectComboHi);

												if (nameMatch)
													stopticks = KKK.Key;

												//Print(stopticks);
											}




											if (StopTicksToName.Count == 1)
											{
												//int ticks = StopTicksToName[

											}



											newstoppoints = RTTS(ThisPrice - ThisEntry)*mu;
											newstopticks = (int) Math.Round(newstoppoints/ThisTickSize,0);

											//if (TargetTicksToQty.ContainsKey(ATMStrategyMovingName))
											thisqtyyy = ATMMovingQ;


											//Print(rrrr + " = " + newstopticks + " / " + stopticks);

											// Guard against zero stopticks (degenerate ATM) before dividing
											if (pRiskRewardEnabled && stopticks > 0)
												rrrr = newstopticks / stopticks;

											FillTargetTicks = Math.Max(FillTargetTicks, newstopticks);
											
										}
		
										
										
					
										// start contracts calculate
									
														
								
										
											//Print(newstoppoints);
											finalamount = ThisTickDollars * newstopticks * thisqtyyy;
										
											valuedisp = newstopticks.ToString();
											valuelab = @" t";
										
											if (pPreviewDisplayMode == "Points")
											{
												points = RTTS(newstopticks * TickSize);
												valuedisp = points.ToString();
												valuelab = @" p";
											}
										
											valuelab = "";
											
											
											sss = string.Empty;
											//sss = " (" + thisqtyyy.ToString() + ") ";

											//if (pPlanDetailsName) sss = KKK.Value.ToString() + valuesep;

											if (pPlanDetailsName) sss = ATMStrategyMovingName + valuesep;

											if (pPlanDetailsUnits) sss = sss + valuedisp + valuelab;// + " Ticks";
											if (pPlanDetailsUnits && pPlanDetailsCurrency) sss = sss + valuesep;
											if (pPlanDetailsCurrency)
											{
												//sss = sss + "$" + Math.Round(finalamount, 2).ToString() + "";


												sss = sss + GetDollarString("$",Math.Round(finalamount, 2));
												sss = sss.Replace(".00", "");

											}

											// "~ " prefix: this target/stop is the one currently
											// being moved (click-move-click phase). Matches the
											// stop-strategy marker convention.
											sss = "~ " + sss;

											// "[MAX] " prefix when the position-sizing risk cap
											// has been hit during this drag — visual cue that the
											// stop won't move further until the user relaxes the
											// cap or accepts a smaller quantity.
											if (stopAtMaxCap) sss = "[MAX] " + sss;


											//MovingATM.stop

											MovingStopTicks = newstopticks;
											MovingStopNewOrderQty = thisqtyyy;
											
											
											//ThisBrushDX = Brushes.Red.ToDxBrush(RenderTarget);
											if (ATMStrategyMovingName.Contains("Target"))
												ThisStroke = pBarUpOutlineStroke;
											else
											
												ThisStroke = pBarDnOutlineStroke;
											
											DrawPlanOrder (chartControl, chartScale, ThisStroke, ThisPrice, ThisEntry, sss, thisqtyyy.ToString(), rrrr, EEE.ATMS, EEE.ThisOrder, "", EEE.Switch);	
										
											 
											
									}
									
									break;
									
									
								
								
							}
							
							


					//Print(movingstopticks);

							// Build per-bracket default tick sets for this plan's ATM so each
							// target/stop line can decide on its own whether it's been modified
							// from the saved default template. Null-safe: if we can't resolve
							// the default (e.g., DefaultAtmStrategy doesn't have this name),
							// the lists stay empty and per-line dirty detection falls back to
							// "not dirty". Built once per plan render, not per-line.
							BracketDefaultLines planDefaultLines = null;
							try { planDefaultLines = GetBracketDefaultLines(EEE.ATMS); } catch { }

							// pMarketPlanActive is a global (whole-ATM) modifier — it applies
							// the same "* " prefix to every line regardless of template match.
							bool planMarketPlanOverride = pMarketPlanActive;

							// all targets



							foreach (KeyValuePair<double, string> KKK in TargetTicksToName)
							{
									thisqtyyy = TargetTicksToQty[KKK.Key];
								
								int finalticks = (int) KKK.Key;
			
								double rrrr = 0;
								
									if (pRiskRewardEnabled)
									{
										rrrr = TargetTicksToRR.ContainsKey(finalticks) ? TargetTicksToRR[finalticks] : 0;
									
									
									//double rrrr = TargetTicksNow / StopTicksNow;
									
									// when moving stop loss adjusttarget  display
									

										
										
										string name222 = KKK.Value;
										//Print(name222);

										name222 = name222.Replace("Target ", "");
										//name222 = KKK.Value.Replace("Stop ", "");




										// Build exact-match tokens so "Target 3" matches "Stop 3" or
										// "Stop 3/4" or "Stop 1/3" but NOT "Stop 13". Previously a
										// naive Contains() caused cross-coupling on ATMs with 10+
										// brackets, but the original tokenized version only checked
										// First-in-list (Lo) and Last-in-list (Hi) positions —
										// it missed the MIDDLE of a 3-or-more merged group, so
										// Target 2 didn't follow when dragging "Stop 1/2/3" during
										// preview (the click-finalize path uses different matching
										// and worked correctly, which is why the final landing
										// price was right but the preview lagged).
										string expectExact    = "Stop " + name222;
										string expectComboLo  = "Stop " + name222 + "/";
										string expectComboHi  = "/" + name222;
										string expectComboMid = "/" + name222 + "/";

										foreach (KeyValuePair<string, double> KKK33 in AllMovingStopTicks)
										{
											bool isStopLoss = KKK33.Key == "Stop Loss";
											bool nameMatch =
												isStopLoss ||
												KKK33.Key == expectExact ||
												KKK33.Key.StartsWith(expectComboLo) ||
												KKK33.Key.EndsWith(expectComboHi) ||
												KKK33.Key.Contains(expectComboMid);

											//Print(KKK33.Key);
											if (pRiskRewardPlanIsEnabled && pRiskRewardEnabled)
											{
												// change target as stop is moving with risk reward lock enabled
												if (nameMatch && KKK33.Value > 0)
													finalticks = (int) (rrrr * KKK33.Value);
											}
											else
											{
												// change risk reward as stop is moved
												if (nameMatch && KKK33.Value > 0)
													rrrr = finalticks / KKK33.Value;
											}
//											Print(KKK33.Key);
//											Print(KKK33.Value);
										}
											
									
								
									
											
//										if (AllMovingStopTicks.ContainsKey(name222))
//											rrrr = KKK.Key / AllMovingStopTicks[name222];
									}
									
								
									FillTargetTicks = Math.Max(FillTargetTicks, (int)finalticks);
									
									
								
									//Print("asf" + thisqtyyy);
								
									//thisqtyyy = 1;
								
								
								
								
								
								
								
									finalamount = ThisTickDollars * finalticks * thisqtyyy;
								
								
								 
									valuedisp = finalticks.ToString();
									valuelab = @" t";
								
									if (pPreviewDisplayMode == "Points")
									{
										points = RTTS(finalticks * TickSize);
										valuedisp = points.ToString();
										valuelab = @" p";
									}
								
									valuelab = "";
									
//									if (ATMStrategyMovingName ==  KKK.Value.ToString())
//										MovingNameQty = thisqtyyy;
									
									sss = string.Empty;
									//sss = " (" + thisqtyyy.ToString() + ") ";
								
						
									
									if (pPlanDetailsName) sss = KKK.Value.ToString() + valuesep;
									if (pPlanDetailsUnits) sss = sss + valuedisp + valuelab;// + " Ticks";
									if (pPlanDetailsUnits && pPlanDetailsCurrency) sss = sss + valuesep;
									if (pPlanDetailsCurrency)
									{
										//sss = sss + "$" + Math.Round(finalamount, 2).ToString() + "";

										sss = sss + GetDollarString("$",Math.Round(finalamount, 2));
										sss = sss.Replace(".00", "");
									}

								//	sss = sss + " | " + rrrr;

									// Per-line dirty detection: compare THIS target's current
									// tick distance against the default template's corresponding
									// bracket. If they differ, OR pMarketPlanActive is true, show
									// a "* " prefix. Skips cleanly if the default lines couldn't
									// be resolved (e.g., Free Edition, dynamic ATMs).
									bool thisTargetDirty = false;
									if (planMarketPlanOverride)
									{
										thisTargetDirty = true;
									}
									else if (planDefaultLines != null && planDefaultLines.TargetTicks.Count > 0)
									{
										int bi = ParseBracketIdxFromLineName(KKK.Value);
										if (bi >= 0 && bi < planDefaultLines.TargetTicks.Count)
										{
											double defTicks = planDefaultLines.TargetTicks[bi];
											if (defTicks > 0 && (int)defTicks != finalticks)
												thisTargetDirty = true;
										}
									}
									if (thisTargetDirty) sss = "* " + sss;


									ThisPrice = RTTS(ThisEntry + mu*finalticks*ThisTickSize);

									//ThisBrushDX = Brushes.Green.ToDxBrush(RenderTarget);
									ThisStroke = pBarUpOutlineStroke;
									DrawPlanOrder (chartControl, chartScale, ThisStroke, ThisPrice, ThisEntry, sss, thisqtyyy.ToString(), rrrr, EEE.ATMS, EEE.ThisOrder, KKK.Value.ToString(), EEE.Switch);

							}

							// all stops
							
							foreach (KeyValuePair<double, string> KKK in StopTicksToName)
							{
									thisqtyyy = StopTicksToQty[KKK.Key];	
								
									FillStopTicks = Math.Max(FillStopTicks, (int)KKK.Key);

									// In H/L mode, use actual H/L distance for display instead of bracket ticks.
									// As long as the entry is at least 1 tick beyond the H/L swing, snap to the
									// configured minimum when the raw H/L distance is smaller than it.
									double displayStopTicks = KKK.Key;
									if (pInitialExitsType == "High / Low")
									{
										double hlSPD = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? InitialHLLowestLow : InitialHLHighestHigh;
										bool wrongSideD = (mu == 1 && hlSPD >= ThisEntry) || (mu == -1 && hlSPD <= ThisEntry);
										if (!wrongSideD && hlSPD > 0)
										{
											double rawHLTicks = Math.Round(Math.Abs(ThisEntry - hlSPD) / ThisTickSize, 0);
											if (pInitialExitHLMinStopTicks > 0 && rawHLTicks >= 1 && rawHLTicks < pInitialExitHLMinStopTicks)
												displayStopTicks = pInitialExitHLMinStopTicks; // snap to minimum
											else
												displayStopTicks = rawHLTicks;
										}
									}

									finalamount = ThisTickDollars * displayStopTicks * thisqtyyy;

									valuedisp = displayStopTicks.ToString();
									valuelab = @" t";

									if (pPreviewDisplayMode == "Points")
									{
										points = RTTS(displayStopTicks * TickSize);
										valuedisp = points.ToString();
										valuelab = @" p";
									}
								
									valuelab = "";
									
									
									sss = string.Empty;
									//sss = " (" + thisqtyyy.ToString() + ") ";
								
									if (pPlanDetailsName) sss = KKK.Value.ToString() + valuesep;
									if (pPlanDetailsUnits) sss = sss + valuedisp + valuelab;// + " Ticks";
									if (pPlanDetailsUnits && pPlanDetailsCurrency) sss = sss + valuesep;
									if (pPlanDetailsCurrency)
									{
										//sss = sss + "$" + Math.Round(finalamount, 2).ToString() + "";	
										
										
										sss = sss + GetDollarString("$",Math.Round(finalamount, 2));
										sss = sss.Replace(".00", "");

									}

									//if (pPlanDetailsCurrency) sss = sss + " ($" + Math.Round(finalamount, 0).ToString() + ")";

									// Per-line dirty detection for stops. A stop line is dirty if:
									//   - pMarketPlanActive (whole-ATM override), OR
									//   - This stop's current tick distance differs from the
									//     default template's stop for the same bracket, OR
									//   - There's a stop-strategy draft for this bracket (Auto BE,
									//     trail steps) — the stop's behavior is no longer default.
									bool thisStopDirty = false;
									if (planMarketPlanOverride)
									{
										thisStopDirty = true;
									}
									else
									{
										int bi = ParseBracketIdxFromLineName(KKK.Value);

										// Compare tick distance against default template.
										if (planDefaultLines != null && planDefaultLines.StopTicks.Count > 0 && bi >= 0 && bi < planDefaultLines.StopTicks.Count)
										{
											double defTicks = planDefaultLines.StopTicks[bi];
											if (defTicks > 0 && (int)defTicks != (int)KKK.Key)
												thisStopDirty = true;
										}

										// Check for a stop-strategy draft on this bracket.
										if (!thisStopDirty && bi >= 0)
										{
											var d = TryGetDraft(EEE.ATMS, bi);
											if (d != null && (d.AutoBEProfitTrigger.HasValue || d.AutoBEPlus.HasValue || d.TrailStepOverrides != null))
												thisStopDirty = true;
										}

										// "Stop Loss" merged label (all brackets share one stop).
										// Dirty if ANY bracket's stop ticks differ from default or
										// has a draft.
										if (!thisStopDirty && bi < 0 && KKK.Value == "Stop Loss")
										{
											if (planDefaultLines != null)
											{
												for (int j = 0; j < planDefaultLines.StopTicks.Count; j++)
												{
													double defTicks = planDefaultLines.StopTicks[j];
													if (defTicks > 0 && (int)defTicks != (int)KKK.Key)
													{
														thisStopDirty = true;
														break;
													}
												}
											}
											if (!thisStopDirty && EEE.ATMS != null && EEE.ATMS.Brackets != null)
											{
												for (int j = 0; j < EEE.ATMS.Brackets.Length; j++)
												{
													var d = TryGetDraft(EEE.ATMS, j);
													if (d != null && (d.AutoBEProfitTrigger.HasValue || d.AutoBEPlus.HasValue || d.TrailStepOverrides != null))
													{
														thisStopDirty = true;
														break;
													}
												}
											}
										}
									}
									if (thisStopDirty) sss = "* " + sss;


									// In H/L mode, lock stop at fixed H/L price; if the raw H/L distance
									// is below the configured minimum (entry at least 1 tick beyond the
									// swing), snap the render to entry − mu*min*tickSize instead.
									// Wrong-side entries fall back to the bracket's own stop ticks.
									if (pInitialExitsType == "High / Low")
									{
										double hlSP = (pLastPlanDirection == "Long" || pLastPlanDirection == "") ? InitialHLLowestLow : InitialHLHighestHigh;
										bool wrongSide2 = (mu == 1 && hlSP >= ThisEntry) || (mu == -1 && hlSP <= ThisEntry);
										double rawHLTicks2 = (hlSP > 0) ? Math.Round(Math.Abs(ThisEntry - hlSP) / ThisTickSize, 0) : 0;
										bool minEngaged = pInitialExitHLMinStopTicks > 0 && rawHLTicks2 >= 1 && rawHLTicks2 < pInitialExitHLMinStopTicks;
										if (wrongSide2 || hlSP <= 0)
											ThisPrice = RTTS(ThisEntry - mu*KKK.Key*ThisTickSize);
										else if (minEngaged)
											ThisPrice = RTTS(ThisEntry - mu * pInitialExitHLMinStopTicks * ThisTickSize);
										else
											ThisPrice = RTTS(hlSP);
									}
									else
									{
										ThisPrice = RTTS(ThisEntry - mu*KKK.Key*ThisTickSize);
									}

									//ThisBrushDX = Brushes.Red.ToDxBrush(RenderTarget);
									ThisStroke = pBarDnOutlineStroke;
									DrawPlanOrder (chartControl, chartScale, ThisStroke, ThisPrice, ThisEntry, sss, thisqtyyy.ToString(), 0, EEE.ATMS, EEE.ThisOrder, KKK.Value.ToString(), EEE.Switch);






							}


							// === Stop-strategy planning markers ===
							// All settings are READ from the selected ATM strategy's StopStrategy
							// (Auto Breakeven, Auto Trail steps, Simulated stop). The ECT indicator
							// no longer customizes any of these via its own properties — it visualizes
							// what NT8 has configured, and overlays any per-trade draft modifications.
							//
							// Multi-target behavior: each Bracket in NT8 can have its own StopStrategy.
							// To avoid clutter when there are several targets, we only render the
							// stop-strategy markers when a single bracket is being considered:
							//   - 1 bracket  → always show that bracket's markers
							//   - N brackets → only show markers for whichever target the mouse is
							//                   currently hovering over (returns -1 = show none)
							//
							// Wrap the entire block in try/catch so any reflection / brush failure
							// cannot abort OnRender (which would leave the click-entry hit rects
							// un-rebuilt and cause buy/sell click to lock to the top of the chart).
							try
							{
								// Master switch — when disabled, skip ALL Stop Strategy
								// rendering (Auto BE / Trail / Sim markers + H/L swing
								// bar outline). Click and wheel handlers are also gated
								// on this property elsewhere.
								if (pStopStrategyManagementDisabled)
									goto SkipStopStrategyBlock;

								Stroke stopStratStroke = GetStopStrategyStrokeSafe();

								int bracketCount = (EEE.ATMS != null && EEE.ATMS.Brackets != null) ? EEE.ATMS.Brackets.Length : 0;

								// Decide which bracket index to render markers for (-1 = none).
								int renderBracketIdx = -1;
								if (bracketCount == 1)
								{
									renderBracketIdx = 0;
								}
								else if (bracketCount > 1)
								{
									renderBracketIdx = GetHoveredTargetBracketIdx();
								}

								// If a move is in progress for THIS atm+bracket, pin the marker
								// bracket so the marker the user is dragging doesn't disappear
								// when they move off the target label.
								if (_movingStopStrategyItem != null
									&& _movingStopStrategyItem.Atm == EEE.ATMS)
								{
									renderBracketIdx = _movingStopStrategyItem.BracketIdx;
								}

								AtmStopStrategyInfo ssInfo = (stopStratStroke != null && renderBracketIdx >= 0)
									? ReadAtmStopStrategyInfo(EEE.ATMS, renderBracketIdx)
									: null;

								if (stopStratStroke != null && ssInfo != null)
								{
									// Tag any draft-overridden values with a leading asterisk so the
									// user can tell at a glance that they've adjusted something.
									string draftMark = ssInfo.HasDraftOverride ? "* " : "";

									// Prefix with bracket number when there's more than one bracket
									// so it's clear which target's stop strategy is being shown.
									string bracketTag = (bracketCount > 1)
										? ("T" + (renderBracketIdx + 1).ToString() + "  ")
										: "";

									// Detect whether any marker is in its move phase. Used to
									// pull the trigger ticks from the mouse position instead of
									// the stored value.
									bool moveActive = _movingStopStrategyItem != null
										&& _movingStopStrategyItem.Atm == EEE.ATMS
										&& _movingStopStrategyItem.BracketIdx == renderBracketIdx;

									// --- Auto Breakeven marker ---
									if (ssInfo.HasAutoBE)
									{
										int beTicks = ssInfo.AutoBEProfitTrigger;
										string liveMark = "";
										if (moveActive && _movingStopStrategyItem.Kind == MoveKind.AutoBETrigger)
										{
											beTicks = MouseToProfitTicks(ThisEntry, mu);
											liveMark = "~ "; // visual cue that this value is being moved
										}

										double bePrice = RTTS(ThisEntry + mu * beTicks * ThisTickSize);
										string beLabel = bracketTag + liveMark + draftMark + "Auto BE  @ +" + beTicks.ToString() + "t";
										if (ssInfo.AutoBEPlus != 0)
											beLabel += "  →  " + (ssInfo.AutoBEPlus >= 0 ? "+" : "") + ssInfo.AutoBEPlus.ToString() + "t";

										double beY = chartScale.GetYByValue(bePrice);
										if (beY >= 0 && beY <= ChartPanel.H)
										{
											ThisStroke = stopStratStroke;
											// Hit-rect name: "SS_BE_<bracketIdx>". OnMouseDown /
											// OnMouseWheel parse this to route clicks and wheel events.
											DrawPlanOrder(chartControl, chartScale, ThisStroke, bePrice, ThisEntry, beLabel, "BE", 0, EEE.ATMS, EEE.ThisOrder, "SS_BE_" + renderBracketIdx, EEE.Switch);
										}
									}

									// --- Auto Trail step markers ---
									if (ssInfo.HasAutoTrail)
									{
										int stepIdx = 1; // 1-based for label, 0-based for draft/hit-rect
										foreach (var step in ssInfo.AutoTrailSteps)
										{
											int stepIdx0 = stepIdx - 1;
											int triggerTicks = step.ProfitTrigger;
											string liveMark = "";

											// Override trigger with mouse price if this is the
											// marker currently being moved.
											if (moveActive
												&& _movingStopStrategyItem.Kind == MoveKind.TrailStepTrigger
												&& _movingStopStrategyItem.StepIdx == stepIdx0)
											{
												triggerTicks = MouseToProfitTicks(ThisEntry, mu);
												liveMark = "~ ";
											}

											if (triggerTicks <= 0) { stepIdx++; continue; }

											double stepPrice = RTTS(ThisEntry + mu * triggerTicks * ThisTickSize);
											string stepLabel = bracketTag + liveMark + draftMark + "Trail " + stepIdx.ToString()
												+ "  @ +" + triggerTicks.ToString() + "t"
												+ "  SL " + step.StopLoss.ToString() + "t"
												+ "  Freq " + step.Frequency.ToString() + "t";

											double stepY = chartScale.GetYByValue(stepPrice);
											if (stepY >= 0 && stepY <= ChartPanel.H)
											{
												ThisStroke = stopStratStroke;
												// Hit-rect name: "SS_Trail_<bracketIdx>_<stepIdx0>".
												DrawPlanOrder(chartControl, chartScale, ThisStroke, stepPrice, ThisEntry, stepLabel, "Trail" + stepIdx, 0, EEE.ATMS, EEE.ThisOrder, "SS_Trail_" + renderBracketIdx + "_" + stepIdx0, EEE.Switch);
											}
											stepIdx++;
										}
									}

									// --- Simulated stop indicator ---
									if (ssInfo.HasSimulatedStop)
									{
										string simLabel = bracketTag + "Sim Stop  vol " + ssInfo.SimulatedStopVolume.ToString();
										double simPrice = ThisEntry;
										double simY = chartScale.GetYByValue(simPrice);
										if (simY >= 0 && simY <= ChartPanel.H)
										{
											ThisStroke = stopStratStroke;
											DrawPlanOrder(chartControl, chartScale, ThisStroke, simPrice, ThisEntry, simLabel, "Sim", 0, EEE.ATMS, EEE.ThisOrder, "SS_Sim_" + renderBracketIdx, EEE.Switch);
										}
									}
								}

								// === H/L swing bar highlight ===
								// When the stop source is H/L, draw a thin OUTLINE around the bars
								// used to compute the swing so the user can see where the stop is
								// anchored. Subtle on purpose — uses a temp brush at low opacity so
								// it never fights for attention with the main plan visuals.
								if (stopStratStroke != null && pInitialExitsType == "High / Low" && pInitialExitHLBars >= 0 && ChartBars != null)
								{
									int lastIdx = ChartBars.ToIndex;
									int firstIdx = Math.Max(ChartBars.FromIndex, lastIdx - pInitialExitHLBars);
									if (lastIdx >= firstIdx && InitialHLHighestHigh > 0 && InitialHLLowestLow > 0)
									{
										float hlX1 = (float) chartControl.GetXByBarIndex(ChartBars, firstIdx) - (float) chartControl.BarWidth / 2f - 1f;
										float hlX2 = (float) chartControl.GetXByBarIndex(ChartBars, lastIdx)  + (float) chartControl.BarWidth / 2f + 1f;
										float hlY1 = (float) chartScale.GetYByValue(InitialHLHighestHigh) - 1f;
										float hlY2 = (float) chartScale.GetYByValue(InitialHLLowestLow)  + 1f;
										if (hlX2 > hlX1 && hlY2 > hlY1)
										{
											SharpDX.RectangleF hlRect = new SharpDX.RectangleF(hlX1, hlY1, hlX2 - hlX1, hlY2 - hlY1);

											// Reuse workingBrushA to avoid creating a SharpDX brush per frame.
											// Update its color + opacity from the stop-strategy stroke's WPF brush.
											if (stopStratStroke.Brush != null && RenderTarget != null && workingBrushA != null)
											{
												SetWorkingBrushColor(workingBrushA, stopStratStroke.Brush, 0.30f);
												SafeDrawRectangle(hlRect, workingBrushA, 1f, SolidStroke.StrokeStyle);
