			// LEAK FIX (deep-dive Round 2 Finding #4): clear the per-bar
			// PriceX1Boxes / PriceX2Boxes caches before populating. The loop
			// below covers only the currently-visible bar range (FB-5 to LB+20),
			// but as bars scroll forward old bar-index keys outside that range
			// were left in the ConcurrentDictionary forever, growing it
			// unbounded over long sessions. The dicts feed GetBoxXPixel —
			// which currently has zero uncommented callers, so the data is
			// computed but unused — but rather than delete the population
			// (in case a future call site is restored), bounding via Clear()
			// keeps the dict scoped to the current visible range.
			PriceX1Boxes.Clear();
			PriceX2Boxes.Clear();

