			int biggesttexThisTickSize = 0;

			if (MaxBoxHeight != MaxBoxHeightP)
			{
				// Binary search 1..100 for the largest font size whose rendered text height
				// is still under (MaxBoxHeight + 5). Heights are monotonically increasing with
				// font size, so binary search is exact and only forces ~7 cache lookups.
				double threshold = MaxBoxHeight + 5;
				int lo = 1, hi = 100;
				while (lo <= hi)
				{
					int mid = (lo + hi) / 2;
					double h = GetCachedTextHeight(mid);
					if (h < threshold)
					{
						biggesttexThisTickSize = mid;
						lo = mid + 1;
					}
					else
					{
						hi = mid - 1;
					}
				}
			}
			
