							int slices = 10;
							float sliceW = (triRight - triLeft) / slices;
							for (int s = 0; s < slices; s++)
							{
								float frac = (s + 0.5f) / slices;
								float barH = triSize * (1f - frac);
								float barY2 = triCY2 - barH / 2f;
