						if (MSG != string.Empty)
						{
										
							int sfasdfgda3 = -1;
							
							if (ChartPanel.Y != 0)
								sfasdfgda3 = 0;
							
			
							CellString = MSG;
							// Cached layout — see _measureLayoutCache. The status
							// bar text changes when click/move state flips but
							// the same MSG repeats across many frames in between.
							CellLayout = MeasureCellText(CellString, CellFormat);
							
		                    float FinalH = CellLayout.Height;
		                    float FinalW = CellLayout.Width;
							
							float hh = FinalH + 4;
							float sw = 0;
							sw = DS(ThisStroke.Width);
							
							ThisRect = new SharpDX.RectangleF(ChartPanel.X+sw, ChartPanel.Y+sfasdfgda3+ChartPanel.H-sw-hh, ChartPanel.W-sw-sw, hh);
							SafeFillRectangle(ThisRect,ChartBackgroundBrushDX);
							SafeFillRectangle(ExpandRect(ThisRect,0,0,2,0),ChartBackgroundFadeBrushDX);

							// Use the CURRENT ThisStroke's brush for the colored overlay so the
							// bar matches the just-decided buy/sell/both color. Previously this
							// used cachedStrokeBrushDX which is built once in CreatePropertyBrushes
							// from whatever ThisStroke happened to be at that moment — totally
							// unrelated to whether we're now in Buy or Sell click mode. Result:
							// the bar stayed green when entering Sell-click (or vice versa).
							// Build a per-frame temp brush so we can apply the 30% opacity the
							// cached brush used to have, without mutating the shared stroke.
							SharpDX.Direct2D1.Brush tempBottomBrush = null;
							try
							{
								if (ThisStroke != null && ThisStroke.Brush != null && RenderTarget != null)
								{
									tempBottomBrush = ThisStroke.Brush.ToDxBrush(RenderTarget);
									tempBottomBrush.Opacity = 0.3f;
									SafeFillRectangle(ThisRect, tempBottomBrush);
								}
								else
								{
									// fallback to whatever brush we had
									SafeFillRectangle(ThisRect, ThisBrushDX);
								}
							}
							finally
							{
								if (tempBottomBrush != null) { try { tempBottomBrush.Dispose(); } catch { } }
							}


							ThisBrushDX = ChartTextBrushDX;
							SafeDrawText(CellString, CellFormat, ThisRect, ThisBrushDX);
								
						}
						
//						if (SomeBuy && SomeSell)
//						{
//							ThisStroke = pOrderBothOutlineStroke;
							
//						}
//						else if (SomeBuy)
//						{
//							ThisStroke = pOrderUpOutlineStroke;					
			
//						}
							
//						else if (SomeSell)
//						{						
//							ThisStroke = pOrderDnOutlineStroke;

//						}
					
						int startxxxx = 0;
						
						
						if (ChartPanel.X != 0)
							startxxxx = ChartPanel.X;
						
						
						int sfasdfgda = -1;

						if (ChartPanel.Y != 0)
							sfasdfgda = 0;

						// Hoist the DPI-scaled stroke width — used 6 times in
						// the four rect constructions below. DS() is a simple
						// scale but reading ThisStroke.Width is a property
						// access, and computing it six times per frame is
						// silly when nothing changes between the four calls.
						float swOutline = DS(ThisStroke.Width);

						ThisRect = new SharpDX.RectangleF(ChartPanel.X+1, ChartPanel.Y, ChartPanel.W-1, swOutline);
						SafeFillRectangle(ThisRect,ThisStroke.BrushDX);

						ThisRect = new SharpDX.RectangleF(ChartPanel.X+1, ChartPanel.Y+sfasdfgda+ChartPanel.H-swOutline, ChartPanel.W-1, swOutline);
						SafeFillRectangle(ThisRect,ThisStroke.BrushDX);

						ThisRect = new SharpDX.RectangleF(startxxxx + 1, ChartPanel.Y, swOutline, ChartPanel.H);
						SafeFillRectangle(ThisRect,ThisStroke.BrushDX);

						ThisRect = new SharpDX.RectangleF(ChartPanel.W+startxxxx-swOutline, ChartPanel.Y, swOutline, ChartPanel.H);
						SafeFillRectangle(ThisRect,ThisStroke.BrushDX);
						
			
						
					}
					
				}
				
				
				
				
			
