			}		
			
					
						
			
			if (RenderTest(20)) return; // 2
			
			
			
								
		
			// TIMER!!!!!!!!!!
				if (!IsInHitTest)
			if (pBarCounterEnabled)
				//if (pBarCounterEnabled && i == LB && LB >= CurrentBars[0])
				{
					
					int thistop2 = ChartPanel.H + ChartPanel.Y;
					
				
					// Alignment/wrap pre-set in CreateCachedTextFormats() so the
					// hot timer path doesn't re-write three properties per frame.
					CellFormat			= cachedTextFontTimeFormat;

					CellString = BarTimerString;

					// Cached layout — the timer string changes once per second
					// (bar countdown) but OnRender fires at ~60Hz, so prior to
					// this cache the bottom-right timer was the dominant
					// per-frame DirectWrite TextLayout allocation source even
					// when nothing else was being drawn.
					CellLayout = MeasureCellText(CellString, CellFormat);

					
					
					//double yB2 = GetBoxYPixel(RTTS(Lows[0].GetValueAt(i)),"Bottom") + pBarCounterOffset;
					xW = CellLayout.Width;	
					xL = ChartPanel.W +ChartPanel.X - xW - 6 - pBarCounterOffsetX - 1;
					
					double yB2 = thistop2 - CellLayout.Height - 4 - pBarCounterOffset;
					
					double yT2 = CellLayout.Height;
					
					if (pActiveOutlineEnabled)
					{
						yB2 = yB2 - DS(pOrderBothOutlineStroke.Width);
						xL = xL - DS(pOrderBothOutlineStroke.Width);
						
					}
					
					
					ThisRect = new SharpDX.RectangleF((float)xL, (float)yB2, (float)xW, (float)yT2);
				
				
					//Print(BarTimerString);
				
					ThisBrushDX = cachedBarCounterBrushDX;
					SafeDrawText(BarTimerString, CellFormat, ThisRect, ThisBrushDX);
				
				}			
			
				
						
			
			
					
						
			
			if (RenderTest(21)) return; // 2
			
			
						
			
			 
				// CellFormat now references cached TextFormats - do not dispose
				CellFormat = null;

			// Rendering Optimization: Only dispose working brushes (ThisBrushDX/DX2).
			// Cached brushes (static + property-dependent) are managed by OnRenderTargetChanged.
			// TextBrushDX1, MainFillBrushDX, MainPrintBrushDX, TransparentBrushDX, CrossHairBrushDX,
			// ChartTextBrushDX, ChartBackgroundBrushDX, button*BrushDX, etc. are now cached.

							if (RenderTest(22)) return; // 2

				// ThisBrushDX/DX2/DX4 now always point to cached brushes - just null the references
				ThisBrushDX = null;
				ThisBrushDX2 = null;
				ThisBrushDX4 = null;

				
				
				
			if (RenderTest(23)) return; // 2
			
			
							
//				Plot1BrushDX.Dispose();
//				Plot2BrushDX.Dispose();
//				Plot3BrushDX.Dispose();
//				Plot4BrushDX.Dispose();
//				Plot5BrushDX.Dispose();
//				Plot6BrushDX.Dispose();	
			
			
			
				//if (ChartBackgroundShade1BrushDX != null) ChartBackgroundShade1BrushDX.Dispose();	
			
			
			if (RenderTest(24)) return; // 2
			
			
			
			
			
			
				
			}
			catch (Exception ex)
			{
				LogDiag("RENDER", "OnRenderOuter", ex.ToString()); if (TestRender) Print("OnRender: " + ThisMasterInstrument.Name + " " + ex.Message + " " + DateTime.Now.ToString("T"));

			}

			// DIAGNOSTIC restore (see RenderDiagMode in the snapshot block):
			// put the order-moving state back exactly as it was before this
			// frame neutralized it. Runs on both the normal and exception path
			// because the outer catch above swallows everything.
			if (_diagMovingNeutralized)
			{
				lock (_accountStateLock)
				{
					MovingOrder = _diagSavedMovingOrder;
					MovingOrders.Clear();
					MovingOrders.AddRange(_diagSavedMovingOrders);
				}
				_diagMovingNeutralized = false;
			}

			// Safety pop — if any code path between Push and Pop threw and the outer
			// catch swallowed it, the clip stack would be left unbalanced, causing
			// D2DERR_PUSH_POP_UNBALANCED on the next frame.
			if (_clipPushDepth != 0)
			{
				LogDiag("RENDER", "ClipImbalance", "depth=" + _clipPushDepth + " at OnRender end");
				try { while (_clipPushDepth > 0 && RenderTarget != null) { RenderTarget.PopAxisAlignedClip(); _clipPushDepth--; } } catch { }
				_clipPushDepth = 0;
			}

			_renderActive = false;
			ApplyHoverCursor();
		}

