		private double GetMaxDouble(List<double> DDD)
		{
			
			double returnd = 0;
			
			foreach (double D in DDD)
				returnd = Math.Max(returnd,D);
			
			return returnd;
			
			
		}
		
		private SharpDX.RectangleF OutlineRect (SharpDX.RectangleF RR)
		{
			
			SharpDX.RectangleF FF = MoveRect(ExpandRect(RR,0,-1,0,-1),1,1);
				
			return FF;
			
		}		
		
		private SharpDX.RectangleF MoveRect (SharpDX.RectangleF RR, float xe, float ye)
		{
			
			SharpDX.RectangleF FF = new SharpDX.RectangleF(RR.X+xe, RR.Y+ye, RR.Width, RR.Height);
				
			return FF;
			
		}
		
		// Spatial expansion (used for order flag glow padding, text background pads, etc.)
		// is DPI-scaled so glow / padding stays visually proportional at high DPI.
		// At 100% DPI dpiScale = 1 so behavior is unchanged.
		private SharpDX.RectangleF ExpandRect (SharpDX.RectangleF RR, float left, float right, float top, float bottom)
		{

			SharpDX.RectangleF FF = new SharpDX.RectangleF(RR.X-S(left), RR.Y-S(top), RR.Width+S(left+right), RR.Height+S(top+bottom));

			return FF;

		}

		private SharpDX.RectangleF ExpandRect (SharpDX.RectangleF RR, float xe, float ye)
		{

			SharpDX.RectangleF FF = new SharpDX.RectangleF(RR.X-S(xe), RR.Y-S(ye), RR.Width+S(xe*2), RR.Height+S(ye*2));
				
			return FF;
			
		}
		
	
		
