		// Draw highlight for a secondary data series indicator plot
		// Draws smooth diagonal lines between secondary bar values, matching how NinjaTrader renders the plot
		private void DrawSecondarySeriesPlotHighlight(IndicatorBase ii, int plotIndex, SharpDX.Direct2D1.Brush highlightBrush, int lineWidth, ChartControl chartControl, ChartScale chartScale)
		{
			try
			{
				ISeries<double> vals = ii.Values[plotIndex];
				int valCount = vals.Count;
				if (valCount == 0 || ii.BarsArray == null || ii.BarsArray.Length == 0) return;

				Bars indBars = ii.BarsArray[0];
				int barCount = indBars.Count;
				if (barCount == 0) return;

				int extraWidth = (lineWidth == 1) ? 3 : 0;
				int finalWidth = lineWidth * 2 + lineWidth + 1 + extraWidth;

				SharpDX.Direct2D1.AntialiasMode savedAA = RenderTarget.AntialiasMode;
				RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

				// Iterate through secondary bars and draw smooth lines connecting values
				int maxIdx = Math.Min(valCount, barCount);
				double prevY = 0;
				double prevX = 0;
				bool started = false;

				for (int i = Math.Max(0, maxIdx - 500); i < maxIdx; i++)
				{
					double val = 0;
					try { val = vals.GetValueAt(i); } catch { continue; }
					if (double.IsNaN(val) || val == 0) continue;

					DateTime barTime;
					try { barTime = indBars.GetTime(i); } catch { continue; }

					double xPos = chartControl.GetXByTime(barTime);
					double yPos = chartScale.GetYByValue(val);

					if (xPos < -50 || xPos > ChartPanel.W + 50) { started = false; continue; }

					if (started)
					{
						// Draw smooth diagonal line from previous point to this point
						StartPoint = new Point(prevX, prevY);
						EndPoint = new Point(xPos, yPos);
						SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), highlightBrush, finalWidth);
					}

					prevX = xPos;
					prevY = yPos;
					started = true;
				}

				// No extension to right edge — highlight only covers the actual plotted line

				RenderTarget.AntialiasMode = savedAA;
			}
			catch { }
		}

		// Get the interpolated Y pixel value of a secondary series plot at a given X pixel position
		// Used for precise hover detection — linearly interpolates between adjacent secondary bar values
		private double GetSecondaryPlotYAtX(IndicatorBase ii, int plotIndex, double mouseX, ChartControl chartControl, ChartScale chartScale)
		{
			try
			{
				ISeries<double> vals = ii.Values[plotIndex];
				int valCount = vals.Count;
				if (valCount == 0 || ii.BarsArray == null || ii.BarsArray.Length == 0) return double.MinValue;

				Bars indBars = ii.BarsArray[0];
				int barCount = indBars.Count;
				if (barCount == 0) return double.MinValue;

				int maxIdx = Math.Min(valCount, barCount);

				// Find the two secondary bars that bracket the mouse X position
				double prevX = double.MinValue;
				double prevVal = 0;

				for (int i = Math.Max(0, maxIdx - 500); i < maxIdx; i++)
				{
					double val = 0;
					try { val = vals.GetValueAt(i); } catch { continue; }
					if (double.IsNaN(val) || val == 0) continue;

					DateTime barTime;
					try { barTime = indBars.GetTime(i); } catch { continue; }

					double xPos = chartControl.GetXByTime(barTime);

					if (xPos >= mouseX && prevX != double.MinValue)
					{
						// Mouse is between prevX and xPos — interpolate
						double ratio = (xPos - prevX) > 0 ? (mouseX - prevX) / (xPos - prevX) : 0;
						double interpVal = prevVal + ratio * (val - prevVal);
						return chartScale.GetYByValue(interpVal);
					}

					prevX = xPos;
					prevVal = val;
				}

				// Mouse is past the last secondary plot point — reject hover.
				// The plot isn't drawn past its last data point, so attaching
				// an order to the empty space to the right is a misclick.
				return double.MinValue;
			}
			catch { return double.MinValue; }
		}

