		public Brush GetTextColor(Brush bg2)
		{


			Brush thisone = Brushes.Black;

			Color bg = new Color();
			bg = Color.FromRgb(0, 0, 0);


			if (bg2 is SolidColorBrush)
			{
				bg = (bg2 as SolidColorBrush).Color;
			}
			else if (bg2 is GradientBrush)
			{
				// Average the gradient stops so ATM / styled buttons (LinearGradientBrush
				// from MakeGradientBrush) get text color based on their actual color,
				// not the skin. Without this, a customer on a light skin gets near-black
				// text over a dark user-chosen button color.
				var gb = bg2 as GradientBrush;
				if (gb.GradientStops != null && gb.GradientStops.Count > 0)
				{
					int r = 0, g = 0, b = 0, n = 0;
					foreach (var gs in gb.GradientStops)
					{
						r += gs.Color.R; g += gs.Color.G; b += gs.Color.B; n++;
					}
					bg = Color.FromRgb((byte)(r / n), (byte)(g / n), (byte)(b / n));
				}
				else
				{
					bg = Color.FromRgb(0, 0, 0);
				}
			}
			else
			{
				string skinname = NinjaTrader.Core.Globals.GeneralOptions.Skin.ToString();

				if (skinname == "NinjaTrader Dark" || skinname == "Dark" || skinname == "Slate Dark" || skinname == "Slate Gray")
				{
					bg = Color.FromRgb(0, 0, 0);
				}
				else
				{
					bg = Color.FromRgb(255, 255, 255);
				}

			}
			
			
			double a = 1 - ( 0.299 * bg.R + 0.587 * bg.G + 0.114 * bg.B)/255;
            if (a < 0.5)
               return Brushes.Black;
            else
               return Brushes.WhiteSmoke;
			
//		    int nThreshold = 150;
//		    int bgDelta = Convert.ToInt32((bg.R * 0.299) + (bg.G * 0.587) + 
//		                                  (bg.B * 0.114));

//		    Brush foreColor = (255 - bgDelta < nThreshold) ? Brushes.Black : Brushes.White;
//		    return foreColor;
			
			
			
		}

						
		
			
	
		
