		// Draws the live click-entry preview flag that follows the mouse
		// during Buy Click / Sell Click / Iceberg / Time Sliced / Close
		// Click / Move Targets / Move Stops placement. Rewritten to match
		// the live/resting order flag visual treatment (DrawSyntheticOrders)
		// pixel-for-pixel so the preview is visually indistinguishable from
		// an already-placed order. Notable differences vs. the old path:
		//
		//   * No X cancel button. The user cancels by clicking the same
		//     side-panel button again (it's a toggle) or by choosing a
		//     different click mode. ClickEntryCancelRect stays zeroed so
		//     the legacy OnMouseDown MouseIn(ClickEntryCancelRect) check
		//     is a no-op.
		//
		//   * Flag width/height come from the same cached metrics as
		//     DrawSyntheticOrders (cachedAASpacerWidth +
		//     cachedOrderDisplayMinHeight) so preview and resting flags
		//     have identical dimensions.
		//
		//   * Text layout uses qty (left) + vertical separator + name
		//     (right), exactly like DrawSyntheticOrders / DrawOrders.
		//
		//   * Outline / inner / body fills use the same FillOrderRect /
		//     ChartOrdersHighlightBrushDX pattern as live flags, so the
		//     rounded outline + 1-px inset "attached to chart" look
		//     matches end to end.
		//
		//   * When the user has an ATM strategy selected, its display
		//     name is always drawn as a label to the left of the preview
		//     flag (matches the on-hover ATM label on live LIT flags).
		//
		//   * Move Targets / Move Stops render as a single centered label
		//     inside the flag body (no qty, no separator) since there is
		//     no meaningful per-order quantity for those modes.
		private void DrawClickEntry (ChartControl chartControl, ChartScale chartScale, Brush ThisBrush2, double CurrentLast, string thisstring)
		{
			// Use smooth anti-aliasing for order flag rendering
			SharpDX.Direct2D1.AntialiasMode savedClickEntryAntialiasMode = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

