			// MouseIn(ClickEntryCancelRect) check in OnMouseDown is a no-op.
			ClickEntryCancelRect = new SharpDX.RectangleF(0, 0, 0, 0);

			SharpDX.DirectWrite.TextFormat ButtonText = cachedTextFont66Format;

			// Plot 20 (click-entry cursor Y-axis flag) is written from OnBarUpdate
			// now — not here. Writing a plot via TriggerCustomEvent from inside
			// OnRender marshalled a plot mutation into the open Direct2D batch,
			// a render-target corruption risk (D2DERR_WRONG_STATE).
			_clickRefPrice = CurrentLast;
			_clickRefBrush = ThisBrush2;
			_clickRefTicks = DateTime.UtcNow.Ticks;

			int rightsideis = ChartPanel.W;
