			double ThisPrice3 = ThisPrice2;

			y1 = chartScale.GetYByValue(ThisPrice3);

			// Flag height — mirror DrawSyntheticOrders so preview snaps to
			// the same row height as a live order flag.
			CellFormat = cachedTextFont66Format;
			if (cachedOrderDisplayMinHeight > 0) OrderDisplayMinHeight = cachedOrderDisplayMinHeight;
			double yA = y1 - OrderDisplayMinHeight/2 - 1;
			double yH = OrderDisplayMinHeight;
			double yT = yA;

			// --- Build qty + name text ---
			int positionQtyq = qudSelector.Value;
			if (thisstring == IcebergName || thisstring == TimeSlicedName)
				positionQtyq = qudSelector2.Value;

			string dirrec = "Buy";
			if (SellClickReady || SellCloseClick || SellIcebergClick || SellTimeSlicedClick || IsInPCSell
				|| (_hoverPreviewActive && !_hoverPreviewIsBuy))
				dirrec = "Sell";

			// Fall back to LMT/MIT default for ClickText if nothing set it yet
			if (string.IsNullOrEmpty(ClickText))
			{
				ClickText = pThisEntryLimitClick;
			}

			// Right-side name text — leading space matches the DrawSyntheticOrders
			// format (" Buy LMT" etc.) so preview and resting flags render with
			// the same kerning.
			bool isMoveLine = thisstring == "CLICK TO MOVE TARGETS" || thisstring == "CLICK TO MOVE STOPS";
			string nameText;
			if (isMoveLine)
			{
				// Centered label, no qty
				nameText = thisstring;
			}
			else if (thisstring == IcebergName)
			{
				nameText = " " + dirrec + " " + IcebergName.ToUpper();
			}
			else if (thisstring == TimeSlicedName)
			{
				nameText = " " + dirrec + " " + "time sliced".ToUpper();
			}
			else
			{
				// Buy Click / Sell Click / Buy Close / Sell Close / price-button
				// hover all land here. ClickText carries the LMT / STP / SLM /
				// MIT / LIT / MKT / "Close Above" / "Close Below" marker set
				// by OnRender in the click-entry branch.
				nameText = " " + dirrec + " " + ClickText;
			}

			string qtyText = isMoveLine ? "" : positionQtyq.ToString();

			// Text widths used for sizing the flag — same formula as
			// DrawSyntheticOrders.
			float nameTextWidth = MeasureCellText(nameText, cachedTextFont66Format).Width;

			float qtyTextWidth = 0;
			if (!isMoveLine)
			{
				qtyTextWidth = MeasureCellText(qtyText, cachedTextFont66Format).Width;
			}

			float orderdwidth;
			if (isMoveLine)
				orderdwidth = nameTextWidth + 16; // padding around centered label
			else
				orderdwidth = nameTextWidth + cachedAASpacerWidth + qtyTextWidth + 3;

			float startright = rightsideis - maininitialspace - effectiveMoveOrdersNewLeft;
			ThisRect = new SharpDX.RectangleF((float)startright - orderdwidth, (float)yT, orderdwidth, (float)yH);

			// Track leftmost flag edge per price for ATM tooltip positioning
			if (!OrderLeftEdgeByPrice.ContainsKey(ThisPrice) || ThisRect.Left < OrderLeftEdgeByPrice[ThisPrice])
				OrderLeftEdgeByPrice[ThisPrice] = ThisRect.Left;

			// Track leftmost flag edge for ATM plan line alignment
			if (ThisRect.Left - 3 < LeftmostFlagX) LeftmostFlagX = ThisRect.Left - 3;

			// Horizontal "level line" across the chart at the preview price,
			// matching the live order flag treatment.
			ThisStroke = pTwoWidthStroke;
			StartPoint = new Point(0, y1);
			EndPoint   = new Point(rightsideis, y1);
			SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), ChartBackgroundBrushDX,         DS(ThisStroke.Width), ThisStroke.StrokeStyle);
			SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), cachedTextColorChartBg60BrushDX, DS(ThisStroke.Width), ThisStroke.StrokeStyle);

			// Three-layer fill — same as DrawSyntheticOrders. Gives the
			// rounded outline + 1-px inset that makes the flag look attached
			// to the chart.
			if (pMakeOrderOutlineNotSeeThru)
				FillOrderRect(ExpandRect(ThisRect, 3, 3), ChartBackgroundBrushDX, pOrderFlagRounding + 1);

			FillOrderRect(ExpandRect(ThisRect, 3, 3), ChartOrdersHighlightBrushDX, pOrderFlagRounding + 1);
			FillOrderRect(ExpandRect(ThisRect, 1, 1), ChartBackgroundBrushDX);

			// Body fill uses the caller-provided brush (Buy / Sell / target /
			// stop palette chosen in the OnRender click-entry branch).
			SetWorkingBrushColor(workingBrushA, ThisBrush2);
			SharpDX.Direct2D1.Brush flagBrush = workingBrushA;
			Brush textColorBrush = GetTextColor(ThisBrush2);
			SharpDX.Direct2D1.Brush flagTextBrush = (textColorBrush == Brushes.Black) ? cachedBlackBrushDX : cachedWhiteSmokeBrushDX;

			FillOrderRect(ThisRect, flagBrush);

			// ---- Text ----
			float sidepadding = 5;
			CellFormat = ButtonText;

			if (isMoveLine)
			{
				// Move Targets / Move Stops: single centered label inside flag
				CellFormat.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Center;
				CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
				CellFormat.WordWrapping       = SharpDX.DirectWrite.WordWrapping.NoWrap;
				SafeDrawText(nameText, CellFormat, ThisRect, flagTextBrush);
			}
			else
			{
				// Qty — left-aligned in a 22-px slot at the flag's left,
				// same as DrawSyntheticOrders.
				CellFormat.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Leading;
				CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
				CellFormat.WordWrapping       = SharpDX.DirectWrite.WordWrapping.NoWrap;
				SharpDX.RectangleF qtyRect = new SharpDX.RectangleF(ThisRect.Left, ThisRect.Top, 22, ThisRect.Height);
				SafeDrawText(qtyText, CellFormat, ExpandRect(qtyRect, sidepadding*-1, 0, 0, 0), flagTextBrush);

				// Vertical separator between qty and name — half-pixel snap
				// for a crisp 1-px line at any DPI. Padding/gap DPI-scale so
				// the line tracks the qty text (which is drawn into a rect
				// whose left side ExpandRect now S()-scales).
				float sepX = (float)Math.Floor(ThisRect.Left + S(sidepadding) + qtyTextWidth + S(4)) + 0.5f;
				ThisStroke = pOneWidthStroke;
				StartPoint = new Point(sepX, ThisRect.Top + S(3));
				EndPoint   = new Point(sepX, ThisRect.Bottom - S(3));
				SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), flagTextBrush, DS(1f), ThisStroke.StrokeStyle);

				// Name — right-aligned, clipped left of the separator
				CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing;
				float nameLeftClip = sidepadding + qtyTextWidth + 8;
				SafeDrawText(nameText, CellFormat, ExpandRect(ThisRect, nameLeftClip, sidepadding*-1, 0, 0), flagTextBrush);
			}

			// ATM strategy name label on the left side of the flag. Always
			// shown when an ATM is selected — gives the user a constant
			// reminder of which ATM they're about to apply.
			if (atmStrategySelector != null && atmStrategySelector.SelectedAtmStrategy != null)
			{
				string atmName = RemoveEndOfLiveATM(atmStrategySelector.SelectedAtmStrategy.DisplayName);
				if (!string.IsNullOrEmpty(atmName))
				{
					CellFormat.TextAlignment      = SharpDX.DirectWrite.TextAlignment.Trailing;
					CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
					CellFormat.WordWrapping       = SharpDX.DirectWrite.WordWrapping.NoWrap;

					{ }
					CellLayout = MeasureCellText(atmName, CellFormat);
					float ttWidth  = CellLayout.Width + S(4);
					float ttHeight = CellLayout.Height + S(2);
					float ttGap    = S(10);
					var atmRect = new SharpDX.RectangleF(
						ThisRect.Left - ttWidth - ttGap,
						ThisRect.Top + (ThisRect.Height - ttHeight) / 2,
						ttWidth,
						ttHeight);
					DrawTextBackground(atmRect);
					SafeDrawText(atmName, CellFormat, atmRect, ChartTextBrushDX);
				}
			}

			// Restore anti-alias mode
			RenderTarget.AntialiasMode = savedClickEntryAntialiasMode;
		}


