public class PriceLevelInfo
{
    public double Price { get; set; }
    public int TotalOrders { get; set; }
    public bool HasStop { get; set; }
    public bool HasTarget { get; set; }
    public bool HasEntry { get; set; }  // Added
    public int YPixel { get; set; }

    public PriceLevelInfo(double price)
    {
        Price = price;
        TotalOrders = 0;
        HasStop = false;
        HasTarget = false;
        HasEntry = false;
        YPixel = 0;
    }
}
		private Dictionary<double, PriceLevelInfo> PriceLevelInfoList = new Dictionary<double, PriceLevelInfo>();



private void TotalTheOrders()
{
    // count total orders for drawing later
    
    AllStopLossPrices.Clear();
    AllTargetPrices.Clear();
    PriceLevelInfoList.Clear();
    
    double ThisPrice = 0;

    bool docombinestopsperprice = !pSplitStopDisplay;
    bool docombinetargetsperprice = !pSplitTargetDisplay2;	
    
    if (myAccount != null)
        foreach (Order or in _renderOrdersSnapshot)
        {
            // HARDENING: skip any order whose price field is non-finite
            // (NaN / Infinity / absurd magnitude). A limit order mid-change
            // during an order storm can momentarily report such a value;
            // seeding it as a price-dictionary key makes DrawOrders build a
            // NaN rect, which draws the flag invisibly AND silently corrupts
            // the Direct2D render target — NinjaTrader then raises
            // D2DERR_WRONG_STATE at EndDraw and the chart freezes.
            if (BadF(or.StopPrice) || BadF(or.LimitPrice))
                continue;

            ThisPrice = or.StopPrice;

            int thisq = or.Quantity;

            OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending 
                || or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelSubmitted || or.OrderState == OrderState.TriggerPending || or.OrderState == OrderState.PartFilled;
            
            if (pShowCancelPendingOrders && or.OrderState == OrderState.CancelPending)
                OrderStateOK = true;
            
            OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
            // PERF: cache IsStop/IsTarget (each does Contains + Any)
            bool isStopLP = IsStop(or.Name);
            bool isTargetLP = IsTarget(or.Name);
            OrderNameOK = isStopLP || isTargetLP;
            OrderTypeOK = true;

            if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
            {
                if (isStopLP)
                {
                    ThisPrice = or.StopPrice;

                    // PERF: TryGetValue (single lookup)
                    int existingStopQty;
                    if (AllStopLossPrices.TryGetValue(ThisPrice, out existingStopQty))
                        AllStopLossPrices[ThisPrice] = existingStopQty + thisq;
                    else
                        AllStopLossPrices.Add(ThisPrice, thisq);
                }

                if (isTargetLP)
                {
                    ThisPrice = or.LimitPrice;

                    // MIT targets use StopPrice; Rithmic/APEX reports MIT as OrderType.Market with TriggerPending
                    if (or.OrderType == OrderType.MIT
                        || (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending))
                        ThisPrice = or.StopPrice;

                    // PERF: TryGetValue (single lookup)
                    int existingTargetQty;
                    if (AllTargetPrices.TryGetValue(ThisPrice, out existingTargetQty))
                        AllTargetPrices[ThisPrice] = existingTargetQty + thisq;
                    else
                        AllTargetPrices.Add(ThisPrice, thisq);
                }
            }
        }
        
    TotalOrdersPrices.Clear();
    OrderLeftEdgeByPrice.Clear();

    FoundStopLossPrices.Clear();
    FoundTargetPrices.Clear();

    if (myAccount != null)
        foreach (Order or in _renderOrdersSnapshot)
        {
            // HARDENING: skip orders with a non-finite price field — keeps
            // NaN/Infinity prices out of TotalOrdersPrices / PriceLevelInfoList.
            // See the matching note in the first loop above.
            if (BadF(or.StopPrice) || BadF(or.LimitPrice))
                continue;

            ThisPrice = or.StopPrice;

            bool ischanging = or.OrderState == OrderState.ChangePending || or.OrderState == OrderState.ChangeSubmitted;

            ischanging = false;

            if (or.OrderType == OrderType.Limit && (or.StopPrice == 0 || (or.OrderState == OrderState.Working || ischanging)))
            {
                ThisPrice = or.LimitPrice;
            }

            // MIT orders may report price via StopPrice or LimitPrice depending on connection
            if (or.OrderType == OrderType.MIT && ThisPrice == 0)
            {
                ThisPrice = or.LimitPrice;
            }

            // Fallback for TriggerPending orders with no StopPrice
            if (or.OrderState == OrderState.TriggerPending && ThisPrice == 0 && or.LimitPrice != 0)
            {
                ThisPrice = or.LimitPrice;
            }

            int thisq = or.Quantity;
        
            OrderStateOK = or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending 
                || or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelSubmitted || or.OrderState == OrderState.TriggerPending || or.OrderState == OrderState.PartFilled;
            
            if (pShowCancelPendingOrders && or.OrderState == OrderState.CancelPending)
                OrderStateOK = true;

            OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
            OrderNameOK = true;
            OrderTypeOK = or.OrderType != OrderType.Market;

            if (or.OrderState == OrderState.Cancelled)
                OrderTypeOK = false;
            if (or.OrderState == OrderState.Filled)
                OrderTypeOK = false;

            // Rithmic/APEX reports MIT orders as OrderType.Market with TriggerPending state
            if (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending && or.StopPrice != 0)
                OrderTypeOK = true;

            if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
            {
                if (docombinestopsperprice && IsStop(or.Name))
                {
                    // PERF: ContainsKey is sufficient — no need for the duplicate !ContainsKey+Add
                    if (FoundStopLossPrices.ContainsKey(ThisPrice))
                        continue;

                    FoundStopLossPrices.Add(ThisPrice, 1);
                }

                if (docombinetargetsperprice && IsTarget(or.Name))
                {
                    if (FoundTargetPrices.ContainsKey(ThisPrice))
                        continue;

                    FoundTargetPrices.Add(ThisPrice, 1);
                }

                // PERF: TryGetValue instead of ContainsKey + [key]
                int existingQty;
                if (TotalOrdersPrices.TryGetValue(ThisPrice, out existingQty))
                    TotalOrdersPrices[ThisPrice] = existingQty + thisq;
                else
                    TotalOrdersPrices.Add(ThisPrice, thisq);
                
                // ADD ALL ORDERS TO PriceLevelInfoList
                if (!PriceLevelInfoList.ContainsKey(ThisPrice))
                    PriceLevelInfoList.Add(ThisPrice, new PriceLevelInfo(ThisPrice));
                
                PriceLevelInfoList[ThisPrice].TotalOrders += thisq;
                
                if (IsStop(or.Name))
                    PriceLevelInfoList[ThisPrice].HasStop = true;
                else if (IsTarget(or.Name))
                    PriceLevelInfoList[ThisPrice].HasTarget = true;
                else
                    PriceLevelInfoList[ThisPrice].HasEntry = true;
                
                if (TotalOrdersPrices[ThisPrice] > 1)
                {
                }
            }
        }
}




