		private void DrawPlanOrder (ChartControl chartControl, ChartScale chartScale, Stroke ThisStroke, double CurrentLast, double ThisEntry, string texter, string qtt, double rrrr, AtmStrategy PlanATM, Order PlanOrder, string ThisLineName, bool IsCustomOrder)
		{

			// Stable "is this the entry row?" flag captured from ThisLineName
			// before it gets reassigned to "Entry 2" at the line drag rect
			// registration site. Replaces the prior texter.Contains("Entry")
			// checks scattered through the function — texter no longer carries
			// the word "Entry" (the direction toggle now reads just "Long" /
			// "Short" / "Long MKT" instead of "<dir> Entry"), so the old check
			// would never fire. Lots of behavior gates on this (entry-only
			// toggles, hide button placement, mode toggle, qty suppression,
			// hover-glow scope, etc.), so we cache once at entry.
			bool isEntryRow = (ThisLineName == "Entry" || ThisLineName == "Entry 2");

			// Hoist Direct2D AntialiasMode set once per call instead of
			// flipping it ~8 times around individual DrawText sites. The
			// inner save/set/restore blocks are left in place but their
			// "set to PerPrimitive" calls become no-ops because Direct2D's
			// state cache short-circuits redundant sets — no batch flush.
			// Saves the cost of repeatedly flushing pending render commands
			// at every toggle / label / glow draw. AA mode is restored to
			// the original value at function exit.
			SharpDX.Direct2D1.AntialiasMode _outerSavedAA = RenderTarget.AntialiasMode;
			RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

				if (CurrentLast != 0)
				{

					MaxATMPlanningDisplay = Math.Max(MaxATMPlanningDisplay, CurrentLast);
					MinATMPlanningDisplay = Math.Min(MinATMPlanningDisplay, CurrentLast);

					// Register a Y-axis flag for this ATM plan level. Each
					// DrawPlanOrder call grabs one plot slot from the top of
					// the Values[] array (counted down by atmPlanPlotCursor,
					// reset per-render in the live-order plot reset block)
					// and stores (price, stroke brush). NT8 renders the flag
					// in the price axis automatically because every plot has
					// ShowLastValue default-true.
					//
					// Safety rails:
					//   * Skip when CurrentLast == 0 (already inside the != 0
					//     branch so we're fine).
					//   * Stop counting down before we collide with the live-
					//     order plot range (plot 25+) — if the user has tons
					//     of live orders AND tons of ATM plan levels at once,
					//     new ATM plan levels just don't get a Y-axis flag
					//     rather than stomping on a live-order slot.
					//   * Skip bracket placeholder labels like "~ …" (moving
					//     target/stop preview): those represent the SAME
					//     price point already drawn by the real target/stop
					//     above or below, so we don't want a duplicate flag.
					//   * Skip when ThisStroke or its Brush is null.
					bool skipAtmPlanFlag = false;
					if (!string.IsNullOrEmpty(texter) && texter.StartsWith("~ "))
						skipAtmPlanFlag = true;
					if (ThisStroke == null || ThisStroke.Brush == null)
						skipAtmPlanFlag = true;

					if (!skipAtmPlanFlag
						&& atmPlanPlotCursor >= 25
						&& atmPlanPlotCursor < Values.Length)
					{
						try
						{
							Values[atmPlanPlotCursor][0] = CurrentLast;
							PlotBrushes[atmPlanPlotCursor][0] = ThisStroke.Brush;
							if (atmPlanPlotCursor < atmPlanPlotLastLow)
								atmPlanPlotLastLow = atmPlanPlotCursor;
						}
						catch { /* plot slot unavailable — skip */ }
						atmPlanPlotCursor--;
					}
				}
					
				
				
//			//Print("DrawPlanOrder");

		//	return;



			// DPI scaling factor: all hardcoded pixel offsets in this
			// routine (shadow thickness, text padding, inter-label gaps,
			// drag handle buffer, highlight line widths) are multiplied by
			// planFontScale so spacing looks consistent across DPI settings.
			// Read once-per-frame cached value computed in OnRender.
			float planFontScale = _planFontScaleCached;

			int exshade = Math.Max(2, (int)Math.Round(2 * planFontScale));

							
							
            SharpDX.DirectWrite.TextFormat ButtonText = cachedTextFont66Format;
			//ButtonText = myProperties.LabelFont.ToDirectWriteTextFormat();
			
			 //Print("DrawPlan 1");
			
			
			// ChartBackgroundFade2BrushDX now cached in CreatePropertyBrushes
			
			double linewidd = pPlanningWidthAd2;


			// to adjust the whole width based on pATMTextMove setting
			linewidd = effectiveMoveOrdersNewLeft + pPlanningWidthAd2 + pATMTextMove;

			linewidd = effectiveMoveOrdersNewLeft + pPlanningWidthAd2 + maininitialspace;
			 
			
			  
			//
			
			
			
			
			
