								// 'S' in Split doesn't immediately drop the chip.
								float lineDragBottomYsh = (float)y1 + Math.Max(6f, 6f * planFontScale);
								float hoverLeft   = (float)sx3 - DS(30f);
								float hoverTop    = (float)y2;
