								string placeDirLabel = (pLastPlanDirection == "Short") ? "Sell" : "Buy";
								// Prefer the freshly-computed qty for THIS entry level
								// (passed in as `qtt` — the same string used for the
								// Qty chip / Entry label on the line). When H/L position
								// sizing is active, pLastQuantity can lag the freshly-
								// recomputed mainq if the qud/qty-state didn't change
								// in lockstep, leaving Place Order showing a stale
								// quantity (e.g. "40") while the on-line label shows
								// the correct "9". Parse qtt first; fall through to
								// pLastQuantity / qudSelector only if qtt isn't a
								// positive integer.
								int placeQty = 0;
								int parsedQtt;
								if (!string.IsNullOrEmpty(qtt) && int.TryParse(qtt, out parsedQtt) && parsedQtt > 0)
									placeQty = parsedQtt;
