								// GetTextColor(orderColor) for maximum contrast against
								// their body. Falls back to ChartTextBrushDX if the cached
								// brush hasn't been initialized yet (early frames).
								SharpDX.Direct2D1.Brush placeTextBrush = cachedTextColorChartBgBrushDX != null ? cachedTextColorChartBgBrushDX : ChartTextBrushDX;

								if (placeButtonDisabled)
								{
									// Disabled: draw the same crisp brush at 0.4 alpha for
