		private bool IsStop(string ssss)
		{
			// Called 100+ times per frame across render loops. Previously used
			// `.Any(char.IsDigit)` which allocates a LINQ enumerator every call.
			// Manual scan is allocation-free and short-circuits on first digit.
			if (ssss == null) return false;
			if (ssss.IndexOf("Stop", StringComparison.Ordinal) < 0) return false;
			for (int i = 0; i < ssss.Length; i++)
			{
				if (ssss[i] >= '0' && ssss[i] <= '9') return true;
			}
			return false;
		}

		private bool IsTarget(string ssss)
		{
			// See IsStop comment -- same allocation-free pattern.
			if (ssss == null) return false;
			if (ssss.IndexOf("Target", StringComparison.Ordinal) < 0) return false;
			for (int i = 0; i < ssss.Length; i++)
			{
				if (ssss[i] >= '0' && ssss[i] <= '9') return true;
			}
			return false;
		}
			
		
