		// --- Cached order/flag text measurement ---------------------------------
		// DrawOrders / DrawLastStrokes / DrawPlanOrder previously built a fresh
		// DirectWrite TextLayout per order, per frame, only to read a string's
		// width/height. Order name / quantity / resting-price labels are stable
		// between frames, so the measured size is cached. Separate caches per font
		// (order path uses cachedTextFont66Format, plan path cachedChartFontAdFormat);
		// an unrecognized format falls back to an uncached measure. Both caches are
		// flushed in DisposeAllCachedTextFormats() when the fonts are rebuilt.
		private readonly Dictionary<string, SharpDX.Size2F> _orderTextSizeCache66 = new Dictionary<string, SharpDX.Size2F>();
		private readonly Dictionary<string, SharpDX.Size2F> _orderTextSizeCacheAd = new Dictionary<string, SharpDX.Size2F>();

		private SharpDX.Size2F MeasureCellText(string text, SharpDX.DirectWrite.TextFormat fmt)
		{
			if (string.IsNullOrEmpty(text) || fmt == null)
				return new SharpDX.Size2F(0f, 0f);

			Dictionary<string, SharpDX.Size2F> cache =
				  object.ReferenceEquals(fmt, cachedTextFont66Format)  ? _orderTextSizeCache66
				: object.ReferenceEquals(fmt, cachedChartFontAdFormat) ? _orderTextSizeCacheAd
				: null;

			SharpDX.Size2F size;
			if (cache != null && cache.TryGetValue(text, out size))
				return size;

			try
			{
				using (var tl = new TextLayout(Core.Globals.DirectWriteFactory, text, fmt, 10000, 10000))
					size = new SharpDX.Size2F(tl.Metrics.Width, tl.Metrics.Height);
			}
			catch { return new SharpDX.Size2F(0f, 0f); }

			if (cache != null)
			{
				if (cache.Count > 512) cache.Clear();
				cache[text] = size;
			}
			return size;
		}

