					// Include Submitted + Initialized so the flag renders the instant
					// NT creates the order object (right at click), before broker
					// confirmation. Bridges the visual gap that used to require a
					// separate gray pending-viz overlay. Color override below
					// switches early-state orders to the pending-side gray so the
					// user still gets the "in flight, not officially resting yet"
					// visual cue — same rendering path though, so the text styling
					// (vertical bar between qty and type, etc.) is identical to a
					// resting flag.
					OrderStateOK = or.OrderState == OrderState.Submitted || or.OrderState == OrderState.Initialized
					|| or.OrderState == OrderState.Working || or.OrderState == OrderState.Accepted || or.OrderState == OrderState.ChangePending
					|| or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelSubmitted || or.OrderState == OrderState.TriggerPending || or.OrderState == OrderState.PartFilled;

								if (pShowCancelPendingOrders && or.OrderState == OrderState.CancelPending)
							OrderStateOK = true;

