					// hasn't acknowledged yet. Used below to swap the Buy/Sell
					// body color for the pending-side color.
					bool isPreConfirmState = (or.OrderState == OrderState.Submitted || or.OrderState == OrderState.Initialized);


//					OrderTypeOK = or.OrderType != OrderType.Market;

					OrderInstrumentOK = or.Instrument.FullName == ThisInstrumment.FullName;
					OrderNameOK = true;
					OrderTypeOK = or.OrderType != OrderType.Market;
					
					
					bool ischanging = or.OrderState == OrderState.ChangePending || or.OrderState == OrderState.ChangeSubmitted;
					
							
						if (or.OrderState == OrderState.Cancelled)
							OrderTypeOK = false;
						if (or.OrderState == OrderState.Filled)
							OrderTypeOK = false;
						
						
						
					// Rithmic/APEX reports MIT orders as OrderType.Market with TriggerPending state
					if (or.OrderType == OrderType.Market && or.OrderState == OrderState.TriggerPending && or.StopPrice != 0)
						OrderTypeOK = true;

					if (OrderTypeOK && OrderStateOK && OrderNameOK && OrderInstrumentOK)
