						if (or.OrderType == OrderType.MIT && ThisPrice == 0)
						{
							ThisPrice = or.LimitPrice;
						}

						// Fallback: if price is still 0 for TriggerPending orders, try LimitPrice
						if (or.OrderState == OrderState.TriggerPending && ThisPrice == 0 && or.LimitPrice != 0)
						{
							ThisPrice = or.LimitPrice;
						}

						// Optimistic in-flight-change price. During ChangePending /
						// ChangeSubmitted, or.LimitPrice / or.StopPrice are still the
						// OLD (working) values while LimitPriceChanged / Stop-
						// PriceChanged hold the REQUESTED new prices. Without this
						// override, after a move commit the flag visibly stays at the
						// old position for ~50-300ms until the broker accepts the
						// change — and during that gap, the mouse (sitting at the
						// just-dropped position) isn't on the flag, so chip / qty /
						// ATM-toggle hover all feel laggy to come back online.
						// Rendering at the requested price keeps the flag right under
						// the cursor through the broker handoff.
						if (ischanging)
