							int combinedStopQty = 0;
							int combinedTargetQty = 0;
							bool hasStopAtPrice = AllStopLossPrices.TryGetValue(ThisPrice2, out combinedStopQty);
							bool hasTargetAtPrice = AllTargetPrices.TryGetValue(ThisPrice2, out combinedTargetQty);

							// Only rename to combined name if multiple orders actually exist at this price
							if (docombinestopsperprice && IsStop(or.Name) && hasStopAtPrice && combinedStopQty != or.Quantity)
								CellString = "Stop Loss";

							if (docombinestopsperprice && or.Name.Contains("SimStop") && hasStopAtPrice && combinedStopQty != or.Quantity)
								CellString = "Sim Stop";

