								AllTargetCombinationButtons.Add(buttonseq,Z);
							
							}
							
							
							
						// end
							
							
							
							
							
							
						// text on top of order
						
						float sidepadding = 5;	
							
							lefttt = startright - ThisRect7.Left + sidepadding + 1;
						
							
							lefttt = sidepadding;
							
							
							
							
							
							
							CellFormat			= ButtonText;
					
		                    CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing;
		                    CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
		                    CellFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

						
						
						//ThisBrushDX = ChartTextBrushDX;
							
						
						//SafeDrawText(ThisOrderNameText, CellFormat, ExpandRect(ThisRect,0,0,0,0), ThisBrushDX2);	
							
						//SafeDrawText(ThisOrderNameText, CellFormat, ExpandRect(ThisRect,0,lefttt*-1,0,0), ThisBrushDX2);	
					
						// text on order flags
							float orderNameLeftClip = sidepadding + qtyTextWidth + 8;
							SafeDrawText(ThisOrderNameText, CellFormat, ExpandRect(ThisRect,orderNameLeftClip,lefttt*-1,0,0), ThisBrushDX2);
							
							
							
							
					
							// quanitity text
				
						//CellString = ThisQtyText;
						
						CellFormat			= ButtonText;
					
		                    CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
		                    CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
		                    CellFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

						
						
						//ThisBrushDX = ChartTextBrushDX;
							 
						
						ThisRect8 = new SharpDX.RectangleF(ThisRect.Left, ThisRect.Top, 22, ThisRect.Height);
						
						
						SafeDrawText(ThisQtyText, CellFormat, ExpandRect(ThisRect8,sidepadding*-1,0,0,0), ThisBrushDX2);

						// Vertical separator between quantity and order type — snap to half-pixel for crisp 1px line.
						// Padding/gap/stroke DPI-scale so the line tracks the qty text (whose draw rect's left
						// is now S()-scaled by ExpandRect), and stays a perceived 1px line at any DPI.
						{
							float sepX = (float)Math.Floor(ThisRect.Left + S(sidepadding) + qtyTextWidth + S(4)) + 0.5f;
							StartPoint = new Point(sepX, ThisRect.Top + S(3));
							EndPoint = new Point(sepX, ThisRect.Bottom - S(3));
							SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), ThisBrushDX2, DS(1f), pOneWidthStroke.StrokeStyle);
						}

						if (!IsExitOrder)
						{
						
						
							//SharpDX.RectangleF Fia = new SharpDX.RectangleF(0, 0, 0, 0);
							
							
						 Z = new OrderDetails();
				            Z.ThisOrder = or;
							Z.ThisRectA = ThisRect8;
				            Z.Name = "";
				            Z.Width = orderprice;
				            Z.Switch = false;
				            Z.Rect = ThisRect8;
				            Z.Hovered = false;

							if (pAllowOrderQuantityAdjustment)
							AllOrderQuantityButtons.Add(buttonseq,Z);	
						
						
				
							
//							LeftOfOrders = (int) (ChartPanel.W * 100 / dpiX); // - 
						
//							LeftOfOrders = ChartPanel.W;
							
							LeftOfOrders = rightsideis - ((int) ThisRect8.Left + 1 + 2) - (int) ChartControl.AxisYRightWidth - 7;
							
							
							//LeftOfOrders = ChartPanel.W - (int) (ThisRect8.Left * 100 / dpiX);
							
							
							TopOfOrders = (int) (ThisRect8.Top * 100 / dpiY) - 5;
							TopOfOrders = Math.Max(0, TopOfOrders);
							
							
						//AdjustQtyChart
						
							//SafeDrawRectangle(ThisRect8, ChartHighlightBrushDX, DS(pHighlightStroke.Width));
							
							
							if (pAllowOrderQuantityAdjustment)
							if (MouseIn(ThisRect8,0,0))
							{

//								Print("TopOfOrders " + TopOfOrders);
//								Print("ChartPanel.Y " + ChartPanel.Y);


//								Print("ChartPanel.W " + ChartPanel.W);
//								Print("ThisRect8.Left " + ThisRect8.Left);

								// Qty hover highlight — use ChartHighlightBrushDX
								// (computed as high-contrast against chart bg via
								// GetOutlineColor2) instead of VerticalLineHighlightDX
								// (which is ChartText at 60% opacity). The old brush
								// was white-on-white on Buy/Sell mode flags because
								// the Nord palette forces white flag text — making
								// the hover effect invisible. ChartHighlightBrushDX
								// is visible against both dark and light chart backgrounds
								// regardless of the flag body color underneath.
								SafeDrawText(ThisQtyText, CellFormat, ExpandRect(ThisRect8,sidepadding*-1,0,0,0), ChartHighlightBrushDX);
								SafeDrawText(ThisQtyText, CellFormat, ExpandRect(ThisRect8,sidepadding*-1,0,0,0), ChartHighlightBrushDX);



									if (pAttachButtonsHoverEnabled)
									{
										HoverInstructions = "Change Quantity";
										
										{ }
							CellLayout = MeasureCellText(HoverInstructions, CellFormat);
										adjusthh = -1*(CellLayout.Width/2)+(float)yH/2 - 3;
										
										if (HoverN == 0)
										{
											SafeDrawText(HoverInstructions, CellFormat, MoveRect(ThisRect8,adjusthh,-1*moveinstabove-2), ChartTextBrushDX);
											HoverN = 1;
										}
									}							
								
								
								
								
							}
						
							
							

         					if (QtyOrder == or)
							{
//								SharpDX.RectangleF Fia = MoveRect(ThisRect8,-20,0);
								
//								SafeDrawRectangle(Fia, ChartHighlightBrushDX, DS(pHighlightStroke.Width));
								
								
								
								ThisRect3 = new SharpDX.RectangleF(ThisRect8.Left-(float)yH+1-S(7), (float)yT+1, (float)yH-1, (float)yH-1);
									
								//ThisRect3 = MoveRect(ThisRect8,-30,0);

								
								
	//							if (OrderIsSelected)
	//							{
	//								SafeFillRectangle(ThisRect3, ChartTextBrushDX);		
	//								//SafeFillRectangle(ThisRect3, ChartBackgroundFade2BrushDX);
	//								SafeDrawRectangle(ThisRect3, ChartBackgroundBrushDX);
	//							}
	//							else
								{
									SafeFillRectangle(ThisRect3, ThisBrushDX4);	
									SafeFillRectangle(ThisRect3, ChartBackgroundFade2BrushDX);
									//SafeDrawRectangle(ThisRect3, ChartBackgroundBrushDX);
									
									DrawButtonBorder(ThisRect3, ChartBackgroundAxisBrushDX);
								}
								
									
								
								
								// DRAW main line for orders
						
								ThisBrushDX = cachedOrderSummaryBrushDX;
								ThisStroke = pTwoWidthStroke;
								
								StartPoint	= new Point(ThisRect3.Right, y1);							
								EndPoint = new Point(ThisRect8.Left, y1);							
											
					
														
								ThisBrushDX = ChartBackgroundBrushDX;
								SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), ThisBrushDX, DS(ThisStroke.Width), ThisStroke.StrokeStyle);	
								ThisBrushDX = cachedTextColorChartBg60BrushDX;

								SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), ThisBrushDX, DS(ThisStroke.Width), ThisStroke.StrokeStyle);

								// end connecting line
										
										
								
								
								CellFormat			= ButtonText;
						
			                    CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			                    CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			                    CellFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
								
							
								if (MouseIn(ThisRect3,exmbl,exmbl))
								{
									
									SafeDrawRectangle(ExpandRect(ThisRect3,-2,-1,-1,-2), ChartHighlightBrushDX, DS(pHighlightStroke.Width));
									
									
									if (pAttachButtonsHoverEnabled)
									{								
										HoverInstructions = "Accept Quantity";
										
										{ }
							CellLayout = MeasureCellText(HoverInstructions, CellFormat);
										adjusthh = -1*(CellLayout.Width/2)+(float)yH/2 - 3;
										
										if (HoverN == 0)
										{
											SafeDrawText(HoverInstructions, CellFormat, MoveRect(ThisRect3,adjusthh,-1*moveinstabove-2), ChartTextBrushDX);
											HoverN = 1;
										}
									}							
								}
								
								SafeDrawText(checkoff, CellFormat, MoveRect(ThisRect3,0,-1), ThisBrushDX2);	
								
								
							    Z = new OrderDetails();
					            Z.ThisOrder = or;
								Z.ThisRectA = ThisRect3;
					            Z.Name = "";
					            Z.Width = orderprice;
					            Z.Switch = false;
					            Z.Rect = ThisRect3;
					            Z.Hovered = false;

								//AllOrderAttach6Buttons.Add(buttonseq,Z);	
								
								AllOrderQuantityConfirmButtons.Add(buttonseq,Z);	
								
								
								
								
								
								
								
							}
			
							
								
						   
						} 



						
						
						
						
						
						
						
						
						
						
						
						
						
						
						
						
						

						if (!AllOrderPrices.ContainsKey(ThisPrice))
							AllOrderPrices.Add(ThisPrice, startright - orderdwidth - orderhspace);
						else
						{
							startright =  AllOrderPrices[ThisPrice] - orderdwidth - orderhspace;
							AllOrderPrices[ThisPrice] = startright;
						}

						// Record this order label's band for cross-price overlap detection
						RecordLabelBand((float)yT, (float)(yT + yH), AllOrderPrices[ThisPrice]);

						// Track leftmost flag extent per price for post-loop line drawing
						{
							float flagLeft = ThisRect.Left - 3; // flush with shadow edge
							if (!OrderLinesToDraw.ContainsKey(ThisPrice))
								OrderLinesToDraw.Add(ThisPrice, new float[] { flagLeft, (float)y1 });
							else if (flagLeft < OrderLinesToDraw[ThisPrice][0])
								OrderLinesToDraw[ThisPrice][0] = flagLeft;
						}


						
						
						
						
							}
						
						
						
						
						
					}
					
					
					
					
					
					// end of slow

					// Reset cached brush opacity modified by allopacity
					if (ThisBrushDX4 != null) ThisBrushDX4.Opacity = 1.0f;
					if (ThisBrushDX2 != null) ThisBrushDX2.Opacity = 1.0f;

				}

				// Redraw the closest-to-mouse order flag on top so it's not obscured by overlapping flags
				if (HasHoveredFlag)
				{
					var hRect = HoveredFlagRect;
					var hBrush = HoveredFlagIsHovered ? cachedHoverHighlightBrushDX : ChartOrdersHighlightBrushDX;

					// Line segment through this flag
					{
						var lineStroke = pTwoWidthStroke;
						float yCenter = hRect.Top + hRect.Height / 2;
						StartPoint	= new Point(hRect.Left - 3, yCenter);
						EndPoint = new Point(hRect.Right + 3, yCenter);
						SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), ChartBackgroundBrushDX, lineStroke.Width, lineStroke.StrokeStyle);
						SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), cachedTextColorChartBg60BrushDX, lineStroke.Width, lineStroke.StrokeStyle);
					}

					// Outline + fill
					FillOrderRect(ExpandRect(hRect, 3, 3), hBrush, pOrderFlagRounding + 1);
					FillOrderRect(ExpandRect(hRect, 1, 1), ChartBackgroundBrushDX);
					if (HoveredFlagFillBrush != null)
						FillOrderRect(hRect, HoveredFlagFillBrush);

					// Order name text
					if (HoveredFlagTextBrush != null)
					{
						CellFormat = ButtonText;
						CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing;
						CellFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
						CellFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
						float orderNameLeftClip2 = 5 + HoveredFlagQtyWidth + 8;
						SafeDrawText(HoveredFlagNameText, CellFormat, ExpandRect(hRect, orderNameLeftClip2, -5, 0, 0), HoveredFlagTextBrush);

						// Quantity hover treatment.
						//
						// Lights up in two cases:
						//   1. Mouse is over the 22-px qty clickable rect
						//      (hQtyRect) — affordance for "this is clickable".
						//   2. Qty adjustment mode is currently active on THIS
						//      flag (HoveredFlagIsBeingAdjusted) — stays lit
						//      while the user scroll-wheels the qty.
						//
						// Uses the same DrawTextToggleHoverGlow treatment as the
						// plan-line text toggles (Hide / R/R / IE / Now/Price /
						// Long-Short / Place Order) so chart-wide hover feedback
						// is visually consistent: soft halo around the digits
						// in the chart highlight color + the digits redrawn in
						// white on top, reading as "this is hot/active." The
						// previous body-brush-at-50% overlay grayed the digits
						// instead of brightening them. addBackdrop=false skips
						// the chart-bg layers since the flag already has its
						// own colored Buy/Sell body fill.
						CellFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
						var hQtyRect = new SharpDX.RectangleF(hRect.Left, hRect.Top, 22, hRect.Height);
						bool qtyHoverGlow = pAllowOrderQuantityAdjustment
							&& HoveredFlagQtyAdjustable
							&& (MouseIn(hQtyRect, 0, 0) || HoveredFlagIsBeingAdjusted);

						if (qtyHoverGlow)
						{
							DrawTextToggleHoverGlow(ExpandRect(hQtyRect, -5, 0, 0, 0), HoveredFlagQtyText, CellFormat, addBackdrop: false);
						}
						else
						{
							SafeDrawText(HoveredFlagQtyText, CellFormat, ExpandRect(hQtyRect, -5, 0, 0, 0), HoveredFlagTextBrush);
						}

						// Vertical separator between qty and name — always drawn.
						// Padding/gap/stroke DPI-scale to track the qty draw rect.
						{
							float sepX = (float)Math.Floor(hRect.Left + S(5) + HoveredFlagQtyWidth + S(4)) + 0.5f;
							StartPoint = new Point(sepX, hRect.Top + S(3));
							EndPoint = new Point(sepX, hRect.Bottom - S(3));
							SafeDrawLine(StartPoint.ToVector2(), EndPoint.ToVector2(), HoveredFlagTextBrush, DS(1f), pOneWidthStroke.StrokeStyle);
						}
					}
				}

			// Restore anti-alias mode
			RenderTarget.AntialiasMode = savedOrderAntialiasMode;
		}

	
		private double GetBoxYPixel(double price, string type)
		{
			price = RTTS(price);
			if (PriceBoxes2.ContainsKey(price))
			{
				if (type == "Top")
				{
					return PriceBoxes2[price].Top;	
				}
				else if (type == "Bottom")
				{
					return PriceBoxes2[price].Bottom;
				}
				else if (type == "Height")
				{
					return PriceBoxes2[price].Height;
				}
				
				GetBoxYPixelStatus = true;
			}
			else
			{
				GetBoxYPixelStatus = false;
				//RefreshRender(1113);
			}
			
			return 0;
			
			
			
		}
         
		private double GetBoxXPixel(double barnum, string type, bool gap)
		{
			//price = RTTS(price);
			
			
//			if (price < PriceX1Boxes.Keys.Min())
//			{
//				return 0;
//			}
//			else if (price > PriceX1Boxes.Keys.Max())
//			{
//				return 20000;
				
//			}
			
//			else if (gap)
				
			if (gap)	
			{
			
				if (PriceX1Boxes.ContainsKey(barnum))
				{
					if (type == "Left")
					{
						return PriceX1Boxes[barnum].Top;	
					}
					else if (type == "Right")
					{
						return PriceX1Boxes[barnum].Bottom;
					}
					else if (type == "Width")
					{
						return PriceX1Boxes[barnum].Height;
					}
					
					
				}
			}
			else
			{
				if (PriceX2Boxes.ContainsKey(barnum))
				{
					if (type == "Left")
					{
						return PriceX2Boxes[barnum].Top;	
					}
					else if (type == "Right")
					{
						return PriceX2Boxes[barnum].Bottom;
					}
					else if (type == "Width")
					{
						return PriceX2Boxes[barnum].Height;
					}
					
					
				}				
				
			}
			
			return 0;
			
			
			
		}
         
		
		
		

