		// across frames AND indicators of the same type. Without this, the
		// per-frame indicator scan in OnRender (:62086) does GetType().GetProperties()
		// on every chart indicator and linearly scans properties for "IndicatorId" --
		// that's reflection in the render hot path. "Missing" is cached as null.
		private static readonly System.Collections.Generic.Dictionary<Type, System.Reflection.PropertyInfo> _indicatorIdPropCache
			= new System.Collections.Generic.Dictionary<Type, System.Reflection.PropertyInfo>();
		
		
		
