		private double pIsPlanInProgress = 0;

		// Bool that mirrors "is the user actively repositioning a plan."
		// Use this for is-active checks instead of `_hasPlanInProgress`,
		// which falsely reports inactive on instruments that legitimately
		// trade at price 0 (rate futures, certain currency pairs, synthetic
		// spreads). The field is set by SetPlanInProgress / ClearPlanInProgress
		// in lockstep with pIsPlanInProgress, so they never diverge.
		private bool _hasPlanInProgress = false;

		private void SetPlanInProgress(double price)
		{
			pIsPlanInProgress = price;
			_hasPlanInProgress = true;
		}

		private void ClearPlanInProgress()
		{
			pIsPlanInProgress = 0;
			_hasPlanInProgress = false;
		}

		// Plan-preview hover freeze: when the user hovers ANY element of the
		// ATM plan preview (entry / target / stop lines or labels, R/R toggle,
		// stop-src badge, SS markers, Place Order button, or the RR fill
		// boxes between entry and target/stop), stop following live price so
		// the user can click stationary plan elements without chasing moving
		// lines. Set this frame by a sweep over AllATMStrategyLevelButtons +
		// PlaceOrderRect + cached RR fill rects at the end of the plan render
		// block; consumed next frame by the IsNotPendingOrder branch to freeze
		// the sentinel preview's entry price.
		private bool _planHoverFreezeActive = false;
		private bool _planHoverFreezeActivePrev = false;
		private double _planHoverFreezeCachedEntry = 0;
		private SharpDX.RectangleF _planLastRRTargetRect;
		private SharpDX.RectangleF _planLastRRStopRect;
		private bool _planLastRRTargetValid = false;
		private bool _planLastRRStopValid = false;

		// Override for the Entry-label order type shown in preview mode only
		// (while !_hasPlanInProgress). Set by each WPF hover handler to the
		// actual configured type for that button (MKT / LMT / MIT / SLM / STP
		// / ICE) — the default pThisEntryType1 is Close-Bar-specific and was
		// incorrect for Market / Limit1 / Limit2 / Signal hovers. Empty string
		// = use default behavior. Cleared by HidePlan so stale overrides
		// don't leak between preview sources.
		private string _previewEntryTypeOverride = "";

        [Display(ResourceType = typeof(Custom.Resource), GroupName = "Advanced Exit Orders Management", Name = "Target 3 ATR Multiplier", Order = 108)]
        public double IsPlanInProgress
        {
            get { return pIsPlanInProgress; }
            set
            {
                pIsPlanInProgress = value;
                _hasPlanInProgress = value != 0;
            }
        }
		
				
		
		
		
		
			
