		// Buy / Sell color mode palette.
		//
		// Defaults below were retoned to form a coherent family — similar
		// saturation and lightness so they read as the same palette when you
		// see multiple flag types at once. Pending (further down) is left at
		// dark grey on purpose — it's meant to recede.
		//
		// Picks are Material-Design-ish:
		//   Buy    = (30, 136, 229)  near DodgerBlue / Material Blue 600 —
		//                             user explicitly asked for "closer to
		//                             DodgerBlue, less royal blue" here
		//   Sell   = (211, 47,  47)  Material Red 700
		//   Target = (67, 160, 71)   Material Green 600 (cleaner than neon Lime)
		//   Stop   = (239, 83,  80)  Material Red 400 — lighter coral, so it
		//                             stays distinguishable from Sell
		//
		// CROSS-THREAD SAFETY HELPER for the Buy/Sell mode palette.
		//
		// SetOrderFlags() is called via TriggerCustomEvent from OnOrderUpdate,
		// which runs on a non-UI strategy thread. Inside SetOrderFlags we do:
		//   PlotBrushes[currentplot][0] = pOrderBuySideColor;
		// Assigning a WPF Brush to PlotBrushes from a non-UI thread throws
		// "The calling thread cannot access this object because a different
		// thread owns it" UNLESS the brush is frozen. System.Windows.Media
		// static brushes (Brushes.Lime, Brushes.Red, etc.) are frozen by
		// default — that's why the pre-existing pOrderTargetColor = Brushes.Lime
		// path never crashed. But our custom Buy/Sell palette uses fresh
		// SolidColorBrush instances (FromRgb(...)) which are NOT frozen.
		//
		// FreezeBrush() freezes a brush in place when possible. Called from:
		//   - Field initializers (via helper constructor pattern below)
		//   - Property setters (in case the user picks a new color at runtime)
		//   - XML deserializer setters (in case the workspace loads a saved color)
		//   - ResetOrderFlagDisplayDefaults (reset-to-defaults path)
		private static Brush FreezeBrush(Brush b)
		{
			if (b != null && b.CanFreeze && !b.IsFrozen)
			{
				try { b.Freeze(); } catch { /* non-fatal — just return unfrozen */ }
			}
			return b;
		}

		// Helper for the field initializer pattern — creates a SolidColorBrush
		// from RGB and freezes it in one call.
		private static Brush FrozenRgbBrush(byte r, byte g, byte b)
		{
			var br = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(r, g, b));
			br.Freeze();
			return br;
		}

		// The serialization key name (the `*S#` string property) is bumped
		// every time we change the default. NT8 writes the current key name
		// into the workspace XML, so bumping the name means the setter never
		// fires on old saved XML and the new C# field initializer is retained.
		// That's how the user gets the new palette *instantly* on the next
		// NinjaScript reload without having to reset anything manually.
		private Brush pOrderBuySideColor = FrozenRgbBrush(10, 50, 155);
		[XmlIgnore]
		[Display(ResourceType = typeof(Custom.Resource), GroupName = "Order Flag Display", Name = "Buy / Sell - Buy", Order = 2)]
		public Brush OrderBuySideColor
		{
			get { return pOrderBuySideColor; } set { pOrderBuySideColor = FreezeBrush(value); }
		}
		[Browsable(false)]
		public string OrderBuySideColorS6
		{
			get { return Serialize.BrushToString(pOrderBuySideColor); } set { pOrderBuySideColor = FreezeBrush(Serialize.StringToBrush(value)); }
		}

#if false // === ECT color-input redesign PARKED — reverted to the standard Brush editor; flip to #if true to resume. ===
		// ----------------------------------------------------------------
		// Order Flag color inputs: named-color dropdown + custom picker
		// ----------------------------------------------------------------
		// NT 8.1.7.0 replaced the property-grid Brush editor with a swatch
		// grid that dropped the named-color list. To bring named colors
		// back AND keep full custom-color control, the color input is
		// fronted by a string property: NamedColorConverter supplies a
		// dropdown of every WPF named color plus a "Custom..." entry, and
		// picking "Custom..." opens aiECTColorPickerWindow (swatch palette,
		// RGBA sliders, hex entry).
		//
		// The Brush field (pOrderBuySideColor) and its serialization
		// companion (OrderBuySideColorS6, above) are untouched. The string
		// property is purely the grid face, so saved workspaces and every
		// consumer of pOrderBuySideColor keep working unchanged.
		//
		// PILOT: wired for "Buy / Sell - Buy" only. Once confirmed in
		// 8.1.7.0 the same pattern (hide the Brush row, add a *Name string
		// property, reuse NamedColorConverter) extends to the other colors.
		// ----------------------------------------------------------------

		internal const string ColorPickerCustomEntry = "Custom...";

		[Display(ResourceType = typeof(Custom.Resource), GroupName = "Order Flag Display", Name = "Buy / Sell - Buy", Order = 2)]
		[TypeConverter(typeof(NamedColorConverter))]
		[PropertyEditor("NinjaTrader.NinjaScript.Indicators.NamedColorPropertyEditor")]
		public string OrderBuySideColorName
		{
			get { return aiECTColorUtil.DescribeBrush(pOrderBuySideColor); }
			set
			{
				if (string.IsNullOrEmpty(value))
					return;

				if (value == ColorPickerCustomEntry)
				{
					System.Windows.Media.Color? picked = aiECTColorPickerWindow.PickColor(aiECTColorUtil.ColorOf(pOrderBuySideColor));
					if (picked.HasValue)
						pOrderBuySideColor = FreezeBrush(new System.Windows.Media.SolidColorBrush(picked.Value));
					return;
				}

				System.Windows.Media.Color? parsed = aiECTColorUtil.TryParseColor(value);
				if (parsed.HasValue)
					pOrderBuySideColor = FreezeBrush(new System.Windows.Media.SolidColorBrush(parsed.Value));
			}
		}

		// Dropdown values for the *Name color properties: "Custom..." plus
		// every WPF named color. Not exclusive, so the editor can still show
		// a raw #AARRGGBB string when the current color is not a named one.
		internal class NamedColorConverter : StringConverter
		{
			public override bool GetStandardValuesSupported(ITypeDescriptorContext context) { return true; }
			public override bool GetStandardValuesExclusive(ITypeDescriptorContext context) { return true; }
			public override StandardValuesCollection GetStandardValues(ITypeDescriptorContext context)
			{
				List<string> values = new List<string>();
				values.Add(ColorPickerCustomEntry);
				// Surface the current value too, so a custom #AARRGGBB that is not
				// a named color still displays in the (now exclusive) dropdown.
				if (context != null && context.PropertyDescriptor != null && context.Instance != null)
				{
					string current = context.PropertyDescriptor.GetValue(context.Instance) as string;
					if (!string.IsNullOrEmpty(current) && current != ColorPickerCustomEntry && !aiECTColorUtil.IsKnownName(current))
						values.Add(current);
				}
				values.AddRange(aiECTColorUtil.AllNames);
				return new StandardValuesCollection(values);
			}
		}

		// Named-color helpers shared by the color-input properties.
		internal static class aiECTColorUtil
		{
			private static readonly object _sync = new object();
			private static List<string> _names;
			private static Dictionary<string, System.Windows.Media.Color> _nameToColor;

			private static void EnsureNamedColors()
			{
				if (_names != null)
					return;
				lock (_sync)
				{
					if (_names != null)
						return;
					List<string> names = new List<string>();
					Dictionary<string, System.Windows.Media.Color> map = new Dictionary<string, System.Windows.Media.Color>();
					foreach (System.Reflection.PropertyInfo pi in typeof(System.Windows.Media.Colors).GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Static))
					{
						if (pi.PropertyType != typeof(System.Windows.Media.Color) || map.ContainsKey(pi.Name))
							continue;
						map[pi.Name] = (System.Windows.Media.Color)pi.GetValue(null, null);
						names.Add(pi.Name);
					}
					names.Sort(System.StringComparer.OrdinalIgnoreCase);
					_nameToColor = map;
					_names = names;
				}
			}

			internal static List<string> AllNames
			{
				get { EnsureNamedColors(); return _names; }
			}

			// True when s is one of the WPF named colors. Used to avoid listing
			// a custom value twice in the dropdown.
			internal static bool IsKnownName(string s)
			{
				if (string.IsNullOrEmpty(s))
					return false;
				EnsureNamedColors();
				return _nameToColor.ContainsKey(s);
			}

			// Underlying Color of a brush (opaque black if it is not solid).
			internal static System.Windows.Media.Color ColorOf(System.Windows.Media.Brush b)
			{
				System.Windows.Media.SolidColorBrush scb = b as System.Windows.Media.SolidColorBrush;
				return scb != null ? scb.Color : System.Windows.Media.Colors.Black;
			}

			// Grid-face text for a brush: the WPF color name when it matches
			// one exactly and is fully opaque, otherwise an #AARRGGBB string.
			internal static string DescribeBrush(System.Windows.Media.Brush b)
			{
				System.Windows.Media.Color c = ColorOf(b);
				EnsureNamedColors();
				if (c.A == 255)
				{
					foreach (string nm in _names)
					{
						System.Windows.Media.Color n = _nameToColor[nm];
						if (n.A == 255 && n.R == c.R && n.G == c.G && n.B == c.B)
							return nm;
					}
				}
				return ToHex(c);
			}

			internal static string ToHex(System.Windows.Media.Color c)
			{
				return string.Format("#{0:X2}{1:X2}{2:X2}{3:X2}", c.A, c.R, c.G, c.B);
			}

			// Parse a WPF color name or #hex string; null when unrecognised.
			internal static System.Windows.Media.Color? TryParseColor(string s)
			{
				if (string.IsNullOrEmpty(s))
					return null;
				try
				{
					object o = System.Windows.Media.ColorConverter.ConvertFromString(s.Trim());
					if (o is System.Windows.Media.Color)
						return (System.Windows.Media.Color)o;
				}
				catch { }
				return null;
			}
		}

		// Custom color picker: swatch palette, recent colors, RGBA sliders
		// and hex entry. Self-contained standard WPF (no NinjaTrader
		// property-grid internals), so it is unaffected by platform
		// updates. Entry point: aiECTColorPickerWindow.PickColor(...).
		internal class aiECTColorPickerWindow : System.Windows.Window
		{
			private static readonly System.Windows.Media.Brush WinBg     = Frz(0xFF, 0x2D, 0x2D, 0x30);
			private static readonly System.Windows.Media.Brush TextBrush  = Frz(0xFF, 0xF0, 0xF0, 0xF0);
			private static readonly System.Windows.Media.Brush MutedBrush = Frz(0xFF, 0x9A, 0x9A, 0xA0);
			private static readonly System.Windows.Media.Brush FieldBg    = Frz(0xFF, 0x3F, 0x3F, 0x46);
			private static readonly System.Windows.Media.Brush LineBrush  = Frz(0xFF, 0x55, 0x55, 0x5A);

			private static readonly List<System.Windows.Media.Color> _recent = new List<System.Windows.Media.Color>();

			private bool _updating;
			private System.Windows.Media.Color _working;

			private System.Windows.Controls.Slider _sA, _sR, _sG, _sB;
			private System.Windows.Controls.TextBlock _vA, _vR, _vG, _vB;
			private System.Windows.Controls.TextBox _hex;
			private System.Windows.Controls.Border _preview;
			private System.Windows.Controls.ListBox _nameList;
			private System.Windows.Controls.TextBox _search;

			internal System.Windows.Media.Color SelectedColor { get; private set; }

			// Opens the picker modally on the UI thread; returns the chosen
			// color, or null if the user cancelled.
			internal static System.Windows.Media.Color? PickColor(System.Windows.Media.Color initial)
			{
				System.Windows.Media.Color? result = null;
				System.Action show = () =>
				{
					aiECTColorPickerWindow win = new aiECTColorPickerWindow(initial);
					try
					{
						if (System.Windows.Application.Current != null)
						{
							foreach (System.Windows.Window w in System.Windows.Application.Current.Windows)
							{
								if (w.IsActive)
								{
									win.Owner = w;
									break;
								}
							}
						}
					}
					catch { }
					win.WindowStartupLocation = win.Owner != null
						? System.Windows.WindowStartupLocation.CenterOwner
						: System.Windows.WindowStartupLocation.CenterScreen;
					if (win.ShowDialog() == true)
					{
						result = win.SelectedColor;
						AddRecent(win.SelectedColor);
					}
				};

				if (System.Windows.Application.Current != null && !System.Windows.Application.Current.Dispatcher.CheckAccess())
					System.Windows.Application.Current.Dispatcher.Invoke(show);
				else
					show();

				return result;
			}

			private static void AddRecent(System.Windows.Media.Color c)
			{
				_recent.RemoveAll(x => x == c);
				_recent.Insert(0, c);
				while (_recent.Count > 10)
					_recent.RemoveAt(_recent.Count - 1);
			}

			private aiECTColorPickerWindow(System.Windows.Media.Color initial)
			{
				_working = initial;
				SelectedColor = initial;

				Title = "Select Color";
				Width = 372;
				SizeToContent = System.Windows.SizeToContent.Height;
				ResizeMode = System.Windows.ResizeMode.NoResize;
				WindowStyle = System.Windows.WindowStyle.SingleBorderWindow;
				ShowInTaskbar = false;
				Background = WinBg;

				System.Windows.Controls.StackPanel root = new System.Windows.Controls.StackPanel();
				root.Margin = new System.Windows.Thickness(14);

				root.Children.Add(Header("Palette"));
				root.Children.Add(BuildSwatchGrid(BuildPalette()));

				if (_recent.Count > 0)
				{
					root.Children.Add(Header("Recent"));
					root.Children.Add(BuildSwatchGrid(new List<System.Windows.Media.Color>(_recent)));
				}

				root.Children.Add(Header("Named colors"));
				root.Children.Add(BuildNamedColorSection());

				root.Children.Add(BuildPreviewRow());
				root.Children.Add(BuildSliderRow("A", out _sA, out _vA));
				root.Children.Add(BuildSliderRow("R", out _sR, out _vR));
				root.Children.Add(BuildSliderRow("G", out _sG, out _vG));
				root.Children.Add(BuildSliderRow("B", out _sB, out _vB));
				root.Children.Add(BuildButtonRow());

				Content = root;

				_sA.ValueChanged += SliderChanged;
				_sR.ValueChanged += SliderChanged;
				_sG.ValueChanged += SliderChanged;
				_sB.ValueChanged += SliderChanged;

				ApplyWorkingColor();
			}

			// Searchable, swatched list of every WPF named color - the part
			// NT 8.1.7.0 dropped from the native editor. Lives in the picker
			// window so it is identical on every NinjaTrader version.
			private System.Windows.UIElement BuildNamedColorSection()
			{
				System.Windows.Controls.StackPanel panel = new System.Windows.Controls.StackPanel();

				_search = new System.Windows.Controls.TextBox();
				_search.Height = 22;
				_search.Margin = new System.Windows.Thickness(0, 0, 0, 4);
				_search.VerticalContentAlignment = System.Windows.VerticalAlignment.Center;
				_search.Background = FieldBg;
				_search.Foreground = TextBrush;
				_search.BorderBrush = LineBrush;
				_search.CaretBrush = TextBrush;
				_search.ToolTip = "Type to filter the color names";
				_search.TextChanged += (s, e) => PopulateNameList(_search.Text);
				panel.Children.Add(_search);

				_nameList = new System.Windows.Controls.ListBox();
				_nameList.Height = 140;
				_nameList.Background = FieldBg;
				_nameList.Foreground = TextBrush;
				_nameList.BorderBrush = LineBrush;
				_nameList.SelectionChanged += (s, e) =>
				{
					if (_updating)
						return;
					System.Windows.Controls.ListBoxItem item = _nameList.SelectedItem as System.Windows.Controls.ListBoxItem;
					if (item != null && item.Tag is System.Windows.Media.Color)
					{
						_working = (System.Windows.Media.Color)item.Tag;
						ApplyWorkingColor();
					}
				};
				panel.Children.Add(_nameList);

				PopulateNameList(null);
				return panel;
			}

			// (Re)fills the named-color list, optionally filtered by substring.
			private void PopulateNameList(string filter)
			{
				if (_nameList == null)
					return;
				bool prev = _updating;
				_updating = true;
				_nameList.Items.Clear();
				string f = string.IsNullOrEmpty(filter) ? null : filter.Trim().ToLowerInvariant();
				foreach (string nm in aiECTColorUtil.AllNames)
				{
					if (f != null && nm.ToLowerInvariant().IndexOf(f) < 0)
						continue;
					System.Windows.Media.Color? cn = aiECTColorUtil.TryParseColor(nm);
					if (!cn.HasValue)
						continue;
					System.Windows.Media.Color c = cn.Value;

					System.Windows.Controls.Border sw = new System.Windows.Controls.Border();
					sw.Width = 16;
					sw.Height = 16;
					sw.BorderThickness = new System.Windows.Thickness(1);
					sw.BorderBrush = LineBrush;
					sw.Background = Frz(c.A, c.R, c.G, c.B);
					sw.VerticalAlignment = System.Windows.VerticalAlignment.Center;

					System.Windows.Controls.TextBlock tb = new System.Windows.Controls.TextBlock();
					tb.Text = nm;
					tb.Foreground = TextBrush;
					tb.Margin = new System.Windows.Thickness(8, 0, 0, 0);
					tb.VerticalAlignment = System.Windows.VerticalAlignment.Center;

					System.Windows.Controls.StackPanel rowPanel = new System.Windows.Controls.StackPanel();
					rowPanel.Orientation = System.Windows.Controls.Orientation.Horizontal;
					rowPanel.Children.Add(sw);
					rowPanel.Children.Add(tb);

					System.Windows.Controls.ListBoxItem lbi = new System.Windows.Controls.ListBoxItem();
					lbi.Content = rowPanel;
					lbi.Tag = c;
					lbi.Padding = new System.Windows.Thickness(3, 2, 3, 2);
					_nameList.Items.Add(lbi);
				}
				_updating = prev;
			}

			private static System.Windows.Media.Brush Frz(byte a, byte r, byte g, byte b)
			{
				System.Windows.Media.SolidColorBrush br = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromArgb(a, r, g, b));
				br.Freeze();
				return br;
			}

			private static System.Windows.Controls.TextBlock Header(string text)
			{
				System.Windows.Controls.TextBlock t = new System.Windows.Controls.TextBlock();
				t.Text = text;
				t.Foreground = MutedBrush;
				t.FontSize = 11;
				t.Margin = new System.Windows.Thickness(0, 8, 0, 4);
				return t;
			}

			private System.Windows.UIElement BuildSwatchGrid(List<System.Windows.Media.Color> colors)
			{
				System.Windows.Controls.Primitives.UniformGrid grid = new System.Windows.Controls.Primitives.UniformGrid();
				grid.Columns = 10;
				grid.HorizontalAlignment = System.Windows.HorizontalAlignment.Left;
				foreach (System.Windows.Media.Color c in colors)
				{
					System.Windows.Media.Color cc = c;
					System.Windows.Controls.Border sw = new System.Windows.Controls.Border();
					sw.Width = 30;
					sw.Height = 22;
					sw.Margin = new System.Windows.Thickness(1);
					sw.BorderThickness = new System.Windows.Thickness(1);
					sw.BorderBrush = LineBrush;
					sw.Background = Frz(cc.A, cc.R, cc.G, cc.B);
					sw.ToolTip = aiECTColorUtil.ToHex(cc);
					sw.Cursor = System.Windows.Input.Cursors.Hand;
					sw.MouseLeftButtonUp += (s, e) =>
					{
						_working = cc;
						ApplyWorkingColor();
					};
					grid.Children.Add(sw);
				}
				return grid;
			}

			private System.Windows.UIElement BuildPreviewRow()
			{
				System.Windows.Controls.Grid g = new System.Windows.Controls.Grid();
				g.Margin = new System.Windows.Thickness(0, 12, 0, 2);
				g.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(70) });
				g.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });

				_preview = new System.Windows.Controls.Border();
				_preview.Height = 30;
				_preview.BorderThickness = new System.Windows.Thickness(1);
				_preview.BorderBrush = LineBrush;
				System.Windows.Controls.Grid.SetColumn(_preview, 0);
				g.Children.Add(_preview);

				_hex = new System.Windows.Controls.TextBox();
				_hex.Margin = new System.Windows.Thickness(8, 0, 0, 0);
				_hex.VerticalContentAlignment = System.Windows.VerticalAlignment.Center;
				_hex.Background = FieldBg;
				_hex.Foreground = TextBrush;
				_hex.BorderBrush = LineBrush;
				_hex.CaretBrush = TextBrush;
				_hex.FontFamily = new System.Windows.Media.FontFamily("Consolas");
				_hex.LostFocus += (s, e) => CommitHex();
				_hex.KeyDown += (s, e) =>
				{
					if (e.Key == System.Windows.Input.Key.Enter)
					{
						CommitHex();
						e.Handled = true;
					}
				};
				System.Windows.Controls.Grid.SetColumn(_hex, 1);
				g.Children.Add(_hex);

				return g;
			}

			private System.Windows.UIElement BuildSliderRow(string label, out System.Windows.Controls.Slider slider, out System.Windows.Controls.TextBlock valBlock)
			{
				System.Windows.Controls.Grid g = new System.Windows.Controls.Grid();
				g.Margin = new System.Windows.Thickness(0, 5, 0, 0);
				g.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(16) });
				g.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });
				g.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(34) });

				System.Windows.Controls.TextBlock lbl = new System.Windows.Controls.TextBlock();
				lbl.Text = label;
				lbl.Foreground = TextBrush;
				lbl.VerticalAlignment = System.Windows.VerticalAlignment.Center;
				System.Windows.Controls.Grid.SetColumn(lbl, 0);
				g.Children.Add(lbl);

				slider = new System.Windows.Controls.Slider();
				slider.Minimum = 0;
				slider.Maximum = 255;
				slider.SmallChange = 1;
				slider.LargeChange = 16;
				slider.IsSnapToTickEnabled = true;
				slider.TickFrequency = 1;
				slider.VerticalAlignment = System.Windows.VerticalAlignment.Center;
				slider.Margin = new System.Windows.Thickness(4, 0, 6, 0);
				System.Windows.Controls.Grid.SetColumn(slider, 1);
				g.Children.Add(slider);

				valBlock = new System.Windows.Controls.TextBlock();
				valBlock.Foreground = TextBrush;
				valBlock.VerticalAlignment = System.Windows.VerticalAlignment.Center;
				valBlock.HorizontalAlignment = System.Windows.HorizontalAlignment.Right;
				System.Windows.Controls.Grid.SetColumn(valBlock, 2);
				g.Children.Add(valBlock);

				return g;
			}

			private System.Windows.UIElement BuildButtonRow()
			{
				System.Windows.Controls.StackPanel p = new System.Windows.Controls.StackPanel();
				p.Orientation = System.Windows.Controls.Orientation.Horizontal;
				p.HorizontalAlignment = System.Windows.HorizontalAlignment.Right;
				p.Margin = new System.Windows.Thickness(0, 14, 0, 0);

				System.Windows.Controls.Button ok = new System.Windows.Controls.Button();
				ok.Content = "OK";
				ok.Width = 76;
				ok.Height = 24;
				ok.IsDefault = true;
				ok.Click += (s, e) =>
				{
					SelectedColor = _working;
					DialogResult = true;
				};

				System.Windows.Controls.Button cancel = new System.Windows.Controls.Button();
				cancel.Content = "Cancel";
				cancel.Width = 76;
				cancel.Height = 24;
				cancel.Margin = new System.Windows.Thickness(8, 0, 0, 0);
				cancel.IsCancel = true;

				p.Children.Add(ok);
				p.Children.Add(cancel);
				return p;
			}

			private void SliderChanged(object sender, System.Windows.RoutedPropertyChangedEventArgs<double> e)
			{
				if (_updating)
					return;
				_working = System.Windows.Media.Color.FromArgb(
					(byte)_sA.Value, (byte)_sR.Value, (byte)_sG.Value, (byte)_sB.Value);
				ApplyWorkingColor();
			}

			private void CommitHex()
			{
				System.Windows.Media.Color? c = aiECTColorUtil.TryParseColor(_hex.Text);
				if (c.HasValue)
					_working = c.Value;
				ApplyWorkingColor();
			}

			private void ApplyWorkingColor()
			{
				_updating = true;
				_sA.Value = _working.A;
				_sR.Value = _working.R;
				_sG.Value = _working.G;
				_sB.Value = _working.B;
				_vA.Text = _working.A.ToString();
				_vR.Text = _working.R.ToString();
				_vG.Text = _working.G.ToString();
				_vB.Text = _working.B.ToString();
				_hex.Text = aiECTColorUtil.ToHex(_working);
				_preview.Background = Frz(_working.A, _working.R, _working.G, _working.B);
				_updating = false;
			}

			private static List<System.Windows.Media.Color> BuildPalette()
			{
				List<System.Windows.Media.Color> list = new List<System.Windows.Media.Color>();
				for (int i = 0; i < 10; i++)
				{
					byte g = (byte)System.Math.Round(i * 255.0 / 9.0);
					list.Add(System.Windows.Media.Color.FromRgb(g, g, g));
				}
				double[,] sv = new double[,]
				{
					{ 0.28, 1.00 }, { 0.52, 1.00 }, { 0.78, 1.00 },
					{ 1.00, 1.00 }, { 1.00, 0.78 }, { 1.00, 0.55 }
				};
				for (int row = 0; row < 6; row++)
					for (int col = 0; col < 10; col++)
						list.Add(ColorFromHsv(col * 36.0, sv[row, 0], sv[row, 1]));
				return list;
			}

			private static System.Windows.Media.Color ColorFromHsv(double h, double s, double v)
			{
				h = h % 360.0;
				if (h < 0)
					h += 360.0;
				double c = v * s;
				double x = c * (1.0 - System.Math.Abs((h / 60.0) % 2.0 - 1.0));
				double m = v - c;
				double r1 = 0, g1 = 0, b1 = 0;
				if (h < 60)       { r1 = c; g1 = x; b1 = 0; }
				else if (h < 120) { r1 = x; g1 = c; b1 = 0; }
				else if (h < 180) { r1 = 0; g1 = c; b1 = x; }
				else if (h < 240) { r1 = 0; g1 = x; b1 = c; }
				else if (h < 300) { r1 = x; g1 = 0; b1 = c; }
				else              { r1 = c; g1 = 0; b1 = x; }
				return System.Windows.Media.Color.FromRgb(
					(byte)System.Math.Round((r1 + m) * 255.0),
					(byte)System.Math.Round((g1 + m) * 255.0),
					(byte)System.Math.Round((b1 + m) * 255.0));
			}
		}
#endif

