        // Shared stroke for stop-strategy planning visuals:
        // BE trigger marker, Stop-after-T1 marker, Trailing stop marker, and the H/L swing bar outline.
        // Goldenrod by default so these "planning aid" markers are visually distinct from
        // entry (neutral), target (up), and stop (down) strokes.
        private Stroke pStopStrategyStroke = new Stroke(Brushes.Goldenrod, DashStyleHelper.Dash, 1);
        [Display(ResourceType = typeof(Custom.Resource), GroupName = "ATM Strategy Planning", Name = "Stop Strategy Display", Order = 41)]
        public Stroke StopStrategyStroke
        {
            get { return pStopStrategyStroke; }
            set
            {
                pStopStrategyStroke = value;
                // When the user picks a new color/dash/width in the properties panel
                // NT8 constructs a fresh Stroke instance with no RenderTarget. Without
                // this re-assignment, BrushDX stays null and the next DrawPlanOrder
                // call that uses this stroke throws an NRE inside OnRender, which
                // aborts the render pass AFTER clearing the plan / click-entry hit
                // rects but BEFORE repopulating them — causing plan visuals and
                // buy/sell-click buttons to stop responding to mouse movement.
                if (pStopStrategyStroke != null && RenderTarget != null)
                    pStopStrategyStroke.RenderTarget = RenderTarget;
            }
        }
		
