		// Hide UserDefinedValues properties when not in use by the HLCCalculationMode.UserDefinedValues
	// When creating a custom type converter for indicators it must inherit from NinjaTrader.NinjaScript.IndicatorBaseConverter to work correctly with indicators
	public class aiEnhancedChartTraderConverter : NinjaTrader.NinjaScript.IndicatorBaseConverter
	{
		// Cache the fully-built PropertyDescriptorCollection. Property grid refresh
		// calls GetProperties on EVERY property change that has [RefreshProperties].
		// Rebuilding ~600 PropertyDescriptorExtended wrappers each time was the
		// source of the ~4s delay when toggling flags like ATM Enabled. Cache keyed
		// by the indicator instance + a signature of every gating flag that
		// influences DeleteThese population — rebuild only when the signature changes.
		// Static — NinjaTrader may instantiate a new converter per grid refresh,
		// so the cache has to survive converter re-creation. ConditionalWeakTable
		// holds weak references to indicator instances, so entries auto-clean when
		// the indicator is GC'd.
		private static System.Runtime.CompilerServices.ConditionalWeakTable<object, CacheEntry> _cache
			= new System.Runtime.CompilerServices.ConditionalWeakTable<object, CacheEntry>();

		private class CacheEntry
		{
			public string Sig;
			public PropertyDescriptorCollection Result;
			// Cache base.GetProperties() reflection result too — property list doesn't
			// change at runtime, so we only need to enumerate it once per indicator.
			// This is the single most expensive part of a cache-miss rebuild.
			public PropertyDescriptorCollection BaseProps;
			// Cache of PropertyDescriptorExtended wrappers keyed by descriptor name.
			// Wrappers capture `value` (indicator instance) in a closure, so they're
			// reusable across rebuilds for the same indicator.
			public Dictionary<string, PropertyDescriptorExtended> HiddenWrappers;
		}

		// Single shared Attribute[] for all hidden wrappers — saves ~200 array allocs per rebuild
		private static readonly Attribute[] BROWSABLE_FALSE_ATTRS = new Attribute[] { new BrowsableAttribute(false) };

		private static string BuildFlagSig(aiEnhancedChartTrader j)
		{
			var sb = new System.Text.StringBuilder(256);
			sb.Append(j.ATMPreviewButtonEnabled ? '1' : '0');
			sb.Append(j.ATMQuickButtonsEnabled ? '1' : '0');
			sb.Append(j.AdvancedExitOrdersManagementEnabled ? '1' : '0');
			sb.Append(j.AdvancedExitOrdersManagementPermission ? '1' : '0');
			sb.Append(j.AttachmentOrdersEnabled ? '1' : '0');
			sb.Append(j.AttachmentOrdersPermission ? '1' : '0');
			sb.Append(j.BarCounterEnabled ? '1' : '0');
			sb.Append(j.BracketEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.BracketEntryOrdersPermission ? '1' : '0');
			sb.Append(j.BracketMode).Append('|');
			sb.Append(j.ButtonsEnabled ? '1' : '0');
			sb.Append(j.ClickEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.CloseBarEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.CloseBarEntryOrdersPermission ? '1' : '0');
			sb.Append(j.CloseButtonType).Append('|');
			sb.Append(j.CloseEntryButtonManagement).Append('|');
			sb.Append(j.CrossHairEnabled ? '1' : '0');
			sb.Append(j.DepthButtonEnabled ? '1' : '0');
			sb.Append(j.DuplicateButtonsEnabled ? '1' : '0');
			sb.Append(j.DuplicateButtonsPermission ? '1' : '0');
			sb.Append(j.EntryHandlingNow).Append('|');
			sb.Append(j.EssentialToolsPermission ? '1' : '0');
			sb.Append(j.ExecutionsAreEnabled ? '1' : '0');
			sb.Append(j.ExitOnCloseButtonEnabled ? '1' : '0');
			sb.Append(j.HotKeysEnabled ? '1' : '0');
			sb.Append(j.IcebergEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.IcebergEntryOrdersPermission ? '1' : '0');
			sb.Append(j.InitialExitAdjustmentsEnabled ? '1' : '0');
			sb.Append(j.IsVolumetricBars ? '1' : '0');
			sb.Append(j.LITEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.LITEntryOrdersPermission ? '1' : '0');
			sb.Append(j.Limit1EntryOrdersEnabled ? '1' : '0');
			sb.Append(j.Limit2EntryOrdersEnabled ? '1' : '0');
			sb.Append(j.LimitOrderClose ? '1' : '0');
			sb.Append(j.LinkButtonsEnabled ? '1' : '0');
			sb.Append(j.MTFEnabled ? '1' : '0');
			sb.Append(j.OneClickOrdersEnabled1 ? '1' : '0');
			sb.Append(j.OneClickOrdersPermission ? '1' : '0');
			sb.Append(j.OrderFlowEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.OrderFlowEntryOrdersPermission ? '1' : '0');
			sb.Append(j.PositionSizingButtonsEnabled ? '1' : '0');
			sb.Append(j.PositionSizingButtonsPermission ? '1' : '0');
			sb.Append(j.PriceBasedEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.PriceBasedEntryOrdersPermission ? '1' : '0');
			sb.Append(j.RiskRewardButtonEnabled ? '1' : '0');
			sb.Append(j.ShowATMResetButton ? '1' : '0');
			sb.Append(j.ShowLastPriceAll ? '1' : '0');
			sb.Append(j.ShowLastPriceMarker2 ? '1' : '0');
			sb.Append(j.ShowMoveAllExits ? '1' : '0');
			sb.Append(j.SignalEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.SignalEntryOrdersPermission ? '1' : '0');
			sb.Append(j.StopEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.StopEntryOrdersPermission ? '1' : '0');
			sb.Append(j.TimeSlicedEntryOrdersEnabled ? '1' : '0');
			sb.Append(j.TimeSlicedEntryOrdersPermission ? '1' : '0');
			sb.Append(j.TrailingStopFeaturesEnabled ? '1' : '0');
			sb.Append(j.TrailingStopShowATR ? '1' : '0');
			sb.Append(j.TrailingStopShowHighLow ? '1' : '0');
			sb.Append(j.UpsellEnabled ? '1' : '0');
			sb.Append(j.UseSLM ? '1' : '0');
			sb.Append(j.UseTimeFilter ? '1' : '0');
			sb.Append(j.NumberOfCustomTrailingStops);
			return sb.ToString();
		}

		public override bool GetPropertiesSupported(ITypeDescriptorContext context) { return true; }

		public override PropertyDescriptorCollection GetProperties(ITypeDescriptorContext context, object value, Attribute[] attributes)
		{
			aiEnhancedChartTrader   jbb = (aiEnhancedChartTrader) value;

			// Cache lookup — two-tier:
			//   1. If flag signature matches cached one, return cached Result directly (fastest).
			//   2. Otherwise reuse cached BaseProps (the reflection result) to avoid the
			//      ~100-500ms base.GetProperties() call, and only rebuild the adjusted collection.
			string currentSig = null;
			CacheEntry cacheEntry = null;
			if (jbb != null)
			{
				currentSig = BuildFlagSig(jbb);
				_cache.TryGetValue(jbb, out cacheEntry);
				if (cacheEntry != null && cacheEntry.Sig == currentSig && cacheEntry.Result != null)
					return cacheEntry.Result;
			}

			PropertyDescriptorCollection propertyDescriptorCollection;
			if (cacheEntry != null && cacheEntry.BaseProps != null)
			{
				// Reuse cached reflection result — saves the expensive base.GetProperties() call
				propertyDescriptorCollection = cacheEntry.BaseProps;
			}
			else
			{
				propertyDescriptorCollection = base.GetPropertiesSupported(context) ? base.GetProperties(context, value, attributes) : TypeDescriptor.GetProperties(value, attributes);
			}
			
			//Pivots						thisPivotsInstance			= (Pivots) value;
			
			//bool MagnetsOn = ;
			
			// HashSet for O(1) Contains lookups — property grid refresh iterates
			// ~600 properties and calls DeleteThese.Contains on each. With List
			// that was O(n²) = ~240k string compares per refresh (~4s delay).
			HashSet<string> DeleteThese = new HashSet<string>();
			HashSet<string> DeleteThese2 = new HashSet<string>();
			
	
			 //DeleteThese.Add("InputUI");
	
			
			
			DeleteThese.Add("SavedSectionStates");
			DeleteThese.Add("SavedScrollPosition");
			DeleteThese.Add("ChartTraderWidth");
			DeleteThese.Add("PNLIsVisible");
			
			DeleteThese.Add("ExecutionsDisplay");
			
			DeleteThese.Add("TotalIndicatorsOnChart");
			DeleteThese.Add("TotalIndicatorsOnChartString");
			

		
		
				DeleteThese.Add("FreePTTicks");
				DeleteThese.Add("FreeSLTicks");			
				DeleteThese.Add("FreeATMEnabled");
		
				DeleteThese.Add("FreeSLEnabled");			
				DeleteThese.Add("FreePTEnabled");		
			
	
			
			
			
				DeleteThese.Add("ContractTypeMode");
				DeleteThese.Add("ThisTIF1");
				DeleteThese.Add("ThisTIF2");			
		
			
			
			
			
			DeleteThese.Add("ShowEx");
			DeleteThese.Add("ShowExecutionsButton");
			
			
			if (!jbb.ExecutionsAreEnabled)
			{
				
				
				
				DeleteThese.Add("ExecutionsDisplayType");
				
				DeleteThese.Add("ColorBid2Tri");
				DeleteThese.Add("ColorAskTri");
				DeleteThese.Add("ColorExitTri");
				
				DeleteThese.Add("TriSize");
				
				DeleteThese.Add("WinningTradeOutlineStroke");
				DeleteThese.Add("LosingTradeOutlineStroke");
				DeleteThese.Add("TimeInTradeEnabled");
				
				
				
			}
				

	
			
		
				DeleteThese.Add("CurrentSetting");
				DeleteThese.Add("SpaceBetweenBars");
				DeleteThese.Add("CurrentSetting2");
				DeleteThese.Add("SpaceBetweenBars2");				
				DeleteThese.Add("ThisBarMarginRight");
				DeleteThese.Add("UseFixedVerticalScale");
				DeleteThese.Add("UseYScroll");
				DeleteThese.Add("ScaleTicks");
				DeleteThese.Add("ScrollTicks");
				DeleteThese.Add("DefaultTopBottomMargin");	
		



			// hot keys
			
		if (!jbb.HotKeysEnabled)
			{
 			
				DeleteThese.Add("KeyBuyMarket");
 				DeleteThese.Add("KeySellMarket");
				
				DeleteThese.Add("KeyBuyLimit1");
 				DeleteThese.Add("KeySellLimit1");				
				DeleteThese.Add("KeyBuyLimit2");
 				DeleteThese.Add("KeySellLimit2");	
				
				
				DeleteThese.Add("KeyBuyClick");
				DeleteThese.Add("KeySellClick");
				DeleteThese.Add("KeyCloseAll");
				DeleteThese.Add("KeyBE");
				
				
				DeleteThese.Add("KeyOrderPanel");
				
				DeleteThese.Add("KeyATM1");
				DeleteThese.Add("KeyATM2");
				DeleteThese.Add("KeyATM3");
				DeleteThese.Add("KeyATM4");
				
				DeleteThese.Add("KeyATMReset");
				

				DeleteThese.Add("KeyBuyPrice");
				DeleteThese.Add("KeySellPrice");				
				
				DeleteThese.Add("KeyPSUp");
				DeleteThese.Add("KeyPSDn");					
				
				DeleteThese.Add("AEOMOnOff");	
				DeleteThese.Add("AEOMCustom1");
				DeleteThese.Add("AEOMCustom2");
				DeleteThese.Add("AEOMCustom3");
				DeleteThese.Add("AEOMCustom4");				
				
				
			}
				
				
			
			if (!jbb.AdvancedExitOrdersManagementEnabled)
			{		
				DeleteThese.Add("AEOMOnOff");
				DeleteThese.Add("AEOMCustom1");
				DeleteThese.Add("AEOMCustom2");
				DeleteThese.Add("AEOMCustom3");
				DeleteThese.Add("AEOMCustom4");
			}			
				
	
