			{
				if (jbb != null) { if (cacheEntry != null) { cacheEntry.Sig = currentSig; cacheEntry.Result = propertyDescriptorCollection; cacheEntry.BaseProps = propertyDescriptorCollection; } else { _cache.Add(jbb, new CacheEntry { Sig = currentSig, Result = propertyDescriptorCollection, BaseProps = propertyDescriptorCollection }); } }
				return propertyDescriptorCollection;
			}

			
		
			
			
			// Wrapper cache — avoid recreating PropertyDescriptorExtended wrappers on every
			// flag-change rebuild. Wrappers capture `value` in a closure and are reusable
			// for the same indicator instance.
			Dictionary<string, PropertyDescriptorExtended> hiddenWrappers;
			if (cacheEntry != null && cacheEntry.HiddenWrappers != null)
			{
				hiddenWrappers = cacheEntry.HiddenWrappers;
			}
			else
			{
				hiddenWrappers = new Dictionary<string, PropertyDescriptorExtended>(256);
			}

			PropertyDescriptorCollection adjusted = new PropertyDescriptorCollection(null);
			foreach (PropertyDescriptor thisDescriptor in propertyDescriptorCollection)
			{
				string descName = thisDescriptor.Name;

				if (!jbb.EssentialToolsPermission && thisDescriptor.Description.ToString().Contains("Market Depth Display"))
				{
					PropertyDescriptorExtended w;
					if (!hiddenWrappers.TryGetValue(descName, out w))
					{
						w = new PropertyDescriptorExtended(thisDescriptor, o => value, null, BROWSABLE_FALSE_ATTRS);
						hiddenWrappers[descName] = w;
					}
					adjusted.Add(w);
				}


				if (DeleteThese.Contains(descName))
				{
					PropertyDescriptorExtended w;
					if (!hiddenWrappers.TryGetValue(descName, out w))
					{
						w = new PropertyDescriptorExtended(thisDescriptor, o => value, null, BROWSABLE_FALSE_ATTRS);
						hiddenWrappers[descName] = w;
					}
					adjusted.Add(w);
				}
				else if (thisDescriptor.Category == "Data Series")
				{
					PropertyDescriptorExtended w;
					if (!hiddenWrappers.TryGetValue(descName, out w))
					{
						w = new PropertyDescriptorExtended(thisDescriptor, o => value, null, BROWSABLE_FALSE_ATTRS);
						hiddenWrappers[descName] = w;
					}
					adjusted.Add(w);
				}
				else
					adjusted.Add(thisDescriptor);

			}
			
			
//			foreach (CategoryItem CI in propertyGrid.Categories)
//				{
				
//					if (DeleteThese.Contains(CI.Name))
//					{
						
						
						
//						//Print(CI.Name);
						
						
//					}
//					else
//					{
//						//CI.IsBrowsable = false;
//						CI.IsExpanded = false;
//					}
					
//				}
				
				
				
						
//				foreach (CategoryItem CI in propertyDescriptorCollection.cate.cat.Categories)
//				{
				
//					if (DeleteThese.Contains(CI.Name))
//					{
						
						
						
//						//Print(CI.Name);
						
						
//					}
//					else
//					{
//						CI.IsBrowsable = false;
//						//CI.IsExpanded = false;
//					}
					
//				}
				
				
			if (jbb != null) { if (cacheEntry != null) { cacheEntry.Sig = currentSig; cacheEntry.Result = adjusted; cacheEntry.BaseProps = propertyDescriptorCollection; cacheEntry.HiddenWrappers = hiddenWrappers; } else { _cache.Add(jbb, new CacheEntry { Sig = currentSig, Result = adjusted, BaseProps = propertyDescriptorCollection, HiddenWrappers = hiddenWrappers }); } }
			return adjusted;
		}
	}

	public class aiEnhancedChartTraderEmailEntryWindow : NTWindow, IWorkspacePersistence
	{
		public IndicatorBase selectedIndicator;
		public string EnteredEmail { get; private set; }
		public bool Confirmed { get; private set; }
		private TextBox _emailTextBox;

		public aiEnhancedChartTraderEmailEntryWindow()
		{
			Caption = "Affordable Indicators - Enter Email Address";
			Width = 420;
			Height = 200;
			WindowStartupLocation = WindowStartupLocation.CenterScreen;
			Content = BuildContent();
			Loaded += OnWindowLoaded;
		}

		private void OnWindowLoaded(object sender, RoutedEventArgs e)
		{
			if (WorkspaceOptions == null)
				WorkspaceOptions = new WorkspaceOptions("aiEnhancedChartTraderEmailEntryWindow" + Guid.NewGuid().ToString("N"), this);

			if (_emailTextBox != null && selectedIndicator != null)
			{
				try
				{
					PropertyInfo pi = selectedIndicator.GetType().GetProperty("LicensingEmailAddress",
						BindingFlags.Public | BindingFlags.Instance);
					if (pi != null)
					{
						object v = pi.GetValue(selectedIndicator);
						if (v != null) _emailTextBox.Text = v.ToString();
					}
				}
				catch { }
				_emailTextBox.Focus();
				_emailTextBox.SelectAll();
			}
		}

		private UIElement BuildContent()
		{
			var root = new System.Windows.Controls.Grid { Margin = new Thickness(15) };
			root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });
			root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });
			root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });
			root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });

			var label = new System.Windows.Controls.TextBlock
			{
				Text = "Please enter the 'Email Address' connected to your Affordable Indicators, Inc. website account:",
				TextWrapping = System.Windows.TextWrapping.Wrap,
				Margin = new Thickness(0, 0, 0, 10),
				Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(0xCC, 0xCC, 0xCC))
			};
			System.Windows.Controls.Grid.SetRow(label, 0);
			root.Children.Add(label);

			_emailTextBox = new TextBox
			{
				MinHeight = 26,
				FontSize = 13,
				Padding = new Thickness(4, 2, 4, 2),
				Margin = new Thickness(0, 0, 0, 10)
			};
			_emailTextBox.KeyDown += (s, ea) =>
			{
				if (ea.Key == System.Windows.Input.Key.Enter)
				{
					ea.Handled = true;
					ConfirmAndClose();
				}
			};
			System.Windows.Controls.Grid.SetRow(_emailTextBox, 1);
			root.Children.Add(_emailTextBox);

			var buttonBar = new System.Windows.Controls.StackPanel
			{
				Orientation = System.Windows.Controls.Orientation.Horizontal,
				HorizontalAlignment = System.Windows.HorizontalAlignment.Right
			};

			var okBtn = new System.Windows.Controls.Button
			{
				Content = "OK",
				MinWidth = 86,
				MinHeight = 27,
				Margin = new Thickness(0),
				IsDefault = true
			};
			okBtn.Click += (s, ea) => ConfirmAndClose();
			buttonBar.Children.Add(okBtn);

			System.Windows.Controls.Grid.SetRow(buttonBar, 3);
			root.Children.Add(buttonBar);

			return root;
		}

		private void ConfirmAndClose()
		{
			Confirmed = true;
			EnteredEmail = _emailTextBox != null ? (_emailTextBox.Text ?? "").Trim() : "";

			if (selectedIndicator != null)
			{
				try
				{
					PropertyInfo pi = selectedIndicator.GetType().GetProperty("LicensingEmailAddress",
						BindingFlags.Public | BindingFlags.Instance);
					if (pi != null && pi.CanWrite)
						pi.SetValue(selectedIndicator, EnteredEmail);
				}
				catch { }
			}

			Close();
		}

		public void Restore(XDocument document, XElement element) { }
		public void Save(XDocument document, XElement element) { }
		public WorkspaceOptions WorkspaceOptions { get; set; }
	}

#if false // === ECT custom color property editor PARKED — flip to #if true to resume. ===
	// ----------------------------------------------------------------
	// Custom property-grid editor: an inline dropdown whose items show a
	// color swatch beside each name, plus a "..." button that opens the
	// full picker window. Subclasses the PropertyEditor type from
	// NinjaTrader's embedded WpfPropertyGrid.
	//
	// REQUIRES a NinjaScript reference to System.Windows.Controls.WpfPropertyGrid.dll
	// (it ships in every NinjaTrader 8 install's bin folder). This is an
	// officially-"unsupported" NinjaTrader API.
	// ----------------------------------------------------------------
	public class NamedColorPropertyEditor : System.Windows.Controls.WpfPropertyGrid.PropertyEditor
	{
		public NamedColorPropertyEditor()
		{
			InlineTemplate = BuildInlineTemplate();
		}

		// One row in the swatch dropdown.
		public class ColorChoice
		{
			public string Name { get; set; }
			public System.Windows.Media.Brush SwatchBrush { get; set; }
			public override string ToString() { return Name; }
		}

		private static List<ColorChoice> _items;
		public static List<ColorChoice> ColorItems
		{
			get
			{
				if (_items == null)
				{
					List<ColorChoice> list = new List<ColorChoice>();
					foreach (string nm in aiEnhancedChartTrader.aiECTColorUtil.AllNames)
					{
						System.Windows.Media.Color? c = aiEnhancedChartTrader.aiECTColorUtil.TryParseColor(nm);
						if (!c.HasValue)
							continue;
						System.Windows.Media.SolidColorBrush b = new System.Windows.Media.SolidColorBrush(c.Value);
						b.Freeze();
						ColorChoice cc = new ColorChoice();
						cc.Name = nm;
						cc.SwatchBrush = b;
						list.Add(cc);
					}
					_items = list;
				}
				return _items;
			}
		}

		// DataTemplate for one combo item: [swatch] name.
		private static System.Windows.DataTemplate BuildItemTemplate()
		{
			System.Windows.FrameworkElementFactory sp = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.StackPanel));
			sp.SetValue(System.Windows.Controls.StackPanel.OrientationProperty, System.Windows.Controls.Orientation.Horizontal);

			System.Windows.FrameworkElementFactory sw = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Border));
			sw.SetValue(System.Windows.FrameworkElement.WidthProperty, 14.0);
			sw.SetValue(System.Windows.FrameworkElement.HeightProperty, 14.0);
			sw.SetValue(System.Windows.Controls.Border.BorderThicknessProperty, new System.Windows.Thickness(1));
			sw.SetValue(System.Windows.Controls.Border.BorderBrushProperty, System.Windows.Media.Brushes.Gray);
			sw.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			sw.SetBinding(System.Windows.Controls.Border.BackgroundProperty, new System.Windows.Data.Binding("SwatchBrush"));

			System.Windows.FrameworkElementFactory tx = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.TextBlock));
			tx.SetValue(System.Windows.FrameworkElement.MarginProperty, new System.Windows.Thickness(6, 0, 0, 0));
			tx.SetValue(System.Windows.FrameworkElement.VerticalAlignmentProperty, System.Windows.VerticalAlignment.Center);
			tx.SetBinding(System.Windows.Controls.TextBlock.TextProperty, new System.Windows.Data.Binding("Name"));

			sp.AppendChild(sw);
			sp.AppendChild(tx);

			System.Windows.DataTemplate dt = new System.Windows.DataTemplate();
			dt.VisualTree = sp;
			return dt;
		}

		// InlineTemplate: [ swatch dropdown ][ ... button ].
		private static System.Windows.DataTemplate BuildInlineTemplate()
		{
			System.Windows.FrameworkElementFactory dock = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.DockPanel));
			dock.SetValue(System.Windows.Controls.DockPanel.LastChildFillProperty, true);

			System.Windows.FrameworkElementFactory btn = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.Button));
			btn.SetValue(System.Windows.Controls.DockPanel.DockProperty, System.Windows.Controls.Dock.Right);
			btn.SetValue(System.Windows.Controls.ContentControl.ContentProperty, "...");
			btn.SetValue(System.Windows.FrameworkElement.WidthProperty, 24.0);
			btn.SetValue(System.Windows.Controls.Control.PaddingProperty, new System.Windows.Thickness(0));
			btn.SetValue(System.Windows.Controls.Primitives.ButtonBase.CommandProperty, System.Windows.Controls.WpfPropertyGrid.PropertyEditorCommands.ShowDialogEditor);
			btn.SetBinding(System.Windows.Controls.Primitives.ButtonBase.CommandParameterProperty, new System.Windows.Data.Binding());

			System.Windows.FrameworkElementFactory combo = new System.Windows.FrameworkElementFactory(typeof(System.Windows.Controls.ComboBox));
			combo.SetValue(System.Windows.Controls.ComboBox.IsEditableProperty, true);
			combo.SetValue(System.Windows.Controls.ItemsControl.ItemsSourceProperty, ColorItems);
			combo.SetValue(System.Windows.Controls.ItemsControl.ItemTemplateProperty, BuildItemTemplate());
			combo.SetValue(System.Windows.Controls.TextSearch.TextPathProperty, "Name");
			System.Windows.Data.Binding textBinding = new System.Windows.Data.Binding("StringValue");
			textBinding.Mode = System.Windows.Data.BindingMode.TwoWay;
			textBinding.UpdateSourceTrigger = System.Windows.Data.UpdateSourceTrigger.PropertyChanged;
			combo.SetBinding(System.Windows.Controls.ComboBox.TextProperty, textBinding);

			dock.AppendChild(btn);
			dock.AppendChild(combo);

			System.Windows.DataTemplate dt = new System.Windows.DataTemplate();
			dt.VisualTree = dock;
			return dt;
		}

		// "..." button -> open the full picker window, write back the result.
		public override void ShowDialog(System.Windows.Controls.WpfPropertyGrid.PropertyItemValue propertyValue, System.Windows.IInputElement commandSource)
		{
			if (propertyValue == null || propertyValue.IsReadOnly)
				return;

			System.Windows.Media.Color? current = aiEnhancedChartTrader.aiECTColorUtil.TryParseColor(propertyValue.StringValue);
			System.Windows.Media.Color seed = current.HasValue ? current.Value : System.Windows.Media.Colors.Black;
			System.Windows.Media.Color? picked = aiEnhancedChartTrader.aiECTColorPickerWindow.PickColor(seed);
			if (picked.HasValue)
				propertyValue.StringValue = aiEnhancedChartTrader.aiECTColorUtil.DescribeBrush(new System.Windows.Media.SolidColorBrush(picked.Value));
		}

		// Reset action - leave the color unchanged (an empty value is meaningless here).
		public override void ClearValue(System.Windows.Controls.WpfPropertyGrid.PropertyItemValue propertyValue, System.Windows.IInputElement commandSource)
		{
		}
	}
#endif
}

